INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (304, '7MGJ', '', 'Serine/threonine-protein kinase TNNI3K', 'May play a role in cardiac physiology.', 'TNNI3K', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ANK repeat, ATP-binding, Cardiomyopathy, Coiled coil, Cytoplasm, Disease variant, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (305, '5FQD', '', 'DNA damage-binding protein 1', 'Protein, which is both involved in DNA repair and protein ubiquitination, as part of the UV-DDB complex and DCX (DDB1-CUL4-X-box) complexes, respectively (PubMed:15448697, PubMed:14739464, PubMed:16260596, PubMed:16482215, PubMed:17079684, PubMed:16407242, PubMed:16407252, PubMed:16940174). Core component of the UV-DDB complex (UV-damaged DNA-binding protein complex), a complex that recognizes UV-induced DNA damage and recruit proteins of the nucleotide excision repair pathway (the NER pathway) to initiate DNA repair (PubMed:15448697, PubMed:16260596, PubMed:16407242, PubMed:16940174). The UV-DDB complex preferentially binds to cyclobutane pyrimidine dimers (CPD), 6-4 photoproducts (6-4 PP), apurinic sites and short mismatches (PubMed:15448697, PubMed:16260596, PubMed:16407242, PubMed:16940174). Also functions as a component of numerous distinct DCX (DDB1-CUL4-X-box) E3 ubiquitin-protein ligase complexes which mediate the ubiquitination and subsequent proteasomal degradation of target proteins (PubMed:14739464, PubMed:16407252, PubMed:16482215, PubMed:17079684, PubMed:25043012, PubMed:25108355, PubMed:18332868, PubMed:18381890, PubMed:19966799, PubMed:22118460, PubMed:28886238). The functional specificity of the DCX E3 ubiquitin-protein ligase complex is determined by the variable substrate recognition component recruited by DDB1 (PubMed:14739464, PubMed:16407252, PubMed:16482215, PubMed:17079684, PubMed:25043012, PubMed:25108355, PubMed:18332868, PubMed:18381890, PubMed:19966799, PubMed:22118460). DCX(DDB2) (also known as DDB1-CUL4-ROC1, CUL4-DDB-ROC1 and CUL4-DDB-RBX1) may ubiquitinate histone H2A, histone H3 and histone H4 at sites of UV-induced DNA damage (PubMed:16678110, PubMed:17041588, PubMed:16473935, PubMed:18593899). The ubiquitination of histones may facilitate their removal from the nucleosome and promote subsequent DNA repair (PubMed:16678110, PubMed:17041588, PubMed:16473935, PubMed:18593899). DCX(DDB2) also ubiquitinates XPC, which may enhance DNA-binding by XPC and promote NER (PubMed:15882621). DCX(DTL) plays a role in PCNA-dependent polyubiquitination of CDT1 and MDM2-dependent ubiquitination of TP53 in response to radiation-induced DNA damage and during DNA replication (PubMed:17041588). DCX(ERCC8) (the CSA complex) plays a role in transcription-coupled repair (TCR) (PubMed:12732143). The DDB1-CUL4A-DTL E3 ligase complex regulates the circadian clock function by mediating the ubiquitination and degradation of CRY1 (PubMed:26431207). DDB1-mediated CRY1 degradation promotes FOXO1 protein stability and FOXO1-mediated gluconeogenesis in the liver (By similarity). By acting on TET dioxygenses, essential for oocyte maintenance at the primordial follicle stage, hence essential for female fertility (By similarity). Maternal factor required for proper zygotic genome activation and genome reprogramming (By similarity).', 'DDB1', 'Homo sapiens', '{[]}', '3D-structure, Acetylation, Alternative splicing, Biological rhythms, Cytoplasm, Disease variant, DNA damage, DNA repair, DNA-binding, Host-virus interaction, Intellectual disability, Isopeptide bond, Nucleus, Phosphoprotein, Reference proteome, Repeat, Ubl conjugation, Ubl conjugation pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (306, '1MRU', '', 'Serine/threonine-protein kinase PknB', 'Protein kinase that regulates many aspects of mycobacterial physiology, and is critical for growth in vitro and survival of the pathogen in the host (PubMed:24706757). Is a key component of a signal transduction pathway that regulates cell growth, cell shape and cell division via phosphorylation of target proteins such as GarA, GlmU, PapA5, FhaB (Rv0019c), FhaA (Rv0020c), MviN, PstP, EmbR, Rv1422, Rv1747, RseA and RmlA (PubMed:15978616, PubMed:15985609, PubMed:15987910, PubMed:16817899, PubMed:16980473, PubMed:19121323, PubMed:19826007, PubMed:20025669, PubMed:21423706, PubMed:22275220, PubMed:33868202). Also catalyzes the phosphorylation of the core proteasome alpha-subunit (PrcA), and thereby regulates the proteolytic activity of the proteasome (PubMed:25224505). Is a major regulator of the oxygen-dependent replication switch since PknB activity is necessary for reactivation of cells from the hypoxic state (PubMed:24409094). Shows a strong preference for Thr versus Ser as the phosphoacceptor. Overexpression of PknB alters cell morphology and leads to cell death (PubMed:24706757) (PubMed:24409094).', 'pknB', 'Mycobacterium tuberculosis (strain ATCC 25618 / H37Rv)', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cell membrane, Direct protein sequencing, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix, Virulence');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (307, '4YOM', '', 'Serine/threonine-protein kinase BRSK2', 'Serine/threonine-protein kinase that plays a key role in polarization of neurons and axonogenesis, cell cycle progress and insulin secretion. Phosphorylates CDK16, CDC25C, MAPT/TAU, PAK1 and WEE1. Following phosphorylation and activation by STK11/LKB1, acts as a key regulator of polarization of cortical neurons, probably by mediating phosphorylation of microtubule-associated proteins such as MAPT/TAU at ''Thr-504'' and ''Ser-554''. Also regulates neuron polarization by mediating phosphorylation of WEE1 at ''Ser-642'' in post-mitotic neurons, leading to down-regulate WEE1 activity in polarized neurons. Plays a role in the regulation of the mitotic cell cycle progress and the onset of mitosis. Plays a role in the regulation of insulin secretion in response to elevated glucose levels, probably via phosphorylation of CDK16 and PAK1. While BRSK2 phosphorylated at Thr-175 can inhibit insulin secretion (PubMed:22798068), BRSK2 phosphorylated at Thr-261 can promote insulin secretion (PubMed:22669945). Regulates reorganization of the actin cytoskeleton. May play a role in the apoptotic response triggered by endoplasmic reticulum (ER) stress.', 'Brsk2', 'Mus musculus', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell division, Cytoplasm, Cytoskeleton, Endoplasmic reticulum, Exocytosis, Kinase, Magnesium, Metal-binding, Mitosis, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (308, '2IWI', '', 'Serine/threonine-protein kinase pim-2', 'Proto-oncogene with serine/threonine kinase activity involved in cell survival and cell proliferation. Exerts its oncogenic activity through: the regulation of MYC transcriptional activity, the regulation of cell cycle progression, the regulation of cap-dependent protein translation and through survival signaling by phosphorylation of a pro-apoptotic protein, BAD. Phosphorylation of MYC leads to an increase of MYC protein stability and thereby an increase transcriptional activity. The stabilization of MYC exerted by PIM2 might explain partly the strong synergism between these 2 oncogenes in tumorigenesis. Regulates cap-dependent protein translation in a mammalian target of rapamycin complex 1 (mTORC1)-independent manner and in parallel to the PI3K-Akt pathway. Mediates survival signaling through phosphorylation of BAD, which induces release of the anti-apoptotic protein Bcl-X(L)/BCL2L1. Promotes cell survival in response to a variety of proliferative signals via positive regulation of the I-kappa-B kinase/NF-kappa-B cascade; this process requires phosphorylation of MAP3K8/COT. Promotes growth factor-independent proliferation by phosphorylation of cell cycle factors such as CDKN1A and CDKN1B. Involved in the positive regulation of chondrocyte survival and autophagy in the epiphyseal growth plate.', 'PIM2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Apoptosis, ATP-binding, Cell cycle, Kinase, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (574, '6YAT', '', 'Serine/threonine-protein kinase 4', 'Stress-activated, pro-apoptotic kinase which, following caspase-cleavage, enters the nucleus and induces chromatin condensation followed by internucleosomal DNA fragmentation. Key component of the Hippo signaling pathway which plays a pivotal role in organ size control and tumor suppression by restricting proliferation and promoting apoptosis. The core of this pathway is composed of a kinase cascade wherein STK3/MST2 and STK4/MST1, in complex with its regulatory protein SAV1, phosphorylates and activates LATS1/2 in complex with its regulatory protein MOB1, which in turn phosphorylates and inactivates YAP1 oncoprotein and WWTR1/TAZ. Phosphorylation of YAP1 by LATS2 inhibits its translocation into the nucleus to regulate cellular genes important for cell proliferation, cell death, and cell migration. STK3/MST2 and STK4/MST1 are required to repress proliferation of mature hepatocytes, to prevent activation of facultative adult liver stem cells (oval cells), and to inhibit tumor formation (By similarity). Phosphorylates ''Ser-14'' of histone H2B (H2BS14ph) during apoptosis. Phosphorylates FOXO3 upon oxidative stress, which results in its nuclear translocation and cell death initiation. Phosphorylates MOBKL1A, MOBKL1B and RASSF2. Phosphorylates TNNI3 (cardiac Tn-I) and alters its binding affinity to TNNC1 (cardiac Tn-C) and TNNT2 (cardiac Tn-T). Phosphorylates FOXO1 on ''Ser-212'' and regulates its activation and stimulates transcription of PMAIP1 in a FOXO1-dependent manner. Phosphorylates SIRT1 and inhibits SIRT1-mediated p53/TP53 deacetylation, thereby promoting p53/TP53 dependent transcription and apoptosis upon DNA damage. Acts as an inhibitor of PKB/AKT1. Phosphorylates AR on ''Ser-650'' and suppresses its activity by intersecting with PKB/AKT1 signaling and antagonizing formation of AR-chromatin complexes.', 'STK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Direct protein sequencing, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (309, '3K2L', '', 'Dual specificity tyrosine-phosphorylation-regulated kinase 2', 'Serine/threonine-protein kinase involved in the regulation of the mitotic cell cycle, cell proliferation, apoptosis, organization of the cytoskeleton and neurite outgrowth. Functions in part via its role in ubiquitin-dependent proteasomal protein degradation. Functions downstream of ATM and phosphorylates p53/TP53 at ''Ser-46'', and thereby contributes to the induction of apoptosis in response to DNA damage. Phosphorylates NFATC1, and thereby inhibits its accumulation in the nucleus and its transcription factor activity. Phosphorylates EIF2B5 at ''Ser-544'', enabling its subsequent phosphorylation and inhibition by GSK3B. Likewise, phosphorylation of NFATC1, CRMP2/DPYSL2 and CRMP4/DPYSL3 promotes their subsequent phosphorylation by GSK3B. May play a general role in the priming of GSK3 substrates. Inactivates GYS1 by phosphorylation at ''Ser-641'', and potentially also a second phosphorylation site, thus regulating glycogen synthesis. Mediates EDVP E3 ligase complex formation and is required for the phosphorylation and subsequent degradation of KATNA1. Phosphorylates TERT at ''Ser-457'', promoting TERT ubiquitination by the EDVP complex. Phosphorylates SIAH2, and thereby increases its ubiquitin ligase activity. Promotes the proteasomal degradation of MYC and JUN, and thereby regulates progress through the mitotic cell cycle and cell proliferation. Promotes proteasomal degradation of GLI2 and GLI3, and thereby plays a role in smoothened and sonic hedgehog signaling. Plays a role in cytoskeleton organization and neurite outgrowth via its phosphorylation of DCX and DPYSL2. Phosphorylates CRMP2/DPYSL2, CRMP4/DPYSL3, DCX, EIF2B5, EIF4EBP1, GLI2, GLI3, GYS1, JUN, MDM2, MYC, NFATC1, p53/TP53, TAU/MAPT and KATNA1. Can phosphorylate histone H1, histone H3 and histone H2B (in vitro). Can phosphorylate CARHSP1 (in vitro).', 'DYRK2', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Kinase, Magnesium, Manganese, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase, Ubl conjugation, Ubl conjugation pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (310, '3VN9', '', 'Dual specificity mitogen-activated protein kinase kinase 6', 'Dual specificity protein kinase which acts as an essential component of the MAP kinase signal transduction pathway. With MAP3K3/MKK3, catalyzes the concomitant phosphorylation of a threonine and a tyrosine residue in the MAP kinases p38 MAPK11, MAPK12, MAPK13 and MAPK14 and plays an important role in the regulation of cellular responses to cytokines and all kinds of stresses. Especially, MAP2K3/MKK3 and MAP2K6/MKK6 are both essential for the activation of MAPK11 and MAPK13 induced by environmental stress, whereas MAP2K6/MKK6 is the major MAPK11 activator in response to TNF. MAP2K6/MKK6 also phosphorylates and activates PAK6. The p38 MAP kinase signal transduction pathway leads to direct activation of transcription factors. Nuclear targets of p38 MAP kinase include the transcription factors ATF2 and ELK1. Within the p38 MAPK signal transduction pathway, MAP3K6/MKK6 mediates phosphorylation of STAT4 through MAPK14 activation, and is therefore required for STAT4 activation and STAT4-regulated gene expression in response to IL-12 stimulation. The pathway is also crucial for IL-6-induced SOCS3 expression and down-regulation of IL-6-mediated gene induction; and for IFNG-dependent gene transcription. Has a role in osteoclast differentiation through NF-kappa-B transactivation by TNFSF11, and in endochondral ossification and since SOX9 is another likely downstream target of the p38 MAPK pathway. MAP2K6/MKK6 mediates apoptotic cell death in thymocytes. Acts also as a regulator for melanocytes dendricity, through the modulation of Rho family GTPases.', 'MAP2K6', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Cytoskeleton, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (311, '6KHE', '', 'Dual specificity protein kinase CLK2', 'Dual specificity kinase acting on both serine/threonine and tyrosine-containing substrates. Phosphorylates serine- and arginine-rich (SR) proteins of the spliceosomal complex. May be a constituent of a network of regulatory mechanisms that enable SR proteins to control RNA splicing and can cause redistribution of SR proteins from speckles to a diffuse nucleoplasmic distribution. Acts as a suppressor of hepatic gluconeogenesis and glucose output by repressing PPARGC1A transcriptional activity on gluconeogenic genes via its phosphorylation. Phosphorylates PPP2R5B thereby stimulating the assembly of PP2A phosphatase with the PPP2R5B-AKT1 complex leading to dephosphorylation of AKT1. Phosphorylates: PTPN1, SRSF1 and SRSF3. Regulates the alternative splicing of tissue factor (F3) pre-mRNA in endothelial cells. Phosphorylates PAGE4 at several serine and threonine residues and this phosphorylation attenuates the ability of PAGE4 to potentiate the transcriptional activator activity of JUN (PubMed:28289210).', 'CLK2', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (312, '5YKS', '', 'SNF-related serine/threonine-protein kinase', 'May play a role in hematopoietic cell proliferation or differentiation. Potential mediator of neuronal apoptosis.', 'SNRK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Magnesium, Metal-binding, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (313, '4YNZ', '', 'Serine/threonine-protein kinase BRSK2', 'Serine/threonine-protein kinase that plays a key role in polarization of neurons and axonogenesis, cell cycle progress and insulin secretion. Phosphorylates CDK16, CDC25C, MAPT/TAU, PAK1 and WEE1. Following phosphorylation and activation by STK11/LKB1, acts as a key regulator of polarization of cortical neurons, probably by mediating phosphorylation of microtubule-associated proteins such as MAPT/TAU at ''Thr-504'' and ''Ser-554''. Also regulates neuron polarization by mediating phosphorylation of WEE1 at ''Ser-642'' in post-mitotic neurons, leading to down-regulate WEE1 activity in polarized neurons. Plays a role in the regulation of the mitotic cell cycle progress and the onset of mitosis. Plays a role in the regulation of insulin secretion in response to elevated glucose levels, probably via phosphorylation of CDK16 and PAK1. While BRSK2 phosphorylated at Thr-175 can inhibit insulin secretion (PubMed:22798068), BRSK2 phosphorylated at Thr-261 can promote insulin secretion (PubMed:22669945). Regulates reorganization of the actin cytoskeleton. May play a role in the apoptotic response triggered by endoplasmic reticulum (ER) stress.', 'Brsk2', 'Mus musculus', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell division, Cytoplasm, Cytoskeleton, Endoplasmic reticulum, Exocytosis, Kinase, Magnesium, Metal-binding, Mitosis, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (314, '5HVJ', '', 'LIM domain kinase 1', 'Serine/threonine-protein kinase that plays an essential role in the regulation of actin filament dynamics. Acts downstream of several Rho family GTPase signal transduction pathways (PubMed:10436159, PubMed:11832213, PubMed:12807904, PubMed:15660133, PubMed:16230460, PubMed:18028908, PubMed:22328514, PubMed:23633677). Activated by upstream kinases including ROCK1, PAK1 and PAK4, which phosphorylate LIMK1 on a threonine residue located in its activation loop (PubMed:10436159). LIMK1 subsequently phosphorylates and inactivates the actin binding/depolymerizing factors cofilin-1/CFL1, cofilin-2/CFL2 and destrin/DSTN, thereby preventing the cleavage of filamentous actin (F-actin), and stabilizing the actin cytoskeleton (PubMed:11832213, PubMed:15660133, PubMed:16230460, PubMed:23633677). In this way LIMK1 regulates several actin-dependent biological processes including cell motility, cell cycle progression, and differentiation (PubMed:11832213, PubMed:15660133, PubMed:16230460, PubMed:23633677). Phosphorylates TPPP on serine residues, thereby promoting microtubule disassembly (PubMed:18028908). Stimulates axonal outgrowth and may be involved in brain development (PubMed:18028908).', 'LIMK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Cytoplasm, Cytoskeleton, Kinase, LIM domain, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Ubl conjugation, Williams-Beuren syndrome, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (315, '1KWP', '', 'MAP kinase-activated protein kinase 2', 'Stress-activated serine/threonine-protein kinase involved in cytokine production, endocytosis, reorganization of the cytoskeleton, cell migration, cell cycle control, chromatin remodeling, DNA damage response and transcriptional regulation. Following stress, it is phosphorylated and activated by MAP kinase p38-alpha/MAPK14, leading to phosphorylation of substrates. Phosphorylates serine in the peptide sequence, Hyd-X-R-X(2)-S, where Hyd is a large hydrophobic residue. Phosphorylates ALOX5, CDC25B, CDC25C, CEP131, ELAVL1, HNRNPA0, HSP27/HSPB1, KRT18, KRT20, LIMK1, LSP1, PABPC1, PARN, PDE4A, RCSD1, RPS6KA3, TAB3 and TTP/ZFP36. Phosphorylates HSF1; leading to the interaction with HSP90 proteins and inhibiting HSF1 homotrimerization, DNA-binding and transactivation activities (PubMed:16278218). Mediates phosphorylation of HSP27/HSPB1 in response to stress, leading to the dissociation of HSP27/HSPB1 from large small heat-shock protein (sHsps) oligomers and impairment of their chaperone activities and ability to protect against oxidative stress effectively. Involved in inflammatory response by regulating tumor necrosis factor (TNF) and IL6 production post-transcriptionally: acts by phosphorylating AU-rich elements (AREs)-binding proteins ELAVL1, HNRNPA0, PABPC1 and TTP/ZFP36, leading to the regulation of the stability and translation of TNF and IL6 mRNAs. Phosphorylation of TTP/ZFP36, a major post-transcriptional regulator of TNF, promotes its binding to 14-3-3 proteins and reduces its ARE mRNA affinity, leading to inhibition of dependent degradation of ARE-containing transcripts. Phosphorylates CEP131 in response to cellular stress induced by ultraviolet irradiation which promotes binding of CEP131 to 14-3-3 proteins and inhibits formation of novel centriolar satellites (PubMed:26616734). Also involved in late G2/M checkpoint following DNA damage through a process of post-transcriptional mRNA stabilization: following DNA damage, relocalizes from nucleus to cytoplasm and phosphorylates HNRNPA0 and PARN, leading to stabilization of GADD45A mRNA. Involved in toll-like receptor signaling pathway (TLR) in dendritic cells: required for acute TLR-induced macropinocytosis by phosphorylating and activating RPS6KA3.', 'MAPKAPK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, DNA damage, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (316, '4TPT', '', 'LIM domain kinase 2', 'Serine/threonine-protein kinase that plays an essential role in the regulation of actin filament dynamics (PubMed:10436159, PubMed:11018042). Acts downstream of several Rho family GTPase signal transduction pathways (PubMed:10436159, PubMed:11018042). Involved in astral microtubule organization and mitotic spindle orientation during early stages of mitosis by mediating phosphorylation of TPPP (PubMed:22328514). Displays serine/threonine-specific phosphorylation of myelin basic protein and histone (MBP) in vitro (PubMed:8537403). Suppresses ciliogenesis via multiple pathways; phosphorylation of CFL1, suppression of directional trafficking of ciliary vesicles to the ciliary base, and by facilitating YAP1 nuclear localization where it acts as a transcriptional corepressor of the TEAD4 target genes AURKA and PLK1 (PubMed:25849865).', 'LIMK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Kinase, LIM domain, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (317, '7B30', '', 'Serine/threonine-protein kinase 24', 'Serine/threonine-protein kinase that acts on both serine and threonine residues and promotes apoptosis in response to stress stimuli and caspase activation. Mediates oxidative-stress-induced cell death by modulating phosphorylation of JNK1-JNK2 (MAPK8 and MAPK9), p38 (MAPK11, MAPK12, MAPK13 and MAPK14) during oxidative stress. Plays a role in a staurosporine-induced caspase-independent apoptotic pathway by regulating the nuclear translocation of AIFM1 and ENDOG and the DNase activity associated with ENDOG. Phosphorylates STK38L on ''Thr-442'' and stimulates its kinase activity. In association with STK26 negatively regulates Golgi reorientation in polarized cell migration upon RHO activation (PubMed:27807006). Regulates also cellular migration with alteration of PTPN12 activity and PXN phosphorylation: phosphorylates PTPN12 and inhibits its activity and may regulate PXN phosphorylation through PTPN12. May act as a key regulator of axon regeneration in the optic nerve and radial nerve.', 'STK24', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (318, '4G16', '', 'Casein kinase I isoform gamma-3', 'Serine/threonine-protein kinase. Casein kinases are operationally defined by their preferential utilization of acidic proteins such as caseins as substrates. It can phosphorylate a large number of proteins. Participates in Wnt signaling. Regulates fast synaptic transmission mediated by glutamate (By similarity).', 'CSNK1G3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (319, '4EC8', '', 'Cyclin-dependent kinase 9', 'Protein kinase involved in the regulation of transcription (PubMed:10574912, PubMed:10757782, PubMed:11145967, PubMed:11575923, PubMed:11809800, PubMed:11884399, PubMed:14701750, PubMed:16109376, PubMed:16109377, PubMed:20930849, PubMed:28426094, PubMed:29335245). Member of the cyclin-dependent kinase pair (CDK9/cyclin-T) complex, also called positive transcription elongation factor b (P-TEFb), which facilitates the transition from abortive to productive elongation by phosphorylating the CTD (C-terminal domain) of the large subunit of RNA polymerase II (RNAP II) POLR2A, SUPT5H and RDBP (PubMed:10574912, PubMed:10757782, PubMed:11145967, PubMed:11575923, PubMed:11809800, PubMed:11884399, PubMed:14701750, PubMed:16109376, PubMed:16109377, PubMed:20930849, PubMed:28426094, PubMed:30134174). This complex is inactive when in the 7SK snRNP complex form (PubMed:10574912, PubMed:10757782, PubMed:11145967, PubMed:11575923, PubMed:11809800, PubMed:11884399, PubMed:14701750, PubMed:16109376, PubMed:16109377, PubMed:20930849, PubMed:28426094). Phosphorylates EP300, MYOD1, RPB1/POLR2A and AR and the negative elongation factors DSIF and NELFE (PubMed:9857195, PubMed:10912001, PubMed:11112772, PubMed:12037670, PubMed:20081228, PubMed:20980437, PubMed:21127351). Regulates cytokine inducible transcription networks by facilitating promoter recognition of target transcription factors (e.g. TNF-inducible RELA/p65 activation and IL-6-inducible STAT3 signaling) (PubMed:17956865, PubMed:18362169). Promotes RNA synthesis in genetic programs for cell growth, differentiation and viral pathogenesis (PubMed:10393184, PubMed:11112772). P-TEFb is also involved in cotranscriptional histone modification, mRNA processing and mRNA export (PubMed:15564463, PubMed:19575011, PubMed:19844166). Modulates a complex network of chromatin modifications including histone H2B monoubiquitination (H2Bub1), H3 lysine 4 trimethylation (H3K4me3) and H3K36me3; integrates phosphorylation during transcription with chromatin modifications to control co-transcriptional histone mRNA processing (PubMed:15564463, PubMed:19575011, PubMed:19844166). The CDK9/cyclin-K complex has also a kinase activity towards CTD of RNAP II and can substitute for CDK9/cyclin-T P-TEFb in vitro (PubMed:21127351). Replication stress response protein; the CDK9/cyclin-K complex is required for genome integrity maintenance, by promoting cell cycle recovery from replication arrest and limiting single-stranded DNA amount in response to replication stress, thus reducing the breakdown of stalled replication forks and avoiding DNA damage (PubMed:20493174). In addition, probable function in DNA repair of isoform 2 via interaction with KU70/XRCC6 (PubMed:20493174). Promotes cardiac myocyte enlargement (PubMed:20081228). RPB1/POLR2A phosphorylation on ''Ser-2'' in CTD activates transcription (PubMed:21127351). AR phosphorylation modulates AR transcription factor promoter selectivity and cell growth. DSIF and NELF phosphorylation promotes transcription by inhibiting their negative effect (PubMed:9857195, PubMed:10912001, PubMed:11112772). The phosphorylation of MYOD1 enhances its transcriptional activity and thus promotes muscle differentiation (PubMed:12037670). Catalyzes phosphorylation of KAT5, promoting KAT5 recruitment to chromatin and histone acetyltransferase activity (PubMed:29335245).', 'CDK9', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, DNA damage, DNA repair, Host-virus interaction, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (320, '6GR8', '', 'Aurora kinase C', 'Serine/threonine-protein kinase component of the chromosomal passenger complex (CPC), a complex that acts as a key regulator of mitosis. The CPC complex has essential functions at the centromere in ensuring correct chromosome alignment and segregation and is required for chromatin-induced microtubule stabilization and spindle assembly. Also plays a role in meiosis and more particularly in spermatogenesis. Has redundant cellular functions with AURKB and can rescue an AURKB knockdown. Like AURKB, AURKC phosphorylates histone H3 at ''Ser-10'' and ''Ser-28''. AURKC phosphorylates the CPC complex subunits BIRC5/survivin and INCENP leading to increased AURKC activity. Phosphorylates TACC1, another protein involved in cell division, at ''Ser-228''.', 'AURKC', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cell division, Centromere, Chromosome, Cytoplasm, Cytoskeleton, Kinase, Meiosis, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (321, '5TWU', '', 'Maternal embryonic leucine zipper kinase', 'Serine/threonine-protein kinase involved in various processes such as cell cycle regulation, self-renewal of stem cells, apoptosis and splicing regulation. Has a broad substrate specificity; phosphorylates BCL2L14, CDC25B, MAP3K5/ASK1 and ZNF622. Acts as an activator of apoptosis by phosphorylating and activating MAP3K5/ASK1. Acts as a regulator of cell cycle, notably by mediating phosphorylation of CDC25B, promoting localization of CDC25B to the centrosome and the spindle poles during mitosis. Plays a key role in cell proliferation and carcinogenesis. Required for proliferation of embryonic and postnatal multipotent neural progenitors. Phosphorylates and inhibits BCL2L14, possibly leading to affect mammary carcinogenesis by mediating inhibition of the pro-apoptotic function of BCL2L14. Also involved in the inhibition of spliceosome assembly during mitosis by phosphorylating ZNF622, thereby contributing to its redirection to the nucleus. May also play a role in primitive hematopoiesis.', 'MELK', 'Homo sapiens', '{[''2.7.10.2'',''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Calcium, Cell cycle, Cell membrane, Kinase, Lipid-binding, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (322, '5UPL', '', 'Serine/threonine-protein kinase PAK 4', 'Serine/threonine protein kinase that plays a role in a variety of different signaling pathways including cytoskeleton regulation, cell migration, growth, proliferation or cell survival. Activation by various effectors including growth factor receptors or active CDC42 and RAC1 results in a conformational change and a subsequent autophosphorylation on several serine and/or threonine residues. Phosphorylates and inactivates the protein phosphatase SSH1, leading to increased inhibitory phosphorylation of the actin binding/depolymerizing factor cofilin. Decreased cofilin activity may lead to stabilization of actin filaments. Phosphorylates LIMK1, a kinase that also inhibits the activity of cofilin. Phosphorylates integrin beta5/ITGB5 and thus regulates cell motility. Phosphorylates ARHGEF2 and activates the downstream target RHOA that plays a role in the regulation of assembly of focal adhesions and actin stress fibers. Stimulates cell survival by phosphorylating the BCL2 antagonist of cell death BAD. Alternatively, inhibits apoptosis by preventing caspase-8 binding to death domain receptors in a kinase independent manner. Plays a role in cell-cycle progression by controlling levels of the cell-cycle regulatory protein CDKN1A and by phosphorylating RAN.', 'PAK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Kinase, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (323, '4RPV', '', 'Serine/threonine-protein kinase pim-1', 'Proto-oncogene with serine/threonine kinase activity involved in cell survival and cell proliferation and thus providing a selective advantage in tumorigenesis (PubMed:15528381, PubMed:1825810, PubMed:31548394). Exerts its oncogenic activity through: the regulation of MYC transcriptional activity, the regulation of cell cycle progression and by phosphorylation and inhibition of proapoptotic proteins (BAD, MAP3K5, FOXO3) (PubMed:18593906). Phosphorylation of MYC leads to an increase of MYC protein stability and thereby an increase of transcriptional activity (By similarity). The stabilization of MYC exerted by PIM1 might explain partly the strong synergism between these two oncogenes in tumorigenesis (By similarity). Mediates survival signaling through phosphorylation of BAD, which induces release of the anti-apoptotic protein Bcl-X(L)/BCL2L1 (By similarity). Phosphorylation of MAP3K5, another proapoptotic protein, by PIM1, significantly decreases MAP3K5 kinase activity and inhibits MAP3K5-mediated phosphorylation of JNK and JNK/p38MAPK subsequently reducing caspase-3 activation and cell apoptosis (PubMed:19749799). Stimulates cell cycle progression at the G1-S and G2-M transitions by phosphorylation of CDC25A and CDC25C (PubMed:16356754). Phosphorylation of CDKN1A, a regulator of cell cycle progression at G1, results in the relocation of CDKN1A to the cytoplasm and enhanced CDKN1A protein stability (PubMed:12431783). Promotes cell cycle progression and tumorigenesis by down-regulating expression of a regulator of cell cycle progression, CDKN1B, at both transcriptional and post-translational levels (PubMed:18593906). Phosphorylation of CDKN1B, induces 14-3-3 proteins binding, nuclear export and proteasome-dependent degradation (PubMed:18593906). May affect the structure or silencing of chromatin by phosphorylating HP1 gamma/CBX3 (PubMed:10664448). Acts also as a regulator of homing and migration of bone marrow cells involving functional interaction with the CXCL12-CXCR4 signaling axis (By similarity). Acts as a positive regulator of mTORC1 signaling by mediating phosphorylation and inhibition of DEPDC5 component of the GATOR1 complex (PubMed:31548394). Acts as a negative regulator of innate immunity by mediating phosphorylation and inactivation of GBP1 in absence of infection: phosphorylation of GBP1 induces interaction with 14-3-3 protein sigma (SFN) and retention in the cytosol (PubMed:37797010). Also phosphorylates and activates the ATP-binding cassette transporter ABCG2, allowing resistance to drugs through their excretion from cells (PubMed:18056989). Promotes brown adipocyte differentiation (By similarity).', 'PIM1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative initiation, Apoptosis, ATP-binding, Cell cycle, Cell membrane, Cytoplasm, Direct protein sequencing, Host-virus interaction, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (324, '5EBZ', '', 'Inhibitor of nuclear factor kappa-B kinase subunit alpha', 'Serine kinase that plays an essential role in the NF-kappa-B signaling pathway which is activated by multiple stimuli such as inflammatory cytokines, bacterial or viral products, DNA damages or other cellular stresses (PubMed:9244310, PubMed:9252186, PubMed:9346484, PubMed:18626576). Acts as a part of the canonical IKK complex in the conventional pathway of NF-kappa-B activation and phosphorylates inhibitors of NF-kappa-B on serine residues (PubMed:9244310, PubMed:9252186, PubMed:9346484, PubMed:18626576, PubMed:35952808). These modifications allow polyubiquitination of the inhibitors and subsequent degradation by the proteasome (PubMed:9244310, PubMed:9252186, PubMed:9346484, PubMed:18626576). In turn, free NF-kappa-B is translocated into the nucleus and activates the transcription of hundreds of genes involved in immune response, growth control, or protection against apoptosis (PubMed:9244310, PubMed:9252186, PubMed:9346484, PubMed:18626576). Negatively regulates the pathway by phosphorylating the scaffold protein TAXBP1 and thus promoting the assembly of the A20/TNFAIP3 ubiquitin-editing complex (composed of A20/TNFAIP3, TAX1BP1, and the E3 ligases ITCH and RNF11) (PubMed:21765415). Therefore, CHUK plays a key role in the negative feedback of NF-kappa-B canonical signaling to limit inflammatory gene activation. As part of the non-canonical pathway of NF-kappa-B activation, the MAP3K14-activated CHUK/IKKA homodimer phosphorylates NFKB2/p100 associated with RelB, inducing its proteolytic processing to NFKB2/p52 and the formation of NF-kappa-B RelB-p52 complexes (PubMed:20501937). In turn, these complexes regulate genes encoding molecules involved in B-cell survival and lymphoid organogenesis. Participates also in the negative feedback of the non-canonical NF-kappa-B signaling pathway by phosphorylating and destabilizing MAP3K14/NIK. Within the nucleus, phosphorylates CREBBP and consequently increases both its transcriptional and histone acetyltransferase activities (PubMed:17434128). Modulates chromatin accessibility at NF-kappa-B-responsive promoters by phosphorylating histones H3 at ''Ser-10'' that are subsequently acetylated at ''Lys-14'' by CREBBP (PubMed:12789342). Additionally, phosphorylates the CREBBP-interacting protein NCOA3. Also phosphorylates FOXO3 and may regulate this pro-apoptotic transcription factor (PubMed:15084260). Phosphorylates RIPK1 at ''Ser-25'' which represses its kinase activity and consequently prevents TNF-mediated RIPK1-dependent cell death (By similarity). Phosphorylates AMBRA1 following mitophagy induction, promoting AMBRA1 interaction with ATG8 family proteins and its mitophagic activity (PubMed:30217973).', 'CHUK', 'Homo sapiens', '{[''2.7.11.10'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Direct protein sequencing, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (325, '4TZ7', '', 'Phosphatidylinositol-4-phosphate 5-kinase type-1 gamma', 'Unknown', 'pip5k1aa', 'Danio rerio', '{[''2.7.1.68'']}', '3D-structure, ATP-binding, Calcium, Kinase, Metal-binding, Nucleotide-binding, Proteomics identification, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (326, '2AC3', '', 'MAP kinase-interacting serine/threonine-protein kinase 2', 'Serine/threonine-protein kinase that phosphorylates SFPQ/PSF, HNRNPA1 and EIF4E. May play a role in the response to environmental stress and cytokines. Appears to regulate translation by phosphorylating EIF4E, thus increasing the affinity of this protein for the 7-methylguanosine-containing mRNA cap. Required for mediating PP2A-inhibition-induced EIF4E phosphorylation. Triggers EIF4E shuttling from cytoplasm to nucleus. Isoform 1 displays a high basal kinase activity, but isoform 2 exhibits a very low kinase activity. Acts as a mediator of the suppressive effects of IFNgamma on hematopoiesis. Negative regulator for signals that control generation of arsenic trioxide As(2)O(3)-dependent apoptosis and anti-leukemic responses. Involved in anti-apoptotic signaling in response to serum withdrawal.', 'MKNK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Translation regulation, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (327, '3G33', '', 'Cyclin-dependent kinase 4', 'Ser/Thr-kinase component of cyclin D-CDK4 (DC) complexes that phosphorylate and inhibit members of the retinoblastoma (RB) protein family including RB1 and regulate the cell-cycle during G(1)/S transition. Phosphorylation of RB1 allows dissociation of the transcription factor E2F from the RB/E2F complexes and the subsequent transcription of E2F target genes which are responsible for the progression through the G(1) phase. Hypophosphorylates RB1 in early G(1) phase. Cyclin D-CDK4 complexes are major integrators of various mitogenenic and antimitogenic signals. Also phosphorylates SMAD3 in a cell-cycle-dependent manner and represses its transcriptional activity. Component of the ternary complex, cyclin D/CDK4/CDKN1B, required for nuclear translocation and activity of the cyclin D-CDK4 complex.', 'CDK4', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cell division, Cytoplasm, Disease variant, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (328, '7XZQ', '', 'TRAF2 and NCK-interacting protein kinase', 'Serine/threonine kinase that acts as an essential activator of the Wnt signaling pathway. Recruited to promoters of Wnt target genes and required to activate their expression. May act by phosphorylating TCF4/TCF7L2. Appears to act upstream of the JUN N-terminal pathway. May play a role in the response to environmental stress. Part of a signaling complex composed of NEDD4, RAP2A and TNIK which regulates neuronal dendrite extension and arborization during development. More generally, it may play a role in cytoskeletal rearrangements and regulate cell spreading. Phosphorylates SMAD1 on Thr-322.', 'TNIK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Endosome, Intellectual disability, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (329, '6KZC', '', 'NT-3 growth factor receptor', 'Receptor tyrosine kinase involved in nervous system and probably heart development. Upon binding of its ligand NTF3/neurotrophin-3, NTRK3 autophosphorylates and activates different signaling pathways, including the phosphatidylinositol 3-kinase/AKT and the MAPK pathways, that control cell survival and differentiation.', 'NTRK3', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Developmental protein, Differentiation, Direct protein sequencing, Disulfide bond, Glycoprotein, Immunoglobulin domain, Kinase, Leucine-rich repeat, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (330, '5OMY', '', 'Casein kinase II subunit alpha', 'Catalytic subunit of a constitutively active serine/threonine-protein kinase complex that phosphorylates a large number of substrates containing acidic residues C-terminal to the phosphorylated serine or threonine (PubMed:11239457, PubMed:11704824, PubMed:16193064, PubMed:19188443, PubMed:20545769, PubMed:20625391, PubMed:22017874, PubMed:22406621, PubMed:24962073, PubMed:30898438, PubMed:31439799). Regulates numerous cellular processes, such as cell cycle progression, apoptosis and transcription, as well as viral infection (PubMed:12631575, PubMed:19387552, PubMed:19387551). May act as a regulatory node which integrates and coordinates numerous signals leading to an appropriate cellular response (PubMed:12631575, PubMed:19387552, PubMed:19387551). During mitosis, functions as a component of the p53/TP53-dependent spindle assembly checkpoint (SAC) that maintains cyclin-B-CDK1 activity and G2 arrest in response to spindle damage (PubMed:11704824, PubMed:19188443). Also required for p53/TP53-mediated apoptosis, phosphorylating ''Ser-392'' of p53/TP53 following UV irradiation (PubMed:11239457). Phosphorylates a number of DNA repair proteins in response to DNA damage, such as MDC1, RAD9A, RAD51 and HTATSF1, promoting their recruitment to DNA damage sites (PubMed:20545769, PubMed:21482717, PubMed:22325354, PubMed:26811421, PubMed:30898438, PubMed:35597237). Can also negatively regulate apoptosis (PubMed:16193064, PubMed:22184066). Phosphorylates the caspases CASP9 and CASP2 and the apoptotic regulator NOL3 (PubMed:16193064). Phosphorylation protects CASP9 from cleavage and activation by CASP8, and inhibits the dimerization of CASP2 and activation of CASP8 (PubMed:16193064). Phosphorylates YY1, protecting YY1 from cleavage by CASP7 during apoptosis (PubMed:22184066). Regulates transcription by direct phosphorylation of RNA polymerases I, II, III and IV (PubMed:19387550, PubMed:12631575, PubMed:19387552, PubMed:19387551, PubMed:23123191). Also phosphorylates and regulates numerous transcription factors including NF-kappa-B, STAT1, CREB1, IRF1, IRF2, ATF1, ATF4, SRF, MAX, JUN, FOS, MYC and MYB (PubMed:19387550, PubMed:12631575, PubMed:19387552, PubMed:19387551, PubMed:23123191). Phosphorylates Hsp90 and its co-chaperones FKBP4 and CDC37, which is essential for chaperone function (PubMed:19387550). Mediates sequential phosphorylation of FNIP1, promoting its gradual interaction with Hsp90, leading to activate both kinase and non-kinase client proteins of Hsp90 (PubMed:30699359). Regulates Wnt signaling by phosphorylating CTNNB1 and the transcription factor LEF1 (PubMed:19387549). Acts as an ectokinase that phosphorylates several extracellular proteins (PubMed:19387550, PubMed:12631575, PubMed:19387552, PubMed:19387551). During viral infection, phosphorylates various proteins involved in the viral life cycles of EBV, HSV, HBV, HCV, HIV, CMV and HPV (PubMed:19387550, PubMed:12631575, PubMed:19387552, PubMed:19387551). Phosphorylates PML at ''Ser-565'' and primes it for ubiquitin-mediated degradation (PubMed:20625391, PubMed:22406621). Plays an important role in the circadian clock function by phosphorylating BMAL1 at ''Ser-90'' which is pivotal for its interaction with CLOCK and which controls CLOCK nuclear entry (By similarity). Phosphorylates CCAR2 at ''Thr-454'' in gastric carcinoma tissue (PubMed:24962073). Phosphorylates FMR1, promoting FMR1-dependent formation of a membraneless compartment (PubMed:30765518, PubMed:31439799).', 'CSNK2A1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Biological rhythms, Cell cycle, Disease variant, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (331, '1S9I', '', 'Dual specificity mitogen-activated protein kinase kinase 2', 'Catalyzes the concomitant phosphorylation of a threonine and a tyrosine residue in a Thr-Glu-Tyr sequence located in MAP kinases. Activates the ERK1 and ERK2 MAP kinases (By similarity). Activates BRAF in a KSR1 or KSR2-dependent manner; by binding to KSR1 or KSR2 releases the inhibitory intramolecular interaction between KSR1 or KSR2 protein kinase and N-terminal domains which promotes KSR1 or KSR2-BRAF dimerization and BRAF activation (PubMed:29433126).', 'MAP2K2', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, ATP-binding, Cardiomyopathy, Cytoplasm, Direct protein sequencing, Disease variant, Ectodermal dysplasia, Intellectual disability, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (332, '3V2A', '', 'Vascular endothelial growth factor receptor 2', 'Tyrosine-protein kinase that acts as a cell-surface receptor for VEGFA, VEGFC and VEGFD. Plays an essential role in the regulation of angiogenesis, vascular development, vascular permeability, and embryonic hematopoiesis. Promotes proliferation, survival, migration and differentiation of endothelial cells. Promotes reorganization of the actin cytoskeleton. Isoforms lacking a transmembrane domain, such as isoform 2 and isoform 3, may function as decoy receptors for VEGFA, VEGFC and/or VEGFD. Isoform 2 plays an important role as negative regulator of VEGFA- and VEGFC-mediated lymphangiogenesis by limiting the amount of free VEGFA and/or VEGFC and preventing their binding to FLT4. Modulates FLT1 and FLT4 signaling by forming heterodimers. Binding of vascular growth factors to isoform 1 leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate and the activation of protein kinase C. Mediates activation of MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. Mediates phosphorylation of PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase, reorganization of the actin cytoskeleton and activation of PTK2/FAK1. Required for VEGFA-mediated induction of NOS2 and NOS3, leading to the production of the signaling molecule nitric oxide (NO) by endothelial cells. Phosphorylates PLCG1. Promotes phosphorylation of FYN, NCK1, NOS3, PIK3R1, PTK2/FAK1 and SRC.', 'KDR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Cytoplasmic vesicle, Developmental protein, Differentiation, Disulfide bond, Endoplasmic reticulum, Endosome, Glycoprotein, Host-virus interaction, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (333, '2GSF', '', 'Ephrin type-A receptor 3', 'Receptor tyrosine kinase which binds promiscuously membrane-bound ephrin family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Highly promiscuous for ephrin-A ligands it binds preferentially EFNA5. Upon activation by EFNA5 regulates cell-cell adhesion, cytoskeletal organization and cell migration. Plays a role in cardiac cells migration and differentiation and regulates the formation of the atrioventricular canal and septum during development probably through activation by EFNA1. Involved in the retinotectal mapping of neurons. May also control the segregation but not the guidance of motor and sensory axons during neuromuscular circuit development.', 'EPHA3', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell membrane, Direct protein sequencing, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (334, '2J90', '', 'Death-associated protein kinase 3', 'Serine/threonine kinase which is involved in the regulation of apoptosis, autophagy, transcription, translation and actin cytoskeleton reorganization. Involved in the regulation of smooth muscle contraction. Regulates both type I (caspase-dependent) apoptotic and type II (caspase-independent) autophagic cell deaths signal, depending on the cellular setting. Involved in regulation of starvation-induced autophagy. Regulates myosin phosphorylation in both smooth muscle and non-muscle cells. In smooth muscle, regulates myosin either directly by phosphorylating MYL12B and MYL9 or through inhibition of smooth muscle myosin phosphatase (SMPP1M) via phosphorylation of PPP1R12A; the inhibition of SMPP1M functions to enhance muscle responsiveness to Ca(2+) and promote a contractile state. Phosphorylates MYL12B in non-muscle cells leading to reorganization of actin cytoskeleton. Isoform 2 can phosphorylate myosin, PPP1R12A and MYL12B. Overexpression leads to condensation of actin stress fibers into thick bundles. Involved in actin filament focal adhesion dynamics. The function in both reorganization of actin cytoskeleton and focal adhesion dissolution is modulated by RhoD. Positively regulates canonical Wnt/beta-catenin signaling through interaction with NLK and TCF7L2. Phosphorylates RPL13A on ''Ser-77'' upon interferon-gamma activation which is causing RPL13A release from the ribosome, RPL13A association with the GAIT complex and its subsequent involvement in transcript-selective translation inhibition. Enhances transcription from AR-responsive promoters in a hormone- and kinase-dependent manner. Involved in regulation of cell cycle progression and cell proliferation. May be a tumor suppressor.', 'DAPK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Activator, Alternative splicing, Apoptosis, ATP-binding, Chromatin regulator, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Translation regulation, Tumor suppressor');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (335, '5EFQ', '', 'Cyclin-dependent kinase 13', 'Cyclin-dependent kinase which displays CTD kinase activity and is required for RNA splicing. Has CTD kinase activity by hyperphosphorylating the C-terminal heptapeptide repeat domain (CTD) of the largest RNA polymerase II subunit RPB1, thereby acting as a key regulator of transcription elongation. Required for RNA splicing, probably by phosphorylating SRSF1/SF2. Required during hematopoiesis. In case of infection by HIV-1 virus, interacts with HIV-1 Tat protein acetylated at ''Lys-50'' and ''Lys-51'', thereby increasing HIV-1 mRNA splicing and promoting the production of the doubly spliced HIV-1 protein Nef.', 'CDK13', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Disease variant, Host-virus interaction, Intellectual disability, Isopeptide bond, Kinase, mRNA processing, mRNA splicing, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, RNA editing, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (336, '4UYA', '', 'Mitogen-activated protein kinase kinase kinase 21', 'Negative regulator of TLR4 signaling. Does not activate JNK1/MAPK8 pathway, p38/MAPK14, nor ERK2/MAPK1 pathways.', 'MAP3K21', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, SH3 domain, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (337, '1ZMU', '', 'Serine/threonine-protein kinase MARK2', 'Serine/threonine-protein kinase. Involved in cell polarity and microtubule dynamics regulation. Phosphorylates CRTC2/TORC2, DCX, HDAC7, KIF13B, MAP2, MAP4 and RAB11FIP2. Phosphorylates the microtubule-associated protein MAPT/TAU. Plays a key role in cell polarity by phosphorylating the microtubule-associated proteins MAP2, MAP4 and MAPT/TAU at KXGS motifs, causing detachment from microtubules, and their disassembly. Regulates epithelial cell polarity by phosphorylating RAB11FIP2. Involved in the regulation of neuronal migration through its dual activities in regulating cellular polarity and microtubule dynamics, possibly by phosphorylating and regulating DCX. Regulates axogenesis by phosphorylating KIF13B, promoting interaction between KIF13B and 14-3-3 and inhibiting microtubule-dependent accumulation of KIF13B. Also required for neurite outgrowth and establishment of neuronal polarity. Regulates localization and activity of some histone deacetylases by mediating phosphorylation of HDAC7, promoting subsequent interaction between HDAC7 and 14-3-3 and export from the nucleus. Also acts as a positive regulator of the Wnt signaling pathway, probably by mediating phosphorylation of dishevelled proteins (DVL1, DVL2 and/or DVL3). Modulates the developmental decision to build a columnar versus a hepatic epithelial cell apparently by promoting a switch from a direct to a transcytotic mode of apical protein delivery. Essential for the asymmetric development of membrane domains of polarized epithelial cells.', 'Mark2', 'Rattus norvegicus', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, ATP-binding, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Developmental protein, Differentiation, Kinase, Lipid-binding, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (338, '4OTD', '', 'Serine/threonine-protein kinase N1', 'PKC-related serine/threonine-protein kinase involved in various processes such as regulation of the intermediate filaments of the actin cytoskeleton, cell migration, tumor cell invasion and transcription regulation. Part of a signaling cascade that begins with the activation of the adrenergic receptor ADRA1B and leads to the activation of MAPK14. Regulates the cytoskeletal network by phosphorylating proteins such as VIM and neurofilament proteins NEFH, NEFL and NEFM, leading to inhibit their polymerization. Phosphorylates ''Ser-575'', ''Ser-637'' and ''Ser-669'' of MAPT/Tau, lowering its ability to bind to microtubules, resulting in disruption of tubulin assembly. Acts as a key coactivator of androgen receptor (AR)-dependent transcription, by being recruited to AR target genes and specifically mediating phosphorylation of ''Thr-11'' of histone H3 (H3T11ph), a specific tag for epigenetic transcriptional activation that promotes demethylation of histone H3 ''Lys-9'' (H3K9me) by KDM4C/JMJD2C. Phosphorylates HDAC5, HDAC7 and HDAC9, leading to impair their import in the nucleus. Phosphorylates ''Thr-38'' of PPP1R14A, ''Ser-159'', ''Ser-163'' and ''Ser-170'' of MARCKS, and GFAP. Able to phosphorylate RPS6 in vitro.', 'PKN1', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell membrane, Chromatin regulator, Coiled coil, Cytoplasm, Endosome, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (339, '5GRN', '', 'Platelet-derived growth factor receptor alpha', 'Tyrosine-protein kinase that acts as a cell-surface receptor for PDGFA, PDGFB and PDGFC and plays an essential role in the regulation of embryonic development, cell proliferation, survival and chemotaxis. Depending on the context, promotes or inhibits cell proliferation and cell migration. Plays an important role in the differentiation of bone marrow-derived mesenchymal stem cells. Required for normal skeleton development and cephalic closure during embryonic development. Required for normal development of the mucosa lining the gastrointestinal tract, and for recruitment of mesenchymal cells and normal development of intestinal villi. Plays a role in cell migration and chemotaxis in wound healing. Plays a role in platelet activation, secretion of agonists from platelet granules, and in thrombin-induced platelet aggregation. Binding of its cognate ligands - homodimeric PDGFA, homodimeric PDGFB, heterodimers formed by PDGFA and PDGFB or homodimeric PDGFC -leads to the activation of several signaling cascades; the response depends on the nature of the bound ligand and is modulated by the formation of heterodimers between PDGFRA and PDGFRB. Phosphorylates PIK3R1, PLCG1, and PTPN11. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate, mobilization of cytosolic Ca(2+) and the activation of protein kinase C. Phosphorylates PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase, and thereby mediates activation of the AKT1 signaling pathway. Mediates activation of HRAS and of the MAP kinases MAPK1/ERK2 and/or MAPK3/ERK1. Promotes activation of STAT family members STAT1, STAT3 and STAT5A and/or STAT5B. Receptor signaling is down-regulated by protein phosphatases that dephosphorylate the receptor and its down-stream effectors, and by rapid internalization of the activated receptor.', 'PDGFRA', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cell projection, Chemotaxis, Developmental protein, Disease variant, Disulfide bond, Glycoprotein, Golgi apparatus, Host-virus interaction, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (340, '3OFM', '', 'Casein kinase II subunit alpha''', 'Catalytic subunit of a constitutively active serine/threonine-protein kinase complex that phosphorylates a large number of substrates containing acidic residues C-terminal to the phosphorylated serine or threonine (PubMed:11239457, PubMed:11704824, PubMed:16193064, PubMed:30898438). Regulates numerous cellular processes, such as cell cycle progression, apoptosis and transcription, as well as viral infection (PubMed:11704824, PubMed:16193064, PubMed:30898438). May act as a regulatory node which integrates and coordinates numerous signals leading to an appropriate cellular response (PubMed:12631575, PubMed:19387552, PubMed:19387551). During mitosis, functions as a component of the p53/TP53-dependent spindle assembly checkpoint (SAC) that maintains cyclin-B-CDK1 activity and G2 arrest in response to spindle damage (PubMed:12631575, PubMed:19387552, PubMed:19387551). Also required for p53/TP53-mediated apoptosis, phosphorylating ''Ser-392'' of p53/TP53 following UV irradiation (PubMed:11239457). Phosphorylates a number of DNA repair proteins in response to DNA damage, such as MDC1, RAD9A, RAD51 and HTATSF1, promoting their recruitment to DNA damage sites (PubMed:20545769, PubMed:21482717, PubMed:22325354, PubMed:26811421, PubMed:30898438, PubMed:35597237). Can also negatively regulate apoptosis (PubMed:19387552, PubMed:19387551). Phosphorylates the caspases CASP9 and CASP2 and the apoptotic regulator NOL3 (PubMed:12631575, PubMed:19387552, PubMed:19387551). Phosphorylation protects CASP9 from cleavage and activation by CASP8, and inhibits the dimerization of CASP2 and activation of CASP8 (PubMed:12631575, PubMed:19387552, PubMed:19387551). Regulates transcription by direct phosphorylation of RNA polymerases I, II, III and IV (PubMed:12631575, PubMed:19387552, PubMed:19387551). Also phosphorylates and regulates numerous transcription factors including NF-kappa-B, STAT1, CREB1, IRF1, IRF2, ATF1, SRF, MAX, JUN, FOS, MYC and MYB (PubMed:12631575, PubMed:19387552, PubMed:19387551). Phosphorylates Hsp90 and its co-chaperones FKBP4 and CDC37, which is essential for chaperone function (PubMed:19387550). Regulates Wnt signaling by phosphorylating CTNNB1 and the transcription factor LEF1 (PubMed:19387549). Acts as an ectokinase that phosphorylates several extracellular proteins (PubMed:12631575, PubMed:19387552, PubMed:19387551). During viral infection, phosphorylates various proteins involved in the viral life cycles of EBV, HSV, HBV, HCV, HIV, CMV and HPV (PubMed:12631575, PubMed:19387552, PubMed:19387551).', 'CSNK2A2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (341, '7Z4V', '', 'Serine/threonine-protein kinase 25', 'Oxidant stress-activated serine/threonine kinase that may play a role in the response to environmental stress. Targets to the Golgi apparatus where it appears to regulate protein transport events, cell adhesion, and polarity complexes important for cell migration.', 'STK25', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Golgi apparatus, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (342, '2J4Z', '', 'Aurora kinase A', 'Mitotic serine/threonine kinase that contributes to the regulation of cell cycle progression (PubMed:26246606, PubMed:12390251, PubMed:18615013, PubMed:11039908, PubMed:17125279, PubMed:17360485). Associates with the centrosome and the spindle microtubules during mitosis and plays a critical role in various mitotic events including the establishment of mitotic spindle, centrosome duplication, centrosome separation as well as maturation, chromosomal alignment, spindle assembly checkpoint, and cytokinesis (PubMed:26246606, PubMed:14523000). Required for normal spindle positioning during mitosis and for the localization of NUMA1 and DCTN1 to the cell cortex during metaphase (PubMed:27335426). Required for initial activation of CDK1 at centrosomes (PubMed:13678582, PubMed:15128871). Phosphorylates numerous target proteins, including ARHGEF2, BORA, BRCA1, CDC25B, DLGP5, HDAC6, KIF2A, LATS2, NDEL1, PARD3, PPP1R2, PLK1, RASSF1, TACC3, p53/TP53 and TPX2 (PubMed:18056443, PubMed:15128871, PubMed:14702041, PubMed:11551964, PubMed:15147269, PubMed:15987997, PubMed:17604723, PubMed:18615013). Regulates KIF2A tubulin depolymerase activity (PubMed:19351716). Important for microtubule formation and/or stabilization (PubMed:18056443). Required for normal axon formation (PubMed:19812038). Plays a role in microtubule remodeling during neurite extension (PubMed:19668197). Also acts as a key regulatory component of the p53/TP53 pathway, and particularly the checkpoint-response pathways critical for oncogenic transformation of cells, by phosphorylating and destabilizing p53/TP53 (PubMed:14702041). Phosphorylates its own inhibitors, the protein phosphatase type 1 (PP1) isoforms, to inhibit their activity (PubMed:11551964). Inhibits cilia outgrowth (By similarity). Required for cilia disassembly via phosphorylation of HDAC6 and subsequent deacetylation of alpha-tubulin (PubMed:17604723, PubMed:20643351). Regulates protein levels of the anti-apoptosis protein BIRC5 by suppressing the expression of the SCF(FBXL7) E3 ubiquitin-protein ligase substrate adapter FBXL7 through the phosphorylation of the transcription factor FOXP1 (PubMed:28218735).', 'AURKA', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell cycle, Cell division, Cell membrane, Cell projection, Cilium, Cilium biogenesis/degradation, Cytoplasm, Cytoskeleton, Isopeptide bond, Kinase, Membrane, Microtubule, Mitosis, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (343, '7BI2', '', 'Phosphatidylinositol 4-phosphate 3-kinase C2 domain-containing subunit alpha', 'Generates phosphatidylinositol 3-phosphate (PtdIns3P) and phosphatidylinositol 3,4-bisphosphate (PtdIns(3,4)P2) that act as second messengers. Has a role in several intracellular trafficking events. Functions in insulin signaling and secretion. Required for translocation of the glucose transporter SLC2A4/GLUT4 to the plasma membrane and glucose uptake in response to insulin-mediated RHOQ activation. Regulates insulin secretion through two different mechanisms: involved in glucose-induced insulin secretion downstream of insulin receptor in a pathway that involves AKT1 activation and TBC1D4/AS160 phosphorylation, and participates in the late step of insulin granule exocytosis probably in insulin granule fusion. Synthesizes PtdIns3P in response to insulin signaling. Functions in clathrin-coated endocytic vesicle formation and distribution. Regulates dynamin-independent endocytosis, probably by recruiting EEA1 to internalizing vesicles. In neurosecretory cells synthesizes PtdIns3P on large dense core vesicles. Participates in calcium induced contraction of vascular smooth muscle by regulating myosin light chain (MLC) phosphorylation through a mechanism involving Rho kinase-dependent phosphorylation of the MLCP-regulatory subunit MYPT1. May play a role in the EGF signaling cascade. May be involved in mitosis and UV-induced damage response. Required for maintenance of normal renal structure and function by supporting normal podocyte function. Involved in the regulation of ciliogenesis and trafficking of ciliary components (By similarity).', 'Pik3c2a', 'Mus musculus', '{[''2.7.1.153'',''2.7.1.137'',''2.7.1.154'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Cytoplasmic vesicle, Endocytosis, Exocytosis, Golgi apparatus, Kinase, Lipid metabolism, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (344, '8OKU', '', 'Serine/threonine-protein kinase SIK3', 'Positive regulator of mTOR signaling that functions by triggering the degradation of DEPTOR, an mTOR inhibitor. Involved in the dynamic regulation of mTOR signaling in chondrocyte differentiation during skeletogenesis (PubMed:30232230). Negatively regulates cAMP signaling pathway possibly by acting on CRTC2/TORC2 and CRTC3/TORC3 (Probable). Prevents HDAC4 translocation to the nucleus (By similarity).', 'SIK3', 'Homo sapiens', '{[''2.7.11.1'']}', 'Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Dwarfism, Kinase, Magnesium, Metal-binding, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (345, '3I6W', '', 'Serine/threonine-protein kinase Chk2', 'Serine/threonine-protein kinase which is required for checkpoint-mediated cell cycle arrest, activation of DNA repair and apoptosis in response to the presence of DNA double-strand breaks. May also negatively regulate cell cycle progression during unperturbed cell cycles. Following activation, phosphorylates numerous effectors preferentially at the consensus sequence [L-X-R-X-X-S/T]. Regulates cell cycle checkpoint arrest through phosphorylation of CDC25A, CDC25B and CDC25C, inhibiting their activity. Inhibition of CDC25 phosphatase activity leads to increased inhibitory tyrosine phosphorylation of CDK-cyclin complexes and blocks cell cycle progression. May also phosphorylate NEK6 which is involved in G2/M cell cycle arrest. Regulates DNA repair through phosphorylation of BRCA2, enhancing the association of RAD51 with chromatin which promotes DNA repair by homologous recombination. Also stimulates the transcription of genes involved in DNA repair (including BRCA2) through the phosphorylation and activation of the transcription factor FOXM1. Regulates apoptosis through the phosphorylation of p53/TP53, MDM4 and PML. Phosphorylation of p53/TP53 at ''Ser-20'' by CHEK2 may alleviate inhibition by MDM2, leading to accumulation of active p53/TP53. Phosphorylation of MDM4 may also reduce degradation of p53/TP53. Also controls the transcription of pro-apoptotic genes through phosphorylation of the transcription factor E2F1. Tumor suppressor, it may also have a DNA damage-independent function in mitotic spindle assembly by phosphorylating BRCA1. Its absence may be a cause of the chromosomal instability observed in some cancer cells. Promotes the CCAR2-SIRT1 association and is required for CCAR2-mediated SIRT1 inhibition (PubMed:25361978).', 'CHEK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell division, Disease variant, DNA damage, DNA repair, Host-virus interaction, Kinase, Li-Fraumeni syndrome, Magnesium, Metal-binding, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Tumor suppressor, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (346, '3ALN', '', 'Dual specificity mitogen-activated protein kinase kinase 4', 'Dual specificity protein kinase which acts as an essential component of the MAP kinase signal transduction pathway. Essential component of the stress-activated protein kinase/c-Jun N-terminal kinase (SAP/JNK) signaling pathway. With MAP2K7/MKK7, is the one of the only known kinase to directly activate the stress-activated protein kinase/c-Jun N-terminal kinases MAPK8/JNK1, MAPK9/JNK2 and MAPK10/JNK3. MAP2K4/MKK4 and MAP2K7/MKK7 both activate the JNKs by phosphorylation, but they differ in their preference for the phosphorylation site in the Thr-Pro-Tyr motif. MAP2K4 shows preference for phosphorylation of the Tyr residue and MAP2K7/MKK7 for the Thr residue. The phosphorylation of the Thr residue by MAP2K7/MKK7 seems to be the prerequisite for JNK activation at least in response to pro-inflammatory cytokines, while other stimuli activate both MAP2K4/MKK4 and MAP2K7/MKK7 which synergistically phosphorylate JNKs. MAP2K4 is required for maintaining peripheral lymphoid homeostasis. The MKK/JNK signaling pathway is also involved in mitochondrial death signaling pathway, including the release cytochrome c, leading to apoptosis. Whereas MAP2K7/MKK7 exclusively activates JNKs, MAP2K4/MKK4 additionally activates the p38 MAPKs MAPK11, MAPK12, MAPK13 and MAPK14.', 'MAP2K4', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Kinase, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (347, '8GW3', '', 'TGF-beta-activated kinase 1 and MAP3K7-binding protein 1', 'Key adapter protein that plays an essential role in JNK and NF-kappa-B activation and proinflammatory cytokines production in response to stimulation with TLRs and cytokines (PubMed:22307082, PubMed:24403530). Mechanistically, associates with the catalytic domain of MAP3K7/TAK1 to trigger MAP3K7/TAK1 autophosphorylation leading to its full activation (PubMed:10838074, PubMed:25260751, PubMed:37832545). Similarly, associates with MAPK14 and triggers its autophosphorylation and subsequent activation (PubMed:11847341, PubMed:29229647). In turn, MAPK14 phosphorylates TAB1 and inhibits MAP3K7/TAK1 activation in a feedback control mechanism (PubMed:14592977). Plays also a role in recruiting MAPK14 to the TAK1 complex for the phosphorylation of the TAB2 and TAB3 regulatory subunits (PubMed:18021073).', 'TAB1', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Cytoplasm, Endoplasmic reticulum, Glycoprotein, Membrane, Phosphoprotein, Reference proteome, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (348, '4IC7', '', 'Mitogen-activated protein kinase 7', 'Plays a role in various cellular processes such as proliferation, differentiation and cell survival. The upstream activator of MAPK7 is the MAPK kinase MAP2K5. Upon activation, it translocates to the nucleus and phosphorylates various downstream targets including MEF2C. EGF activates MAPK7 through a Ras-independent and MAP2K5-dependent pathway. As part of the MAPK/ERK signaling pathway, acts as a negative regulator of apoptosis in cardiomyocytes via interaction with STUB1/CHIP and promotion of STUB1-mediated ubiquitination and degradation of ICER-type isoforms of CREM (By similarity). May have a role in muscle cell differentiation. May be important for endothelial function and maintenance of blood vessel integrity. MAP2K5 and MAPK7 interact specifically with one another and not with MEK1/ERK1 or MEK2/ERK2 pathways. Phosphorylates SGK1 at Ser-78 and this is required for growth factor-induced cell cycle progression. Involved in the regulation of p53/TP53 by disrupting the PML-MDM2 interaction.', 'MAPK7', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cytoplasm, Differentiation, Direct protein sequencing, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (349, '7LBF', '', 'Envelope glycoprotein H', 'The heterodimer glycoprotein H-glycoprotein L is required for the fusion of viral and plasma membranes leading to virus entry into the host cell. Following initial binding to host receptor, membrane fusion is mediated by the fusion machinery composed of gB and the heterodimer gH/gL. May also be involved in the fusion between the virion envelope and the outer nuclear membrane during virion morphogenesis (By similarity). In human cytomegalovirus, forms two distincts complexes to mediate viral entry, a trimer and a pentamer at the surface of the virion envelope. The gH-gL-gO trimer is required for infection in fibroblasts by interacting with host PDGFRA, and in glioblastoma cells by interacting with host EPHA2 (PubMed:28403202, PubMed:37146061). The gH-gL-UL128-UL130-UL131A pentamer is essential for viral entry in epithelial, endothelial and myeloid cells via interaction with host NRP2 (PubMed:17942555, PubMed:23853586, PubMed:30057110, PubMed:28783665).', 'gH', 'Human cytomegalovirus (strain Merlin)', '{[]}', '3D-structure, Fusion of virus membrane with host cell membrane, Fusion of virus membrane with host membrane, Glycoprotein, Host cell membrane, Host endosome, Host membrane, Host-virus interaction, Membrane, Reference proteome, Sialic acid, Signal, Transmembrane, Transmembrane helix, Viral attachment to host cell, Viral attachment to host entry receptor, Viral envelope protein, Viral penetration into host cytoplasm, Virion, Virus entry into host cell');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (350, '3MDY', '', 'Bone morphogenetic protein receptor type-1B', 'On ligand binding, forms a receptor complex consisting of two type II and two type I transmembrane serine/threonine kinases. Type II receptors phosphorylate and activate type I receptors which autophosphorylate, then bind and activate SMAD transcriptional regulators. Receptor for BMP7/OP-1 and GDF5. Positively regulates chondrocyte differentiation through GDF5 interaction.', 'BMPR1B', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Chondrogenesis, Disease variant, Disulfide bond, Dwarfism, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (351, '2JAM', '', 'Calcium/calmodulin-dependent protein kinase type 1G', 'Calcium/calmodulin-dependent protein kinase belonging to a proposed calcium-triggered signaling cascade. In vitro phosphorylates transcription factor CREB1 (By similarity).', 'CAMK1G', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Allosteric enzyme, Alternative splicing, ATP-binding, Calmodulin-binding, Cell membrane, Cytoplasm, Golgi apparatus, Kinase, Lipoprotein, Membrane, Nucleotide-binding, Prenylation, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (352, '6GVJ', '', 'Dual specificity protein kinase TTK', 'Phosphorylates proteins on serine, threonine, and tyrosine (PubMed:18243099, PubMed:29162720). Probably associated with cell proliferation (PubMed:18243099). Phosphorylates MAD1L1 to promote mitotic checkpoint signaling (PubMed:29162720). Essential for chromosome alignment by enhancing AURKB activity (via direct CDCA8 phosphorylation) at the centromere, and for the mitotic checkpoint (PubMed:18243099).', 'TTK', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (434, '7O7I', '', 'Homeodomain-interacting protein kinase 3', 'Serine/threonine-protein kinase involved in transcription regulation, apoptosis and steroidogenic gene expression. Phosphorylates JUN and RUNX2. Seems to negatively regulate apoptosis by promoting FADD phosphorylation. Enhances androgen receptor-mediated transcription. May act as a transcriptional corepressor for NK homeodomain transcription factors. The phosphorylation of NR5A1 activates SF1 leading to increased steroidogenic gene expression upon cAMP signaling pathway stimulation. In osteoblasts, supports transcription activation: phosphorylates RUNX2 that synergizes with SPEN/MINT to enhance FGFR2-mediated activation of the osteocalcin FGF-responsive element (OCFRE).', 'HIPK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (353, '8DKS', '', 'Interleukin-1 receptor-associated kinase 4', 'Serine/threonine-protein kinase that plays a critical role in initiating innate immune response against foreign pathogens. Involved in Toll-like receptor (TLR) and IL-1R signaling pathways (PubMed:17878374). Is rapidly recruited by MYD88 to the receptor-signaling complex upon TLR activation to form the Myddosome together with IRAK2. Phosphorylates initially IRAK1, thus stimulating the kinase activity and intensive autophosphorylation of IRAK1. Phosphorylates E3 ubiquitin ligases Pellino proteins (PELI1, PELI2 and PELI3) to promote pellino-mediated polyubiquitination of IRAK1. Then, the ubiquitin-binding domain of IKBKG/NEMO binds to polyubiquitinated IRAK1 bringing together the IRAK1-MAP3K7/TAK1-TRAF6 complex and the NEMO-IKKA-IKKB complex. In turn, MAP3K7/TAK1 activates IKKs (CHUK/IKKA and IKBKB/IKKB) leading to NF-kappa-B nuclear translocation and activation. Alternatively, phosphorylates TIRAP to promote its ubiquitination and subsequent degradation. Phosphorylates NCF1 and regulates NADPH oxidase activation after LPS stimulation suggesting a similar mechanism during microbial infections.', 'IRAK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Immunity, Innate immunity, Kinase, Magnesium, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (354, '4FL2', '', 'Tyrosine-protein kinase SYK', 'Non-receptor tyrosine kinase which mediates signal transduction downstream of a variety of transmembrane receptors including classical immunoreceptors like the B-cell receptor (BCR). Regulates several biological processes including innate and adaptive immunity, cell adhesion, osteoclast maturation, platelet activation and vascular development (PubMed:12387735, PubMed:33782605). Assembles into signaling complexes with activated receptors at the plasma membrane via interaction between its SH2 domains and the receptor tyrosine-phosphorylated ITAM domains. The association with the receptor can also be indirect and mediated by adapter proteins containing ITAM or partial hemITAM domains. The phosphorylation of the ITAM domains is generally mediated by SRC subfamily kinases upon engagement of the receptor. More rarely signal transduction via SYK could be ITAM-independent. Direct downstream effectors phosphorylated by SYK include DEPTOR, VAV1, PLCG1, PI-3-kinase, LCP2 and BLNK (PubMed:12456653, PubMed:15388330, PubMed:8657103, PubMed:34634301). Initially identified as essential in B-cell receptor (BCR) signaling, it is necessary for the maturation of B-cells most probably at the pro-B to pre-B transition (PubMed:12456653). Activated upon BCR engagement, it phosphorylates and activates BLNK an adapter linking the activated BCR to downstream signaling adapters and effectors. It also phosphorylates and activates PLCG1 and the PKC signaling pathway. It also phosphorylates BTK and regulates its activity in B-cell antigen receptor (BCR)-coupled signaling. In addition to its function downstream of BCR also plays a role in T-cell receptor signaling. Plays also a crucial role in the innate immune response to fungal, bacterial and viral pathogens. It is for instance activated by the membrane lectin CLEC7A. Upon stimulation by fungal proteins, CLEC7A together with SYK activates immune cells inducing the production of ROS. Also activates the inflammasome and NF-kappa-B-mediated transcription of chemokines and cytokines in presence of pathogens. Regulates neutrophil degranulation and phagocytosis through activation of the MAPK signaling cascade (By similarity). Required for the stimulation of neutrophil phagocytosis by IL15 (PubMed:15123770). Also mediates the activation of dendritic cells by cell necrosis stimuli. Also involved in mast cells activation. Involved in interleukin-3/IL3-mediated signaling pathway in basophils (By similarity). Also functions downstream of receptors mediating cell adhesion (PubMed:12387735). Relays for instance, integrin-mediated neutrophils and macrophages activation and P-selectin receptor/SELPG-mediated recruitment of leukocytes to inflammatory loci. Also plays a role in non-immune processes. It is for instance involved in vascular development where it may regulate blood and lymphatic vascular separation. It is also required for osteoclast development and function. Functions in the activation of platelets by collagen, mediating PLCG2 phosphorylation and activation. May be coupled to the collagen receptor by the ITAM domain-containing FCER1G. Also activated by the membrane lectin CLEC1B that is required for activation of platelets by PDPN/podoplanin. Involved in platelet adhesion being activated by ITGB3 engaged by fibrinogen. Together with CEACAM20, enhances production of the cytokine CXCL8/IL-8 via the NFKB pathway and may thus have a role in the intestinal immune response (By similarity).', 'SYK', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Adaptive immunity, Alternative splicing, Angiogenesis, ATP-binding, Cell membrane, Cytoplasm, Disease variant, Host-virus interaction, Immunity, Innate immunity, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SH2 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (355, '4BK4', '', 'Ephrin type-A receptor 4', 'Receptor tyrosine kinase which binds membrane-bound ephrin family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Highly promiscuous, it has the unique property among Eph receptors to bind and to be physiologically activated by both GPI-anchored ephrin-A and transmembrane ephrin-B ligands including EFNA1 and EFNB3. Upon activation by ephrin ligands, modulates cell morphology and integrin-dependent cell adhesion through regulation of the Rac, Rap and Rho GTPases activity. Plays an important role in the development of the nervous system controlling different steps of axonal guidance including the establishment of the corticospinal projections. May also control the segregation of motor and sensory axons during neuromuscular circuit development. In addition to its role in axonal guidance plays a role in synaptic plasticity. Activated by EFNA1 phosphorylates CDK5 at ''Tyr-15'' which in turn phosphorylates NGEF regulating RHOA and dendritic spine morphogenesis. In the nervous system, also plays a role in repair after injury preventing axonal regeneration and in angiogenesis playing a role in central nervous system vascular formation. Additionally, its promiscuity makes it available to participate in a variety of cell-cell signaling regulating for instance the development of the thymic epithelium. During development of the cochlear organ of Corti, regulates pillar cell separation by forming a ternary complex with ADAM10 and CADH1 which facilitates the cleavage of CADH1 by ADAM10 and disruption of adherens junctions (By similarity). Phosphorylates CAPRIN1, promoting CAPRIN1-dependent formation of a membraneless compartment (By similarity).', 'EPHA4', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell junction, Cell membrane, Cell projection, Developmental protein, Endosome, Glycoprotein, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Postsynaptic cell membrane, Receptor, Reference proteome, Repeat, Signal, Synapse, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (356, '6FAD', '', 'SRSF protein kinase 1', 'Serine/arginine-rich protein-specific kinase which specifically phosphorylates its substrates at serine residues located in regions rich in arginine/serine dipeptides, known as RS domains and is involved in the phosphorylation of SR splicing factors and the regulation of splicing. Plays a central role in the regulatory network for splicing, controlling the intranuclear distribution of splicing factors in interphase cells and the reorganization of nuclear speckles during mitosis. Can influence additional steps of mRNA maturation, as well as other cellular activities, such as chromatin reorganization in somatic and sperm cells and cell cycle progression. Isoform 2 phosphorylates SFRS2, ZRSR2, LBR and PRM1. Isoform 2 phosphorylates SRSF1 using a directional (C-terminal to N-terminal) and a dual-track mechanism incorporating both processive phosphorylation (in which the kinase stays attached to the substrate after each round of phosphorylation) and distributive phosphorylation steps (in which the kinase and substrate dissociate after each phosphorylation event). The RS domain of SRSF1 binds first to a docking groove in the large lobe of the kinase domain of SRPK1. This induces certain structural changes in SRPK1 and/or RRM2 domain of SRSF1, allowing RRM2 to bind the kinase and initiate phosphorylation. The cycles continue for several phosphorylation steps in a processive manner (steps 1-8) until the last few phosphorylation steps (approximately steps 9-12). During that time, a mechanical stress induces the unfolding of the beta-4 motif in RRM2, which then docks at the docking groove of SRPK1. This also signals RRM2 to begin to dissociate, which facilitates SRSF1 dissociation after phosphorylation is completed. Isoform 2 can mediate hepatitis B virus (HBV) core protein phosphorylation. It plays a negative role in the regulation of HBV replication through a mechanism not involving the phosphorylation of the core protein but by reducing the packaging efficiency of the pregenomic RNA (pgRNA) without affecting the formation of the viral core particles. Isoform 1 and isoform 2 can induce splicing of exon 10 in MAPT/TAU. The ratio of isoform 1/isoform 2 plays a decisive role in determining cell fate in K-562 leukaemic cell line: isoform 2 favors proliferation where as isoform 1 favors differentiation.', 'SRPK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Chromosome, Chromosome partition, Cytoplasm, Differentiation, Direct protein sequencing, Endoplasmic reticulum, Host-virus interaction, Kinase, Microsome, mRNA processing, mRNA splicing, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (357, '2IN6', '', 'Wee1-like protein kinase', 'Acts as a negative regulator of entry into mitosis (G2 to M transition) by protecting the nucleus from cytoplasmically activated cyclin B1-complexed CDK1 before the onset of mitosis by mediating phosphorylation of CDK1 on ''Tyr-15'' (PubMed:7743995, PubMed:8348613, PubMed:8428596, PubMed:15070733). Specifically phosphorylates and inactivates cyclin B1-complexed CDK1 reaching a maximum during G2 phase and a minimum as cells enter M phase (PubMed:7743995, PubMed:8348613, PubMed:8428596). Phosphorylation of cyclin B1-CDK1 occurs exclusively on ''Tyr-15'' and phosphorylation of monomeric CDK1 does not occur (PubMed:7743995, PubMed:8348613, PubMed:8428596). Its activity increases during S and G2 phases and decreases at M phase when it is hyperphosphorylated (PubMed:7743995). A correlated decrease in protein level occurs at M/G1 phase, probably due to its degradation (PubMed:7743995).', 'WEE1', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cell division, Kinase, Magnesium, Metal-binding, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (205, '8USO', '', 'Calcium/calmodulin-dependent protein kinase type II subunit delta', 'Unknown', 'CAMK2D', 'Homo sapiens', '{[''2.7.11.17'']}', 'ATP-binding, Calmodulin-binding, Kinase, Nucleotide-binding, Proteomics identification, Reference proteome, Sarcoplasmic reticulum, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (358, '4Z32', '', 'Tyrosine-protein kinase JAK2', 'Non-receptor tyrosine kinase involved in various processes such as cell growth, development, differentiation or histone modifications. Mediates essential signaling events in both innate and adaptive immunity. In the cytoplasm, plays a pivotal role in signal transduction via its association with type I receptors such as growth hormone (GHR), prolactin (PRLR), leptin (LEPR), erythropoietin (EPOR), thrombopoietin (THPO); or type II receptors including IFN-alpha, IFN-beta, IFN-gamma and multiple interleukins (PubMed:7615558). Following ligand-binding to cell surface receptors, phosphorylates specific tyrosine residues on the cytoplasmic tails of the receptor, creating docking sites for STATs proteins (PubMed:9618263). Subsequently, phosphorylates the STATs proteins once they are recruited to the receptor. Phosphorylated STATs then form homodimer or heterodimers and translocate to the nucleus to activate gene transcription. For example, cell stimulation with erythropoietin (EPO) during erythropoiesis leads to JAK2 autophosphorylation, activation, and its association with erythropoietin receptor (EPOR) that becomes phosphorylated in its cytoplasmic domain. Then, STAT5 (STAT5A or STAT5B) is recruited, phosphorylated and activated by JAK2. Once activated, dimerized STAT5 translocates into the nucleus and promotes the transcription of several essential genes involved in the modulation of erythropoiesis. Part of a signaling cascade that is activated by increased cellular retinol and that leads to the activation of STAT5 (STAT5A or STAT5B) (PubMed:21368206). In addition, JAK2 mediates angiotensin-2-induced ARHGEF1 phosphorylation (PubMed:20098430). Plays a role in cell cycle by phosphorylating CDKN1B (PubMed:21423214). Cooperates with TEC through reciprocal phosphorylation to mediate cytokine-driven activation of FOS transcription. In the nucleus, plays a key role in chromatin by specifically mediating phosphorylation of ''Tyr-41'' of histone H3 (H3Y41ph), a specific tag that promotes exclusion of CBX5 (HP1 alpha) from chromatin (PubMed:19783980).', 'JAK2', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Adaptive immunity, ATP-binding, Chromatin regulator, Chromosomal rearrangement, Cytoplasm, Disease variant, Immunity, Innate immunity, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Repeat, SH2 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (359, '5A46', '', 'Fibroblast growth factor receptor 1', 'Tyrosine-protein kinase that acts as a cell-surface receptor for fibroblast growth factors and plays an essential role in the regulation of embryonic development, cell proliferation, differentiation and migration. Required for normal mesoderm patterning and correct axial organization during embryonic development, normal skeletogenesis and normal development of the gonadotropin-releasing hormone (GnRH) neuronal system. Phosphorylates PLCG1, FRS2, GAB1 and SHB. Ligand binding leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate. Phosphorylation of FRS2 triggers recruitment of GRB2, GAB1, PIK3R1 and SOS1, and mediates activation of RAS, MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. Promotes phosphorylation of SHC1, STAT1 and PTPN11/SHP2. In the nucleus, enhances RPS6KA1 and CREB1 activity and contributes to the regulation of transcription. FGFR1 signaling is down-regulated by IL17RD/SEF, and by FGFR1 ubiquitination, internalization and degradation.', 'FGFR1', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Chromosomal rearrangement, Craniosynostosis, Cytoplasm, Cytoplasmic vesicle, Direct protein sequencing, Disease variant, Disulfide bond, Dwarfism, Glycoprotein, Heparin-binding, Holoprosencephaly, Hypogonadotropic hypogonadism, Immunoglobulin domain, Intellectual disability, Kallmann syndrome, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transcription, Transcription regulation, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (360, '6KHF', '', 'Dual specificity protein kinase CLK3', 'Dual specificity kinase acting on both serine/threonine and tyrosine-containing substrates. Phosphorylates serine- and arginine-rich (SR) proteins of the spliceosomal complex. May be a constituent of a network of regulatory mechanisms that enable SR proteins to control RNA splicing and can cause redistribution of SR proteins from speckles to a diffuse nucleoplasmic distribution. Phosphorylates SRSF1 and SRSF3. Regulates the alternative splicing of tissue factor (F3) pre-mRNA in endothelial cells.', 'CLK3', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoplasmic vesicle, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (361, '4W9X', '', 'BMP-2-inducible protein kinase', 'May be involved in osteoblast differentiation.', 'BMP2K', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (362, '7K7J', '', 'Ephrin type-B receptor 6', 'Kinase-defective receptor for members of the ephrin-B family. Binds to ephrin-B1 and ephrin-B2. Modulates cell adhesion and migration by exerting both positive and negative effects upon stimulation with ephrin-B2. Inhibits JNK activation, T-cell receptor-induced IL-2 secretion and CD25 expression upon stimulation with ephrin-B2.', 'EPHB6', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, ATP-binding, Direct protein sequencing, Glycoprotein, Membrane, Nucleotide-binding, Receptor, Reference proteome, Repeat, Secreted, Signal, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (363, '1H4L', 'MQKYEKLEKIGEGTYGTVFKAKNRETHEIVALKRVRLDDDDEGVPSSALREICLLKELKHKNIVRLHDVLHSDKKLTLVFEFCDQDLKKYFDSCNGDLDPEIVKSFLFQLLKGLGFCHSRNVLHRDLKPQNLLINRNGELKLADFGLARAFGIPVRCYSAEVVTLWYRPPDVLFGAKLYSTSIDMWSAGCIFAELANAGRPLFPGNDVDDQLKRIFRLLGTPTEEQWPSMTKLPDYKPYPMYPATTSLVNVVPKLNATGRDLLQNLLKCNPVQRISAEEALQHPYFSDFCPP', 'Cyclin-dependent kinase 5', 'Proline-directed serine/threonine-protein kinase essential for neuronal cell cycle arrest and differentiation and may be involved in apoptotic cell death in neuronal diseases by triggering abortive cell cycle re-entry. Interacts with D1 and D3-type G1 cyclins. Phosphorylates SRC, NOS3, VIM/vimentin, p35/CDK5R1, MEF2A, SIPA1L1, SH3GLB1, PXN, PAK1, MCAM/MUC18, SEPT5, SYN1, DNM1, AMPH, SYNJ1, CDK16, RAC1, RHOA, CDC42, TONEBP/NFAT5, MAPT/TAU, MAP1B, histone H1, p53/TP53, HDAC1, APEX1, PTK2/FAK1, huntingtin/HTT, ATM, MAP2, NEFH and NEFM. Regulates several neuronal development and physiological processes including neuronal survival, migration and differentiation, axonal and neurite growth, synaptogenesis, oligodendrocyte differentiation, synaptic plasticity and neurotransmission, by phosphorylating key proteins. Negatively regulates the CACNA1B/CAV2.2 -mediated Ca(2+) release probability at hippocampal neuronal soma and synaptic terminals (By similarity). Activated by interaction with CDK5R1 (p35) and CDK5R2 (p39), especially in postmitotic neurons, and promotes CDK5R1 (p35) expression in an autostimulation loop. Phosphorylates many downstream substrates such as Rho and Ras family small GTPases (e.g. PAK1, RAC1, RHOA, CDC42) or microtubule-binding proteins (e.g. MAPT/TAU, MAP2, MAP1B), and modulates actin dynamics to regulate neurite growth and/or spine morphogenesis. Phosphorylates also exocytosis associated proteins such as MCAM/MUC18, SEPT5, SYN1, and CDK16/PCTAIRE1 as well as endocytosis associated proteins such as DNM1, AMPH and SYNJ1 at synaptic terminals. In the mature central nervous system (CNS), regulates neurotransmitter movements by phosphorylating substrates associated with neurotransmitter release and synapse plasticity; synaptic vesicle exocytosis, vesicles fusion with the presynaptic membrane, and endocytosis. Promotes cell survival by activating anti-apoptotic proteins BCL2 and STAT3, and negatively regulating of JNK3/MAPK10 activity. Phosphorylation of p53/TP53 in response to genotoxic and oxidative stresses enhances its stabilization by preventing ubiquitin ligase-mediated proteasomal degradation, and induces transactivation of p53/TP53 target genes, thus regulating apoptosis. Phosphorylation of p35/CDK5R1 enhances its stabilization by preventing calpain-mediated proteolysis producing p25/CDK5R1 and avoiding ubiquitin ligase-mediated proteasomal degradation. During aberrant cell-cycle activity and DNA damage, p25/CDK5 activity elicits cell-cycle activity and double-strand DNA breaks that precedes neuronal death by deregulating HDAC1. DNA damage triggered phosphorylation of huntingtin/HTT in nuclei of neurons protects neurons against polyglutamine expansion as well as DNA damage mediated toxicity. Phosphorylation of PXN reduces its interaction with PTK2/FAK1 in matrix-cell focal adhesions (MCFA) during oligodendrocytes (OLs) differentiation. Negative regulator of Wnt/beta-catenin signaling pathway. Activator of the GAIT (IFN-gamma-activated inhibitor of translation) pathway, which suppresses expression of a post-transcriptional regulon of proinflammatory genes in myeloid cells; phosphorylates the linker domain of glutamyl-prolyl tRNA synthetase (EPRS) in a IFN-gamma-dependent manner, the initial event in assembly of the GAIT complex. Phosphorylation of SH3GLB1 is required for autophagy induction in starved neurons. Phosphorylation of TONEBP/NFAT5 in response to osmotic stress mediates its rapid nuclear localization. MEF2 is inactivated by phosphorylation in nucleus in response to neurotoxin, thus leading to neuronal apoptosis. APEX1 AP-endodeoxyribonuclease is repressed by phosphorylation, resulting in accumulation of DNA damage and contributing to neuronal death. NOS3 phosphorylation down regulates NOS3-derived nitrite (NO) levels. SRC phosphorylation mediates its ubiquitin-dependent degradation and thus leads to cytoskeletal reorganization. May regulate endothelial cell migration and angiogenesis via the modulation of lamellipodia formation. Involved in dendritic spine morphogenesis by mediating the EFNA1-EPHA4 signaling. The complex p35/CDK5 participates in the regulation of the circadian clock by modulating the function of CLOCK protein: phosphorylates CLOCK at ''Thr-451'' and ''Thr-461'' and regulates the transcriptional activity of the CLOCK-BMAL1 heterodimer in association with altered stability and subcellular distribution.', 'CDK5', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Biological rhythms, Cell cycle, Cell division, Cell membrane, Cell projection, Cytoplasm, Kinase, Lissencephaly, Membrane, Neurodegeneration, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Synapse, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (364, '6MNH', '', 'Serine/threonine-protein kinase ULK1', 'Serine/threonine-protein kinase involved in autophagy in response to starvation (PubMed:18936157, PubMed:21460634, PubMed:21795849, PubMed:23524951, PubMed:25040165, PubMed:31123703, PubMed:29487085). Acts upstream of phosphatidylinositol 3-kinase PIK3C3 to regulate the formation of autophagophores, the precursors of autophagosomes (PubMed:18936157, PubMed:21460634, PubMed:21795849, PubMed:25040165). Part of regulatory feedback loops in autophagy: acts both as a downstream effector and negative regulator of mammalian target of rapamycin complex 1 (mTORC1) via interaction with RPTOR (PubMed:21795849). Activated via phosphorylation by AMPK and also acts as a regulator of AMPK by mediating phosphorylation of AMPK subunits PRKAA1, PRKAB2 and PRKAG1, leading to negatively regulate AMPK activity (PubMed:21460634). May phosphorylate ATG13/KIAA0652 and RPTOR; however such data need additional evidences (PubMed:18936157). Plays a role early in neuronal differentiation and is required for granule cell axon formation (PubMed:11146101). Also phosphorylates SESN2 and SQSTM1 to regulate autophagy (PubMed:25040165, PubMed:37306101). Phosphorylates FLCN, promoting autophagy (PubMed:25126726). Phosphorylates AMBRA1 in response to autophagy induction, releasing AMBRA1 from the cytoskeletal docking site to induce autophagosome nucleation (PubMed:20921139). Phosphorylates ATG4B, leading to inhibit autophagy by decreasing both proteolytic activation and delipidation activities of ATG4B (PubMed:28821708).', 'ULK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Autophagy, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (365, '4NEU', '', 'Receptor-interacting serine/threonine-protein kinase 1', 'Serine-threonine kinase which is a key regulator of TNF-mediated apoptosis, necroptosis and inflammatory pathways (PubMed:32657447, PubMed:31827280, PubMed:31827281, PubMed:17703191, PubMed:24144979). Exhibits kinase activity-dependent functions that regulate cell death and kinase-independent scaffold functions regulating inflammatory signaling and cell survival (PubMed:11101870, PubMed:19524512, PubMed:19524513, PubMed:29440439, PubMed:30988283). Has kinase-independent scaffold functions: upon binding of TNF to TNFR1, RIPK1 is recruited to the TNF-R1 signaling complex (TNF-RSC also known as complex I) where it acts as a scaffold protein promoting cell survival, in part, by activating the canonical NF-kappa-B pathway (By similarity). Kinase activity is essential to regulate necroptosis and apoptosis, two parallel forms of cell death: upon activation of its protein kinase activity, regulates assembly of two death-inducing complexes, namely complex IIa (RIPK1-FADD-CASP8), which drives apoptosis, and the complex IIb (RIPK1-RIPK3-MLKL), which drives necroptosis (By similarity). RIPK1 is required to limit CASP8-dependent TNFR1-induced apoptosis (By similarity). In normal conditions, RIPK1 acts as an inhibitor of RIPK3-dependent necroptosis, a process mediated by RIPK3 component of complex IIb, which catalyzes phosphorylation of MLKL upon induction by ZBP1 (PubMed:19524512, PubMed:19524513, PubMed:29440439, PubMed:30988283). Inhibits RIPK3-mediated necroptosis via FADD-mediated recruitment of CASP8, which cleaves RIPK1 and limits TNF-induced necroptosis (PubMed:19524512, PubMed:19524513, PubMed:29440439, PubMed:30988283). Required to inhibit apoptosis and necroptosis during embryonic development: acts by preventing the interaction of TRADD with FADD thereby limiting aberrant activation of CASP8 (By similarity). In addition to apoptosis and necroptosis, also involved in inflammatory response by promoting transcriptional production of pro-inflammatory cytokines, such as interleukin-6 (IL6) (PubMed:31827280, PubMed:31827281). Phosphorylates RIPK3: RIPK1 and RIPK3 undergo reciprocal auto- and trans-phosphorylation (PubMed:19524513). Phosphorylates DAB2IP at ''Ser-728'' in a TNF-alpha-dependent manner, and thereby activates the MAP3K5-JNK apoptotic cascade (PubMed:17389591, PubMed:15310755). Required for ZBP1-induced NF-kappa-B activation in response to DNA damage (By similarity).', 'RIPK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell membrane, Cytoplasm, Disease variant, Glycoprotein, Host-virus interaction, Inflammatory response, Isopeptide bond, Kinase, Membrane, Necrosis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (366, '4WAE', '', 'Phosphatidylinositol 4-kinase beta', 'Phosphorylates phosphatidylinositol (PI) in the first committed step in the production of the second messenger inositol-1,4,5,-trisphosphate (PIP). May regulate Golgi disintegration/reorganization during mitosis, possibly via its phosphorylation. Involved in Golgi-to-plasma membrane trafficking (By similarity) (PubMed:10559940, PubMed:11277933, PubMed:12749687, PubMed:9405935). May play an important role in the inner ear development.', 'PI4KB', 'Homo sapiens', '{[''2.7.1.67'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Deafness, Direct protein sequencing, Disease variant, Endoplasmic reticulum, Golgi apparatus, Host-virus interaction, Kinase, Lipid metabolism, Membrane, Mitochondrion, Mitochondrion outer membrane, Non-syndromic deafness, Nucleotide-binding, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (367, '6FDY', '', 'Serine/threonine-protein kinase ULK3', 'Serine/threonine protein kinase that acts as a regulator of Sonic hedgehog (SHH) signaling and autophagy. Acts as a negative regulator of SHH signaling in the absence of SHH ligand: interacts with SUFU, thereby inactivating the protein kinase activity and preventing phosphorylation of GLI proteins (GLI1, GLI2 and/or GLI3). Positively regulates SHH signaling in the presence of SHH: dissociates from SUFU, autophosphorylates and mediates phosphorylation of GLI2, activating it and promoting its nuclear translocation. Phosphorylates in vitro GLI2, as well as GLI1 and GLI3, although less efficiently. Also acts as a regulator of autophagy: following cellular senescence, able to induce autophagy.', 'ULK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Autophagy, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (426, '8S9P', '', 'Agrin', 'Heparan sulfate basal lamina glycoprotein that plays a central role in the formation and the maintenance of the neuromuscular junction (NMJ) and directs key events in postsynaptic differentiation. Component of the AGRN-LRP4 receptor complex that induces the phosphorylation and activation of MUSK. The activation of MUSK in myotubes induces the formation of NMJ by regulating different processes including the transcription of specific genes and the clustering of AChR in the postsynaptic membrane. Calcium ions are required for maximal AChR clustering. AGRN function in neurons is highly regulated by alternative splicing, glycan binding and proteolytic processing. Modulates calcium ion homeostasis in neurons, specifically by inducing an increase in cytoplasmic calcium ions. Functions differentially in the central nervous system (CNS) by inhibiting the alpha(3)-subtype of Na+/K+-ATPase and evoking depolarization at CNS synapses. This secreted isoform forms a bridge, after release from motor neurons, to basal lamina through binding laminin via the NtA domain.', 'AGRN', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Calcium, Cell membrane, Congenital myasthenic syndrome, Developmental protein, Differentiation, Disease variant, Disulfide bond, EGF-like domain, Extracellular matrix, Glycoprotein, Heparan sulfate, Laminin EGF-like domain, Membrane, Metal-binding, Phosphoprotein, Proteoglycan, Reference proteome, Repeat, Secreted, Signal, Synapse, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (368, '1OPK', '', 'Tyrosine-protein kinase ABL1', 'Non-receptor tyrosine-protein kinase that plays a role in many key processes linked to cell growth and survival such as cytoskeleton remodeling in response to extracellular stimuli, cell motility and adhesion, receptor endocytosis, autophagy, DNA damage response and apoptosis. Coordinates actin remodeling through tyrosine phosphorylation of proteins controlling cytoskeleton dynamics like WASF3 (involved in branch formation); ANXA1 (involved in membrane anchoring); DBN1, DBNL, CTTN, RAPH1 and ENAH (involved in signaling); or MAPT and PXN (microtubule-binding proteins). Phosphorylation of WASF3 is critical for the stimulation of lamellipodia formation and cell migration. Involved in the regulation of cell adhesion and motility through phosphorylation of key regulators of these processes such as BCAR1, CRK, CRKL, DOK1, EFS or NEDD9. Phosphorylates multiple receptor tyrosine kinases and more particularly promotes endocytosis of EGFR, facilitates the formation of neuromuscular synapses through MUSK, inhibits PDGFRB-mediated chemotaxis and modulates the endocytosis of activated B-cell receptor complexes. Other substrates which are involved in endocytosis regulation are the caveolin (CAV1) and RIN1. Moreover, ABL1 regulates the CBL family of ubiquitin ligases that drive receptor down-regulation and actin remodeling. Phosphorylation of CBL leads to increased EGFR stability. Involved in late-stage autophagy by regulating positively the trafficking and function of lysosomal components. ABL1 targets to mitochondria in response to oxidative stress and thereby mediates mitochondrial dysfunction and cell death. In response to oxidative stress, phosphorylates serine/threonine kinase PRKD2 at ''Tyr-717'' (By similarity). ABL1 is also translocated in the nucleus where it has DNA-binding activity and is involved in DNA-damage response and apoptosis. Many substrates are known mediators of DNA repair: DDB1, DDB2, ERCC3, ERCC6, RAD9A, RAD51, RAD52 or WRN. Activates the proapoptotic pathway when the DNA damage is too severe to be repaired. Phosphorylates TP73, a primary regulator for this type of damage-induced apoptosis. Phosphorylates the caspase CASP9 on ''Tyr-191'' and regulates its processing in the apoptotic response to DNA damage. Phosphorylates PSMA7 that leads to an inhibition of proteasomal activity and cell cycle transition blocks. Regulates T-cell differentiation in a TBX21-dependent manner (PubMed:21690296). Positively regulates chemokine-mediated T-cell migration, polarization, and homing to lymph nodes and immune-challenged tissues, potentially via activation of NEDD9/HEF1 and RAP1 (PubMed:22810897). Phosphorylates TBX21 on tyrosine residues leading to an enhancement of its transcriptional activator activity (PubMed:21690296).', 'Abl1', 'Mus musculus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Autophagy, Cell adhesion, Chromosomal rearrangement, Cytoplasm, Cytoskeleton, DNA damage, DNA repair, DNA-binding, Endocytosis, Kinase, Lipoprotein, Magnesium, Manganese, Metal-binding, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (369, '6YKY', '', 'Mitogen-activated protein kinase 6', 'Atypical MAPK protein. Phosphorylates microtubule-associated protein 2 (MAP2) and MAPKAPK5. The precise role of the complex formed with MAPKAPK5 is still unclear, but the complex follows a complex set of phosphorylation events: upon interaction with atypical MAPKAPK5, ERK3/MAPK6 is phosphorylated at Ser-189 and then mediates phosphorylation and activation of MAPKAPK5, which in turn phosphorylates ERK3/MAPK6. May promote entry in the cell cycle (By similarity).', 'MAPK6', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, ATP-binding, Cell cycle, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (370, '3RGF', '', 'Cyclin-dependent kinase 8', 'Component of the Mediator complex, a coactivator involved in regulated gene transcription of nearly all RNA polymerase II-dependent genes. Mediator functions as a bridge to convey information from gene-specific regulatory proteins to the basal RNA polymerase II transcription machinery. Mediator is recruited to promoters by direct interactions with regulatory proteins and serves as a scaffold for the assembly of a functional pre-initiation complex with RNA polymerase II and the general transcription factors. Phosphorylates the CTD (C-terminal domain) of the large subunit of RNA polymerase II (RNAp II), which may inhibit the formation of a transcription initiation complex. Phosphorylates CCNH leading to down-regulation of the TFIIH complex and transcriptional repression. Recruited through interaction with MAML1 to hyperphosphorylate the intracellular domain of NOTCH, leading to its degradation.', 'CDK8', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Activator, Alternative splicing, ATP-binding, Autism spectrum disorder, Disease variant, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Reference proteome, Repressor, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (371, '6UNP', '', 'Bone morphogenetic protein receptor type-2', 'On ligand binding, forms a receptor complex consisting of two type II and two type I transmembrane serine/threonine kinases. Type II receptors phosphorylate and activate type I receptors which autophosphorylate, then bind and activate SMAD transcriptional regulators. Can also mediate signaling through the activation of the p38MAPK cascade (PubMed:12045205). Binds to BMP7, BMP2 and, less efficiently, BMP4. Binding is weak but enhanced by the presence of type I receptors for BMPs. Mediates induction of adipogenesis by GDF6.', 'BMPR2', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (372, '5BRK', '', 'MOB kinase activator 1A', 'Activator of LATS1/2 in the Hippo signaling pathway which plays a pivotal role in organ size control and tumor suppression by restricting proliferation and promoting apoptosis. The core of this pathway is composed of a kinase cascade wherein STK3/MST2 and STK4/MST1, in complex with its regulatory protein SAV1, phosphorylates and activates LATS1/2 in complex with its regulatory protein MOB1, which in turn phosphorylates and inactivates YAP1 oncoprotein and WWTR1/TAZ. Phosphorylation of YAP1 by LATS1/2 inhibits its translocation into the nucleus to regulate cellular genes important for cell proliferation, cell death, and cell migration. Stimulates the kinase activity of STK38 and STK38L. Acts cooperatively with STK3/MST2 to activate STK38.', 'MOB1A', 'Homo sapiens', '{[]}', '3D-structure, Acetylation, Alternative splicing, Direct protein sequencing, Metal-binding, Phosphoprotein, Reference proteome, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (373, '8U4B', '', 'Insulin receptor', 'Receptor tyrosine kinase which mediates the pleiotropic actions of insulin. Binding of insulin leads to phosphorylation of several intracellular substrates, including, insulin receptor substrates (IRS1, 2, 3, 4), SHC, GAB1, CBL and other signaling intermediates. Each of these phosphorylated proteins serve as docking proteins for other signaling proteins that contain Src-homology-2 domains (SH2 domain) that specifically recognize different phosphotyrosine residues, including the p85 regulatory subunit of PI3K and SHP2. Phosphorylation of IRSs proteins lead to the activation of two main signaling pathways: the PI3K-AKT/PKB pathway, which is responsible for most of the metabolic actions of insulin, and the Ras-MAPK pathway, which regulates expression of some genes and cooperates with the PI3K pathway to control cell growth and differentiation. Binding of the SH2 domains of PI3K to phosphotyrosines on IRS1 leads to the activation of PI3K and the generation of phosphatidylinositol-(3, 4, 5)-triphosphate (PIP3), a lipid second messenger, which activates several PIP3-dependent serine/threonine kinases, such as PDPK1 and subsequently AKT/PKB. The net effect of this pathway is to produce a translocation of the glucose transporter SLC2A4/GLUT4 from cytoplasmic vesicles to the cell membrane to facilitate glucose transport. Moreover, upon insulin stimulation, activated AKT/PKB is responsible for: anti-apoptotic effect of insulin by inducing phosphorylation of BAD; regulates the expression of gluconeogenic and lipogenic enzymes by controlling the activity of the winged helix or forkhead (FOX) class of transcription factors. Another pathway regulated by PI3K-AKT/PKB activation is mTORC1 signaling pathway which regulates cell growth and metabolism and integrates signals from insulin. AKT mediates insulin-stimulated protein synthesis by phosphorylating TSC2 thereby activating mTORC1 pathway. The Ras/RAF/MAP2K/MAPK pathway is mainly involved in mediating cell growth, survival and cellular differentiation of insulin. Phosphorylated IRS1 recruits GRB2/SOS complex, which triggers the activation of the Ras/RAF/MAP2K/MAPK pathway. In addition to binding insulin, the insulin receptor can bind insulin-like growth factors (IGFI and IGFII). Isoform Short has a higher affinity for IGFII binding. When present in a hybrid receptor with IGF1R, binds IGF1. PubMed:12138094 shows that hybrid receptors composed of IGF1R and INSR isoform Long are activated with a high affinity by IGF1, with low affinity by IGF2 and not significantly activated by insulin, and that hybrid receptors composed of IGF1R and INSR isoform Short are activated by IGF1, IGF2 and insulin. In contrast, PubMed:16831875 shows that hybrid receptors composed of IGF1R and INSR isoform Long and hybrid receptors composed of IGF1R and INSR isoform Short have similar binding characteristics, both bind IGF1 and have a low affinity for insulin. In adipocytes, inhibits lipolysis (By similarity).', 'INSR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Carbohydrate metabolism, Cell membrane, Cleavage on pair of basic residues, Diabetes mellitus, Direct protein sequencing, Disease variant, Disulfide bond, Endosome, Glycoprotein, Kinase, Lysosome, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (374, '8AZA', '', 'E3 ubiquitin-protein ligase XIAP', 'Multi-functional protein which regulates not only caspases and apoptosis, but also modulates inflammatory signaling and immunity, copper homeostasis, mitogenic kinase signaling, cell proliferation, as well as cell invasion and metastasis (PubMed:11447297, PubMed:12121969, PubMed:9230442, PubMed:11257230, PubMed:11257231, PubMed:12620238, PubMed:17967870, PubMed:19473982, PubMed:20154138, PubMed:22103349, PubMed:17560374). Acts as a direct caspase inhibitor (PubMed:11257230, PubMed:11257231, PubMed:12620238). Directly bind to the active site pocket of CASP3 and CASP7 and obstructs substrate entry (PubMed:11257230, PubMed:11257231, PubMed:16352606, PubMed:16916640). Inactivates CASP9 by keeping it in a monomeric, inactive state (PubMed:12620238). Acts as an E3 ubiquitin-protein ligase regulating NF-kappa-B signaling and the target proteins for its E3 ubiquitin-protein ligase activity include: RIPK1, RIPK2, MAP3K2/MEKK2, DIABLO/SMAC, AIFM1, CCS, PTEN and BIRC5/survivin (PubMed:17967870, PubMed:19473982, PubMed:20154138, PubMed:22103349, PubMed:22607974, PubMed:30026309, PubMed:29452636, PubMed:17560374). Acts as an important regulator of innate immunity by mediating ''Lys-63''-linked polyubiquitination of RIPK2 downstream of NOD1 and NOD2, thereby transforming RIPK2 into a scaffolding protein for downstream effectors, ultimately leading to activation of the NF-kappa-B and MAP kinases signaling (PubMed:19667203, PubMed:22607974, PubMed:30026309, PubMed:29452636). ''Lys-63''-linked polyubiquitination of RIPK2 also promotes recruitment of the LUBAC complex to RIPK2 (PubMed:22607974, PubMed:29452636). Regulates the BMP signaling pathway and the SMAD and MAP3K7/TAK1 dependent pathways leading to NF-kappa-B and JNK activation (PubMed:17560374). Ubiquitination of CCS leads to enhancement of its chaperone activity toward its physiologic target, SOD1, rather than proteasomal degradation (PubMed:20154138). Ubiquitination of MAP3K2/MEKK2 and AIFM1 does not lead to proteasomal degradation (PubMed:17967870, PubMed:22103349). Plays a role in copper homeostasis by ubiquitinating COMMD1 and promoting its proteasomal degradation (PubMed:14685266). Can also function as E3 ubiquitin-protein ligase of the NEDD8 conjugation pathway, targeting effector caspases for neddylation and inactivation (PubMed:21145488). Ubiquitinates and therefore mediates the proteasomal degradation of BCL2 in response to apoptosis (PubMed:29020630). Protects cells from spontaneous formation of the ripoptosome, a large multi-protein complex that has the capability to kill cancer cells in a caspase-dependent and caspase-independent manner (PubMed:22095281). Suppresses ripoptosome formation by ubiquitinating RIPK1 and CASP8 (PubMed:22095281). Acts as a positive regulator of Wnt signaling and ubiquitinates TLE1, TLE2, TLE3, TLE4 and AES (PubMed:22304967). Ubiquitination of TLE3 results in inhibition of its interaction with TCF7L2/TCF4 thereby allowing efficient recruitment and binding of the transcriptional coactivator beta-catenin to TCF7L2/TCF4 that is required to initiate a Wnt-specific transcriptional program (PubMed:22304967).', 'XIAP', 'Homo sapiens', '{[''2.3.2.27'']}', '3D-structure, Apoptosis, Cytoplasm, Isopeptide bond, Metal-binding, Nucleus, Phosphoprotein, Protease inhibitor, Reference proteome, Repeat, S-nitrosylation, Thiol protease inhibitor, Transferase, Ubl conjugation, Ubl conjugation pathway, Wnt signaling pathway, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (375, '6JK8', '', 'Insulin-like growth factor 1 receptor', 'Receptor tyrosine kinase which mediates actions of insulin-like growth factor 1 (IGF1). Binds IGF1 with high affinity and IGF2 and insulin (INS) with a lower affinity. The activated IGF1R is involved in cell growth and survival control. IGF1R is crucial for tumor transformation and survival of malignant cell. Ligand binding activates the receptor kinase, leading to receptor autophosphorylation, and tyrosines phosphorylation of multiple substrates, that function as signaling adapter proteins including, the insulin-receptor substrates (IRS1/2), Shc and 14-3-3 proteins. Phosphorylation of IRSs proteins lead to the activation of two main signaling pathways: the PI3K-AKT/PKB pathway and the Ras-MAPK pathway. The result of activating the MAPK pathway is increased cellular proliferation, whereas activating the PI3K pathway inhibits apoptosis and stimulates protein synthesis. Phosphorylated IRS1 can activate the 85 kDa regulatory subunit of PI3K (PIK3R1), leading to activation of several downstream substrates, including protein AKT/PKB. AKT phosphorylation, in turn, enhances protein synthesis through mTOR activation and triggers the antiapoptotic effects of IGFIR through phosphorylation and inactivation of BAD. In parallel to PI3K-driven signaling, recruitment of Grb2/SOS by phosphorylated IRS1 or Shc leads to recruitment of Ras and activation of the ras-MAPK pathway. In addition to these two main signaling pathways IGF1R signals also through the Janus kinase/signal transducer and activator of transcription pathway (JAK/STAT). Phosphorylation of JAK proteins can lead to phosphorylation/activation of signal transducers and activators of transcription (STAT) proteins. In particular activation of STAT3, may be essential for the transforming activity of IGF1R. The JAK/STAT pathway activates gene transcription and may be responsible for the transforming activity. JNK kinases can also be activated by the IGF1R. IGF1 exerts inhibiting activities on JNK activation via phosphorylation and inhibition of MAP3K5/ASK1, which is able to directly associate with the IGF1R.', 'IGF1R', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Cleavage on pair of basic residues, Direct protein sequencing, Disease variant, Disulfide bond, Glycoprotein, Host-virus interaction, Isopeptide bond, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (376, '2WTK', '', 'Calcium-binding protein 39', 'Component of a complex that binds and activates STK11/LKB1. In the complex, required to stabilize the interaction between CAB39/MO25 (CAB39/MO25alpha or CAB39L/MO25beta) and STK11/LKB1.', 'CAB39', 'Homo sapiens', '{[]}', '3D-structure, Cytoplasm, Reference proteome');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (377, '6T28', '', 'Calcium/calmodulin-dependent protein kinase type 1D', 'Calcium/calmodulin-dependent protein kinase that operates in the calcium-triggered CaMKK-CaMK1 signaling cascade and, upon calcium influx, activates CREB-dependent gene transcription, regulates calcium-mediated granulocyte function and respiratory burst and promotes basal dendritic growth of hippocampal neurons. In neutrophil cells, required for cytokine-induced proliferative responses and activation of the respiratory burst. Activates the transcription factor CREB1 in hippocampal neuron nuclei. May play a role in apoptosis of erythroleukemia cells. In vitro, phosphorylates transcription factor CREM isoform Beta.', 'CAMK1D', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Allosteric enzyme, Alternative splicing, ATP-binding, Calcium, Calmodulin-binding, Cytoplasm, Inflammatory response, Isopeptide bond, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (378, '1XWS', '', 'Serine/threonine-protein kinase pim-1', 'Proto-oncogene with serine/threonine kinase activity involved in cell survival and cell proliferation and thus providing a selective advantage in tumorigenesis (PubMed:15528381, PubMed:1825810, PubMed:31548394). Exerts its oncogenic activity through: the regulation of MYC transcriptional activity, the regulation of cell cycle progression and by phosphorylation and inhibition of proapoptotic proteins (BAD, MAP3K5, FOXO3) (PubMed:18593906). Phosphorylation of MYC leads to an increase of MYC protein stability and thereby an increase of transcriptional activity (By similarity). The stabilization of MYC exerted by PIM1 might explain partly the strong synergism between these two oncogenes in tumorigenesis (By similarity). Mediates survival signaling through phosphorylation of BAD, which induces release of the anti-apoptotic protein Bcl-X(L)/BCL2L1 (By similarity). Phosphorylation of MAP3K5, another proapoptotic protein, by PIM1, significantly decreases MAP3K5 kinase activity and inhibits MAP3K5-mediated phosphorylation of JNK and JNK/p38MAPK subsequently reducing caspase-3 activation and cell apoptosis (PubMed:19749799). Stimulates cell cycle progression at the G1-S and G2-M transitions by phosphorylation of CDC25A and CDC25C (PubMed:16356754). Phosphorylation of CDKN1A, a regulator of cell cycle progression at G1, results in the relocation of CDKN1A to the cytoplasm and enhanced CDKN1A protein stability (PubMed:12431783). Promotes cell cycle progression and tumorigenesis by down-regulating expression of a regulator of cell cycle progression, CDKN1B, at both transcriptional and post-translational levels (PubMed:18593906). Phosphorylation of CDKN1B, induces 14-3-3 proteins binding, nuclear export and proteasome-dependent degradation (PubMed:18593906). May affect the structure or silencing of chromatin by phosphorylating HP1 gamma/CBX3 (PubMed:10664448). Acts also as a regulator of homing and migration of bone marrow cells involving functional interaction with the CXCL12-CXCR4 signaling axis (By similarity). Acts as a positive regulator of mTORC1 signaling by mediating phosphorylation and inhibition of DEPDC5 component of the GATOR1 complex (PubMed:31548394). Acts as a negative regulator of innate immunity by mediating phosphorylation and inactivation of GBP1 in absence of infection: phosphorylation of GBP1 induces interaction with 14-3-3 protein sigma (SFN) and retention in the cytosol (PubMed:37797010). Also phosphorylates and activates the ATP-binding cassette transporter ABCG2, allowing resistance to drugs through their excretion from cells (PubMed:18056989). Promotes brown adipocyte differentiation (By similarity).', 'PIM1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative initiation, Apoptosis, ATP-binding, Cell cycle, Cell membrane, Cytoplasm, Direct protein sequencing, Host-virus interaction, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (379, '6D3K', '', 'Interferon-induced, double-stranded RNA-activated protein kinase', 'IFN-induced dsRNA-dependent serine/threonine-protein kinase that phosphorylates the alpha subunit of eukaryotic translation initiation factor 2 (EIF2S1/eIF-2-alpha) and plays a key role in the innate immune response to viral infection (PubMed:18835251, PubMed:19507191, PubMed:19189853, PubMed:21123651, PubMed:21072047, PubMed:22948139, PubMed:23229543, PubMed:22381929). Inhibits viral replication via the integrated stress response (ISR): EIF2S1/eIF-2-alpha phosphorylation in response to viral infection converts EIF2S1/eIF-2-alpha in a global protein synthesis inhibitor, resulting to a shutdown of cellular and viral protein synthesis, while concomitantly initiating the preferential translation of ISR-specific mRNAs, such as the transcriptional activator ATF4 (PubMed:19189853, PubMed:21123651, PubMed:22948139, PubMed:23229543). Exerts its antiviral activity on a wide range of DNA and RNA viruses including hepatitis C virus (HCV), hepatitis B virus (HBV), measles virus (MV) and herpes simplex virus 1 (HHV-1) (PubMed:11836380, PubMed:19189853, PubMed:20171114, PubMed:19840259, PubMed:21710204, PubMed:23115276, PubMed:23399035). Also involved in the regulation of signal transduction, apoptosis, cell proliferation and differentiation: phosphorylates other substrates including p53/TP53, PPP2R5A, DHX9, ILF3, IRS1 and the HHV-1 viral protein US11 (PubMed:11836380, PubMed:22214662, PubMed:19229320). In addition to serine/threonine-protein kinase activity, also has tyrosine-protein kinase activity and phosphorylates CDK1 at ''Tyr-4'' upon DNA damage, facilitating its ubiquitination and proteasomal degradation (PubMed:20395957). Either as an adapter protein and/or via its kinase activity, can regulate various signaling pathways (p38 MAP kinase, NF-kappa-B and insulin signaling pathways) and transcription factors (JUN, STAT1, STAT3, IRF1, ATF3) involved in the expression of genes encoding pro-inflammatory cytokines and IFNs (PubMed:22948139, PubMed:23084476, PubMed:23372823). Activates the NF-kappa-B pathway via interaction with IKBKB and TRAF family of proteins and activates the p38 MAP kinase pathway via interaction with MAP2K6 (PubMed:10848580, PubMed:15121867, PubMed:15229216). Can act as both a positive and negative regulator of the insulin signaling pathway (ISP) (PubMed:20685959). Negatively regulates ISP by inducing the inhibitory phosphorylation of insulin receptor substrate 1 (IRS1) at ''Ser-312'' and positively regulates ISP via phosphorylation of PPP2R5A which activates FOXO1, which in turn up-regulates the expression of insulin receptor substrate 2 (IRS2) (PubMed:20685959). Can regulate NLRP3 inflammasome assembly and the activation of NLRP3, NLRP1, AIM2 and NLRC4 inflammasomes (PubMed:22801494). Plays a role in the regulation of the cytoskeleton by binding to gelsolin (GSN), sequestering the protein in an inactive conformation away from actin (By similarity).', 'EIF2AK2', 'Homo sapiens', '{[''2.7.10.2'',''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Antiviral defense, ATP-binding, Cytoplasm, Direct protein sequencing, Disease variant, Dystonia, Host-virus interaction, Immunity, Innate immunity, Isopeptide bond, Kinase, Magnesium, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, RNA-binding, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (380, '2D9Z', '', 'Serine/threonine-protein kinase D3', 'Converts transient diacylglycerol (DAG) signals into prolonged physiological effects, downstream of PKC. Involved in resistance to oxidative stress (By similarity).', 'PRKD3', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (381, '1A9U', '', 'Mitogen-activated protein kinase 14', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. MAPK14 is one of the four p38 MAPKs which play an important role in the cascades of cellular responses evoked by extracellular stimuli such as pro-inflammatory cytokines or physical stress leading to direct activation of transcription factors. Accordingly, p38 MAPKs phosphorylate a broad range of proteins and it has been estimated that they may have approximately 200 to 300 substrates each. Some of the targets are downstream kinases which are activated through phosphorylation and further phosphorylate additional targets. RPS6KA5/MSK1 and RPS6KA4/MSK2 can directly phosphorylate and activate transcription factors such as CREB1, ATF1, the NF-kappa-B isoform RELA/NFKB3, STAT1 and STAT3, but can also phosphorylate histone H3 and the nucleosomal protein HMGN1 (PubMed:9687510, PubMed:9792677). RPS6KA5/MSK1 and RPS6KA4/MSK2 play important roles in the rapid induction of immediate-early genes in response to stress or mitogenic stimuli, either by inducing chromatin remodeling or by recruiting the transcription machinery (PubMed:9687510, PubMed:9792677). On the other hand, two other kinase targets, MAPKAPK2/MK2 and MAPKAPK3/MK3, participate in the control of gene expression mostly at the post-transcriptional level, by phosphorylating ZFP36 (tristetraprolin) and ELAVL1, and by regulating EEF2K, which is important for the elongation of mRNA during translation. MKNK1/MNK1 and MKNK2/MNK2, two other kinases activated by p38 MAPKs, regulate protein synthesis by phosphorylating the initiation factor EIF4E2 (PubMed:11154262). MAPK14 interacts also with casein kinase II, leading to its activation through autophosphorylation and further phosphorylation of TP53/p53 (PubMed:10747897). In the cytoplasm, the p38 MAPK pathway is an important regulator of protein turnover. For example, CFLAR is an inhibitor of TNF-induced apoptosis whose proteasome-mediated degradation is regulated by p38 MAPK phosphorylation. In a similar way, MAPK14 phosphorylates the ubiquitin ligase SIAH2, regulating its activity towards EGLN3 (PubMed:17003045). MAPK14 may also inhibit the lysosomal degradation pathway of autophagy by interfering with the intracellular trafficking of the transmembrane protein ATG9 (PubMed:19893488). Another function of MAPK14 is to regulate the endocytosis of membrane receptors by different mechanisms that impinge on the small GTPase RAB5A. In addition, clathrin-mediated EGFR internalization induced by inflammatory cytokines and UV irradiation depends on MAPK14-mediated phosphorylation of EGFR itself as well as of RAB5A effectors (PubMed:16932740). Ectodomain shedding of transmembrane proteins is regulated by p38 MAPKs as well. In response to inflammatory stimuli, p38 MAPKs phosphorylate the membrane-associated metalloprotease ADAM17 (PubMed:20188673). Such phosphorylation is required for ADAM17-mediated ectodomain shedding of TGF-alpha family ligands, which results in the activation of EGFR signaling and cell proliferation. Another p38 MAPK substrate is FGFR1. FGFR1 can be translocated from the extracellular space into the cytosol and nucleus of target cells, and regulates processes such as rRNA synthesis and cell growth. FGFR1 translocation requires p38 MAPK activation. In the nucleus, many transcription factors are phosphorylated and activated by p38 MAPKs in response to different stimuli. Classical examples include ATF1, ATF2, ATF6, ELK1, PTPRH, DDIT3, TP53/p53 and MEF2C and MEF2A (PubMed:9430721, PubMed:9858528, PubMed:10330143). The p38 MAPKs are emerging as important modulators of gene expression by regulating chromatin modifiers and remodelers. The promoters of several genes involved in the inflammatory response, such as IL6, IL8 and IL12B, display a p38 MAPK-dependent enrichment of histone H3 phosphorylation on ''Ser-10'' (H3S10ph) in LPS-stimulated myeloid cells. This phosphorylation enhances the accessibility of the cryptic NF-kappa-B-binding sites marking promoters for increased NF-kappa-B recruitment. Phosphorylates CDC25B and CDC25C which is required for binding to 14-3-3 proteins and leads to initiation of a G2 delay after ultraviolet radiation (PubMed:11333986). Phosphorylates TIAR following DNA damage, releasing TIAR from GADD45A mRNA and preventing mRNA degradation (PubMed:20932473). The p38 MAPKs may also have kinase-independent roles, which are thought to be due to the binding to targets in the absence of phosphorylation. Protein O-Glc-N-acylation catalyzed by the OGT is regulated by MAPK14, and, although OGT does not seem to be phosphorylated by MAPK14, their interaction increases upon MAPK14 activation induced by glucose deprivation. This interaction may regulate OGT activity by recruiting it to specific targets such as neurofilament H, stimulating its O-Glc-N-acylation. Required in mid-fetal development for the growth of embryo-derived blood vessels in the labyrinth layer of the placenta. Also plays an essential role in developmental and stress-induced erythropoiesis, through regulation of EPO gene expression (PubMed:10943842). Isoform MXI2 activation is stimulated by mitogens and oxidative stress and only poorly phosphorylates ELK1 and ATF2. Isoform EXIP may play a role in the early onset of apoptosis. Phosphorylates S100A9 at ''Thr-113'' (PubMed:15905572). Phosphorylates NLRP1 downstream of MAP3K20/ZAK in response to UV-B irradiation and ribosome collisions, promoting activation of the NLRP1 inflammasome and pyroptosis (PubMed:35857590).', 'MAPK14', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Direct protein sequencing, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (382, '5W5V', '', 'Serine/threonine-protein kinase TBK1', 'Serine/threonine kinase that plays an essential role in regulating inflammatory responses to foreign agents (PubMed:12692549, PubMed:14703513, PubMed:18583960, PubMed:12702806, PubMed:15367631, PubMed:10581243, PubMed:11839743, PubMed:15485837, PubMed:21138416, PubMed:25636800, PubMed:23453971, PubMed:23453972, PubMed:23746807, PubMed:26611359, PubMed:32404352). Following activation of toll-like receptors by viral or bacterial components, associates with TRAF3 and TANK and phosphorylates interferon regulatory factors (IRFs) IRF3 and IRF7 as well as DDX3X (PubMed:12692549, PubMed:14703513, PubMed:18583960, PubMed:12702806, PubMed:15367631, PubMed:25636800). This activity allows subsequent homodimerization and nuclear translocation of the IRFs leading to transcriptional activation of pro-inflammatory and antiviral genes including IFNA and IFNB (PubMed:12702806, PubMed:15367631, PubMed:25636800, PubMed:32972995). In order to establish such an antiviral state, TBK1 form several different complexes whose composition depends on the type of cell and cellular stimuli (PubMed:23453971, PubMed:23453972, PubMed:23746807). Plays a key role in IRF3 activation: acts by first phosphorylating innate adapter proteins MAVS, STING1 and TICAM1 on their pLxIS motif, leading to recruitment of IRF3, thereby licensing IRF3 for phosphorylation by TBK1 (PubMed:25636800, PubMed:30842653). Phosphorylated IRF3 dissociates from the adapter proteins, dimerizes, and then enters the nucleus to induce expression of interferons (PubMed:25636800). Thus, several scaffolding molecules including FADD, TRADD, MAVS, AZI2, TANK or TBKBP1/SINTBAD can be recruited to the TBK1-containing-complexes (PubMed:21931631). Under particular conditions, functions as a NF-kappa-B effector by phosphorylating NF-kappa-B inhibitor alpha/NFKBIA, IKBKB or RELA to translocate NF-Kappa-B to the nucleus (PubMed:10783893, PubMed:15489227). Restricts bacterial proliferation by phosphorylating the autophagy receptor OPTN/Optineurin on ''Ser-177'', thus enhancing LC3 binding affinity and antibacterial autophagy (PubMed:21617041). Phosphorylates SMCR8 component of the C9orf72-SMCR8 complex, promoting autophagosome maturation (PubMed:27103069). Phosphorylates ATG8 proteins MAP1LC3C and GABARAPL2, thereby preventing their delipidation and premature removal from nascent autophagosomes (PubMed:31709703). Phosphorylates and activates AKT1 (PubMed:21464307). Seems to play a role in energy balance regulation by sustaining a state of chronic, low-grade inflammation in obesity, wich leads to a negative impact on insulin sensitivity (By similarity). Attenuates retroviral budding by phosphorylating the endosomal sorting complex required for transport-I (ESCRT-I) subunit VPS37C (PubMed:21270402). Phosphorylates Borna disease virus (BDV) P protein (PubMed:16155125). Plays an essential role in the TLR3- and IFN-dependent control of herpes virus HSV-1 and HSV-2 infections in the central nervous system (PubMed:22851595). Acts both as a positive and negative regulator of the mTORC1 complex, depending on the context: activates mTORC1 in response to growth factors by catalyzing phosphorylation of MTOR, while it limits the mTORC1 complex by promoting phosphorylation of RPTOR (PubMed:29150432, PubMed:31530866).', 'TBK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Amyotrophic lateral sclerosis, Antiviral defense, ATP-binding, Coiled coil, Cytoplasm, Disease variant, Glaucoma, Host-virus interaction, Immunity, Innate immunity, Isopeptide bond, Kinase, Neurodegeneration, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (383, '8FP1', '', 'Protein kinase C eta type', 'Calcium-independent, phospholipid- and diacylglycerol (DAG)-dependent serine/threonine-protein kinase that is involved in the regulation of cell differentiation in keratinocytes and pre-B cell receptor, mediates regulation of epithelial tight junction integrity and foam cell formation, and is required for glioblastoma proliferation and apoptosis prevention in MCF-7 cells. In keratinocytes, binds and activates the tyrosine kinase FYN, which in turn blocks epidermal growth factor receptor (EGFR) signaling and leads to keratinocyte growth arrest and differentiation. Associates with the cyclin CCNE1-CDK2-CDKN1B complex and inhibits CDK2 kinase activity, leading to RB1 dephosphorylation and thereby G1 arrest in keratinocytes. In association with RALA activates actin depolymerization, which is necessary for keratinocyte differentiation. In the pre-B cell receptor signaling, functions downstream of BLNK by up-regulating IRF4, which in turn activates L chain gene rearrangement. Regulates epithelial tight junctions (TJs) by phosphorylating occludin (OCLN) on threonine residues, which is necessary for the assembly and maintenance of TJs. In association with PLD2 and via TLR4 signaling, is involved in lipopolysaccharide (LPS)-induced RGS2 down-regulation and foam cell formation. Upon PMA stimulation, mediates glioblastoma cell proliferation by activating the mTOR pathway, the PI3K/AKT pathway and the ERK1-dependent phosphorylation of ELK1. Involved in the protection of glioblastoma cells from irradiation-induced apoptosis by preventing caspase-9 activation. In camptothecin-treated MCF-7 cells, regulates NF-kappa-B upstream signaling by activating IKBKB, and confers protection against DNA damage-induced apoptosis. Promotes oncogenic functions of ATF2 in the nucleus while blocking its apoptotic function at mitochondria. Phosphorylates ATF2 which promotes its nuclear retention and transcriptional activity and negatively regulates its mitochondrial localization.', 'PRKCH', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Differentiation, Kinase, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (384, '7MFD', '', 'Serine/threonine-protein kinase B-raf', 'Protein kinase involved in the transduction of mitogenic signals from the cell membrane to the nucleus (Probable). Phosphorylates MAP2K1, and thereby activates the MAP kinase signal transduction pathway (PubMed:21441910, PubMed:29433126). Phosphorylates PFKFB2 (PubMed:36402789). May play a role in the postsynaptic responses of hippocampal neurons (PubMed:1508179).', 'BRAF', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Allosteric enzyme, ATP-binding, Cardiomyopathy, Cell membrane, Chromosomal rearrangement, Cytoplasm, Deafness, Direct protein sequencing, Disease variant, Ectodermal dysplasia, Intellectual disability, Isopeptide bond, Kinase, Membrane, Metal-binding, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (427, '2QLU', '', 'Activin receptor type-2B', 'Transmembrane serine/threonine kinase activin type-2 receptor forming an activin receptor complex with activin type-1 serine/threonine kinase receptors (ACVR1, ACVR1B or ACVR1c). Transduces the activin signal from the cell surface to the cytoplasm and is thus regulating many physiological and pathological processes including neuronal differentiation and neuronal survival, hair follicle development and cycling, FSH production by the pituitary gland, wound healing, extracellular matrix production, immunosuppression and carcinogenesis. Activin is also thought to have a paracrine or autocrine role in follicular development in the ovary. Within the receptor complex, the type-2 receptors act as a primary activin receptors (binds activin-A/INHBA, activin-B/INHBB as well as inhibin-A/INHA-INHBA). The type-1 receptors like ACVR1B act as downstream transducers of activin signals. Activin binds to type-2 receptor at the plasma membrane and activates its serine-threonine kinase. The activated receptor type-2 then phosphorylates and activates the type-1 receptor. Once activated, the type-1 receptor binds and phosphorylates the SMAD proteins SMAD2 and SMAD3, on serine residues of the C-terminal tail. Soon after their association with the activin receptor and subsequent phosphorylation, SMAD2 and SMAD3 are released into the cytoplasm where they interact with the common partner SMAD4. This SMAD complex translocates into the nucleus where it mediates activin-induced transcription. Inhibitory SMAD7, which is recruited to ACVR1B through FKBP1A, can prevent the association of SMAD2 and SMAD3 with the activin receptor complex, thereby blocking the activin signal. Activin signal transduction is also antagonized by the binding to the receptor of inhibin-B via the IGSF1 inhibin coreceptor.', 'ACVR2B', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Heterotaxy, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (385, '7ZKX', '', 'SRSF protein kinase 2', 'Serine/arginine-rich protein-specific kinase which specifically phosphorylates its substrates at serine residues located in regions rich in arginine/serine dipeptides, known as RS domains and is involved in the phosphorylation of SR splicing factors and the regulation of splicing (PubMed:9472028, PubMed:18559500, PubMed:21056976). Promotes neuronal apoptosis by up-regulating cyclin-D1 (CCND1) expression (PubMed:19592491). This is done by the phosphorylation of SRSF2, leading to the suppression of p53/TP53 phosphorylation thereby relieving the repressive effect of p53/TP53 on cyclin-D1 (CCND1) expression (PubMed:21205200). Phosphorylates ACIN1, and redistributes it from the nuclear speckles to the nucleoplasm, resulting in cyclin A1 but not cyclin A2 up-regulation (PubMed:18559500). Plays an essential role in spliceosomal B complex formation via the phosphorylation of DDX23/PRP28 (PubMed:18425142). Probably by phosphorylating DDX23, leads to the suppression of incorrect R-loops formed during transcription; R-loops are composed of a DNA:RNA hybrid and the associated non-template single-stranded DNA (PubMed:28076779). Can mediate hepatitis B virus (HBV) core protein phosphorylation (PubMed:12134018). Plays a negative role in the regulation of HBV replication through a mechanism not involving the phosphorylation of the core protein but by reducing the packaging efficiency of the pregenomic RNA (pgRNA) without affecting the formation of the viral core particles (PubMed:16122776).', 'SRPK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Chromosome, Cytoplasm, Differentiation, Kinase, mRNA processing, mRNA splicing, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (386, '2YA9', '', 'Death-associated protein kinase 2', 'Calcium/calmodulin-dependent serine/threonine kinase involved in multiple cellular signaling pathways that trigger cell survival, apoptosis, and autophagy. Capable of regulating both type I apoptotic and type II autophagic cell death signals. The former involves caspase activation, chromatin and mitochondrial condensation while the latter involves caspase-independent cell death in conjunction with accumulation of mature autophagic vesicles, plasma membrane blebs, and nuclear condensation without DNA degradation. Mediator of anoikis and a suppressor of beta-catenin-dependent anchorage-independent growth of malignant epithelial cells. May play a role in granulocytic maturation (By similarity). Regulates granulocytes motility by controlling cell spreading and polarization (PubMed:24163421).', 'Dapk2', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Calmodulin-binding, Cytoplasm, Cytoplasmic vesicle, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (387, '3P1A', '', 'Membrane-associated tyrosine- and threonine-specific cdc2-inhibitory kinase', 'Acts as a negative regulator of entry into mitosis (G2 to M transition) by phosphorylation of the CDK1 kinase specifically when CDK1 is complexed to cyclins (PubMed:9268380, PubMed:9001210, PubMed:10504341, PubMed:10373560). Mediates phosphorylation of CDK1 predominantly on ''Thr-14''. Also involved in Golgi fragmentation (PubMed:9268380, PubMed:9001210). May be involved in phosphorylation of CDK1 on ''Tyr-15'' to a lesser degree, however tyrosine kinase activity is unclear and may be indirect (PubMed:9268380, PubMed:9001210).', 'PKMYT1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Endoplasmic reticulum, Golgi apparatus, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (388, '6YG1', '', 'Dual specificity mitogen-activated protein kinase kinase 7', 'Dual specificity protein kinase which acts as an essential component of the MAP kinase signal transduction pathway. Essential component of the stress-activated protein kinase/c-Jun N-terminal kinase (SAP/JNK) signaling pathway. With MAP2K4/MKK4, is the one of the only known kinase to directly activate the stress-activated protein kinase/c-Jun N-terminal kinases MAPK8/JNK1, MAPK9/JNK2 and MAPK10/JNK3. MAP2K4/MKK4 and MAP2K7/MKK7 both activate the JNKs by phosphorylation, but they differ in their preference for the phosphorylation site in the Thr-Pro-Tyr motif. MAP2K4/MKK4 shows preference for phosphorylation of the Tyr residue and MAP2K7/MKK7 for the Thr residue. The monophosphorylation of JNKs on the Thr residue is sufficient to increase JNK activity indicating that MAP2K7/MKK7 is important to trigger JNK activity, while the additional phosphorylation of the Tyr residue by MAP2K4/MKK4 ensures optimal JNK activation. Has a specific role in JNK signal transduction pathway activated by pro-inflammatory cytokines. The MKK/JNK signaling pathway is also involved in mitochondrial death signaling pathway, including the release cytochrome c, leading to apoptosis. Part of a non-canonical MAPK signaling pathway, composed of the upstream MAP3K12 kinase and downstream MAP kinases MAPK1/ERK2 and MAPK3/ERK1, that enhances the AP-1-mediated transcription of APP in response to APOE (PubMed:28111074).', 'MAP2K7', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (389, '3ZDU', '', 'Cyclin-dependent kinase-like 3', 'Unknown', 'CDKL3', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (433, '2GK9', '', 'Phosphatidylinositol 5-phosphate 4-kinase type-2 gamma', 'Phosphatidylinositol 5-phosphate 4-kinase with low enzymatic activity. May be a GTP sensor, has higher GTP-dependent kinase activity than ATP-dependent kinase activity. PIP4Ks negatively regulate insulin signaling through a catalytic-independent mechanism. They interact with PIP5Ks and suppress PIP5K-mediated PtdIns(4,5)P2 synthesis and insulin-dependent conversion to PtdIns(3,4,5)P3 (PubMed:31091439).', 'PIP4K2C', 'Homo sapiens', '{[''2.7.1.149'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Endoplasmic reticulum, Kinase, Lipid metabolism, Nucleotide-binding, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (390, '5L4Q', '', 'AP2-associated protein kinase 1', 'Regulates clathrin-mediated endocytosis by phosphorylating the AP2M1/mu2 subunit of the adaptor protein complex 2 (AP-2) which ensures high affinity binding of AP-2 to cargo membrane proteins during the initial stages of endocytosis (PubMed:17494869, PubMed:11877457, PubMed:11877461, PubMed:12952931, PubMed:14617351, PubMed:25653444). Isoform 1 and isoform 2 display similar levels of kinase activity towards AP2M1 (PubMed:17494869). Preferentially, may phosphorylate substrates on threonine residues (PubMed:11877457, PubMed:18657069). Regulates phosphorylation of other AP-2 subunits as well as AP-2 localization and AP-2-mediated internalization of ligand complexes (PubMed:12952931). Phosphorylates NUMB and regulates its cellular localization, promoting NUMB localization to endosomes (PubMed:18657069). Binds to and stabilizes the activated form of NOTCH1, increases its localization in endosomes and regulates its transcriptional activity (PubMed:21464124).', 'AAK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell membrane, Cell projection, Coated pit, Endocytosis, Kinase, Membrane, Methylation, Nucleotide-binding, Pharmaceutical, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Synapse, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (391, '3ANQ', '', 'Dual specificity tyrosine-phosphorylation-regulated kinase 1A', 'Dual-specificity kinase which possesses both serine/threonine and tyrosine kinase activities (PubMed:21127067, PubMed:8769099, PubMed:30773093, PubMed:20981014, PubMed:23665168). Exhibits a substrate preference for proline at position P+1 and arginine at position P-3 (PubMed:23665168). Plays an important role in double-strand breaks (DSBs) repair following DNA damage (PubMed:31024071). Mechanistically, phosphorylates RNF169 and increases its ability to block accumulation of TP53BP1 at the DSB sites thereby promoting homologous recombination repair (HRR) (PubMed:30773093). Also acts as a positive regulator of transcription by acting as a CTD kinase that mediates phosphorylation of the CTD (C-terminal domain) of the large subunit of RNA polymerase II (RNAP II) POLR2A (PubMed:25620562, PubMed:29849146). May play a role in a signaling pathway regulating nuclear functions of cell proliferation (PubMed:14500717). Modulates alternative splicing by phosphorylating the splice factor SRSF6 (By similarity). Has pro-survival function and negatively regulates the apoptotic process (By similarity). Promotes cell survival upon genotoxic stress through phosphorylation of SIRT1 (By similarity). This in turn inhibits p53/TP53 activity and apoptosis (By similarity). Phosphorylates SEPTIN4, SEPTIN5 and SF3B1 at ''Thr-434'' (By similarity).', 'DYRK1A', 'Homo sapiens', '{[''2.7.11.23'',''2.7.12.1'']}', '3D-structure, Alternative splicing, ATP-binding, Host-virus interaction, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (392, '4CFE', '', '5''-AMP-activated protein kinase catalytic subunit alpha-2', 'Catalytic subunit of AMP-activated protein kinase (AMPK), an energy sensor protein kinase that plays a key role in regulating cellular energy metabolism (PubMed:17307971, PubMed:17712357). In response to reduction of intracellular ATP levels, AMPK activates energy-producing pathways and inhibits energy-consuming processes: inhibits protein, carbohydrate and lipid biosynthesis, as well as cell growth and proliferation (PubMed:17307971, PubMed:17712357). AMPK acts via direct phosphorylation of metabolic enzymes, and by longer-term effects via phosphorylation of transcription regulators (PubMed:17307971, PubMed:17712357). Regulates lipid synthesis by phosphorylating and inactivating lipid metabolic enzymes such as ACACA, ACACB, GYS1, HMGCR and LIPE; regulates fatty acid and cholesterol synthesis by phosphorylating acetyl-CoA carboxylase (ACACA and ACACB) and hormone-sensitive lipase (LIPE) enzymes, respectively (PubMed:7959015). Promotes lipolysis of lipid droplets by mediating phosphorylation of isoform 1 of CHKA (CHKalpha2) (PubMed:34077757). Regulates insulin-signaling and glycolysis by phosphorylating IRS1, PFKFB2 and PFKFB3 (By similarity). Involved in insulin receptor/INSR internalization (PubMed:25687571). AMPK stimulates glucose uptake in muscle by increasing the translocation of the glucose transporter SLC2A4/GLUT4 to the plasma membrane, possibly by mediating phosphorylation of TBC1D4/AS160 (By similarity). Regulates transcription and chromatin structure by phosphorylating transcription regulators involved in energy metabolism such as CRTC2/TORC2, FOXO3, histone H2B, HDAC5, MEF2C, MLXIPL/ChREBP, EP300, HNF4A, p53/TP53, SREBF1, SREBF2 and PPARGC1A (PubMed:11554766, PubMed:11518699, PubMed:15866171, PubMed:17711846, PubMed:18184930). Acts as a key regulator of glucose homeostasis in liver by phosphorylating CRTC2/TORC2, leading to CRTC2/TORC2 sequestration in the cytoplasm (By similarity). In response to stress, phosphorylates ''Ser-36'' of histone H2B (H2BS36ph), leading to promote transcription (By similarity). Acts as a key regulator of cell growth and proliferation by phosphorylating FNIP1, TSC2, RPTOR, WDR24 and ATG1/ULK1: in response to nutrient limitation, negatively regulates the mTORC1 complex by phosphorylating RPTOR component of the mTORC1 complex and by phosphorylating and activating TSC2 (PubMed:14651849, PubMed:20160076, PubMed:21205641). Also phosphorylates and inhibits GATOR2 subunit WDR24 in response to nutrient limitation, leading to suppress glucose-mediated mTORC1 activation (PubMed:36732624). In response to energetic stress, phosphorylates FNIP1, inactivating the non-canonical mTORC1 signaling, thereby promoting nuclear translocation of TFEB and TFE3, and inducing transcription of lysosomal or autophagy genes (PubMed:37079666). In response to nutrient limitation, promotes autophagy by phosphorylating and activating ATG1/ULK1 (PubMed:21205641). In that process also activates WDR45/WIPI4 (PubMed:28561066). Phosphorylates CASP6, thereby preventing its autoprocessing and subsequent activation (PubMed:32029622). AMPK also acts as a regulator of circadian rhythm by mediating phosphorylation of CRY1, leading to destabilize it (By similarity). May regulate the Wnt signaling pathway by phosphorylating CTNNB1, leading to stabilize it (By similarity). Also acts as a regulator of cellular polarity by remodeling the actin cytoskeleton; probably by indirectly activating myosin (PubMed:17486097). Also phosphorylates CFTR, EEF2K, KLC1, NOS3 and SLC12A1 (PubMed:12519745, PubMed:20074060). Plays an important role in the differential regulation of pro-autophagy (composed of PIK3C3, BECN1, PIK3R4 and UVRAG or ATG14) and non-autophagy (composed of PIK3C3, BECN1 and PIK3R4) complexes, in response to glucose starvation (By similarity). Can inhibit the non-autophagy complex by phosphorylating PIK3C3 and can activate the pro-autophagy complex by phosphorylating BECN1 (By similarity). Upon glucose starvation, promotes ARF6 activation in a kinase-independent manner leading to cell migration (PubMed:36017701). Upon glucose deprivation mediates the phosphorylation of ACSS2 at ''Ser-659'', which exposes the nuclear localization signal of ACSS2, required for its interaction with KPNA1 and nuclear translocation (PubMed:28552616).', 'PRKAA2', 'Homo sapiens', '{[''2.7.11.31'',''2.7.11.1'']}', '3D-structure, ATP-binding, Autophagy, Biological rhythms, Cholesterol biosynthesis, Cholesterol metabolism, Chromatin regulator, Cytoplasm, Fatty acid biosynthesis, Fatty acid metabolism, Kinase, Lipid biosynthesis, Lipid metabolism, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Steroid biosynthesis, Steroid metabolism, Sterol biosynthesis, Sterol metabolism, Transcription, Transcription regulation, Transferase, Ubl conjugation, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (393, '4HZS', '', 'Activated CDC42 kinase 1', 'Non-receptor tyrosine-protein and serine/threonine-protein kinase that is implicated in cell spreading and migration, cell survival, cell growth and proliferation. Transduces extracellular signals to cytosolic and nuclear effectors. Phosphorylates AKT1, AR, MCF2, WASL and WWOX. Implicated in trafficking and clathrin-mediated endocytosis through binding to epidermal growth factor receptor (EGFR) and clathrin. Binds to both poly- and mono-ubiquitin and regulates ligand-induced degradation of EGFR, thereby contributing to the accumulation of EGFR at the limiting membrane of early endosomes. Downstream effector of CDC42 which mediates CDC42-dependent cell migration via phosphorylation of BCAR1. May be involved both in adult synaptic function and plasticity and in brain development. Activates AKT1 by phosphorylating it on ''Tyr-176''. Phosphorylates AR on ''Tyr-267'' and ''Tyr-363'' thereby promoting its recruitment to androgen-responsive enhancers (AREs). Phosphorylates WWOX on ''Tyr-287''. Phosphorylates MCF2, thereby enhancing its activity as a guanine nucleotide exchange factor (GEF) toward Rho family proteins. Contributes to the control of AXL receptor levels. Confers metastatic properties on cancer cells and promotes tumor growth by negatively regulating tumor suppressor such as WWOX and positively regulating pro-survival factors such as AKT1 and AR. Phosphorylates WASP (PubMed:20110370).', 'TNK2', 'Homo sapiens', '{[''2.7.10.2'',''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell junction, Cell membrane, Coated pit, Cytoplasm, Cytoplasmic vesicle, Endocytosis, Endosome, Kinase, Magnesium, Membrane, Metal-binding, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (417, '7T6F', '', 'Tyrosine-protein kinase JAK1', 'Tyrosine kinase of the non-receptor type, involved in the IFN-alpha/beta/gamma signal pathway. Kinase partner for the interleukin (IL)-2 receptor as well as interleukin (IL)-10 receptor. Kinase partner for the type I interferon receptor IFNAR2. In response to interferon-binding to IFNAR1-IFNAR2 heterodimer, phosphorylates and activates its binding partner IFNAR2, creating docking sites for STAT proteins. Directly phosphorylates STAT proteins but also activates STAT signaling through the transactivation of other JAK kinases associated with signaling receptors.', 'Jak1', 'Mus musculus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, ATP-binding, Direct protein sequencing, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SH2 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (394, '6FER', '', 'Discoidin domain-containing receptor 2', 'Tyrosine kinase involved in the regulation of tissues remodeling (PubMed:30449416). It functions as a cell surface receptor for fibrillar collagen and regulates cell differentiation, remodeling of the extracellular matrix, cell migration and cell proliferation. Required for normal bone development. Regulates osteoblast differentiation and chondrocyte maturation via a signaling pathway that involves MAP kinases and leads to the activation of the transcription factor RUNX2. Regulates remodeling of the extracellular matrix by up-regulation of the collagenases MMP1, MMP2 and MMP13, and thereby facilitates cell migration and tumor cell invasion. Promotes fibroblast migration and proliferation, and thereby contributes to cutaneous wound healing.', 'DDR2', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Dwarfism, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Osteogenesis, Phosphoprotein, Receptor, Reference proteome, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (395, '7SXF', '', 'Glycogen synthase kinase-3 alpha', 'Constitutively active protein kinase that acts as a negative regulator in the hormonal control of glucose homeostasis, Wnt signaling and regulation of transcription factors and microtubules, by phosphorylating and inactivating glycogen synthase (GYS1 or GYS2), CTNNB1/beta-catenin, APC and AXIN1 (PubMed:11749387, PubMed:17478001, PubMed:19366350). Requires primed phosphorylation of the majority of its substrates (PubMed:11749387, PubMed:17478001, PubMed:19366350). Contributes to insulin regulation of glycogen synthesis by phosphorylating and inhibiting GYS1 activity and hence glycogen synthesis (PubMed:11749387, PubMed:17478001, PubMed:19366350). Regulates glycogen metabolism in liver, but not in muscle (By similarity). May also mediate the development of insulin resistance by regulating activation of transcription factors (PubMed:10868943, PubMed:17478001). In Wnt signaling, regulates the level and transcriptional activity of nuclear CTNNB1/beta-catenin (PubMed:17229088). Facilitates amyloid precursor protein (APP) processing and the generation of APP-derived amyloid plaques found in Alzheimer disease (PubMed:12761548). May be involved in the regulation of replication in pancreatic beta-cells (By similarity). Is necessary for the establishment of neuronal polarity and axon outgrowth (By similarity). Through phosphorylation of the anti-apoptotic protein MCL1, may control cell apoptosis in response to growth factors deprivation (By similarity). Acts as a regulator of autophagy by mediating phosphorylation of KAT5/TIP60 under starvation conditions which activates KAT5/TIP60 acetyltransferase activity and promotes acetylation of key autophagy regulators, such as ULK1 and RUBCNL/Pacer (PubMed:30704899). Negatively regulates extrinsic apoptotic signaling pathway via death domain receptors. Promotes the formation of an anti-apoptotic complex, made of DDX3X, BRIC2 and GSK3B, at death receptors, including TNFRSF10B. The anti-apoptotic function is most effective with weak apoptotic signals and can be overcome by stronger stimulation (By similarity). Phosphorylates mTORC2 complex component RICTOR at ''Thr-1695'' which facilitates FBXW7-mediated ubiquitination and subsequent degradation of RICTOR (PubMed:25897075).', 'GSK3A', 'Homo sapiens', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, Acetylation, Alzheimer disease, ATP-binding, Carbohydrate metabolism, Diabetes mellitus, Glycogen metabolism, Kinase, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Signal transduction inhibitor, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (396, '8SI2', '', 'Transient receptor potential cation channel subfamily M member 7', 'Essential ion channel and serine/threonine-protein kinase. Divalent cation channel permeable to calcium and magnesium. Has a central role in magnesium ion homeostasis and in the regulation of anoxic neuronal cell death. Involved in TNF-induced necroptosis downstream of MLKL by mediating calcium influx. The kinase activity is essential for the channel function. May be involved in a fundamental process that adjusts plasma membrane divalent cation fluxes according to the metabolic state of the cell. Phosphorylates annexin A1 (ANXA1).', 'Trpm7', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Calcium, Calcium channel, Calcium transport, Coiled coil, Ion channel, Ion transport, Kinase, Membrane, Metal-binding, Necrosis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix, Transport, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (397, '2QHM', '', 'Serine/threonine-protein kinase Chk1', 'Serine/threonine-protein kinase which is required for checkpoint-mediated cell cycle arrest and activation of DNA repair in response to the presence of DNA damage or unreplicated DNA (PubMed:11535615, PubMed:12446774, PubMed:12399544, PubMed:14559997, PubMed:14988723, PubMed:15311285, PubMed:15665856, PubMed:15650047, PubMed:32357935). May also negatively regulate cell cycle progression during unperturbed cell cycles (PubMed:11535615, PubMed:12446774, PubMed:12399544, PubMed:14559997, PubMed:14988723, PubMed:15311285, PubMed:15665856, PubMed:15650047). This regulation is achieved by a number of mechanisms that together help to preserve the integrity of the genome (PubMed:11535615, PubMed:12446774, PubMed:12399544, PubMed:14559997, PubMed:14988723, PubMed:15311285, PubMed:15665856, PubMed:15650047). Recognizes the substrate consensus sequence [R-X-X-S/T] (PubMed:11535615, PubMed:12446774, PubMed:12399544, PubMed:14559997, PubMed:14988723, PubMed:15311285, PubMed:15665856, PubMed:15650047). Binds to and phosphorylates CDC25A, CDC25B and CDC25C (PubMed:9278511, PubMed:12676583, PubMed:14681206, PubMed:12676925, PubMed:12759351, PubMed:19734889, PubMed:14559997). Phosphorylation of CDC25A at ''Ser-178'' and ''Thr-507'' and phosphorylation of CDC25C at ''Ser-216'' creates binding sites for 14-3-3 proteins which inhibit CDC25A and CDC25C (PubMed:9278511). Phosphorylation of CDC25A at ''Ser-76'', ''Ser-124'', ''Ser-178'', ''Ser-279'' and ''Ser-293'' promotes proteolysis of CDC25A (PubMed:9278511, PubMed:12676583, PubMed:14681206, PubMed:12676925, PubMed:12759351, PubMed:19734889). Phosphorylation of CDC25A at ''Ser-76'' primes the protein for subsequent phosphorylation at ''Ser-79'', ''Ser-82'' and ''Ser-88'' by NEK11, which is required for polyubiquitination and degradation of CDCD25A (PubMed:9278511, PubMed:19734889, PubMed:20090422). Inhibition of CDC25 leads to increased inhibitory tyrosine phosphorylation of CDK-cyclin complexes and blocks cell cycle progression (PubMed:9278511). Also phosphorylates NEK6 (PubMed:18728393). Binds to and phosphorylates RAD51 at ''Thr-309'', which promotes the release of RAD51 from BRCA2 and enhances the association of RAD51 with chromatin, thereby promoting DNA repair by homologous recombination (PubMed:15665856). Phosphorylates multiple sites within the C-terminus of TP53, which promotes activation of TP53 by acetylation and promotes cell cycle arrest and suppression of cellular proliferation (PubMed:10673501, PubMed:15659650, PubMed:16511572). Also promotes repair of DNA cross-links through phosphorylation of FANCE (PubMed:17296736). Binds to and phosphorylates TLK1 at ''Ser-743'', which prevents the TLK1-dependent phosphorylation of the chromatin assembly factor ASF1A (PubMed:12660173, PubMed:12955071). This may enhance chromatin assembly both in the presence or absence of DNA damage (PubMed:12660173, PubMed:12955071). May also play a role in replication fork maintenance through regulation of PCNA (PubMed:18451105). May regulate the transcription of genes that regulate cell-cycle progression through the phosphorylation of histones (By similarity). Phosphorylates histone H3.1 (to form H3T11ph), which leads to epigenetic inhibition of a subset of genes (By similarity). May also phosphorylate RB1 to promote its interaction with the E2F family of transcription factors and subsequent cell cycle arrest (PubMed:17380128). Phosphorylates SPRTN, promoting SPRTN recruitment to chromatin (PubMed:31316063). Reduces replication stress and activates the G2/M checkpoint, by phosphorylating and inactivating PABIR1/FAM122A and promoting the serine/threonine-protein phosphatase 2A-mediated dephosphorylation and stabilization of WEE1 levels and activity (PubMed:33108758).', 'CHEK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Chromosome, Cytoplasm, Cytoskeleton, DNA damage, DNA repair, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (398, '4LIQ', '', 'Macrophage colony-stimulating factor 1 receptor', 'Tyrosine-protein kinase that acts as a cell-surface receptor for CSF1 and IL34 and plays an essential role in the regulation of survival, proliferation and differentiation of hematopoietic precursor cells, especially mononuclear phagocytes, such as macrophages and monocytes. Promotes the release of pro-inflammatory chemokines in response to IL34 and CSF1, and thereby plays an important role in innate immunity and in inflammatory processes. Plays an important role in the regulation of osteoclast proliferation and differentiation, the regulation of bone resorption, and is required for normal bone and tooth development. Required for normal male and female fertility, and for normal development of milk ducts and acinar structures in the mammary gland during pregnancy. Promotes reorganization of the actin cytoskeleton, regulates formation of membrane ruffles, cell adhesion and cell migration, and promotes cancer cell invasion. Activates several signaling pathways in response to ligand binding, including the ERK1/2 and the JNK pathway (PubMed:20504948, PubMed:30982609). Phosphorylates PIK3R1, PLCG2, GRB2, SLA2 and CBL. Activation of PLCG2 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate, that then lead to the activation of protein kinase C family members, especially PRKCD. Phosphorylation of PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase, leads to activation of the AKT1 signaling pathway. Activated CSF1R also mediates activation of the MAP kinases MAPK1/ERK2 and/or MAPK3/ERK1, and of the SRC family kinases SRC, FYN and YES1. Activated CSF1R transmits signals both via proteins that directly interact with phosphorylated tyrosine residues in its intracellular domain, or via adapter proteins, such as GRB2. Promotes activation of STAT family members STAT3, STAT5A and/or STAT5B. Promotes tyrosine phosphorylation of SHC1 and INPP5D/SHIP-1. Receptor signaling is down-regulated by protein phosphatases, such as INPP5D/SHIP-1, that dephosphorylate the receptor and its downstream effectors, and by rapid internalization of the activated receptor. In the central nervous system, may play a role in the development of microglia macrophages (PubMed:30982608).', 'CSF1R', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Immunity, Immunoglobulin domain, Inflammatory response, Innate immunity, Kinase, Membrane, Neurodegeneration, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (418, '4AF3', '', 'Aurora kinase B', 'Serine/threonine-protein kinase component of the chromosomal passenger complex (CPC), a complex that acts as a key regulator of mitosis (PubMed:11516652, PubMed:12925766, PubMed:14610074, PubMed:14722118, PubMed:29449677). The CPC complex has essential functions at the centromere in ensuring correct chromosome alignment and segregation and is required for chromatin-induced microtubule stabilization and spindle assembly (PubMed:11516652, PubMed:12925766, PubMed:14610074, PubMed:14722118, PubMed:26829474). Involved in the bipolar attachment of spindle microtubules to kinetochores and is a key regulator for the onset of cytokinesis during mitosis (PubMed:15249581). Required for central/midzone spindle assembly and cleavage furrow formation (PubMed:12458200, PubMed:12686604). Key component of the cytokinesis checkpoint, a process required to delay abscission to prevent both premature resolution of intercellular chromosome bridges and accumulation of DNA damage: phosphorylates CHMP4C, leading to retain abscission-competent VPS4 (VPS4A and/or VPS4B) at the midbody ring until abscission checkpoint signaling is terminated at late cytokinesis (PubMed:22422861, PubMed:24814515). AURKB phosphorylates the CPC complex subunits BIRC5/survivin, CDCA8/borealin and INCENP (PubMed:11516652, PubMed:12925766, PubMed:14610074). Phosphorylation of INCENP leads to increased AURKB activity (PubMed:11516652, PubMed:12925766, PubMed:14610074). Other known AURKB substrates involved in centromeric functions and mitosis are CENPA, DES/desmin, GPAF, KIF2C, NSUN2, RACGAP1, SEPTIN1, VIM/vimentin, HASPIN, and histone H3 (PubMed:11784863, PubMed:12689593, PubMed:14602875, PubMed:11856369, PubMed:16103226, PubMed:21658950, PubMed:11756469). A positive feedback loop involving HASPIN and AURKB contributes to localization of CPC to centromeres (PubMed:21658950). Phosphorylation of VIM controls vimentin filament segregation in cytokinetic process, whereas histone H3 is phosphorylated at ''Ser-10'' and ''Ser-28'' during mitosis (H3S10ph and H3S28ph, respectively) (PubMed:11784863, PubMed:11856369). AURKB is also required for kinetochore localization of BUB1 and SGO1 (PubMed:15020684, PubMed:17617734). Phosphorylation of p53/TP53 negatively regulates its transcriptional activity (PubMed:20959462). Key regulator of active promoters in resting B- and T-lymphocytes: acts by mediating phosphorylation of H3S28ph at active promoters in resting B-cells, inhibiting RNF2/RING1B-mediated ubiquitination of histone H2A and enhancing binding and activity of the USP16 deubiquitinase at transcribed genes (By similarity). Acts as an inhibitor of CGAS during mitosis: catalyzes phosphorylation of the N-terminus of CGAS during the G2-M transition, blocking CGAS liquid phase separation and activation, and thereby preventing CGAS-induced autoimmunity (PubMed:33542149). Phosphorylates KRT5 during anaphase and telophase (By similarity).', 'AURKB', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cell division, Centromere, Chromosome, Cytoplasm, Cytoskeleton, Kinase, Kinetochore, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (419, '5H64', '', 'Serine/threonine-protein kinase mTOR', 'Serine/threonine protein kinase which is a central regulator of cellular metabolism, growth and survival in response to hormones, growth factors, nutrients, energy and stress signals (PubMed:12087098, PubMed:12150925, PubMed:12150926, PubMed:12231510, PubMed:12718876, PubMed:14651849, PubMed:15268862, PubMed:15467718, PubMed:15545625, PubMed:15718470, PubMed:18497260, PubMed:18762023, PubMed:18925875, PubMed:20516213, PubMed:20537536, PubMed:21659604, PubMed:23429703, PubMed:23429704, PubMed:25799227, PubMed:26018084, PubMed:29150432, PubMed:31112131, PubMed:31601708, PubMed:32561715, PubMed:34519269, PubMed:29236692, PubMed:37751742). MTOR directly or indirectly regulates the phosphorylation of at least 800 proteins (PubMed:15268862, PubMed:15467718, PubMed:17517883, PubMed:18925875, PubMed:18372248, PubMed:18497260, PubMed:20516213, PubMed:21576368, PubMed:21659604, PubMed:23429704, PubMed:29236692, PubMed:37751742). Functions as part of 2 structurally and functionally distinct signaling complexes mTORC1 and mTORC2 (mTOR complex 1 and 2) (PubMed:15268862, PubMed:15467718, PubMed:18925875, PubMed:18497260, PubMed:20516213, PubMed:21576368, PubMed:21659604, PubMed:23429704). In response to nutrients, growth factors or amino acids, mTORC1 is recruited to the lysosome membrane and promotes protein, lipid and nucleotide synthesis by phosphorylating key regulators of mRNA translation and ribosome synthesis (PubMed:12087098, PubMed:12150925, PubMed:12150926, PubMed:12231510, PubMed:12718876, PubMed:14651849, PubMed:15268862, PubMed:15467718, PubMed:15545625, PubMed:15718470, PubMed:18497260, PubMed:18762023, PubMed:18925875, PubMed:20516213, PubMed:20537536, PubMed:21659604, PubMed:23429703, PubMed:23429704, PubMed:25799227, PubMed:26018084, PubMed:29150432, PubMed:31112131, PubMed:34519269, PubMed:29236692). This includes phosphorylation of EIF4EBP1 and release of its inhibition toward the elongation initiation factor 4E (eiF4E) (PubMed:24403073, PubMed:29236692). Moreover, phosphorylates and activates RPS6KB1 and RPS6KB2 that promote protein synthesis by modulating the activity of their downstream targets including ribosomal protein S6, eukaryotic translation initiation factor EIF4B, and the inhibitor of translation initiation PDCD4 (PubMed:12150925, PubMed:12087098, PubMed:18925875, PubMed:29150432, PubMed:29236692). Stimulates the pyrimidine biosynthesis pathway, both by acute regulation through RPS6KB1-mediated phosphorylation of the biosynthetic enzyme CAD, and delayed regulation, through transcriptional enhancement of the pentose phosphate pathway which produces 5-phosphoribosyl-1-pyrophosphate (PRPP), an allosteric activator of CAD at a later step in synthesis, this function is dependent on the mTORC1 complex (PubMed:23429704, PubMed:23429703). Regulates ribosome synthesis by activating RNA polymerase III-dependent transcription through phosphorylation and inhibition of MAF1 an RNA polymerase III-repressor (PubMed:20516213). Activates dormant ribosomes by mediating phosphorylation of SERBP1, leading to SERBP1 inactivation and reactivation of translation (PubMed:36691768). In parallel to protein synthesis, also regulates lipid synthesis through SREBF1/SREBP1 and LPIN1 (By similarity). To maintain energy homeostasis mTORC1 may also regulate mitochondrial biogenesis through regulation of PPARGC1A (By similarity). In the same time, mTORC1 inhibits catabolic pathways: negatively regulates autophagy through phosphorylation of ULK1 (PubMed:32561715). Under nutrient sufficiency, phosphorylates ULK1 at ''Ser-758'', disrupting the interaction with AMPK and preventing activation of ULK1 (PubMed:32561715). Also prevents autophagy through phosphorylation of the autophagy inhibitor DAP (PubMed:20537536). Also prevents autophagy by phosphorylating RUBCNL/Pacer under nutrient-rich conditions (PubMed:30704899). Prevents autophagy by mediating phosphorylation of AMBRA1, thereby inhibiting AMBRA1 ability to mediate ubiquitination of ULK1 and interaction between AMBRA1 and PPP2CA (PubMed:23524951, PubMed:25438055). mTORC1 exerts a feedback control on upstream growth factor signaling that includes phosphorylation and activation of GRB10 a INSR-dependent signaling suppressor (PubMed:21659604). Among other potential targets mTORC1 may phosphorylate CLIP1 and regulate microtubules (PubMed:12231510). The mTORC1 complex is inhibited in response to starvation and amino acid depletion (PubMed:12150925, PubMed:12150926, PubMed:24403073). The non-canonical mTORC1 complex, which acts independently of RHEB, specifically mediates phosphorylation of MiT/TFE factors MITF, TFEB and TFE3 in the presence of nutrients, promoting their cytosolic retention and inactivation (PubMed:22576015, PubMed:22343943, PubMed:22692423, PubMed:24448649, PubMed:32612235, PubMed:36608670, PubMed:36697823). Upon starvation or lysosomal stress, inhibition of mTORC1 induces dephosphorylation and nuclear translocation of TFEB and TFE3, promoting their transcription factor activity (PubMed:22576015, PubMed:22343943, PubMed:22692423, PubMed:24448649, PubMed:32612235, PubMed:36608670). The mTORC1 complex regulates pyroptosis in macrophages by promoting GSDMD oligomerization (PubMed:34289345). MTOR phosphorylates RPTOR which in turn inhibits mTORC1 (By similarity). As part of the mTORC2 complex MTOR may regulate other cellular processes including survival and organization of the cytoskeleton (PubMed:15268862, PubMed:15467718). mTORC2 plays a critical role in the phosphorylation at ''Ser-473'' of AKT1, a pro-survival effector of phosphoinositide 3-kinase, facilitating its activation by PDK1 (PubMed:15718470). mTORC2 may regulate the actin cytoskeleton, through phosphorylation of PRKCA, PXN and activation of the Rho-type guanine nucleotide exchange factors RHOA and RAC1A or RAC1B (PubMed:15268862). mTORC2 also regulates the phosphorylation of SGK1 at ''Ser-422'' (PubMed:18925875). Regulates osteoclastogenesis by adjusting the expression of CEBPB isoforms (By similarity). Plays an important regulatory role in the circadian clock function; regulates period length and rhythm amplitude of the suprachiasmatic nucleus (SCN) and liver clocks (By similarity).', 'MTOR', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Biological rhythms, Cytoplasm, Cytoplasmic vesicle, Disease variant, Endoplasmic reticulum, Epilepsy, Golgi apparatus, Intellectual disability, Kinase, Lysosome, Membrane, Microsome, Mitochondrion, Mitochondrion outer membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, TPR repeat, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (399, '2J7T', '', 'Serine/threonine-protein kinase 10', 'Serine/threonine-protein kinase involved in regulation of lymphocyte migration. Phosphorylates MSN, and possibly PLK1. Involved in regulation of lymphocyte migration by mediating phosphorylation of ERM proteins such as MSN. Acts as a negative regulator of MAP3K1/MEKK1. May also act as a cell cycle regulator by acting as a polo kinase kinase: mediates phosphorylation of PLK1 in vitro; however such data require additional evidences in vivo.', 'STK10', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell cycle, Cell membrane, Coiled coil, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (400, '1I09', '', 'Glycogen synthase kinase-3 beta', 'Constitutively active protein kinase that acts as a negative regulator in the hormonal control of glucose homeostasis, Wnt signaling and regulation of transcription factors and microtubules, by phosphorylating and inactivating glycogen synthase (GYS1 or GYS2), EIF2B, CTNNB1/beta-catenin, APC, AXIN1, DPYSL2/CRMP2, JUN, NFATC1/NFATC, MAPT/TAU and MACF1 (PubMed:1846781, PubMed:9072970, PubMed:14690523, PubMed:20937854, PubMed:12554650, PubMed:11430833, PubMed:16484495). Requires primed phosphorylation of the majority of its substrates (PubMed:11430833, PubMed:16484495). In skeletal muscle, contributes to insulin regulation of glycogen synthesis by phosphorylating and inhibiting GYS1 activity and hence glycogen synthesis (PubMed:8397507). May also mediate the development of insulin resistance by regulating activation of transcription factors (PubMed:8397507). Regulates protein synthesis by controlling the activity of initiation factor 2B (EIF2BE/EIF2B5) in the same manner as glycogen synthase (PubMed:8397507). In Wnt signaling, GSK3B forms a multimeric complex with APC, AXIN1 and CTNNB1/beta-catenin and phosphorylates the N-terminus of CTNNB1 leading to its degradation mediated by ubiquitin/proteasomes (PubMed:12554650). Phosphorylates JUN at sites proximal to its DNA-binding domain, thereby reducing its affinity for DNA (PubMed:1846781). Phosphorylates NFATC1/NFATC on conserved serine residues promoting NFATC1/NFATC nuclear export, shutting off NFATC1/NFATC gene regulation, and thereby opposing the action of calcineurin (PubMed:9072970). Phosphorylates MAPT/TAU on ''Thr-548'', decreasing significantly MAPT/TAU ability to bind and stabilize microtubules (PubMed:14690523). MAPT/TAU is the principal component of neurofibrillary tangles in Alzheimer disease (PubMed:14690523). Plays an important role in ERBB2-dependent stabilization of microtubules at the cell cortex (PubMed:20937854). Phosphorylates MACF1, inhibiting its binding to microtubules which is critical for its role in bulge stem cell migration and skin wound repair (By similarity). Probably regulates NF-kappa-B (NFKB1) at the transcriptional level and is required for the NF-kappa-B-mediated anti-apoptotic response to TNF-alpha (TNF/TNFA) (By similarity). Negatively regulates replication in pancreatic beta-cells, resulting in apoptosis, loss of beta-cells and diabetes (By similarity). Through phosphorylation of the anti-apoptotic protein MCL1, may control cell apoptosis in response to growth factors deprivation (By similarity). Phosphorylates MUC1 in breast cancer cells, decreasing the interaction of MUC1 with CTNNB1/beta-catenin (PubMed:9819408). Is necessary for the establishment of neuronal polarity and axon outgrowth (PubMed:20067585). Phosphorylates MARK2, leading to inhibition of its activity (By similarity). Phosphorylates SIK1 at ''Thr-182'', leading to sustainment of its activity (PubMed:18348280). Phosphorylates ZC3HAV1 which enhances its antiviral activity (PubMed:22514281). Phosphorylates SNAI1, leading to its BTRC-triggered ubiquitination and proteasomal degradation (PubMed:15448698, PubMed:15647282). Phosphorylates SFPQ at ''Thr-687'' upon T-cell activation (PubMed:20932480). Phosphorylates NR1D1 st ''Ser-55'' and ''Ser-59'' and stabilizes it by protecting it from proteasomal degradation. Regulates the circadian clock via phosphorylation of the major clock components including BMAL1, CLOCK and PER2 (PubMed:19946213, PubMed:28903391). Phosphorylates FBXL2 at ''Thr-404'' and primes it for ubiquitination by the SCF(FBXO3) complex and proteasomal degradation (By similarity). Phosphorylates CLOCK AT ''Ser-427'' and targets it for proteasomal degradation (PubMed:19946213). Phosphorylates BMAL1 at ''Ser-17'' and ''Ser-21'' and primes it for ubiquitination and proteasomal degradation (PubMed:28903391). Phosphorylates OGT at ''Ser-3'' or ''Ser-4'' which positively regulates its activity. Phosphorylates MYCN in neuroblastoma cells which may promote its degradation (PubMed:24391509). Regulates the circadian rhythmicity of hippocampal long-term potentiation and BMAL1 and PER2 expression (By similarity). Acts as a regulator of autophagy by mediating phosphorylation of KAT5/TIP60 under starvation conditions, activating KAT5/TIP60 acetyltransferase activity and promoting acetylation of key autophagy regulators, such as ULK1 and RUBCNL/Pacer (PubMed:30704899). Negatively regulates extrinsic apoptotic signaling pathway via death domain receptors. Promotes the formation of an anti-apoptotic complex, made of DDX3X, BRIC2 and GSK3B, at death receptors, including TNFRSF10B. The anti-apoptotic function is most effective with weak apoptotic signals and can be overcome by stronger stimulation (PubMed:18846110). Phosphorylates E2F1, promoting the interaction between E2F1 and USP11, stabilizing E2F1 and promoting its activity (PubMed:17050006, PubMed:28992046). Phosphorylates mTORC2 complex component RICTOR at ''Thr-1695'' which facilitates FBXW7-mediated ubiquitination and subsequent degradation of RICTOR (PubMed:25897075). Phosphorylates FXR1, promoting FXR1 ubiquitination by the SCF(FBXO4) complex and FXR1 degradation by the proteasome (By similarity). Phosphorylates interleukin-22 receptor subunit IL22RA1, preventing its proteasomal degradation (By similarity).', 'GSK3B', 'Homo sapiens', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, ADP-ribosylation, Alternative splicing, Alzheimer disease, ATP-binding, Biological rhythms, Carbohydrate metabolism, Cell membrane, Cytoplasm, Developmental protein, Diabetes mellitus, Differentiation, Glycogen metabolism, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Signal transduction inhibitor, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (401, '4AGU', '', 'Cyclin-dependent kinase-like 1', 'Unknown', 'CDKL1', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (402, '8BEM', '', 'STE20-like serine/threonine-protein kinase', 'Mediates apoptosis and actin stress fiber dissolution.', 'SLK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (403, '2CMW', '', 'Casein kinase I isoform gamma-1', 'Serine/threonine-protein kinase. Casein kinases are operationally defined by their preferential utilization of acidic proteins such as caseins as substrates. It can phosphorylate a large number of proteins. Participates in Wnt signaling. Regulates fast synaptic transmission mediated by glutamate (By similarity). Phosphorylates CLSPN.', 'CSNK1G1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (404, '2X7F', '', 'TRAF2 and NCK-interacting protein kinase', 'Serine/threonine kinase that acts as an essential activator of the Wnt signaling pathway. Recruited to promoters of Wnt target genes and required to activate their expression. May act by phosphorylating TCF4/TCF7L2. Appears to act upstream of the JUN N-terminal pathway. May play a role in the response to environmental stress. Part of a signaling complex composed of NEDD4, RAP2A and TNIK which regulates neuronal dendrite extension and arborization during development. More generally, it may play a role in cytoskeletal rearrangements and regulate cell spreading. Phosphorylates SMAD1 on Thr-322.', 'TNIK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Endosome, Intellectual disability, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (601, '4EC8', '', 'Cyclin-dependent kinase 9', 'Protein kinase involved in the regulation of transcription (PubMed:10574912, PubMed:10757782, PubMed:11145967, PubMed:11575923, PubMed:11809800, PubMed:11884399, PubMed:14701750, PubMed:16109376, PubMed:16109377, PubMed:20930849, PubMed:28426094, PubMed:29335245). Member of the cyclin-dependent kinase pair (CDK9/cyclin-T) complex, also called positive transcription elongation factor b (P-TEFb), which facilitates the transition from abortive to productive elongation by phosphorylating the CTD (C-terminal domain) of the large subunit of RNA polymerase II (RNAP II) POLR2A, SUPT5H and RDBP (PubMed:10574912, PubMed:10757782, PubMed:11145967, PubMed:11575923, PubMed:11809800, PubMed:11884399, PubMed:14701750, PubMed:16109376, PubMed:16109377, PubMed:20930849, PubMed:28426094, PubMed:30134174). This complex is inactive when in the 7SK snRNP complex form (PubMed:10574912, PubMed:10757782, PubMed:11145967, PubMed:11575923, PubMed:11809800, PubMed:11884399, PubMed:14701750, PubMed:16109376, PubMed:16109377, PubMed:20930849, PubMed:28426094). Phosphorylates EP300, MYOD1, RPB1/POLR2A and AR and the negative elongation factors DSIF and NELFE (PubMed:9857195, PubMed:10912001, PubMed:11112772, PubMed:12037670, PubMed:20081228, PubMed:20980437, PubMed:21127351). Regulates cytokine inducible transcription networks by facilitating promoter recognition of target transcription factors (e.g. TNF-inducible RELA/p65 activation and IL-6-inducible STAT3 signaling) (PubMed:17956865, PubMed:18362169). Promotes RNA synthesis in genetic programs for cell growth, differentiation and viral pathogenesis (PubMed:10393184, PubMed:11112772). P-TEFb is also involved in cotranscriptional histone modification, mRNA processing and mRNA export (PubMed:15564463, PubMed:19575011, PubMed:19844166). Modulates a complex network of chromatin modifications including histone H2B monoubiquitination (H2Bub1), H3 lysine 4 trimethylation (H3K4me3) and H3K36me3; integrates phosphorylation during transcription with chromatin modifications to control co-transcriptional histone mRNA processing (PubMed:15564463, PubMed:19575011, PubMed:19844166). The CDK9/cyclin-K complex has also a kinase activity towards CTD of RNAP II and can substitute for CDK9/cyclin-T P-TEFb in vitro (PubMed:21127351). Replication stress response protein; the CDK9/cyclin-K complex is required for genome integrity maintenance, by promoting cell cycle recovery from replication arrest and limiting single-stranded DNA amount in response to replication stress, thus reducing the breakdown of stalled replication forks and avoiding DNA damage (PubMed:20493174). In addition, probable function in DNA repair of isoform 2 via interaction with KU70/XRCC6 (PubMed:20493174). Promotes cardiac myocyte enlargement (PubMed:20081228). RPB1/POLR2A phosphorylation on ''Ser-2'' in CTD activates transcription (PubMed:21127351). AR phosphorylation modulates AR transcription factor promoter selectivity and cell growth. DSIF and NELF phosphorylation promotes transcription by inhibiting their negative effect (PubMed:9857195, PubMed:10912001, PubMed:11112772). The phosphorylation of MYOD1 enhances its transcriptional activity and thus promotes muscle differentiation (PubMed:12037670). Catalyzes phosphorylation of KAT5, promoting KAT5 recruitment to chromatin and histone acetyltransferase activity (PubMed:29335245).', 'CDK9', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, DNA damage, DNA repair, Host-virus interaction, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (405, '5WNI', '', 'Receptor-interacting serine/threonine-protein kinase 4', 'Involved in stratified epithelial development (By similarity). It is a direct transcriptional target of TP63. Plays a role in NF-kappa-B activation.', 'Ripk4', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, ANK repeat, ATP-binding, Cytoplasm, Isopeptide bond, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (420, '5J5T', '', 'Mitogen-activated protein kinase kinase kinase kinase 3', 'May play a role in the response to environmental stress. Appears to act upstream of the JUN N-terminal pathway.', 'MAP4K3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (421, '4APC', '', 'Serine/threonine-protein kinase Nek1', 'Phosphorylates serines and threonines, but also appears to possess tyrosine kinase activity (PubMed:20230784). Involved in DNA damage checkpoint control and for proper DNA damage repair (PubMed:20230784). In response to injury that includes DNA damage, NEK1 phosphorylates VDAC1 to limit mitochondrial cell death (PubMed:20230784). May be implicated in the control of meiosis (By similarity). Involved in cilium assembly (PubMed:21211617).', 'NEK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Amyotrophic lateral sclerosis, ATP-binding, Cell cycle, Cell division, Ciliopathy, Cilium biogenesis/degradation, Cytoplasm, Cytoskeleton, Kinase, Magnesium, Metal-binding, Mitosis, Neurodegeneration, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (422, '7Z37', '', 'Heat shock protein HSP 90-beta', 'Molecular chaperone that promotes the maturation, structural maintenance and proper regulation of specific target proteins involved for instance in cell cycle control and signal transduction. Undergoes a functional cycle linked to its ATPase activity. This cycle probably induces conformational changes in the client proteins, thereby causing their activation. Interacts dynamically with various co-chaperones that modulate its substrate recognition, ATPase cycle and chaperone function (PubMed:16478993, PubMed:19696785). Engages with a range of client protein classes via its interaction with various co-chaperone proteins or complexes, that act as adapters, simultaneously able to interact with the specific client and the central chaperone itself. Recruitment of ATP and co-chaperone followed by client protein forms a functional chaperone. After the completion of the chaperoning process, properly folded client protein and co-chaperone leave HSP90 in an ADP-bound partially open conformation and finally, ADP is released from HSP90 which acquires an open conformation for the next cycle (PubMed:27295069, PubMed:26991466). Apart from its chaperone activity, it also plays a role in the regulation of the transcription machinery. HSP90 and its co-chaperones modulate transcription at least at three different levels. They first alter the steady-state levels of certain transcription factors in response to various physiological cues. Second, they modulate the activity of certain epigenetic modifiers, such as histone deacetylases or DNA methyl transferases, and thereby respond to the change in the environment. Third, they participate in the eviction of histones from the promoter region of certain genes and thereby turn on gene expression (PubMed:25973397). Antagonizes STUB1-mediated inhibition of TGF-beta signaling via inhibition of STUB1-mediated SMAD3 ubiquitination and degradation (PubMed:24613385). Promotes cell differentiation by chaperoning BIRC2 and thereby protecting from auto-ubiquitination and degradation by the proteasomal machinery (PubMed:18239673). Main chaperone involved in the phosphorylation/activation of the STAT1 by chaperoning both JAK2 and PRKCE under heat shock and in turn, activates its own transcription (PubMed:20353823). Involved in the translocation into ERGIC (endoplasmic reticulum-Golgi intermediate compartment) of leaderless cargos (lacking the secretion signal sequence) such as the interleukin 1/IL-1; the translocation process is mediated by the cargo receptor TMED10 (PubMed:32272059).', 'HSP90AB1', 'Homo sapiens', '{[]}', '3D-structure, Acetylation, ATP-binding, Cell membrane, Chaperone, Cytoplasm, Direct protein sequencing, Glycoprotein, Membrane, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, S-nitrosylation, Secreted, Stress response, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (423, '7S7K', '', 'Ephrin type-B receptor 2', 'Receptor tyrosine kinase which binds promiscuously transmembrane ephrin-B family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Functions in axon guidance during development. Involved in the guidance of commissural axons, that form a major interhemispheric connection between the 2 temporal lobes of the cerebral cortex. Also involved in guidance of contralateral inner ear efferent growth cones at the midline and of retinal ganglion cell axons to the optic disk. In addition to axon guidance, also regulates dendritic spines development and maturation and stimulates the formation of excitatory synapses. Upon activation by EFNB1, abolishes the ARHGEF15-mediated negative regulation on excitatory synapse formation. Controls other aspects of development including angiogenesis, palate development and in inner ear development through regulation of endolymph production. Forward and reverse signaling through the EFNB2/EPHB2 complex regulate movement and adhesion of cells that tubularize the urethra and septate the cloaca. May function as a tumor suppressor. May be involved in the regulation of platelet activation and blood coagulation (By similarity).', 'Ephb2', 'Mus musculus', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cell projection, Developmental protein, Direct protein sequencing, Disulfide bond, Glycoprotein, Isopeptide bond, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (406, '5T89', '', 'Vascular endothelial growth factor A, long form', 'Participates in the induction of key genes involved in the response to hypoxia and in the induction of angiogenesis such as HIF1A (PubMed:35455969). Involved in protecting cells from hypoxia-mediated cell death (By similarity).', 'VEGFA', 'Homo sapiens', '{[]}', '3D-structure, Alternative initiation, Alternative promoter usage, Alternative splicing, Angiogenesis, Cytoplasm, Developmental protein, Differentiation, Direct protein sequencing, Disulfide bond, Endoplasmic reticulum, Extracellular matrix, Glycoprotein, Golgi apparatus, Growth factor, Heparin-binding, Mitogen, Nucleus, Reference proteome, Secreted');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (407, '2IFG', '', 'High affinity nerve growth factor receptor', 'Receptor tyrosine kinase involved in the development and the maturation of the central and peripheral nervous systems through regulation of proliferation, differentiation and survival of sympathetic and nervous neurons. High affinity receptor for NGF which is its primary ligand (PubMed:1850821, PubMed:1849459, PubMed:1281417, PubMed:8325889, PubMed:15488758, PubMed:22649032, PubMed:17196528, PubMed:27445338). Can also bind and be activated by NTF3/neurotrophin-3. However, NTF3 only supports axonal extension through NTRK1 but has no effect on neuron survival (By similarity). Upon dimeric NGF ligand-binding, undergoes homodimerization, autophosphorylation and activation (PubMed:1281417). Recruits, phosphorylates and/or activates several downstream effectors including SHC1, FRS2, SH2B1, SH2B2 and PLCG1 that regulate distinct overlapping signaling cascades driving cell survival and differentiation. Through SHC1 and FRS2 activates a GRB2-Ras-MAPK cascade that regulates cell differentiation and survival. Through PLCG1 controls NF-Kappa-B activation and the transcription of genes involved in cell survival. Through SHC1 and SH2B1 controls a Ras-PI3 kinase-AKT1 signaling cascade that is also regulating survival. In absence of ligand and activation, may promote cell death, making the survival of neurons dependent on trophic factors.', 'NTRK1', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Chromosomal rearrangement, Developmental protein, Differentiation, Disease variant, Disulfide bond, Endosome, Glycoprotein, Immunoglobulin domain, Kinase, Leucine-rich repeat, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (408, '2P0C', '', 'Tyrosine-protein kinase Mer', 'Receptor tyrosine kinase that transduces signals from the extracellular matrix into the cytoplasm by binding to several ligands including LGALS3, TUB, TULP1 or GAS6. Regulates many physiological processes including cell survival, migration, differentiation, and phagocytosis of apoptotic cells (efferocytosis). Ligand binding at the cell surface induces autophosphorylation of MERTK on its intracellular domain that provides docking sites for downstream signaling molecules. Following activation by ligand, interacts with GRB2 or PLCG2 and induces phosphorylation of MAPK1, MAPK2, FAK/PTK2 or RAC1. MERTK signaling plays a role in various processes such as macrophage clearance of apoptotic cells, platelet aggregation, cytoskeleton reorganization and engulfment (PubMed:32640697). Functions in the retinal pigment epithelium (RPE) as a regulator of rod outer segments fragments phagocytosis. Also plays an important role in inhibition of Toll-like receptors (TLRs)-mediated innate immune response by activating STAT1, which selectively induces production of suppressors of cytokine signaling SOCS1 and SOCS3.', 'MERTK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Retinitis pigmentosa, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (409, '2C30', '', 'Serine/threonine-protein kinase PAK 6', 'Serine/threonine protein kinase that plays a role in the regulation of gene transcription. The kinase activity is induced by various effectors including AR or MAP2K6/MAPKK6. Phosphorylates the DNA-binding domain of androgen receptor/AR and thereby inhibits AR-mediated transcription. Inhibits also ESR1-mediated transcription. May play a role in cytoskeleton regulation by interacting with IQGAP1. May protect cells from apoptosis through phosphorylation of BAD.', 'PAK6', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (410, '2RD0', '', 'Phosphatidylinositol 4,5-bisphosphate 3-kinase catalytic subunit alpha isoform', 'Phosphoinositide-3-kinase (PI3K) phosphorylates phosphatidylinositol (PI) and its phosphorylated derivatives at position 3 of the inositol ring to produce 3-phosphoinositides (PubMed:15135396, PubMed:23936502, PubMed:28676499). Uses ATP and PtdIns(4,5)P2 (phosphatidylinositol 4,5-bisphosphate) to generate phosphatidylinositol 3,4,5-trisphosphate (PIP3) (PubMed:15135396, PubMed:28676499). PIP3 plays a key role by recruiting PH domain-containing proteins to the membrane, including AKT1 and PDPK1, activating signaling cascades involved in cell growth, survival, proliferation, motility and morphology. Participates in cellular signaling in response to various growth factors. Involved in the activation of AKT1 upon stimulation by receptor tyrosine kinases ligands such as EGF, insulin, IGF1, VEGFA and PDGF. Involved in signaling via insulin-receptor substrate (IRS) proteins. Essential in endothelial cell migration during vascular development through VEGFA signaling, possibly by regulating RhoA activity. Required for lymphatic vasculature development, possibly by binding to RAS and by activation by EGF and FGF2, but not by PDGF. Regulates invadopodia formation through the PDPK1-AKT1 pathway. Participates in cardiomyogenesis in embryonic stem cells through a AKT1 pathway. Participates in vasculogenesis in embryonic stem cells through PDK1 and protein kinase C pathway. In addition to its lipid kinase activity, it displays a serine-protein kinase activity that results in the autophosphorylation of the p85alpha regulatory subunit as well as phosphorylation of other proteins such as 4EBP1, H-Ras, the IL-3 beta c receptor and possibly others (PubMed:23936502, PubMed:28676499). Plays a role in the positive regulation of phagocytosis and pinocytosis (By similarity).', 'PIK3CA', 'Homo sapiens', '{[''2.7.1.153'',''2.7.11.1'',''2.7.1.137'']}', '3D-structure, Angiogenesis, ATP-binding, Disease variant, Kinase, Lipid metabolism, Nucleotide-binding, Phagocytosis, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (424, '4C57', '', 'Cyclin-G-associated kinase', 'Associates with cyclin G and CDK5. Seems to act as an auxilin homolog that is involved in the uncoating of clathrin-coated vesicles by Hsc70 in non-neuronal cells. Expression oscillates slightly during the cell cycle, peaking at G1 (PubMed:10625686). May play a role in clathrin-mediated endocytosis and intracellular trafficking, and in the dynamics of clathrin assembly/disassembly (PubMed:18489706).', 'GAK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cell junction, Cytoplasm, Cytoplasmic vesicle, Golgi apparatus, Kinase, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (137, '5H64', '', 'Serine/threonine-protein kinase mTOR', 'Serine/threonine protein kinase which is a central regulator of cellular metabolism, growth and survival in response to hormones, growth factors, nutrients, energy and stress signals (PubMed:12087098, PubMed:12150925, PubMed:12150926, PubMed:12231510, PubMed:12718876, PubMed:14651849, PubMed:15268862, PubMed:15467718, PubMed:15545625, PubMed:15718470, PubMed:18497260, PubMed:18762023, PubMed:18925875, PubMed:20516213, PubMed:20537536, PubMed:21659604, PubMed:23429703, PubMed:23429704, PubMed:25799227, PubMed:26018084, PubMed:29150432, PubMed:31112131, PubMed:31601708, PubMed:32561715, PubMed:34519269, PubMed:29236692, PubMed:37751742). MTOR directly or indirectly regulates the phosphorylation of at least 800 proteins (PubMed:15268862, PubMed:15467718, PubMed:17517883, PubMed:18925875, PubMed:18372248, PubMed:18497260, PubMed:20516213, PubMed:21576368, PubMed:21659604, PubMed:23429704, PubMed:29236692, PubMed:37751742). Functions as part of 2 structurally and functionally distinct signaling complexes mTORC1 and mTORC2 (mTOR complex 1 and 2) (PubMed:15268862, PubMed:15467718, PubMed:18925875, PubMed:18497260, PubMed:20516213, PubMed:21576368, PubMed:21659604, PubMed:23429704). In response to nutrients, growth factors or amino acids, mTORC1 is recruited to the lysosome membrane and promotes protein, lipid and nucleotide synthesis by phosphorylating key regulators of mRNA translation and ribosome synthesis (PubMed:12087098, PubMed:12150925, PubMed:12150926, PubMed:12231510, PubMed:12718876, PubMed:14651849, PubMed:15268862, PubMed:15467718, PubMed:15545625, PubMed:15718470, PubMed:18497260, PubMed:18762023, PubMed:18925875, PubMed:20516213, PubMed:20537536, PubMed:21659604, PubMed:23429703, PubMed:23429704, PubMed:25799227, PubMed:26018084, PubMed:29150432, PubMed:31112131, PubMed:34519269, PubMed:29236692). This includes phosphorylation of EIF4EBP1 and release of its inhibition toward the elongation initiation factor 4E (eiF4E) (PubMed:24403073, PubMed:29236692). Moreover, phosphorylates and activates RPS6KB1 and RPS6KB2 that promote protein synthesis by modulating the activity of their downstream targets including ribosomal protein S6, eukaryotic translation initiation factor EIF4B, and the inhibitor of translation initiation PDCD4 (PubMed:12150925, PubMed:12087098, PubMed:18925875, PubMed:29150432, PubMed:29236692). Stimulates the pyrimidine biosynthesis pathway, both by acute regulation through RPS6KB1-mediated phosphorylation of the biosynthetic enzyme CAD, and delayed regulation, through transcriptional enhancement of the pentose phosphate pathway which produces 5-phosphoribosyl-1-pyrophosphate (PRPP), an allosteric activator of CAD at a later step in synthesis, this function is dependent on the mTORC1 complex (PubMed:23429704, PubMed:23429703). Regulates ribosome synthesis by activating RNA polymerase III-dependent transcription through phosphorylation and inhibition of MAF1 an RNA polymerase III-repressor (PubMed:20516213). Activates dormant ribosomes by mediating phosphorylation of SERBP1, leading to SERBP1 inactivation and reactivation of translation (PubMed:36691768). In parallel to protein synthesis, also regulates lipid synthesis through SREBF1/SREBP1 and LPIN1 (By similarity). To maintain energy homeostasis mTORC1 may also regulate mitochondrial biogenesis through regulation of PPARGC1A (By similarity). In the same time, mTORC1 inhibits catabolic pathways: negatively regulates autophagy through phosphorylation of ULK1 (PubMed:32561715). Under nutrient sufficiency, phosphorylates ULK1 at ''Ser-758'', disrupting the interaction with AMPK and preventing activation of ULK1 (PubMed:32561715). Also prevents autophagy through phosphorylation of the autophagy inhibitor DAP (PubMed:20537536). Also prevents autophagy by phosphorylating RUBCNL/Pacer under nutrient-rich conditions (PubMed:30704899). Prevents autophagy by mediating phosphorylation of AMBRA1, thereby inhibiting AMBRA1 ability to mediate ubiquitination of ULK1 and interaction between AMBRA1 and PPP2CA (PubMed:23524951, PubMed:25438055). mTORC1 exerts a feedback control on upstream growth factor signaling that includes phosphorylation and activation of GRB10 a INSR-dependent signaling suppressor (PubMed:21659604). Among other potential targets mTORC1 may phosphorylate CLIP1 and regulate microtubules (PubMed:12231510). The mTORC1 complex is inhibited in response to starvation and amino acid depletion (PubMed:12150925, PubMed:12150926, PubMed:24403073). The non-canonical mTORC1 complex, which acts independently of RHEB, specifically mediates phosphorylation of MiT/TFE factors MITF, TFEB and TFE3 in the presence of nutrients, promoting their cytosolic retention and inactivation (PubMed:22576015, PubMed:22343943, PubMed:22692423, PubMed:24448649, PubMed:32612235, PubMed:36608670, PubMed:36697823). Upon starvation or lysosomal stress, inhibition of mTORC1 induces dephosphorylation and nuclear translocation of TFEB and TFE3, promoting their transcription factor activity (PubMed:22576015, PubMed:22343943, PubMed:22692423, PubMed:24448649, PubMed:32612235, PubMed:36608670). The mTORC1 complex regulates pyroptosis in macrophages by promoting GSDMD oligomerization (PubMed:34289345). MTOR phosphorylates RPTOR which in turn inhibits mTORC1 (By similarity). As part of the mTORC2 complex MTOR may regulate other cellular processes including survival and organization of the cytoskeleton (PubMed:15268862, PubMed:15467718). mTORC2 plays a critical role in the phosphorylation at ''Ser-473'' of AKT1, a pro-survival effector of phosphoinositide 3-kinase, facilitating its activation by PDK1 (PubMed:15718470). mTORC2 may regulate the actin cytoskeleton, through phosphorylation of PRKCA, PXN and activation of the Rho-type guanine nucleotide exchange factors RHOA and RAC1A or RAC1B (PubMed:15268862). mTORC2 also regulates the phosphorylation of SGK1 at ''Ser-422'' (PubMed:18925875). Regulates osteoclastogenesis by adjusting the expression of CEBPB isoforms (By similarity). Plays an important regulatory role in the circadian clock function; regulates period length and rhythm amplitude of the suprachiasmatic nucleus (SCN) and liver clocks (By similarity).', 'MTOR', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Biological rhythms, Cytoplasm, Cytoplasmic vesicle, Disease variant, Endoplasmic reticulum, Epilepsy, Golgi apparatus, Intellectual disability, Kinase, Lysosome, Membrane, Microsome, Mitochondrion, Mitochondrion outer membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, TPR repeat, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (411, '3G51', '', 'Ribosomal protein S6 kinase alpha-3', 'Serine/threonine-protein kinase that acts downstream of ERK (MAPK1/ERK2 and MAPK3/ERK1) signaling and mediates mitogenic and stress-induced activation of the transcription factors CREB1, ETV1/ER81 and NR4A1/NUR77, regulates translation through RPS6 and EIF4B phosphorylation, and mediates cellular proliferation, survival, and differentiation by modulating mTOR signaling and repressing pro-apoptotic function of BAD and DAPK1 (PubMed:10856237, PubMed:15109498). In fibroblast, is required for EGF-stimulated phosphorylation of CREB1 and histone H3 at ''Ser-10'', which results in the subsequent transcriptional activation of several immediate-early genes (By similarity). In response to mitogenic stimulation (EGF and PMA), phosphorylates and activates NR4A1/NUR77 and ETV1/ER81 transcription factors and the cofactor CREBBP (By similarity). Upon insulin-derived signal, acts indirectly on the transcription regulation of several genes by phosphorylating GSK3B at ''Ser-9'' and inhibiting its activity (By similarity). Phosphorylates RPS6 in response to serum or EGF via an mTOR-independent mechanism and promotes translation initiation by facilitating assembly of the preinitiation complex (By similarity). In response to insulin, phosphorylates EIF4B, enhancing EIF4B affinity for the EIF3 complex and stimulating cap-dependent translation (By similarity). Is involved in the mTOR nutrient-sensing pathway by directly phosphorylating TSC2 at ''Ser-1798'', which potently inhibits TSC2 ability to suppress mTOR signaling, and mediates phosphorylation of RPTOR, which regulates mTORC1 activity and may promote rapamycin-sensitive signaling independently of the PI3K/AKT pathway (By similarity). Mediates cell survival by phosphorylating the pro-apoptotic proteins BAD and DAPK1 and suppressing their pro-apoptotic function (By similarity). Promotes the survival of hepatic stellate cells by phosphorylating CEBPB in response to the hepatotoxin carbon tetrachloride (CCl4) (By similarity). Is involved in cell cycle regulation by phosphorylating the CDK inhibitor CDKN1B, which promotes CDKN1B association with 14-3-3 proteins and prevents its translocation to the nucleus and inhibition of G1 progression (PubMed:14504289). In LPS-stimulated dendritic cells, is involved in TLR4-induced macropinocytosis, and in myeloma cells, acts as effector of FGFR3-mediated transformation signaling, after direct phosphorylation at Tyr-529 by FGFR3 (PubMed:17785202, PubMed:17906627). Negatively regulates EGF-induced MAPK1/3 phosphorylation via phosphorylation of SOS1 (PubMed:22827337). Phosphorylates SOS1 at ''Ser-1134'' and ''Ser-1161'' that create YWHAB and YWHAE binding sites and which contribute to the negative regulation of MAPK1/3 phosphorylation (PubMed:22827337). Phosphorylates EPHA2 at ''Ser-897'', the RPS6KA-EPHA2 signaling pathway controls cell migration (By similarity). Acts as a regulator of osteoblast differentiation by mediating phosphorylation of ATF4, thereby promoting ATF4 transactivation activity (PubMed:15109498).', 'Rps6ka3', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell cycle, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Stress response, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (412, '6CMJ', '', 'Calcium/calmodulin-dependent protein kinase kinase 2', 'Calcium/calmodulin-dependent protein kinase belonging to a proposed calcium-triggered signaling cascade involved in a number of cellular processes. Isoform 1, isoform 2 and isoform 3 phosphorylate CAMK1 and CAMK4. Isoform 3 phosphorylates CAMK1D. Isoform 4, isoform 5 and isoform 6 lacking part of the calmodulin-binding domain are inactive. Efficiently phosphorylates 5''-AMP-activated protein kinase (AMPK) trimer, including that consisting of PRKAA1, PRKAB1 and PRKAG1. This phosphorylation is stimulated in response to Ca(2+) signals (By similarity). Seems to be involved in hippocampal activation of CREB1 (By similarity). May play a role in neurite growth. Isoform 3 may promote neurite elongation, while isoform 1 may promoter neurite branching.', 'CAMKK2', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Calmodulin-binding, Cell projection, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (413, '4YHJ', '', 'G protein-coupled receptor kinase 4', 'Specifically phosphorylates the activated forms of G protein-coupled receptors. GRK4-alpha can phosphorylate rhodopsin and its activity is inhibited by calmodulin; the other three isoforms do not phosphorylate rhodopsin and do not interact with calmodulin. GRK4-alpha and GRK4-gamma phosphorylate DRD3. Phosphorylates ADRB2.', 'GRK4', 'Homo sapiens', '{[''2.7.11.16'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Lipoprotein, Nucleotide-binding, Palmitate, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (414, '6CCF', '', 'Calcium/calmodulin-dependent protein kinase kinase 1', 'Calcium/calmodulin-dependent protein kinase that belongs to a proposed calcium-triggered signaling cascade involved in a number of cellular processes. Phosphorylates CAMK1, CAMK1D, CAMK1G and CAMK4. Involved in regulating cell apoptosis. Promotes cell survival by phosphorylating AKT1/PKB that inhibits pro-apoptotic BAD/Bcl2-antagonist of cell death.', 'CAMKK1', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Alternative splicing, ATP-binding, Calmodulin-binding, Cytoplasm, Kinase, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (124, '5T89', '', 'Vascular endothelial growth factor A, long form', 'Participates in the induction of key genes involved in the response to hypoxia and in the induction of angiogenesis such as HIF1A (PubMed:35455969). Involved in protecting cells from hypoxia-mediated cell death (By similarity).', 'VEGFA', 'Homo sapiens', '{[]}', '3D-structure, Alternative initiation, Alternative promoter usage, Alternative splicing, Angiogenesis, Cytoplasm, Developmental protein, Differentiation, Direct protein sequencing, Disulfide bond, Endoplasmic reticulum, Extracellular matrix, Glycoprotein, Golgi apparatus, Growth factor, Heparin-binding, Mitogen, Nucleus, Reference proteome, Secreted');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (125, '2IFG', '', 'High affinity nerve growth factor receptor', 'Receptor tyrosine kinase involved in the development and the maturation of the central and peripheral nervous systems through regulation of proliferation, differentiation and survival of sympathetic and nervous neurons. High affinity receptor for NGF which is its primary ligand (PubMed:1850821, PubMed:1849459, PubMed:1281417, PubMed:8325889, PubMed:15488758, PubMed:22649032, PubMed:17196528, PubMed:27445338). Can also bind and be activated by NTF3/neurotrophin-3. However, NTF3 only supports axonal extension through NTRK1 but has no effect on neuron survival (By similarity). Upon dimeric NGF ligand-binding, undergoes homodimerization, autophosphorylation and activation (PubMed:1281417). Recruits, phosphorylates and/or activates several downstream effectors including SHC1, FRS2, SH2B1, SH2B2 and PLCG1 that regulate distinct overlapping signaling cascades driving cell survival and differentiation. Through SHC1 and FRS2 activates a GRB2-Ras-MAPK cascade that regulates cell differentiation and survival. Through PLCG1 controls NF-Kappa-B activation and the transcription of genes involved in cell survival. Through SHC1 and SH2B1 controls a Ras-PI3 kinase-AKT1 signaling cascade that is also regulating survival. In absence of ligand and activation, may promote cell death, making the survival of neurons dependent on trophic factors.', 'NTRK1', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Chromosomal rearrangement, Developmental protein, Differentiation, Disease variant, Disulfide bond, Endosome, Glycoprotein, Immunoglobulin domain, Kinase, Leucine-rich repeat, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (126, '2P0C', '', 'Tyrosine-protein kinase Mer', 'Receptor tyrosine kinase that transduces signals from the extracellular matrix into the cytoplasm by binding to several ligands including LGALS3, TUB, TULP1 or GAS6. Regulates many physiological processes including cell survival, migration, differentiation, and phagocytosis of apoptotic cells (efferocytosis). Ligand binding at the cell surface induces autophosphorylation of MERTK on its intracellular domain that provides docking sites for downstream signaling molecules. Following activation by ligand, interacts with GRB2 or PLCG2 and induces phosphorylation of MAPK1, MAPK2, FAK/PTK2 or RAC1. MERTK signaling plays a role in various processes such as macrophage clearance of apoptotic cells, platelet aggregation, cytoskeleton reorganization and engulfment (PubMed:32640697). Functions in the retinal pigment epithelium (RPE) as a regulator of rod outer segments fragments phagocytosis. Also plays an important role in inhibition of Toll-like receptors (TLRs)-mediated innate immune response by activating STAT1, which selectively induces production of suppressors of cytokine signaling SOCS1 and SOCS3.', 'MERTK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Retinitis pigmentosa, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (127, '2C30', '', 'Serine/threonine-protein kinase PAK 6', 'Serine/threonine protein kinase that plays a role in the regulation of gene transcription. The kinase activity is induced by various effectors including AR or MAP2K6/MAPKK6. Phosphorylates the DNA-binding domain of androgen receptor/AR and thereby inhibits AR-mediated transcription. Inhibits also ESR1-mediated transcription. May play a role in cytoskeleton regulation by interacting with IQGAP1. May protect cells from apoptosis through phosphorylation of BAD.', 'PAK6', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (128, '2RD0', '', 'Phosphatidylinositol 4,5-bisphosphate 3-kinase catalytic subunit alpha isoform', 'Phosphoinositide-3-kinase (PI3K) phosphorylates phosphatidylinositol (PI) and its phosphorylated derivatives at position 3 of the inositol ring to produce 3-phosphoinositides (PubMed:15135396, PubMed:23936502, PubMed:28676499). Uses ATP and PtdIns(4,5)P2 (phosphatidylinositol 4,5-bisphosphate) to generate phosphatidylinositol 3,4,5-trisphosphate (PIP3) (PubMed:15135396, PubMed:28676499). PIP3 plays a key role by recruiting PH domain-containing proteins to the membrane, including AKT1 and PDPK1, activating signaling cascades involved in cell growth, survival, proliferation, motility and morphology. Participates in cellular signaling in response to various growth factors. Involved in the activation of AKT1 upon stimulation by receptor tyrosine kinases ligands such as EGF, insulin, IGF1, VEGFA and PDGF. Involved in signaling via insulin-receptor substrate (IRS) proteins. Essential in endothelial cell migration during vascular development through VEGFA signaling, possibly by regulating RhoA activity. Required for lymphatic vasculature development, possibly by binding to RAS and by activation by EGF and FGF2, but not by PDGF. Regulates invadopodia formation through the PDPK1-AKT1 pathway. Participates in cardiomyogenesis in embryonic stem cells through a AKT1 pathway. Participates in vasculogenesis in embryonic stem cells through PDK1 and protein kinase C pathway. In addition to its lipid kinase activity, it displays a serine-protein kinase activity that results in the autophosphorylation of the p85alpha regulatory subunit as well as phosphorylation of other proteins such as 4EBP1, H-Ras, the IL-3 beta c receptor and possibly others (PubMed:23936502, PubMed:28676499). Plays a role in the positive regulation of phagocytosis and pinocytosis (By similarity).', 'PIK3CA', 'Homo sapiens', '{[''2.7.1.153'',''2.7.11.1'',''2.7.1.137'']}', '3D-structure, Angiogenesis, ATP-binding, Disease variant, Kinase, Lipid metabolism, Nucleotide-binding, Phagocytosis, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (129, '3G51', '', 'Ribosomal protein S6 kinase alpha-3', 'Serine/threonine-protein kinase that acts downstream of ERK (MAPK1/ERK2 and MAPK3/ERK1) signaling and mediates mitogenic and stress-induced activation of the transcription factors CREB1, ETV1/ER81 and NR4A1/NUR77, regulates translation through RPS6 and EIF4B phosphorylation, and mediates cellular proliferation, survival, and differentiation by modulating mTOR signaling and repressing pro-apoptotic function of BAD and DAPK1 (PubMed:10856237, PubMed:15109498). In fibroblast, is required for EGF-stimulated phosphorylation of CREB1 and histone H3 at ''Ser-10'', which results in the subsequent transcriptional activation of several immediate-early genes (By similarity). In response to mitogenic stimulation (EGF and PMA), phosphorylates and activates NR4A1/NUR77 and ETV1/ER81 transcription factors and the cofactor CREBBP (By similarity). Upon insulin-derived signal, acts indirectly on the transcription regulation of several genes by phosphorylating GSK3B at ''Ser-9'' and inhibiting its activity (By similarity). Phosphorylates RPS6 in response to serum or EGF via an mTOR-independent mechanism and promotes translation initiation by facilitating assembly of the preinitiation complex (By similarity). In response to insulin, phosphorylates EIF4B, enhancing EIF4B affinity for the EIF3 complex and stimulating cap-dependent translation (By similarity). Is involved in the mTOR nutrient-sensing pathway by directly phosphorylating TSC2 at ''Ser-1798'', which potently inhibits TSC2 ability to suppress mTOR signaling, and mediates phosphorylation of RPTOR, which regulates mTORC1 activity and may promote rapamycin-sensitive signaling independently of the PI3K/AKT pathway (By similarity). Mediates cell survival by phosphorylating the pro-apoptotic proteins BAD and DAPK1 and suppressing their pro-apoptotic function (By similarity). Promotes the survival of hepatic stellate cells by phosphorylating CEBPB in response to the hepatotoxin carbon tetrachloride (CCl4) (By similarity). Is involved in cell cycle regulation by phosphorylating the CDK inhibitor CDKN1B, which promotes CDKN1B association with 14-3-3 proteins and prevents its translocation to the nucleus and inhibition of G1 progression (PubMed:14504289). In LPS-stimulated dendritic cells, is involved in TLR4-induced macropinocytosis, and in myeloma cells, acts as effector of FGFR3-mediated transformation signaling, after direct phosphorylation at Tyr-529 by FGFR3 (PubMed:17785202, PubMed:17906627). Negatively regulates EGF-induced MAPK1/3 phosphorylation via phosphorylation of SOS1 (PubMed:22827337). Phosphorylates SOS1 at ''Ser-1134'' and ''Ser-1161'' that create YWHAB and YWHAE binding sites and which contribute to the negative regulation of MAPK1/3 phosphorylation (PubMed:22827337). Phosphorylates EPHA2 at ''Ser-897'', the RPS6KA-EPHA2 signaling pathway controls cell migration (By similarity). Acts as a regulator of osteoblast differentiation by mediating phosphorylation of ATF4, thereby promoting ATF4 transactivation activity (PubMed:15109498).', 'Rps6ka3', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell cycle, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Stress response, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (130, '6CMJ', '', 'Calcium/calmodulin-dependent protein kinase kinase 2', 'Calcium/calmodulin-dependent protein kinase belonging to a proposed calcium-triggered signaling cascade involved in a number of cellular processes. Isoform 1, isoform 2 and isoform 3 phosphorylate CAMK1 and CAMK4. Isoform 3 phosphorylates CAMK1D. Isoform 4, isoform 5 and isoform 6 lacking part of the calmodulin-binding domain are inactive. Efficiently phosphorylates 5''-AMP-activated protein kinase (AMPK) trimer, including that consisting of PRKAA1, PRKAB1 and PRKAG1. This phosphorylation is stimulated in response to Ca(2+) signals (By similarity). Seems to be involved in hippocampal activation of CREB1 (By similarity). May play a role in neurite growth. Isoform 3 may promote neurite elongation, while isoform 1 may promoter neurite branching.', 'CAMKK2', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Calmodulin-binding, Cell projection, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (645, '1H4L', 'MQKYEKLEKIGEGTYGTVFKAKNRETHEIVALKRVRLDDDDEGVPSSALREICLLKELKHKNIVRLHDVLHSDKKLTLVFEFCDQDLKKYFDSCNGDLDPEIVKSFLFQLLKGLGFCHSRNVLHRDLKPQNLLINRNGELKLADFGLARAFGIPVRCYSAEVVTLWYRPPDVLFGAKLYSTSIDMWSAGCIFAELANAGRPLFPGNDVDDQLKRIFRLLGTPTEEQWPSMTKLPDYKPYPMYPATTSLVNVVPKLNATGRDLLQNLLKCNPVQRISAEEALQHPYFSDFCPP', 'Cyclin-dependent kinase 5', 'Proline-directed serine/threonine-protein kinase essential for neuronal cell cycle arrest and differentiation and may be involved in apoptotic cell death in neuronal diseases by triggering abortive cell cycle re-entry. Interacts with D1 and D3-type G1 cyclins. Phosphorylates SRC, NOS3, VIM/vimentin, p35/CDK5R1, MEF2A, SIPA1L1, SH3GLB1, PXN, PAK1, MCAM/MUC18, SEPT5, SYN1, DNM1, AMPH, SYNJ1, CDK16, RAC1, RHOA, CDC42, TONEBP/NFAT5, MAPT/TAU, MAP1B, histone H1, p53/TP53, HDAC1, APEX1, PTK2/FAK1, huntingtin/HTT, ATM, MAP2, NEFH and NEFM. Regulates several neuronal development and physiological processes including neuronal survival, migration and differentiation, axonal and neurite growth, synaptogenesis, oligodendrocyte differentiation, synaptic plasticity and neurotransmission, by phosphorylating key proteins. Negatively regulates the CACNA1B/CAV2.2 -mediated Ca(2+) release probability at hippocampal neuronal soma and synaptic terminals (By similarity). Activated by interaction with CDK5R1 (p35) and CDK5R2 (p39), especially in postmitotic neurons, and promotes CDK5R1 (p35) expression in an autostimulation loop. Phosphorylates many downstream substrates such as Rho and Ras family small GTPases (e.g. PAK1, RAC1, RHOA, CDC42) or microtubule-binding proteins (e.g. MAPT/TAU, MAP2, MAP1B), and modulates actin dynamics to regulate neurite growth and/or spine morphogenesis. Phosphorylates also exocytosis associated proteins such as MCAM/MUC18, SEPT5, SYN1, and CDK16/PCTAIRE1 as well as endocytosis associated proteins such as DNM1, AMPH and SYNJ1 at synaptic terminals. In the mature central nervous system (CNS), regulates neurotransmitter movements by phosphorylating substrates associated with neurotransmitter release and synapse plasticity; synaptic vesicle exocytosis, vesicles fusion with the presynaptic membrane, and endocytosis. Promotes cell survival by activating anti-apoptotic proteins BCL2 and STAT3, and negatively regulating of JNK3/MAPK10 activity. Phosphorylation of p53/TP53 in response to genotoxic and oxidative stresses enhances its stabilization by preventing ubiquitin ligase-mediated proteasomal degradation, and induces transactivation of p53/TP53 target genes, thus regulating apoptosis. Phosphorylation of p35/CDK5R1 enhances its stabilization by preventing calpain-mediated proteolysis producing p25/CDK5R1 and avoiding ubiquitin ligase-mediated proteasomal degradation. During aberrant cell-cycle activity and DNA damage, p25/CDK5 activity elicits cell-cycle activity and double-strand DNA breaks that precedes neuronal death by deregulating HDAC1. DNA damage triggered phosphorylation of huntingtin/HTT in nuclei of neurons protects neurons against polyglutamine expansion as well as DNA damage mediated toxicity. Phosphorylation of PXN reduces its interaction with PTK2/FAK1 in matrix-cell focal adhesions (MCFA) during oligodendrocytes (OLs) differentiation. Negative regulator of Wnt/beta-catenin signaling pathway. Activator of the GAIT (IFN-gamma-activated inhibitor of translation) pathway, which suppresses expression of a post-transcriptional regulon of proinflammatory genes in myeloid cells; phosphorylates the linker domain of glutamyl-prolyl tRNA synthetase (EPRS) in a IFN-gamma-dependent manner, the initial event in assembly of the GAIT complex. Phosphorylation of SH3GLB1 is required for autophagy induction in starved neurons. Phosphorylation of TONEBP/NFAT5 in response to osmotic stress mediates its rapid nuclear localization. MEF2 is inactivated by phosphorylation in nucleus in response to neurotoxin, thus leading to neuronal apoptosis. APEX1 AP-endodeoxyribonuclease is repressed by phosphorylation, resulting in accumulation of DNA damage and contributing to neuronal death. NOS3 phosphorylation down regulates NOS3-derived nitrite (NO) levels. SRC phosphorylation mediates its ubiquitin-dependent degradation and thus leads to cytoskeletal reorganization. May regulate endothelial cell migration and angiogenesis via the modulation of lamellipodia formation. Involved in dendritic spine morphogenesis by mediating the EFNA1-EPHA4 signaling. The complex p35/CDK5 participates in the regulation of the circadian clock by modulating the function of CLOCK protein: phosphorylates CLOCK at ''Thr-451'' and ''Thr-461'' and regulates the transcriptional activity of the CLOCK-BMAL1 heterodimer in association with altered stability and subcellular distribution.', 'CDK5', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Biological rhythms, Cell cycle, Cell division, Cell membrane, Cell projection, Cytoplasm, Kinase, Lissencephaly, Membrane, Neurodegeneration, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Synapse, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (131, '4YHJ', '', 'G protein-coupled receptor kinase 4', 'Specifically phosphorylates the activated forms of G protein-coupled receptors. GRK4-alpha can phosphorylate rhodopsin and its activity is inhibited by calmodulin; the other three isoforms do not phosphorylate rhodopsin and do not interact with calmodulin. GRK4-alpha and GRK4-gamma phosphorylate DRD3. Phosphorylates ADRB2.', 'GRK4', 'Homo sapiens', '{[''2.7.11.16'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Lipoprotein, Nucleotide-binding, Palmitate, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (132, '6CCF', '', 'Calcium/calmodulin-dependent protein kinase kinase 1', 'Calcium/calmodulin-dependent protein kinase that belongs to a proposed calcium-triggered signaling cascade involved in a number of cellular processes. Phosphorylates CAMK1, CAMK1D, CAMK1G and CAMK4. Involved in regulating cell apoptosis. Promotes cell survival by phosphorylating AKT1/PKB that inhibits pro-apoptotic BAD/Bcl2-antagonist of cell death.', 'CAMKK1', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Alternative splicing, ATP-binding, Calmodulin-binding, Cytoplasm, Kinase, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (133, '2H8H', '', 'Proto-oncogene tyrosine-protein kinase Src', 'Non-receptor protein tyrosine kinase which is activated following engagement of many different classes of cellular receptors including immune response receptors, integrins and other adhesion receptors, receptor protein tyrosine kinases, G protein-coupled receptors as well as cytokine receptors. Participates in signaling pathways that control a diverse spectrum of biological activities including gene transcription, immune response, cell adhesion, cell cycle progression, apoptosis, migration, and transformation. Due to functional redundancy between members of the SRC kinase family, identification of the specific role of each SRC kinase is very difficult. SRC appears to be one of the primary kinases activated following engagement of receptors and plays a role in the activation of other protein tyrosine kinase (PTK) families. Receptor clustering or dimerization leads to recruitment of SRC to the receptor complexes where it phosphorylates the tyrosine residues within the receptor cytoplasmic domains. Plays an important role in the regulation of cytoskeletal organization through phosphorylation of specific substrates such as AFAP1. Phosphorylation of AFAP1 allows the SRC SH2 domain to bind AFAP1 and to localize to actin filaments. Cytoskeletal reorganization is also controlled through the phosphorylation of cortactin (CTTN) (Probable). When cells adhere via focal adhesions to the extracellular matrix, signals are transmitted by integrins into the cell resulting in tyrosine phosphorylation of a number of focal adhesion proteins, including PTK2/FAK1 and paxillin (PXN) (PubMed:21411625). In addition to phosphorylating focal adhesion proteins, SRC is also active at the sites of cell-cell contact adherens junctions and phosphorylates substrates such as beta-catenin (CTNNB1), delta-catenin (CTNND1), and plakoglobin (JUP). Another type of cell-cell junction, the gap junction, is also a target for SRC, which phosphorylates connexin-43 (GJA1). SRC is implicated in regulation of pre-mRNA-processing and phosphorylates RNA-binding proteins such as KHDRBS1 (Probable). Also plays a role in PDGF-mediated tyrosine phosphorylation of both STAT1 and STAT3, leading to increased DNA binding activity of these transcription factors (By similarity). Involved in the RAS pathway through phosphorylation of RASA1 and RASGRF1 (PubMed:11389730). Plays a role in EGF-mediated calcium-activated chloride channel activation (PubMed:18586953). Required for epidermal growth factor receptor (EGFR) internalization through phosphorylation of clathrin heavy chain (CLTC and CLTCL1) at ''Tyr-1477''. Involved in beta-arrestin (ARRB1 and ARRB2) desensitization through phosphorylation and activation of GRK2, leading to beta-arrestin phosphorylation and internalization. Has a critical role in the stimulation of the CDK20/MAPK3 mitogen-activated protein kinase cascade by epidermal growth factor (Probable). Might be involved not only in mediating the transduction of mitogenic signals at the level of the plasma membrane but also in controlling progression through the cell cycle via interaction with regulatory proteins in the nucleus (PubMed:7853507). Plays an important role in osteoclastic bone resorption in conjunction with PTK2B/PYK2. Both the formation of a SRC-PTK2B/PYK2 complex and SRC kinase activity are necessary for this function. Recruited to activated integrins by PTK2B/PYK2, thereby phosphorylating CBL, which in turn induces the activation and recruitment of phosphatidylinositol 3-kinase to the cell membrane in a signaling pathway that is critical for osteoclast function (PubMed:8755529, PubMed:14585963). Promotes energy production in osteoclasts by activating mitochondrial cytochrome C oxidase (PubMed:12615910). Phosphorylates DDR2 on tyrosine residues, thereby promoting its subsequent autophosphorylation (PubMed:16186108). Phosphorylates RUNX3 and COX2 on tyrosine residues, TNK2 on ''Tyr-284'' and CBL on ''Tyr-731'' (PubMed:20100835, PubMed:21309750). Enhances RIGI-elicited antiviral signaling (PubMed:19419966). Phosphorylates PDPK1 at ''Tyr-9'', ''Tyr-373'' and ''Tyr-376'' (PubMed:14585963). Phosphorylates BCAR1 at ''Tyr-128'' (PubMed:22710723). Phosphorylates CBLC at multiple tyrosine residues, phosphorylation at ''Tyr-341'' activates CBLC E3 activity (PubMed:20525694). Phosphorylates synaptic vesicle protein synaptophysin (SYP) (By similarity). Involved in anchorage-independent cell growth (PubMed:19307596). Required for podosome formation (By similarity). Mediates IL6 signaling by activating YAP1-NOTCH pathway to induce inflammation-induced epithelial regeneration (PubMed:25731159). Phosphorylates OTUB1, promoting deubiquitination of RPTOR (PubMed:35927303). Phosphorylates caspase CASP8 at ''Tyr-380'' which negatively regulates CASP8 processing and activation, down-regulating CASP8 proapoptotic function (PubMed:16619028).', 'SRC', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell cycle, Cell junction, Cell membrane, Cytoplasm, Cytoskeleton, Disease variant, Host-virus interaction, Immunity, Kinase, Lipoprotein, Membrane, Mitochondrion, Mitochondrion inner membrane, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (134, '8OMV', '', 'Inhibitor of nuclear factor kappa-B kinase subunit beta', 'Serine kinase that plays an essential role in the NF-kappa-B signaling pathway which is activated by multiple stimuli such as inflammatory cytokines, bacterial or viral products, DNA damages or other cellular stresses (PubMed:20434986, PubMed:20797629, PubMed:21138416, PubMed:9346484, PubMed:30337470). Acts as a part of the canonical IKK complex in the conventional pathway of NF-kappa-B activation (PubMed:9346484). Phosphorylates inhibitors of NF-kappa-B on 2 critical serine residues (PubMed:9346484, PubMed:20434986, PubMed:20797629, PubMed:21138416). These modifications allow polyubiquitination of the inhibitors and subsequent degradation by the proteasome (PubMed:9346484, PubMed:20434986, PubMed:20797629, PubMed:21138416). In turn, free NF-kappa-B is translocated into the nucleus and activates the transcription of hundreds of genes involved in immune response, growth control, or protection against apoptosis (PubMed:9346484, PubMed:20434986, PubMed:20797629, PubMed:21138416). In addition to the NF-kappa-B inhibitors, phosphorylates several other components of the signaling pathway including NEMO/IKBKG, NF-kappa-B subunits RELA and NFKB1, as well as IKK-related kinases TBK1 and IKBKE (PubMed:11297557, PubMed:14673179, PubMed:20410276, PubMed:21138416). IKK-related kinase phosphorylations may prevent the overproduction of inflammatory mediators since they exert a negative regulation on canonical IKKs (PubMed:11297557, PubMed:20410276, PubMed:21138416). Phosphorylates FOXO3, mediating the TNF-dependent inactivation of this pro-apoptotic transcription factor (PubMed:15084260). Also phosphorylates other substrates including NAA10, NCOA3, BCL10 and IRS1 (PubMed:19716809, PubMed:17213322). Phosphorylates RIPK1 at ''Ser-25'' which represses its kinase activity and consequently prevents TNF-mediated RIPK1-dependent cell death (By similarity). Phosphorylates the C-terminus of IRF5, stimulating IRF5 homodimerization and translocation into the nucleus (PubMed:25326418).', 'IKBKB', 'Homo sapiens', '{[''2.7.11.10'',''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Direct protein sequencing, Disease variant, Host-virus interaction, Hydroxylation, Isopeptide bond, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, S-nitrosylation, SCID, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (135, '7T6F', '', 'Tyrosine-protein kinase JAK1', 'Tyrosine kinase of the non-receptor type, involved in the IFN-alpha/beta/gamma signal pathway. Kinase partner for the interleukin (IL)-2 receptor as well as interleukin (IL)-10 receptor. Kinase partner for the type I interferon receptor IFNAR2. In response to interferon-binding to IFNAR1-IFNAR2 heterodimer, phosphorylates and activates its binding partner IFNAR2, creating docking sites for STAT proteins. Directly phosphorylates STAT proteins but also activates STAT signaling through the transactivation of other JAK kinases associated with signaling receptors.', 'Jak1', 'Mus musculus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, ATP-binding, Direct protein sequencing, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SH2 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (136, '4AF3', '', 'Aurora kinase B', 'Serine/threonine-protein kinase component of the chromosomal passenger complex (CPC), a complex that acts as a key regulator of mitosis (PubMed:11516652, PubMed:12925766, PubMed:14610074, PubMed:14722118, PubMed:29449677). The CPC complex has essential functions at the centromere in ensuring correct chromosome alignment and segregation and is required for chromatin-induced microtubule stabilization and spindle assembly (PubMed:11516652, PubMed:12925766, PubMed:14610074, PubMed:14722118, PubMed:26829474). Involved in the bipolar attachment of spindle microtubules to kinetochores and is a key regulator for the onset of cytokinesis during mitosis (PubMed:15249581). Required for central/midzone spindle assembly and cleavage furrow formation (PubMed:12458200, PubMed:12686604). Key component of the cytokinesis checkpoint, a process required to delay abscission to prevent both premature resolution of intercellular chromosome bridges and accumulation of DNA damage: phosphorylates CHMP4C, leading to retain abscission-competent VPS4 (VPS4A and/or VPS4B) at the midbody ring until abscission checkpoint signaling is terminated at late cytokinesis (PubMed:22422861, PubMed:24814515). AURKB phosphorylates the CPC complex subunits BIRC5/survivin, CDCA8/borealin and INCENP (PubMed:11516652, PubMed:12925766, PubMed:14610074). Phosphorylation of INCENP leads to increased AURKB activity (PubMed:11516652, PubMed:12925766, PubMed:14610074). Other known AURKB substrates involved in centromeric functions and mitosis are CENPA, DES/desmin, GPAF, KIF2C, NSUN2, RACGAP1, SEPTIN1, VIM/vimentin, HASPIN, and histone H3 (PubMed:11784863, PubMed:12689593, PubMed:14602875, PubMed:11856369, PubMed:16103226, PubMed:21658950, PubMed:11756469). A positive feedback loop involving HASPIN and AURKB contributes to localization of CPC to centromeres (PubMed:21658950). Phosphorylation of VIM controls vimentin filament segregation in cytokinetic process, whereas histone H3 is phosphorylated at ''Ser-10'' and ''Ser-28'' during mitosis (H3S10ph and H3S28ph, respectively) (PubMed:11784863, PubMed:11856369). AURKB is also required for kinetochore localization of BUB1 and SGO1 (PubMed:15020684, PubMed:17617734). Phosphorylation of p53/TP53 negatively regulates its transcriptional activity (PubMed:20959462). Key regulator of active promoters in resting B- and T-lymphocytes: acts by mediating phosphorylation of H3S28ph at active promoters in resting B-cells, inhibiting RNF2/RING1B-mediated ubiquitination of histone H2A and enhancing binding and activity of the USP16 deubiquitinase at transcribed genes (By similarity). Acts as an inhibitor of CGAS during mitosis: catalyzes phosphorylation of the N-terminus of CGAS during the G2-M transition, blocking CGAS liquid phase separation and activation, and thereby preventing CGAS-induced autoimmunity (PubMed:33542149). Phosphorylates KRT5 during anaphase and telophase (By similarity).', 'AURKB', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cell division, Centromere, Chromosome, Cytoplasm, Cytoskeleton, Kinase, Kinetochore, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (138, '5J5T', '', 'Mitogen-activated protein kinase kinase kinase kinase 3', 'May play a role in the response to environmental stress. Appears to act upstream of the JUN N-terminal pathway.', 'MAP4K3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (139, '4APC', '', 'Serine/threonine-protein kinase Nek1', 'Phosphorylates serines and threonines, but also appears to possess tyrosine kinase activity (PubMed:20230784). Involved in DNA damage checkpoint control and for proper DNA damage repair (PubMed:20230784). In response to injury that includes DNA damage, NEK1 phosphorylates VDAC1 to limit mitochondrial cell death (PubMed:20230784). May be implicated in the control of meiosis (By similarity). Involved in cilium assembly (PubMed:21211617).', 'NEK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Amyotrophic lateral sclerosis, ATP-binding, Cell cycle, Cell division, Ciliopathy, Cilium biogenesis/degradation, Cytoplasm, Cytoskeleton, Kinase, Magnesium, Metal-binding, Mitosis, Neurodegeneration, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (140, '7Z37', '', 'Heat shock protein HSP 90-beta', 'Molecular chaperone that promotes the maturation, structural maintenance and proper regulation of specific target proteins involved for instance in cell cycle control and signal transduction. Undergoes a functional cycle linked to its ATPase activity. This cycle probably induces conformational changes in the client proteins, thereby causing their activation. Interacts dynamically with various co-chaperones that modulate its substrate recognition, ATPase cycle and chaperone function (PubMed:16478993, PubMed:19696785). Engages with a range of client protein classes via its interaction with various co-chaperone proteins or complexes, that act as adapters, simultaneously able to interact with the specific client and the central chaperone itself. Recruitment of ATP and co-chaperone followed by client protein forms a functional chaperone. After the completion of the chaperoning process, properly folded client protein and co-chaperone leave HSP90 in an ADP-bound partially open conformation and finally, ADP is released from HSP90 which acquires an open conformation for the next cycle (PubMed:27295069, PubMed:26991466). Apart from its chaperone activity, it also plays a role in the regulation of the transcription machinery. HSP90 and its co-chaperones modulate transcription at least at three different levels. They first alter the steady-state levels of certain transcription factors in response to various physiological cues. Second, they modulate the activity of certain epigenetic modifiers, such as histone deacetylases or DNA methyl transferases, and thereby respond to the change in the environment. Third, they participate in the eviction of histones from the promoter region of certain genes and thereby turn on gene expression (PubMed:25973397). Antagonizes STUB1-mediated inhibition of TGF-beta signaling via inhibition of STUB1-mediated SMAD3 ubiquitination and degradation (PubMed:24613385). Promotes cell differentiation by chaperoning BIRC2 and thereby protecting from auto-ubiquitination and degradation by the proteasomal machinery (PubMed:18239673). Main chaperone involved in the phosphorylation/activation of the STAT1 by chaperoning both JAK2 and PRKCE under heat shock and in turn, activates its own transcription (PubMed:20353823). Involved in the translocation into ERGIC (endoplasmic reticulum-Golgi intermediate compartment) of leaderless cargos (lacking the secretion signal sequence) such as the interleukin 1/IL-1; the translocation process is mediated by the cargo receptor TMED10 (PubMed:32272059).', 'HSP90AB1', 'Homo sapiens', '{[]}', '3D-structure, Acetylation, ATP-binding, Cell membrane, Chaperone, Cytoplasm, Direct protein sequencing, Glycoprotein, Membrane, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, S-nitrosylation, Secreted, Stress response, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (141, '7S7K', '', 'Ephrin type-B receptor 2', 'Receptor tyrosine kinase which binds promiscuously transmembrane ephrin-B family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Functions in axon guidance during development. Involved in the guidance of commissural axons, that form a major interhemispheric connection between the 2 temporal lobes of the cerebral cortex. Also involved in guidance of contralateral inner ear efferent growth cones at the midline and of retinal ganglion cell axons to the optic disk. In addition to axon guidance, also regulates dendritic spines development and maturation and stimulates the formation of excitatory synapses. Upon activation by EFNB1, abolishes the ARHGEF15-mediated negative regulation on excitatory synapse formation. Controls other aspects of development including angiogenesis, palate development and in inner ear development through regulation of endolymph production. Forward and reverse signaling through the EFNB2/EPHB2 complex regulate movement and adhesion of cells that tubularize the urethra and septate the cloaca. May function as a tumor suppressor. May be involved in the regulation of platelet activation and blood coagulation (By similarity).', 'Ephb2', 'Mus musculus', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cell projection, Developmental protein, Direct protein sequencing, Disulfide bond, Glycoprotein, Isopeptide bond, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (142, '4C57', '', 'Cyclin-G-associated kinase', 'Associates with cyclin G and CDK5. Seems to act as an auxilin homolog that is involved in the uncoating of clathrin-coated vesicles by Hsc70 in non-neuronal cells. Expression oscillates slightly during the cell cycle, peaking at G1 (PubMed:10625686). May play a role in clathrin-mediated endocytosis and intracellular trafficking, and in the dynamics of clathrin assembly/disassembly (PubMed:18489706).', 'GAK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cell junction, Cytoplasm, Cytoplasmic vesicle, Golgi apparatus, Kinase, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (143, '1TVO', '', 'Mitogen-activated protein kinase 1', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. MAPK1/ERK2 and MAPK3/ERK1 are the 2 MAPKs which play an important role in the MAPK/ERK cascade. They participate also in a signaling cascade initiated by activated KIT and KITLG/SCF. Depending on the cellular context, the MAPK/ERK cascade mediates diverse biological functions such as cell growth, adhesion, survival and differentiation through the regulation of transcription, translation, cytoskeletal rearrangements. The MAPK/ERK cascade also plays a role in initiation and regulation of meiosis, mitosis, and postmitotic functions in differentiated cells by phosphorylating a number of transcription factors. About 160 substrates have already been discovered for ERKs. Many of these substrates are localized in the nucleus, and seem to participate in the regulation of transcription upon stimulation. However, other substrates are found in the cytosol as well as in other cellular organelles, and those are responsible for processes such as translation, mitosis and apoptosis. Moreover, the MAPK/ERK cascade is also involved in the regulation of the endosomal dynamics, including lysosome processing and endosome cycling through the perinuclear recycling compartment (PNRC); as well as in the fragmentation of the Golgi apparatus during mitosis. The substrates include transcription factors (such as ATF2, BCL6, ELK1, ERF, FOS, HSF4 or SPZ1), cytoskeletal elements (such as CANX, CTTN, GJA1, MAP2, MAPT, PXN, SORBS3 or STMN1), regulators of apoptosis (such as BAD, BTG2, CASP9, DAPK1, IER3, MCL1 or PPARG), regulators of translation (such as EIF4EBP1 and FXR1) and a variety of other signaling-related molecules (like ARHGEF2, DCC, FRS2 or GRB10). Protein kinases (such as RAF1, RPS6KA1/RSK1, RPS6KA3/RSK2, RPS6KA2/RSK3, RPS6KA6/RSK4, SYK, MKNK1/MNK1, MKNK2/MNK2, RPS6KA5/MSK1, RPS6KA4/MSK2, MAPKAPK3 or MAPKAPK5) and phosphatases (such as DUSP1, DUSP4, DUSP6 or DUSP16) are other substrates which enable the propagation the MAPK/ERK signal to additional cytosolic and nuclear targets, thereby extending the specificity of the cascade. Mediates phosphorylation of TPR in response to EGF stimulation. May play a role in the spindle assembly checkpoint. Phosphorylates PML and promotes its interaction with PIN1, leading to PML degradation. Phosphorylates CDK2AP2 (By similarity).', 'MAPK1', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell junction, Cytoplasm, Cytoskeleton, Direct protein sequencing, Disease variant, DNA-binding, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repressor, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (144, '8S9P', '', 'Agrin', 'Heparan sulfate basal lamina glycoprotein that plays a central role in the formation and the maintenance of the neuromuscular junction (NMJ) and directs key events in postsynaptic differentiation. Component of the AGRN-LRP4 receptor complex that induces the phosphorylation and activation of MUSK. The activation of MUSK in myotubes induces the formation of NMJ by regulating different processes including the transcription of specific genes and the clustering of AChR in the postsynaptic membrane. Calcium ions are required for maximal AChR clustering. AGRN function in neurons is highly regulated by alternative splicing, glycan binding and proteolytic processing. Modulates calcium ion homeostasis in neurons, specifically by inducing an increase in cytoplasmic calcium ions. Functions differentially in the central nervous system (CNS) by inhibiting the alpha(3)-subtype of Na+/K+-ATPase and evoking depolarization at CNS synapses. This secreted isoform forms a bridge, after release from motor neurons, to basal lamina through binding laminin via the NtA domain.', 'AGRN', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Calcium, Cell membrane, Congenital myasthenic syndrome, Developmental protein, Differentiation, Disease variant, Disulfide bond, EGF-like domain, Extracellular matrix, Glycoprotein, Heparan sulfate, Laminin EGF-like domain, Membrane, Metal-binding, Phosphoprotein, Proteoglycan, Reference proteome, Repeat, Secreted, Signal, Synapse, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (145, '2QLU', '', 'Activin receptor type-2B', 'Transmembrane serine/threonine kinase activin type-2 receptor forming an activin receptor complex with activin type-1 serine/threonine kinase receptors (ACVR1, ACVR1B or ACVR1c). Transduces the activin signal from the cell surface to the cytoplasm and is thus regulating many physiological and pathological processes including neuronal differentiation and neuronal survival, hair follicle development and cycling, FSH production by the pituitary gland, wound healing, extracellular matrix production, immunosuppression and carcinogenesis. Activin is also thought to have a paracrine or autocrine role in follicular development in the ovary. Within the receptor complex, the type-2 receptors act as a primary activin receptors (binds activin-A/INHBA, activin-B/INHBB as well as inhibin-A/INHA-INHBA). The type-1 receptors like ACVR1B act as downstream transducers of activin signals. Activin binds to type-2 receptor at the plasma membrane and activates its serine-threonine kinase. The activated receptor type-2 then phosphorylates and activates the type-1 receptor. Once activated, the type-1 receptor binds and phosphorylates the SMAD proteins SMAD2 and SMAD3, on serine residues of the C-terminal tail. Soon after their association with the activin receptor and subsequent phosphorylation, SMAD2 and SMAD3 are released into the cytoplasm where they interact with the common partner SMAD4. This SMAD complex translocates into the nucleus where it mediates activin-induced transcription. Inhibitory SMAD7, which is recruited to ACVR1B through FKBP1A, can prevent the association of SMAD2 and SMAD3 with the activin receptor complex, thereby blocking the activin signal. Activin signal transduction is also antagonized by the binding to the receptor of inhibin-B via the IGSF1 inhibin coreceptor.', 'ACVR2B', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Heterotaxy, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (146, '2WQM', '', 'Serine/threonine-protein kinase Nek7', 'Protein kinase which plays an important role in mitotic cell cycle progression (PubMed:17101132, PubMed:31409757, PubMed:19941817). Required for microtubule nucleation activity of the centrosome, robust mitotic spindle formation and cytokinesis (PubMed:17586473, PubMed:19414596, PubMed:31409757, PubMed:19941817, PubMed:26522158). Phosphorylates EML4 at ''Ser-146'', promoting its dissociation from microtubules during mitosis which is required for efficient chromosome congression (PubMed:31409757). Phosphorylates RPS6KB1 (By similarity). Acts as an essential activator of the NLRP3 inflammasome assembly independently of its kinase activity (PubMed:26642356, PubMed:36442502). Acts by unlocking NLRP3 following NLRP3 tranlocation into the microtubule organizing center (MTOC), relieving NLRP3 autoinhibition and promoting formation of the NLRP3:PYCARD complex, and activation of CASP1 (PubMed:26642356, PubMed:31189953, PubMed:36442502). Serves as a cellular switch that enforces mutual exclusivity of the inflammasome response and cell division: interaction with NEK9 prevents interaction with NLRP3 and activation of the inflammasome during mitosis (PubMed:26642356, PubMed:31189953).', 'NEK7', 'Homo sapiens', '{[''2.7.11.34'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Kinase, Magnesium, Metal-binding, Microtubule, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (147, '8Q61', '', 'RAC-beta serine/threonine-protein kinase', 'AKT2 is one of 3 closely related serine/threonine-protein kinases (AKT1, AKT2 and AKT3) called the AKT kinase, and which regulate many processes including metabolism, proliferation, cell survival, growth and angiogenesis. This is mediated through serine and/or threonine phosphorylation of a range of downstream substrates. Over 100 substrate candidates have been reported so far, but for most of them, no isoform specificity has been reported. AKT is responsible of the regulation of glucose uptake by mediating insulin-induced translocation of the SLC2A4/GLUT4 glucose transporter to the cell surface. Phosphorylation of PTPN1 at ''Ser-50'' negatively modulates its phosphatase activity preventing dephosphorylation of the insulin receptor and the attenuation of insulin signaling. Phosphorylation of TBC1D4 triggers the binding of this effector to inhibitory 14-3-3 proteins, which is required for insulin-stimulated glucose transport. AKT regulates also the storage of glucose in the form of glycogen by phosphorylating GSK3A at ''Ser-21'' and GSK3B at ''Ser-9'', resulting in inhibition of its kinase activity. Phosphorylation of GSK3 isoforms by AKT is also thought to be one mechanism by which cell proliferation is driven. AKT regulates also cell survival via the phosphorylation of MAP3K5 (apoptosis signal-related kinase). Phosphorylation of ''Ser-83'' decreases MAP3K5 kinase activity stimulated by oxidative stress and thereby prevents apoptosis. AKT mediates insulin-stimulated protein synthesis by phosphorylating TSC2 at ''Ser-939'' and ''Thr-1462'', thereby activating mTORC1 signaling and leading to both phosphorylation of 4E-BP1 and in activation of RPS6KB1. AKT is involved in the phosphorylation of members of the FOXO factors (Forkhead family of transcription factors), leading to binding of 14-3-3 proteins and cytoplasmic localization. In particular, FOXO1 is phosphorylated at ''Thr-24'', ''Ser-256'' and ''Ser-319''. FOXO3 and FOXO4 are phosphorylated on equivalent sites. AKT has an important role in the regulation of NF-kappa-B-dependent gene transcription and positively regulates the activity of CREB1 (cyclic AMP (cAMP)-response element binding protein). The phosphorylation of CREB1 induces the binding of accessory proteins that are necessary for the transcription of pro-survival genes such as BCL2 and MCL1. AKT phosphorylates ''Ser-454'' on ATP citrate lyase (ACLY), thereby potentially regulating ACLY activity and fatty acid synthesis. Activates the 3B isoform of cyclic nucleotide phosphodiesterase (PDE3B) via phosphorylation of ''Ser-273'', resulting in reduced cyclic AMP levels and inhibition of lipolysis. Phosphorylates PIKFYVE on ''Ser-318'', which results in increased PI(3)P-5 activity. The Rho GTPase-activating protein DLC1 is another substrate and its phosphorylation is implicated in the regulation cell proliferation and cell growth. AKT plays a role as key modulator of the AKT-mTOR signaling pathway controlling the tempo of the process of newborn neurons integration during adult neurogenesis, including correct neuron positioning, dendritic development and synapse formation. Signals downstream of phosphatidylinositol 3-kinase (PI(3)K) to mediate the effects of various growth factors such as platelet-derived growth factor (PDGF), epidermal growth factor (EGF), insulin and insulin-like growth factor I (IGF-I). AKT mediates the antiapoptotic effects of IGF-I. Essential for the SPATA13-mediated regulation of cell migration and adhesion assembly and disassembly. May be involved in the regulation of the placental development. Involved in the inhibition of ciliogenesis associated with RAB8-dependent cilia growth (PubMed:31204173).', 'AKT2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Carbohydrate metabolism, Cell membrane, Cytoplasm, Developmental protein, Diabetes mellitus, Disease variant, Disulfide bond, Endosome, Glucose metabolism, Glycogen biosynthesis, Glycogen metabolism, Glycoprotein, Kinase, Manganese, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Sugar transport, Transferase, Translation regulation, Transport, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (148, '2OU7', '', 'Serine/threonine-protein kinase PLK1', 'Serine/threonine-protein kinase that performs several important functions throughout M phase of the cell cycle, including the regulation of centrosome maturation and spindle assembly, the removal of cohesins from chromosome arms, the inactivation of anaphase-promoting complex/cyclosome (APC/C) inhibitors, and the regulation of mitotic exit and cytokinesis (PubMed:8991084, PubMed:11202906, PubMed:12207013, PubMed:12447691, PubMed:12524548, PubMed:12738781, PubMed:12852856, PubMed:12939256, PubMed:14532005, PubMed:14734534, PubMed:15070733, PubMed:15148369, PubMed:15469984, PubMed:16198290, PubMed:16247472, PubMed:16980960, PubMed:17081991, PubMed:17351640, PubMed:17376779, PubMed:17617734, PubMed:18174154, PubMed:18331714, PubMed:18418051, PubMed:18477460, PubMed:18521620, PubMed:18615013, PubMed:19160488, PubMed:19351716, PubMed:19468300, PubMed:19468302, PubMed:19473992, PubMed:19509060, PubMed:19597481, PubMed:23455478, PubMed:23509069). Polo-like kinase proteins act by binding and phosphorylating proteins that are already phosphorylated on a specific motif recognized by the POLO box domains (PubMed:8991084, PubMed:11202906, PubMed:12207013, PubMed:12447691, PubMed:12524548, PubMed:12738781, PubMed:12852856, PubMed:12939256, PubMed:14532005, PubMed:14734534, PubMed:15070733, PubMed:15148369, PubMed:15469984, PubMed:16198290, PubMed:16247472, PubMed:16980960, PubMed:17081991, PubMed:17351640, PubMed:17376779, PubMed:17617734, PubMed:18174154, PubMed:18331714, PubMed:18418051, PubMed:18477460, PubMed:18521620, PubMed:18615013, PubMed:19160488, PubMed:19351716, PubMed:19468300, PubMed:19468302, PubMed:19473992, PubMed:19509060, PubMed:19597481, PubMed:23455478, PubMed:23509069). Phosphorylates BORA, BUB1B/BUBR1, CCNB1, CDC25C, CEP55, ECT2, ERCC6L, FBXO5/EMI1, FOXM1, KIF20A/MKLP2, CENPU, NEDD1, NINL, NPM1, NUDC, PKMYT1/MYT1, KIZ, PPP1R12A/MYPT1, POLQ, PRC1, RACGAP1/CYK4, RAD51, RHNO1, SGO1, STAG2/SA2, TEX14, TOPORS, p73/TP73, TPT1, WEE1 and HNRNPU (PubMed:8991084, PubMed:11202906, PubMed:12207013, PubMed:12447691, PubMed:12524548, PubMed:12738781, PubMed:12852856, PubMed:12939256, PubMed:14532005, PubMed:14734534, PubMed:15070733, PubMed:15148369, PubMed:15469984, PubMed:16198290, PubMed:16247472, PubMed:16980960, PubMed:17081991, PubMed:17218258, PubMed:17351640, PubMed:17376779, PubMed:17617734, PubMed:18174154, PubMed:18331714, PubMed:18418051, PubMed:18477460, PubMed:18521620, PubMed:18615013, PubMed:19160488, PubMed:19351716, PubMed:19468300, PubMed:19468302, PubMed:19473992, PubMed:19509060, PubMed:22325354, PubMed:19597481, PubMed:23455478, PubMed:23509069, PubMed:25986610, PubMed:26811421, PubMed:37674080, PubMed:37440612). Plays a key role in centrosome functions and the assembly of bipolar spindles by phosphorylating KIZ, NEDD1 and NINL (PubMed:16980960, PubMed:19509060). NEDD1 phosphorylation promotes subsequent targeting of the gamma-tubulin ring complex (gTuRC) to the centrosome, an important step for spindle formation (PubMed:19509060). Phosphorylation of NINL component of the centrosome leads to NINL dissociation from other centrosomal proteins (PubMed:12852856). Involved in mitosis exit and cytokinesis by phosphorylating CEP55, ECT2, KIF20A/MKLP2, CENPU, PRC1 and RACGAP1 (PubMed:12939256, PubMed:16247472, PubMed:17351640, PubMed:19468300, PubMed:19468302). Recruited at the central spindle by phosphorylating and docking PRC1 and KIF20A/MKLP2; creates its own docking sites on PRC1 and KIF20A/MKLP2 by mediating phosphorylation of sites subsequently recognized by the POLO box domains (PubMed:12939256, PubMed:17351640). Phosphorylates RACGAP1, thereby creating a docking site for the Rho GTP exchange factor ECT2 that is essential for the cleavage furrow formation (PubMed:19468300, PubMed:19468302). Promotes the central spindle recruitment of ECT2 (PubMed:16247472). Plays a central role in G2/M transition of mitotic cell cycle by phosphorylating CCNB1, CDC25C, FOXM1, CENPU, PKMYT1/MYT1, PPP1R12A/MYPT1 and WEE1 (PubMed:11202906, PubMed:12447691, PubMed:12524548, PubMed:19160488). Part of a regulatory circuit that promotes the activation of CDK1 by phosphorylating the positive regulator CDC25C and inhibiting the negative regulators WEE1 and PKMYT1/MYT1 (PubMed:11202906). Also acts by mediating phosphorylation of cyclin-B1 (CCNB1) on centrosomes in prophase (PubMed:12447691, PubMed:12524548). Phosphorylates FOXM1, a key mitotic transcription regulator, leading to enhance FOXM1 transcriptional activity (PubMed:19160488). Involved in kinetochore functions and sister chromatid cohesion by phosphorylating BUB1B/BUBR1, FBXO5/EMI1 and STAG2/SA2 (PubMed:15469984, PubMed:15148369, PubMed:17376779, PubMed:18331714). PLK1 is high on non-attached kinetochores suggesting a role of PLK1 in kinetochore attachment or in spindle assembly checkpoint (SAC) regulation (PubMed:17617734). Required for kinetochore localization of BUB1B (PubMed:17376779). Regulates the dissociation of cohesin from chromosomes by phosphorylating cohesin subunits such as STAG2/SA2 (By similarity). Phosphorylates SGO1: required for spindle pole localization of isoform 3 of SGO1 and plays a role in regulating its centriole cohesion function (PubMed:18331714). Mediates phosphorylation of FBXO5/EMI1, a negative regulator of the APC/C complex during prophase, leading to FBXO5/EMI1 ubiquitination and degradation by the proteasome (PubMed:15469984, PubMed:15148369). Acts as a negative regulator of p53 family members: phosphorylates TOPORS, leading to inhibit the sumoylation of p53/TP53 and simultaneously enhance the ubiquitination and subsequent degradation of p53/TP53 (PubMed:19473992). Phosphorylates the transactivation domain of the transcription factor p73/TP73, leading to inhibit p73/TP73-mediated transcriptional activation and pro-apoptotic functions. Phosphorylates BORA, and thereby promotes the degradation of BORA (PubMed:18521620). Contributes to the regulation of AURKA function (PubMed:18662541, PubMed:18615013). Also required for recovery after DNA damage checkpoint and entry into mitosis (PubMed:18662541, PubMed:18615013). Phosphorylates MISP, leading to stabilization of cortical and astral microtubule attachments required for proper spindle positioning (PubMed:23509069). Together with MEIKIN, acts as a regulator of kinetochore function during meiosis I: required both for mono-orientation of kinetochores on sister chromosomes and protection of centromeric cohesin from separase-mediated cleavage (By similarity). Phosphorylates CEP68 and is required for its degradation (PubMed:25503564). Regulates nuclear envelope breakdown during prophase by phosphorylating DCTN1 resulting in its localization in the nuclear envelope (PubMed:20679239). Phosphorylates the heat shock transcription factor HSF1, promoting HSF1 nuclear translocation upon heat shock (PubMed:15661742). Phosphorylates HSF1 also in the early mitotic period; this phosphorylation regulates HSF1 localization to the spindle pole, the recruitment of the SCF(BTRC) ubiquitin ligase complex induicing HSF1 degradation, and hence mitotic progression (PubMed:18794143). Regulates mitotic progression by phosphorylating RIOK2 (PubMed:21880710). Through the phosphorylation of DZIP1 regulates the localization during mitosis of the BBSome, a ciliary protein complex involved in cilium biogenesis (PubMed:27979967). Regulates DNA repair during mitosis by mediating phosphorylation of POLQ and RHNO1, thereby promoting POLQ recruitment to DNA damage sites (PubMed:37674080, PubMed:37440612).', 'PLK1', 'Homo sapiens', '{[''2.7.11.21'']}', '3D-structure, Acetylation, ATP-binding, Cell cycle, Cell division, Centromere, Chromosome, Cytoplasm, Cytoskeleton, Isopeptide bond, Kinase, Kinetochore, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (155, '6BXI', '', 'Serine/threonine-protein kinase 38', 'Negative regulator of MAP3K1/2 signaling. Converts MAP3K2 from its phosphorylated form to its non-phosphorylated form and inhibits autophosphorylation of MAP3K2.', 'STK38', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Direct protein sequencing, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (149, '5O0Y', '', 'Serine/threonine-protein kinase tousled-like 2', 'Serine/threonine-protein kinase involved in the process of chromatin assembly and probably also DNA replication, transcription, repair, and chromosome segregation (PubMed:9427565, PubMed:10523312, PubMed:11470414, PubMed:12660173, PubMed:12955071, PubMed:29955062, PubMed:33323470). Phosphorylates the chromatin assembly factors ASF1A and ASF1B (PubMed:11470414, PubMed:20016786, PubMed:29955062, PubMed:35136069). Phosphorylation of ASF1A prevents its proteasome-mediated degradation, thereby enhancing chromatin assembly (PubMed:20016786). Negative regulator of amino acid starvation-induced autophagy (PubMed:22354037).', 'TLK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Chromatin regulator, Coiled coil, Cytoplasm, Cytoskeleton, Disease variant, DNA damage, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (150, '1U5Q', '', 'Serine/threonine-protein kinase TAO2', 'Serine/threonine-protein kinase involved in different processes such as membrane blebbing and apoptotic bodies formation DNA damage response and MAPK14/p38 MAPK stress-activated MAPK cascade. Phosphorylates itself, MBP, activated MAPK8, MAP2K3, MAP2K6 and tubulins. Activates the MAPK14/p38 MAPK signaling pathway through the specific activation and phosphorylation of the upstream MAP2K3 and MAP2K6 kinases. In response to DNA damage, involved in the G2/M transition DNA damage checkpoint by activating the p38/MAPK14 stress-activated MAPK cascade, probably by mediating phosphorylation of upstream MAP2K3 and MAP2K6 kinases. May affect microtubule organization and stability. May play a role in the osmotic stress-MAPK8 pathway. Prevents MAP3K7-mediated activation of CHUK, and thus NF-kappa-B activation. Isoform 2, but not isoform 1, is required for PCDH8 endocytosis. Following homophilic interactions between PCDH8 extracellular domains, isoform 2 phosphorylates and activates MAPK14/p38 MAPK which in turn phosphorylates isoform 2. This process leads to PCDH8 endocytosis and CDH2 cointernalization. Both isoforms are involved in MAPK14/p38 MAPK activation.', 'Taok2', 'Rattus norvegicus', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Coiled coil, Cytoplasm, Cytoplasmic vesicle, Cytoskeleton, Kinase, Magnesium, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (151, '2GK9', '', 'Phosphatidylinositol 5-phosphate 4-kinase type-2 gamma', 'Phosphatidylinositol 5-phosphate 4-kinase with low enzymatic activity. May be a GTP sensor, has higher GTP-dependent kinase activity than ATP-dependent kinase activity. PIP4Ks negatively regulate insulin signaling through a catalytic-independent mechanism. They interact with PIP5Ks and suppress PIP5K-mediated PtdIns(4,5)P2 synthesis and insulin-dependent conversion to PtdIns(3,4,5)P3 (PubMed:31091439).', 'PIP4K2C', 'Homo sapiens', '{[''2.7.1.149'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Endoplasmic reticulum, Kinase, Lipid metabolism, Nucleotide-binding, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (152, '7O7I', '', 'Homeodomain-interacting protein kinase 3', 'Serine/threonine-protein kinase involved in transcription regulation, apoptosis and steroidogenic gene expression. Phosphorylates JUN and RUNX2. Seems to negatively regulate apoptosis by promoting FADD phosphorylation. Enhances androgen receptor-mediated transcription. May act as a transcriptional corepressor for NK homeodomain transcription factors. The phosphorylation of NR5A1 activates SF1 leading to increased steroidogenic gene expression upon cAMP signaling pathway stimulation. In osteoblasts, supports transcription activation: phosphorylates RUNX2 that synergizes with SPEN/MINT to enhance FGFR2-mediated activation of the osteocalcin FGF-responsive element (OCFRE).', 'HIPK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (153, '3Q4T', '', 'Activin receptor type-2A', 'On ligand binding, forms a receptor complex consisting of two type II and two type I transmembrane serine/threonine kinases. Type II receptors phosphorylate and activate type I receptors which autophosphorylate, then bind and activate SMAD transcriptional regulators. Receptor for activin A, activin B and inhibin A (PubMed:17911401). Mediates induction of adipogenesis by GDF6 (By similarity).', 'ACVR2A', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disulfide bond, Glycoprotein, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (154, '6PXN', '', 'Casein kinase I isoform delta', 'Essential serine/threonine-protein kinase that regulates diverse cellular growth and survival processes including Wnt signaling, DNA repair and circadian rhythms. It can phosphorylate a large number of proteins. Casein kinases are operationally defined by their preferential utilization of acidic proteins such as caseins as substrates. Phosphorylates connexin-43/GJA1, MAP1A, SNAPIN, MAPT/TAU, TOP2A, DCK, HIF1A, EIF6, p53/TP53, DVL2, DVL3, ESR1, AIB1/NCOA3, DNMT1, PKD2, YAP1, PER1 and PER2. Central component of the circadian clock. In balance with PP1, determines the circadian period length through the regulation of the speed and rhythmicity of PER1 and PER2 phosphorylation. Controls PER1 and PER2 nuclear transport and degradation. YAP1 phosphorylation promotes its SCF(beta-TRCP) E3 ubiquitin ligase-mediated ubiquitination and subsequent degradation. DNMT1 phosphorylation reduces its DNA-binding activity. Phosphorylation of ESR1 and AIB1/NCOA3 stimulates their activity and coactivation. Phosphorylation of DVL2 and DVL3 regulates WNT3A signaling pathway that controls neurite outgrowth. Phosphorylates NEDD9/HEF1 (By similarity). EIF6 phosphorylation promotes its nuclear export. Triggers down-regulation of dopamine receptors in the forebrain. Activates DCK in vitro by phosphorylation. TOP2A phosphorylation favors DNA cleavable complex formation. May regulate the formation of the mitotic spindle apparatus in extravillous trophoblast. Modulates connexin-43/GJA1 gap junction assembly by phosphorylation. Probably involved in lymphocyte physiology. Regulates fast synaptic transmission mediated by glutamate.', 'CSNK1D', 'Homo sapiens', '{[''2.7.11.1'',''2.7.11.26'']}', '3D-structure, Alternative splicing, ATP-binding, Biological rhythms, Cell membrane, Cytoplasm, Cytoskeleton, Disease variant, Golgi apparatus, Kinase, Membrane, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (156, '7ZV9', '', 'Fms-related tyrosine kinase 3 ligand', 'Stimulates the proliferation of early hematopoietic cells by activating FLT3. Synergizes well with a number of other colony stimulating factors and interleukins.', 'FLT3LG', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Cell membrane, Cytokine, Disulfide bond, Glycoprotein, Membrane, Reference proteome, Secreted, Signal, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (157, '2C47', '', 'Casein kinase I isoform gamma-2', 'Serine/threonine-protein kinase. Casein kinases are operationally defined by their preferential utilization of acidic proteins such as caseins as substrates. It can phosphorylate a large number of proteins. Participates in Wnt signaling (By similarity). Phosphorylates COL4A3BP/CERT, MTA1 and SMAD3. SMAD3 phosphorylation promotes its ligand-dependent ubiquitination and subsequent proteasome degradation, thus inhibiting SMAD3-mediated TGF-beta responses. Hyperphosphorylation of the serine-repeat motif of COL4A3BP/CERT leads to its inactivation by dissociation from the Golgi complex, thus down-regulating ER-to-Golgi transport of ceramide and sphingomyelin synthesis. Triggers PER1 proteasomal degradation probably through phosphorylation (PubMed:15077195, PubMed:15917222, PubMed:18794808, PubMed:19005213). Involved in brain development and vesicular trafficking and neurotransmitter releasing from small synaptic vesicles. Regulates fast synaptic transmission mediated by glutamate (By similarity). Involved in regulation of reactive oxygen species (ROS) levels (PubMed:37099597).', 'CSNK1G2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (158, '4LGD', '', 'Serine/threonine-protein kinase 3', 'Stress-activated, pro-apoptotic kinase which, following caspase-cleavage, enters the nucleus and induces chromatin condensation followed by internucleosomal DNA fragmentation. Key component of the Hippo signaling pathway which plays a pivotal role in organ size control and tumor suppression by restricting proliferation and promoting apoptosis. The core of this pathway is composed of a kinase cascade wherein STK3/MST2 and STK4/MST1, in complex with its regulatory protein SAV1, phosphorylates and activates LATS1/2 in complex with its regulatory protein MOB1, which in turn phosphorylates and inactivates YAP1 oncoprotein and WWTR1/TAZ (PubMed:23972470). Phosphorylation of YAP1 by LATS2 inhibits its translocation into the nucleus to regulate cellular genes important for cell proliferation, cell death, and cell migration. STK3/MST2 and STK4/MST1 are required to repress proliferation of mature hepatocytes, to prevent activation of facultative adult liver stem cells (oval cells), and to inhibit tumor formation. Phosphorylates NKX2-1 (By similarity). Phosphorylates NEK2 and plays a role in centrosome disjunction by regulating the localization of NEK2 to centrosome, and its ability to phosphorylate CROCC and CEP250 (PubMed:21723128). In conjunction with SAV1, activates the transcriptional activity of ESR1 through the modulation of its phosphorylation. Positively regulates RAF1 activation via suppression of the inhibitory phosphorylation of RAF1 on ''Ser-259''. Phosphorylates MOBKL1A and RASSF2. Phosphorylates MOBKL1B on ''Thr-74''. Acts cooperatively with MOBKL1B to activate STK38.', 'STK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Cytoskeleton, Direct protein sequencing, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (159, '4K0V', '', 'Angiopoietin-1 receptor', 'Tyrosine-protein kinase that acts as a cell-surface receptor for ANGPT1, ANGPT2 and ANGPT4 and regulates angiogenesis, endothelial cell survival, proliferation, migration, adhesion and cell spreading, reorganization of the actin cytoskeleton, but also maintenance of vascular quiescence. Has anti-inflammatory effects by preventing the leakage of pro-inflammatory plasma proteins and leukocytes from blood vessels. Required for normal angiogenesis and heart development during embryogenesis. Required for post-natal hematopoiesis. After birth, activates or inhibits angiogenesis, depending on the context. Inhibits angiogenesis and promotes vascular stability in quiescent vessels, where endothelial cells have tight contacts. In quiescent vessels, ANGPT1 oligomers recruit TEK to cell-cell contacts, forming complexes with TEK molecules from adjoining cells, and this leads to preferential activation of phosphatidylinositol 3-kinase and the AKT1 signaling cascades. In migrating endothelial cells that lack cell-cell adhesions, ANGT1 recruits TEK to contacts with the extracellular matrix, leading to the formation of focal adhesion complexes, activation of PTK2/FAK and of the downstream kinases MAPK1/ERK2 and MAPK3/ERK1, and ultimately to the stimulation of sprouting angiogenesis. ANGPT1 signaling triggers receptor dimerization and autophosphorylation at specific tyrosine residues that then serve as binding sites for scaffold proteins and effectors. Signaling is modulated by ANGPT2 that has lower affinity for TEK, can promote TEK autophosphorylation in the absence of ANGPT1, but inhibits ANGPT1-mediated signaling by competing for the same binding site. Signaling is also modulated by formation of heterodimers with TIE1, and by proteolytic processing that gives rise to a soluble TEK extracellular domain. The soluble extracellular domain modulates signaling by functioning as decoy receptor for angiopoietins. TEK phosphorylates DOK2, GRB7, GRB14, PIK3R1; SHC1 and TIE1.', 'TEK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Cytoskeleton, Direct protein sequencing, Disease variant, Disulfide bond, EGF-like domain, Glaucoma, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (170, '5AX9', '', 'TRAF2 and NCK-interacting protein kinase', 'Serine/threonine kinase that acts as an essential activator of the Wnt signaling pathway. Recruited to promoters of Wnt target genes and required to activate their expression. May act by phosphorylating TCF4/TCF7L2. Appears to act upstream of the JUN N-terminal pathway. May play a role in the response to environmental stress. Part of a signaling complex composed of NEDD4, RAP2A and TNIK which regulates neuronal dendrite extension and arborization during development. More generally, it may play a role in cytoskeletal rearrangements and regulate cell spreading. Phosphorylates SMAD1 on Thr-322.', 'TNIK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Endosome, Intellectual disability, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (160, '1OPL', '', 'Tyrosine-protein kinase ABL1', 'Non-receptor tyrosine-protein kinase that plays a role in many key processes linked to cell growth and survival such as cytoskeleton remodeling in response to extracellular stimuli, cell motility and adhesion, receptor endocytosis, autophagy, DNA damage response and apoptosis. Coordinates actin remodeling through tyrosine phosphorylation of proteins controlling cytoskeleton dynamics like WASF3 (involved in branch formation); ANXA1 (involved in membrane anchoring); DBN1, DBNL, CTTN, RAPH1 and ENAH (involved in signaling); or MAPT and PXN (microtubule-binding proteins). Phosphorylation of WASF3 is critical for the stimulation of lamellipodia formation and cell migration. Involved in the regulation of cell adhesion and motility through phosphorylation of key regulators of these processes such as BCAR1, CRK, CRKL, DOK1, EFS or NEDD9 (PubMed:22810897). Phosphorylates multiple receptor tyrosine kinases and more particularly promotes endocytosis of EGFR, facilitates the formation of neuromuscular synapses through MUSK, inhibits PDGFRB-mediated chemotaxis and modulates the endocytosis of activated B-cell receptor complexes. Other substrates which are involved in endocytosis regulation are the caveolin (CAV1) and RIN1. Moreover, ABL1 regulates the CBL family of ubiquitin ligases that drive receptor down-regulation and actin remodeling. Phosphorylation of CBL leads to increased EGFR stability. Involved in late-stage autophagy by regulating positively the trafficking and function of lysosomal components. ABL1 targets to mitochondria in response to oxidative stress and thereby mediates mitochondrial dysfunction and cell death. In response to oxidative stress, phosphorylates serine/threonine kinase PRKD2 at ''Tyr-717'' (PubMed:28428613). ABL1 is also translocated in the nucleus where it has DNA-binding activity and is involved in DNA-damage response and apoptosis. Many substrates are known mediators of DNA repair: DDB1, DDB2, ERCC3, ERCC6, RAD9A, RAD51, RAD52 or WRN. Activates the proapoptotic pathway when the DNA damage is too severe to be repaired. Phosphorylates TP73, a primary regulator for this type of damage-induced apoptosis. Phosphorylates the caspase CASP9 on ''Tyr-153'' and regulates its processing in the apoptotic response to DNA damage. Phosphorylates PSMA7 that leads to an inhibition of proteasomal activity and cell cycle transition blocks. ABL1 acts also as a regulator of multiple pathological signaling cascades during infection. Several known tyrosine-phosphorylated microbial proteins have been identified as ABL1 substrates. This is the case of A36R of Vaccinia virus, Tir (translocated intimin receptor) of pathogenic E.coli and possibly Citrobacter, CagA (cytotoxin-associated gene A) of H.pylori, or AnkA (ankyrin repeat-containing protein A) of A.phagocytophilum. Pathogens can highjack ABL1 kinase signaling to reorganize the host actin cytoskeleton for multiple purposes, like facilitating intracellular movement and host cell exit. Finally, functions as its own regulator through autocatalytic activity as well as through phosphorylation of its inhibitor, ABI1. Regulates T-cell differentiation in a TBX21-dependent manner (By similarity). Positively regulates chemokine-mediated T-cell migration, polarization, and homing to lymph nodes and immune-challenged tissues, potentially via activation of NEDD9/HEF1 and RAP1 (By similarity). Phosphorylates TBX21 on tyrosine residues leading to an enhancement of its transcriptional activator activity (By similarity).', 'ABL1', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Autophagy, Cell adhesion, Chromosomal rearrangement, Cytoplasm, Cytoskeleton, Disease variant, DNA damage, DNA repair, DNA-binding, Endocytosis, Kinase, Lipoprotein, Magnesium, Manganese, Membrane, Metal-binding, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (161, '6NYB', '', 'Serine/threonine-protein kinase B-raf', 'Protein kinase involved in the transduction of mitogenic signals from the cell membrane to the nucleus (Probable). Phosphorylates MAP2K1, and thereby activates the MAP kinase signal transduction pathway (PubMed:21441910, PubMed:29433126). Phosphorylates PFKFB2 (PubMed:36402789). May play a role in the postsynaptic responses of hippocampal neurons (PubMed:1508179).', 'BRAF', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Allosteric enzyme, ATP-binding, Cardiomyopathy, Cell membrane, Chromosomal rearrangement, Cytoplasm, Deafness, Direct protein sequencing, Disease variant, Ectodermal dysplasia, Intellectual disability, Isopeptide bond, Kinase, Membrane, Metal-binding, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (162, '3LM0', '', 'Serine/threonine-protein kinase 17B', 'Phosphorylates myosin light chains (By similarity). Acts as a positive regulator of apoptosis.', 'STK17B', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Apoptosis, ATP-binding, Cell membrane, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (163, '5HES', '', 'Mitogen-activated protein kinase kinase kinase 20', 'Stress-activated component of a protein kinase signal transduction cascade that promotes programmed cell death in response to various stress, such as ribosomal stress, osmotic shock and ionizing radiation (PubMed:10924358, PubMed:11836244, PubMed:12220515, PubMed:14521931, PubMed:15350844, PubMed:15737997, PubMed:18331592, PubMed:20559024, PubMed:32610081, PubMed:32289254, PubMed:35857590, PubMed:26999302). Acts by catalyzing phosphorylation of MAP kinase kinases, leading to activation of the JNK (MAPK8/JNK1, MAPK9/JNK2 and/or MAPK10/JNK3) and MAP kinase p38 (MAPK11, MAPK12, MAPK13 and/or MAPK14) pathways (PubMed:11042189, PubMed:11836244, PubMed:12220515, PubMed:14521931, PubMed:15172994, PubMed:15737997, PubMed:32610081, PubMed:32289254, PubMed:35857590). Activates JNK through phosphorylation of MAP2K4/MKK4 and MAP2K7/MKK7, and MAP kinase p38 gamma (MAPK12) via phosphorylation of MAP2K3/MKK3 and MAP2K6/MKK6 (PubMed:11836244, PubMed:12220515). Involved in stress associated with adrenergic stimulation: contributes to cardiac decompensation during periods of acute cardiac stress (PubMed:15350844, PubMed:21224381, PubMed:27859413). May be involved in regulation of S and G2 cell cycle checkpoint by mediating phosphorylation of CHEK2 (PubMed:15342622).', 'MAP3K20', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cytoplasm, Disease variant, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, RNA-binding, rRNA-binding, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (164, '1CM8', '', 'Mitogen-activated protein kinase 12', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. MAPK12 is one of the four p38 MAPKs which play an important role in the cascades of cellular responses evoked by extracellular stimuli such as pro-inflammatory cytokines or physical stress leading to direct activation of transcription factors such as ELK1 and ATF2. Accordingly, p38 MAPKs phosphorylate a broad range of proteins and it has been estimated that they may have approximately 200 to 300 substrates each. Some of the targets are downstream kinases such as MAPKAPK2, which are activated through phosphorylation and further phosphorylate additional targets. Plays a role in myoblast differentiation and also in the down-regulation of cyclin D1 in response to hypoxia in adrenal cells suggesting MAPK12 may inhibit cell proliferation while promoting differentiation. Phosphorylates DLG1. Following osmotic shock, MAPK12 in the cell nucleus increases its association with nuclear DLG1, thereby causing dissociation of DLG1-SFPQ complexes. This function is independent of its catalytic activity and could affect mRNA processing and/or gene transcription to aid cell adaptation to osmolarity changes in the environment. Regulates UV-induced checkpoint signaling and repair of UV-induced DNA damage and G2 arrest after gamma-radiation exposure. MAPK12 is involved in the regulation of SLC2A1 expression and basal glucose uptake in L6 myotubes; and negatively regulates SLC2A4 expression and contraction-mediated glucose uptake in adult skeletal muscle. C-Jun (JUN) phosphorylation is stimulated by MAPK14 and inhibited by MAPK12, leading to a distinct AP-1 regulation. MAPK12 is required for the normal kinetochore localization of PLK1, prevents chromosomal instability and supports mitotic cell viability. MAPK12-signaling is also positively regulating the expansion of transient amplifying myogenic precursor cells during muscle growth and regeneration.', 'MAPK12', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cytoplasm, Kinase, Magnesium, Metal-binding, Mitochondrion, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (211, '3AGL', '', 'cAMP-dependent protein kinase catalytic subunit alpha', 'Phosphorylates a large number of substrates in the cytoplasm and the nucleus (PubMed:15642694, PubMed:15905176, PubMed:16387847, PubMed:17333334, PubMed:17565987, PubMed:17693412, PubMed:18836454, PubMed:19949837, PubMed:20356841, PubMed:21085490, PubMed:21514275, PubMed:21812984, PubMed:31112131). Phosphorylates CDC25B, ABL1, NFKB1, CLDN3, PSMC5/RPT6, PJA2, RYR2, RORA, SOX9 and VASP (PubMed:15642694, PubMed:15905176, PubMed:16387847, PubMed:17333334, PubMed:17565987, PubMed:17693412, PubMed:18836454, PubMed:19949837, PubMed:20356841, PubMed:21085490, PubMed:21514275, PubMed:21812984). Regulates the abundance of compartmentalized pools of its regulatory subunits through phosphorylation of PJA2 which binds and ubiquitinates these subunits, leading to their subsequent proteolysis (PubMed:21423175). RORA is activated by phosphorylation (PubMed:21514275). Required for glucose-mediated adipogenic differentiation increase and osteogenic differentiation inhibition from osteoblasts (PubMed:19949837). Involved in chondrogenesis by mediating phosphorylation of SOX9 (By similarity). Involved in the regulation of platelets in response to thrombin and collagen; maintains circulating platelets in a resting state by phosphorylating proteins in numerous platelet inhibitory pathways when in complex with NF-kappa-B (NFKB1 and NFKB2) and I-kappa-B-alpha (NFKBIA), but thrombin and collagen disrupt these complexes and free active PRKACA stimulates platelets and leads to platelet aggregation by phosphorylating VASP (PubMed:15642694, PubMed:20356841). Prevents the antiproliferative and anti-invasive effects of alpha-difluoromethylornithine in breast cancer cells when activated (PubMed:17333334). RYR2 channel activity is potentiated by phosphorylation in presence of luminal Ca(2+), leading to reduced amplitude and increased frequency of store overload-induced Ca(2+) release (SOICR) characterized by an increased rate of Ca(2+) release and propagation velocity of spontaneous Ca(2+) waves, despite reduced wave amplitude and resting cytosolic Ca(2+) (PubMed:17693412). PSMC5/RPT6 activation by phosphorylation stimulates proteasome (PubMed:17565987). Negatively regulates tight junctions (TJs) in ovarian cancer cells via CLDN3 phosphorylation (PubMed:15905176). NFKB1 phosphorylation promotes NF-kappa-B p50-p50 DNA binding (PubMed:15642694). Required for phosphorylation of GLI transcription factors which inhibits them and prevents transcriptional activation of Hedgehog signaling pathway target genes (By similarity). GLI transcription factor phosphorylation is inhibited by interaction of PRKACA with SMO which sequesters PRKACA at the cell membrane (By similarity). Involved in embryonic development by down-regulating the Hedgehog (Hh) signaling pathway that determines embryo pattern formation and morphogenesis most probably through the regulation of OFD1 in ciliogenesis (PubMed:33934390). Prevents meiosis resumption in prophase-arrested oocytes via CDC25B inactivation by phosphorylation (By similarity). May also regulate rapid eye movement (REM) sleep in the pedunculopontine tegmental (PPT) (By similarity). Phosphorylates APOBEC3G and AICDA (PubMed:16387847, PubMed:18836454). Phosphorylates HSF1; this phosphorylation promotes HSF1 nuclear localization and transcriptional activity upon heat shock (PubMed:21085490). Acts as a negative regulator of mTORC1 by mediating phosphorylation of RPTOR (PubMed:31112131).', 'PRKACA', 'Homo sapiens', '{[''2.7.11.11'']}', '3D-structure, Alternative splicing, ATP-binding, cAMP, Cell membrane, Cell projection, Cilium, Cushing syndrome, Cytoplasm, Cytoplasmic vesicle, Disease variant, Flagellum, Kinase, Lipoprotein, Membrane, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (165, '1K9A', '', 'Tyrosine-protein kinase CSK', 'Non-receptor tyrosine-protein kinase that plays an important role in the regulation of cell growth, differentiation, migration and immune response. Phosphorylates tyrosine residues located in the C-terminal tails of Src-family kinases (SFKs) including LCK, SRC, HCK, FYN, LYN, CSK or YES1. Upon tail phosphorylation, Src-family members engage in intramolecular interactions between the phosphotyrosine tail and the SH2 domain that result in an inactive conformation. To inhibit SFKs, CSK is recruited to the plasma membrane via binding to transmembrane proteins or adapter proteins located near the plasma membrane. Suppresses signaling by various surface receptors, including T-cell receptor (TCR) and B-cell receptor (BCR) by phosphorylating and maintaining inactive several positive effectors such as FYN or LCK (By similarity).', 'Csk', 'Rattus norvegicus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Adaptive immunity, ATP-binding, Cell membrane, Cytoplasm, Direct protein sequencing, Immunity, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (166, '2V62', '', 'Serine/threonine-protein kinase VRK2', 'Serine/threonine kinase that regulates several signal transduction pathways (PubMed:16704422, PubMed:14645249, PubMed:16495336, PubMed:17709393, PubMed:18617507, PubMed:18286207, PubMed:20679487). Isoform 1 modulates the stress response to hypoxia and cytokines, such as interleukin-1 beta (IL1B) and this is dependent on its interaction with MAPK8IP1, which assembles mitogen-activated protein kinase (MAPK) complexes (PubMed:17709393). Inhibition of signal transmission mediated by the assembly of MAPK8IP1-MAPK complexes reduces JNK phosphorylation and JUN-dependent transcription (PubMed:18286207). Phosphorylates ''Thr-18'' of p53/TP53, histone H3, and may also phosphorylate MAPK8IP1 (PubMed:16704422). Phosphorylates BANF1 and disrupts its ability to bind DNA and reduces its binding to LEM domain-containing proteins (PubMed:16495336). Down-regulates the transactivation of transcription induced by ERBB2, HRAS, BRAF, and MEK1 (PubMed:20679487). Blocks the phosphorylation of ERK in response to ERBB2 and HRAS (PubMed:20679487). Can also phosphorylate the following substrates that are commonly used to establish in vitro kinase activity: casein, MBP and histone H2B, but it is not sure that this is physiologically relevant (PubMed:14645249).', 'VRK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Endoplasmic reticulum, Host-virus interaction, Kinase, Membrane, Mitochondrion, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (167, '3ZEW', '', 'Ephrin type-B receptor 4', 'Receptor tyrosine kinase which binds promiscuously transmembrane ephrin-B family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Together with its cognate ligand/functional ligand EFNB2 it is involved in the regulation of cell adhesion and migration, and plays a central role in heart morphogenesis, angiogenesis and blood vessel remodeling and permeability. EPHB4-mediated forward signaling controls cellular repulsion and segregation from EFNB2-expressing cells.', 'EPHB4', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell membrane, Developmental protein, Disease variant, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (168, '2X7G', '', 'SRSF protein kinase 2', 'Serine/arginine-rich protein-specific kinase which specifically phosphorylates its substrates at serine residues located in regions rich in arginine/serine dipeptides, known as RS domains and is involved in the phosphorylation of SR splicing factors and the regulation of splicing (PubMed:9472028, PubMed:18559500, PubMed:21056976). Promotes neuronal apoptosis by up-regulating cyclin-D1 (CCND1) expression (PubMed:19592491). This is done by the phosphorylation of SRSF2, leading to the suppression of p53/TP53 phosphorylation thereby relieving the repressive effect of p53/TP53 on cyclin-D1 (CCND1) expression (PubMed:21205200). Phosphorylates ACIN1, and redistributes it from the nuclear speckles to the nucleoplasm, resulting in cyclin A1 but not cyclin A2 up-regulation (PubMed:18559500). Plays an essential role in spliceosomal B complex formation via the phosphorylation of DDX23/PRP28 (PubMed:18425142). Probably by phosphorylating DDX23, leads to the suppression of incorrect R-loops formed during transcription; R-loops are composed of a DNA:RNA hybrid and the associated non-template single-stranded DNA (PubMed:28076779). Can mediate hepatitis B virus (HBV) core protein phosphorylation (PubMed:12134018). Plays a negative role in the regulation of HBV replication through a mechanism not involving the phosphorylation of the core protein but by reducing the packaging efficiency of the pregenomic RNA (pgRNA) without affecting the formation of the viral core particles (PubMed:16122776).', 'SRPK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Chromosome, Cytoplasm, Differentiation, Kinase, mRNA processing, mRNA splicing, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (169, '6G76', '', 'Ribosomal protein S6 kinase alpha-6', 'Constitutively active serine/threonine-protein kinase that exhibits growth-factor-independent kinase activity and that may participate in p53/TP53-dependent cell growth arrest signaling and play an inhibitory role during embryogenesis.', 'RPS6KA6', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (171, '3KUL', '', 'Ephrin type-A receptor 8', 'Receptor tyrosine kinase which binds promiscuously GPI-anchored ephrin-A family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. The GPI-anchored ephrin-A EFNA2, EFNA3, and EFNA5 are able to activate EPHA8 through phosphorylation. With EFNA5 may regulate integrin-mediated cell adhesion and migration on fibronectin substrate but also neurite outgrowth. During development of the nervous system also plays a role in axon guidance. Downstream effectors of the EPHA8 signaling pathway include FYN which promotes cell adhesion upon activation by EPHA8 and the MAP kinases in the stimulation of neurite outgrowth (By similarity).', 'EPHA8', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell membrane, Cell projection, Developmental protein, Endosome, Glycoprotein, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (172, '3MTL', '', 'Cyclin-dependent kinase 16', 'Protein kinase that plays a role in vesicle-mediated transport processes and exocytosis. Regulates GH1 release by brain neurons. Phosphorylates NSF, and thereby regulates NSF oligomerization. Required for normal spermatogenesis. Regulates neuron differentiation and dendrite development (By similarity). Plays a role in the regulation of insulin secretion in response to changes in blood glucose levels. Can phosphorylate CCNY at ''Ser-336'' (in vitro).', 'CDK16', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Cytoplasmic vesicle, Differentiation, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Spermatogenesis, Synapse, Synaptosome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (173, '8T7T', '', 'eIF-2-alpha kinase GCN2', 'Metabolic-stress sensing protein kinase that phosphorylates the alpha subunit of eukaryotic translation initiation factor 2 (EIF2S1/eIF-2-alpha) in response to low amino acid availability (PubMed:25329545, PubMed:32610081). Plays a role as an activator of the integrated stress response (ISR) required for adaptation to amino acid starvation (By similarity). EIF2S1/eIF-2-alpha phosphorylation in response to stress converts EIF2S1/eIF-2-alpha into a global protein synthesis inhibitor, leading to a global attenuation of cap-dependent translation, and thus to a reduced overall utilization of amino acids, while concomitantly initiating the preferential translation of ISR-specific mRNAs, such as the transcriptional activator ATF4, and hence allowing ATF4-mediated reprogramming of amino acid biosynthetic gene expression to alleviate nutrient depletion (PubMed:32610081). Binds uncharged tRNAs (By similarity). Required for the translational induction of protein kinase PRKCH following amino acid starvation (By similarity). Involved in cell cycle arrest by promoting cyclin D1 mRNA translation repression after the unfolded protein response pathway (UPR) activation or cell cycle inhibitor CDKN1A/p21 mRNA translation activation in response to amino acid deprivation (PubMed:26102367). Plays a role in the consolidation of synaptic plasticity, learning as well as formation of long-term memory (By similarity). Plays a role in neurite outgrowth inhibition (By similarity). Plays a proapoptotic role in response to glucose deprivation (By similarity). Promotes global cellular protein synthesis repression in response to UV irradiation independently of the stress-activated protein kinase/c-Jun N-terminal kinase (SAPK/JNK) and p38 MAPK signaling pathways (By similarity). Plays a role in the antiviral response against alphavirus infection; impairs early viral mRNA translation of the incoming genomic virus RNA, thus preventing alphavirus replication (By similarity).', 'EIF2AK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Activation of host autophagy by virus, Activator, Adaptive immunity, Alternative splicing, Antiviral defense, ATP-binding, Cell cycle, Coiled coil, Cytoplasm, Disease variant, Growth arrest, Host-virus interaction, Immunity, Kinase, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, RNA-binding, Serine/threonine-protein kinase, Stress response, Transferase, Translation regulation, tRNA-binding');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (174, '7Z5W', '', 'Proto-oncogene tyrosine-protein kinase ROS', 'Receptor tyrosine kinase (RTK) that plays a role in epithelial cell differentiation and regionalization of the proximal epididymal epithelium. NELL2 is an endogenous ligand for ROS1. Upon endogenous stimulation by NELL2, ROS1 activates the intracellular signaling pathway and triggers epididymal epithelial differentiation and subsequent sperm maturation (By similarity). May activate several downstream signaling pathways related to cell differentiation, proliferation, growth and survival including the PI3 kinase-mTOR signaling pathway. Mediates the phosphorylation of PTPN11, an activator of this pathway. May also phosphorylate and activate the transcription factor STAT3 to control anchorage-independent cell growth. Mediates the phosphorylation and the activation of VAV3, a guanine nucleotide exchange factor regulating cell morphology. May activate other downstream signaling proteins including AKT1, MAPK1, MAPK3, IRS1 and PLCG2.', 'ROS1', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Chromosomal rearrangement, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (175, '1V0O', 'MEKYHGLEKIGEGTYGVVYKAQNNYGETFALKKIRLEKEDEGIPSTTIREISILKELKHSNIVKLYDVIHTKKRLVLVFEHLDQDLKKLLDVCEGGLESVTAKSFLLQLLNGIAYCHDRRVLHRDLKPQNLLINREGELKIADFGLARAFGIPVRKYTHEVVTLWYRAPDVLMGSKKYSTTIDIWSVGCIFAEMVNGTPLFPGVSEADQLMRIFRILGTPNSKNWPNVTELPKYDPNFTVYEPLPWESFLKGLDESGIDLLSKMLKLDPNQRITAKQALEHAYFKENN', 'Cyclin-dependent kinase 2 homolog', 'Serine/threonine-protein kinase (PubMed:8844681, PubMed:14604523). Involved in the control of the cell cycle (By similarity). Required for entry into S-phase and mitosis (By similarity). Probable component of the kinase complex that phosphorylates the repetitive C-terminus of RNA polymerase II (By similarity). In schizonts, phosphorylates ORC1 resulting in its dissociation from DNA, relocalization to the cytoplasm and likely its degradation (By similarity).', 'CRK2', 'Plasmodium falciparum (isolate K1 / Thailand)', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, ATP-binding, Cell cycle, Cell division, Cytoplasm, Kinase, Magnesium, Metal-binding, Mitosis, Nucleotide-binding, Phosphoprotein, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (176, '4AW2', '', 'Serine/threonine-protein kinase MRCK alpha', 'Serine/threonine-protein kinase which is an important downstream effector of CDC42 and plays a role in the regulation of cytoskeleton reorganization and cell migration (PubMed:9418861). Regulates actin cytoskeletal reorganization via phosphorylation of PPP1R12A and MYL9/MLC2 (PubMed:21457715). In concert with MYO18A and LURAP1, is involved in modulating lamellar actomyosin retrograde flow that is crucial to cell protrusion and migration (PubMed:18854160). Phosphorylates: PPP1R12C, LIMK1 and LIMK2. May play a role in TFRC-mediated iron uptake. In concert with FAM89B/LRAP25 mediates the targeting of LIMK1 to the lamellipodium resulting in its activation and subsequent phosphorylation of CFL1 which is important for lamellipodial F-actin regulation (By similarity). Triggers the formation of an extrusion apical actin ring required for epithelial extrusion of apoptotic cells (By similarity).', 'Cdc42bpa', 'Rattus norvegicus', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Coiled coil, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (177, '4PED', '', 'Atypical kinase COQ8A, mitochondrial', 'Atypical kinase involved in the biosynthesis of coenzyme Q, also named ubiquinone, an essential lipid-soluble electron transporter for aerobic cellular respiration (PubMed:25498144, PubMed:21296186, PubMed:25540914, PubMed:27499294). Its substrate specificity is unclear: does not show any protein kinase activity (PubMed:25498144, PubMed:27499294). Probably acts as a small molecule kinase, possibly a lipid kinase that phosphorylates a prenyl lipid in the ubiquinone biosynthesis pathway, as suggested by its ability to bind coenzyme Q lipid intermediates (PubMed:25498144, PubMed:27499294). Shows an unusual selectivity for binding ADP over ATP (PubMed:25498144).', 'COQ8A', 'Homo sapiens', '{[''2.7.-.-'']}', '3D-structure, Alternative splicing, ATP-binding, Direct protein sequencing, Disease variant, Kinase, Membrane, Mitochondrion, Neurodegeneration, Nucleotide-binding, Primary mitochondrial disease, Reference proteome, Transferase, Transit peptide, Transmembrane, Transmembrane helix, Ubiquinone biosynthesis');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (178, '7F3M', '', 'Fibroblast growth factor receptor 4', 'Tyrosine-protein kinase that acts as a cell-surface receptor for fibroblast growth factors and plays a role in the regulation of cell proliferation, differentiation and migration, and in regulation of lipid metabolism, bile acid biosynthesis, glucose uptake, vitamin D metabolism and phosphate homeostasis. Required for normal down-regulation of the expression of CYP7A1, the rate-limiting enzyme in bile acid synthesis, in response to FGF19. Phosphorylates PLCG1 and FRS2. Ligand binding leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate. Phosphorylation of FRS2 triggers recruitment of GRB2, GAB1, PIK3R1 and SOS1, and mediates activation of RAS, MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. Promotes SRC-dependent phosphorylation of the matrix protease MMP14 and its lysosomal degradation. FGFR4 signaling is down-regulated by receptor internalization and degradation; MMP14 promotes internalization and degradation of FGFR4. Mutations that lead to constitutive kinase activation or impair normal FGFR4 inactivation lead to aberrant signaling.', 'FGFR4', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Direct protein sequencing, Disulfide bond, Endoplasmic reticulum, Endosome, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (179, '7TYJ', '', 'Insulin receptor-related protein', 'Receptor with tyrosine-protein kinase activity. Functions as a pH sensing receptor which is activated by increased extracellular pH. Activates an intracellular signaling pathway that involves IRS1 and AKT1/PKB.', 'INSRR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cleavage on pair of basic residues, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (180, '8DFM', '', 'Mast/stem cell growth factor receptor Kit', 'Tyrosine-protein kinase that acts as a cell-surface receptor for the cytokine KITLG/SCF and plays an essential role in the regulation of cell survival and proliferation, hematopoiesis, stem cell maintenance, gametogenesis, mast cell development, migration and function, and in melanogenesis. In response to KITLG/SCF binding, KIT can activate several signaling pathways. Phosphorylates PIK3R1, PLCG1, SH2B2/APS and CBL. Activates the AKT1 signaling pathway by phosphorylation of PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase. Activated KIT also transmits signals via GRB2 and activation of RAS, RAF1 and the MAP kinases MAPK1/ERK2 and/or MAPK3/ERK1. Promotes activation of STAT family members STAT1, STAT3, STAT5A and STAT5B. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate. KIT signaling is modulated by protein phosphatases, and by rapid internalization and degradation of the receptor. Activated KIT promotes phosphorylation of the protein phosphatases PTPN6/SHP-1 and PTPRU, and of the transcription factors STAT1, STAT3, STAT5A and STAT5B. Promotes phosphorylation of PIK3R1, CBL, CRK (isoform Crk-II), LYN, MAPK1/ERK2 and/or MAPK3/ERK1, PLCG1, SRC and SHC1.', 'KIT', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Direct protein sequencing, Disease variant, Disulfide bond, Glycoprotein, Immunoglobulin domain, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (181, '7MN5', '', 'Receptor tyrosine-protein kinase erbB-3', 'Tyrosine-protein kinase that plays an essential role as cell surface receptor for neuregulins. Binds to neuregulin-1 (NRG1) and is activated by it; ligand-binding increases phosphorylation on tyrosine residues and promotes its association with the p85 subunit of phosphatidylinositol 3-kinase (PubMed:20682778). May also be activated by CSPG5 (PubMed:15358134). Involved in the regulation of myeloid cell differentiation (PubMed:27416908).', 'ERBB3', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (182, '8YGW', '', 'Mitogen-activated protein kinase 11', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway (PubMed:12452429, PubMed:20626350, PubMed:35857590). MAPK11 is one of the four p38 MAPKs which play an important role in the cascades of cellular responses evoked by extracellular stimuli such as pro-inflammatory cytokines or physical stress leading to direct activation of transcription factors (PubMed:12452429, PubMed:20626350, PubMed:35857590). Accordingly, p38 MAPKs phosphorylate a broad range of proteins and it has been estimated that they may have approximately 200 to 300 substrates each (PubMed:12452429, PubMed:20626350, PubMed:35857590). MAPK11 functions are mostly redundant with those of MAPK14 (PubMed:12452429, PubMed:20626350, PubMed:35857590). Some of the targets are downstream kinases which are activated through phosphorylation and further phosphorylate additional targets (PubMed:12452429, PubMed:20626350). RPS6KA5/MSK1 and RPS6KA4/MSK2 can directly phosphorylate and activate transcription factors such as CREB1, ATF1, the NF-kappa-B isoform RELA/NFKB3, STAT1 and STAT3, but can also phosphorylate histone H3 and the nucleosomal protein HMGN1 (PubMed:9687510). RPS6KA5/MSK1 and RPS6KA4/MSK2 play important roles in the rapid induction of immediate-early genes in response to stress or mitogenic stimuli, either by inducing chromatin remodeling or by recruiting the transcription machinery. On the other hand, two other kinase targets, MAPKAPK2/MK2 and MAPKAPK3/MK3, participate in the control of gene expression mostly at the post-transcriptional level, by phosphorylating ZFP36 (tristetraprolin) and ELAVL1, and by regulating EEF2K, which is important for the elongation of mRNA during translation. MKNK1/MNK1 and MKNK2/MNK2, two other kinases activated by p38 MAPKs, regulate protein synthesis by phosphorylating the initiation factor EIF4E2 (PubMed:11154262). In the cytoplasm, the p38 MAPK pathway is an important regulator of protein turnover. For example, CFLAR is an inhibitor of TNF-induced apoptosis whose proteasome-mediated degradation is regulated by p38 MAPK phosphorylation. Ectodomain shedding of transmembrane proteins is regulated by p38 MAPKs as well. In response to inflammatory stimuli, p38 MAPKs phosphorylate the membrane-associated metalloprotease ADAM17. Such phosphorylation is required for ADAM17-mediated ectodomain shedding of TGF-alpha family ligands, which results in the activation of EGFR signaling and cell proliferation. Additional examples of p38 MAPK substrates are the FGFR1. FGFR1 can be translocated from the extracellular space into the cytosol and nucleus of target cells, and regulates processes such as rRNA synthesis and cell growth. FGFR1 translocation requires p38 MAPK activation. In the nucleus, many transcription factors are phosphorylated and activated by p38 MAPKs in response to different stimuli. Classical examples include ATF1, ATF2, ATF6, ELK1, PTPRH, DDIT3, TP53/p53 and MEF2C and MEF2A (PubMed:9430721, PubMed:10330143, PubMed:15356147). The p38 MAPKs are emerging as important modulators of gene expression by regulating chromatin modifiers and remodelers (PubMed:9430721, PubMed:10330143, PubMed:15356147). The promoters of several genes involved in the inflammatory response, such as IL6, IL8 and IL12B, display a p38 MAPK-dependent enrichment of histone H3 phosphorylation on ''Ser-10'' (H3S10ph) in LPS-stimulated myeloid cells. This phosphorylation enhances the accessibility of the cryptic NF-kappa-B-binding sites marking promoters for increased NF-kappa-B recruitment. Phosphorylates NLRP1 downstream of MAP3K20/ZAK in response to UV-B irradiation and ribosome collisions, promoting activation of the NLRP1 inflammasome and pyroptosis (PubMed:35857590).', 'MAPK11', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (183, '4OLI', '', 'Non-receptor tyrosine-protein kinase TYK2', 'Tyrosine kinase of the non-receptor type involved in numerous cytokines and interferons signaling, which regulates cell growth, development, cell migration, innate and adaptive immunity (PubMed:8232552, PubMed:7813427, PubMed:7657660, PubMed:10995743, PubMed:10542297). Plays both structural and catalytic roles in numerous interleukins and interferons (IFN-alpha/beta) signaling (PubMed:10542297). Associates with heterodimeric cytokine receptor complexes and activates STAT family members including STAT1, STAT3, STAT4 or STAT6 (PubMed:10542297, PubMed:7638186). The heterodimeric cytokine receptor complexes are composed of (1) a TYK2-associated receptor chain (IFNAR1, IL12RB1, IL10RB or IL13RA1), and (2) a second receptor chain associated either with JAK1 or JAK2 (PubMed:7813427, PubMed:10542297, PubMed:7526154, PubMed:25762719). In response to cytokine-binding to receptors, phosphorylates and activates receptors (IFNAR1, IL12RB1, IL10RB or IL13RA1), creating docking sites for STAT members (PubMed:7526154, PubMed:7657660). In turn, recruited STATs are phosphorylated by TYK2 (or JAK1/JAK2 on the second receptor chain), form homo- and heterodimers, translocate to the nucleus, and regulate cytokine/growth factor responsive genes (PubMed:7657660, PubMed:10542297, PubMed:25762719). Negatively regulates STAT3 activity by promototing phosphorylation at a specific tyrosine that differs from the site used for signaling (PubMed:29162862).', 'TYK2', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SH2 domain, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (184, '4AAA', '', 'Cyclin-dependent kinase-like 2', 'Unknown', 'CDKL2', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (185, '4NIF', '', 'Ribosomal protein S6 kinase alpha-1', 'Serine/threonine-protein kinase that acts downstream of ERK (MAPK1/ERK2 and MAPK3/ERK1) signaling and mediates mitogenic and stress-induced activation of the transcription factors CREB1, ETV1/ER81 and NR4A1/NUR77, regulates translation through RPS6 and EIF4B phosphorylation, and mediates cellular proliferation, survival, and differentiation by modulating mTOR signaling and repressing pro-apoptotic function of BAD and DAPK1 (PubMed:10679322, PubMed:16223362, PubMed:15117958, PubMed:12213813, PubMed:9430688, PubMed:17360704, PubMed:26158630, PubMed:18722121, PubMed:35772404). In fibroblast, is required for EGF-stimulated phosphorylation of CREB1, which results in the subsequent transcriptional activation of several immediate-early genes (PubMed:18508509, PubMed:18813292). In response to mitogenic stimulation (EGF and PMA), phosphorylates and activates NR4A1/NUR77 and ETV1/ER81 transcription factors and the cofactor CREBBP (PubMed:12213813, PubMed:16223362). Upon insulin-derived signal, acts indirectly on the transcription regulation of several genes by phosphorylating GSK3B at ''Ser-9'' and inhibiting its activity (PubMed:18508509, PubMed:18813292). Phosphorylates RPS6 in response to serum or EGF via an mTOR-independent mechanism and promotes translation initiation by facilitating assembly of the pre-initiation complex (PubMed:17360704). In response to insulin, phosphorylates EIF4B, enhancing EIF4B affinity for the EIF3 complex and stimulating cap-dependent translation (PubMed:16763566). Is involved in the mTOR nutrient-sensing pathway by directly phosphorylating TSC2 at ''Ser-1798'', which potently inhibits TSC2 ability to suppress mTOR signaling, and mediates phosphorylation of RPTOR, which regulates mTORC1 activity and may promote rapamycin-sensitive signaling independently of the PI3K/AKT pathway (PubMed:15342917). Also involved in feedback regulation of mTORC1 and mTORC2 by phosphorylating DEPTOR (PubMed:22017876). Mediates cell survival by phosphorylating the pro-apoptotic proteins BAD and DAPK1 and suppressing their pro-apoptotic function (PubMed:10679322, PubMed:16213824). Promotes the survival of hepatic stellate cells by phosphorylating CEBPB in response to the hepatotoxin carbon tetrachloride (CCl4) (PubMed:11684016). Mediates induction of hepatocyte prolifration by TGFA through phosphorylation of CEBPB (PubMed:18508509, PubMed:18813292). Is involved in cell cycle regulation by phosphorylating the CDK inhibitor CDKN1B, which promotes CDKN1B association with 14-3-3 proteins and prevents its translocation to the nucleus and inhibition of G1 progression (PubMed:18508509, PubMed:18813292). Phosphorylates EPHA2 at ''Ser-897'', the RPS6KA-EPHA2 signaling pathway controls cell migration (PubMed:26158630). In response to mTORC1 activation, phosphorylates EIF4B at ''Ser-406'' and ''Ser-422'' which stimulates bicarbonate cotransporter SLC4A7 mRNA translation, increasing SLC4A7 protein abundance and function (PubMed:35772404).', 'RPS6KA1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cytoplasm, Host-virus interaction, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Stress response, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (186, '6P5S', '', 'Homeodomain-interacting protein kinase 2', 'Serine/threonine-protein kinase involved in transcription regulation, p53/TP53-mediated cellular apoptosis and regulation of the cell cycle. Acts as a corepressor of several transcription factors, including SMAD1 and POU4F1/Brn3a and probably NK homeodomain transcription factors. Phosphorylates PDX1, ATF1, PML, p53/TP53, CREB1, CTBP1, CBX4, RUNX1, EP300, CTNNB1, HMGA1, ZBTB4 and DAZAP2. Inhibits cell growth and promotes apoptosis through the activation of p53/TP53 both at the transcription level and at the protein level (by phosphorylation and indirect acetylation). The phosphorylation of p53/TP53 may be mediated by a p53/TP53-HIPK2-AXIN1 complex. Involved in the response to hypoxia by acting as a transcriptional co-suppressor of HIF1A. Mediates transcriptional activation of TP73. In response to TGFB, cooperates with DAXX to activate JNK. Negative regulator through phosphorylation and subsequent proteasomal degradation of CTNNB1 and the antiapoptotic factor CTBP1. In the Wnt/beta-catenin signaling pathway acts as an intermediate kinase between MAP3K7/TAK1 and NLK to promote the proteasomal degradation of MYB. Phosphorylates CBX4 upon DNA damage and promotes its E3 SUMO-protein ligase activity. Activates CREB1 and ATF1 transcription factors by phosphorylation in response to genotoxic stress. In response to DNA damage, stabilizes PML by phosphorylation. PML, HIPK2 and FBXO3 may act synergically to activate p53/TP53-dependent transactivation. Promotes angiogenesis, and is involved in erythroid differentiation, especially during fetal liver erythropoiesis. Phosphorylation of RUNX1 and EP300 stimulates EP300 transcription regulation activity. Triggers ZBTB4 protein degradation in response to DNA damage. In response to DNA damage, phosphorylates DAZAP2 which localizes DAZAP2 to the nucleus, reduces interaction of DAZAP2 with HIPK2 and prevents DAZAP2-dependent ubiquitination of HIPK2 by E3 ubiquitin-protein ligase SIAH1 and subsequent proteasomal degradation (PubMed:33591310). Modulates HMGA1 DNA-binding affinity. In response to high glucose, triggers phosphorylation-mediated subnuclear localization shifting of PDX1. Involved in the regulation of eye size, lens formation and retinal lamination during late embryogenesis.', 'HIPK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, DNA damage, Host-virus interaction, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (187, '7SYD', '', 'Epidermal growth factor receptor', 'Receptor tyrosine kinase binding ligands of the EGF family and activating several signaling cascades to convert extracellular cues into appropriate cellular responses (PubMed:2790960, PubMed:10805725, PubMed:27153536). Known ligands include EGF, TGFA/TGF-alpha, AREG, epigen/EPGN, BTC/betacellulin, epiregulin/EREG and HBEGF/heparin-binding EGF (PubMed:2790960, PubMed:7679104, PubMed:8144591, PubMed:9419975, PubMed:15611079, PubMed:12297049, PubMed:27153536, PubMed:20837704, PubMed:17909029). Ligand binding triggers receptor homo- and/or heterodimerization and autophosphorylation on key cytoplasmic residues. The phosphorylated receptor recruits adapter proteins like GRB2 which in turn activates complex downstream signaling cascades. Activates at least 4 major downstream signaling cascades including the RAS-RAF-MEK-ERK, PI3 kinase-AKT, PLCgamma-PKC and STATs modules (PubMed:27153536). May also activate the NF-kappa-B signaling cascade (PubMed:11116146). Also directly phosphorylates other proteins like RGS16, activating its GTPase activity and probably coupling the EGF receptor signaling to the G protein-coupled receptor signaling (PubMed:11602604). Also phosphorylates MUC1 and increases its interaction with SRC and CTNNB1/beta-catenin (PubMed:11483589). Positively regulates cell migration via interaction with CCDC88A/GIV which retains EGFR at the cell membrane following ligand stimulation, promoting EGFR signaling which triggers cell migration (PubMed:20462955). Plays a role in enhancing learning and memory performance (By similarity). Plays a role in mammalian pain signaling (long-lasting hypersensitivity) (By similarity).', 'EGFR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Developmental protein, Direct protein sequencing, Disease variant, Disulfide bond, Endoplasmic reticulum, Endosome, Glycoprotein, Golgi apparatus, Host cell receptor for virus entry, Host-virus interaction, Hydroxylation, Isopeptide bond, Kinase, Lipoprotein, Membrane, Methylation, Nucleotide-binding, Nucleus, Palmitate, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (188, '8TZB', '', 'Leucine-rich repeat serine/threonine-protein kinase 2', 'Serine/threonine-protein kinase which phosphorylates a broad range of proteins involved in multiple processes such as neuronal plasticity, innate immunity, autophagy, and vesicle trafficking (PubMed:20949042, PubMed:22012985, PubMed:26824392, PubMed:27830463, PubMed:29125462, PubMed:28720718, PubMed:29127255, PubMed:30398148, PubMed:29212815, PubMed:30635421, PubMed:21850687, PubMed:23395371, PubMed:17114044, PubMed:24687852, PubMed:26014385, PubMed:25201882). Is a key regulator of RAB GTPases by regulating the GTP/GDP exchange and interaction partners of RABs through phosphorylation (PubMed:26824392, PubMed:28720718, PubMed:29127255, PubMed:30398148, PubMed:29212815, PubMed:29125462, PubMed:30635421). Phosphorylates RAB3A, RAB3B, RAB3C, RAB3D, RAB5A, RAB5B, RAB5C, RAB8A, RAB8B, RAB10, RAB12, RAB35, and RAB43 (PubMed:26824392, PubMed:28720718, PubMed:29127255, PubMed:30398148, PubMed:29212815, PubMed:29125462, PubMed:30635421, PubMed:23395371). Regulates the RAB3IP-catalyzed GDP/GTP exchange for RAB8A through the phosphorylation of ''Thr-72'' on RAB8A (PubMed:26824392). Inhibits the interaction between RAB8A and GDI1 and/or GDI2 by phosphorylating ''Thr-72'' on RAB8A (PubMed:26824392). Regulates primary ciliogenesis through phosphorylation of RAB8A and RAB10, which promotes SHH signaling in the brain (PubMed:29125462, PubMed:30398148). Together with RAB29, plays a role in the retrograde trafficking pathway for recycling proteins, such as mannose-6-phosphate receptor (M6PR), between lysosomes and the Golgi apparatus in a retromer-dependent manner (PubMed:23395371). Regulates neuronal process morphology in the intact central nervous system (CNS) (PubMed:17114044). Plays a role in synaptic vesicle trafficking (PubMed:24687852). Plays an important role in recruiting SEC16A to endoplasmic reticulum exit sites (ERES) and in regulating ER to Golgi vesicle-mediated transport and ERES organization (PubMed:25201882). Positively regulates autophagy through a calcium-dependent activation of the CaMKK/AMPK signaling pathway (PubMed:22012985). The process involves activation of nicotinic acid adenine dinucleotide phosphate (NAADP) receptors, increase in lysosomal pH, and calcium release from lysosomes (PubMed:22012985). Phosphorylates PRDX3 (PubMed:21850687). By phosphorylating APP on ''Thr-743'', which promotes the production and the nuclear translocation of the APP intracellular domain (AICD), regulates dopaminergic neuron apoptosis (PubMed:28720718). Acts as a positive regulator of innate immunity by mediating phosphorylation of RIPK2 downstream of NOD1 and NOD2, thereby enhancing RIPK2 activation (PubMed:27830463). Independent of its kinase activity, inhibits the proteasomal degradation of MAPT, thus promoting MAPT oligomerization and secretion (PubMed:26014385). In addition, has GTPase activity via its Roc domain which regulates LRRK2 kinase activity (PubMed:18230735, PubMed:26824392, PubMed:29125462, PubMed:28720718, PubMed:29212815).', 'LRRK2', 'Homo sapiens', '{[''3.6.5.-'',''2.7.11.1'']}', '3D-structure, ATP-binding, Autophagy, Cell projection, Coiled coil, Cytoplasm, Cytoplasmic vesicle, Cytoskeleton, Differentiation, Disease variant, Endoplasmic reticulum, Endosome, Golgi apparatus, GTP-binding, GTPase activation, Hydrolase, Kinase, Leucine-rich repeat, Lysosome, Membrane, Mitochondrion, Mitochondrion outer membrane, Neurodegeneration, Nucleotide-binding, Parkinson disease, Parkinsonism, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Synapse, Transferase, Ubl conjugation, WD repeat');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (204, '6BRJ', '', 'Epithelial discoidin domain-containing receptor 1', 'Tyrosine kinase that functions as a cell surface receptor for fibrillar collagen and regulates cell attachment to the extracellular matrix, remodeling of the extracellular matrix, cell migration, differentiation, survival and cell proliferation. Collagen binding triggers a signaling pathway that involves SRC and leads to the activation of MAP kinases. Regulates remodeling of the extracellular matrix by up-regulation of the matrix metalloproteinases MMP2, MMP7 and MMP9, and thereby facilitates cell migration and wound healing. Required for normal blastocyst implantation during pregnancy, for normal mammary gland differentiation and normal lactation. Required for normal ear morphology and normal hearing (By similarity). Promotes smooth muscle cell migration, and thereby contributes to arterial wound healing. Also plays a role in tumor cell invasion. Phosphorylates PTPN11.', 'DDR1', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Calcium, Cell membrane, Direct protein sequencing, Disulfide bond, Glycoprotein, Kinase, Lactation, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Pregnancy, Receptor, Reference proteome, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (189, '2X10', '', 'Ephrin type-A receptor 2', 'Receptor tyrosine kinase which binds promiscuously membrane-bound ephrin-A family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Activated by the ligand ephrin-A1/EFNA1 regulates migration, integrin-mediated adhesion, proliferation and differentiation of cells. Regulates cell adhesion and differentiation through DSG1/desmoglein-1 and inhibition of the ERK1/ERK2 (MAPK3/MAPK1, respectively) signaling pathway. May also participate in UV radiation-induced apoptosis and have a ligand-independent stimulatory effect on chemotactic cell migration. During development, may function in distinctive aspects of pattern formation and subsequently in development of several fetal tissues. Involved for instance in angiogenesis, in early hindbrain development and epithelial proliferation and branching morphogenesis during mammary gland development. Engaged by the ligand ephrin-A5/EFNA5 may regulate lens fiber cells shape and interactions and be important for lens transparency development and maintenance. With ephrin-A2/EFNA2 may play a role in bone remodeling through regulation of osteoclastogenesis and osteoblastogenesis.', 'EPHA2', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, Apoptosis, ATP-binding, Cataract, Cell adhesion, Cell junction, Cell membrane, Cell projection, Differentiation, Disease variant, Disulfide bond, Glycoprotein, Host cell receptor for virus entry, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (190, '3BKB', '', 'Tyrosine-protein kinase Fes/Fps', 'Tyrosine-protein kinase that acts downstream of cell surface receptors and plays a role in the regulation of the actin cytoskeleton, microtubule assembly, cell attachment and cell spreading. Plays a role in FCER1 (high affinity immunoglobulin epsilon receptor)-mediated signaling in mast cells. Acts down-stream of the activated FCER1 receptor and the mast/stem cell growth factor receptor KIT. Plays a role in the regulation of mast cell degranulation. Plays a role in the regulation of cell differentiation and promotes neurite outgrowth in response to NGF signaling. Plays a role in cell scattering and cell migration in response to HGF-induced activation of EZR. Phosphorylates BCR and down-regulates BCR kinase activity. Phosphorylates HCLS1/HS1, PECAM1, STAT3 and TRIM28.', 'FES', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative splicing, ATP-binding, Cell junction, Cell membrane, Coiled coil, Cytoplasm, Cytoplasmic vesicle, Cytoskeleton, Golgi apparatus, Kinase, Lipid-binding, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, Transferase, Tumor suppressor, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (191, '4PNI', '', 'Rhodopsin kinase GRK1', 'Retina-specific kinase involved in the signal turnoff via phosphorylation of rhodopsin (RHO), the G protein- coupled receptor that initiates the phototransduction cascade (PubMed:12686556, PubMed:16675451, PubMed:21299498). This rapid desensitization is essential for scotopic vision and permits rapid adaptation to changes in illumination (By similarity). May play a role in the maintenance of the outer nuclear layer in the retina (By similarity).', 'GRK1', 'Bos taurus', '{[''2.7.11.14'']}', '3D-structure, ATP-binding, Cell projection, Direct protein sequencing, Kinase, Lipoprotein, Membrane, Methylation, Nucleotide-binding, Phosphoprotein, Prenylation, Reference proteome, Sensory transduction, Serine/threonine-protein kinase, Transferase, Vision');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (192, '2ESM', '', 'Rho-associated protein kinase 1', 'Protein kinase which is a key regulator of the actin cytoskeleton and cell polarity (PubMed:10436159, PubMed:10652353, PubMed:11018042, PubMed:11283607, PubMed:17158456, PubMed:18573880, PubMed:19131646, PubMed:8617235, PubMed:9722579). Involved in regulation of smooth muscle contraction, actin cytoskeleton organization, stress fiber and focal adhesion formation, neurite retraction, cell adhesion and motility via phosphorylation of DAPK3, GFAP, LIMK1, LIMK2, MYL9/MLC2, TPPP, PFN1 and PPP1R12A (PubMed:10436159, PubMed:10652353, PubMed:11018042, PubMed:11283607, PubMed:17158456, PubMed:18573880, PubMed:19131646, PubMed:8617235, PubMed:9722579, PubMed:23093407, PubMed:23355470). Phosphorylates FHOD1 and acts synergistically with it to promote SRC-dependent non-apoptotic plasma membrane blebbing (PubMed:18694941). Phosphorylates JIP3 and regulates the recruitment of JNK to JIP3 upon UVB-induced stress (PubMed:19036714). Acts as a suppressor of inflammatory cell migration by regulating PTEN phosphorylation and stability (By similarity). Acts as a negative regulator of VEGF-induced angiogenic endothelial cell activation (PubMed:19181962). Required for centrosome positioning and centrosome-dependent exit from mitosis (By similarity). Plays a role in terminal erythroid differentiation (PubMed:21072057). Inhibits podocyte motility via regulation of actin cytoskeletal dynamics and phosphorylation of CFL1 (By similarity). Promotes keratinocyte terminal differentiation (PubMed:19997641). Involved in osteoblast compaction through the fibronectin fibrillogenesis cell-mediated matrix assembly process, essential for osteoblast mineralization (By similarity). May regulate closure of the eyelids and ventral body wall by inducing the assembly of actomyosin bundles (By similarity).', 'ROCK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Apoptosis, ATP-binding, Cell membrane, Cell projection, Coiled coil, Cytoplasm, Cytoskeleton, Direct protein sequencing, Golgi apparatus, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (198, '4AGC', '', 'Vascular endothelial growth factor receptor 2', 'Tyrosine-protein kinase that acts as a cell-surface receptor for VEGFA, VEGFC and VEGFD. Plays an essential role in the regulation of angiogenesis, vascular development, vascular permeability, and embryonic hematopoiesis. Promotes proliferation, survival, migration and differentiation of endothelial cells. Promotes reorganization of the actin cytoskeleton. Isoforms lacking a transmembrane domain, such as isoform 2 and isoform 3, may function as decoy receptors for VEGFA, VEGFC and/or VEGFD. Isoform 2 plays an important role as negative regulator of VEGFA- and VEGFC-mediated lymphangiogenesis by limiting the amount of free VEGFA and/or VEGFC and preventing their binding to FLT4. Modulates FLT1 and FLT4 signaling by forming heterodimers. Binding of vascular growth factors to isoform 1 leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate and the activation of protein kinase C. Mediates activation of MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. Mediates phosphorylation of PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase, reorganization of the actin cytoskeleton and activation of PTK2/FAK1. Required for VEGFA-mediated induction of NOS2 and NOS3, leading to the production of the signaling molecule nitric oxide (NO) by endothelial cells. Phosphorylates PLCG1. Promotes phosphorylation of FYN, NCK1, NOS3, PIK3R1, PTK2/FAK1 and SRC.', 'KDR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Cytoplasmic vesicle, Developmental protein, Differentiation, Disulfide bond, Endoplasmic reticulum, Endosome, Glycoprotein, Host-virus interaction, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (193, '6V6Q', '', 'Fibroblast growth factor receptor 2', 'Tyrosine-protein kinase that acts as a cell-surface receptor for fibroblast growth factors and plays an essential role in the regulation of cell proliferation, differentiation, migration and apoptosis, and in the regulation of embryonic development. Required for normal embryonic patterning, trophoblast function, limb bud development, lung morphogenesis, osteogenesis and skin development. Plays an essential role in the regulation of osteoblast differentiation, proliferation and apoptosis, and is required for normal skeleton development. Promotes cell proliferation in keratinocytes and immature osteoblasts, but promotes apoptosis in differentiated osteoblasts. Phosphorylates PLCG1, FRS2 and PAK4. Ligand binding leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate. Phosphorylation of FRS2 triggers recruitment of GRB2, GAB1, PIK3R1 and SOS1, and mediates activation of RAS, MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. FGFR2 signaling is down-regulated by ubiquitination, internalization and degradation. Mutations that lead to constitutive kinase activation or impair normal FGFR2 maturation, internalization and degradation lead to aberrant signaling. Over-expressed FGFR2 promotes activation of STAT1.', 'FGFR2', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell membrane, Craniosynostosis, Cytoplasmic vesicle, Disease variant, Disulfide bond, Ectodermal dysplasia, Glycoprotein, Golgi apparatus, Heparin-binding, Immunoglobulin domain, Intellectual disability, Kinase, Lacrimo-auriculo-dento-digital syndrome, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (194, '6C9D', '', 'Serine/threonine-protein kinase MARK1', 'Serine/threonine-protein kinase (PubMed:23666762). Involved in cell polarity and microtubule dynamics regulation. Phosphorylates DCX, MAP2 and MAP4. Phosphorylates the microtubule-associated protein MAPT/TAU (PubMed:23666762). Involved in cell polarity by phosphorylating the microtubule-associated proteins MAP2, MAP4 and MAPT/TAU at KXGS motifs, causing detachment from microtubules, and their disassembly. Involved in the regulation of neuronal migration through its dual activities in regulating cellular polarity and microtubule dynamics, possibly by phosphorylating and regulating DCX. Also acts as a positive regulator of the Wnt signaling pathway, probably by mediating phosphorylation of dishevelled proteins (DVL1, DVL2 and/or DVL3).', 'MARK1', 'Homo sapiens', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Autism, Autism spectrum disorder, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Kinase, Lipid-binding, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (195, '2ROV', '', 'Rho-associated protein kinase 2', 'Protein kinase which is a key regulator of actin cytoskeleton and cell polarity. Involved in regulation of smooth muscle contraction, actin cytoskeleton organization, stress fiber and focal adhesion formation, neurite retraction, cell adhesion and motility via phosphorylation of ADD1, BRCA2, CNN1, EZR, DPYSL2, EP300, MSN, MYL9/MLC2, NPM1, RDX, PPP1R12A and VIM. Phosphorylates SORL1 and IRF4. Acts as a negative regulator of VEGF-induced angiogenic endothelial cell activation. Positively regulates the activation of p42/MAPK1-p44/MAPK3 and of p90RSK/RPS6KA1 during myogenic differentiation. Plays an important role in the timely initiation of centrosome duplication. Inhibits keratinocyte terminal differentiation. May regulate closure of the eyelids and ventral body wall through organization of actomyosin bundles. Plays a critical role in the regulation of spine and synaptic properties in the hippocampus. Plays a role in placental homeostasis during the perinatal period. Plays an important role in generating the circadian rhythm of the aortic myofilament Ca(2+) sensitivity and vascular contractility by modulating the myosin light chain phosphorylation.', 'Rock2', 'Rattus norvegicus', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Biological rhythms, Cell membrane, Coiled coil, Cytoplasm, Cytoskeleton, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (196, '4L46', '', 'Ribosomal protein S6 kinase beta-1', 'Serine/threonine-protein kinase that acts downstream of mTOR signaling in response to growth factors and nutrients to promote cell proliferation, cell growth and cell cycle progression (PubMed:11500364, PubMed:12801526, PubMed:14673156, PubMed:15071500, PubMed:15341740, PubMed:16286006, PubMed:17052453, PubMed:17053147, PubMed:17936702, PubMed:18952604, PubMed:19085255, PubMed:19720745, PubMed:19935711, PubMed:19995915, PubMed:23429703, PubMed:28178239, PubMed:22017876). Regulates protein synthesis through phosphorylation of EIF4B, RPS6 and EEF2K, and contributes to cell survival by repressing the pro-apoptotic function of BAD (PubMed:11500364, PubMed:12801526, PubMed:14673156, PubMed:15071500, PubMed:15341740, PubMed:16286006, PubMed:17052453, PubMed:17053147, PubMed:17936702, PubMed:18952604, PubMed:19085255, PubMed:19720745, PubMed:19935711, PubMed:19995915, PubMed:23429703, PubMed:28178239, PubMed:22017876). Under conditions of nutrient depletion, the inactive form associates with the EIF3 translation initiation complex (PubMed:16286006). Upon mitogenic stimulation, phosphorylation by the mechanistic target of rapamycin complex 1 (mTORC1) leads to dissociation from the EIF3 complex and activation (PubMed:16286006). The active form then phosphorylates and activates several substrates in the pre-initiation complex, including the EIF2B complex and the cap-binding complex component EIF4B (PubMed:16286006). Also controls translation initiation by phosphorylating a negative regulator of EIF4A, PDCD4, targeting it for ubiquitination and subsequent proteolysis (PubMed:17053147). Promotes initiation of the pioneer round of protein synthesis by phosphorylating POLDIP3/SKAR (PubMed:15341740). In response to IGF1, activates translation elongation by phosphorylating EEF2 kinase (EEF2K), which leads to its inhibition and thus activation of EEF2 (PubMed:11500364). Also plays a role in feedback regulation of mTORC2 by mTORC1 by phosphorylating RICTOR, resulting in the inhibition of mTORC2 and AKT1 signaling (PubMed:19720745, PubMed:19935711, PubMed:19995915). Also involved in feedback regulation of mTORC1 and mTORC2 by phosphorylating DEPTOR (PubMed:22017876). Mediates cell survival by phosphorylating the pro-apoptotic protein BAD and suppressing its pro-apoptotic function (By similarity). Phosphorylates mitochondrial URI1 leading to dissociation of a URI1-PPP1CC complex (PubMed:17936702). The free mitochondrial PPP1CC can then dephosphorylate RPS6KB1 at Thr-412, which is proposed to be a negative feedback mechanism for the RPS6KB1 anti-apoptotic function (PubMed:17936702). Mediates TNF-alpha-induced insulin resistance by phosphorylating IRS1 at multiple serine residues, resulting in accelerated degradation of IRS1 (PubMed:18952604). In cells lacking functional TSC1-2 complex, constitutively phosphorylates and inhibits GSK3B (PubMed:17052453). May be involved in cytoskeletal rearrangement through binding to neurabin (By similarity). Phosphorylates and activates the pyrimidine biosynthesis enzyme CAD, downstream of MTOR (PubMed:23429703). Following activation by mTORC1, phosphorylates EPRS and thereby plays a key role in fatty acid uptake by adipocytes and also most probably in interferon-gamma-induced translation inhibition (PubMed:28178239).', 'RPS6KB1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative initiation, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Kinase, Membrane, Mitochondrion, Mitochondrion outer membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Synapse, Synaptosome, Transferase, Translation regulation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (197, '3Q5I', '', 'Calcium-dependent protein kinase 1', 'Calcium-dependent protein kinase which acts as a sensor and effector of intracellular Ca(2+) levels probably in part downstream of cGMP-activated PKG kinase (By similarity). During the liver stage, involved in sporozoite motility and thus in sporozoite invasion of host hepatocytes, probably together with CDPK4 and CDPK5 (PubMed:32866196). In the mosquito midgut and during the last stage of male gamete exflagellation, may play a role in the rupture of the host erythrocyte membrane (PubMed:22817984). In the mosquito midgut, required for the differentiation of the zygote into the ookinete by promoting the translational activation of a subset of repressed mRNAs; these mRNAs are kept repressed in the zygote by the DOZI- or CITH-containing mRNP complexes (PubMed:22817984, PubMed:24265753). Dispensable during the asexual blood stage (PubMed:24265753).', 'CDPK1', 'Plasmodium berghei (strain Anka)', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Calcium, Cell membrane, Cell projection, Cilium, Cytoplasm, Flagellum, Host cell membrane, Host membrane, Kinase, Lipoprotein, Magnesium, Membrane, Metal-binding, Myristate, Nucleotide-binding, Palmitate, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (199, '8EEC', '', 'Mitogen-activated protein kinase kinase kinase kinase 1', 'Serine/threonine-protein kinase, which may play a role in the response to environmental stress (PubMed:24362026). Appears to act upstream of the JUN N-terminal pathway (PubMed:8824585). May play a role in hematopoietic lineage decisions and growth regulation (PubMed:8824585, PubMed:24362026). Able to autophosphorylate (PubMed:8824585). Together with CLNK, it enhances CD3-triggered activation of T-cells and subsequent IL2 production (By similarity).', 'MAP4K1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (200, '8R4O', '', 'Serine/threonine-protein kinase SIK3', 'Positive regulator of mTOR signaling that functions by triggering the degradation of DEPTOR, an mTOR inhibitor. Involved in the dynamic regulation of mTOR signaling in chondrocyte differentiation during skeletogenesis (PubMed:30232230). Negatively regulates cAMP signaling pathway possibly by acting on CRTC2/TORC2 and CRTC3/TORC3 (Probable). Prevents HDAC4 translocation to the nucleus (By similarity).', 'SIK3', 'Homo sapiens', '{[''2.7.11.1'']}', 'Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Dwarfism, Kinase, Magnesium, Metal-binding, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (201, '4CRS', '', 'Serine/threonine-protein kinase N2', 'PKC-related serine/threonine-protein kinase and Rho/Rac effector protein that participates in specific signal transduction responses in the cell. Plays a role in the regulation of cell cycle progression, actin cytoskeleton assembly, cell migration, cell adhesion, tumor cell invasion and transcription activation signaling processes. Phosphorylates CTTN in hyaluronan-induced astrocytes and hence decreases CTTN ability to associate with filamentous actin. Phosphorylates HDAC5, therefore lead to impair HDAC5 import. Direct RhoA target required for the regulation of the maturation of primordial junctions into apical junction formation in bronchial epithelial cells. Required for G2/M phases of the cell cycle progression and abscission during cytokinesis in a ECT2-dependent manner. Stimulates FYN kinase activity that is required for establishment of skin cell-cell adhesion during keratinocytes differentiation. Regulates epithelial bladder cells speed and direction of movement during cell migration and tumor cell invasion. Inhibits Akt pro-survival-induced kinase activity. Mediates Rho protein-induced transcriptional activation via the c-fos serum response factor (SRF). Involved in the negative regulation of ciliogenesis (PubMed:27104747).', 'PKN2', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cell adhesion, Cell cycle, Cell division, Cell junction, Cell projection, Cilium biogenesis/degradation, Coiled coil, Cytoplasm, Cytoskeleton, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (202, '4EYJ', '', 'Mitogen-activated protein kinase 13', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. MAPK13 is one of the four p38 MAPKs which play an important role in the cascades of cellular responses evoked by extracellular stimuli such as pro-inflammatory cytokines or physical stress leading to direct activation of transcription factors such as ELK1 and ATF2. Accordingly, p38 MAPKs phosphorylate a broad range of proteins and it has been estimated that they may have approximately 200 to 300 substrates each. MAPK13 is one of the less studied p38 MAPK isoforms. Some of the targets are downstream kinases such as MAPKAPK2, which are activated through phosphorylation and further phosphorylate additional targets. Plays a role in the regulation of protein translation by phosphorylating and inactivating EEF2K. Involved in cytoskeletal remodeling through phosphorylation of MAPT and STMN1. Mediates UV irradiation induced up-regulation of the gene expression of CXCL14. Plays an important role in the regulation of epidermal keratinocyte differentiation, apoptosis and skin tumor development. Phosphorylates the transcriptional activator MYB in response to stress which leads to rapid MYB degradation via a proteasome-dependent pathway. MAPK13 also phosphorylates and down-regulates PRKD1 during regulation of insulin secretion in pancreatic beta cells.', 'MAPK13', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (203, '2ZOQ', '', 'Mitogen-activated protein kinase 3', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway (PubMed:34497368). MAPK1/ERK2 and MAPK3/ERK1 are the 2 MAPKs which play an important role in the MAPK/ERK cascade. They participate also in a signaling cascade initiated by activated KIT and KITLG/SCF. Depending on the cellular context, the MAPK/ERK cascade mediates diverse biological functions such as cell growth, adhesion, survival and differentiation through the regulation of transcription, translation, cytoskeletal rearrangements. The MAPK/ERK cascade also plays a role in initiation and regulation of meiosis, mitosis, and postmitotic functions in differentiated cells by phosphorylating a number of transcription factors. About 160 substrates have already been discovered for ERKs. Many of these substrates are localized in the nucleus, and seem to participate in the regulation of transcription upon stimulation. However, other substrates are found in the cytosol as well as in other cellular organelles, and those are responsible for processes such as translation, mitosis and apoptosis. Moreover, the MAPK/ERK cascade is also involved in the regulation of the endosomal dynamics, including lysosome processing and endosome cycling through the perinuclear recycling compartment (PNRC); as well as in the fragmentation of the Golgi apparatus during mitosis. The substrates include transcription factors (such as ATF2, BCL6, ELK1, ERF, FOS, HSF4 or SPZ1), cytoskeletal elements (such as CANX, CTTN, GJA1, MAP2, MAPT, PXN, SORBS3 or STMN1), regulators of apoptosis (such as BAD, BTG2, CASP9, DAPK1, IER3, MCL1 or PPARG), regulators of translation (such as EIF4EBP1) and a variety of other signaling-related molecules (like ARHGEF2, DEPTOR, FRS2 or GRB10) (PubMed:35216969). Protein kinases (such as RAF1, RPS6KA1/RSK1, RPS6KA3/RSK2, RPS6KA2/RSK3, RPS6KA6/RSK4, SYK, MKNK1/MNK1, MKNK2/MNK2, RPS6KA5/MSK1, RPS6KA4/MSK2, MAPKAPK3 or MAPKAPK5) and phosphatases (such as DUSP1, DUSP4, DUSP6 or DUSP16) are other substrates which enable the propagation the MAPK/ERK signal to additional cytosolic and nuclear targets, thereby extending the specificity of the cascade.', 'MAPK3', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell junction, Cytoplasm, Direct protein sequencing, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (206, '4I5M', '', 'Serine/threonine-protein kinase PLK2', 'Tumor suppressor serine/threonine-protein kinase involved in synaptic plasticity, centriole duplication and G1/S phase transition. Polo-like kinases act by binding and phosphorylating proteins that are already phosphorylated on a specific motif recognized by the POLO box domains. Phosphorylates CENPJ, NPM1, RAPGEF2, RASGRF1, SNCA, SIPA1L1 and SYNGAP1. Plays a key role in synaptic plasticity and memory by regulating the Ras and Rap protein signaling: required for overactivity-dependent spine remodeling by phosphorylating the Ras activator RASGRF1 and the Rap inhibitor SIPA1L1 leading to their degradation by the proteasome. Conversely, phosphorylates the Rap activator RAPGEF2 and the Ras inhibitor SYNGAP1, promoting their activity. Also regulates synaptic plasticity independently of kinase activity, via its interaction with NSF that disrupts the interaction between NSF and the GRIA2 subunit of AMPARs, leading to a rapid rundown of AMPAR-mediated current that occludes long term depression. Required for procentriole formation and centriole duplication by phosphorylating CENPJ and NPM1, respectively. Its induction by p53/TP53 suggests that it may participate in the mitotic checkpoint following stress.', 'PLK2', 'Homo sapiens', '{[''2.7.11.21'']}', '3D-structure, ATP-binding, Cell projection, Cytoplasm, Cytoskeleton, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Tumor suppressor');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (207, '1VZO', '', 'Ribosomal protein S6 kinase alpha-5', 'Serine/threonine-protein kinase that is required for the mitogen or stress-induced phosphorylation of the transcription factors CREB1 and ATF1 and for the regulation of the transcription factors RELA, STAT3 and ETV1/ER81, and that contributes to gene activation by histone phosphorylation and functions in the regulation of inflammatory genes (PubMed:11909979, PubMed:12569367, PubMed:12763138, PubMed:9687510, PubMed:18511904, PubMed:9873047). Phosphorylates CREB1 and ATF1 in response to mitogenic or stress stimuli such as UV-C irradiation, epidermal growth factor (EGF) and anisomycin (PubMed:11909979, PubMed:9873047). Plays an essential role in the control of RELA transcriptional activity in response to TNF and upon glucocorticoid, associates in the cytoplasm with the glucocorticoid receptor NR3C1 and contributes to RELA inhibition and repression of inflammatory gene expression (PubMed:12628924, PubMed:18511904). In skeletal myoblasts is required for phosphorylation of RELA at ''Ser-276'' during oxidative stress (PubMed:12628924). In erythropoietin-stimulated cells, is necessary for the ''Ser-727'' phosphorylation of STAT3 and regulation of its transcriptional potential (PubMed:12763138). Phosphorylates ETV1/ER81 at ''Ser-191'' and ''Ser-216'', and thereby regulates its ability to stimulate transcription, which may be important during development and breast tumor formation (PubMed:12569367). Directly represses transcription via phosphorylation of ''Ser-1'' of histone H2A (PubMed:15010469). Phosphorylates ''Ser-10'' of histone H3 in response to mitogenics, stress stimuli and EGF, which results in the transcriptional activation of several immediate early genes, including proto-oncogenes c-fos/FOS and c-jun/JUN (PubMed:12773393). May also phosphorylate ''Ser-28'' of histone H3 (PubMed:12773393). Mediates the mitogen- and stress-induced phosphorylation of high mobility group protein 1 (HMGN1/HMG14) (PubMed:12773393). In lipopolysaccharide-stimulated primary macrophages, acts downstream of the Toll-like receptor TLR4 to limit the production of pro-inflammatory cytokines (By similarity). Functions probably by inducing transcription of the MAP kinase phosphatase DUSP1 and the anti-inflammatory cytokine interleukin 10 (IL10), via CREB1 and ATF1 transcription factors (By similarity). Plays a role in neuronal cell death by mediating the downstream effects of excitotoxic injury (By similarity). Phosphorylates TRIM7 at ''Ser-107'' in response to growth factor signaling via the MEK/ERK pathway, thereby stimulating its ubiquitin ligase activity (PubMed:25851810).', 'RPS6KA5', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Inflammatory response, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Stress response, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (208, '7XQK', '', 'Glutathione S-transferase class-mu 26 kDa isozyme', 'Conjugation of reduced glutathione to a wide number of exogenous and endogenous hydrophobic electrophiles.', 'NaN', 'Schistosoma japonicum', '{[''2.5.1.18'']}', '3D-structure, Direct protein sequencing, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (209, '4BGQ', '', 'Cyclin-dependent kinase-like 5', 'Mediates phosphorylation of MECP2 (PubMed:15917271, PubMed:16935860). May regulate ciliogenesis (PubMed:29420175).', 'CDKL5', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Chromosomal rearrangement, Cytoplasm, Cytoskeleton, Disease variant, Epilepsy, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (210, '2VD5', '', 'Myotonin-protein kinase', 'Non-receptor serine/threonine protein kinase which is necessary for the maintenance of skeletal muscle structure and function. May play a role in myocyte differentiation and survival by regulating the integrity of the nuclear envelope and the expression of muscle-specific genes. May also phosphorylate PPP1R12A and inhibit the myosin phosphatase activity to regulate myosin phosphorylation. Also critical to the modulation of cardiac contractility and to the maintenance of proper cardiac conduction activity probably through the regulation of cellular calcium homeostasis. Phosphorylates PLN, a regulator of calcium pumps and may regulate sarcoplasmic reticulum calcium uptake in myocytes. May also phosphorylate FXYD1/PLM which is able to induce chloride currents. May also play a role in synaptic plasticity.', 'DMPK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cataract, Cell membrane, Coiled coil, Cytoplasm, Endoplasmic reticulum, Kinase, Magnesium, Membrane, Metal-binding, Mitochondrion, Mitochondrion outer membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Sarcoplasmic reticulum, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (212, '3Q52', '', 'Serine/threonine-protein kinase PAK 1', 'Protein kinase involved in intracellular signaling pathways downstream of integrins and receptor-type kinases that plays an important role in cytoskeleton dynamics, in cell adhesion, migration, proliferation, apoptosis, mitosis, and in vesicle-mediated transport processes (PubMed:10551809, PubMed:11896197, PubMed:12876277, PubMed:14585966, PubMed:15611088, PubMed:17726028, PubMed:17989089, PubMed:30290153). Can directly phosphorylate BAD and protects cells against apoptosis (By similarity). Activated by interaction with CDC42 and RAC1 (PubMed:8805275, PubMed:9528787). Functions as a GTPase effector that links the Rho-related GTPases CDC42 and RAC1 to the JNK MAP kinase pathway (PubMed:8805275, PubMed:9528787). Phosphorylates and activates MAP2K1, and thereby mediates activation of downstream MAP kinases (By similarity). Involved in the reorganization of the actin cytoskeleton, actin stress fibers and of focal adhesion complexes (PubMed:9395435, PubMed:9032240). Phosphorylates the tubulin chaperone TBCB and thereby plays a role in the regulation of microtubule biogenesis and organization of the tubulin cytoskeleton (PubMed:15831477). Plays a role in the regulation of insulin secretion in response to elevated glucose levels (PubMed:22669945). Part of a ternary complex that contains PAK1, DVL1 and MUSK that is important for MUSK-dependent regulation of AChR clustering during the formation of the neuromuscular junction (NMJ) (By similarity). Activity is inhibited in cells undergoing apoptosis, potentially due to binding of CDC2L1 and CDC2L2 (PubMed:12624090). Phosphorylates MYL9/MLC2 (By similarity). Phosphorylates RAF1 at ''Ser-338'' and ''Ser-339'' resulting in: activation of RAF1, stimulation of RAF1 translocation to mitochondria, phosphorylation of BAD by RAF1, and RAF1 binding to BCL2 (PubMed:11733498). Phosphorylates SNAI1 at ''Ser-246'' promoting its transcriptional repressor activity by increasing its accumulation in the nucleus (PubMed:15833848). In podocytes, promotes NR3C2 nuclear localization (By similarity). Required for atypical chemokine receptor ACKR2-induced phosphorylation of LIMK1 and cofilin (CFL1) and for the up-regulation of ACKR2 from endosomal compartment to cell membrane, increasing its efficiency in chemokine uptake and degradation (PubMed:23633677). In synapses, seems to mediate the regulation of F-actin cluster formation performed by SHANK3, maybe through CFL1 phosphorylation and inactivation (By similarity). Plays a role in RUFY3-mediated facilitating gastric cancer cells migration and invasion (PubMed:25766321). In response to DNA damage, phosphorylates MORC2 which activates its ATPase activity and facilitates chromatin remodeling (PubMed:23260667). In neurons, plays a crucial role in regulating GABA(A) receptor synaptic stability and hence GABAergic inhibitory synaptic transmission through its role in F-actin stabilization (By similarity). In hippocampal neurons, necessary for the formation of dendritic spines and excitatory synapses; this function is dependent on kinase activity and may be exerted by the regulation of actomyosin contractility through the phosphorylation of myosin II regulatory light chain (MLC) (By similarity). Along with GIT1, positively regulates microtubule nucleation during interphase (PubMed:27012601). Phosphorylates FXR1, promoting its localization to stress granules and activity (PubMed:20417602).', 'PAK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Allosteric enzyme, Alternative splicing, Apoptosis, ATP-binding, Cell junction, Cell membrane, Cell projection, Chromosome, Cytoplasm, Cytoskeleton, Disease variant, Epilepsy, Exocytosis, Intellectual disability, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (213, '2Y3A', '', 'Phosphatidylinositol 4,5-bisphosphate 3-kinase catalytic subunit beta isoform', 'Phosphoinositide-3-kinase (PI3K) phosphorylates phosphatidylinositol (PI) derivatives at position 3 of the inositol ring to produce 3-phosphoinositides. Uses ATP and PtdIns(4,5)P2 (phosphatidylinositol 4,5-bisphosphate) to generate phosphatidylinositol 3,4,5-trisphosphate (PIP3) (By similarity). PIP3 plays a key role by recruiting PH domain-containing proteins to the membrane, including AKT1 and PDPK1, activating signaling cascades involved in cell growth, survival, proliferation, motility and morphology. Involved in the activation of AKT1 upon stimulation by G-protein coupled receptors (GPCRs) ligands such as CXCL12, sphingosine 1-phosphate, and lysophosphatidic acid. May also act downstream receptor tyrosine kinases. Required in different signaling pathways for stable platelet adhesion and aggregation. Plays a role in platelet activation signaling triggered by GPCRs, alpha-IIb/beta-3 integrins (ITGA2B/ ITGB3) and ITAM (immunoreceptor tyrosine-based activation motif)-bearing receptors such as GP6. Regulates the strength of adhesion of ITGA2B/ ITGB3 activated receptors necessary for the cellular transmission of contractile forces. Required for platelet aggregation induced by F2 (thrombin) and thromboxane A2 (TXA2). Has a role in cell survival. May have a role in cell migration. Involved in the early stage of autophagosome formation. Modulates the intracellular level of PtdIns3P (phosphatidylinositol 3-phosphate) and activates PIK3C3 kinase activity. May act as a scaffold, independently of its lipid kinase activity to positively regulate autophagy. May have a role in insulin signaling as scaffolding protein in which the lipid kinase activity is not required. May have a kinase-independent function in regulating cell proliferation and in clathrin-mediated endocytosis. Mediator of oncogenic signal in cell lines lacking PTEN. The lipid kinase activity is necessary for its role in oncogenic transformation. Required for the growth of ERBB2 and RAS driven tumors. Has also a protein kinase activity showing autophosphorylation.', 'Pik3cb', 'Mus musculus', '{[''2.7.1.153'',''2.7.11.1'']}', '3D-structure, ATP-binding, Autophagy, Cell adhesion, Cytoplasm, Endocytosis, Kinase, Lipid metabolism, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (214, '3TAC', '', 'Peripheral plasma membrane protein CASK', 'Multidomain scaffolding Mg(2+)-independent protein kinase that catalyzes the phosphotransfer from ATP to proteins such as NRXN1, and plays a role in synaptic transmembrane protein anchoring and ion channel trafficking (PubMed:18423203). Contributes to neural development and regulation of gene expression via interaction with the transcription factor TBR1. Binds to cell-surface proteins, including amyloid precursor protein, neurexins and syndecans. May mediate a link between the extracellular matrix and the actin cytoskeleton via its interaction with syndecan and with the actin/spectrin-binding protein 4.1. Component of the LIN-10-LIN-2-LIN-7 complex, which associates with the motor protein KIF17 to transport vesicles containing N-methyl-D-aspartate (NMDA) receptor subunit NR2B along microtubules (By similarity).', 'CASK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Calmodulin-binding, Cell membrane, Cytoplasm, Disease variant, Intellectual disability, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, SH3 domain, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (215, '5D7V', '', 'Protein-tyrosine kinase 6', 'Non-receptor tyrosine-protein kinase implicated in the regulation of a variety of signaling pathways that control the differentiation and maintenance of normal epithelia, as well as tumor growth. Function seems to be context dependent and differ depending on cell type, as well as its intracellular localization. A number of potential nuclear and cytoplasmic substrates have been identified. These include the RNA-binding proteins: KHDRBS1/SAM68, KHDRBS2/SLM1, KHDRBS3/SLM2 and SFPQ/PSF; transcription factors: STAT3 and STAT5A/B and a variety of signaling molecules: ARHGAP35/p190RhoGAP, PXN/paxillin, BTK/ATK, STAP2/BKS. Associates also with a variety of proteins that are likely upstream of PTK6 in various signaling pathways, or for which PTK6 may play an adapter-like role. These proteins include ADAM15, EGFR, ERBB2, ERBB3 and IRS4. In normal or non-tumorigenic tissues, PTK6 promotes cellular differentiation and apoptosis. In tumors PTK6 contributes to cancer progression by sensitizing cells to mitogenic signals and enhancing proliferation, anchorage-independent survival and migration/invasion. Association with EGFR, ERBB2, ERBB3 may contribute to mammary tumor development and growth through enhancement of EGF-induced signaling via BTK/AKT and PI3 kinase. Contributes to migration and proliferation by contributing to EGF-mediated phosphorylation of ARHGAP35/p190RhoGAP, which promotes association with RASA1/p120RasGAP, inactivating RhoA while activating RAS. EGF stimulation resulted in phosphorylation of PNX/Paxillin by PTK6 and activation of RAC1 via CRK/CrKII, thereby promoting migration and invasion. PTK6 activates STAT3 and STAT5B to promote proliferation. Nuclear PTK6 may be important for regulating growth in normal epithelia, while cytoplasmic PTK6 might activate oncogenic signaling pathways.', 'PTK6', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Cytoplasm, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (216, '2VWI', '', 'Serine/threonine-protein kinase OSR1', 'Effector serine/threonine-protein kinase component of the WNK-SPAK/OSR1 kinase cascade, which is involved in various processes, such as ion transport, response to hypertonic stress and blood pressure (PubMed:16669787, PubMed:18270262, PubMed:21321328, PubMed:34289367). Specifically recognizes and binds proteins with a RFXV motif (PubMed:16669787, PubMed:21321328, PubMed:17721439). Acts downstream of WNK kinases (WNK1, WNK2, WNK3 or WNK4): following activation by WNK kinases, catalyzes phosphorylation of ion cotransporters, such as SLC12A1/NKCC2, SLC12A2/NKCC1, SLC12A3/NCC, SLC12A5/KCC2 or SLC12A6/KCC3, regulating their activity (PubMed:17721439). Mediates regulatory volume increase in response to hyperosmotic stress by catalyzing phosphorylation of ion cotransporters SLC12A1/NKCC2, SLC12A2/NKCC1 and SLC12A6/KCC3 downstream of WNK1 and WNK3 kinases (PubMed:16669787, PubMed:21321328). Phosphorylation of Na-K-Cl cotransporters SLC12A2/NKCC1 and SLC12A2/NKCC1 promote their activation and ion influx; simultaneously, phosphorylation of K-Cl cotransporters SLC12A5/KCC2 and SLC12A6/KCC3 inhibit their activity, blocking ion efflux (PubMed:16669787, PubMed:19665974, PubMed:21321328). Acts as a regulator of NaCl reabsorption in the distal nephron by mediating phosphorylation and activation of the thiazide-sensitive Na-Cl cotransporter SLC12A3/NCC in distal convoluted tubule cells of kidney downstream of WNK4 (PubMed:18270262). Also acts as a regulator of angiogenesis in endothelial cells downstream of WNK1 (PubMed:23386621, PubMed:25362046). Acts as an activator of inward rectifier potassium channels KCNJ2/Kir2.1 and KCNJ4/Kir2.3 downstream of WNK1: recognizes and binds the RXFXV/I variant motif on KCNJ2/Kir2.1 and KCNJ4/Kir2.3 and regulates their localization to the cell membrane without mediating their phosphorylation (PubMed:29581290). Phosphorylates RELL1, RELL2 and RELT (PubMed:16389068, PubMed:28688764). Phosphorylates PAK1 (PubMed:14707132). Phosphorylates PLSCR1 in the presence of RELT (PubMed:22052202).', 'OXSR1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (217, '6QAT', '', 'Serine/threonine-protein kinase ULK2', 'Serine/threonine-protein kinase involved in autophagy in response to starvation. Acts upstream of phosphatidylinositol 3-kinase PIK3C3 to regulate the formation of autophagophores, the precursors of autophagosomes. Part of regulatory feedback loops in autophagy: acts both as a downstream effector and a negative regulator of mammalian target of rapamycin complex 1 (mTORC1) via interaction with RPTOR. Activated via phosphorylation by AMPK, also acts as a negative regulator of AMPK through phosphorylation of the AMPK subunits PRKAA1, PRKAB2 and PRKAG1. May phosphorylate ATG13/KIAA0652, FRS2, FRS3 and RPTOR; however such data need additional evidences. Not involved in ammonia-induced autophagy or in autophagic response of cerebellar granule neurons (CGN) to low potassium concentration. Plays a role early in neuronal differentiation and is required for granule cell axon formation: may govern axon formation via Ras-like GTPase signaling and through regulation of the Rab5-mediated endocytic pathways within developing axons.', 'ULK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Autophagy, Cytoplasmic vesicle, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (218, '2REI', '', 'Ephrin type-A receptor 7', 'Receptor tyrosine kinase which binds promiscuously GPI-anchored ephrin-A family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Among GPI-anchored ephrin-A ligands, EFNA5 is a cognate/functional ligand for EPHA7 and their interaction regulates brain development modulating cell-cell adhesion and repulsion. Has a repellent activity on axons and is for instance involved in the guidance of corticothalamic axons and in the proper topographic mapping of retinal axons to the colliculus. May also regulate brain development through a caspase(CASP3)-dependent proapoptotic activity. Forward signaling may result in activation of components of the ERK signaling pathway including MAP2K1, MAP2K2, MAPK1 and MAPK3 which are phosphorylated upon activation of EPHA7.', 'EPHA7', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell membrane, Developmental protein, Glycoprotein, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (219, '2NPT', '', 'Dual specificity mitogen-activated protein kinase kinase 5', 'Acts as a scaffold for the formation of a ternary MAP3K2/MAP3K3-MAP3K5-MAPK7 signaling complex. Activation of this pathway appears to play a critical role in protecting cells from stress-induced apoptosis, neuronal survival and cardiac development and angiogenesis. As part of the MAPK/ERK signaling pathway, acts as a negative regulator of apoptosis in cardiomyocytes via promotion of STUB1/CHIP-mediated ubiquitination and degradation of ICER-type isoforms of CREM (By similarity).', 'MAP2K5', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (220, '4EKU', '', 'Protein-tyrosine kinase 2-beta', 'Non-receptor protein-tyrosine kinase that regulates reorganization of the actin cytoskeleton, cell polarization, cell migration, adhesion, spreading and bone remodeling. Plays a role in the regulation of the humoral immune response, and is required for normal levels of marginal B-cells in the spleen and normal migration of splenic B-cells. Required for normal macrophage polarization and migration towards sites of inflammation. Regulates cytoskeleton rearrangement and cell spreading in T-cells, and contributes to the regulation of T-cell responses. Promotes osteoclastic bone resorption; this requires both PTK2B/PYK2 and SRC. May inhibit differentiation and activity of osteoprogenitor cells. Functions in signaling downstream of integrin and collagen receptors, immune receptors, G-protein coupled receptors (GPCR), cytokine, chemokine and growth factor receptors, and mediates responses to cellular stress. Forms multisubunit signaling complexes with SRC and SRC family members upon activation; this leads to the phosphorylation of additional tyrosine residues, creating binding sites for scaffold proteins, effectors and substrates. Regulates numerous signaling pathways. Promotes activation of phosphatidylinositol 3-kinase and of the AKT1 signaling cascade. Promotes activation of NOS3. Regulates production of the cellular messenger cGMP. Promotes activation of the MAP kinase signaling cascade, including activation of MAPK1/ERK2, MAPK3/ERK1 and MAPK8/JNK1. Promotes activation of Rho family GTPases, such as RHOA and RAC1. Recruits the ubiquitin ligase MDM2 to P53/TP53 in the nucleus, and thereby regulates P53/TP53 activity, P53/TP53 ubiquitination and proteasomal degradation. Acts as a scaffold, binding to both PDPK1 and SRC, thereby allowing SRC to phosphorylate PDPK1 at ''Tyr-9, ''Tyr-373'', and ''Tyr-376''. Promotes phosphorylation of NMDA receptors by SRC family members, and thereby contributes to the regulation of NMDA receptor ion channel activity and intracellular Ca(2+) levels. May also regulate potassium ion transport by phosphorylation of potassium channel subunits. Phosphorylates SRC; this increases SRC kinase activity. Phosphorylates ASAP1, NPHP1, KCNA2 and SHC1. Promotes phosphorylation of ASAP2, RHOU and PXN; this requires both SRC and PTK2/PYK2.', 'PTK2B', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Adaptive immunity, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cell projection, Cytoplasm, Immunity, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (221, '7NX3', '', 'ALK tyrosine kinase receptor', 'Neuronal receptor tyrosine kinase that is essentially and transiently expressed in specific regions of the central and peripheral nervous systems and plays an important role in the genesis and differentiation of the nervous system (PubMed:11121404, PubMed:11387242, PubMed:16317043, PubMed:17274988, PubMed:30061385, PubMed:34646012, PubMed:34819673). Also acts as a key thinness protein involved in the resistance to weight gain: in hypothalamic neurons, controls energy expenditure acting as a negative regulator of white adipose tissue lipolysis and sympathetic tone to fine-tune energy homeostasis (By similarity). Following activation by ALKAL2 ligand at the cell surface, transduces an extracellular signal into an intracellular response (PubMed:30061385, PubMed:33411331, PubMed:34646012, PubMed:34819673). In contrast, ALKAL1 is not a potent physiological ligand for ALK (PubMed:34646012). Ligand-binding to the extracellular domain induces tyrosine kinase activation, leading to activation of the mitogen-activated protein kinase (MAPK) pathway (PubMed:34819673). Phosphorylates almost exclusively at the first tyrosine of the Y-x-x-x-Y-Y motif (PubMed:15226403, PubMed:16878150). Induces tyrosine phosphorylation of CBL, FRS2, IRS1 and SHC1, as well as of the MAP kinases MAPK1/ERK2 and MAPK3/ERK1 (PubMed:15226403, PubMed:16878150). ALK activation may also be regulated by pleiotrophin (PTN) and midkine (MDK) (PubMed:11278720, PubMed:11809760, PubMed:12107166, PubMed:12122009). PTN-binding induces MAPK pathway activation, which is important for the anti-apoptotic signaling of PTN and regulation of cell proliferation (PubMed:11278720, PubMed:11809760, PubMed:12107166). MDK-binding induces phosphorylation of the ALK target insulin receptor substrate (IRS1), activates mitogen-activated protein kinases (MAPKs) and PI3-kinase, resulting also in cell proliferation induction (PubMed:12122009). Drives NF-kappa-B activation, probably through IRS1 and the activation of the AKT serine/threonine kinase (PubMed:15226403, PubMed:16878150). Recruitment of IRS1 to activated ALK and the activation of NF-kappa-B are essential for the autocrine growth and survival signaling of MDK (PubMed:15226403, PubMed:16878150).', 'ALK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Chromosomal rearrangement, Disease variant, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (222, '1CTP', '', 'cAMP-dependent protein kinase catalytic subunit alpha', 'Phosphorylates a large number of substrates in the cytoplasm and the nucleus (By similarity). Phosphorylates CDC25B, ABL1, NFKB1, CLDN3, PSMC5/RPT6, PJA2, RYR2, RORA, SOX9 and VASP (By similarity). Regulates the abundance of compartmentalized pools of its regulatory subunits through phosphorylation of PJA2 which binds and ubiquitinates these subunits, leading to their subsequent proteolysis. RORA is activated by phosphorylation. Required for glucose-mediated adipogenic differentiation increase and osteogenic differentiation inhibition from osteoblasts (By similarity). Involved in chondrogenesis by mediating phosphorylation of SOX9 (By similarity). Involved in the regulation of platelets in response to thrombin and collagen; maintains circulating platelets in a resting state by phosphorylating proteins in numerous platelet inhibitory pathways when in complex with NF-kappa-B (NFKB1 and NFKB2) and I-kappa-B-alpha (NFKBIA), but thrombin and collagen disrupt these complexes and free active PRKACA stimulates platelets and leads to platelet aggregation by phosphorylating VASP. RYR2 channel activity is potentiated by phosphorylation in presence of luminal Ca(2+), leading to reduced amplitude and increased frequency of store overload-induced Ca(2+) release (SOICR) characterized by an increased rate of Ca(2+) release and propagation velocity of spontaneous Ca(2+) waves, despite reduced wave amplitude and resting cytosolic Ca(2+). PSMC5/RPT6 activation by phosphorylation stimulates proteasome. Negatively regulates tight junctions (TJs) in ovarian cancer cells via CLDN3 phosphorylation. NFKB1 phosphorylation promotes NF-kappa-B p50-p50 DNA binding. Required for phosphorylation of GLI transcription factors which inhibits them and prevents transcriptional activation of Hedgehog signaling pathway target genes (By similarity). GLI transcription factor phosphorylation is inhibited by interaction of PRKACA with SMO which sequesters PRKACA at the cell membrane (By similarity). Involved in embryonic development by down-regulating the Hedgehog (Hh) signaling pathway that determines embryo pattern formation and morphogenesis most probably through the regulation of OFD1 in ciliogenesis (By similarity). Prevents meiosis resumption in prophase-arrested oocytes via CDC25B inactivation by phosphorylation (By similarity). May also regulate rapid eye movement (REM) sleep in the pedunculopontine tegmental (PPT) (By similarity). Phosphorylates APOBEC3G and AICDA. Phosphorylates HSF1; this phosphorylation promotes HSF1 nuclear localization and transcriptional activity upon heat shock (By similarity). Acts as a negative regulator of mTORC1 by mediating phosphorylation of RPTOR (By similarity).', 'PRKACA', 'Sus scrofa', '{[''2.7.11.11'']}', '3D-structure, ATP-binding, cAMP, Cell membrane, Cytoplasm, Direct protein sequencing, Kinase, Lipoprotein, Membrane, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (223, '3TXO', '', 'Protein kinase C eta type', 'Calcium-independent, phospholipid- and diacylglycerol (DAG)-dependent serine/threonine-protein kinase that is involved in the regulation of cell differentiation in keratinocytes and pre-B cell receptor, mediates regulation of epithelial tight junction integrity and foam cell formation, and is required for glioblastoma proliferation and apoptosis prevention in MCF-7 cells. In keratinocytes, binds and activates the tyrosine kinase FYN, which in turn blocks epidermal growth factor receptor (EGFR) signaling and leads to keratinocyte growth arrest and differentiation. Associates with the cyclin CCNE1-CDK2-CDKN1B complex and inhibits CDK2 kinase activity, leading to RB1 dephosphorylation and thereby G1 arrest in keratinocytes. In association with RALA activates actin depolymerization, which is necessary for keratinocyte differentiation. In the pre-B cell receptor signaling, functions downstream of BLNK by up-regulating IRF4, which in turn activates L chain gene rearrangement. Regulates epithelial tight junctions (TJs) by phosphorylating occludin (OCLN) on threonine residues, which is necessary for the assembly and maintenance of TJs. In association with PLD2 and via TLR4 signaling, is involved in lipopolysaccharide (LPS)-induced RGS2 down-regulation and foam cell formation. Upon PMA stimulation, mediates glioblastoma cell proliferation by activating the mTOR pathway, the PI3K/AKT pathway and the ERK1-dependent phosphorylation of ELK1. Involved in the protection of glioblastoma cells from irradiation-induced apoptosis by preventing caspase-9 activation. In camptothecin-treated MCF-7 cells, regulates NF-kappa-B upstream signaling by activating IKBKB, and confers protection against DNA damage-induced apoptosis. Promotes oncogenic functions of ATF2 in the nucleus while blocking its apoptotic function at mitochondria. Phosphorylates ATF2 which promotes its nuclear retention and transcriptional activity and negatively regulates its mitochondrial localization.', 'PRKCH', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Differentiation, Kinase, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (224, '7MEZ', '', 'Phosphatidylinositol 4,5-bisphosphate 3-kinase catalytic subunit gamma isoform', 'Phosphoinositide-3-kinase (PI3K) that phosphorylates PtdIns(4,5)P2 (Phosphatidylinositol 4,5-bisphosphate) to generate phosphatidylinositol 3,4,5-trisphosphate (PIP3). PIP3 plays a key role by recruiting PH domain-containing proteins to the membrane, including AKT1 and PDPK1, activating signaling cascades involved in cell growth, survival, proliferation, motility and morphology. Links G-protein coupled receptor activation to PIP3 production. Involved in immune, inflammatory and allergic responses. Modulates leukocyte chemotaxis to inflammatory sites and in response to chemoattractant agents. May control leukocyte polarization and migration by regulating the spatial accumulation of PIP3 and by regulating the organization of F-actin formation and integrin-based adhesion at the leading edge. Controls motility of dendritic cells. Together with PIK3CD is involved in natural killer (NK) cell development and migration towards the sites of inflammation. Participates in T-lymphocyte migration. Regulates T-lymphocyte proliferation, activation, and cytokine production. Together with PIK3CD participates in T-lymphocyte development. Required for B-lymphocyte development and signaling. Together with PIK3CD participates in neutrophil respiratory burst. Together with PIK3CD is involved in neutrophil chemotaxis and extravasation. Together with PIK3CB promotes platelet aggregation and thrombosis. Regulates alpha-IIb/beta-3 integrins (ITGA2B/ ITGB3) adhesive function in platelets downstream of P2Y12 through a lipid kinase activity-independent mechanism. May have also a lipid kinase activity-dependent function in platelet aggregation. Involved in endothelial progenitor cell migration. Negative regulator of cardiac contractility. Modulates cardiac contractility by anchoring protein kinase A (PKA) and PDE3B activation, reducing cAMP levels. Regulates cardiac contractility also by promoting beta-adrenergic receptor internalization by binding to GRK2 and by non-muscle tropomyosin phosphorylation. Also has serine/threonine protein kinase activity: both lipid and protein kinase activities are required for beta-adrenergic receptor endocytosis. May also have a scaffolding role in modulating cardiac contractility. Contributes to cardiac hypertrophy under pathological stress. Through simultaneous binding of PDE3B to RAPGEF3 and PIK3R6 is assembled in a signaling complex in which the PI3K gamma complex is activated by RAPGEF3 and which is involved in angiogenesis.', 'PIK3CG', 'Homo sapiens', '{[''2.7.1.153'',''2.7.11.1'',''2.7.1.137'',''2.7.1.154'']}', '3D-structure, Angiogenesis, ATP-binding, Cell membrane, Chemotaxis, Cytoplasm, Disease variant, Endocytosis, Immunity, Inflammatory response, Kinase, Lipid metabolism, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (225, '4UY9', '', 'Mitogen-activated protein kinase kinase kinase 9', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. Plays an important role in the cascades of cellular responses evoked by changes in the environment. Once activated, acts as an upstream activator of the MKK/JNK signal transduction cascade through the phosphorylation of MAP2K4/MKK4 and MAP2K7/MKK7 which in turn activate the JNKs. The MKK/JNK signaling pathway regulates stress response via activator protein-1 (JUN) and GATA4 transcription factors. Also plays a role in mitochondrial death signaling pathway, including the release cytochrome c, leading to apoptosis.', 'MAP3K9', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, SH3 domain, Stress response, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (226, '6W4O', '', 'Calcium/calmodulin-dependent protein kinase type II subunit alpha', 'Calcium/calmodulin-dependent protein kinase that functions autonomously after Ca(2+)/calmodulin-binding and autophosphorylation, and is involved in various processes, such as synaptic plasticity, neurotransmitter release and long-term potentiation (PubMed:14722083). Member of the NMDAR signaling complex in excitatory synapses, it regulates NMDAR-dependent potentiation of the AMPAR and therefore excitatory synaptic transmission (By similarity). Regulates dendritic spine development (PubMed:28130356). Also regulates the migration of developing neurons (PubMed:29100089). Phosphorylates the transcription factor FOXO3 to activate its transcriptional activity (PubMed:23805378). Phosphorylates the transcription factor ETS1 in response to calcium signaling, thereby decreasing ETS1 affinity for DNA (By similarity). In response to interferon-gamma (IFN-gamma) stimulation, catalyzes phosphorylation of STAT1, stimulating the JAK-STAT signaling pathway (PubMed:11972023). In response to interferon-beta (IFN-beta) stimulation, stimulates the JAK-STAT signaling pathway (PubMed:35568036). Acts as a negative regulator of 2-arachidonoylglycerol (2-AG)-mediated synaptic signaling via modulation of DAGLA activity (By similarity).', 'CAMK2A', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Alternative splicing, ATP-binding, Calmodulin-binding, Cell projection, Disease variant, Intellectual disability, Kinase, Lipoprotein, Magnesium, Metal-binding, Nucleotide-binding, Palmitate, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Synapse, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (227, '2Y7J', '', 'Phosphorylase b kinase gamma catalytic chain, liver/testis isoform', 'Catalytic subunit of the phosphorylase b kinase (PHK), which mediates the neural and hormonal regulation of glycogen breakdown (glycogenolysis) by phosphorylating and thereby activating glycogen phosphorylase. May regulate glycogeneolysis in the testis. In vitro, phosphorylates PYGM (By similarity).', 'PHKG2', 'Homo sapiens', '{[''2.7.11.19'']}', '3D-structure, Alternative splicing, ATP-binding, Calmodulin-binding, Carbohydrate metabolism, Disease variant, Glycogen metabolism, Glycogen storage disease, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (228, '3MY0', '', 'Serine/threonine-protein kinase receptor R3', 'Type I receptor for TGF-beta family ligands BMP9/GDF2 and BMP10 and important regulator of normal blood vessel development. On ligand binding, forms a receptor complex consisting of two type II and two type I transmembrane serine/threonine kinases. Type II receptors phosphorylate and activate type I receptors which autophosphorylate, then bind and activate SMAD transcriptional regulators. May bind activin as well.', 'ACVRL1', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Angiogenesis, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (229, '8GMB', '', 'Tyrosine-protein kinase BTK', 'Non-receptor tyrosine kinase indispensable for B lymphocyte development, differentiation and signaling (PubMed:7538439, PubMed:8629002, PubMed:10852954). Binding of antigen to the B-cell antigen receptor (BCR) triggers signaling that ultimately leads to B-cell activation (By similarity). After BCR engagement and activation at the plasma membrane, phosphorylates PLCG2 at several sites, igniting the downstream signaling pathway through calcium mobilization, followed by activation of the protein kinase C (PKC) family members (By similarity). PLCG2 phosphorylation is performed in close cooperation with the adapter protein B-cell linker protein BLNK (By similarity). BTK acts as a platform to bring together a diverse array of signaling proteins and is implicated in cytokine receptor signaling pathways (By similarity). Plays an important role in the function of immune cells of innate as well as adaptive immunity, as a component of the Toll-like receptors (TLR) pathway (PubMed:17725607). The TLR pathway acts as a primary surveillance system for the detection of pathogens and are crucial to the activation of host defense (By similarity). Especially, is a critical molecule in regulating TLR9 activation in splenic B-cells (By similarity). Within the TLR pathway, induces tyrosine phosphorylation of TIRAP which leads to TIRAP degradation (By similarity). BTK also plays a critical role in transcription regulation (By similarity). Induces the activity of NF-kappa-B, which is involved in regulating the expression of hundreds of genes (By similarity). BTK is involved on the signaling pathway linking TLR8 and TLR9 to NF-kappa-B (By similarity). Acts as an activator of NLRP3 inflammasome assembly by mediating phosphorylation of NLRP3 (PubMed:34554188). Transiently phosphorylates transcription factor GTF2I on tyrosine residues in response to BCR (PubMed:11120822, PubMed:16738337). GTF2I then translocates to the nucleus to bind regulatory enhancer elements to modulate gene expression (PubMed:11120822, PubMed:16738337). ARID3A and NFAT are other transcriptional target of BTK (PubMed:11120822, PubMed:16738337). BTK is required for the formation of functional ARID3A DNA-binding complexes (PubMed:11120822, PubMed:16738337). There is however no evidence that BTK itself binds directly to DNA (PubMed:11120822, PubMed:16738337). BTK has a dual role in the regulation of apoptosis (By similarity).', 'Btk', 'Mus musculus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Adaptive immunity, Apoptosis, ATP-binding, Cell membrane, Cytoplasm, Direct protein sequencing, Disease variant, Immunity, Innate immunity, Kinase, Lipid-binding, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, SH2 domain, SH3 domain, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (230, '5E8V', '', 'TGF-beta receptor type-2', 'Transmembrane serine/threonine kinase forming with the TGF-beta type I serine/threonine kinase receptor, TGFBR1, the non-promiscuous receptor for the TGF-beta cytokines TGFB1, TGFB2 and TGFB3. Transduces the TGFB1, TGFB2 and TGFB3 signal from the cell surface to the cytoplasm and thus regulates a plethora of physiological and pathological processes including cell cycle arrest in epithelial and hematopoietic cells, control of mesenchymal cell proliferation and differentiation, wound healing, extracellular matrix production, immunosuppression and carcinogenesis. The formation of the receptor complex composed of 2 TGFBR1 and 2 TGFBR2 molecules symmetrically bound to the cytokine dimer results in the phosphorylation and activation of TGFBR1 by the constitutively active TGFBR2. Activated TGFBR1 phosphorylates SMAD2 which dissociates from the receptor and interacts with SMAD4. The SMAD2-SMAD4 complex is subsequently translocated to the nucleus where it modulates the transcription of the TGF-beta-regulated genes. This constitutes the canonical SMAD-dependent TGF-beta signaling cascade. Also involved in non-canonical, SMAD-independent TGF-beta signaling pathways.', 'TGFBR2', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, Aortic aneurysm, Apoptosis, ATP-binding, Cell membrane, Craniosynostosis, Differentiation, Direct protein sequencing, Disease variant, Disulfide bond, Glycoprotein, Growth regulation, Hereditary nonpolyposis colorectal cancer, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Secreted, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (231, '3COK', '', 'Serine/threonine-protein kinase PLK4', 'Serine/threonine-protein kinase that plays a central role in centriole duplication. Able to trigger procentriole formation on the surface of the parental centriole cylinder, leading to the recruitment of centriole biogenesis proteins such as SASS6, CENPJ/CPAP, CCP110, CEP135 and gamma-tubulin. When overexpressed, it is able to induce centrosome amplification through the simultaneous generation of multiple procentrioles adjoining each parental centriole during S phase. Phosphorylates ''Ser-151'' of FBXW5 during the G1/S transition, leading to inhibit FBXW5 ability to ubiquitinate SASS6. Its central role in centriole replication suggests a possible role in tumorigenesis, centrosome aberrations being frequently observed in tumors. Also involved in deuterosome-mediated centriole amplification in multiciliated that can generate more than 100 centrioles. Also involved in trophoblast differentiation by phosphorylating HAND1, leading to disrupt the interaction between HAND1 and MDFIC and activate HAND1. Phosphorylates CDC25C and CHEK2. Required for the recruitment of STIL to the centriole and for STIL-mediated centriole amplification (PubMed:22020124). Phosphorylates CEP131 at ''Ser-78'' and PCM1 at ''Ser-372'' which is essential for proper organization and integrity of centriolar satellites (PubMed:30804208).', 'PLK4', 'Homo sapiens', '{[''2.7.11.21'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Dwarfism, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (232, '1AQ1', 'MENFQKVEKIGEGTYGVVYKARNKLTGEVVALKKIRLDTETEGVPSTAIREISLLKELNHPNIVKLLDVIHTENKLYLVFEFLHQDLKKFMDASALTGIPLPLIKSYLFQLLQGLAFCHSHRVLHRDLKPQNLLINTEGAIKLADFGLARAFGVPVRTYTHEVVTLWYRAPEILLGCKYYSTAVDIWSLGCIFAEMVTRRALFPGDSEIDQLFRIFRTLGTPDEVVWPGVTSMPDYKPSFPKWARQDFSKVVPPLDEDGRSLLSQMLHYDPNKRISAKAALAHPFFQDVTKPVPHLRL', 'Cyclin-dependent kinase 2', 'Serine/threonine-protein kinase involved in the control of the cell cycle; essential for meiosis, but dispensable for mitosis. Phosphorylates CTNNB1, USP37, p53/TP53, NPM1, CDK7, RB1, BRCA2, MYC, NPAT, EZH2. Triggers duplication of centrosomes and DNA. Acts at the G1-S transition to promote the E2F transcriptional program and the initiation of DNA synthesis, and modulates G2 progression; controls the timing of entry into mitosis/meiosis by controlling the subsequent activation of cyclin B/CDK1 by phosphorylation, and coordinates the activation of cyclin B/CDK1 at the centrosome and in the nucleus. Crucial role in orchestrating a fine balance between cellular proliferation, cell death, and DNA repair in human embryonic stem cells (hESCs). Activity of CDK2 is maximal during S phase and G2; activated by interaction with cyclin E during the early stages of DNA synthesis to permit G1-S transition, and subsequently activated by cyclin A2 (cyclin A1 in germ cells) during the late stages of DNA replication to drive the transition from S phase to mitosis, the G2 phase. EZH2 phosphorylation promotes H3K27me3 maintenance and epigenetic gene silencing. Phosphorylates CABLES1 (By similarity). Cyclin E/CDK2 prevents oxidative stress-mediated Ras-induced senescence by phosphorylating MYC. Involved in G1-S phase DNA damage checkpoint that prevents cells with damaged DNA from initiating mitosis; regulates homologous recombination-dependent repair by phosphorylating BRCA2, this phosphorylation is low in S phase when recombination is active, but increases as cells progress towards mitosis. In response to DNA damage, double-strand break repair by homologous recombination a reduction of CDK2-mediated BRCA2 phosphorylation. Phosphorylation of RB1 disturbs its interaction with E2F1. NPM1 phosphorylation by cyclin E/CDK2 promotes its dissociates from unduplicated centrosomes, thus initiating centrosome duplication. Cyclin E/CDK2-mediated phosphorylation of NPAT at G1-S transition and until prophase stimulates the NPAT-mediated activation of histone gene transcription during S phase. Required for vitamin D-mediated growth inhibition by being itself inactivated. Involved in the nitric oxide- (NO) mediated signaling in a nitrosylation/activation-dependent manner. USP37 is activated by phosphorylation and thus triggers G1-S transition. CTNNB1 phosphorylation regulates insulin internalization. Phosphorylates FOXP3 and negatively regulates its transcriptional activity and protein stability (By similarity). Phosphorylates CDK2AP2 (PubMed:12944431). Phosphorylates ERCC6 which is essential for its chromatin remodeling activity at DNA double-strand breaks (PubMed:29203878).', 'CDK2', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cell division, Cytoplasm, Cytoskeleton, DNA damage, DNA repair, Endosome, Kinase, Magnesium, Meiosis, Metal-binding, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, S-nitrosylation, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (239, '4B6L', '', 'Serine/threonine-protein kinase PLK3', 'Serine/threonine-protein kinase involved in cell cycle regulation, response to stress and Golgi disassembly. Polo-like kinases act by binding and phosphorylating proteins that are already phosphorylated on a specific motif recognized by the POLO box domains. Phosphorylates ATF2, BCL2L1, CDC25A, CDC25C, CHEK2, HIF1A, JUN, p53/TP53, p73/TP73, PTEN, TOP2A and VRK1. Involved in cell cycle regulation: required for entry into S phase and cytokinesis. Phosphorylates BCL2L1, leading to regulate the G2 checkpoint and progression to cytokinesis during mitosis. Plays a key role in response to stress: rapidly activated upon stress stimulation, such as ionizing radiation, reactive oxygen species (ROS), hyperosmotic stress, UV irradiation and hypoxia. Involved in DNA damage response and G1/S transition checkpoint by phosphorylating CDC25A, p53/TP53 and p73/TP73. Phosphorylates p53/TP53 in response to reactive oxygen species (ROS), thereby promoting p53/TP53-mediated apoptosis. Phosphorylates CHEK2 in response to DNA damage, promoting the G2/M transition checkpoint. Phosphorylates the transcription factor p73/TP73 in response to DNA damage, leading to inhibit p73/TP73-mediated transcriptional activation and pro-apoptotic functions. Phosphorylates HIF1A and JUN is response to hypoxia. Phosphorylates ATF2 following hyperosmotic stress in corneal epithelium. Also involved in Golgi disassembly during the cell cycle: part of a MEK1/MAP2K1-dependent pathway that induces Golgi fragmentation during mitosis by mediating phosphorylation of VRK1. May participate in endomitotic cell cycle, a form of mitosis in which both karyokinesis and cytokinesis are interrupted and is a hallmark of megakaryocyte differentiation, via its interaction with CIB1.', 'PLK3', 'Homo sapiens', '{[''2.7.11.21'']}', '3D-structure, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Cytoskeleton, DNA damage, Golgi apparatus, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (233, '2X0G', '', 'Death-associated protein kinase 1', 'Calcium/calmodulin-dependent serine/threonine kinase involved in multiple cellular signaling pathways that trigger cell survival, apoptosis, and autophagy. Regulates both type I apoptotic and type II autophagic cell deaths signal, depending on the cellular setting. The former is caspase-dependent, while the latter is caspase-independent and is characterized by the accumulation of autophagic vesicles. Phosphorylates PIN1 resulting in inhibition of its catalytic activity, nuclear localization, and cellular function. Phosphorylates TPM1, enhancing stress fiber formation in endothelial cells. Phosphorylates STX1A and significantly decreases its binding to STXBP1. Phosphorylates PRKD1 and regulates JNK signaling by binding and activating PRKD1 under oxidative stress. Phosphorylates BECN1, reducing its interaction with BCL2 and BCL2L1 and promoting the induction of autophagy. Phosphorylates TSC2, disrupting the TSC1-TSC2 complex and stimulating mTORC1 activity in a growth factor-dependent pathway. Phosphorylates RPS6, MYL9 and DAPK3. Acts as a signaling amplifier of NMDA receptors at extrasynaptic sites for mediating brain damage in stroke. Cerebral ischemia recruits DAPK1 into the NMDA receptor complex and it phosphorylates GRINB at Ser-1303 inducing injurious Ca(2+) influx through NMDA receptor channels, resulting in an irreversible neuronal death. Required together with DAPK3 for phosphorylation of RPL13A upon interferon-gamma activation which is causing RPL13A involvement in transcript-selective translation inhibition.', 'DAPK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ANK repeat, Apoptosis, ATP-binding, Calmodulin-binding, Cytoplasm, Cytoskeleton, GTP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Translation regulation, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (234, '5ES1', '', 'MAP/microtubule affinity-regulating kinase 4', 'Serine/threonine-protein kinase (PubMed:15009667, PubMed:14594945, PubMed:23666762, PubMed:23184942). Phosphorylates the microtubule-associated protein MAPT/TAU (PubMed:14594945, PubMed:23666762). Also phosphorylates the microtubule-associated proteins MAP2 and MAP4 (PubMed:14594945). Involved in regulation of the microtubule network, causing reorganization of microtubules into bundles (PubMed:14594945, PubMed:25123532). Required for the initiation of axoneme extension during cilium assembly (PubMed:23400999). Regulates the centrosomal location of ODF2 and phosphorylates ODF2 in vitro (PubMed:23400999). Plays a role in cell cycle progression, specifically in the G1/S checkpoint (PubMed:25123532). Reduces neuronal cell survival (PubMed:15009667). Plays a role in energy homeostasis by regulating satiety and metabolic rate (By similarity). Promotes adipogenesis by activating JNK1 and inhibiting the p38MAPK pathway, and triggers apoptosis by activating the JNK1 pathway (By similarity). Phosphorylates mTORC1 complex member RPTOR and acts as a negative regulator of the mTORC1 complex, probably due to disruption of the interaction between phosphorylated RPTOR and the RRAGA/RRAGC heterodimer which is required for mTORC1 activation (PubMed:23184942). Involved in NLRP3 positioning along microtubules by mediating NLRP3 recruitment to microtubule organizing center (MTOC) upon inflammasome activation (PubMed:28656979).', 'MARK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cell division, Cell projection, Cilium biogenesis/degradation, Cytoplasm, Cytoskeleton, Kinase, Mitosis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (235, '1UA2', '', 'Cyclin-dependent kinase 7', 'Serine/threonine kinase involved in cell cycle control and in RNA polymerase II-mediated RNA transcription. Cyclin-dependent kinases (CDKs) are activated by the binding to a cyclin and mediate the progression through the cell cycle. Each different complex controls a specific transition between 2 subsequent phases in the cell cycle. Required for both activation and complex formation of CDK1/cyclin-B during G2-M transition, and for activation of CDK2/cyclins during G1-S transition (but not complex formation). CDK7 is the catalytic subunit of the CDK-activating kinase (CAK) complex. Phosphorylates SPT5/SUPT5H, SF1/NR5A1, POLR2A, p53/TP53, CDK1, CDK2, CDK4, CDK6 and CDK11B/CDK11. CAK activates the cyclin-associated kinases CDK1, CDK2, CDK4 and CDK6 by threonine phosphorylation, thus regulating cell cycle progression. CAK complexed to the core-TFIIH basal transcription factor activates RNA polymerase II by serine phosphorylation of the repetitive C-terminal domain (CTD) of its large subunit (POLR2A), allowing its escape from the promoter and elongation of the transcripts (PubMed:9852112). Phosphorylation of POLR2A in complex with DNA promotes transcription initiation by triggering dissociation from DNA. Its expression and activity are constant throughout the cell cycle. Upon DNA damage, triggers p53/TP53 activation by phosphorylation, but is inactivated in turn by p53/TP53; this feedback loop may lead to an arrest of the cell cycle and of the transcription, helping in cell recovery, or to apoptosis. Required for DNA-bound peptides-mediated transcription and cellular growth inhibition.', 'CDK7', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Acetylation, ATP-binding, Cell cycle, Cell division, Cytoplasm, DNA damage, DNA repair, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (236, '7QUE', '', 'Serine/threonine-protein kinase 17A', 'Acts as a positive regulator of apoptosis. Also acts as a regulator of cellular reactive oxygen species.', 'STK17A', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Apoptosis, ATP-binding, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (237, '3O96', '', 'RAC-alpha serine/threonine-protein kinase', 'AKT1 is one of 3 closely related serine/threonine-protein kinases (AKT1, AKT2 and AKT3) called the AKT kinase, and which regulate many processes including metabolism, proliferation, cell survival, growth and angiogenesis (PubMed:15861136, PubMed:15526160, PubMed:11882383, PubMed:21620960, PubMed:21432781, PubMed:31204173). This is mediated through serine and/or threonine phosphorylation of a range of downstream substrates (PubMed:15526160, PubMed:11882383, PubMed:21620960, PubMed:21432781, PubMed:31204173). Over 100 substrate candidates have been reported so far, but for most of them, no isoform specificity has been reported (PubMed:15526160, PubMed:11882383, PubMed:21620960, PubMed:21432781). AKT is responsible of the regulation of glucose uptake by mediating insulin-induced translocation of the SLC2A4/GLUT4 glucose transporter to the cell surface (By similarity). Phosphorylation of PTPN1 at ''Ser-50'' negatively modulates its phosphatase activity preventing dephosphorylation of the insulin receptor and the attenuation of insulin signaling (By similarity). Phosphorylation of TBC1D4 triggers the binding of this effector to inhibitory 14-3-3 proteins, which is required for insulin-stimulated glucose transport (PubMed:11994271). AKT regulates also the storage of glucose in the form of glycogen by phosphorylating GSK3A at ''Ser-21'' and GSK3B at ''Ser-9'', resulting in inhibition of its kinase activity (By similarity). Phosphorylation of GSK3 isoforms by AKT is also thought to be one mechanism by which cell proliferation is driven (By similarity). AKT regulates also cell survival via the phosphorylation of MAP3K5 (apoptosis signal-related kinase) (PubMed:11154276). Phosphorylation of ''Ser-83'' decreases MAP3K5 kinase activity stimulated by oxidative stress and thereby prevents apoptosis (PubMed:11154276). AKT mediates insulin-stimulated protein synthesis by phosphorylating TSC2 at ''Ser-939'' and ''Thr-1462'', thereby activating the mTORC1 signaling pathway, and leading to both phosphorylation of 4E-BP1 and in activation of RPS6KB1 (PubMed:12150915, PubMed:12172553). Also regulates the mTORC1 signaling pathway by catalyzing phosphorylation of CASTOR1 and DEPDC5 (PubMed:31548394, PubMed:33594058). AKT is involved in the phosphorylation of members of the FOXO factors (Forkhead family of transcription factors), leading to binding of 14-3-3 proteins and cytoplasmic localization (PubMed:10358075). In particular, FOXO1 is phosphorylated at ''Thr-24'', ''Ser-256'' and ''Ser-319'' (PubMed:10358075). FOXO3 and FOXO4 are phosphorylated on equivalent sites (PubMed:10358075). AKT has an important role in the regulation of NF-kappa-B-dependent gene transcription and positively regulates the activity of CREB1 (cyclic AMP (cAMP)-response element binding protein) (PubMed:9829964). The phosphorylation of CREB1 induces the binding of accessory proteins that are necessary for the transcription of pro-survival genes such as BCL2 and MCL1 (PubMed:9829964). AKT phosphorylates ''Ser-454'' on ATP citrate lyase (ACLY), thereby potentially regulating ACLY activity and fatty acid synthesis (By similarity). Activates the 3B isoform of cyclic nucleotide phosphodiesterase (PDE3B) via phosphorylation of ''Ser-273'', resulting in reduced cyclic AMP levels and inhibition of lipolysis (By similarity). Phosphorylates PIKFYVE on ''Ser-318'', which results in increased PI(3)P-5 activity (By similarity). The Rho GTPase-activating protein DLC1 is another substrate and its phosphorylation is implicated in the regulation cell proliferation and cell growth (By similarity). AKT plays a role as key modulator of the AKT-mTOR signaling pathway controlling the tempo of the process of newborn neurons integration during adult neurogenesis, including correct neuron positioning, dendritic development and synapse formation (By similarity). Signals downstream of phosphatidylinositol 3-kinase (PI(3)K) to mediate the effects of various growth factors such as platelet-derived growth factor (PDGF), epidermal growth factor (EGF), insulin and insulin-like growth factor I (IGF-I) (PubMed:12176338, PubMed:12964941). AKT mediates the antiapoptotic effects of IGF-I (By similarity). Essential for the SPATA13-mediated regulation of cell migration and adhesion assembly and disassembly (PubMed:19934221). May be involved in the regulation of the placental development (By similarity). Phosphorylates STK4/MST1 at ''Thr-120'' and ''Thr-387'' leading to inhibition of its: kinase activity, nuclear translocation, autophosphorylation and ability to phosphorylate FOXO3 (PubMed:17726016). Phosphorylates STK3/MST2 at ''Thr-117'' and ''Thr-384'' leading to inhibition of its: cleavage, kinase activity, autophosphorylation at Thr-180, binding to RASSF1 and nuclear translocation (PubMed:20086174, PubMed:20231902). Phosphorylates SRPK2 and enhances its kinase activity towards SRSF2 and ACIN1 and promotes its nuclear translocation (PubMed:19592491). Phosphorylates RAF1 at ''Ser-259'' and negatively regulates its activity (PubMed:10576742). Phosphorylation of BAD stimulates its pro-apoptotic activity (PubMed:10926925). Phosphorylates KAT6A at ''Thr-369'' and this phosphorylation inhibits the interaction of KAT6A with PML and negatively regulates its acetylation activity towards p53/TP53 (PubMed:23431171). Phosphorylates palladin (PALLD), modulating cytoskeletal organization and cell motility (PubMed:20471940). Phosphorylates prohibitin (PHB), playing an important role in cell metabolism and proliferation (PubMed:18507042). Phosphorylates CDKN1A, for which phosphorylation at ''Thr-145'' induces its release from CDK2 and cytoplasmic relocalization (PubMed:16982699). These recent findings indicate that the AKT1 isoform has a more specific role in cell motility and proliferation (PubMed:16139227). Phosphorylates CLK2 thereby controlling cell survival to ionizing radiation (PubMed:20682768). Phosphorylates PCK1 at ''Ser-90'', reducing the binding affinity of PCK1 to oxaloacetate and changing PCK1 into an atypical protein kinase activity using GTP as donor (PubMed:32322062). Also acts as an activator of TMEM175 potassium channel activity in response to growth factors: forms the lysoK(GF) complex together with TMEM175 and acts by promoting TMEM175 channel activation, independently of its protein kinase activity (PubMed:32228865). Acts as an inhibitor of tRNA methylation by mediating phosphorylation of the N-terminus of METTL1, thereby inhibiting METTL1 methyltransferase activity (PubMed:15861136). In response to LPAR1 receptor pathway activation, phosphorylates Rabin8/RAB3IP which alters its activity and phosphorylates WDR44 which induces WDR44 binding to Rab11, thereby switching Rab11 vesicular function from preciliary trafficking to endocytic recycling (PubMed:31204173).', 'AKT1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Carbohydrate metabolism, Cell membrane, Cytoplasm, Developmental protein, Disease variant, Disulfide bond, Glucose metabolism, Glycogen biosynthesis, Glycogen metabolism, Glycoprotein, Isopeptide bond, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Sugar transport, Transferase, Translation regulation, Transport, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (238, '3LXK', '', 'Tyrosine-protein kinase JAK3', 'Non-receptor tyrosine kinase involved in various processes such as cell growth, development, or differentiation. Mediates essential signaling events in both innate and adaptive immunity and plays a crucial role in hematopoiesis during T-cells development. In the cytoplasm, plays a pivotal role in signal transduction via its association with type I receptors sharing the common subunit gamma such as IL2R, IL4R, IL7R, IL9R, IL15R and IL21R. Following ligand binding to cell surface receptors, phosphorylates specific tyrosine residues on the cytoplasmic tails of the receptor, creating docking sites for STATs proteins. Subsequently, phosphorylates the STATs proteins once they are recruited to the receptor. Phosphorylated STATs then form homodimer or heterodimers and translocate to the nucleus to activate gene transcription. For example, upon IL2R activation by IL2, JAK1 and JAK3 molecules bind to IL2R beta (IL2RB) and gamma chain (IL2RG) subunits inducing the tyrosine phosphorylation of both receptor subunits on their cytoplasmic domain. Then, STAT5A and STAT5B are recruited, phosphorylated and activated by JAK1 and JAK3. Once activated, dimerized STAT5 translocates to the nucleus and promotes the transcription of specific target genes in a cytokine-specific fashion.', 'JAK3', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Adaptive immunity, Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Immunity, Innate immunity, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SCID, SH2 domain, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (240, '4Y5O', '', 'Cerebral cavernous malformations 2 protein', 'Component of the CCM signaling pathway which is a crucial regulator of heart and vessel formation and integrity. May act through the stabilization of endothelial cell junctions (By similarity). May function as a scaffold protein for MAP2K3-MAP3K3 signaling. Seems to play a major role in the modulation of MAP3K3-dependent p38 activation induced by hyperosmotic shock (By similarity).', 'CCM2', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Cytoplasm, Developmental protein, Direct protein sequencing, Disease variant, Phosphoprotein, Reference proteome');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (241, '6FD3', '', 'Serine/threonine-protein kinase PAK 3', 'Serine/threonine protein kinase that plays a role in a variety of different signaling pathways including cytoskeleton regulation, cell migration, or cell cycle regulation. Plays a role in dendrite spine morphogenesis as well as synapse formation and plasticity. Acts as a downstream effector of the small GTPases CDC42 and RAC1. Activation by the binding of active CDC42 and RAC1 results in a conformational change and a subsequent autophosphorylation on several serine and/or threonine residues. Phosphorylates MAPK4 and MAPK6 and activates the downstream target MAPKAPK5, a regulator of F-actin polymerization and cell migration. Additionally, phosphorylates TNNI3/troponin I to modulate calcium sensitivity and relaxation kinetics of thin myofilaments. May also be involved in early neuronal development. In hippocampal neurons, necessary for the formation of dendritic spines and excitatory synapses; this function is dependent on kinase activity and may be exerted by the regulation of actomyosin contractility through the phosphorylation of myosin II regulatory light chain (MLC) (By similarity).', 'PAK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Allosteric enzyme, Alternative splicing, ATP-binding, Cytoplasm, Developmental protein, Disease variant, Intellectual disability, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, SH3-binding, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (242, '4JG6', '', 'Ribosomal protein S6 kinase alpha-3', 'Serine/threonine-protein kinase that acts downstream of ERK (MAPK1/ERK2 and MAPK3/ERK1) signaling and mediates mitogenic and stress-induced activation of the transcription factors CREB1, ETV1/ER81 and NR4A1/NUR77, regulates translation through RPS6 and EIF4B phosphorylation, and mediates cellular proliferation, survival, and differentiation by modulating mTOR signaling and repressing pro-apoptotic function of BAD and DAPK1 (PubMed:9770464, PubMed:16223362, PubMed:17360704, PubMed:16213824). In fibroblast, is required for EGF-stimulated phosphorylation of CREB1 and histone H3 at ''Ser-10'', which results in the subsequent transcriptional activation of several immediate-early genes (PubMed:9770464, PubMed:10436156). In response to mitogenic stimulation (EGF and PMA), phosphorylates and activates NR4A1/NUR77 and ETV1/ER81 transcription factors and the cofactor CREBBP (PubMed:16223362). Upon insulin-derived signal, acts indirectly on the transcription regulation of several genes by phosphorylating GSK3B at ''Ser-9'' and inhibiting its activity (PubMed:8250835). Phosphorylates RPS6 in response to serum or EGF via an mTOR-independent mechanism and promotes translation initiation by facilitating assembly of the preinitiation complex (PubMed:17360704). In response to insulin, phosphorylates EIF4B, enhancing EIF4B affinity for the EIF3 complex and stimulating cap-dependent translation (PubMed:18508509, PubMed:18813292). Is involved in the mTOR nutrient-sensing pathway by directly phosphorylating TSC2 at ''Ser-1798'', which potently inhibits TSC2 ability to suppress mTOR signaling, and mediates phosphorylation of RPTOR, which regulates mTORC1 activity and may promote rapamycin-sensitive signaling independently of the PI3K/AKT pathway (PubMed:18722121). Mediates cell survival by phosphorylating the pro-apoptotic proteins BAD and DAPK1 and suppressing their pro-apoptotic function (PubMed:16213824). Promotes the survival of hepatic stellate cells by phosphorylating CEBPB in response to the hepatotoxin carbon tetrachloride (CCl4) (PubMed:18508509, PubMed:18813292). Is involved in cell cycle regulation by phosphorylating the CDK inhibitor CDKN1B, which promotes CDKN1B association with 14-3-3 proteins and prevents its translocation to the nucleus and inhibition of G1 progression (By similarity). In LPS-stimulated dendritic cells, is involved in TLR4-induced macropinocytosis, and in myeloma cells, acts as effector of FGFR3-mediated transformation signaling, after direct phosphorylation at Tyr-529 by FGFR3 (By similarity). Negatively regulates EGF-induced MAPK1/3 phosphorylation via phosphorylation of SOS1 (By similarity). Phosphorylates SOS1 at ''Ser-1134'' and ''Ser-1161'' that create YWHAB and YWHAE binding sites and which contribute to the negative regulation of MAPK1/3 phosphorylation (By similarity). Phosphorylates EPHA2 at ''Ser-897'', the RPS6KA-EPHA2 signaling pathway controls cell migration (PubMed:26158630). Acts as a regulator of osteoblast differentiation by mediating phosphorylation of ATF4, thereby promoting ATF4 transactivation activity (By similarity).', 'RPS6KA3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell cycle, Cytoplasm, Disease variant, Intellectual disability, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Stress response, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (243, '4K2R', '', 'Tyrosine-protein kinase ZAP-70', 'Tyrosine kinase that plays an essential role in regulation of the adaptive immune response. Regulates motility, adhesion and cytokine expression of mature T-cells, as well as thymocyte development. Contributes also to the development and activation of primary B-lymphocytes. When antigen presenting cells (APC) activate T-cell receptor (TCR), a serie of phosphorylations lead to the recruitment of ZAP70 to the doubly phosphorylated TCR component CD247/CD3Z through ITAM motif at the plasma membrane. This recruitment serves to localization to the stimulated TCR and to relieve its autoinhibited conformation. Release of ZAP70 active conformation is further stabilized by phosphorylation mediated by LCK. Subsequently, ZAP70 phosphorylates at least 2 essential adapter proteins: LAT and LCP2. In turn, a large number of signaling molecules are recruited and ultimately lead to lymphokine production, T-cell proliferation and differentiation. Furthermore, ZAP70 controls cytoskeleton modifications, adhesion and mobility of T-lymphocytes, thus ensuring correct delivery of effectors to the APC. ZAP70 is also required for TCR-CD247/CD3Z internalization and degradation through interaction with the E3 ubiquitin-protein ligase CBL and adapter proteins SLA and SLA2. Thus, ZAP70 regulates both T-cell activation switch on and switch off by modulating TCR expression at the T-cell surface. During thymocyte development, ZAP70 promotes survival and cell-cycle progression of developing thymocytes before positive selection (when cells are still CD4/CD8 double negative). Additionally, ZAP70-dependent signaling pathway may also contribute to primary B-cells formation and activation through B-cell receptor (BCR).', 'ZAP70', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Adaptive immunity, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Disease variant, Immunity, Isopeptide bond, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SCID, SH2 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (244, '2COA', '', 'Serine/threonine-protein kinase D2', 'Serine/threonine-protein kinase that converts transient diacylglycerol (DAG) signals into prolonged physiological effects downstream of PKC, and is involved in the regulation of cell proliferation via MAPK1/3 (ERK1/2) signaling, oxidative stress-induced NF-kappa-B activation, inhibition of HDAC7 transcriptional repression, signaling downstream of T-cell antigen receptor (TCR) and cytokine production, and plays a role in Golgi membrane trafficking, angiogenesis, secretory granule release and cell adhesion (PubMed:15604256, PubMed:14743217, PubMed:17077180, PubMed:16928771, PubMed:17962809, PubMed:17951978, PubMed:18262756, PubMed:19192391, PubMed:19001381, PubMed:23503467, PubMed:28428613). May potentiate mitogenesis induced by the neuropeptide bombesin by mediating an increase in the duration of MAPK1/3 (ERK1/2) signaling, which leads to accumulation of immediate-early gene products including FOS that stimulate cell cycle progression (By similarity). In response to oxidative stress, is phosphorylated at Tyr-438 and Tyr-717 by ABL1, which leads to the activation of PRKD2 without increasing its catalytic activity, and mediates activation of NF-kappa-B (PubMed:15604256, PubMed:28428613). In response to the activation of the gastrin receptor CCKBR, is phosphorylated at Ser-244 by CSNK1D and CSNK1E, translocates to the nucleus, phosphorylates HDAC7, leading to nuclear export of HDAC7 and inhibition of HDAC7 transcriptional repression of NR4A1/NUR77 (PubMed:17962809). Upon TCR stimulation, is activated independently of ZAP70, translocates from the cytoplasm to the nucleus and is required for interleukin-2 (IL2) promoter up-regulation (PubMed:17077180). During adaptive immune responses, is required in peripheral T-lymphocytes for the production of the effector cytokines IL2 and IFNG after TCR engagement and for optimal induction of antibody responses to antigens (By similarity). In epithelial cells stimulated with lysophosphatidic acid (LPA), is activated through a PKC-dependent pathway and mediates LPA-stimulated interleukin-8 (IL8) secretion via a NF-kappa-B-dependent pathway (PubMed:16928771). During TCR-induced T-cell activation, interacts with and is activated by the tyrosine kinase LCK, which results in the activation of the NFAT transcription factors (PubMed:19192391). In the trans-Golgi network (TGN), regulates the fission of transport vesicles that are on their way to the plasma membrane and in polarized cells is involved in the transport of proteins from the TGN to the basolateral membrane (PubMed:14743217). Plays an important role in endothelial cell proliferation and migration prior to angiogenesis, partly through modulation of the expression of KDR/VEGFR2 and FGFR1, two key growth factor receptors involved in angiogenesis (PubMed:19001381). In secretory pathway, is required for the release of chromogranin-A (CHGA)-containing secretory granules from the TGN (PubMed:18262756). Downstream of PRKCA, plays important roles in angiotensin-2-induced monocyte adhesion to endothelial cells (PubMed:17951978). Plays a regulatory role in angiogenesis and tumor growth by phosphorylating a downstream mediator CIB1 isoform 2, resulting in vascular endothelial growth factor A (VEGFA) secretion (PubMed:23503467).', 'PRKD2', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Adaptive immunity, Alternative splicing, Angiogenesis, ATP-binding, Cell adhesion, Cell membrane, Cytoplasm, Golgi apparatus, Immunity, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (245, '2R5T', '', 'Serine/threonine-protein kinase Sgk1', 'Serine/threonine-protein kinase which is involved in the regulation of a wide variety of ion channels, membrane transporters, cellular enzymes, transcription factors, neuronal excitability, cell growth, proliferation, survival, migration and apoptosis. Plays an important role in cellular stress response. Contributes to regulation of renal Na(+) retention, renal K(+) elimination, salt appetite, gastric acid secretion, intestinal Na(+)/H(+) exchange and nutrient transport, insulin-dependent salt sensitivity of blood pressure, salt sensitivity of peripheral glucose uptake, cardiac repolarization and memory consolidation. Up-regulates Na(+) channels: SCNN1A/ENAC, SCN5A and ASIC1/ACCN2, K(+) channels: KCNJ1/ROMK1, KCNA1-5, KCNQ1-5 and KCNE1, epithelial Ca(2+) channels: TRPV5 and TRPV6, chloride channels: BSND, CLCN2 and CFTR, glutamate transporters: SLC1A3/EAAT1, SLC1A2 /EAAT2, SLC1A1/EAAT3, SLC1A6/EAAT4 and SLC1A7/EAAT5, amino acid transporters: SLC1A5/ASCT2, SLC38A1/SN1 and SLC6A19, creatine transporter: SLC6A8, Na(+)/dicarboxylate cotransporter: SLC13A2/NADC1, Na(+)-dependent phosphate cotransporter: SLC34A2/NAPI-2B, glutamate receptor: GRIK2/GLUR6. Up-regulates carriers: SLC9A3/NHE3, SLC12A1/NKCC2, SLC12A3/NCC, SLC5A3/SMIT, SLC2A1/GLUT1, SLC5A1/SGLT1 and SLC15A2/PEPT2. Regulates enzymes: GSK3A/B, PMM2 and Na(+)/K(+) ATPase, and transcription factors: CTNNB1 and nuclear factor NF-kappa-B. Stimulates sodium transport into epithelial cells by enhancing the stability and expression of SCNN1A/ENAC. This is achieved by phosphorylating the NEDD4L ubiquitin E3 ligase, promoting its interaction with 14-3-3 proteins, thereby preventing it from binding to SCNN1A/ENAC and targeting it for degradation. Regulates store-operated Ca(+2) entry (SOCE) by stimulating ORAI1 and STIM1. Regulates KCNJ1/ROMK1 directly via its phosphorylation or indirectly via increased interaction with SLC9A3R2/NHERF2. Phosphorylates MDM2 and activates MDM2-dependent ubiquitination of p53/TP53. Phosphorylates MAPT/TAU and mediates microtubule depolymerization and neurite formation in hippocampal neurons. Phosphorylates SLC2A4/GLUT4 and up-regulates its activity. Phosphorylates APBB1/FE65 and promotes its localization to the nucleus. Phosphorylates MAPK1/ERK2 and activates it by enhancing its interaction with MAP2K1/MEK1 and MAP2K2/MEK2. Phosphorylates FBXW7 and plays an inhibitory role in the NOTCH1 signaling. Phosphorylates FOXO1 resulting in its relocalization from the nucleus to the cytoplasm. Phosphorylates FOXO3, promoting its exit from the nucleus and interference with FOXO3-dependent transcription. Phosphorylates BRAF and MAP3K3/MEKK3 and inhibits their activity. Phosphorylates SLC9A3/NHE3 in response to dexamethasone, resulting in its activation and increased localization at the cell membrane. Phosphorylates CREB1. Necessary for vascular remodeling during angiogenesis. Sustained high levels and activity may contribute to conditions such as hypertension and diabetic nephropathy. Isoform 2 exhibited a greater effect on cell plasma membrane expression of SCNN1A/ENAC and Na(+) transport than isoform 1.', 'SGK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative promoter usage, Alternative splicing, Apoptosis, ATP-binding, Cell membrane, Cytoplasm, Disulfide bond, Endoplasmic reticulum, Kinase, Membrane, Mitochondrion, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (252, '2M9X', '', 'Microtubule-associated serine/threonine-protein kinase 1', 'Microtubule-associated protein essential for correct brain development (PubMed:30449657). Appears to link the dystrophin/utrophin network with microtubule filaments via the syntrophins. Phosphorylation of DMD or UTRN may modulate their affinities for associated proteins (By similarity).', 'MAST1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Disease variant, Intellectual disability, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (246, '8ELC', '', 'Mitogen-activated protein kinase 9', 'Serine/threonine-protein kinase involved in various processes such as cell proliferation, differentiation, migration, transformation and programmed cell death. Extracellular stimuli such as pro-inflammatory cytokines or physical stress stimulate the stress-activated protein kinase/c-Jun N-terminal kinase (SAP/JNK) signaling pathway. In this cascade, two dual specificity kinases MAP2K4/MKK4 and MAP2K7/MKK7 phosphorylate and activate MAPK9/JNK2. In turn, MAPK9/JNK2 phosphorylates a number of transcription factors, primarily components of AP-1 such as JUN and ATF2 and thus regulates AP-1 transcriptional activity. In response to oxidative or ribotoxic stresses, inhibits rRNA synthesis by phosphorylating and inactivating the RNA polymerase 1-specific transcription initiation factor RRN3. Promotes stressed cell apoptosis by phosphorylating key regulatory factors including TP53 and YAP1. In T-cells, MAPK8 and MAPK9 are required for polarized differentiation of T-helper cells into Th1 cells. Upon T-cell receptor (TCR) stimulation, is activated by CARMA1, BCL10, MAP2K7 and MAP3K7/TAK1 to regulate JUN protein levels. Plays an important role in the osmotic stress-induced epithelial tight-junctions disruption. When activated, promotes beta-catenin/CTNNB1 degradation and inhibits the canonical Wnt signaling pathway. Participates also in neurite growth in spiral ganglion neurons. Phosphorylates the CLOCK-BMAL1 heterodimer and plays a role in the regulation of the circadian clock (PubMed:22441692). Phosphorylates POU5F1, which results in the inhibition of POU5F1''s transcriptional activity and enhances its proteasomal degradation (By similarity).', 'MAPK9', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Biological rhythms, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (247, '5U6B', '', 'Tyrosine-protein kinase receptor UFO', 'Receptor tyrosine kinase that transduces signals from the extracellular matrix into the cytoplasm by binding growth factor GAS6 and which is thus regulating many physiological processes including cell survival, cell proliferation, migration and differentiation. Ligand binding at the cell surface induces dimerization and autophosphorylation of AXL. Following activation by ligand, AXL binds and induces tyrosine phosphorylation of PI3-kinase subunits PIK3R1, PIK3R2 and PIK3R3; but also GRB2, PLCG1, LCK and PTPN11. Other downstream substrate candidates for AXL are CBL, NCK2, SOCS1 and TNS2. Recruitment of GRB2 and phosphatidylinositol 3 kinase regulatory subunits by AXL leads to the downstream activation of the AKT kinase. GAS6/AXL signaling plays a role in various processes such as endothelial cell survival during acidification by preventing apoptosis, optimal cytokine signaling during human natural killer cell development, hepatic regeneration, gonadotropin-releasing hormone neuron survival and migration, platelet activation, or regulation of thrombotic responses. Also plays an important role in inhibition of Toll-like receptors (TLRs)-mediated innate immune response.', 'AXL', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Differentiation, Disulfide bond, Glycoprotein, Host cell receptor for virus entry, Host-virus interaction, Immunity, Immunoglobulin domain, Innate immunity, Kinase, Membrane, Nucleotide-binding, Oncogene, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (248, '7UY0', '', 'Tyrosine-protein kinase Fgr', 'Non-receptor tyrosine-protein kinase that transmits signals from cell surface receptors devoid of kinase activity and contributes to the regulation of immune responses, including neutrophil, monocyte, macrophage and mast cell functions, cytoskeleton remodeling in response to extracellular stimuli, phagocytosis, cell adhesion and migration. Promotes mast cell degranulation, release of inflammatory cytokines and IgE-mediated anaphylaxis. Acts downstream of receptors that bind the Fc region of immunoglobulins, such as MS4A2/FCER1B, FCGR2A and/or FCGR2B. Acts downstream of ITGB1 and ITGB2, and regulates actin cytoskeleton reorganization, cell spreading and adhesion. Depending on the context, activates or inhibits cellular responses. Functions as a negative regulator of ITGB2 signaling, phagocytosis and SYK activity in monocytes. Required for normal ITGB1 and ITGB2 signaling, normal cell spreading and adhesion in neutrophils and macrophages. Functions as a positive regulator of cell migration and regulates cytoskeleton reorganization via RAC1 activation. Phosphorylates SYK (in vitro) and promotes SYK-dependent activation of AKT1 and MAP kinase signaling. Phosphorylates PLD2 in antigen-stimulated mast cells, leading to PLD2 activation and the production of the signaling molecules lysophosphatidic acid and diacylglycerol. Promotes activation of PIK3R1. Phosphorylates FASLG, and thereby regulates its ubiquitination and subsequent internalization. Phosphorylates ABL1. Promotes phosphorylation of CBL, CTTN, PIK3R1, PTK2/FAK1, PTK2B/PYK2 and VAV2. Phosphorylates HCLS1 that has already been phosphorylated by SYK, but not unphosphorylated HCLS1. Together with CLNK, it acts as a negative regulator of natural killer cell-activating receptors and inhibits interferon-gamma production (By similarity).', 'FGR', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, ATP-binding, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Immunity, Innate immunity, Kinase, Lipoprotein, Membrane, Mitochondrion, Mitochondrion inner membrane, Myristate, Nucleotide-binding, Palmitate, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (249, '2X4F', '', 'Myosin light chain kinase family member 4', 'Unknown', 'MYLK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (250, '7LV3', '', 'cGMP-dependent protein kinase 1', 'Serine/threonine protein kinase that acts as a key mediator of the nitric oxide (NO)/cGMP signaling pathway. GMP binding activates PRKG1, which phosphorylates serines and threonines on many cellular proteins. Numerous protein targets for PRKG1 phosphorylation are implicated in modulating cellular calcium, but the contribution of each of these targets may vary substantially among cell types. Proteins that are phosphorylated by PRKG1 regulate platelet activation and adhesion, smooth muscle contraction, cardiac function, gene expression, feedback of the NO-signaling pathway, and other processes involved in several aspects of the CNS like axon guidance, hippocampal and cerebellar learning, circadian rhythm and nociception. Smooth muscle relaxation is mediated through lowering of intracellular free calcium, by desensitization of contractile proteins to calcium, and by decrease in the contractile state of smooth muscle or in platelet activation. Regulates intracellular calcium levels via several pathways: phosphorylates IRAG1 and inhibits IP3-induced Ca(2+) release from intracellular stores, phosphorylation of KCNMA1 (BKCa) channels decreases intracellular Ca(2+) levels, which leads to increased opening of this channel. PRKG1 phosphorylates the canonical transient receptor potential channel (TRPC) family which inactivates the associated inward calcium current. Another mode of action of NO/cGMP/PKGI signaling involves PKGI-mediated inactivation of the Ras homolog gene family member A (RhoA). Phosphorylation of RHOA by PRKG1 blocks the action of this protein in myriad processes: regulation of RHOA translocation; decreasing contraction; controlling vesicle trafficking, reduction of myosin light chain phosphorylation resulting in vasorelaxation. Activation of PRKG1 by NO signaling alters also gene expression in a number of tissues. In smooth muscle cells, increased cGMP and PRKG1 activity influence expression of smooth muscle-specific contractile proteins, levels of proteins in the NO/cGMP signaling pathway, down-regulation of the matrix proteins osteopontin and thrombospondin-1 to limit smooth muscle cell migration and phenotype. Regulates vasodilator-stimulated phosphoprotein (VASP) functions in platelets and smooth muscle.', 'PRKG1', 'Homo sapiens', '{[''2.7.11.12'']}', '3D-structure, Acetylation, Allosteric enzyme, Alternative splicing, Aortic aneurysm, ATP-binding, cGMP, cGMP-binding, Coiled coil, Cytoplasm, Disease variant, Disulfide bond, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (251, '8QGY', '', 'Mitogen-activated protein kinase kinase kinase 5', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. Plays an important role in the cascades of cellular responses evoked by changes in the environment. Mediates signaling for determination of cell fate such as differentiation and survival. Plays a crucial role in the apoptosis signal transduction pathway through mitochondria-dependent caspase activation. MAP3K5/ASK1 is required for the innate immune response, which is essential for host defense against a wide range of pathogens. Mediates signal transduction of various stressors like oxidative stress as well as by receptor-mediated inflammatory signals, such as the tumor necrosis factor (TNF) or lipopolysaccharide (LPS). Once activated, acts as an upstream activator of the MKK/JNK signal transduction cascade and the p38 MAPK signal transduction cascade through the phosphorylation and activation of several MAP kinase kinases like MAP2K4/SEK1, MAP2K3/MKK3, MAP2K6/MKK6 and MAP2K7/MKK7. These MAP2Ks in turn activate p38 MAPKs and c-jun N-terminal kinases (JNKs). Both p38 MAPK and JNKs control the transcription factors activator protein-1 (AP-1).', 'MAP3K5', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Endoplasmic reticulum, Host-virus interaction, Immunity, Innate immunity, Kinase, Magnesium, Metal-binding, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (253, '5D9H', '', 'STE20/SPS1-related proline-alanine-rich protein kinase', 'Effector serine/threonine-protein kinase component of the WNK-SPAK/OSR1 kinase cascade, which is involved in various processes, such as ion transport, response to hypertonic stress and blood pressure (PubMed:16382158, PubMed:17488636, PubMed:19633012, PubMed:21486947). Specifically recognizes and binds proteins with a RFXV motif (PubMed:14563843). Acts downstream of WNK kinases (WNK1, WNK2, WNK3 or WNK4): following activation by WNK kinases, catalyzes phosphorylation of ion cotransporters, such as SLC12A1/NKCC2, SLC12A2/NKCC1, SLC12A3/NCC, SLC12A5/KCC2 or SLC12A6/KCC3, regulating their activity (PubMed:14563843, PubMed:16382158, PubMed:17488636, PubMed:19633012, PubMed:21486947). Mediates regulatory volume increase in response to hyperosmotic stress by catalyzing phosphorylation of ion cotransporters SLC12A1/NKCC2, SLC12A2/NKCC1 and SLC12A6/KCC3 downstream of WNK1 and WNK3 kinases (By similarity). Phosphorylation of Na-K-Cl cotransporters SLC12A2/NKCC1 and SLC12A2/NKCC1 promote their activation and ion influx; simultaneously, phosphorylation of K-Cl cotransporters SLC12A5/KCC2 and SLC12A6/KCC3 inhibit their activity, blocking ion efflux (By similarity). Acts as a regulator of NaCl reabsorption in the distal nephron by mediating phosphorylation and activation of the thiazide-sensitive Na-Cl cotransporter SLC12A3/NCC in distal convoluted tubule cells of kidney downstream of WNK4 (PubMed:17488636, PubMed:19633012, PubMed:21486947). Mediates the inhibition of SLC4A4, SLC26A6 as well as CFTR activities (PubMed:21317537, PubMed:23542070). Phosphorylates RELT (PubMed:16530727).', 'Stk39', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (254, '7T8J', '', 'Transcription factor ETV6', 'Transcriptional repressor; binds to the DNA sequence 5''-CCGGAAGT-3''. Plays a role in hematopoiesis and malignant transformation.', 'ETV6', 'Homo sapiens', '{[]}', '3D-structure, Acetylation, Chromosomal rearrangement, Disease variant, DNA-binding, Isopeptide bond, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Repressor, Transcription, Transcription regulation, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (255, '7KJA', '', 'Ephrin type-A receptor 2', 'Receptor tyrosine kinase which binds promiscuously membrane-bound ephrin-A family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Activated by the ligand ephrin-A1/EFNA1 regulates migration, integrin-mediated adhesion, proliferation and differentiation of cells. Regulates cell adhesion and differentiation through DSG1/desmoglein-1 and inhibition of the ERK1/ERK2 (MAPK3/MAPK1, respectively) signaling pathway. May also participate in UV radiation-induced apoptosis and have a ligand-independent stimulatory effect on chemotactic cell migration. During development, may function in distinctive aspects of pattern formation and subsequently in development of several fetal tissues. Involved for instance in angiogenesis, in early hindbrain development and epithelial proliferation and branching morphogenesis during mammary gland development. Engaged by the ligand ephrin-A5/EFNA5 may regulate lens fiber cells shape and interactions and be important for lens transparency development and maintenance. With ephrin-A2/EFNA2 may play a role in bone remodeling through regulation of osteoclastogenesis and osteoblastogenesis.', 'EPHA2', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, Apoptosis, ATP-binding, Cataract, Cell adhesion, Cell junction, Cell membrane, Cell projection, Differentiation, Disease variant, Disulfide bond, Glycoprotein, Host cell receptor for virus entry, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (256, '2J0J', '', 'Focal adhesion kinase 1', 'Non-receptor protein-tyrosine kinase that plays an essential role in regulating cell migration, adhesion, spreading, reorganization of the actin cytoskeleton, formation and disassembly of focal adhesions and cell protrusions, cell cycle progression, cell proliferation and apoptosis. Required for early embryonic development, embryonic angiogenesis, normal cardiomyocyte migration and proliferation, and normal heart development. Regulates axon growth and neuronal cell migration, axon branching and synapse formation; required for normal development of the nervous system. Plays a role in osteogenesis and differentiation of osteoblasts. Functions in integrin signal transduction, but also in signaling downstream of numerous growth factor receptors, G-protein coupled receptors (GPCR), ephrin receptors, netrin receptors and LDL receptors. Forms multisubunit signaling complexes with SRC and SRC family members upon activation; this leads to the phosphorylation of additional tyrosine residues, creating binding sites for scaffold proteins, effectors and substrates. Regulates numerous signaling pathways. Promotes activation of phosphatidylinositol 3-kinase and the AKT1 signaling cascade. Promotes activation of MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling cascade. Promotes localized and transient activation of guanine nucleotide exchange factors (GEFs) and GTPase-activating proteins (GAPs), and thereby modulates the activity of Rho family GTPases. Signaling via CAS family members mediates activation of RAC1. Regulates P53/TP53 activity and stability. Phosphorylates SRC; this increases SRC kinase activity. Isoform 2 (FRNK) does not contain a kinase domain and inhibits PTK2/FAK1 phosphorylation and signaling.', 'PTK2', 'Gallus gallus', '{[''2.7.10.2'']}', '3D-structure, Alternative promoter usage, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Developmental protein, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (257, '2HW6', '', 'MAP kinase-interacting serine/threonine-protein kinase 1', 'May play a role in the response to environmental stress and cytokines. Appears to regulate translation by phosphorylating EIF4E, thus increasing the affinity of this protein for the 7-methylguanosine-containing mRNA cap.', 'MKNK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Translation regulation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (283, '8JFK', '', 'Phosphorylase b kinase regulatory subunit beta', 'Phosphorylase b kinase catalyzes the phosphorylation of serine in certain substrates, including troponin I. The beta chain acts as a regulatory unit and modulates the activity of the holoenzyme in response to phosphorylation.', 'PHKB', 'Homo sapiens', '{[]}', 'Acetylation, Alternative splicing, Calmodulin-binding, Carbohydrate metabolism, Cell membrane, Disease variant, Glycogen metabolism, Glycogen storage disease, Lipoprotein, Membrane, Phosphoprotein, Prenylation, Reference proteome');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (258, '7NX0', '', 'Leukocyte tyrosine kinase receptor', 'Receptor with a tyrosine-protein kinase activity (PubMed:10445845, PubMed:20548102, PubMed:30061385). Following activation by ALKAL1 or ALKAL2 ligands at the cell surface, transduces an extracellular signal into an intracellular response (PubMed:30061385, PubMed:34646012). Ligand-binding to the extracellular domain induces tyrosine kinase activation, leading to activation of the mitogen-activated protein kinase (MAPK) pathway (PubMed:20548102). Phosphorylates almost exclusively at the first tyrosine of the Y-x-x-x-Y-Y motif (By similarity). The exact function of this protein is not known; studies with chimeric proteins demonstrate its ability to promote growth and specifically neurite outgrowth, and cell survival (PubMed:9223670, PubMed:18849880). Involved in regulation of the secretory pathway involving endoplasmic reticulum (ER) export sites (ERESs) and ER to Golgi transport (PubMed:20548102).', 'LTK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Signal, Systemic lupus erythematosus, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (259, '6GL7', '', 'Neurturin', 'Supports the survival of sympathetic neurons in culture. May regulate the development and maintenance of the CNS. Might control the size of non-neuronal cell population such as haemopoietic cells.', 'NRTN', 'Homo sapiens', '{[]}', '3D-structure, Disease variant, Disulfide bond, Growth factor, Hirschsprung disease, Reference proteome, Secreted, Signal');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (260, '5CEN', '', 'Mitogen-activated protein kinase kinase kinase 12', 'Part of a non-canonical MAPK signaling pathway (PubMed:28111074). Activated by APOE, enhances the AP-1-mediated transcription of APP, via a MAP kinase signal transduction pathway composed of MAP2K7 and MAPK1/ERK2 and MAPK3/ERK1 (PubMed:28111074). May be an activator of the JNK/SAPK pathway.', 'MAP3K12', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Kinase, Magnesium, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (261, '6KHD', '', 'Dual specificity protein kinase CLK1', 'Dual specificity kinase acting on both serine/threonine and tyrosine-containing substrates. Phosphorylates serine- and arginine-rich (SR) proteins of the spliceosomal complex and may be a constituent of a network of regulatory mechanisms that enable SR proteins to control RNA splicing. Phosphorylates: SRSF1, SRSF3 and PTPN1 (PubMed:10480872, PubMed:19168442). Regulates the alternative splicing of tissue factor (F3) pre-mRNA in endothelial cells (PubMed:19168442).', 'CLK1', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (262, '6ZIW', '', 'Interleukin-1 receptor-associated kinase 3', 'Putative inactive protein kinase which regulates signaling downstream of immune receptors including IL1R and Toll-like receptors (PubMed:10383454, PubMed:29686383). Inhibits dissociation of IRAK1 and IRAK4 from the Toll-like receptor signaling complex by either inhibiting the phosphorylation of IRAK1 and IRAK4 or stabilizing the receptor complex (By similarity). Upon IL33-induced lung inflammation, positively regulates expression of IL6, CSF3, CXCL2 and CCL5 mRNAs in dendritic cells (PubMed:29686383).', 'IRAK3', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Asthma, ATP-binding, Cytoplasm, Disulfide bond, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (263, '6NT9', '', 'Serine/threonine-protein kinase TBK1', 'Serine/threonine kinase that plays an essential role in regulating inflammatory responses to foreign agents (PubMed:12692549, PubMed:14703513, PubMed:18583960, PubMed:12702806, PubMed:15367631, PubMed:10581243, PubMed:11839743, PubMed:15485837, PubMed:21138416, PubMed:25636800, PubMed:23453971, PubMed:23453972, PubMed:23746807, PubMed:26611359, PubMed:32404352). Following activation of toll-like receptors by viral or bacterial components, associates with TRAF3 and TANK and phosphorylates interferon regulatory factors (IRFs) IRF3 and IRF7 as well as DDX3X (PubMed:12692549, PubMed:14703513, PubMed:18583960, PubMed:12702806, PubMed:15367631, PubMed:25636800). This activity allows subsequent homodimerization and nuclear translocation of the IRFs leading to transcriptional activation of pro-inflammatory and antiviral genes including IFNA and IFNB (PubMed:12702806, PubMed:15367631, PubMed:25636800, PubMed:32972995). In order to establish such an antiviral state, TBK1 form several different complexes whose composition depends on the type of cell and cellular stimuli (PubMed:23453971, PubMed:23453972, PubMed:23746807). Plays a key role in IRF3 activation: acts by first phosphorylating innate adapter proteins MAVS, STING1 and TICAM1 on their pLxIS motif, leading to recruitment of IRF3, thereby licensing IRF3 for phosphorylation by TBK1 (PubMed:25636800, PubMed:30842653). Phosphorylated IRF3 dissociates from the adapter proteins, dimerizes, and then enters the nucleus to induce expression of interferons (PubMed:25636800). Thus, several scaffolding molecules including FADD, TRADD, MAVS, AZI2, TANK or TBKBP1/SINTBAD can be recruited to the TBK1-containing-complexes (PubMed:21931631). Under particular conditions, functions as a NF-kappa-B effector by phosphorylating NF-kappa-B inhibitor alpha/NFKBIA, IKBKB or RELA to translocate NF-Kappa-B to the nucleus (PubMed:10783893, PubMed:15489227). Restricts bacterial proliferation by phosphorylating the autophagy receptor OPTN/Optineurin on ''Ser-177'', thus enhancing LC3 binding affinity and antibacterial autophagy (PubMed:21617041). Phosphorylates SMCR8 component of the C9orf72-SMCR8 complex, promoting autophagosome maturation (PubMed:27103069). Phosphorylates ATG8 proteins MAP1LC3C and GABARAPL2, thereby preventing their delipidation and premature removal from nascent autophagosomes (PubMed:31709703). Phosphorylates and activates AKT1 (PubMed:21464307). Seems to play a role in energy balance regulation by sustaining a state of chronic, low-grade inflammation in obesity, wich leads to a negative impact on insulin sensitivity (By similarity). Attenuates retroviral budding by phosphorylating the endosomal sorting complex required for transport-I (ESCRT-I) subunit VPS37C (PubMed:21270402). Phosphorylates Borna disease virus (BDV) P protein (PubMed:16155125). Plays an essential role in the TLR3- and IFN-dependent control of herpes virus HSV-1 and HSV-2 infections in the central nervous system (PubMed:22851595). Acts both as a positive and negative regulator of the mTORC1 complex, depending on the context: activates mTORC1 in response to growth factors by catalyzing phosphorylation of MTOR, while it limits the mTORC1 complex by promoting phosphorylation of RPTOR (PubMed:29150432, PubMed:31530866).', 'TBK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Amyotrophic lateral sclerosis, Antiviral defense, ATP-binding, Coiled coil, Cytoplasm, Disease variant, Glaucoma, Host-virus interaction, Immunity, Innate immunity, Isopeptide bond, Kinase, Neurodegeneration, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (264, '4OBO', '', 'Mitogen-activated protein kinase kinase kinase kinase 4', 'Serine/threonine kinase that may play a role in the response to environmental stress and cytokines such as TNF-alpha. Appears to act upstream of the JUN N-terminal pathway. Phosphorylates SMAD1 on Thr-322.', 'MAP4K4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (265, '7UKZ', '', 'Cyclin-dependent kinase 11B', 'Plays multiple roles in cell cycle progression, cytokinesis and apoptosis. Involved in pre-mRNA splicing in a kinase activity-dependent manner. Isoform 7 may act as a negative regulator of normal cell cycle progression.', 'CDK11B', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative initiation, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (266, '1B6C', '', 'Peptidyl-prolyl cis-trans isomerase FKBP1A', 'Keeps in an inactive conformation TGFBR1, the TGF-beta type I serine/threonine kinase receptor, preventing TGF-beta receptor activation in absence of ligand. Recruits SMAD7 to ACVR1B which prevents the association of SMAD2 and SMAD3 with the activin receptor complex, thereby blocking the activin signal. May modulate the RYR1 calcium channel activity. PPIases accelerate the folding of proteins. It catalyzes the cis-trans isomerization of proline imidic peptide bonds in oligopeptides.', 'FKBP1A', 'Homo sapiens', '{[''5.2.1.8'']}', '3D-structure, Acetylation, Cytoplasm, Direct protein sequencing, Isomerase, Membrane, Reference proteome, Rotamase, Sarcoplasmic reticulum');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (267, '6BFN', '', 'Interleukin-1 receptor-associated kinase 1', 'Serine/threonine-protein kinase that plays a critical role in initiating innate immune response against foreign pathogens. Involved in Toll-like receptor (TLR) and IL-1R signaling pathways. Is rapidly recruited by MYD88 to the receptor-signaling complex upon TLR activation. Association with MYD88 leads to IRAK1 phosphorylation by IRAK4 and subsequent autophosphorylation and kinase activation. Phosphorylates E3 ubiquitin ligases Pellino proteins (PELI1, PELI2 and PELI3) to promote pellino-mediated polyubiquitination of IRAK1. Then, the ubiquitin-binding domain of IKBKG/NEMO binds to polyubiquitinated IRAK1 bringing together the IRAK1-MAP3K7/TAK1-TRAF6 complex and the NEMO-IKKA-IKKB complex. In turn, MAP3K7/TAK1 activates IKKs (CHUK/IKKA and IKBKB/IKKB) leading to NF-kappa-B nuclear translocation and activation. Alternatively, phosphorylates TIRAP to promote its ubiquitination and subsequent degradation. Phosphorylates the interferon regulatory factor 7 (IRF7) to induce its activation and translocation to the nucleus, resulting in transcriptional activation of type I IFN genes, which drive the cell in an antiviral state. When sumoylated, translocates to the nucleus and phosphorylates STAT3.', 'IRAK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Direct protein sequencing, Host-virus interaction, Immunity, Innate immunity, Isopeptide bond, Kinase, Lipid droplet, Magnesium, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (268, '1XJD', '', 'Protein kinase C theta type', 'Calcium-independent, phospholipid- and diacylglycerol (DAG)-dependent serine/threonine-protein kinase that mediates non-redundant functions in T-cell receptor (TCR) signaling, including T-cells activation, proliferation, differentiation and survival, by mediating activation of multiple transcription factors such as NF-kappa-B, JUN, NFATC1 and NFATC2. In TCR-CD3/CD28-co-stimulated T-cells, is required for the activation of NF-kappa-B and JUN, which in turn are essential for IL2 production, and participates in the calcium-dependent NFATC1 and NFATC2 transactivation. Mediates the activation of the canonical NF-kappa-B pathway (NFKB1) by direct phosphorylation of CARD11 on several serine residues, inducing CARD11 association with lipid rafts and recruitment of the BCL10-MALT1 complex, which then activates IKK complex, resulting in nuclear translocation and activation of NFKB1. May also play an indirect role in activation of the non-canonical NF-kappa-B (NFKB2) pathway. In the signaling pathway leading to JUN activation, acts by phosphorylating the mediator STK39/SPAK and may not act through MAP kinases signaling. Plays a critical role in TCR/CD28-induced NFATC1 and NFATC2 transactivation by participating in the regulation of reduced inositol 1,4,5-trisphosphate generation and intracellular calcium mobilization. After costimulation of T-cells through CD28 can phosphorylate CBLB and is required for the ubiquitination and subsequent degradation of CBLB, which is a prerequisite for the activation of TCR. During T-cells differentiation, plays an important role in the development of T-helper 2 (Th2) cells following immune and inflammatory responses, and, in the development of inflammatory autoimmune diseases, is necessary for the activation of IL17-producing Th17 cells. May play a minor role in Th1 response. Upon TCR stimulation, mediates T-cell protective survival signal by phosphorylating BAD, thus protecting T-cells from BAD-induced apoptosis, and by up-regulating BCL-X(L)/BCL2L1 levels through NF-kappa-B and JUN pathways. In platelets, regulates signal transduction downstream of the ITGA2B, CD36/GP4, F2R/PAR1 and F2RL3/PAR4 receptors, playing a positive role in ''outside-in'' signaling and granule secretion signal transduction. May relay signals from the activated ITGA2B receptor by regulating the uncoupling of WASP and WIPF1, thereby permitting the regulation of actin filament nucleation and branching activity of the Arp2/3 complex. May mediate inhibitory effects of free fatty acids on insulin signaling by phosphorylating IRS1, which in turn blocks IRS1 tyrosine phosphorylation and downstream activation of the PI3K/AKT pathway. Phosphorylates MSN (moesin) in the presence of phosphatidylglycerol or phosphatidylinositol. Phosphorylates PDPK1 at ''Ser-504'' and ''Ser-532'' and negatively regulates its ability to phosphorylate PKB/AKT1. Phosphorylates CCDC88A/GIV and inhibits its guanine nucleotide exchange factor activity (PubMed:23509302).', 'PRKCQ', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Immunity, Inflammatory response, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (282, '3GGF', '', 'Serine/threonine-protein kinase 26', 'Serine/threonine-protein kinase that acts as a mediator of cell growth (PubMed:11641781, PubMed:17360971). Modulates apoptosis (PubMed:11641781, PubMed:17360971). In association with STK24 negatively regulates Golgi reorientation in polarized cell migration upon RHO activation (PubMed:27807006). Phosphorylates ATG4B at ''Ser-383'', thereby increasing autophagic flux (PubMed:29232556).', 'STK26', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Golgi apparatus, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (269, '4QT8', '', 'Macrophage-stimulating protein receptor', 'Receptor tyrosine kinase that transduces signals from the extracellular matrix into the cytoplasm by binding to MST1 ligand. Regulates many physiological processes including cell survival, migration and differentiation. Ligand binding at the cell surface induces autophosphorylation of RON on its intracellular domain that provides docking sites for downstream signaling molecules. Following activation by ligand, interacts with the PI3-kinase subunit PIK3R1, PLCG1 or the adapter GAB1. Recruitment of these downstream effectors by RON leads to the activation of several signaling cascades including the RAS-ERK, PI3 kinase-AKT, or PLCgamma-PKC. RON signaling activates the wound healing response by promoting epithelial cell migration, proliferation as well as survival at the wound site. Also plays a role in the innate immune response by regulating the migration and phagocytic activity of macrophages. Alternatively, RON can also promote signals such as cell migration and proliferation in response to growth factors other than MST1 ligand.', 'MST1R', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cleavage on pair of basic residues, Disease variant, Disulfide bond, Glycoprotein, Immunity, Innate immunity, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (270, '3QUP', '', 'Tyrosine-protein kinase receptor TYRO3', 'Receptor tyrosine kinase that transduces signals from the extracellular matrix into the cytoplasm by binding to several ligands including TULP1 or GAS6. Regulates many physiological processes including cell survival, migration and differentiation. Ligand binding at the cell surface induces dimerization and autophosphorylation of TYRO3 on its intracellular domain that provides docking sites for downstream signaling molecules. Following activation by ligand, interacts with PIK3R1 and thereby enhances PI3-kinase activity. Activates the AKT survival pathway, including nuclear translocation of NF-kappa-B and up-regulation of transcription of NF-kappa-B-regulated genes. TYRO3 signaling plays a role in various processes such as neuron protection from excitotoxic injury, platelet aggregation and cytoskeleton reorganization. Also plays an important role in inhibition of Toll-like receptors (TLRs)-mediated innate immune response by activating STAT1, which selectively induces production of suppressors of cytokine signaling SOCS1 and SOCS3.', 'Tyro3', 'Mus musculus', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell membrane, Disulfide bond, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (271, '6WHB', '', 'Mitogen-activated protein kinase kinase kinase 1', 'Component of a protein kinase signal transduction cascade (PubMed:9808624). Activates the ERK and JNK kinase pathways by phosphorylation of MAP2K1 and MAP2K4 (PubMed:9808624). May phosphorylate the MAPK8/JNK1 kinase (PubMed:17761173). Activates CHUK and IKBKB, the central protein kinases of the NF-kappa-B pathway (PubMed:9808624).', 'MAP3K1', 'Homo sapiens', '{[''2.7.11.25'',''2.3.2.27'']}', '3D-structure, Acetylation, ATP-binding, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (272, '7MO7', '', 'Hepatocyte growth factor', 'Potent mitogen for mature parenchymal hepatocyte cells, seems to be a hepatotrophic factor, and acts as a growth factor for a broad spectrum of tissues and cell types (PubMed:20624990). Activating ligand for the receptor tyrosine kinase MET by binding to it and promoting its dimerization (PubMed:20977675, PubMed:15167892). Activates MAPK signaling following TMPRSS13 cleavage and activation (PubMed:20977675).', 'HGF', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Deafness, Direct protein sequencing, Disulfide bond, Glycoprotein, Growth factor, Kringle, Non-syndromic deafness, Pyrrolidone carboxylic acid, Reference proteome, Repeat, Serine protease homolog, Signal');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (273, '2W4O', '', 'Calcium/calmodulin-dependent protein kinase type IV', 'Calcium/calmodulin-dependent protein kinase that operates in the calcium-triggered CaMKK-CaMK4 signaling cascade and regulates, mainly by phosphorylation, the activity of several transcription activators, such as CREB1, MEF2D, JUN and RORA, which play pivotal roles in immune response, inflammation, and memory consolidation. In the thymus, regulates the CD4(+)/CD8(+) double positive thymocytes selection threshold during T-cell ontogeny. In CD4 memory T-cells, is required to link T-cell antigen receptor (TCR) signaling to the production of IL2, IFNG and IL4 (through the regulation of CREB and MEF2). Regulates the differentiation and survival phases of osteoclasts and dendritic cells (DCs). Mediates DCs survival by linking TLR4 and the regulation of temporal expression of BCL2. Phosphorylates the transcription activator CREB1 on ''Ser-133'' in hippocampal neuron nuclei and contribute to memory consolidation and long term potentiation (LTP) in the hippocampus. Can activate the MAP kinases MAPK1/ERK2, MAPK8/JNK1 and MAPK14/p38 and stimulate transcription through the phosphorylation of ELK1 and ATF2. Can also phosphorylate in vitro CREBBP, PRM2, MEF2A and STMN1/OP18.', 'CAMK4', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Adaptive immunity, ATP-binding, Calcium, Calmodulin-binding, Cytoplasm, Glycoprotein, Immunity, Inflammatory response, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (274, '8X2A', '', 'Cytoplasmic tyrosine-protein kinase BMX', 'Non-receptor tyrosine kinase that plays central but diverse modulatory roles in various signaling processes involved in the regulation of actin reorganization, cell migration, cell proliferation and survival, cell adhesion, and apoptosis. Participates in signal transduction stimulated by growth factor receptors, cytokine receptors, G-protein coupled receptors, antigen receptors and integrins. Induces tyrosine phosphorylation of BCAR1 in response to integrin regulation. Activation of BMX by integrins is mediated by PTK2/FAK1, a key mediator of integrin signaling events leading to the regulation of actin cytoskeleton and cell motility. Plays a critical role in TNF-induced angiogenesis, and implicated in the signaling of TEK and FLT1 receptors, 2 important receptor families essential for angiogenesis. Required for the phosphorylation and activation of STAT3, a transcription factor involved in cell differentiation. Also involved in interleukin-6 (IL6) induced differentiation. Also plays a role in programming adaptive cytoprotection against extracellular stress in different cell systems, salivary epithelial cells, brain endothelial cells, and dermal fibroblasts. May be involved in regulation of endocytosis through its interaction with an endosomal protein RUFY1. May also play a role in the growth and differentiation of hematopoietic cells; as well as in signal transduction in endocardial and arterial endothelial cells.', 'BMX', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Apoptosis, ATP-binding, Cell adhesion, Cytoplasm, Direct protein sequencing, Kinase, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, SH2 domain, Stress response, Transferase, Tyrosine-protein kinase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (275, '5HGI', '', 'Serine/threonine-protein kinase/endoribonuclease IRE1', 'Serine/threonine-protein kinase and endoribonuclease that acts as a key sensor for the endoplasmic reticulum unfolded protein response (UPR) (PubMed:11175748, PubMed:11779464, PubMed:12637535, PubMed:21317875, PubMed:28128204, PubMed:9637683, PubMed:30118681). In unstressed cells, the endoplasmic reticulum luminal domain is maintained in its inactive monomeric state by binding to the endoplasmic reticulum chaperone HSPA5/BiP (PubMed:21317875). Accumulation of misfolded proteins in the endoplasmic reticulum causes release of HSPA5/BiP, allowing the luminal domain to homodimerize, promoting autophosphorylation of the kinase domain and subsequent activation of the endoribonuclease activity (PubMed:21317875). The endoribonuclease activity is specific for XBP1 mRNA and excises 26 nucleotides from XBP1 mRNA (PubMed:11779464, PubMed:24508390, PubMed:21317875). The resulting spliced transcript of XBP1 encodes a transcriptional activator protein that up-regulates expression of UPR target genes (PubMed:11779464, PubMed:24508390, PubMed:21317875). Acts as an upstream signal for ER stress-induced GORASP2-mediated unconventional (ER/Golgi-independent) trafficking of CFTR to cell membrane by modulating the expression and localization of SEC16A (PubMed:21884936, PubMed:28067262).', 'ERN1', 'Homo sapiens', '{[''2.7.11.1'',''3.1.26.-'']}', '3D-structure, ADP-ribosylation, Alternative splicing, Apoptosis, ATP-binding, Disulfide bond, Endoplasmic reticulum, Glycoprotein, Hydrolase, Kinase, Magnesium, Membrane, Metal-binding, Multifunctional enzyme, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Signal, Transcription, Transcription regulation, Transferase, Transmembrane, Transmembrane helix, Unfolded protein response');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (276, '2WWE', '', 'Phosphatidylinositol 3-kinase C2 domain-containing subunit gamma', 'Generates phosphatidylinositol 3-phosphate (PtdIns3P) and phosphatidylinositol 3,4-bisphosphate (PtdIns(3,4)P2) that act as second messengers (By similarity). May play a role in SDF1A-stimulated chemotaxis (By similarity).', 'PIK3C2G', 'Homo sapiens', '{[''2.7.1.137'',''2.7.1.154'']}', '3D-structure, Alternative splicing, ATP-binding, Chemotaxis, Kinase, Lipid metabolism, Membrane, Nucleotide-binding, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (277, '4WIH', '', 'cAMP-dependent protein kinase catalytic subunit alpha', 'Phosphorylates a large number of substrates in the cytoplasm and the nucleus (By similarity). Phosphorylates CDC25B, ABL1, NFKB1, CLDN3, PSMC5/RPT6, PJA2, RYR2, RORA, SOX9 and VASP (By similarity). Regulates the abundance of compartmentalized pools of its regulatory subunits through phosphorylation of PJA2 which binds and ubiquitinates these subunits, leading to their subsequent proteolysis. RORA is activated by phosphorylation. Required for glucose-mediated adipogenic differentiation increase and osteogenic differentiation inhibition from osteoblasts (By similarity). Involved in chondrogenesis by mediating phosphorylation of SOX9 (By similarity). Involved in the regulation of platelets in response to thrombin and collagen; maintains circulating platelets in a resting state by phosphorylating proteins in numerous platelet inhibitory pathways when in complex with NF-kappa-B (NFKB1 and NFKB2) and I-kappa-B-alpha (NFKBIA), but thrombin and collagen disrupt these complexes and free active PRKACA stimulates platelets and leads to platelet aggregation by phosphorylating VASP. RYR2 channel activity is potentiated by phosphorylation in presence of luminal Ca(2+), leading to reduced amplitude and increased frequency of store overload-induced Ca(2+) release (SOICR) characterized by an increased rate of Ca(2+) release and propagation velocity of spontaneous Ca(2+) waves, despite reduced wave amplitude and resting cytosolic Ca(2+). PSMC5/RPT6 activation by phosphorylation stimulates proteasome. Negatively regulates tight junctions (TJs) in ovarian cancer cells via CLDN3 phosphorylation. NFKB1 phosphorylation promotes NF-kappa-B p50-p50 DNA binding. Required for phosphorylation of GLI transcription factors which inhibits them and prevents transcriptional activation of Hedgehog signaling pathway target genes (By similarity). GLI transcription factor phosphorylation is inhibited by interaction of PRKACA with SMO which sequesters PRKACA at the cell membrane (By similarity). Involved in embryonic development by down-regulating the Hedgehog (Hh) signaling pathway that determines embryo pattern formation and morphogenesis most probably through the regulation of OFD1 in ciliogenesis (By similarity). Prevents meiosis resumption in prophase-arrested oocytes via CDC25B inactivation by phosphorylation (By similarity). May also regulate rapid eye movement (REM) sleep in the pedunculopontine tegmental (PPT) (By similarity). Phosphorylates APOBEC3G and AICDA. Phosphorylates HSF1; this phosphorylation promotes HSF1 nuclear localization and transcriptional activity upon heat shock (By similarity). Acts as a negative regulator of mTORC1 by mediating phosphorylation of RPTOR (By similarity).', 'PRKACA', 'Cricetulus griseus', '{[''2.7.11.11'']}', '3D-structure, ATP-binding, cAMP, Cell membrane, Cytoplasm, Kinase, Lipoprotein, Membrane, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (278, '1A06', '', 'Calcium/calmodulin-dependent protein kinase type 1', 'Calcium/calmodulin-dependent protein kinase that operates in the calcium-triggered CaMKK-CaMK1 signaling cascade and, upon calcium influx, regulates transcription activators activity, cell cycle, hormone production, cell differentiation, actin filament organization and neurite outgrowth. Recognizes the substrate consensus sequence [MVLIF]-x-R-x(2)-[ST]-x(3)-[MVLIF]. Regulates axonal extension and growth cone motility in hippocampal and cerebellar nerve cells. Upon NMDA receptor-mediated Ca(2+) elevation, promotes dendritic growth in hippocampal neurons and is essential in synapses for full long-term potentiation (LTP) and ERK2-dependent translational activation. Downstream of NMDA receptors, promotes the formation of spines and synapses in hippocampal neurons by phosphorylating ARHGEF7/BETAPIX on ''Ser-516'', which results in the enhancement of ARHGEF7 activity and activation of RAC1. Promotes neuronal differentiation and neurite outgrowth by activation and phosphorylation of MARK2 on ''Ser-91'', ''Ser-92'', ''Ser-93'' and ''Ser-294''. Promotes nuclear export of HDAC5 and binding to 14-3-3 by phosphorylation of ''Ser-259'' and ''Ser-498'' in the regulation of muscle cell differentiation (By similarity). Regulates NUMB-mediated endocytosis by phosphorylation of NUMB on ''Ser-275'' and ''Ser-294''. Involved in the regulation of basal and estrogen-stimulated migration of medulloblastoma cells through ARHGEF7/BETAPIX phosphorylation (By similarity). Is required for proper activation of cyclin-D1/CDK4 complex during G1 progression in diploid fibroblasts. Plays a role in K(+) and ANG2-mediated regulation of the aldosterone synthase (CYP11B2) to produce aldosterone in the adrenal cortex. Phosphorylates EIF4G3/eIF4GII. In vitro phosphorylates CREB1, ATF1, CFTR, MYL9 and SYN1/synapsin I.', 'Camk1', 'Rattus norvegicus', '{[''2.7.11.17'']}', '3D-structure, Allosteric enzyme, ATP-binding, Calmodulin-binding, Cell cycle, Cytoplasm, Developmental protein, Differentiation, Direct protein sequencing, Isopeptide bond, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (279, '3TTI', '', 'Mitogen-activated protein kinase 10', 'Serine/threonine-protein kinase involved in various processes such as neuronal proliferation, differentiation, migration and programmed cell death. Extracellular stimuli such as pro-inflammatory cytokines or physical stress stimulate the stress-activated protein kinase/c-Jun N-terminal kinase (SAP/JNK) signaling pathway. In this cascade, two dual specificity kinases MAP2K4/MKK4 and MAP2K7/MKK7 phosphorylate and activate MAPK10/JNK3. In turn, MAPK10/JNK3 phosphorylates a number of transcription factors, primarily components of AP-1 such as JUN and ATF2 and thus regulates AP-1 transcriptional activity. Plays regulatory roles in the signaling pathways during neuronal apoptosis. Phosphorylates the neuronal microtubule regulator STMN2. Acts in the regulation of the amyloid-beta precursor protein/APP signaling during neuronal differentiation by phosphorylating APP. Participates also in neurite growth in spiral ganglion neurons. Phosphorylates the CLOCK-BMAL1 heterodimer and plays a role in the photic regulation of the circadian clock (PubMed:22441692). Phosphorylates JUND and this phosphorylation is inhibited in the presence of MEN1 (PubMed:22327296).', 'MAPK10', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Biological rhythms, Chromosomal rearrangement, Cytoplasm, Direct protein sequencing, Epilepsy, Intellectual disability, Kinase, Lipoprotein, Membrane, Mitochondrion, Nucleotide-binding, Nucleus, Palmitate, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (280, '1BO1', '', 'Phosphatidylinositol 5-phosphate 4-kinase type-2 beta', 'Participates in the biosynthesis of phosphatidylinositol 4,5-bisphosphate (PubMed:9038203, PubMed:26774281). Preferentially utilizes GTP, rather than ATP, for PI(5)P phosphorylation and its activity reflects changes in direct proportion to the physiological GTP concentration (PubMed:26774281). Its GTP-sensing activity is critical for metabolic adaptation (PubMed:26774281). PIP4Ks negatively regulate insulin signaling through a catalytic-independent mechanism. They interact with PIP5Ks and suppress PIP5K-mediated PtdIns(4,5)P2 synthesis and insulin-dependent conversion to PtdIns(3,4,5)P3 (PubMed:31091439).', 'PIP4K2B', 'Homo sapiens', '{[''2.7.1.149'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Endoplasmic reticulum, GTP-binding, Kinase, Lipid metabolism, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (281, '6KYQ', '', 'Serine/threonine-protein kinase DCLK1', 'Probable kinase that may be involved in a calcium-signaling pathway controlling neuronal migration in the developing brain. May also participate in functions of the mature nervous system.', 'DCLK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Developmental protein, Differentiation, Kinase, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (284, '6EIX', '', 'Activin receptor type-1', 'Bone morphogenetic protein (BMP) type I receptor that is involved in a wide variety of biological processes, including bone, heart, cartilage, nervous, and reproductive system development and regulation (PubMed:20628059, PubMed:22977237). As a type I receptor, forms heterotetrameric receptor complexes with the type II receptors AMHR2, ACVR2A or ACVR2B (PubMed:17911401). Upon binding of ligands such as BMP7 or GDF2/BMP9 to the heteromeric complexes, type II receptors transphosphorylate ACVR1 intracellular domain (PubMed:25354296). In turn, ACVR1 kinase domain is activated and subsequently phosphorylates SMAD1/5/8 proteins that transduce the signal (PubMed:9748228). In addition to its role in mediating BMP pathway-specific signaling, suppresses TGFbeta/activin pathway signaling by interfering with the binding of activin to its type II receptor (PubMed:17911401). Besides canonical SMAD signaling, can activate non-canonical pathways such as p38 mitogen-activated protein kinases/MAPKs (By similarity). May promote the expression of HAMP, potentially via its interaction with BMP6 (By similarity).', 'ACVR1', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, ATP-binding, Disease variant, Glycoprotein, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (285, '5DE2', '', 'Serine/threonine-protein kinase Nek7', 'Protein kinase which plays an important role in mitotic cell cycle progression (PubMed:17101132, PubMed:31409757, PubMed:19941817). Required for microtubule nucleation activity of the centrosome, robust mitotic spindle formation and cytokinesis (PubMed:17586473, PubMed:19414596, PubMed:31409757, PubMed:19941817, PubMed:26522158). Phosphorylates EML4 at ''Ser-146'', promoting its dissociation from microtubules during mitosis which is required for efficient chromosome congression (PubMed:31409757). Phosphorylates RPS6KB1 (By similarity). Acts as an essential activator of the NLRP3 inflammasome assembly independently of its kinase activity (PubMed:26642356, PubMed:36442502). Acts by unlocking NLRP3 following NLRP3 tranlocation into the microtubule organizing center (MTOC), relieving NLRP3 autoinhibition and promoting formation of the NLRP3:PYCARD complex, and activation of CASP1 (PubMed:26642356, PubMed:31189953, PubMed:36442502). Serves as a cellular switch that enforces mutual exclusivity of the inflammasome response and cell division: interaction with NEK9 prevents interaction with NLRP3 and activation of the inflammasome during mitosis (PubMed:26642356, PubMed:31189953).', 'NEK7', 'Homo sapiens', '{[''2.7.11.34'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Kinase, Magnesium, Metal-binding, Microtubule, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (286, '6G6W', '', 'Phosphatidylinositol 4,5-bisphosphate 3-kinase catalytic subunit delta isoform', 'Phosphoinositide-3-kinase (PI3K) phosphorylates phosphatidylinositol (PI) and its phosphorylated derivatives at position 3 of the inositol ring to produce 3-phosphoinositides (PubMed:9235916). Uses ATP and PtdIns(4,5)P2 (phosphatidylinositol 4,5-bisphosphate) to generate phosphatidylinositol 3,4,5-trisphosphate (PIP3) (PubMed:15135396). PIP3 plays a key role by recruiting PH domain-containing proteins to the membrane, including AKT1 and PDPK1, activating signaling cascades involved in cell growth, survival, proliferation, motility and morphology. Mediates immune responses. Plays a role in B-cell development, proliferation, migration, and function. Required for B-cell receptor (BCR) signaling. Mediates B-cell proliferation response to anti-IgM, anti-CD40 and IL4 stimulation. Promotes cytokine production in response to TLR4 and TLR9. Required for antibody class switch mediated by TLR9. Involved in the antigen presentation function of B-cells. Involved in B-cell chemotaxis in response to CXCL13 and sphingosine 1-phosphate (S1P). Required for proliferation, signaling and cytokine production of naive, effector and memory T-cells. Required for T-cell receptor (TCR) signaling. Mediates TCR signaling events at the immune synapse. Activation by TCR leads to antigen-dependent memory T-cell migration and retention to antigenic tissues. Together with PIK3CG participates in T-cell development. Contributes to T-helper cell expansion and differentiation. Required for T-cell migration mediated by homing receptors SELL/CD62L, CCR7 and S1PR1 and antigen dependent recruitment of T-cells. Together with PIK3CG is involved in natural killer (NK) cell development and migration towards the sites of inflammation. Participates in NK cell receptor activation. Plays a role in NK cell maturation and cytokine production. Together with PIK3CG is involved in neutrophil chemotaxis and extravasation. Together with PIK3CG participates in neutrophil respiratory burst. Plays important roles in mast-cell development and mast cell mediated allergic response. Involved in stem cell factor (SCF)-mediated proliferation, adhesion and migration. Required for allergen-IgE-induced degranulation and cytokine release. The lipid kinase activity is required for its biological function. Isoform 2 may be involved in stabilizing total RAS levels, resulting in increased ERK phosphorylation and increased PI3K activity.', 'PIK3CD', 'Homo sapiens', '{[''2.7.1.153'',''2.7.1.137'']}', '3D-structure, Adaptive immunity, Alternative splicing, ATP-binding, Chemotaxis, Cytoplasm, Differentiation, Direct protein sequencing, Disease variant, Immunity, Inflammatory response, Innate immunity, Kinase, Lipid metabolism, Nucleotide-binding, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (287, '3TKU', '', 'Serine/threonine-protein kinase MRCK beta', 'Serine/threonine-protein kinase which is an important downstream effector of CDC42 and plays a role in the regulation of cytoskeleton reorganization and cell migration. Regulates actin cytoskeletal reorganization via phosphorylation of PPP1R12C and MYL9/MLC2 (PubMed:21457715, PubMed:21949762). In concert with MYO18A and LURAP1, is involved in modulating lamellar actomyosin retrograde flow that is crucial to cell protrusion and migration (PubMed:18854160). Phosphorylates PPP1R12A (PubMed:21457715). In concert with FAM89B/LRAP25 mediates the targeting of LIMK1 to the lamellipodium resulting in its activation and subsequent phosphorylation of CFL1 which is important for lamellipodial F-actin regulation (By similarity).', 'CDC42BPB', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell junction, Cell membrane, Cell projection, Coiled coil, Cytoplasm, Disease variant, Intellectual disability, Kinase, Magnesium, Membrane, Metal-binding, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (288, '8C2Z', '', 'Dual specificity tyrosine-phosphorylation-regulated kinase 1B', 'Dual-specificity kinase which possesses both serine/threonine and tyrosine kinase activities. Plays an essential role in ribosomal DNA (rDNA) double-strand break repair and rDNA copy number maintenance (PubMed:33469661). During DNA damage, mediates transcription silencing in part via phosphorylating and enforcing DSB accumulation of the histone methyltransferase EHMT2 (PubMed:32611815). Enhances the transcriptional activity of TCF1/HNF1A and FOXO1. Inhibits epithelial cell migration. Mediates colon carcinoma cell survival in mitogen-poor environments. Inhibits the SHH and WNT1 pathways, thereby enhancing adipogenesis. In addition, promotes expression of the gluconeogenic enzyme glucose-6-phosphatase catalytic subunit 1 (G6PC1).', 'DYRK1B', 'Homo sapiens', '{[''2.7.12.1'']}', 'Alternative splicing, ATP-binding, Chromosome, Diabetes mellitus, DNA damage, DNA repair, Kinase, Nucleotide-binding, Nucleus, Obesity, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (289, '5VDK', '', 'Wee1-like protein kinase 2', 'Oocyte-specific protein tyrosine kinase that phosphorylates and inhibits CDK1/CDC2 and acts as a key regulator of meiosis during both prophase I and metaphase II (PubMed:29606300). Required to maintain meiotic arrest in oocytes during the germinal vesicle (GV) stage, a long period of quiescence at dictyate prophase I, by phosphorylating CDK1 at ''Tyr-15'', leading to inhibit CDK1 activity and prevent meiotic reentry. Also required for metaphase II exit during egg activation by phosphorylating CDK1 at ''Tyr-15'', to ensure exit from meiosis in oocytes and promote pronuclear formation (By similarity).', 'WEE2', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, ATP-binding, Coiled coil, Disease variant, Kinase, Magnesium, Meiosis, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (290, '4DC2', '', 'Protein kinase C iota type', 'Calcium- and diacylglycerol-independent serine/ threonine-protein kinase that plays a general protective role against apoptotic stimuli, is involved in NF-kappa-B activation, cell survival, differentiation and polarity, and contributes to the regulation of microtubule dynamics in the early secretory pathway. Is necessary for BCR-ABL oncogene-mediated resistance to apoptotic drug in leukemia cells, protecting leukemia cells against drug-induced apoptosis. In cultured neurons, prevents amyloid beta protein-induced apoptosis by interrupting cell death process at a very early step. In glioblastoma cells, may function downstream of phosphatidylinositol 3-kinase (PI3K) and PDPK1 in the promotion of cell survival by phosphorylating and inhibiting the pro-apoptotic factor BAD. Can form a protein complex in non-small cell lung cancer (NSCLC) cells with PARD6A and ECT2 and regulate ECT2 oncogenic activity by phosphorylation, which in turn promotes transformed growth and invasion. In response to nerve growth factor (NGF), acts downstream of SRC to phosphorylate and activate IRAK1, allowing the subsequent activation of NF-kappa-B and neuronal cell survival. Functions in the organization of the apical domain in epithelial cells by phosphorylating EZR. This step is crucial for activation and normal distribution of EZR at the early stages of intestinal epithelial cell differentiation. Forms a protein complex with LLGL1 and PARD6B independently of PARD3 to regulate epithelial cell polarity. Plays a role in microtubule dynamics in the early secretory pathway through interaction with RAB2A and GAPDH and recruitment to vesicular tubular clusters (VTCs). In human coronary artery endothelial cells (HCAEC), is activated by saturated fatty acids and mediates lipid-induced apoptosis (By similarity). Downstream of PI3K is required for insulin-stimulated glucose transport. Activates RAB4A and promotes its association with KIF3A which is required for the insulin-induced SLC2A4/GLUT4 translocation in adipocytes. Is essential in early embryogenesis and development of differentiating photoreceptors by playing a role in the establishment of epithelial and neuronal polarity. Involved in early synaptic long term potentiation phase in CA1 hippocampal cells and short term memory formation (By similarity).', 'Prkci', 'Mus musculus', '{[''2.7.11.13'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Developmental protein, Endosome, Kinase, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Tumor suppressor, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (291, '4FR4', '', 'Serine/threonine-protein kinase 32A', 'Unknown', 'STK32A', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Kinase, Lipoprotein, Magnesium, Membrane, Metal-binding, Myristate, Nucleotide-binding, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (292, '6YAT', '', 'Serine/threonine-protein kinase 4', 'Stress-activated, pro-apoptotic kinase which, following caspase-cleavage, enters the nucleus and induces chromatin condensation followed by internucleosomal DNA fragmentation. Key component of the Hippo signaling pathway which plays a pivotal role in organ size control and tumor suppression by restricting proliferation and promoting apoptosis. The core of this pathway is composed of a kinase cascade wherein STK3/MST2 and STK4/MST1, in complex with its regulatory protein SAV1, phosphorylates and activates LATS1/2 in complex with its regulatory protein MOB1, which in turn phosphorylates and inactivates YAP1 oncoprotein and WWTR1/TAZ. Phosphorylation of YAP1 by LATS2 inhibits its translocation into the nucleus to regulate cellular genes important for cell proliferation, cell death, and cell migration. STK3/MST2 and STK4/MST1 are required to repress proliferation of mature hepatocytes, to prevent activation of facultative adult liver stem cells (oval cells), and to inhibit tumor formation (By similarity). Phosphorylates ''Ser-14'' of histone H2B (H2BS14ph) during apoptosis. Phosphorylates FOXO3 upon oxidative stress, which results in its nuclear translocation and cell death initiation. Phosphorylates MOBKL1A, MOBKL1B and RASSF2. Phosphorylates TNNI3 (cardiac Tn-I) and alters its binding affinity to TNNC1 (cardiac Tn-C) and TNNT2 (cardiac Tn-T). Phosphorylates FOXO1 on ''Ser-212'' and regulates its activation and stimulates transcription of PMAIP1 in a FOXO1-dependent manner. Phosphorylates SIRT1 and inhibits SIRT1-mediated p53/TP53 deacetylation, thereby promoting p53/TP53 dependent transcription and apoptosis upon DNA damage. Acts as an inhibitor of PKB/AKT1. Phosphorylates AR on ''Ser-650'' and suppresses its activity by intersecting with PKB/AKT1 signaling and antagonizing formation of AR-chromatin complexes.', 'STK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Direct protein sequencing, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (293, '1QCF', '', 'Tyrosine-protein kinase HCK', 'Non-receptor tyrosine-protein kinase found in hematopoietic cells that transmits signals from cell surface receptors and plays an important role in the regulation of innate immune responses, including neutrophil, monocyte, macrophage and mast cell functions, phagocytosis, cell survival and proliferation, cell adhesion and migration. Acts downstream of receptors that bind the Fc region of immunoglobulins, such as FCGR1A and FCGR2A, but also CSF3R, PLAUR, the receptors for IFNG, IL2, IL6 and IL8, and integrins, such as ITGB1 and ITGB2. During the phagocytic process, mediates mobilization of secretory lysosomes, degranulation, and activation of NADPH oxidase to bring about the respiratory burst. Plays a role in the release of inflammatory molecules. Promotes reorganization of the actin cytoskeleton and actin polymerization, formation of podosomes and cell protrusions. Inhibits TP73-mediated transcription activation and TP73-mediated apoptosis. Phosphorylates CBL in response to activation of immunoglobulin gamma Fc region receptors. Phosphorylates ADAM15, BCR, ELMO1, FCGR2A, GAB1, GAB2, RAPGEF1, STAT5B, TP73, VAV1 and WAS.', 'HCK', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative initiation, Alternative splicing, ATP-binding, Cell junction, Cell membrane, Cell projection, Cytoplasm, Cytoplasmic vesicle, Cytoskeleton, Exocytosis, Golgi apparatus, Host-virus interaction, Immunity, Inflammatory response, Innate immunity, Kinase, Lipoprotein, Lysosome, Membrane, Myristate, Nucleotide-binding, Nucleus, Palmitate, Phagocytosis, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (294, '6TM5', '', 'Anaphase-promoting complex subunit 1', 'Component of the anaphase promoting complex/cyclosome (APC/C), a cell cycle-regulated E3 ubiquitin ligase that controls progression through mitosis and the G1 phase of the cell cycle. The APC/C complex acts by mediating ubiquitination and subsequent degradation of target proteins: it mainly mediates the formation of ''Lys-11''-linked polyubiquitin chains and, to a lower extent, the formation of ''Lys-48''- and ''Lys-63''-linked polyubiquitin chains.', 'ANAPC1', 'Homo sapiens', '{[]}', '3D-structure, Cell cycle, Cell division, Ectodermal dysplasia, Hypotrichosis, Mitosis, Phosphoprotein, Reference proteome, Repeat, Ubl conjugation pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (300, '4XI2', '', 'Tyrosine-protein kinase BTK', 'Non-receptor tyrosine kinase indispensable for B lymphocyte development, differentiation and signaling (PubMed:7538439, PubMed:8629002, PubMed:10852954). Binding of antigen to the B-cell antigen receptor (BCR) triggers signaling that ultimately leads to B-cell activation (By similarity). After BCR engagement and activation at the plasma membrane, phosphorylates PLCG2 at several sites, igniting the downstream signaling pathway through calcium mobilization, followed by activation of the protein kinase C (PKC) family members (By similarity). PLCG2 phosphorylation is performed in close cooperation with the adapter protein B-cell linker protein BLNK (By similarity). BTK acts as a platform to bring together a diverse array of signaling proteins and is implicated in cytokine receptor signaling pathways (By similarity). Plays an important role in the function of immune cells of innate as well as adaptive immunity, as a component of the Toll-like receptors (TLR) pathway (PubMed:17725607). The TLR pathway acts as a primary surveillance system for the detection of pathogens and are crucial to the activation of host defense (By similarity). Especially, is a critical molecule in regulating TLR9 activation in splenic B-cells (By similarity). Within the TLR pathway, induces tyrosine phosphorylation of TIRAP which leads to TIRAP degradation (By similarity). BTK also plays a critical role in transcription regulation (By similarity). Induces the activity of NF-kappa-B, which is involved in regulating the expression of hundreds of genes (By similarity). BTK is involved on the signaling pathway linking TLR8 and TLR9 to NF-kappa-B (By similarity). Acts as an activator of NLRP3 inflammasome assembly by mediating phosphorylation of NLRP3 (PubMed:34554188). Transiently phosphorylates transcription factor GTF2I on tyrosine residues in response to BCR (PubMed:11120822, PubMed:16738337). GTF2I then translocates to the nucleus to bind regulatory enhancer elements to modulate gene expression (PubMed:11120822, PubMed:16738337). ARID3A and NFAT are other transcriptional target of BTK (PubMed:11120822, PubMed:16738337). BTK is required for the formation of functional ARID3A DNA-binding complexes (PubMed:11120822, PubMed:16738337). There is however no evidence that BTK itself binds directly to DNA (PubMed:11120822, PubMed:16738337). BTK has a dual role in the regulation of apoptosis (By similarity).', 'Btk', 'Mus musculus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Adaptive immunity, Apoptosis, ATP-binding, Cell membrane, Cytoplasm, Direct protein sequencing, Disease variant, Immunity, Innate immunity, Kinase, Lipid-binding, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, SH2 domain, SH3 domain, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (295, '2F57', '', 'Serine/threonine-protein kinase PAK 5', 'Serine/threonine protein kinase that plays a role in a variety of different signaling pathways including cytoskeleton regulation, cell migration, proliferation or cell survival. Activation by various effectors including growth factor receptors or active CDC42 and RAC1 results in a conformational change and a subsequent autophosphorylation on several serine and/or threonine residues. Phosphorylates the proto-oncogene RAF1 and stimulates its kinase activity. Promotes cell survival by phosphorylating the BCL2 antagonist of cell death BAD. Phosphorylates CTNND1, probably to regulate cytoskeletal organization and cell morphology. Keeps microtubules stable through MARK2 inhibition and destabilizes the F-actin network leading to the disappearance of stress fibers and focal adhesions.', 'PAK5', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Apoptosis, ATP-binding, Cytoplasm, Kinase, Mitochondrion, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (296, '6BDN', '', 'Serine/threonine-protein kinase TAO3', 'Serine/threonine-protein kinase that acts as a regulator of the p38/MAPK14 stress-activated MAPK cascade and of the MAPK8/JNK cascade. Acts as an activator of the p38/MAPK14 stress-activated MAPK cascade. In response to DNA damage, involved in the G2/M transition DNA damage checkpoint by activating the p38/MAPK14 stress-activated MAPK cascade, probably by mediating phosphorylation of upstream MAP2K3 and MAP2K6 kinases. Inhibits basal activity of MAPK8/JNK cascade and diminishes its activation in response epidermal growth factor (EGF).', 'TAOK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cell membrane, Coiled coil, Cytoplasm, DNA damage, DNA repair, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (297, '2R7B', '', '3-phosphoinositide-dependent protein kinase 1', 'Serine/threonine kinase which acts as a master kinase, phosphorylating and activating a subgroup of the AGC family of protein kinases. Its targets include: protein kinase B (PKB/AKT1, PKB/AKT2, PKB/AKT3), p70 ribosomal protein S6 kinase (RPS6KB1), p90 ribosomal protein S6 kinase (RPS6KA1, RPS6KA2 and RPS6KA3), cyclic AMP-dependent protein kinase (PRKACA), protein kinase C (PRKCD and PRKCZ), serum and glucocorticoid-inducible kinase (SGK1, SGK2 and SGK3), p21-activated kinase-1 (PAK1), protein kinase PKN (PKN1 and PKN2). Plays a central role in the transduction of signals from insulin by providing the activating phosphorylation to PKB/AKT1, thus propagating the signal to downstream targets controlling cell proliferation and survival, as well as glucose and amino acid uptake and storage. Negatively regulates the TGF-beta-induced signaling by: modulating the association of SMAD3 and SMAD7 with TGF-beta receptor, phosphorylating SMAD2, SMAD3, SMAD4 and SMAD7, preventing the nuclear translocation of SMAD3 and SMAD4 and the translocation of SMAD7 from the nucleus to the cytoplasm in response to TGF-beta. Activates PPARG transcriptional activity and promotes adipocyte differentiation. Activates the NF-kappa-B pathway via phosphorylation of IKKB. The tyrosine phosphorylated form is crucial for the regulation of focal adhesions by angiotensin II. Controls proliferation, survival, and growth of developing pancreatic cells. Participates in the regulation of Ca(2+) entry and Ca(2+)-activated K(+) channels of mast cells. Essential for the motility of vascular endothelial cells (ECs) and is involved in the regulation of their chemotaxis. Plays a critical role in cardiac homeostasis by serving as a dual effector for cell survival and beta-adrenergic response. Plays an important role during thymocyte development by regulating the expression of key nutrient receptors on the surface of pre-T cells and mediating Notch-induced cell growth and proliferative responses. Provides negative feedback inhibition to toll-like receptor-mediated NF-kappa-B activation in macrophages. Isoform 3 is catalytically inactive.', 'PDPK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Activator, Alternative splicing, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Direct protein sequencing, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (298, '2WQB', '', 'Angiopoietin-1 receptor', 'Tyrosine-protein kinase that acts as a cell-surface receptor for ANGPT1, ANGPT2 and ANGPT4 and regulates angiogenesis, endothelial cell survival, proliferation, migration, adhesion and cell spreading, reorganization of the actin cytoskeleton, but also maintenance of vascular quiescence. Has anti-inflammatory effects by preventing the leakage of pro-inflammatory plasma proteins and leukocytes from blood vessels. Required for normal angiogenesis and heart development during embryogenesis. Required for post-natal hematopoiesis. After birth, activates or inhibits angiogenesis, depending on the context. Inhibits angiogenesis and promotes vascular stability in quiescent vessels, where endothelial cells have tight contacts. In quiescent vessels, ANGPT1 oligomers recruit TEK to cell-cell contacts, forming complexes with TEK molecules from adjoining cells, and this leads to preferential activation of phosphatidylinositol 3-kinase and the AKT1 signaling cascades. In migrating endothelial cells that lack cell-cell adhesions, ANGT1 recruits TEK to contacts with the extracellular matrix, leading to the formation of focal adhesion complexes, activation of PTK2/FAK and of the downstream kinases MAPK1/ERK2 and MAPK3/ERK1, and ultimately to the stimulation of sprouting angiogenesis. ANGPT1 signaling triggers receptor dimerization and autophosphorylation at specific tyrosine residues that then serve as binding sites for scaffold proteins and effectors. Signaling is modulated by ANGPT2 that has lower affinity for TEK, can promote TEK autophosphorylation in the absence of ANGPT1, but inhibits ANGPT1-mediated signaling by competing for the same binding site. Signaling is also modulated by formation of heterodimers with TIE1, and by proteolytic processing that gives rise to a soluble TEK extracellular domain. The soluble extracellular domain modulates signaling by functioning as decoy receptor for angiopoietins. TEK phosphorylates DOK2, GRB7, GRB14, PIK3R1; SHC1 and TIE1.', 'TEK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Cytoskeleton, Direct protein sequencing, Disease variant, Disulfide bond, EGF-like domain, Glaucoma, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (299, '4RER', '', '5''-AMP-activated protein kinase catalytic subunit alpha-1', 'Catalytic subunit of AMP-activated protein kinase (AMPK), an energy sensor protein kinase that plays a key role in regulating cellular energy metabolism (PubMed:17307971, PubMed:17712357, PubMed:24563466, PubMed:37821951). In response to reduction of intracellular ATP levels, AMPK activates energy-producing pathways and inhibits energy-consuming processes: inhibits protein, carbohydrate and lipid biosynthesis, as well as cell growth and proliferation (PubMed:17307971, PubMed:17712357). AMPK acts via direct phosphorylation of metabolic enzymes, and by longer-term effects via phosphorylation of transcription regulators (PubMed:17307971, PubMed:17712357). Regulates lipid synthesis by phosphorylating and inactivating lipid metabolic enzymes such as ACACA, ACACB, GYS1, HMGCR and LIPE; regulates fatty acid and cholesterol synthesis by phosphorylating acetyl-CoA carboxylase (ACACA and ACACB) and hormone-sensitive lipase (LIPE) enzymes, respectively (By similarity). Promotes lipolysis of lipid droplets by mediating phosphorylation of isoform 1 of CHKA (CHKalpha2) (PubMed:34077757). Regulates insulin-signaling and glycolysis by phosphorylating IRS1, PFKFB2 and PFKFB3 (By similarity). AMPK stimulates glucose uptake in muscle by increasing the translocation of the glucose transporter SLC2A4/GLUT4 to the plasma membrane, possibly by mediating phosphorylation of TBC1D4/AS160 (By similarity). Regulates transcription and chromatin structure by phosphorylating transcription regulators involved in energy metabolism such as CRTC2/TORC2, FOXO3, histone H2B, HDAC5, MEF2C, MLXIPL/ChREBP, EP300, HNF4A, p53/TP53, SREBF1, SREBF2 and PPARGC1A (PubMed:11554766, PubMed:11518699, PubMed:15866171, PubMed:17711846, PubMed:18184930). Acts as a key regulator of glucose homeostasis in liver by phosphorylating CRTC2/TORC2, leading to CRTC2/TORC2 sequestration in the cytoplasm (By similarity). In response to stress, phosphorylates ''Ser-36'' of histone H2B (H2BS36ph), leading to promote transcription (By similarity). Acts as a key regulator of cell growth and proliferation by phosphorylating FNIP1, TSC2, RPTOR, WDR24 and ATG1/ULK1: in response to nutrient limitation, negatively regulates the mTORC1 complex by phosphorylating RPTOR component of the mTORC1 complex and by phosphorylating and activating TSC2 (PubMed:14651849, PubMed:18439900, PubMed:20160076, PubMed:21205641). Also phosphorylates and inhibits GATOR2 subunit WDR24 in response to nutrient limitation, leading to suppress glucose-mediated mTORC1 activation (PubMed:36732624). In response to energetic stress, phosphorylates FNIP1, inactivating the non-canonical mTORC1 signaling, thereby promoting nuclear translocation of TFEB and TFE3, and inducing transcription of lysosomal or autophagy genes (PubMed:37079666). In response to nutrient limitation, promotes autophagy by phosphorylating and activating ATG1/ULK1 (PubMed:21205641). In that process also activates WDR45/WIPI4 (PubMed:28561066). Phosphorylates CASP6, thereby preventing its autoprocessing and subsequent activation (PubMed:32029622). In response to nutrient limitation, phosphorylates transcription factor FOXO3 promoting FOXO3 mitochondrial import (By similarity). Also acts as a regulator of cellular polarity by remodeling the actin cytoskeleton; probably by indirectly activating myosin (PubMed:17486097). AMPK also acts as a regulator of circadian rhythm by mediating phosphorylation of CRY1, leading to destabilize it (By similarity). May regulate the Wnt signaling pathway by phosphorylating CTNNB1, leading to stabilize it (By similarity). Also has tau-protein kinase activity: in response to amyloid beta A4 protein (APP) exposure, activated by CAMKK2, leading to phosphorylation of MAPT/TAU; however the relevance of such data remains unclear in vivo (By similarity). Also phosphorylates CFTR, EEF2K, KLC1, NOS3 and SLC12A1 (PubMed:20074060, PubMed:12519745). Regulates hepatic lipogenesis. Activated via SIRT3, represses sterol regulatory element-binding protein (SREBP) transcriptional activities and ATP-consuming lipogenesis to restore cellular energy balance.', 'PRKAA1', 'Homo sapiens', '{[''2.7.11.31'',''2.7.11.1'',''2.7.11.26'']}', '3D-structure, Alternative splicing, ATP-binding, Autophagy, Biological rhythms, Cholesterol biosynthesis, Cholesterol metabolism, Chromatin regulator, Cytoplasm, Fatty acid biosynthesis, Fatty acid metabolism, Glycoprotein, Host-virus interaction, Kinase, Lipid biosynthesis, Lipid metabolism, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Steroid biosynthesis, Steroid metabolism, Sterol biosynthesis, Sterol metabolism, Transcription, Transcription regulation, Transferase, Ubl conjugation, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (301, '6T41', '', 'Cyclin-dependent kinase 8', 'Component of the Mediator complex, a coactivator involved in regulated gene transcription of nearly all RNA polymerase II-dependent genes. Mediator functions as a bridge to convey information from gene-specific regulatory proteins to the basal RNA polymerase II transcription machinery. Mediator is recruited to promoters by direct interactions with regulatory proteins and serves as a scaffold for the assembly of a functional pre-initiation complex with RNA polymerase II and the general transcription factors. Phosphorylates the CTD (C-terminal domain) of the large subunit of RNA polymerase II (RNAp II), which may inhibit the formation of a transcription initiation complex. Phosphorylates CCNH leading to down-regulation of the TFIIH complex and transcriptional repression. Recruited through interaction with MAML1 to hyperphosphorylate the intracellular domain of NOTCH, leading to its degradation.', 'CDK8', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Activator, Alternative splicing, ATP-binding, Autism spectrum disorder, Disease variant, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Reference proteome, Repressor, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (302, '6V6A', '', 'Mitogen-activated protein kinase', 'Unknown', 'MAPK2', 'Toxoplasma gondii', '{[''2.7.11.24'']}', '3D-structure, ATP-binding, Kinase, Magnesium, Nucleotide-binding, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (303, '2BUJ', '', 'Serine/threonine-protein kinase 16', 'Membrane-associated protein kinase that phosphorylates on serine and threonine residues. In vitro substrates include DRG1, ENO1 and EIF4EBP1. Also autophosphorylates. May be involved in secretory vesicle trafficking or intracellular signaling. May have a role in regulating stromal-epithelial interactions that occur during ductal morphogenesis in the mammary gland. May be involved in TGF-beta signaling. Able to autophosphorylate on Tyr residue; it is however unclear whether it has tyrosine-protein kinase toward other proteins.', 'STK16', 'Homo sapiens', '{[''2.7.10.2'',''2.7.11.1'']}', '3D-structure, ATP-binding, Cytoplasm, Kinase, Lipoprotein, Membrane, Myristate, Nucleotide-binding, Palmitate, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (415, '2H8H', '', 'Proto-oncogene tyrosine-protein kinase Src', 'Non-receptor protein tyrosine kinase which is activated following engagement of many different classes of cellular receptors including immune response receptors, integrins and other adhesion receptors, receptor protein tyrosine kinases, G protein-coupled receptors as well as cytokine receptors. Participates in signaling pathways that control a diverse spectrum of biological activities including gene transcription, immune response, cell adhesion, cell cycle progression, apoptosis, migration, and transformation. Due to functional redundancy between members of the SRC kinase family, identification of the specific role of each SRC kinase is very difficult. SRC appears to be one of the primary kinases activated following engagement of receptors and plays a role in the activation of other protein tyrosine kinase (PTK) families. Receptor clustering or dimerization leads to recruitment of SRC to the receptor complexes where it phosphorylates the tyrosine residues within the receptor cytoplasmic domains. Plays an important role in the regulation of cytoskeletal organization through phosphorylation of specific substrates such as AFAP1. Phosphorylation of AFAP1 allows the SRC SH2 domain to bind AFAP1 and to localize to actin filaments. Cytoskeletal reorganization is also controlled through the phosphorylation of cortactin (CTTN) (Probable). When cells adhere via focal adhesions to the extracellular matrix, signals are transmitted by integrins into the cell resulting in tyrosine phosphorylation of a number of focal adhesion proteins, including PTK2/FAK1 and paxillin (PXN) (PubMed:21411625). In addition to phosphorylating focal adhesion proteins, SRC is also active at the sites of cell-cell contact adherens junctions and phosphorylates substrates such as beta-catenin (CTNNB1), delta-catenin (CTNND1), and plakoglobin (JUP). Another type of cell-cell junction, the gap junction, is also a target for SRC, which phosphorylates connexin-43 (GJA1). SRC is implicated in regulation of pre-mRNA-processing and phosphorylates RNA-binding proteins such as KHDRBS1 (Probable). Also plays a role in PDGF-mediated tyrosine phosphorylation of both STAT1 and STAT3, leading to increased DNA binding activity of these transcription factors (By similarity). Involved in the RAS pathway through phosphorylation of RASA1 and RASGRF1 (PubMed:11389730). Plays a role in EGF-mediated calcium-activated chloride channel activation (PubMed:18586953). Required for epidermal growth factor receptor (EGFR) internalization through phosphorylation of clathrin heavy chain (CLTC and CLTCL1) at ''Tyr-1477''. Involved in beta-arrestin (ARRB1 and ARRB2) desensitization through phosphorylation and activation of GRK2, leading to beta-arrestin phosphorylation and internalization. Has a critical role in the stimulation of the CDK20/MAPK3 mitogen-activated protein kinase cascade by epidermal growth factor (Probable). Might be involved not only in mediating the transduction of mitogenic signals at the level of the plasma membrane but also in controlling progression through the cell cycle via interaction with regulatory proteins in the nucleus (PubMed:7853507). Plays an important role in osteoclastic bone resorption in conjunction with PTK2B/PYK2. Both the formation of a SRC-PTK2B/PYK2 complex and SRC kinase activity are necessary for this function. Recruited to activated integrins by PTK2B/PYK2, thereby phosphorylating CBL, which in turn induces the activation and recruitment of phosphatidylinositol 3-kinase to the cell membrane in a signaling pathway that is critical for osteoclast function (PubMed:8755529, PubMed:14585963). Promotes energy production in osteoclasts by activating mitochondrial cytochrome C oxidase (PubMed:12615910). Phosphorylates DDR2 on tyrosine residues, thereby promoting its subsequent autophosphorylation (PubMed:16186108). Phosphorylates RUNX3 and COX2 on tyrosine residues, TNK2 on ''Tyr-284'' and CBL on ''Tyr-731'' (PubMed:20100835, PubMed:21309750). Enhances RIGI-elicited antiviral signaling (PubMed:19419966). Phosphorylates PDPK1 at ''Tyr-9'', ''Tyr-373'' and ''Tyr-376'' (PubMed:14585963). Phosphorylates BCAR1 at ''Tyr-128'' (PubMed:22710723). Phosphorylates CBLC at multiple tyrosine residues, phosphorylation at ''Tyr-341'' activates CBLC E3 activity (PubMed:20525694). Phosphorylates synaptic vesicle protein synaptophysin (SYP) (By similarity). Involved in anchorage-independent cell growth (PubMed:19307596). Required for podosome formation (By similarity). Mediates IL6 signaling by activating YAP1-NOTCH pathway to induce inflammation-induced epithelial regeneration (PubMed:25731159). Phosphorylates OTUB1, promoting deubiquitination of RPTOR (PubMed:35927303). Phosphorylates caspase CASP8 at ''Tyr-380'' which negatively regulates CASP8 processing and activation, down-regulating CASP8 proapoptotic function (PubMed:16619028).', 'SRC', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell cycle, Cell junction, Cell membrane, Cytoplasm, Cytoskeleton, Disease variant, Host-virus interaction, Immunity, Kinase, Lipoprotein, Membrane, Mitochondrion, Mitochondrion inner membrane, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (416, '8OMV', '', 'Inhibitor of nuclear factor kappa-B kinase subunit beta', 'Serine kinase that plays an essential role in the NF-kappa-B signaling pathway which is activated by multiple stimuli such as inflammatory cytokines, bacterial or viral products, DNA damages or other cellular stresses (PubMed:20434986, PubMed:20797629, PubMed:21138416, PubMed:9346484, PubMed:30337470). Acts as a part of the canonical IKK complex in the conventional pathway of NF-kappa-B activation (PubMed:9346484). Phosphorylates inhibitors of NF-kappa-B on 2 critical serine residues (PubMed:9346484, PubMed:20434986, PubMed:20797629, PubMed:21138416). These modifications allow polyubiquitination of the inhibitors and subsequent degradation by the proteasome (PubMed:9346484, PubMed:20434986, PubMed:20797629, PubMed:21138416). In turn, free NF-kappa-B is translocated into the nucleus and activates the transcription of hundreds of genes involved in immune response, growth control, or protection against apoptosis (PubMed:9346484, PubMed:20434986, PubMed:20797629, PubMed:21138416). In addition to the NF-kappa-B inhibitors, phosphorylates several other components of the signaling pathway including NEMO/IKBKG, NF-kappa-B subunits RELA and NFKB1, as well as IKK-related kinases TBK1 and IKBKE (PubMed:11297557, PubMed:14673179, PubMed:20410276, PubMed:21138416). IKK-related kinase phosphorylations may prevent the overproduction of inflammatory mediators since they exert a negative regulation on canonical IKKs (PubMed:11297557, PubMed:20410276, PubMed:21138416). Phosphorylates FOXO3, mediating the TNF-dependent inactivation of this pro-apoptotic transcription factor (PubMed:15084260). Also phosphorylates other substrates including NAA10, NCOA3, BCL10 and IRS1 (PubMed:19716809, PubMed:17213322). Phosphorylates RIPK1 at ''Ser-25'' which represses its kinase activity and consequently prevents TNF-mediated RIPK1-dependent cell death (By similarity). Phosphorylates the C-terminus of IRF5, stimulating IRF5 homodimerization and translocation into the nucleus (PubMed:25326418).', 'IKBKB', 'Homo sapiens', '{[''2.7.11.10'',''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Direct protein sequencing, Disease variant, Host-virus interaction, Hydroxylation, Isopeptide bond, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, S-nitrosylation, SCID, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (425, '1TVO', '', 'Mitogen-activated protein kinase 1', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. MAPK1/ERK2 and MAPK3/ERK1 are the 2 MAPKs which play an important role in the MAPK/ERK cascade. They participate also in a signaling cascade initiated by activated KIT and KITLG/SCF. Depending on the cellular context, the MAPK/ERK cascade mediates diverse biological functions such as cell growth, adhesion, survival and differentiation through the regulation of transcription, translation, cytoskeletal rearrangements. The MAPK/ERK cascade also plays a role in initiation and regulation of meiosis, mitosis, and postmitotic functions in differentiated cells by phosphorylating a number of transcription factors. About 160 substrates have already been discovered for ERKs. Many of these substrates are localized in the nucleus, and seem to participate in the regulation of transcription upon stimulation. However, other substrates are found in the cytosol as well as in other cellular organelles, and those are responsible for processes such as translation, mitosis and apoptosis. Moreover, the MAPK/ERK cascade is also involved in the regulation of the endosomal dynamics, including lysosome processing and endosome cycling through the perinuclear recycling compartment (PNRC); as well as in the fragmentation of the Golgi apparatus during mitosis. The substrates include transcription factors (such as ATF2, BCL6, ELK1, ERF, FOS, HSF4 or SPZ1), cytoskeletal elements (such as CANX, CTTN, GJA1, MAP2, MAPT, PXN, SORBS3 or STMN1), regulators of apoptosis (such as BAD, BTG2, CASP9, DAPK1, IER3, MCL1 or PPARG), regulators of translation (such as EIF4EBP1 and FXR1) and a variety of other signaling-related molecules (like ARHGEF2, DCC, FRS2 or GRB10). Protein kinases (such as RAF1, RPS6KA1/RSK1, RPS6KA3/RSK2, RPS6KA2/RSK3, RPS6KA6/RSK4, SYK, MKNK1/MNK1, MKNK2/MNK2, RPS6KA5/MSK1, RPS6KA4/MSK2, MAPKAPK3 or MAPKAPK5) and phosphatases (such as DUSP1, DUSP4, DUSP6 or DUSP16) are other substrates which enable the propagation the MAPK/ERK signal to additional cytosolic and nuclear targets, thereby extending the specificity of the cascade. Mediates phosphorylation of TPR in response to EGF stimulation. May play a role in the spindle assembly checkpoint. Phosphorylates PML and promotes its interaction with PIN1, leading to PML degradation. Phosphorylates CDK2AP2 (By similarity).', 'MAPK1', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell junction, Cytoplasm, Cytoskeleton, Direct protein sequencing, Disease variant, DNA-binding, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repressor, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (428, '2WQM', '', 'Serine/threonine-protein kinase Nek7', 'Protein kinase which plays an important role in mitotic cell cycle progression (PubMed:17101132, PubMed:31409757, PubMed:19941817). Required for microtubule nucleation activity of the centrosome, robust mitotic spindle formation and cytokinesis (PubMed:17586473, PubMed:19414596, PubMed:31409757, PubMed:19941817, PubMed:26522158). Phosphorylates EML4 at ''Ser-146'', promoting its dissociation from microtubules during mitosis which is required for efficient chromosome congression (PubMed:31409757). Phosphorylates RPS6KB1 (By similarity). Acts as an essential activator of the NLRP3 inflammasome assembly independently of its kinase activity (PubMed:26642356, PubMed:36442502). Acts by unlocking NLRP3 following NLRP3 tranlocation into the microtubule organizing center (MTOC), relieving NLRP3 autoinhibition and promoting formation of the NLRP3:PYCARD complex, and activation of CASP1 (PubMed:26642356, PubMed:31189953, PubMed:36442502). Serves as a cellular switch that enforces mutual exclusivity of the inflammasome response and cell division: interaction with NEK9 prevents interaction with NLRP3 and activation of the inflammasome during mitosis (PubMed:26642356, PubMed:31189953).', 'NEK7', 'Homo sapiens', '{[''2.7.11.34'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Kinase, Magnesium, Metal-binding, Microtubule, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (429, '8Q61', '', 'RAC-beta serine/threonine-protein kinase', 'AKT2 is one of 3 closely related serine/threonine-protein kinases (AKT1, AKT2 and AKT3) called the AKT kinase, and which regulate many processes including metabolism, proliferation, cell survival, growth and angiogenesis. This is mediated through serine and/or threonine phosphorylation of a range of downstream substrates. Over 100 substrate candidates have been reported so far, but for most of them, no isoform specificity has been reported. AKT is responsible of the regulation of glucose uptake by mediating insulin-induced translocation of the SLC2A4/GLUT4 glucose transporter to the cell surface. Phosphorylation of PTPN1 at ''Ser-50'' negatively modulates its phosphatase activity preventing dephosphorylation of the insulin receptor and the attenuation of insulin signaling. Phosphorylation of TBC1D4 triggers the binding of this effector to inhibitory 14-3-3 proteins, which is required for insulin-stimulated glucose transport. AKT regulates also the storage of glucose in the form of glycogen by phosphorylating GSK3A at ''Ser-21'' and GSK3B at ''Ser-9'', resulting in inhibition of its kinase activity. Phosphorylation of GSK3 isoforms by AKT is also thought to be one mechanism by which cell proliferation is driven. AKT regulates also cell survival via the phosphorylation of MAP3K5 (apoptosis signal-related kinase). Phosphorylation of ''Ser-83'' decreases MAP3K5 kinase activity stimulated by oxidative stress and thereby prevents apoptosis. AKT mediates insulin-stimulated protein synthesis by phosphorylating TSC2 at ''Ser-939'' and ''Thr-1462'', thereby activating mTORC1 signaling and leading to both phosphorylation of 4E-BP1 and in activation of RPS6KB1. AKT is involved in the phosphorylation of members of the FOXO factors (Forkhead family of transcription factors), leading to binding of 14-3-3 proteins and cytoplasmic localization. In particular, FOXO1 is phosphorylated at ''Thr-24'', ''Ser-256'' and ''Ser-319''. FOXO3 and FOXO4 are phosphorylated on equivalent sites. AKT has an important role in the regulation of NF-kappa-B-dependent gene transcription and positively regulates the activity of CREB1 (cyclic AMP (cAMP)-response element binding protein). The phosphorylation of CREB1 induces the binding of accessory proteins that are necessary for the transcription of pro-survival genes such as BCL2 and MCL1. AKT phosphorylates ''Ser-454'' on ATP citrate lyase (ACLY), thereby potentially regulating ACLY activity and fatty acid synthesis. Activates the 3B isoform of cyclic nucleotide phosphodiesterase (PDE3B) via phosphorylation of ''Ser-273'', resulting in reduced cyclic AMP levels and inhibition of lipolysis. Phosphorylates PIKFYVE on ''Ser-318'', which results in increased PI(3)P-5 activity. The Rho GTPase-activating protein DLC1 is another substrate and its phosphorylation is implicated in the regulation cell proliferation and cell growth. AKT plays a role as key modulator of the AKT-mTOR signaling pathway controlling the tempo of the process of newborn neurons integration during adult neurogenesis, including correct neuron positioning, dendritic development and synapse formation. Signals downstream of phosphatidylinositol 3-kinase (PI(3)K) to mediate the effects of various growth factors such as platelet-derived growth factor (PDGF), epidermal growth factor (EGF), insulin and insulin-like growth factor I (IGF-I). AKT mediates the antiapoptotic effects of IGF-I. Essential for the SPATA13-mediated regulation of cell migration and adhesion assembly and disassembly. May be involved in the regulation of the placental development. Involved in the inhibition of ciliogenesis associated with RAB8-dependent cilia growth (PubMed:31204173).', 'AKT2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Carbohydrate metabolism, Cell membrane, Cytoplasm, Developmental protein, Diabetes mellitus, Disease variant, Disulfide bond, Endosome, Glucose metabolism, Glycogen biosynthesis, Glycogen metabolism, Glycoprotein, Kinase, Manganese, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Sugar transport, Transferase, Translation regulation, Transport, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (430, '2OU7', '', 'Serine/threonine-protein kinase PLK1', 'Serine/threonine-protein kinase that performs several important functions throughout M phase of the cell cycle, including the regulation of centrosome maturation and spindle assembly, the removal of cohesins from chromosome arms, the inactivation of anaphase-promoting complex/cyclosome (APC/C) inhibitors, and the regulation of mitotic exit and cytokinesis (PubMed:8991084, PubMed:11202906, PubMed:12207013, PubMed:12447691, PubMed:12524548, PubMed:12738781, PubMed:12852856, PubMed:12939256, PubMed:14532005, PubMed:14734534, PubMed:15070733, PubMed:15148369, PubMed:15469984, PubMed:16198290, PubMed:16247472, PubMed:16980960, PubMed:17081991, PubMed:17351640, PubMed:17376779, PubMed:17617734, PubMed:18174154, PubMed:18331714, PubMed:18418051, PubMed:18477460, PubMed:18521620, PubMed:18615013, PubMed:19160488, PubMed:19351716, PubMed:19468300, PubMed:19468302, PubMed:19473992, PubMed:19509060, PubMed:19597481, PubMed:23455478, PubMed:23509069). Polo-like kinase proteins act by binding and phosphorylating proteins that are already phosphorylated on a specific motif recognized by the POLO box domains (PubMed:8991084, PubMed:11202906, PubMed:12207013, PubMed:12447691, PubMed:12524548, PubMed:12738781, PubMed:12852856, PubMed:12939256, PubMed:14532005, PubMed:14734534, PubMed:15070733, PubMed:15148369, PubMed:15469984, PubMed:16198290, PubMed:16247472, PubMed:16980960, PubMed:17081991, PubMed:17351640, PubMed:17376779, PubMed:17617734, PubMed:18174154, PubMed:18331714, PubMed:18418051, PubMed:18477460, PubMed:18521620, PubMed:18615013, PubMed:19160488, PubMed:19351716, PubMed:19468300, PubMed:19468302, PubMed:19473992, PubMed:19509060, PubMed:19597481, PubMed:23455478, PubMed:23509069). Phosphorylates BORA, BUB1B/BUBR1, CCNB1, CDC25C, CEP55, ECT2, ERCC6L, FBXO5/EMI1, FOXM1, KIF20A/MKLP2, CENPU, NEDD1, NINL, NPM1, NUDC, PKMYT1/MYT1, KIZ, PPP1R12A/MYPT1, POLQ, PRC1, RACGAP1/CYK4, RAD51, RHNO1, SGO1, STAG2/SA2, TEX14, TOPORS, p73/TP73, TPT1, WEE1 and HNRNPU (PubMed:8991084, PubMed:11202906, PubMed:12207013, PubMed:12447691, PubMed:12524548, PubMed:12738781, PubMed:12852856, PubMed:12939256, PubMed:14532005, PubMed:14734534, PubMed:15070733, PubMed:15148369, PubMed:15469984, PubMed:16198290, PubMed:16247472, PubMed:16980960, PubMed:17081991, PubMed:17218258, PubMed:17351640, PubMed:17376779, PubMed:17617734, PubMed:18174154, PubMed:18331714, PubMed:18418051, PubMed:18477460, PubMed:18521620, PubMed:18615013, PubMed:19160488, PubMed:19351716, PubMed:19468300, PubMed:19468302, PubMed:19473992, PubMed:19509060, PubMed:22325354, PubMed:19597481, PubMed:23455478, PubMed:23509069, PubMed:25986610, PubMed:26811421, PubMed:37674080, PubMed:37440612). Plays a key role in centrosome functions and the assembly of bipolar spindles by phosphorylating KIZ, NEDD1 and NINL (PubMed:16980960, PubMed:19509060). NEDD1 phosphorylation promotes subsequent targeting of the gamma-tubulin ring complex (gTuRC) to the centrosome, an important step for spindle formation (PubMed:19509060). Phosphorylation of NINL component of the centrosome leads to NINL dissociation from other centrosomal proteins (PubMed:12852856). Involved in mitosis exit and cytokinesis by phosphorylating CEP55, ECT2, KIF20A/MKLP2, CENPU, PRC1 and RACGAP1 (PubMed:12939256, PubMed:16247472, PubMed:17351640, PubMed:19468300, PubMed:19468302). Recruited at the central spindle by phosphorylating and docking PRC1 and KIF20A/MKLP2; creates its own docking sites on PRC1 and KIF20A/MKLP2 by mediating phosphorylation of sites subsequently recognized by the POLO box domains (PubMed:12939256, PubMed:17351640). Phosphorylates RACGAP1, thereby creating a docking site for the Rho GTP exchange factor ECT2 that is essential for the cleavage furrow formation (PubMed:19468300, PubMed:19468302). Promotes the central spindle recruitment of ECT2 (PubMed:16247472). Plays a central role in G2/M transition of mitotic cell cycle by phosphorylating CCNB1, CDC25C, FOXM1, CENPU, PKMYT1/MYT1, PPP1R12A/MYPT1 and WEE1 (PubMed:11202906, PubMed:12447691, PubMed:12524548, PubMed:19160488). Part of a regulatory circuit that promotes the activation of CDK1 by phosphorylating the positive regulator CDC25C and inhibiting the negative regulators WEE1 and PKMYT1/MYT1 (PubMed:11202906). Also acts by mediating phosphorylation of cyclin-B1 (CCNB1) on centrosomes in prophase (PubMed:12447691, PubMed:12524548). Phosphorylates FOXM1, a key mitotic transcription regulator, leading to enhance FOXM1 transcriptional activity (PubMed:19160488). Involved in kinetochore functions and sister chromatid cohesion by phosphorylating BUB1B/BUBR1, FBXO5/EMI1 and STAG2/SA2 (PubMed:15469984, PubMed:15148369, PubMed:17376779, PubMed:18331714). PLK1 is high on non-attached kinetochores suggesting a role of PLK1 in kinetochore attachment or in spindle assembly checkpoint (SAC) regulation (PubMed:17617734). Required for kinetochore localization of BUB1B (PubMed:17376779). Regulates the dissociation of cohesin from chromosomes by phosphorylating cohesin subunits such as STAG2/SA2 (By similarity). Phosphorylates SGO1: required for spindle pole localization of isoform 3 of SGO1 and plays a role in regulating its centriole cohesion function (PubMed:18331714). Mediates phosphorylation of FBXO5/EMI1, a negative regulator of the APC/C complex during prophase, leading to FBXO5/EMI1 ubiquitination and degradation by the proteasome (PubMed:15469984, PubMed:15148369). Acts as a negative regulator of p53 family members: phosphorylates TOPORS, leading to inhibit the sumoylation of p53/TP53 and simultaneously enhance the ubiquitination and subsequent degradation of p53/TP53 (PubMed:19473992). Phosphorylates the transactivation domain of the transcription factor p73/TP73, leading to inhibit p73/TP73-mediated transcriptional activation and pro-apoptotic functions. Phosphorylates BORA, and thereby promotes the degradation of BORA (PubMed:18521620). Contributes to the regulation of AURKA function (PubMed:18662541, PubMed:18615013). Also required for recovery after DNA damage checkpoint and entry into mitosis (PubMed:18662541, PubMed:18615013). Phosphorylates MISP, leading to stabilization of cortical and astral microtubule attachments required for proper spindle positioning (PubMed:23509069). Together with MEIKIN, acts as a regulator of kinetochore function during meiosis I: required both for mono-orientation of kinetochores on sister chromosomes and protection of centromeric cohesin from separase-mediated cleavage (By similarity). Phosphorylates CEP68 and is required for its degradation (PubMed:25503564). Regulates nuclear envelope breakdown during prophase by phosphorylating DCTN1 resulting in its localization in the nuclear envelope (PubMed:20679239). Phosphorylates the heat shock transcription factor HSF1, promoting HSF1 nuclear translocation upon heat shock (PubMed:15661742). Phosphorylates HSF1 also in the early mitotic period; this phosphorylation regulates HSF1 localization to the spindle pole, the recruitment of the SCF(BTRC) ubiquitin ligase complex induicing HSF1 degradation, and hence mitotic progression (PubMed:18794143). Regulates mitotic progression by phosphorylating RIOK2 (PubMed:21880710). Through the phosphorylation of DZIP1 regulates the localization during mitosis of the BBSome, a ciliary protein complex involved in cilium biogenesis (PubMed:27979967). Regulates DNA repair during mitosis by mediating phosphorylation of POLQ and RHNO1, thereby promoting POLQ recruitment to DNA damage sites (PubMed:37674080, PubMed:37440612).', 'PLK1', 'Homo sapiens', '{[''2.7.11.21'']}', '3D-structure, Acetylation, ATP-binding, Cell cycle, Cell division, Centromere, Chromosome, Cytoplasm, Cytoskeleton, Isopeptide bond, Kinase, Kinetochore, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (431, '5O0Y', '', 'Serine/threonine-protein kinase tousled-like 2', 'Serine/threonine-protein kinase involved in the process of chromatin assembly and probably also DNA replication, transcription, repair, and chromosome segregation (PubMed:9427565, PubMed:10523312, PubMed:11470414, PubMed:12660173, PubMed:12955071, PubMed:29955062, PubMed:33323470). Phosphorylates the chromatin assembly factors ASF1A and ASF1B (PubMed:11470414, PubMed:20016786, PubMed:29955062, PubMed:35136069). Phosphorylation of ASF1A prevents its proteasome-mediated degradation, thereby enhancing chromatin assembly (PubMed:20016786). Negative regulator of amino acid starvation-induced autophagy (PubMed:22354037).', 'TLK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Chromatin regulator, Coiled coil, Cytoplasm, Cytoskeleton, Disease variant, DNA damage, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (432, '1U5Q', '', 'Serine/threonine-protein kinase TAO2', 'Serine/threonine-protein kinase involved in different processes such as membrane blebbing and apoptotic bodies formation DNA damage response and MAPK14/p38 MAPK stress-activated MAPK cascade. Phosphorylates itself, MBP, activated MAPK8, MAP2K3, MAP2K6 and tubulins. Activates the MAPK14/p38 MAPK signaling pathway through the specific activation and phosphorylation of the upstream MAP2K3 and MAP2K6 kinases. In response to DNA damage, involved in the G2/M transition DNA damage checkpoint by activating the p38/MAPK14 stress-activated MAPK cascade, probably by mediating phosphorylation of upstream MAP2K3 and MAP2K6 kinases. May affect microtubule organization and stability. May play a role in the osmotic stress-MAPK8 pathway. Prevents MAP3K7-mediated activation of CHUK, and thus NF-kappa-B activation. Isoform 2, but not isoform 1, is required for PCDH8 endocytosis. Following homophilic interactions between PCDH8 extracellular domains, isoform 2 phosphorylates and activates MAPK14/p38 MAPK which in turn phosphorylates isoform 2. This process leads to PCDH8 endocytosis and CDH2 cointernalization. Both isoforms are involved in MAPK14/p38 MAPK activation.', 'Taok2', 'Rattus norvegicus', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Coiled coil, Cytoplasm, Cytoplasmic vesicle, Cytoskeleton, Kinase, Magnesium, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (435, '3Q4T', '', 'Activin receptor type-2A', 'On ligand binding, forms a receptor complex consisting of two type II and two type I transmembrane serine/threonine kinases. Type II receptors phosphorylate and activate type I receptors which autophosphorylate, then bind and activate SMAD transcriptional regulators. Receptor for activin A, activin B and inhibin A (PubMed:17911401). Mediates induction of adipogenesis by GDF6 (By similarity).', 'ACVR2A', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disulfide bond, Glycoprotein, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (436, '6PXN', '', 'Casein kinase I isoform delta', 'Essential serine/threonine-protein kinase that regulates diverse cellular growth and survival processes including Wnt signaling, DNA repair and circadian rhythms. It can phosphorylate a large number of proteins. Casein kinases are operationally defined by their preferential utilization of acidic proteins such as caseins as substrates. Phosphorylates connexin-43/GJA1, MAP1A, SNAPIN, MAPT/TAU, TOP2A, DCK, HIF1A, EIF6, p53/TP53, DVL2, DVL3, ESR1, AIB1/NCOA3, DNMT1, PKD2, YAP1, PER1 and PER2. Central component of the circadian clock. In balance with PP1, determines the circadian period length through the regulation of the speed and rhythmicity of PER1 and PER2 phosphorylation. Controls PER1 and PER2 nuclear transport and degradation. YAP1 phosphorylation promotes its SCF(beta-TRCP) E3 ubiquitin ligase-mediated ubiquitination and subsequent degradation. DNMT1 phosphorylation reduces its DNA-binding activity. Phosphorylation of ESR1 and AIB1/NCOA3 stimulates their activity and coactivation. Phosphorylation of DVL2 and DVL3 regulates WNT3A signaling pathway that controls neurite outgrowth. Phosphorylates NEDD9/HEF1 (By similarity). EIF6 phosphorylation promotes its nuclear export. Triggers down-regulation of dopamine receptors in the forebrain. Activates DCK in vitro by phosphorylation. TOP2A phosphorylation favors DNA cleavable complex formation. May regulate the formation of the mitotic spindle apparatus in extravillous trophoblast. Modulates connexin-43/GJA1 gap junction assembly by phosphorylation. Probably involved in lymphocyte physiology. Regulates fast synaptic transmission mediated by glutamate.', 'CSNK1D', 'Homo sapiens', '{[''2.7.11.1'',''2.7.11.26'']}', '3D-structure, Alternative splicing, ATP-binding, Biological rhythms, Cell membrane, Cytoplasm, Cytoskeleton, Disease variant, Golgi apparatus, Kinase, Membrane, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (437, '6BXI', '', 'Serine/threonine-protein kinase 38', 'Negative regulator of MAP3K1/2 signaling. Converts MAP3K2 from its phosphorylated form to its non-phosphorylated form and inhibits autophosphorylation of MAP3K2.', 'STK38', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Direct protein sequencing, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (438, '7ZV9', '', 'Fms-related tyrosine kinase 3 ligand', 'Stimulates the proliferation of early hematopoietic cells by activating FLT3. Synergizes well with a number of other colony stimulating factors and interleukins.', 'FLT3LG', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Cell membrane, Cytokine, Disulfide bond, Glycoprotein, Membrane, Reference proteome, Secreted, Signal, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (439, '2C47', '', 'Casein kinase I isoform gamma-2', 'Serine/threonine-protein kinase. Casein kinases are operationally defined by their preferential utilization of acidic proteins such as caseins as substrates. It can phosphorylate a large number of proteins. Participates in Wnt signaling (By similarity). Phosphorylates COL4A3BP/CERT, MTA1 and SMAD3. SMAD3 phosphorylation promotes its ligand-dependent ubiquitination and subsequent proteasome degradation, thus inhibiting SMAD3-mediated TGF-beta responses. Hyperphosphorylation of the serine-repeat motif of COL4A3BP/CERT leads to its inactivation by dissociation from the Golgi complex, thus down-regulating ER-to-Golgi transport of ceramide and sphingomyelin synthesis. Triggers PER1 proteasomal degradation probably through phosphorylation (PubMed:15077195, PubMed:15917222, PubMed:18794808, PubMed:19005213). Involved in brain development and vesicular trafficking and neurotransmitter releasing from small synaptic vesicles. Regulates fast synaptic transmission mediated by glutamate (By similarity). Involved in regulation of reactive oxygen species (ROS) levels (PubMed:37099597).', 'CSNK1G2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (440, '4LGD', '', 'Serine/threonine-protein kinase 3', 'Stress-activated, pro-apoptotic kinase which, following caspase-cleavage, enters the nucleus and induces chromatin condensation followed by internucleosomal DNA fragmentation. Key component of the Hippo signaling pathway which plays a pivotal role in organ size control and tumor suppression by restricting proliferation and promoting apoptosis. The core of this pathway is composed of a kinase cascade wherein STK3/MST2 and STK4/MST1, in complex with its regulatory protein SAV1, phosphorylates and activates LATS1/2 in complex with its regulatory protein MOB1, which in turn phosphorylates and inactivates YAP1 oncoprotein and WWTR1/TAZ (PubMed:23972470). Phosphorylation of YAP1 by LATS2 inhibits its translocation into the nucleus to regulate cellular genes important for cell proliferation, cell death, and cell migration. STK3/MST2 and STK4/MST1 are required to repress proliferation of mature hepatocytes, to prevent activation of facultative adult liver stem cells (oval cells), and to inhibit tumor formation. Phosphorylates NKX2-1 (By similarity). Phosphorylates NEK2 and plays a role in centrosome disjunction by regulating the localization of NEK2 to centrosome, and its ability to phosphorylate CROCC and CEP250 (PubMed:21723128). In conjunction with SAV1, activates the transcriptional activity of ESR1 through the modulation of its phosphorylation. Positively regulates RAF1 activation via suppression of the inhibitory phosphorylation of RAF1 on ''Ser-259''. Phosphorylates MOBKL1A and RASSF2. Phosphorylates MOBKL1B on ''Thr-74''. Acts cooperatively with MOBKL1B to activate STK38.', 'STK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Cytoskeleton, Direct protein sequencing, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (441, '4K0V', '', 'Angiopoietin-1 receptor', 'Tyrosine-protein kinase that acts as a cell-surface receptor for ANGPT1, ANGPT2 and ANGPT4 and regulates angiogenesis, endothelial cell survival, proliferation, migration, adhesion and cell spreading, reorganization of the actin cytoskeleton, but also maintenance of vascular quiescence. Has anti-inflammatory effects by preventing the leakage of pro-inflammatory plasma proteins and leukocytes from blood vessels. Required for normal angiogenesis and heart development during embryogenesis. Required for post-natal hematopoiesis. After birth, activates or inhibits angiogenesis, depending on the context. Inhibits angiogenesis and promotes vascular stability in quiescent vessels, where endothelial cells have tight contacts. In quiescent vessels, ANGPT1 oligomers recruit TEK to cell-cell contacts, forming complexes with TEK molecules from adjoining cells, and this leads to preferential activation of phosphatidylinositol 3-kinase and the AKT1 signaling cascades. In migrating endothelial cells that lack cell-cell adhesions, ANGT1 recruits TEK to contacts with the extracellular matrix, leading to the formation of focal adhesion complexes, activation of PTK2/FAK and of the downstream kinases MAPK1/ERK2 and MAPK3/ERK1, and ultimately to the stimulation of sprouting angiogenesis. ANGPT1 signaling triggers receptor dimerization and autophosphorylation at specific tyrosine residues that then serve as binding sites for scaffold proteins and effectors. Signaling is modulated by ANGPT2 that has lower affinity for TEK, can promote TEK autophosphorylation in the absence of ANGPT1, but inhibits ANGPT1-mediated signaling by competing for the same binding site. Signaling is also modulated by formation of heterodimers with TIE1, and by proteolytic processing that gives rise to a soluble TEK extracellular domain. The soluble extracellular domain modulates signaling by functioning as decoy receptor for angiopoietins. TEK phosphorylates DOK2, GRB7, GRB14, PIK3R1; SHC1 and TIE1.', 'TEK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Cytoskeleton, Direct protein sequencing, Disease variant, Disulfide bond, EGF-like domain, Glaucoma, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (442, '1OPL', '', 'Tyrosine-protein kinase ABL1', 'Non-receptor tyrosine-protein kinase that plays a role in many key processes linked to cell growth and survival such as cytoskeleton remodeling in response to extracellular stimuli, cell motility and adhesion, receptor endocytosis, autophagy, DNA damage response and apoptosis. Coordinates actin remodeling through tyrosine phosphorylation of proteins controlling cytoskeleton dynamics like WASF3 (involved in branch formation); ANXA1 (involved in membrane anchoring); DBN1, DBNL, CTTN, RAPH1 and ENAH (involved in signaling); or MAPT and PXN (microtubule-binding proteins). Phosphorylation of WASF3 is critical for the stimulation of lamellipodia formation and cell migration. Involved in the regulation of cell adhesion and motility through phosphorylation of key regulators of these processes such as BCAR1, CRK, CRKL, DOK1, EFS or NEDD9 (PubMed:22810897). Phosphorylates multiple receptor tyrosine kinases and more particularly promotes endocytosis of EGFR, facilitates the formation of neuromuscular synapses through MUSK, inhibits PDGFRB-mediated chemotaxis and modulates the endocytosis of activated B-cell receptor complexes. Other substrates which are involved in endocytosis regulation are the caveolin (CAV1) and RIN1. Moreover, ABL1 regulates the CBL family of ubiquitin ligases that drive receptor down-regulation and actin remodeling. Phosphorylation of CBL leads to increased EGFR stability. Involved in late-stage autophagy by regulating positively the trafficking and function of lysosomal components. ABL1 targets to mitochondria in response to oxidative stress and thereby mediates mitochondrial dysfunction and cell death. In response to oxidative stress, phosphorylates serine/threonine kinase PRKD2 at ''Tyr-717'' (PubMed:28428613). ABL1 is also translocated in the nucleus where it has DNA-binding activity and is involved in DNA-damage response and apoptosis. Many substrates are known mediators of DNA repair: DDB1, DDB2, ERCC3, ERCC6, RAD9A, RAD51, RAD52 or WRN. Activates the proapoptotic pathway when the DNA damage is too severe to be repaired. Phosphorylates TP73, a primary regulator for this type of damage-induced apoptosis. Phosphorylates the caspase CASP9 on ''Tyr-153'' and regulates its processing in the apoptotic response to DNA damage. Phosphorylates PSMA7 that leads to an inhibition of proteasomal activity and cell cycle transition blocks. ABL1 acts also as a regulator of multiple pathological signaling cascades during infection. Several known tyrosine-phosphorylated microbial proteins have been identified as ABL1 substrates. This is the case of A36R of Vaccinia virus, Tir (translocated intimin receptor) of pathogenic E.coli and possibly Citrobacter, CagA (cytotoxin-associated gene A) of H.pylori, or AnkA (ankyrin repeat-containing protein A) of A.phagocytophilum. Pathogens can highjack ABL1 kinase signaling to reorganize the host actin cytoskeleton for multiple purposes, like facilitating intracellular movement and host cell exit. Finally, functions as its own regulator through autocatalytic activity as well as through phosphorylation of its inhibitor, ABI1. Regulates T-cell differentiation in a TBX21-dependent manner (By similarity). Positively regulates chemokine-mediated T-cell migration, polarization, and homing to lymph nodes and immune-challenged tissues, potentially via activation of NEDD9/HEF1 and RAP1 (By similarity). Phosphorylates TBX21 on tyrosine residues leading to an enhancement of its transcriptional activator activity (By similarity).', 'ABL1', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Autophagy, Cell adhesion, Chromosomal rearrangement, Cytoplasm, Cytoskeleton, Disease variant, DNA damage, DNA repair, DNA-binding, Endocytosis, Kinase, Lipoprotein, Magnesium, Manganese, Membrane, Metal-binding, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (443, '6NYB', '', 'Serine/threonine-protein kinase B-raf', 'Protein kinase involved in the transduction of mitogenic signals from the cell membrane to the nucleus (Probable). Phosphorylates MAP2K1, and thereby activates the MAP kinase signal transduction pathway (PubMed:21441910, PubMed:29433126). Phosphorylates PFKFB2 (PubMed:36402789). May play a role in the postsynaptic responses of hippocampal neurons (PubMed:1508179).', 'BRAF', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Allosteric enzyme, ATP-binding, Cardiomyopathy, Cell membrane, Chromosomal rearrangement, Cytoplasm, Deafness, Direct protein sequencing, Disease variant, Ectodermal dysplasia, Intellectual disability, Isopeptide bond, Kinase, Membrane, Metal-binding, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (444, '3LM0', '', 'Serine/threonine-protein kinase 17B', 'Phosphorylates myosin light chains (By similarity). Acts as a positive regulator of apoptosis.', 'STK17B', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Apoptosis, ATP-binding, Cell membrane, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (445, '5HES', '', 'Mitogen-activated protein kinase kinase kinase 20', 'Stress-activated component of a protein kinase signal transduction cascade that promotes programmed cell death in response to various stress, such as ribosomal stress, osmotic shock and ionizing radiation (PubMed:10924358, PubMed:11836244, PubMed:12220515, PubMed:14521931, PubMed:15350844, PubMed:15737997, PubMed:18331592, PubMed:20559024, PubMed:32610081, PubMed:32289254, PubMed:35857590, PubMed:26999302). Acts by catalyzing phosphorylation of MAP kinase kinases, leading to activation of the JNK (MAPK8/JNK1, MAPK9/JNK2 and/or MAPK10/JNK3) and MAP kinase p38 (MAPK11, MAPK12, MAPK13 and/or MAPK14) pathways (PubMed:11042189, PubMed:11836244, PubMed:12220515, PubMed:14521931, PubMed:15172994, PubMed:15737997, PubMed:32610081, PubMed:32289254, PubMed:35857590). Activates JNK through phosphorylation of MAP2K4/MKK4 and MAP2K7/MKK7, and MAP kinase p38 gamma (MAPK12) via phosphorylation of MAP2K3/MKK3 and MAP2K6/MKK6 (PubMed:11836244, PubMed:12220515). Involved in stress associated with adrenergic stimulation: contributes to cardiac decompensation during periods of acute cardiac stress (PubMed:15350844, PubMed:21224381, PubMed:27859413). May be involved in regulation of S and G2 cell cycle checkpoint by mediating phosphorylation of CHEK2 (PubMed:15342622).', 'MAP3K20', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cytoplasm, Disease variant, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, RNA-binding, rRNA-binding, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (446, '1CM8', '', 'Mitogen-activated protein kinase 12', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. MAPK12 is one of the four p38 MAPKs which play an important role in the cascades of cellular responses evoked by extracellular stimuli such as pro-inflammatory cytokines or physical stress leading to direct activation of transcription factors such as ELK1 and ATF2. Accordingly, p38 MAPKs phosphorylate a broad range of proteins and it has been estimated that they may have approximately 200 to 300 substrates each. Some of the targets are downstream kinases such as MAPKAPK2, which are activated through phosphorylation and further phosphorylate additional targets. Plays a role in myoblast differentiation and also in the down-regulation of cyclin D1 in response to hypoxia in adrenal cells suggesting MAPK12 may inhibit cell proliferation while promoting differentiation. Phosphorylates DLG1. Following osmotic shock, MAPK12 in the cell nucleus increases its association with nuclear DLG1, thereby causing dissociation of DLG1-SFPQ complexes. This function is independent of its catalytic activity and could affect mRNA processing and/or gene transcription to aid cell adaptation to osmolarity changes in the environment. Regulates UV-induced checkpoint signaling and repair of UV-induced DNA damage and G2 arrest after gamma-radiation exposure. MAPK12 is involved in the regulation of SLC2A1 expression and basal glucose uptake in L6 myotubes; and negatively regulates SLC2A4 expression and contraction-mediated glucose uptake in adult skeletal muscle. C-Jun (JUN) phosphorylation is stimulated by MAPK14 and inhibited by MAPK12, leading to a distinct AP-1 regulation. MAPK12 is required for the normal kinetochore localization of PLK1, prevents chromosomal instability and supports mitotic cell viability. MAPK12-signaling is also positively regulating the expansion of transient amplifying myogenic precursor cells during muscle growth and regeneration.', 'MAPK12', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cytoplasm, Kinase, Magnesium, Metal-binding, Mitochondrion, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (447, '1K9A', '', 'Tyrosine-protein kinase CSK', 'Non-receptor tyrosine-protein kinase that plays an important role in the regulation of cell growth, differentiation, migration and immune response. Phosphorylates tyrosine residues located in the C-terminal tails of Src-family kinases (SFKs) including LCK, SRC, HCK, FYN, LYN, CSK or YES1. Upon tail phosphorylation, Src-family members engage in intramolecular interactions between the phosphotyrosine tail and the SH2 domain that result in an inactive conformation. To inhibit SFKs, CSK is recruited to the plasma membrane via binding to transmembrane proteins or adapter proteins located near the plasma membrane. Suppresses signaling by various surface receptors, including T-cell receptor (TCR) and B-cell receptor (BCR) by phosphorylating and maintaining inactive several positive effectors such as FYN or LCK (By similarity).', 'Csk', 'Rattus norvegicus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Adaptive immunity, ATP-binding, Cell membrane, Cytoplasm, Direct protein sequencing, Immunity, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (448, '2V62', '', 'Serine/threonine-protein kinase VRK2', 'Serine/threonine kinase that regulates several signal transduction pathways (PubMed:16704422, PubMed:14645249, PubMed:16495336, PubMed:17709393, PubMed:18617507, PubMed:18286207, PubMed:20679487). Isoform 1 modulates the stress response to hypoxia and cytokines, such as interleukin-1 beta (IL1B) and this is dependent on its interaction with MAPK8IP1, which assembles mitogen-activated protein kinase (MAPK) complexes (PubMed:17709393). Inhibition of signal transmission mediated by the assembly of MAPK8IP1-MAPK complexes reduces JNK phosphorylation and JUN-dependent transcription (PubMed:18286207). Phosphorylates ''Thr-18'' of p53/TP53, histone H3, and may also phosphorylate MAPK8IP1 (PubMed:16704422). Phosphorylates BANF1 and disrupts its ability to bind DNA and reduces its binding to LEM domain-containing proteins (PubMed:16495336). Down-regulates the transactivation of transcription induced by ERBB2, HRAS, BRAF, and MEK1 (PubMed:20679487). Blocks the phosphorylation of ERK in response to ERBB2 and HRAS (PubMed:20679487). Can also phosphorylate the following substrates that are commonly used to establish in vitro kinase activity: casein, MBP and histone H2B, but it is not sure that this is physiologically relevant (PubMed:14645249).', 'VRK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Endoplasmic reticulum, Host-virus interaction, Kinase, Membrane, Mitochondrion, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (449, '3ZEW', '', 'Ephrin type-B receptor 4', 'Receptor tyrosine kinase which binds promiscuously transmembrane ephrin-B family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Together with its cognate ligand/functional ligand EFNB2 it is involved in the regulation of cell adhesion and migration, and plays a central role in heart morphogenesis, angiogenesis and blood vessel remodeling and permeability. EPHB4-mediated forward signaling controls cellular repulsion and segregation from EFNB2-expressing cells.', 'EPHB4', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell membrane, Developmental protein, Disease variant, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (450, '2X7G', '', 'SRSF protein kinase 2', 'Serine/arginine-rich protein-specific kinase which specifically phosphorylates its substrates at serine residues located in regions rich in arginine/serine dipeptides, known as RS domains and is involved in the phosphorylation of SR splicing factors and the regulation of splicing (PubMed:9472028, PubMed:18559500, PubMed:21056976). Promotes neuronal apoptosis by up-regulating cyclin-D1 (CCND1) expression (PubMed:19592491). This is done by the phosphorylation of SRSF2, leading to the suppression of p53/TP53 phosphorylation thereby relieving the repressive effect of p53/TP53 on cyclin-D1 (CCND1) expression (PubMed:21205200). Phosphorylates ACIN1, and redistributes it from the nuclear speckles to the nucleoplasm, resulting in cyclin A1 but not cyclin A2 up-regulation (PubMed:18559500). Plays an essential role in spliceosomal B complex formation via the phosphorylation of DDX23/PRP28 (PubMed:18425142). Probably by phosphorylating DDX23, leads to the suppression of incorrect R-loops formed during transcription; R-loops are composed of a DNA:RNA hybrid and the associated non-template single-stranded DNA (PubMed:28076779). Can mediate hepatitis B virus (HBV) core protein phosphorylation (PubMed:12134018). Plays a negative role in the regulation of HBV replication through a mechanism not involving the phosphorylation of the core protein but by reducing the packaging efficiency of the pregenomic RNA (pgRNA) without affecting the formation of the viral core particles (PubMed:16122776).', 'SRPK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Chromosome, Cytoplasm, Differentiation, Kinase, mRNA processing, mRNA splicing, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (451, '6G76', '', 'Ribosomal protein S6 kinase alpha-6', 'Constitutively active serine/threonine-protein kinase that exhibits growth-factor-independent kinase activity and that may participate in p53/TP53-dependent cell growth arrest signaling and play an inhibitory role during embryogenesis.', 'RPS6KA6', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (452, '5AX9', '', 'TRAF2 and NCK-interacting protein kinase', 'Serine/threonine kinase that acts as an essential activator of the Wnt signaling pathway. Recruited to promoters of Wnt target genes and required to activate their expression. May act by phosphorylating TCF4/TCF7L2. Appears to act upstream of the JUN N-terminal pathway. May play a role in the response to environmental stress. Part of a signaling complex composed of NEDD4, RAP2A and TNIK which regulates neuronal dendrite extension and arborization during development. More generally, it may play a role in cytoskeletal rearrangements and regulate cell spreading. Phosphorylates SMAD1 on Thr-322.', 'TNIK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Endosome, Intellectual disability, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (453, '3KUL', '', 'Ephrin type-A receptor 8', 'Receptor tyrosine kinase which binds promiscuously GPI-anchored ephrin-A family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. The GPI-anchored ephrin-A EFNA2, EFNA3, and EFNA5 are able to activate EPHA8 through phosphorylation. With EFNA5 may regulate integrin-mediated cell adhesion and migration on fibronectin substrate but also neurite outgrowth. During development of the nervous system also plays a role in axon guidance. Downstream effectors of the EPHA8 signaling pathway include FYN which promotes cell adhesion upon activation by EPHA8 and the MAP kinases in the stimulation of neurite outgrowth (By similarity).', 'EPHA8', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell membrane, Cell projection, Developmental protein, Endosome, Glycoprotein, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (454, '3MTL', '', 'Cyclin-dependent kinase 16', 'Protein kinase that plays a role in vesicle-mediated transport processes and exocytosis. Regulates GH1 release by brain neurons. Phosphorylates NSF, and thereby regulates NSF oligomerization. Required for normal spermatogenesis. Regulates neuron differentiation and dendrite development (By similarity). Plays a role in the regulation of insulin secretion in response to changes in blood glucose levels. Can phosphorylate CCNY at ''Ser-336'' (in vitro).', 'CDK16', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Cytoplasmic vesicle, Differentiation, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Spermatogenesis, Synapse, Synaptosome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (460, '7F3M', '', 'Fibroblast growth factor receptor 4', 'Tyrosine-protein kinase that acts as a cell-surface receptor for fibroblast growth factors and plays a role in the regulation of cell proliferation, differentiation and migration, and in regulation of lipid metabolism, bile acid biosynthesis, glucose uptake, vitamin D metabolism and phosphate homeostasis. Required for normal down-regulation of the expression of CYP7A1, the rate-limiting enzyme in bile acid synthesis, in response to FGF19. Phosphorylates PLCG1 and FRS2. Ligand binding leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate. Phosphorylation of FRS2 triggers recruitment of GRB2, GAB1, PIK3R1 and SOS1, and mediates activation of RAS, MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. Promotes SRC-dependent phosphorylation of the matrix protease MMP14 and its lysosomal degradation. FGFR4 signaling is down-regulated by receptor internalization and degradation; MMP14 promotes internalization and degradation of FGFR4. Mutations that lead to constitutive kinase activation or impair normal FGFR4 inactivation lead to aberrant signaling.', 'FGFR4', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Direct protein sequencing, Disulfide bond, Endoplasmic reticulum, Endosome, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (455, '8T7T', '', 'eIF-2-alpha kinase GCN2', 'Metabolic-stress sensing protein kinase that phosphorylates the alpha subunit of eukaryotic translation initiation factor 2 (EIF2S1/eIF-2-alpha) in response to low amino acid availability (PubMed:25329545, PubMed:32610081). Plays a role as an activator of the integrated stress response (ISR) required for adaptation to amino acid starvation (By similarity). EIF2S1/eIF-2-alpha phosphorylation in response to stress converts EIF2S1/eIF-2-alpha into a global protein synthesis inhibitor, leading to a global attenuation of cap-dependent translation, and thus to a reduced overall utilization of amino acids, while concomitantly initiating the preferential translation of ISR-specific mRNAs, such as the transcriptional activator ATF4, and hence allowing ATF4-mediated reprogramming of amino acid biosynthetic gene expression to alleviate nutrient depletion (PubMed:32610081). Binds uncharged tRNAs (By similarity). Required for the translational induction of protein kinase PRKCH following amino acid starvation (By similarity). Involved in cell cycle arrest by promoting cyclin D1 mRNA translation repression after the unfolded protein response pathway (UPR) activation or cell cycle inhibitor CDKN1A/p21 mRNA translation activation in response to amino acid deprivation (PubMed:26102367). Plays a role in the consolidation of synaptic plasticity, learning as well as formation of long-term memory (By similarity). Plays a role in neurite outgrowth inhibition (By similarity). Plays a proapoptotic role in response to glucose deprivation (By similarity). Promotes global cellular protein synthesis repression in response to UV irradiation independently of the stress-activated protein kinase/c-Jun N-terminal kinase (SAPK/JNK) and p38 MAPK signaling pathways (By similarity). Plays a role in the antiviral response against alphavirus infection; impairs early viral mRNA translation of the incoming genomic virus RNA, thus preventing alphavirus replication (By similarity).', 'EIF2AK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Activation of host autophagy by virus, Activator, Adaptive immunity, Alternative splicing, Antiviral defense, ATP-binding, Cell cycle, Coiled coil, Cytoplasm, Disease variant, Growth arrest, Host-virus interaction, Immunity, Kinase, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, RNA-binding, Serine/threonine-protein kinase, Stress response, Transferase, Translation regulation, tRNA-binding');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (456, '7Z5W', '', 'Proto-oncogene tyrosine-protein kinase ROS', 'Receptor tyrosine kinase (RTK) that plays a role in epithelial cell differentiation and regionalization of the proximal epididymal epithelium. NELL2 is an endogenous ligand for ROS1. Upon endogenous stimulation by NELL2, ROS1 activates the intracellular signaling pathway and triggers epididymal epithelial differentiation and subsequent sperm maturation (By similarity). May activate several downstream signaling pathways related to cell differentiation, proliferation, growth and survival including the PI3 kinase-mTOR signaling pathway. Mediates the phosphorylation of PTPN11, an activator of this pathway. May also phosphorylate and activate the transcription factor STAT3 to control anchorage-independent cell growth. Mediates the phosphorylation and the activation of VAV3, a guanine nucleotide exchange factor regulating cell morphology. May activate other downstream signaling proteins including AKT1, MAPK1, MAPK3, IRS1 and PLCG2.', 'ROS1', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Chromosomal rearrangement, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (457, '1V0O', 'MEKYHGLEKIGEGTYGVVYKAQNNYGETFALKKIRLEKEDEGIPSTTIREISILKELKHSNIVKLYDVIHTKKRLVLVFEHLDQDLKKLLDVCEGGLESVTAKSFLLQLLNGIAYCHDRRVLHRDLKPQNLLINREGELKIADFGLARAFGIPVRKYTHEVVTLWYRAPDVLMGSKKYSTTIDIWSVGCIFAEMVNGTPLFPGVSEADQLMRIFRILGTPNSKNWPNVTELPKYDPNFTVYEPLPWESFLKGLDESGIDLLSKMLKLDPNQRITAKQALEHAYFKENN', 'Cyclin-dependent kinase 2 homolog', 'Serine/threonine-protein kinase (PubMed:8844681, PubMed:14604523). Involved in the control of the cell cycle (By similarity). Required for entry into S-phase and mitosis (By similarity). Probable component of the kinase complex that phosphorylates the repetitive C-terminus of RNA polymerase II (By similarity). In schizonts, phosphorylates ORC1 resulting in its dissociation from DNA, relocalization to the cytoplasm and likely its degradation (By similarity).', 'CRK2', 'Plasmodium falciparum (isolate K1 / Thailand)', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, ATP-binding, Cell cycle, Cell division, Cytoplasm, Kinase, Magnesium, Metal-binding, Mitosis, Nucleotide-binding, Phosphoprotein, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (458, '4AW2', '', 'Serine/threonine-protein kinase MRCK alpha', 'Serine/threonine-protein kinase which is an important downstream effector of CDC42 and plays a role in the regulation of cytoskeleton reorganization and cell migration (PubMed:9418861). Regulates actin cytoskeletal reorganization via phosphorylation of PPP1R12A and MYL9/MLC2 (PubMed:21457715). In concert with MYO18A and LURAP1, is involved in modulating lamellar actomyosin retrograde flow that is crucial to cell protrusion and migration (PubMed:18854160). Phosphorylates: PPP1R12C, LIMK1 and LIMK2. May play a role in TFRC-mediated iron uptake. In concert with FAM89B/LRAP25 mediates the targeting of LIMK1 to the lamellipodium resulting in its activation and subsequent phosphorylation of CFL1 which is important for lamellipodial F-actin regulation (By similarity). Triggers the formation of an extrusion apical actin ring required for epithelial extrusion of apoptotic cells (By similarity).', 'Cdc42bpa', 'Rattus norvegicus', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Coiled coil, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (459, '4PED', '', 'Atypical kinase COQ8A, mitochondrial', 'Atypical kinase involved in the biosynthesis of coenzyme Q, also named ubiquinone, an essential lipid-soluble electron transporter for aerobic cellular respiration (PubMed:25498144, PubMed:21296186, PubMed:25540914, PubMed:27499294). Its substrate specificity is unclear: does not show any protein kinase activity (PubMed:25498144, PubMed:27499294). Probably acts as a small molecule kinase, possibly a lipid kinase that phosphorylates a prenyl lipid in the ubiquinone biosynthesis pathway, as suggested by its ability to bind coenzyme Q lipid intermediates (PubMed:25498144, PubMed:27499294). Shows an unusual selectivity for binding ADP over ATP (PubMed:25498144).', 'COQ8A', 'Homo sapiens', '{[''2.7.-.-'']}', '3D-structure, Alternative splicing, ATP-binding, Direct protein sequencing, Disease variant, Kinase, Membrane, Mitochondrion, Neurodegeneration, Nucleotide-binding, Primary mitochondrial disease, Reference proteome, Transferase, Transit peptide, Transmembrane, Transmembrane helix, Ubiquinone biosynthesis');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (493, '3AGL', '', 'cAMP-dependent protein kinase catalytic subunit alpha', 'Phosphorylates a large number of substrates in the cytoplasm and the nucleus (PubMed:15642694, PubMed:15905176, PubMed:16387847, PubMed:17333334, PubMed:17565987, PubMed:17693412, PubMed:18836454, PubMed:19949837, PubMed:20356841, PubMed:21085490, PubMed:21514275, PubMed:21812984, PubMed:31112131). Phosphorylates CDC25B, ABL1, NFKB1, CLDN3, PSMC5/RPT6, PJA2, RYR2, RORA, SOX9 and VASP (PubMed:15642694, PubMed:15905176, PubMed:16387847, PubMed:17333334, PubMed:17565987, PubMed:17693412, PubMed:18836454, PubMed:19949837, PubMed:20356841, PubMed:21085490, PubMed:21514275, PubMed:21812984). Regulates the abundance of compartmentalized pools of its regulatory subunits through phosphorylation of PJA2 which binds and ubiquitinates these subunits, leading to their subsequent proteolysis (PubMed:21423175). RORA is activated by phosphorylation (PubMed:21514275). Required for glucose-mediated adipogenic differentiation increase and osteogenic differentiation inhibition from osteoblasts (PubMed:19949837). Involved in chondrogenesis by mediating phosphorylation of SOX9 (By similarity). Involved in the regulation of platelets in response to thrombin and collagen; maintains circulating platelets in a resting state by phosphorylating proteins in numerous platelet inhibitory pathways when in complex with NF-kappa-B (NFKB1 and NFKB2) and I-kappa-B-alpha (NFKBIA), but thrombin and collagen disrupt these complexes and free active PRKACA stimulates platelets and leads to platelet aggregation by phosphorylating VASP (PubMed:15642694, PubMed:20356841). Prevents the antiproliferative and anti-invasive effects of alpha-difluoromethylornithine in breast cancer cells when activated (PubMed:17333334). RYR2 channel activity is potentiated by phosphorylation in presence of luminal Ca(2+), leading to reduced amplitude and increased frequency of store overload-induced Ca(2+) release (SOICR) characterized by an increased rate of Ca(2+) release and propagation velocity of spontaneous Ca(2+) waves, despite reduced wave amplitude and resting cytosolic Ca(2+) (PubMed:17693412). PSMC5/RPT6 activation by phosphorylation stimulates proteasome (PubMed:17565987). Negatively regulates tight junctions (TJs) in ovarian cancer cells via CLDN3 phosphorylation (PubMed:15905176). NFKB1 phosphorylation promotes NF-kappa-B p50-p50 DNA binding (PubMed:15642694). Required for phosphorylation of GLI transcription factors which inhibits them and prevents transcriptional activation of Hedgehog signaling pathway target genes (By similarity). GLI transcription factor phosphorylation is inhibited by interaction of PRKACA with SMO which sequesters PRKACA at the cell membrane (By similarity). Involved in embryonic development by down-regulating the Hedgehog (Hh) signaling pathway that determines embryo pattern formation and morphogenesis most probably through the regulation of OFD1 in ciliogenesis (PubMed:33934390). Prevents meiosis resumption in prophase-arrested oocytes via CDC25B inactivation by phosphorylation (By similarity). May also regulate rapid eye movement (REM) sleep in the pedunculopontine tegmental (PPT) (By similarity). Phosphorylates APOBEC3G and AICDA (PubMed:16387847, PubMed:18836454). Phosphorylates HSF1; this phosphorylation promotes HSF1 nuclear localization and transcriptional activity upon heat shock (PubMed:21085490). Acts as a negative regulator of mTORC1 by mediating phosphorylation of RPTOR (PubMed:31112131).', 'PRKACA', 'Homo sapiens', '{[''2.7.11.11'']}', '3D-structure, Alternative splicing, ATP-binding, cAMP, Cell membrane, Cell projection, Cilium, Cushing syndrome, Cytoplasm, Cytoplasmic vesicle, Disease variant, Flagellum, Kinase, Lipoprotein, Membrane, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (461, '7TYJ', '', 'Insulin receptor-related protein', 'Receptor with tyrosine-protein kinase activity. Functions as a pH sensing receptor which is activated by increased extracellular pH. Activates an intracellular signaling pathway that involves IRS1 and AKT1/PKB.', 'INSRR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cleavage on pair of basic residues, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (462, '8DFM', '', 'Mast/stem cell growth factor receptor Kit', 'Tyrosine-protein kinase that acts as a cell-surface receptor for the cytokine KITLG/SCF and plays an essential role in the regulation of cell survival and proliferation, hematopoiesis, stem cell maintenance, gametogenesis, mast cell development, migration and function, and in melanogenesis. In response to KITLG/SCF binding, KIT can activate several signaling pathways. Phosphorylates PIK3R1, PLCG1, SH2B2/APS and CBL. Activates the AKT1 signaling pathway by phosphorylation of PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase. Activated KIT also transmits signals via GRB2 and activation of RAS, RAF1 and the MAP kinases MAPK1/ERK2 and/or MAPK3/ERK1. Promotes activation of STAT family members STAT1, STAT3, STAT5A and STAT5B. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate. KIT signaling is modulated by protein phosphatases, and by rapid internalization and degradation of the receptor. Activated KIT promotes phosphorylation of the protein phosphatases PTPN6/SHP-1 and PTPRU, and of the transcription factors STAT1, STAT3, STAT5A and STAT5B. Promotes phosphorylation of PIK3R1, CBL, CRK (isoform Crk-II), LYN, MAPK1/ERK2 and/or MAPK3/ERK1, PLCG1, SRC and SHC1.', 'KIT', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Direct protein sequencing, Disease variant, Disulfide bond, Glycoprotein, Immunoglobulin domain, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (463, '7MN5', '', 'Receptor tyrosine-protein kinase erbB-3', 'Tyrosine-protein kinase that plays an essential role as cell surface receptor for neuregulins. Binds to neuregulin-1 (NRG1) and is activated by it; ligand-binding increases phosphorylation on tyrosine residues and promotes its association with the p85 subunit of phosphatidylinositol 3-kinase (PubMed:20682778). May also be activated by CSPG5 (PubMed:15358134). Involved in the regulation of myeloid cell differentiation (PubMed:27416908).', 'ERBB3', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (464, '8YGW', '', 'Mitogen-activated protein kinase 11', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway (PubMed:12452429, PubMed:20626350, PubMed:35857590). MAPK11 is one of the four p38 MAPKs which play an important role in the cascades of cellular responses evoked by extracellular stimuli such as pro-inflammatory cytokines or physical stress leading to direct activation of transcription factors (PubMed:12452429, PubMed:20626350, PubMed:35857590). Accordingly, p38 MAPKs phosphorylate a broad range of proteins and it has been estimated that they may have approximately 200 to 300 substrates each (PubMed:12452429, PubMed:20626350, PubMed:35857590). MAPK11 functions are mostly redundant with those of MAPK14 (PubMed:12452429, PubMed:20626350, PubMed:35857590). Some of the targets are downstream kinases which are activated through phosphorylation and further phosphorylate additional targets (PubMed:12452429, PubMed:20626350). RPS6KA5/MSK1 and RPS6KA4/MSK2 can directly phosphorylate and activate transcription factors such as CREB1, ATF1, the NF-kappa-B isoform RELA/NFKB3, STAT1 and STAT3, but can also phosphorylate histone H3 and the nucleosomal protein HMGN1 (PubMed:9687510). RPS6KA5/MSK1 and RPS6KA4/MSK2 play important roles in the rapid induction of immediate-early genes in response to stress or mitogenic stimuli, either by inducing chromatin remodeling or by recruiting the transcription machinery. On the other hand, two other kinase targets, MAPKAPK2/MK2 and MAPKAPK3/MK3, participate in the control of gene expression mostly at the post-transcriptional level, by phosphorylating ZFP36 (tristetraprolin) and ELAVL1, and by regulating EEF2K, which is important for the elongation of mRNA during translation. MKNK1/MNK1 and MKNK2/MNK2, two other kinases activated by p38 MAPKs, regulate protein synthesis by phosphorylating the initiation factor EIF4E2 (PubMed:11154262). In the cytoplasm, the p38 MAPK pathway is an important regulator of protein turnover. For example, CFLAR is an inhibitor of TNF-induced apoptosis whose proteasome-mediated degradation is regulated by p38 MAPK phosphorylation. Ectodomain shedding of transmembrane proteins is regulated by p38 MAPKs as well. In response to inflammatory stimuli, p38 MAPKs phosphorylate the membrane-associated metalloprotease ADAM17. Such phosphorylation is required for ADAM17-mediated ectodomain shedding of TGF-alpha family ligands, which results in the activation of EGFR signaling and cell proliferation. Additional examples of p38 MAPK substrates are the FGFR1. FGFR1 can be translocated from the extracellular space into the cytosol and nucleus of target cells, and regulates processes such as rRNA synthesis and cell growth. FGFR1 translocation requires p38 MAPK activation. In the nucleus, many transcription factors are phosphorylated and activated by p38 MAPKs in response to different stimuli. Classical examples include ATF1, ATF2, ATF6, ELK1, PTPRH, DDIT3, TP53/p53 and MEF2C and MEF2A (PubMed:9430721, PubMed:10330143, PubMed:15356147). The p38 MAPKs are emerging as important modulators of gene expression by regulating chromatin modifiers and remodelers (PubMed:9430721, PubMed:10330143, PubMed:15356147). The promoters of several genes involved in the inflammatory response, such as IL6, IL8 and IL12B, display a p38 MAPK-dependent enrichment of histone H3 phosphorylation on ''Ser-10'' (H3S10ph) in LPS-stimulated myeloid cells. This phosphorylation enhances the accessibility of the cryptic NF-kappa-B-binding sites marking promoters for increased NF-kappa-B recruitment. Phosphorylates NLRP1 downstream of MAP3K20/ZAK in response to UV-B irradiation and ribosome collisions, promoting activation of the NLRP1 inflammasome and pyroptosis (PubMed:35857590).', 'MAPK11', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (465, '4OLI', '', 'Non-receptor tyrosine-protein kinase TYK2', 'Tyrosine kinase of the non-receptor type involved in numerous cytokines and interferons signaling, which regulates cell growth, development, cell migration, innate and adaptive immunity (PubMed:8232552, PubMed:7813427, PubMed:7657660, PubMed:10995743, PubMed:10542297). Plays both structural and catalytic roles in numerous interleukins and interferons (IFN-alpha/beta) signaling (PubMed:10542297). Associates with heterodimeric cytokine receptor complexes and activates STAT family members including STAT1, STAT3, STAT4 or STAT6 (PubMed:10542297, PubMed:7638186). The heterodimeric cytokine receptor complexes are composed of (1) a TYK2-associated receptor chain (IFNAR1, IL12RB1, IL10RB or IL13RA1), and (2) a second receptor chain associated either with JAK1 or JAK2 (PubMed:7813427, PubMed:10542297, PubMed:7526154, PubMed:25762719). In response to cytokine-binding to receptors, phosphorylates and activates receptors (IFNAR1, IL12RB1, IL10RB or IL13RA1), creating docking sites for STAT members (PubMed:7526154, PubMed:7657660). In turn, recruited STATs are phosphorylated by TYK2 (or JAK1/JAK2 on the second receptor chain), form homo- and heterodimers, translocate to the nucleus, and regulate cytokine/growth factor responsive genes (PubMed:7657660, PubMed:10542297, PubMed:25762719). Negatively regulates STAT3 activity by promototing phosphorylation at a specific tyrosine that differs from the site used for signaling (PubMed:29162862).', 'TYK2', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SH2 domain, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (466, '4AAA', '', 'Cyclin-dependent kinase-like 2', 'Unknown', 'CDKL2', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (467, '4NIF', '', 'Ribosomal protein S6 kinase alpha-1', 'Serine/threonine-protein kinase that acts downstream of ERK (MAPK1/ERK2 and MAPK3/ERK1) signaling and mediates mitogenic and stress-induced activation of the transcription factors CREB1, ETV1/ER81 and NR4A1/NUR77, regulates translation through RPS6 and EIF4B phosphorylation, and mediates cellular proliferation, survival, and differentiation by modulating mTOR signaling and repressing pro-apoptotic function of BAD and DAPK1 (PubMed:10679322, PubMed:16223362, PubMed:15117958, PubMed:12213813, PubMed:9430688, PubMed:17360704, PubMed:26158630, PubMed:18722121, PubMed:35772404). In fibroblast, is required for EGF-stimulated phosphorylation of CREB1, which results in the subsequent transcriptional activation of several immediate-early genes (PubMed:18508509, PubMed:18813292). In response to mitogenic stimulation (EGF and PMA), phosphorylates and activates NR4A1/NUR77 and ETV1/ER81 transcription factors and the cofactor CREBBP (PubMed:12213813, PubMed:16223362). Upon insulin-derived signal, acts indirectly on the transcription regulation of several genes by phosphorylating GSK3B at ''Ser-9'' and inhibiting its activity (PubMed:18508509, PubMed:18813292). Phosphorylates RPS6 in response to serum or EGF via an mTOR-independent mechanism and promotes translation initiation by facilitating assembly of the pre-initiation complex (PubMed:17360704). In response to insulin, phosphorylates EIF4B, enhancing EIF4B affinity for the EIF3 complex and stimulating cap-dependent translation (PubMed:16763566). Is involved in the mTOR nutrient-sensing pathway by directly phosphorylating TSC2 at ''Ser-1798'', which potently inhibits TSC2 ability to suppress mTOR signaling, and mediates phosphorylation of RPTOR, which regulates mTORC1 activity and may promote rapamycin-sensitive signaling independently of the PI3K/AKT pathway (PubMed:15342917). Also involved in feedback regulation of mTORC1 and mTORC2 by phosphorylating DEPTOR (PubMed:22017876). Mediates cell survival by phosphorylating the pro-apoptotic proteins BAD and DAPK1 and suppressing their pro-apoptotic function (PubMed:10679322, PubMed:16213824). Promotes the survival of hepatic stellate cells by phosphorylating CEBPB in response to the hepatotoxin carbon tetrachloride (CCl4) (PubMed:11684016). Mediates induction of hepatocyte prolifration by TGFA through phosphorylation of CEBPB (PubMed:18508509, PubMed:18813292). Is involved in cell cycle regulation by phosphorylating the CDK inhibitor CDKN1B, which promotes CDKN1B association with 14-3-3 proteins and prevents its translocation to the nucleus and inhibition of G1 progression (PubMed:18508509, PubMed:18813292). Phosphorylates EPHA2 at ''Ser-897'', the RPS6KA-EPHA2 signaling pathway controls cell migration (PubMed:26158630). In response to mTORC1 activation, phosphorylates EIF4B at ''Ser-406'' and ''Ser-422'' which stimulates bicarbonate cotransporter SLC4A7 mRNA translation, increasing SLC4A7 protein abundance and function (PubMed:35772404).', 'RPS6KA1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cytoplasm, Host-virus interaction, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Stress response, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (468, '6P5S', '', 'Homeodomain-interacting protein kinase 2', 'Serine/threonine-protein kinase involved in transcription regulation, p53/TP53-mediated cellular apoptosis and regulation of the cell cycle. Acts as a corepressor of several transcription factors, including SMAD1 and POU4F1/Brn3a and probably NK homeodomain transcription factors. Phosphorylates PDX1, ATF1, PML, p53/TP53, CREB1, CTBP1, CBX4, RUNX1, EP300, CTNNB1, HMGA1, ZBTB4 and DAZAP2. Inhibits cell growth and promotes apoptosis through the activation of p53/TP53 both at the transcription level and at the protein level (by phosphorylation and indirect acetylation). The phosphorylation of p53/TP53 may be mediated by a p53/TP53-HIPK2-AXIN1 complex. Involved in the response to hypoxia by acting as a transcriptional co-suppressor of HIF1A. Mediates transcriptional activation of TP73. In response to TGFB, cooperates with DAXX to activate JNK. Negative regulator through phosphorylation and subsequent proteasomal degradation of CTNNB1 and the antiapoptotic factor CTBP1. In the Wnt/beta-catenin signaling pathway acts as an intermediate kinase between MAP3K7/TAK1 and NLK to promote the proteasomal degradation of MYB. Phosphorylates CBX4 upon DNA damage and promotes its E3 SUMO-protein ligase activity. Activates CREB1 and ATF1 transcription factors by phosphorylation in response to genotoxic stress. In response to DNA damage, stabilizes PML by phosphorylation. PML, HIPK2 and FBXO3 may act synergically to activate p53/TP53-dependent transactivation. Promotes angiogenesis, and is involved in erythroid differentiation, especially during fetal liver erythropoiesis. Phosphorylation of RUNX1 and EP300 stimulates EP300 transcription regulation activity. Triggers ZBTB4 protein degradation in response to DNA damage. In response to DNA damage, phosphorylates DAZAP2 which localizes DAZAP2 to the nucleus, reduces interaction of DAZAP2 with HIPK2 and prevents DAZAP2-dependent ubiquitination of HIPK2 by E3 ubiquitin-protein ligase SIAH1 and subsequent proteasomal degradation (PubMed:33591310). Modulates HMGA1 DNA-binding affinity. In response to high glucose, triggers phosphorylation-mediated subnuclear localization shifting of PDX1. Involved in the regulation of eye size, lens formation and retinal lamination during late embryogenesis.', 'HIPK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, DNA damage, Host-virus interaction, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (469, '7SYD', '', 'Epidermal growth factor receptor', 'Receptor tyrosine kinase binding ligands of the EGF family and activating several signaling cascades to convert extracellular cues into appropriate cellular responses (PubMed:2790960, PubMed:10805725, PubMed:27153536). Known ligands include EGF, TGFA/TGF-alpha, AREG, epigen/EPGN, BTC/betacellulin, epiregulin/EREG and HBEGF/heparin-binding EGF (PubMed:2790960, PubMed:7679104, PubMed:8144591, PubMed:9419975, PubMed:15611079, PubMed:12297049, PubMed:27153536, PubMed:20837704, PubMed:17909029). Ligand binding triggers receptor homo- and/or heterodimerization and autophosphorylation on key cytoplasmic residues. The phosphorylated receptor recruits adapter proteins like GRB2 which in turn activates complex downstream signaling cascades. Activates at least 4 major downstream signaling cascades including the RAS-RAF-MEK-ERK, PI3 kinase-AKT, PLCgamma-PKC and STATs modules (PubMed:27153536). May also activate the NF-kappa-B signaling cascade (PubMed:11116146). Also directly phosphorylates other proteins like RGS16, activating its GTPase activity and probably coupling the EGF receptor signaling to the G protein-coupled receptor signaling (PubMed:11602604). Also phosphorylates MUC1 and increases its interaction with SRC and CTNNB1/beta-catenin (PubMed:11483589). Positively regulates cell migration via interaction with CCDC88A/GIV which retains EGFR at the cell membrane following ligand stimulation, promoting EGFR signaling which triggers cell migration (PubMed:20462955). Plays a role in enhancing learning and memory performance (By similarity). Plays a role in mammalian pain signaling (long-lasting hypersensitivity) (By similarity).', 'EGFR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Developmental protein, Direct protein sequencing, Disease variant, Disulfide bond, Endoplasmic reticulum, Endosome, Glycoprotein, Golgi apparatus, Host cell receptor for virus entry, Host-virus interaction, Hydroxylation, Isopeptide bond, Kinase, Lipoprotein, Membrane, Methylation, Nucleotide-binding, Nucleus, Palmitate, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (470, '8TZB', '', 'Leucine-rich repeat serine/threonine-protein kinase 2', 'Serine/threonine-protein kinase which phosphorylates a broad range of proteins involved in multiple processes such as neuronal plasticity, innate immunity, autophagy, and vesicle trafficking (PubMed:20949042, PubMed:22012985, PubMed:26824392, PubMed:27830463, PubMed:29125462, PubMed:28720718, PubMed:29127255, PubMed:30398148, PubMed:29212815, PubMed:30635421, PubMed:21850687, PubMed:23395371, PubMed:17114044, PubMed:24687852, PubMed:26014385, PubMed:25201882). Is a key regulator of RAB GTPases by regulating the GTP/GDP exchange and interaction partners of RABs through phosphorylation (PubMed:26824392, PubMed:28720718, PubMed:29127255, PubMed:30398148, PubMed:29212815, PubMed:29125462, PubMed:30635421). Phosphorylates RAB3A, RAB3B, RAB3C, RAB3D, RAB5A, RAB5B, RAB5C, RAB8A, RAB8B, RAB10, RAB12, RAB35, and RAB43 (PubMed:26824392, PubMed:28720718, PubMed:29127255, PubMed:30398148, PubMed:29212815, PubMed:29125462, PubMed:30635421, PubMed:23395371). Regulates the RAB3IP-catalyzed GDP/GTP exchange for RAB8A through the phosphorylation of ''Thr-72'' on RAB8A (PubMed:26824392). Inhibits the interaction between RAB8A and GDI1 and/or GDI2 by phosphorylating ''Thr-72'' on RAB8A (PubMed:26824392). Regulates primary ciliogenesis through phosphorylation of RAB8A and RAB10, which promotes SHH signaling in the brain (PubMed:29125462, PubMed:30398148). Together with RAB29, plays a role in the retrograde trafficking pathway for recycling proteins, such as mannose-6-phosphate receptor (M6PR), between lysosomes and the Golgi apparatus in a retromer-dependent manner (PubMed:23395371). Regulates neuronal process morphology in the intact central nervous system (CNS) (PubMed:17114044). Plays a role in synaptic vesicle trafficking (PubMed:24687852). Plays an important role in recruiting SEC16A to endoplasmic reticulum exit sites (ERES) and in regulating ER to Golgi vesicle-mediated transport and ERES organization (PubMed:25201882). Positively regulates autophagy through a calcium-dependent activation of the CaMKK/AMPK signaling pathway (PubMed:22012985). The process involves activation of nicotinic acid adenine dinucleotide phosphate (NAADP) receptors, increase in lysosomal pH, and calcium release from lysosomes (PubMed:22012985). Phosphorylates PRDX3 (PubMed:21850687). By phosphorylating APP on ''Thr-743'', which promotes the production and the nuclear translocation of the APP intracellular domain (AICD), regulates dopaminergic neuron apoptosis (PubMed:28720718). Acts as a positive regulator of innate immunity by mediating phosphorylation of RIPK2 downstream of NOD1 and NOD2, thereby enhancing RIPK2 activation (PubMed:27830463). Independent of its kinase activity, inhibits the proteasomal degradation of MAPT, thus promoting MAPT oligomerization and secretion (PubMed:26014385). In addition, has GTPase activity via its Roc domain which regulates LRRK2 kinase activity (PubMed:18230735, PubMed:26824392, PubMed:29125462, PubMed:28720718, PubMed:29212815).', 'LRRK2', 'Homo sapiens', '{[''3.6.5.-'',''2.7.11.1'']}', '3D-structure, ATP-binding, Autophagy, Cell projection, Coiled coil, Cytoplasm, Cytoplasmic vesicle, Cytoskeleton, Differentiation, Disease variant, Endoplasmic reticulum, Endosome, Golgi apparatus, GTP-binding, GTPase activation, Hydrolase, Kinase, Leucine-rich repeat, Lysosome, Membrane, Mitochondrion, Mitochondrion outer membrane, Neurodegeneration, Nucleotide-binding, Parkinson disease, Parkinsonism, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Synapse, Transferase, Ubl conjugation, WD repeat');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (471, '2X10', '', 'Ephrin type-A receptor 2', 'Receptor tyrosine kinase which binds promiscuously membrane-bound ephrin-A family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Activated by the ligand ephrin-A1/EFNA1 regulates migration, integrin-mediated adhesion, proliferation and differentiation of cells. Regulates cell adhesion and differentiation through DSG1/desmoglein-1 and inhibition of the ERK1/ERK2 (MAPK3/MAPK1, respectively) signaling pathway. May also participate in UV radiation-induced apoptosis and have a ligand-independent stimulatory effect on chemotactic cell migration. During development, may function in distinctive aspects of pattern formation and subsequently in development of several fetal tissues. Involved for instance in angiogenesis, in early hindbrain development and epithelial proliferation and branching morphogenesis during mammary gland development. Engaged by the ligand ephrin-A5/EFNA5 may regulate lens fiber cells shape and interactions and be important for lens transparency development and maintenance. With ephrin-A2/EFNA2 may play a role in bone remodeling through regulation of osteoclastogenesis and osteoblastogenesis.', 'EPHA2', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, Apoptosis, ATP-binding, Cataract, Cell adhesion, Cell junction, Cell membrane, Cell projection, Differentiation, Disease variant, Disulfide bond, Glycoprotein, Host cell receptor for virus entry, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (472, '3BKB', '', 'Tyrosine-protein kinase Fes/Fps', 'Tyrosine-protein kinase that acts downstream of cell surface receptors and plays a role in the regulation of the actin cytoskeleton, microtubule assembly, cell attachment and cell spreading. Plays a role in FCER1 (high affinity immunoglobulin epsilon receptor)-mediated signaling in mast cells. Acts down-stream of the activated FCER1 receptor and the mast/stem cell growth factor receptor KIT. Plays a role in the regulation of mast cell degranulation. Plays a role in the regulation of cell differentiation and promotes neurite outgrowth in response to NGF signaling. Plays a role in cell scattering and cell migration in response to HGF-induced activation of EZR. Phosphorylates BCR and down-regulates BCR kinase activity. Phosphorylates HCLS1/HS1, PECAM1, STAT3 and TRIM28.', 'FES', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative splicing, ATP-binding, Cell junction, Cell membrane, Coiled coil, Cytoplasm, Cytoplasmic vesicle, Cytoskeleton, Golgi apparatus, Kinase, Lipid-binding, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, Transferase, Tumor suppressor, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (494, '3Q52', '', 'Serine/threonine-protein kinase PAK 1', 'Protein kinase involved in intracellular signaling pathways downstream of integrins and receptor-type kinases that plays an important role in cytoskeleton dynamics, in cell adhesion, migration, proliferation, apoptosis, mitosis, and in vesicle-mediated transport processes (PubMed:10551809, PubMed:11896197, PubMed:12876277, PubMed:14585966, PubMed:15611088, PubMed:17726028, PubMed:17989089, PubMed:30290153). Can directly phosphorylate BAD and protects cells against apoptosis (By similarity). Activated by interaction with CDC42 and RAC1 (PubMed:8805275, PubMed:9528787). Functions as a GTPase effector that links the Rho-related GTPases CDC42 and RAC1 to the JNK MAP kinase pathway (PubMed:8805275, PubMed:9528787). Phosphorylates and activates MAP2K1, and thereby mediates activation of downstream MAP kinases (By similarity). Involved in the reorganization of the actin cytoskeleton, actin stress fibers and of focal adhesion complexes (PubMed:9395435, PubMed:9032240). Phosphorylates the tubulin chaperone TBCB and thereby plays a role in the regulation of microtubule biogenesis and organization of the tubulin cytoskeleton (PubMed:15831477). Plays a role in the regulation of insulin secretion in response to elevated glucose levels (PubMed:22669945). Part of a ternary complex that contains PAK1, DVL1 and MUSK that is important for MUSK-dependent regulation of AChR clustering during the formation of the neuromuscular junction (NMJ) (By similarity). Activity is inhibited in cells undergoing apoptosis, potentially due to binding of CDC2L1 and CDC2L2 (PubMed:12624090). Phosphorylates MYL9/MLC2 (By similarity). Phosphorylates RAF1 at ''Ser-338'' and ''Ser-339'' resulting in: activation of RAF1, stimulation of RAF1 translocation to mitochondria, phosphorylation of BAD by RAF1, and RAF1 binding to BCL2 (PubMed:11733498). Phosphorylates SNAI1 at ''Ser-246'' promoting its transcriptional repressor activity by increasing its accumulation in the nucleus (PubMed:15833848). In podocytes, promotes NR3C2 nuclear localization (By similarity). Required for atypical chemokine receptor ACKR2-induced phosphorylation of LIMK1 and cofilin (CFL1) and for the up-regulation of ACKR2 from endosomal compartment to cell membrane, increasing its efficiency in chemokine uptake and degradation (PubMed:23633677). In synapses, seems to mediate the regulation of F-actin cluster formation performed by SHANK3, maybe through CFL1 phosphorylation and inactivation (By similarity). Plays a role in RUFY3-mediated facilitating gastric cancer cells migration and invasion (PubMed:25766321). In response to DNA damage, phosphorylates MORC2 which activates its ATPase activity and facilitates chromatin remodeling (PubMed:23260667). In neurons, plays a crucial role in regulating GABA(A) receptor synaptic stability and hence GABAergic inhibitory synaptic transmission through its role in F-actin stabilization (By similarity). In hippocampal neurons, necessary for the formation of dendritic spines and excitatory synapses; this function is dependent on kinase activity and may be exerted by the regulation of actomyosin contractility through the phosphorylation of myosin II regulatory light chain (MLC) (By similarity). Along with GIT1, positively regulates microtubule nucleation during interphase (PubMed:27012601). Phosphorylates FXR1, promoting its localization to stress granules and activity (PubMed:20417602).', 'PAK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Allosteric enzyme, Alternative splicing, Apoptosis, ATP-binding, Cell junction, Cell membrane, Cell projection, Chromosome, Cytoplasm, Cytoskeleton, Disease variant, Epilepsy, Exocytosis, Intellectual disability, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (473, '4PNI', '', 'Rhodopsin kinase GRK1', 'Retina-specific kinase involved in the signal turnoff via phosphorylation of rhodopsin (RHO), the G protein- coupled receptor that initiates the phototransduction cascade (PubMed:12686556, PubMed:16675451, PubMed:21299498). This rapid desensitization is essential for scotopic vision and permits rapid adaptation to changes in illumination (By similarity). May play a role in the maintenance of the outer nuclear layer in the retina (By similarity).', 'GRK1', 'Bos taurus', '{[''2.7.11.14'']}', '3D-structure, ATP-binding, Cell projection, Direct protein sequencing, Kinase, Lipoprotein, Membrane, Methylation, Nucleotide-binding, Phosphoprotein, Prenylation, Reference proteome, Sensory transduction, Serine/threonine-protein kinase, Transferase, Vision');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (474, '2ESM', '', 'Rho-associated protein kinase 1', 'Protein kinase which is a key regulator of the actin cytoskeleton and cell polarity (PubMed:10436159, PubMed:10652353, PubMed:11018042, PubMed:11283607, PubMed:17158456, PubMed:18573880, PubMed:19131646, PubMed:8617235, PubMed:9722579). Involved in regulation of smooth muscle contraction, actin cytoskeleton organization, stress fiber and focal adhesion formation, neurite retraction, cell adhesion and motility via phosphorylation of DAPK3, GFAP, LIMK1, LIMK2, MYL9/MLC2, TPPP, PFN1 and PPP1R12A (PubMed:10436159, PubMed:10652353, PubMed:11018042, PubMed:11283607, PubMed:17158456, PubMed:18573880, PubMed:19131646, PubMed:8617235, PubMed:9722579, PubMed:23093407, PubMed:23355470). Phosphorylates FHOD1 and acts synergistically with it to promote SRC-dependent non-apoptotic plasma membrane blebbing (PubMed:18694941). Phosphorylates JIP3 and regulates the recruitment of JNK to JIP3 upon UVB-induced stress (PubMed:19036714). Acts as a suppressor of inflammatory cell migration by regulating PTEN phosphorylation and stability (By similarity). Acts as a negative regulator of VEGF-induced angiogenic endothelial cell activation (PubMed:19181962). Required for centrosome positioning and centrosome-dependent exit from mitosis (By similarity). Plays a role in terminal erythroid differentiation (PubMed:21072057). Inhibits podocyte motility via regulation of actin cytoskeletal dynamics and phosphorylation of CFL1 (By similarity). Promotes keratinocyte terminal differentiation (PubMed:19997641). Involved in osteoblast compaction through the fibronectin fibrillogenesis cell-mediated matrix assembly process, essential for osteoblast mineralization (By similarity). May regulate closure of the eyelids and ventral body wall by inducing the assembly of actomyosin bundles (By similarity).', 'ROCK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Apoptosis, ATP-binding, Cell membrane, Cell projection, Coiled coil, Cytoplasm, Cytoskeleton, Direct protein sequencing, Golgi apparatus, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (475, '6V6Q', '', 'Fibroblast growth factor receptor 2', 'Tyrosine-protein kinase that acts as a cell-surface receptor for fibroblast growth factors and plays an essential role in the regulation of cell proliferation, differentiation, migration and apoptosis, and in the regulation of embryonic development. Required for normal embryonic patterning, trophoblast function, limb bud development, lung morphogenesis, osteogenesis and skin development. Plays an essential role in the regulation of osteoblast differentiation, proliferation and apoptosis, and is required for normal skeleton development. Promotes cell proliferation in keratinocytes and immature osteoblasts, but promotes apoptosis in differentiated osteoblasts. Phosphorylates PLCG1, FRS2 and PAK4. Ligand binding leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate. Phosphorylation of FRS2 triggers recruitment of GRB2, GAB1, PIK3R1 and SOS1, and mediates activation of RAS, MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. FGFR2 signaling is down-regulated by ubiquitination, internalization and degradation. Mutations that lead to constitutive kinase activation or impair normal FGFR2 maturation, internalization and degradation lead to aberrant signaling. Over-expressed FGFR2 promotes activation of STAT1.', 'FGFR2', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell membrane, Craniosynostosis, Cytoplasmic vesicle, Disease variant, Disulfide bond, Ectodermal dysplasia, Glycoprotein, Golgi apparatus, Heparin-binding, Immunoglobulin domain, Intellectual disability, Kinase, Lacrimo-auriculo-dento-digital syndrome, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (476, '6C9D', '', 'Serine/threonine-protein kinase MARK1', 'Serine/threonine-protein kinase (PubMed:23666762). Involved in cell polarity and microtubule dynamics regulation. Phosphorylates DCX, MAP2 and MAP4. Phosphorylates the microtubule-associated protein MAPT/TAU (PubMed:23666762). Involved in cell polarity by phosphorylating the microtubule-associated proteins MAP2, MAP4 and MAPT/TAU at KXGS motifs, causing detachment from microtubules, and their disassembly. Involved in the regulation of neuronal migration through its dual activities in regulating cellular polarity and microtubule dynamics, possibly by phosphorylating and regulating DCX. Also acts as a positive regulator of the Wnt signaling pathway, probably by mediating phosphorylation of dishevelled proteins (DVL1, DVL2 and/or DVL3).', 'MARK1', 'Homo sapiens', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Autism, Autism spectrum disorder, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Kinase, Lipid-binding, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (523, '6FD3', '', 'Serine/threonine-protein kinase PAK 3', 'Serine/threonine protein kinase that plays a role in a variety of different signaling pathways including cytoskeleton regulation, cell migration, or cell cycle regulation. Plays a role in dendrite spine morphogenesis as well as synapse formation and plasticity. Acts as a downstream effector of the small GTPases CDC42 and RAC1. Activation by the binding of active CDC42 and RAC1 results in a conformational change and a subsequent autophosphorylation on several serine and/or threonine residues. Phosphorylates MAPK4 and MAPK6 and activates the downstream target MAPKAPK5, a regulator of F-actin polymerization and cell migration. Additionally, phosphorylates TNNI3/troponin I to modulate calcium sensitivity and relaxation kinetics of thin myofilaments. May also be involved in early neuronal development. In hippocampal neurons, necessary for the formation of dendritic spines and excitatory synapses; this function is dependent on kinase activity and may be exerted by the regulation of actomyosin contractility through the phosphorylation of myosin II regulatory light chain (MLC) (By similarity).', 'PAK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Allosteric enzyme, Alternative splicing, ATP-binding, Cytoplasm, Developmental protein, Disease variant, Intellectual disability, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, SH3-binding, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (477, '2ROV', '', 'Rho-associated protein kinase 2', 'Protein kinase which is a key regulator of actin cytoskeleton and cell polarity. Involved in regulation of smooth muscle contraction, actin cytoskeleton organization, stress fiber and focal adhesion formation, neurite retraction, cell adhesion and motility via phosphorylation of ADD1, BRCA2, CNN1, EZR, DPYSL2, EP300, MSN, MYL9/MLC2, NPM1, RDX, PPP1R12A and VIM. Phosphorylates SORL1 and IRF4. Acts as a negative regulator of VEGF-induced angiogenic endothelial cell activation. Positively regulates the activation of p42/MAPK1-p44/MAPK3 and of p90RSK/RPS6KA1 during myogenic differentiation. Plays an important role in the timely initiation of centrosome duplication. Inhibits keratinocyte terminal differentiation. May regulate closure of the eyelids and ventral body wall through organization of actomyosin bundles. Plays a critical role in the regulation of spine and synaptic properties in the hippocampus. Plays a role in placental homeostasis during the perinatal period. Plays an important role in generating the circadian rhythm of the aortic myofilament Ca(2+) sensitivity and vascular contractility by modulating the myosin light chain phosphorylation.', 'Rock2', 'Rattus norvegicus', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Biological rhythms, Cell membrane, Coiled coil, Cytoplasm, Cytoskeleton, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (478, '4L46', '', 'Ribosomal protein S6 kinase beta-1', 'Serine/threonine-protein kinase that acts downstream of mTOR signaling in response to growth factors and nutrients to promote cell proliferation, cell growth and cell cycle progression (PubMed:11500364, PubMed:12801526, PubMed:14673156, PubMed:15071500, PubMed:15341740, PubMed:16286006, PubMed:17052453, PubMed:17053147, PubMed:17936702, PubMed:18952604, PubMed:19085255, PubMed:19720745, PubMed:19935711, PubMed:19995915, PubMed:23429703, PubMed:28178239, PubMed:22017876). Regulates protein synthesis through phosphorylation of EIF4B, RPS6 and EEF2K, and contributes to cell survival by repressing the pro-apoptotic function of BAD (PubMed:11500364, PubMed:12801526, PubMed:14673156, PubMed:15071500, PubMed:15341740, PubMed:16286006, PubMed:17052453, PubMed:17053147, PubMed:17936702, PubMed:18952604, PubMed:19085255, PubMed:19720745, PubMed:19935711, PubMed:19995915, PubMed:23429703, PubMed:28178239, PubMed:22017876). Under conditions of nutrient depletion, the inactive form associates with the EIF3 translation initiation complex (PubMed:16286006). Upon mitogenic stimulation, phosphorylation by the mechanistic target of rapamycin complex 1 (mTORC1) leads to dissociation from the EIF3 complex and activation (PubMed:16286006). The active form then phosphorylates and activates several substrates in the pre-initiation complex, including the EIF2B complex and the cap-binding complex component EIF4B (PubMed:16286006). Also controls translation initiation by phosphorylating a negative regulator of EIF4A, PDCD4, targeting it for ubiquitination and subsequent proteolysis (PubMed:17053147). Promotes initiation of the pioneer round of protein synthesis by phosphorylating POLDIP3/SKAR (PubMed:15341740). In response to IGF1, activates translation elongation by phosphorylating EEF2 kinase (EEF2K), which leads to its inhibition and thus activation of EEF2 (PubMed:11500364). Also plays a role in feedback regulation of mTORC2 by mTORC1 by phosphorylating RICTOR, resulting in the inhibition of mTORC2 and AKT1 signaling (PubMed:19720745, PubMed:19935711, PubMed:19995915). Also involved in feedback regulation of mTORC1 and mTORC2 by phosphorylating DEPTOR (PubMed:22017876). Mediates cell survival by phosphorylating the pro-apoptotic protein BAD and suppressing its pro-apoptotic function (By similarity). Phosphorylates mitochondrial URI1 leading to dissociation of a URI1-PPP1CC complex (PubMed:17936702). The free mitochondrial PPP1CC can then dephosphorylate RPS6KB1 at Thr-412, which is proposed to be a negative feedback mechanism for the RPS6KB1 anti-apoptotic function (PubMed:17936702). Mediates TNF-alpha-induced insulin resistance by phosphorylating IRS1 at multiple serine residues, resulting in accelerated degradation of IRS1 (PubMed:18952604). In cells lacking functional TSC1-2 complex, constitutively phosphorylates and inhibits GSK3B (PubMed:17052453). May be involved in cytoskeletal rearrangement through binding to neurabin (By similarity). Phosphorylates and activates the pyrimidine biosynthesis enzyme CAD, downstream of MTOR (PubMed:23429703). Following activation by mTORC1, phosphorylates EPRS and thereby plays a key role in fatty acid uptake by adipocytes and also most probably in interferon-gamma-induced translation inhibition (PubMed:28178239).', 'RPS6KB1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative initiation, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Kinase, Membrane, Mitochondrion, Mitochondrion outer membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Synapse, Synaptosome, Transferase, Translation regulation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (479, '3Q5I', '', 'Calcium-dependent protein kinase 1', 'Calcium-dependent protein kinase which acts as a sensor and effector of intracellular Ca(2+) levels probably in part downstream of cGMP-activated PKG kinase (By similarity). During the liver stage, involved in sporozoite motility and thus in sporozoite invasion of host hepatocytes, probably together with CDPK4 and CDPK5 (PubMed:32866196). In the mosquito midgut and during the last stage of male gamete exflagellation, may play a role in the rupture of the host erythrocyte membrane (PubMed:22817984). In the mosquito midgut, required for the differentiation of the zygote into the ookinete by promoting the translational activation of a subset of repressed mRNAs; these mRNAs are kept repressed in the zygote by the DOZI- or CITH-containing mRNP complexes (PubMed:22817984, PubMed:24265753). Dispensable during the asexual blood stage (PubMed:24265753).', 'CDPK1', 'Plasmodium berghei (strain Anka)', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Calcium, Cell membrane, Cell projection, Cilium, Cytoplasm, Flagellum, Host cell membrane, Host membrane, Kinase, Lipoprotein, Magnesium, Membrane, Metal-binding, Myristate, Nucleotide-binding, Palmitate, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (480, '4AGC', '', 'Vascular endothelial growth factor receptor 2', 'Tyrosine-protein kinase that acts as a cell-surface receptor for VEGFA, VEGFC and VEGFD. Plays an essential role in the regulation of angiogenesis, vascular development, vascular permeability, and embryonic hematopoiesis. Promotes proliferation, survival, migration and differentiation of endothelial cells. Promotes reorganization of the actin cytoskeleton. Isoforms lacking a transmembrane domain, such as isoform 2 and isoform 3, may function as decoy receptors for VEGFA, VEGFC and/or VEGFD. Isoform 2 plays an important role as negative regulator of VEGFA- and VEGFC-mediated lymphangiogenesis by limiting the amount of free VEGFA and/or VEGFC and preventing their binding to FLT4. Modulates FLT1 and FLT4 signaling by forming heterodimers. Binding of vascular growth factors to isoform 1 leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate and the activation of protein kinase C. Mediates activation of MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. Mediates phosphorylation of PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase, reorganization of the actin cytoskeleton and activation of PTK2/FAK1. Required for VEGFA-mediated induction of NOS2 and NOS3, leading to the production of the signaling molecule nitric oxide (NO) by endothelial cells. Phosphorylates PLCG1. Promotes phosphorylation of FYN, NCK1, NOS3, PIK3R1, PTK2/FAK1 and SRC.', 'KDR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Cytoplasmic vesicle, Developmental protein, Differentiation, Disulfide bond, Endoplasmic reticulum, Endosome, Glycoprotein, Host-virus interaction, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (481, '8EEC', '', 'Mitogen-activated protein kinase kinase kinase kinase 1', 'Serine/threonine-protein kinase, which may play a role in the response to environmental stress (PubMed:24362026). Appears to act upstream of the JUN N-terminal pathway (PubMed:8824585). May play a role in hematopoietic lineage decisions and growth regulation (PubMed:8824585, PubMed:24362026). Able to autophosphorylate (PubMed:8824585). Together with CLNK, it enhances CD3-triggered activation of T-cells and subsequent IL2 production (By similarity).', 'MAP4K1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (482, '8R4O', '', 'Serine/threonine-protein kinase SIK3', 'Positive regulator of mTOR signaling that functions by triggering the degradation of DEPTOR, an mTOR inhibitor. Involved in the dynamic regulation of mTOR signaling in chondrocyte differentiation during skeletogenesis (PubMed:30232230). Negatively regulates cAMP signaling pathway possibly by acting on CRTC2/TORC2 and CRTC3/TORC3 (Probable). Prevents HDAC4 translocation to the nucleus (By similarity).', 'SIK3', 'Homo sapiens', '{[''2.7.11.1'']}', 'Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Dwarfism, Kinase, Magnesium, Metal-binding, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (483, '4CRS', '', 'Serine/threonine-protein kinase N2', 'PKC-related serine/threonine-protein kinase and Rho/Rac effector protein that participates in specific signal transduction responses in the cell. Plays a role in the regulation of cell cycle progression, actin cytoskeleton assembly, cell migration, cell adhesion, tumor cell invasion and transcription activation signaling processes. Phosphorylates CTTN in hyaluronan-induced astrocytes and hence decreases CTTN ability to associate with filamentous actin. Phosphorylates HDAC5, therefore lead to impair HDAC5 import. Direct RhoA target required for the regulation of the maturation of primordial junctions into apical junction formation in bronchial epithelial cells. Required for G2/M phases of the cell cycle progression and abscission during cytokinesis in a ECT2-dependent manner. Stimulates FYN kinase activity that is required for establishment of skin cell-cell adhesion during keratinocytes differentiation. Regulates epithelial bladder cells speed and direction of movement during cell migration and tumor cell invasion. Inhibits Akt pro-survival-induced kinase activity. Mediates Rho protein-induced transcriptional activation via the c-fos serum response factor (SRF). Involved in the negative regulation of ciliogenesis (PubMed:27104747).', 'PKN2', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cell adhesion, Cell cycle, Cell division, Cell junction, Cell projection, Cilium biogenesis/degradation, Coiled coil, Cytoplasm, Cytoskeleton, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (484, '4EYJ', '', 'Mitogen-activated protein kinase 13', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. MAPK13 is one of the four p38 MAPKs which play an important role in the cascades of cellular responses evoked by extracellular stimuli such as pro-inflammatory cytokines or physical stress leading to direct activation of transcription factors such as ELK1 and ATF2. Accordingly, p38 MAPKs phosphorylate a broad range of proteins and it has been estimated that they may have approximately 200 to 300 substrates each. MAPK13 is one of the less studied p38 MAPK isoforms. Some of the targets are downstream kinases such as MAPKAPK2, which are activated through phosphorylation and further phosphorylate additional targets. Plays a role in the regulation of protein translation by phosphorylating and inactivating EEF2K. Involved in cytoskeletal remodeling through phosphorylation of MAPT and STMN1. Mediates UV irradiation induced up-regulation of the gene expression of CXCL14. Plays an important role in the regulation of epidermal keratinocyte differentiation, apoptosis and skin tumor development. Phosphorylates the transcriptional activator MYB in response to stress which leads to rapid MYB degradation via a proteasome-dependent pathway. MAPK13 also phosphorylates and down-regulates PRKD1 during regulation of insulin secretion in pancreatic beta cells.', 'MAPK13', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (485, '2ZOQ', '', 'Mitogen-activated protein kinase 3', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway (PubMed:34497368). MAPK1/ERK2 and MAPK3/ERK1 are the 2 MAPKs which play an important role in the MAPK/ERK cascade. They participate also in a signaling cascade initiated by activated KIT and KITLG/SCF. Depending on the cellular context, the MAPK/ERK cascade mediates diverse biological functions such as cell growth, adhesion, survival and differentiation through the regulation of transcription, translation, cytoskeletal rearrangements. The MAPK/ERK cascade also plays a role in initiation and regulation of meiosis, mitosis, and postmitotic functions in differentiated cells by phosphorylating a number of transcription factors. About 160 substrates have already been discovered for ERKs. Many of these substrates are localized in the nucleus, and seem to participate in the regulation of transcription upon stimulation. However, other substrates are found in the cytosol as well as in other cellular organelles, and those are responsible for processes such as translation, mitosis and apoptosis. Moreover, the MAPK/ERK cascade is also involved in the regulation of the endosomal dynamics, including lysosome processing and endosome cycling through the perinuclear recycling compartment (PNRC); as well as in the fragmentation of the Golgi apparatus during mitosis. The substrates include transcription factors (such as ATF2, BCL6, ELK1, ERF, FOS, HSF4 or SPZ1), cytoskeletal elements (such as CANX, CTTN, GJA1, MAP2, MAPT, PXN, SORBS3 or STMN1), regulators of apoptosis (such as BAD, BTG2, CASP9, DAPK1, IER3, MCL1 or PPARG), regulators of translation (such as EIF4EBP1) and a variety of other signaling-related molecules (like ARHGEF2, DEPTOR, FRS2 or GRB10) (PubMed:35216969). Protein kinases (such as RAF1, RPS6KA1/RSK1, RPS6KA3/RSK2, RPS6KA2/RSK3, RPS6KA6/RSK4, SYK, MKNK1/MNK1, MKNK2/MNK2, RPS6KA5/MSK1, RPS6KA4/MSK2, MAPKAPK3 or MAPKAPK5) and phosphatases (such as DUSP1, DUSP4, DUSP6 or DUSP16) are other substrates which enable the propagation the MAPK/ERK signal to additional cytosolic and nuclear targets, thereby extending the specificity of the cascade.', 'MAPK3', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell junction, Cytoplasm, Direct protein sequencing, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (486, '6BRJ', '', 'Epithelial discoidin domain-containing receptor 1', 'Tyrosine kinase that functions as a cell surface receptor for fibrillar collagen and regulates cell attachment to the extracellular matrix, remodeling of the extracellular matrix, cell migration, differentiation, survival and cell proliferation. Collagen binding triggers a signaling pathway that involves SRC and leads to the activation of MAP kinases. Regulates remodeling of the extracellular matrix by up-regulation of the matrix metalloproteinases MMP2, MMP7 and MMP9, and thereby facilitates cell migration and wound healing. Required for normal blastocyst implantation during pregnancy, for normal mammary gland differentiation and normal lactation. Required for normal ear morphology and normal hearing (By similarity). Promotes smooth muscle cell migration, and thereby contributes to arterial wound healing. Also plays a role in tumor cell invasion. Phosphorylates PTPN11.', 'DDR1', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Calcium, Cell membrane, Direct protein sequencing, Disulfide bond, Glycoprotein, Kinase, Lactation, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Pregnancy, Receptor, Reference proteome, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (487, '8USO', '', 'Calcium/calmodulin-dependent protein kinase type II subunit delta', 'Unknown', 'CAMK2D', 'Homo sapiens', '{[''2.7.11.17'']}', 'ATP-binding, Calmodulin-binding, Kinase, Nucleotide-binding, Proteomics identification, Reference proteome, Sarcoplasmic reticulum, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (488, '4I5M', '', 'Serine/threonine-protein kinase PLK2', 'Tumor suppressor serine/threonine-protein kinase involved in synaptic plasticity, centriole duplication and G1/S phase transition. Polo-like kinases act by binding and phosphorylating proteins that are already phosphorylated on a specific motif recognized by the POLO box domains. Phosphorylates CENPJ, NPM1, RAPGEF2, RASGRF1, SNCA, SIPA1L1 and SYNGAP1. Plays a key role in synaptic plasticity and memory by regulating the Ras and Rap protein signaling: required for overactivity-dependent spine remodeling by phosphorylating the Ras activator RASGRF1 and the Rap inhibitor SIPA1L1 leading to their degradation by the proteasome. Conversely, phosphorylates the Rap activator RAPGEF2 and the Ras inhibitor SYNGAP1, promoting their activity. Also regulates synaptic plasticity independently of kinase activity, via its interaction with NSF that disrupts the interaction between NSF and the GRIA2 subunit of AMPARs, leading to a rapid rundown of AMPAR-mediated current that occludes long term depression. Required for procentriole formation and centriole duplication by phosphorylating CENPJ and NPM1, respectively. Its induction by p53/TP53 suggests that it may participate in the mitotic checkpoint following stress.', 'PLK2', 'Homo sapiens', '{[''2.7.11.21'']}', '3D-structure, ATP-binding, Cell projection, Cytoplasm, Cytoskeleton, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Tumor suppressor');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (489, '1VZO', '', 'Ribosomal protein S6 kinase alpha-5', 'Serine/threonine-protein kinase that is required for the mitogen or stress-induced phosphorylation of the transcription factors CREB1 and ATF1 and for the regulation of the transcription factors RELA, STAT3 and ETV1/ER81, and that contributes to gene activation by histone phosphorylation and functions in the regulation of inflammatory genes (PubMed:11909979, PubMed:12569367, PubMed:12763138, PubMed:9687510, PubMed:18511904, PubMed:9873047). Phosphorylates CREB1 and ATF1 in response to mitogenic or stress stimuli such as UV-C irradiation, epidermal growth factor (EGF) and anisomycin (PubMed:11909979, PubMed:9873047). Plays an essential role in the control of RELA transcriptional activity in response to TNF and upon glucocorticoid, associates in the cytoplasm with the glucocorticoid receptor NR3C1 and contributes to RELA inhibition and repression of inflammatory gene expression (PubMed:12628924, PubMed:18511904). In skeletal myoblasts is required for phosphorylation of RELA at ''Ser-276'' during oxidative stress (PubMed:12628924). In erythropoietin-stimulated cells, is necessary for the ''Ser-727'' phosphorylation of STAT3 and regulation of its transcriptional potential (PubMed:12763138). Phosphorylates ETV1/ER81 at ''Ser-191'' and ''Ser-216'', and thereby regulates its ability to stimulate transcription, which may be important during development and breast tumor formation (PubMed:12569367). Directly represses transcription via phosphorylation of ''Ser-1'' of histone H2A (PubMed:15010469). Phosphorylates ''Ser-10'' of histone H3 in response to mitogenics, stress stimuli and EGF, which results in the transcriptional activation of several immediate early genes, including proto-oncogenes c-fos/FOS and c-jun/JUN (PubMed:12773393). May also phosphorylate ''Ser-28'' of histone H3 (PubMed:12773393). Mediates the mitogen- and stress-induced phosphorylation of high mobility group protein 1 (HMGN1/HMG14) (PubMed:12773393). In lipopolysaccharide-stimulated primary macrophages, acts downstream of the Toll-like receptor TLR4 to limit the production of pro-inflammatory cytokines (By similarity). Functions probably by inducing transcription of the MAP kinase phosphatase DUSP1 and the anti-inflammatory cytokine interleukin 10 (IL10), via CREB1 and ATF1 transcription factors (By similarity). Plays a role in neuronal cell death by mediating the downstream effects of excitotoxic injury (By similarity). Phosphorylates TRIM7 at ''Ser-107'' in response to growth factor signaling via the MEK/ERK pathway, thereby stimulating its ubiquitin ligase activity (PubMed:25851810).', 'RPS6KA5', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Inflammatory response, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Stress response, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (490, '7XQK', '', 'Glutathione S-transferase class-mu 26 kDa isozyme', 'Conjugation of reduced glutathione to a wide number of exogenous and endogenous hydrophobic electrophiles.', 'NaN', 'Schistosoma japonicum', '{[''2.5.1.18'']}', '3D-structure, Direct protein sequencing, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (491, '4BGQ', '', 'Cyclin-dependent kinase-like 5', 'Mediates phosphorylation of MECP2 (PubMed:15917271, PubMed:16935860). May regulate ciliogenesis (PubMed:29420175).', 'CDKL5', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Chromosomal rearrangement, Cytoplasm, Cytoskeleton, Disease variant, Epilepsy, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (492, '2VD5', '', 'Myotonin-protein kinase', 'Non-receptor serine/threonine protein kinase which is necessary for the maintenance of skeletal muscle structure and function. May play a role in myocyte differentiation and survival by regulating the integrity of the nuclear envelope and the expression of muscle-specific genes. May also phosphorylate PPP1R12A and inhibit the myosin phosphatase activity to regulate myosin phosphorylation. Also critical to the modulation of cardiac contractility and to the maintenance of proper cardiac conduction activity probably through the regulation of cellular calcium homeostasis. Phosphorylates PLN, a regulator of calcium pumps and may regulate sarcoplasmic reticulum calcium uptake in myocytes. May also phosphorylate FXYD1/PLM which is able to induce chloride currents. May also play a role in synaptic plasticity.', 'DMPK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cataract, Cell membrane, Coiled coil, Cytoplasm, Endoplasmic reticulum, Kinase, Magnesium, Membrane, Metal-binding, Mitochondrion, Mitochondrion outer membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Sarcoplasmic reticulum, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (495, '2Y3A', '', 'Phosphatidylinositol 4,5-bisphosphate 3-kinase catalytic subunit beta isoform', 'Phosphoinositide-3-kinase (PI3K) phosphorylates phosphatidylinositol (PI) derivatives at position 3 of the inositol ring to produce 3-phosphoinositides. Uses ATP and PtdIns(4,5)P2 (phosphatidylinositol 4,5-bisphosphate) to generate phosphatidylinositol 3,4,5-trisphosphate (PIP3) (By similarity). PIP3 plays a key role by recruiting PH domain-containing proteins to the membrane, including AKT1 and PDPK1, activating signaling cascades involved in cell growth, survival, proliferation, motility and morphology. Involved in the activation of AKT1 upon stimulation by G-protein coupled receptors (GPCRs) ligands such as CXCL12, sphingosine 1-phosphate, and lysophosphatidic acid. May also act downstream receptor tyrosine kinases. Required in different signaling pathways for stable platelet adhesion and aggregation. Plays a role in platelet activation signaling triggered by GPCRs, alpha-IIb/beta-3 integrins (ITGA2B/ ITGB3) and ITAM (immunoreceptor tyrosine-based activation motif)-bearing receptors such as GP6. Regulates the strength of adhesion of ITGA2B/ ITGB3 activated receptors necessary for the cellular transmission of contractile forces. Required for platelet aggregation induced by F2 (thrombin) and thromboxane A2 (TXA2). Has a role in cell survival. May have a role in cell migration. Involved in the early stage of autophagosome formation. Modulates the intracellular level of PtdIns3P (phosphatidylinositol 3-phosphate) and activates PIK3C3 kinase activity. May act as a scaffold, independently of its lipid kinase activity to positively regulate autophagy. May have a role in insulin signaling as scaffolding protein in which the lipid kinase activity is not required. May have a kinase-independent function in regulating cell proliferation and in clathrin-mediated endocytosis. Mediator of oncogenic signal in cell lines lacking PTEN. The lipid kinase activity is necessary for its role in oncogenic transformation. Required for the growth of ERBB2 and RAS driven tumors. Has also a protein kinase activity showing autophosphorylation.', 'Pik3cb', 'Mus musculus', '{[''2.7.1.153'',''2.7.11.1'']}', '3D-structure, ATP-binding, Autophagy, Cell adhesion, Cytoplasm, Endocytosis, Kinase, Lipid metabolism, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (496, '3TAC', '', 'Peripheral plasma membrane protein CASK', 'Multidomain scaffolding Mg(2+)-independent protein kinase that catalyzes the phosphotransfer from ATP to proteins such as NRXN1, and plays a role in synaptic transmembrane protein anchoring and ion channel trafficking (PubMed:18423203). Contributes to neural development and regulation of gene expression via interaction with the transcription factor TBR1. Binds to cell-surface proteins, including amyloid precursor protein, neurexins and syndecans. May mediate a link between the extracellular matrix and the actin cytoskeleton via its interaction with syndecan and with the actin/spectrin-binding protein 4.1. Component of the LIN-10-LIN-2-LIN-7 complex, which associates with the motor protein KIF17 to transport vesicles containing N-methyl-D-aspartate (NMDA) receptor subunit NR2B along microtubules (By similarity).', 'CASK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Calmodulin-binding, Cell membrane, Cytoplasm, Disease variant, Intellectual disability, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, SH3 domain, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (497, '5D7V', '', 'Protein-tyrosine kinase 6', 'Non-receptor tyrosine-protein kinase implicated in the regulation of a variety of signaling pathways that control the differentiation and maintenance of normal epithelia, as well as tumor growth. Function seems to be context dependent and differ depending on cell type, as well as its intracellular localization. A number of potential nuclear and cytoplasmic substrates have been identified. These include the RNA-binding proteins: KHDRBS1/SAM68, KHDRBS2/SLM1, KHDRBS3/SLM2 and SFPQ/PSF; transcription factors: STAT3 and STAT5A/B and a variety of signaling molecules: ARHGAP35/p190RhoGAP, PXN/paxillin, BTK/ATK, STAP2/BKS. Associates also with a variety of proteins that are likely upstream of PTK6 in various signaling pathways, or for which PTK6 may play an adapter-like role. These proteins include ADAM15, EGFR, ERBB2, ERBB3 and IRS4. In normal or non-tumorigenic tissues, PTK6 promotes cellular differentiation and apoptosis. In tumors PTK6 contributes to cancer progression by sensitizing cells to mitogenic signals and enhancing proliferation, anchorage-independent survival and migration/invasion. Association with EGFR, ERBB2, ERBB3 may contribute to mammary tumor development and growth through enhancement of EGF-induced signaling via BTK/AKT and PI3 kinase. Contributes to migration and proliferation by contributing to EGF-mediated phosphorylation of ARHGAP35/p190RhoGAP, which promotes association with RASA1/p120RasGAP, inactivating RhoA while activating RAS. EGF stimulation resulted in phosphorylation of PNX/Paxillin by PTK6 and activation of RAC1 via CRK/CrKII, thereby promoting migration and invasion. PTK6 activates STAT3 and STAT5B to promote proliferation. Nuclear PTK6 may be important for regulating growth in normal epithelia, while cytoplasmic PTK6 might activate oncogenic signaling pathways.', 'PTK6', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Cytoplasm, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (498, '2VWI', '', 'Serine/threonine-protein kinase OSR1', 'Effector serine/threonine-protein kinase component of the WNK-SPAK/OSR1 kinase cascade, which is involved in various processes, such as ion transport, response to hypertonic stress and blood pressure (PubMed:16669787, PubMed:18270262, PubMed:21321328, PubMed:34289367). Specifically recognizes and binds proteins with a RFXV motif (PubMed:16669787, PubMed:21321328, PubMed:17721439). Acts downstream of WNK kinases (WNK1, WNK2, WNK3 or WNK4): following activation by WNK kinases, catalyzes phosphorylation of ion cotransporters, such as SLC12A1/NKCC2, SLC12A2/NKCC1, SLC12A3/NCC, SLC12A5/KCC2 or SLC12A6/KCC3, regulating their activity (PubMed:17721439). Mediates regulatory volume increase in response to hyperosmotic stress by catalyzing phosphorylation of ion cotransporters SLC12A1/NKCC2, SLC12A2/NKCC1 and SLC12A6/KCC3 downstream of WNK1 and WNK3 kinases (PubMed:16669787, PubMed:21321328). Phosphorylation of Na-K-Cl cotransporters SLC12A2/NKCC1 and SLC12A2/NKCC1 promote their activation and ion influx; simultaneously, phosphorylation of K-Cl cotransporters SLC12A5/KCC2 and SLC12A6/KCC3 inhibit their activity, blocking ion efflux (PubMed:16669787, PubMed:19665974, PubMed:21321328). Acts as a regulator of NaCl reabsorption in the distal nephron by mediating phosphorylation and activation of the thiazide-sensitive Na-Cl cotransporter SLC12A3/NCC in distal convoluted tubule cells of kidney downstream of WNK4 (PubMed:18270262). Also acts as a regulator of angiogenesis in endothelial cells downstream of WNK1 (PubMed:23386621, PubMed:25362046). Acts as an activator of inward rectifier potassium channels KCNJ2/Kir2.1 and KCNJ4/Kir2.3 downstream of WNK1: recognizes and binds the RXFXV/I variant motif on KCNJ2/Kir2.1 and KCNJ4/Kir2.3 and regulates their localization to the cell membrane without mediating their phosphorylation (PubMed:29581290). Phosphorylates RELL1, RELL2 and RELT (PubMed:16389068, PubMed:28688764). Phosphorylates PAK1 (PubMed:14707132). Phosphorylates PLSCR1 in the presence of RELT (PubMed:22052202).', 'OXSR1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (499, '6QAT', '', 'Serine/threonine-protein kinase ULK2', 'Serine/threonine-protein kinase involved in autophagy in response to starvation. Acts upstream of phosphatidylinositol 3-kinase PIK3C3 to regulate the formation of autophagophores, the precursors of autophagosomes. Part of regulatory feedback loops in autophagy: acts both as a downstream effector and a negative regulator of mammalian target of rapamycin complex 1 (mTORC1) via interaction with RPTOR. Activated via phosphorylation by AMPK, also acts as a negative regulator of AMPK through phosphorylation of the AMPK subunits PRKAA1, PRKAB2 and PRKAG1. May phosphorylate ATG13/KIAA0652, FRS2, FRS3 and RPTOR; however such data need additional evidences. Not involved in ammonia-induced autophagy or in autophagic response of cerebellar granule neurons (CGN) to low potassium concentration. Plays a role early in neuronal differentiation and is required for granule cell axon formation: may govern axon formation via Ras-like GTPase signaling and through regulation of the Rab5-mediated endocytic pathways within developing axons.', 'ULK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Autophagy, Cytoplasmic vesicle, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (500, '2REI', '', 'Ephrin type-A receptor 7', 'Receptor tyrosine kinase which binds promiscuously GPI-anchored ephrin-A family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Among GPI-anchored ephrin-A ligands, EFNA5 is a cognate/functional ligand for EPHA7 and their interaction regulates brain development modulating cell-cell adhesion and repulsion. Has a repellent activity on axons and is for instance involved in the guidance of corticothalamic axons and in the proper topographic mapping of retinal axons to the colliculus. May also regulate brain development through a caspase(CASP3)-dependent proapoptotic activity. Forward signaling may result in activation of components of the ERK signaling pathway including MAP2K1, MAP2K2, MAPK1 and MAPK3 which are phosphorylated upon activation of EPHA7.', 'EPHA7', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell membrane, Developmental protein, Glycoprotein, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (501, '2NPT', '', 'Dual specificity mitogen-activated protein kinase kinase 5', 'Acts as a scaffold for the formation of a ternary MAP3K2/MAP3K3-MAP3K5-MAPK7 signaling complex. Activation of this pathway appears to play a critical role in protecting cells from stress-induced apoptosis, neuronal survival and cardiac development and angiogenesis. As part of the MAPK/ERK signaling pathway, acts as a negative regulator of apoptosis in cardiomyocytes via promotion of STUB1/CHIP-mediated ubiquitination and degradation of ICER-type isoforms of CREM (By similarity).', 'MAP2K5', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (502, '4EKU', '', 'Protein-tyrosine kinase 2-beta', 'Non-receptor protein-tyrosine kinase that regulates reorganization of the actin cytoskeleton, cell polarization, cell migration, adhesion, spreading and bone remodeling. Plays a role in the regulation of the humoral immune response, and is required for normal levels of marginal B-cells in the spleen and normal migration of splenic B-cells. Required for normal macrophage polarization and migration towards sites of inflammation. Regulates cytoskeleton rearrangement and cell spreading in T-cells, and contributes to the regulation of T-cell responses. Promotes osteoclastic bone resorption; this requires both PTK2B/PYK2 and SRC. May inhibit differentiation and activity of osteoprogenitor cells. Functions in signaling downstream of integrin and collagen receptors, immune receptors, G-protein coupled receptors (GPCR), cytokine, chemokine and growth factor receptors, and mediates responses to cellular stress. Forms multisubunit signaling complexes with SRC and SRC family members upon activation; this leads to the phosphorylation of additional tyrosine residues, creating binding sites for scaffold proteins, effectors and substrates. Regulates numerous signaling pathways. Promotes activation of phosphatidylinositol 3-kinase and of the AKT1 signaling cascade. Promotes activation of NOS3. Regulates production of the cellular messenger cGMP. Promotes activation of the MAP kinase signaling cascade, including activation of MAPK1/ERK2, MAPK3/ERK1 and MAPK8/JNK1. Promotes activation of Rho family GTPases, such as RHOA and RAC1. Recruits the ubiquitin ligase MDM2 to P53/TP53 in the nucleus, and thereby regulates P53/TP53 activity, P53/TP53 ubiquitination and proteasomal degradation. Acts as a scaffold, binding to both PDPK1 and SRC, thereby allowing SRC to phosphorylate PDPK1 at ''Tyr-9, ''Tyr-373'', and ''Tyr-376''. Promotes phosphorylation of NMDA receptors by SRC family members, and thereby contributes to the regulation of NMDA receptor ion channel activity and intracellular Ca(2+) levels. May also regulate potassium ion transport by phosphorylation of potassium channel subunits. Phosphorylates SRC; this increases SRC kinase activity. Phosphorylates ASAP1, NPHP1, KCNA2 and SHC1. Promotes phosphorylation of ASAP2, RHOU and PXN; this requires both SRC and PTK2/PYK2.', 'PTK2B', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Adaptive immunity, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cell projection, Cytoplasm, Immunity, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (503, '7NX3', '', 'ALK tyrosine kinase receptor', 'Neuronal receptor tyrosine kinase that is essentially and transiently expressed in specific regions of the central and peripheral nervous systems and plays an important role in the genesis and differentiation of the nervous system (PubMed:11121404, PubMed:11387242, PubMed:16317043, PubMed:17274988, PubMed:30061385, PubMed:34646012, PubMed:34819673). Also acts as a key thinness protein involved in the resistance to weight gain: in hypothalamic neurons, controls energy expenditure acting as a negative regulator of white adipose tissue lipolysis and sympathetic tone to fine-tune energy homeostasis (By similarity). Following activation by ALKAL2 ligand at the cell surface, transduces an extracellular signal into an intracellular response (PubMed:30061385, PubMed:33411331, PubMed:34646012, PubMed:34819673). In contrast, ALKAL1 is not a potent physiological ligand for ALK (PubMed:34646012). Ligand-binding to the extracellular domain induces tyrosine kinase activation, leading to activation of the mitogen-activated protein kinase (MAPK) pathway (PubMed:34819673). Phosphorylates almost exclusively at the first tyrosine of the Y-x-x-x-Y-Y motif (PubMed:15226403, PubMed:16878150). Induces tyrosine phosphorylation of CBL, FRS2, IRS1 and SHC1, as well as of the MAP kinases MAPK1/ERK2 and MAPK3/ERK1 (PubMed:15226403, PubMed:16878150). ALK activation may also be regulated by pleiotrophin (PTN) and midkine (MDK) (PubMed:11278720, PubMed:11809760, PubMed:12107166, PubMed:12122009). PTN-binding induces MAPK pathway activation, which is important for the anti-apoptotic signaling of PTN and regulation of cell proliferation (PubMed:11278720, PubMed:11809760, PubMed:12107166). MDK-binding induces phosphorylation of the ALK target insulin receptor substrate (IRS1), activates mitogen-activated protein kinases (MAPKs) and PI3-kinase, resulting also in cell proliferation induction (PubMed:12122009). Drives NF-kappa-B activation, probably through IRS1 and the activation of the AKT serine/threonine kinase (PubMed:15226403, PubMed:16878150). Recruitment of IRS1 to activated ALK and the activation of NF-kappa-B are essential for the autocrine growth and survival signaling of MDK (PubMed:15226403, PubMed:16878150).', 'ALK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Chromosomal rearrangement, Disease variant, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (504, '1CTP', '', 'cAMP-dependent protein kinase catalytic subunit alpha', 'Phosphorylates a large number of substrates in the cytoplasm and the nucleus (By similarity). Phosphorylates CDC25B, ABL1, NFKB1, CLDN3, PSMC5/RPT6, PJA2, RYR2, RORA, SOX9 and VASP (By similarity). Regulates the abundance of compartmentalized pools of its regulatory subunits through phosphorylation of PJA2 which binds and ubiquitinates these subunits, leading to their subsequent proteolysis. RORA is activated by phosphorylation. Required for glucose-mediated adipogenic differentiation increase and osteogenic differentiation inhibition from osteoblasts (By similarity). Involved in chondrogenesis by mediating phosphorylation of SOX9 (By similarity). Involved in the regulation of platelets in response to thrombin and collagen; maintains circulating platelets in a resting state by phosphorylating proteins in numerous platelet inhibitory pathways when in complex with NF-kappa-B (NFKB1 and NFKB2) and I-kappa-B-alpha (NFKBIA), but thrombin and collagen disrupt these complexes and free active PRKACA stimulates platelets and leads to platelet aggregation by phosphorylating VASP. RYR2 channel activity is potentiated by phosphorylation in presence of luminal Ca(2+), leading to reduced amplitude and increased frequency of store overload-induced Ca(2+) release (SOICR) characterized by an increased rate of Ca(2+) release and propagation velocity of spontaneous Ca(2+) waves, despite reduced wave amplitude and resting cytosolic Ca(2+). PSMC5/RPT6 activation by phosphorylation stimulates proteasome. Negatively regulates tight junctions (TJs) in ovarian cancer cells via CLDN3 phosphorylation. NFKB1 phosphorylation promotes NF-kappa-B p50-p50 DNA binding. Required for phosphorylation of GLI transcription factors which inhibits them and prevents transcriptional activation of Hedgehog signaling pathway target genes (By similarity). GLI transcription factor phosphorylation is inhibited by interaction of PRKACA with SMO which sequesters PRKACA at the cell membrane (By similarity). Involved in embryonic development by down-regulating the Hedgehog (Hh) signaling pathway that determines embryo pattern formation and morphogenesis most probably through the regulation of OFD1 in ciliogenesis (By similarity). Prevents meiosis resumption in prophase-arrested oocytes via CDC25B inactivation by phosphorylation (By similarity). May also regulate rapid eye movement (REM) sleep in the pedunculopontine tegmental (PPT) (By similarity). Phosphorylates APOBEC3G and AICDA. Phosphorylates HSF1; this phosphorylation promotes HSF1 nuclear localization and transcriptional activity upon heat shock (By similarity). Acts as a negative regulator of mTORC1 by mediating phosphorylation of RPTOR (By similarity).', 'PRKACA', 'Sus scrofa', '{[''2.7.11.11'']}', '3D-structure, ATP-binding, cAMP, Cell membrane, Cytoplasm, Direct protein sequencing, Kinase, Lipoprotein, Membrane, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (505, '3TXO', '', 'Protein kinase C eta type', 'Calcium-independent, phospholipid- and diacylglycerol (DAG)-dependent serine/threonine-protein kinase that is involved in the regulation of cell differentiation in keratinocytes and pre-B cell receptor, mediates regulation of epithelial tight junction integrity and foam cell formation, and is required for glioblastoma proliferation and apoptosis prevention in MCF-7 cells. In keratinocytes, binds and activates the tyrosine kinase FYN, which in turn blocks epidermal growth factor receptor (EGFR) signaling and leads to keratinocyte growth arrest and differentiation. Associates with the cyclin CCNE1-CDK2-CDKN1B complex and inhibits CDK2 kinase activity, leading to RB1 dephosphorylation and thereby G1 arrest in keratinocytes. In association with RALA activates actin depolymerization, which is necessary for keratinocyte differentiation. In the pre-B cell receptor signaling, functions downstream of BLNK by up-regulating IRF4, which in turn activates L chain gene rearrangement. Regulates epithelial tight junctions (TJs) by phosphorylating occludin (OCLN) on threonine residues, which is necessary for the assembly and maintenance of TJs. In association with PLD2 and via TLR4 signaling, is involved in lipopolysaccharide (LPS)-induced RGS2 down-regulation and foam cell formation. Upon PMA stimulation, mediates glioblastoma cell proliferation by activating the mTOR pathway, the PI3K/AKT pathway and the ERK1-dependent phosphorylation of ELK1. Involved in the protection of glioblastoma cells from irradiation-induced apoptosis by preventing caspase-9 activation. In camptothecin-treated MCF-7 cells, regulates NF-kappa-B upstream signaling by activating IKBKB, and confers protection against DNA damage-induced apoptosis. Promotes oncogenic functions of ATF2 in the nucleus while blocking its apoptotic function at mitochondria. Phosphorylates ATF2 which promotes its nuclear retention and transcriptional activity and negatively regulates its mitochondrial localization.', 'PRKCH', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Differentiation, Kinase, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (506, '7MEZ', '', 'Phosphatidylinositol 4,5-bisphosphate 3-kinase catalytic subunit gamma isoform', 'Phosphoinositide-3-kinase (PI3K) that phosphorylates PtdIns(4,5)P2 (Phosphatidylinositol 4,5-bisphosphate) to generate phosphatidylinositol 3,4,5-trisphosphate (PIP3). PIP3 plays a key role by recruiting PH domain-containing proteins to the membrane, including AKT1 and PDPK1, activating signaling cascades involved in cell growth, survival, proliferation, motility and morphology. Links G-protein coupled receptor activation to PIP3 production. Involved in immune, inflammatory and allergic responses. Modulates leukocyte chemotaxis to inflammatory sites and in response to chemoattractant agents. May control leukocyte polarization and migration by regulating the spatial accumulation of PIP3 and by regulating the organization of F-actin formation and integrin-based adhesion at the leading edge. Controls motility of dendritic cells. Together with PIK3CD is involved in natural killer (NK) cell development and migration towards the sites of inflammation. Participates in T-lymphocyte migration. Regulates T-lymphocyte proliferation, activation, and cytokine production. Together with PIK3CD participates in T-lymphocyte development. Required for B-lymphocyte development and signaling. Together with PIK3CD participates in neutrophil respiratory burst. Together with PIK3CD is involved in neutrophil chemotaxis and extravasation. Together with PIK3CB promotes platelet aggregation and thrombosis. Regulates alpha-IIb/beta-3 integrins (ITGA2B/ ITGB3) adhesive function in platelets downstream of P2Y12 through a lipid kinase activity-independent mechanism. May have also a lipid kinase activity-dependent function in platelet aggregation. Involved in endothelial progenitor cell migration. Negative regulator of cardiac contractility. Modulates cardiac contractility by anchoring protein kinase A (PKA) and PDE3B activation, reducing cAMP levels. Regulates cardiac contractility also by promoting beta-adrenergic receptor internalization by binding to GRK2 and by non-muscle tropomyosin phosphorylation. Also has serine/threonine protein kinase activity: both lipid and protein kinase activities are required for beta-adrenergic receptor endocytosis. May also have a scaffolding role in modulating cardiac contractility. Contributes to cardiac hypertrophy under pathological stress. Through simultaneous binding of PDE3B to RAPGEF3 and PIK3R6 is assembled in a signaling complex in which the PI3K gamma complex is activated by RAPGEF3 and which is involved in angiogenesis.', 'PIK3CG', 'Homo sapiens', '{[''2.7.1.153'',''2.7.11.1'',''2.7.1.137'',''2.7.1.154'']}', '3D-structure, Angiogenesis, ATP-binding, Cell membrane, Chemotaxis, Cytoplasm, Disease variant, Endocytosis, Immunity, Inflammatory response, Kinase, Lipid metabolism, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (507, '4UY9', '', 'Mitogen-activated protein kinase kinase kinase 9', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. Plays an important role in the cascades of cellular responses evoked by changes in the environment. Once activated, acts as an upstream activator of the MKK/JNK signal transduction cascade through the phosphorylation of MAP2K4/MKK4 and MAP2K7/MKK7 which in turn activate the JNKs. The MKK/JNK signaling pathway regulates stress response via activator protein-1 (JUN) and GATA4 transcription factors. Also plays a role in mitochondrial death signaling pathway, including the release cytochrome c, leading to apoptosis.', 'MAP3K9', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, SH3 domain, Stress response, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (508, '6W4O', '', 'Calcium/calmodulin-dependent protein kinase type II subunit alpha', 'Calcium/calmodulin-dependent protein kinase that functions autonomously after Ca(2+)/calmodulin-binding and autophosphorylation, and is involved in various processes, such as synaptic plasticity, neurotransmitter release and long-term potentiation (PubMed:14722083). Member of the NMDAR signaling complex in excitatory synapses, it regulates NMDAR-dependent potentiation of the AMPAR and therefore excitatory synaptic transmission (By similarity). Regulates dendritic spine development (PubMed:28130356). Also regulates the migration of developing neurons (PubMed:29100089). Phosphorylates the transcription factor FOXO3 to activate its transcriptional activity (PubMed:23805378). Phosphorylates the transcription factor ETS1 in response to calcium signaling, thereby decreasing ETS1 affinity for DNA (By similarity). In response to interferon-gamma (IFN-gamma) stimulation, catalyzes phosphorylation of STAT1, stimulating the JAK-STAT signaling pathway (PubMed:11972023). In response to interferon-beta (IFN-beta) stimulation, stimulates the JAK-STAT signaling pathway (PubMed:35568036). Acts as a negative regulator of 2-arachidonoylglycerol (2-AG)-mediated synaptic signaling via modulation of DAGLA activity (By similarity).', 'CAMK2A', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Alternative splicing, ATP-binding, Calmodulin-binding, Cell projection, Disease variant, Intellectual disability, Kinase, Lipoprotein, Magnesium, Metal-binding, Nucleotide-binding, Palmitate, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Synapse, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (509, '2Y7J', '', 'Phosphorylase b kinase gamma catalytic chain, liver/testis isoform', 'Catalytic subunit of the phosphorylase b kinase (PHK), which mediates the neural and hormonal regulation of glycogen breakdown (glycogenolysis) by phosphorylating and thereby activating glycogen phosphorylase. May regulate glycogeneolysis in the testis. In vitro, phosphorylates PYGM (By similarity).', 'PHKG2', 'Homo sapiens', '{[''2.7.11.19'']}', '3D-structure, Alternative splicing, ATP-binding, Calmodulin-binding, Carbohydrate metabolism, Disease variant, Glycogen metabolism, Glycogen storage disease, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (510, '3MY0', '', 'Serine/threonine-protein kinase receptor R3', 'Type I receptor for TGF-beta family ligands BMP9/GDF2 and BMP10 and important regulator of normal blood vessel development. On ligand binding, forms a receptor complex consisting of two type II and two type I transmembrane serine/threonine kinases. Type II receptors phosphorylate and activate type I receptors which autophosphorylate, then bind and activate SMAD transcriptional regulators. May bind activin as well.', 'ACVRL1', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Angiogenesis, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (511, '8GMB', '', 'Tyrosine-protein kinase BTK', 'Non-receptor tyrosine kinase indispensable for B lymphocyte development, differentiation and signaling (PubMed:7538439, PubMed:8629002, PubMed:10852954). Binding of antigen to the B-cell antigen receptor (BCR) triggers signaling that ultimately leads to B-cell activation (By similarity). After BCR engagement and activation at the plasma membrane, phosphorylates PLCG2 at several sites, igniting the downstream signaling pathway through calcium mobilization, followed by activation of the protein kinase C (PKC) family members (By similarity). PLCG2 phosphorylation is performed in close cooperation with the adapter protein B-cell linker protein BLNK (By similarity). BTK acts as a platform to bring together a diverse array of signaling proteins and is implicated in cytokine receptor signaling pathways (By similarity). Plays an important role in the function of immune cells of innate as well as adaptive immunity, as a component of the Toll-like receptors (TLR) pathway (PubMed:17725607). The TLR pathway acts as a primary surveillance system for the detection of pathogens and are crucial to the activation of host defense (By similarity). Especially, is a critical molecule in regulating TLR9 activation in splenic B-cells (By similarity). Within the TLR pathway, induces tyrosine phosphorylation of TIRAP which leads to TIRAP degradation (By similarity). BTK also plays a critical role in transcription regulation (By similarity). Induces the activity of NF-kappa-B, which is involved in regulating the expression of hundreds of genes (By similarity). BTK is involved on the signaling pathway linking TLR8 and TLR9 to NF-kappa-B (By similarity). Acts as an activator of NLRP3 inflammasome assembly by mediating phosphorylation of NLRP3 (PubMed:34554188). Transiently phosphorylates transcription factor GTF2I on tyrosine residues in response to BCR (PubMed:11120822, PubMed:16738337). GTF2I then translocates to the nucleus to bind regulatory enhancer elements to modulate gene expression (PubMed:11120822, PubMed:16738337). ARID3A and NFAT are other transcriptional target of BTK (PubMed:11120822, PubMed:16738337). BTK is required for the formation of functional ARID3A DNA-binding complexes (PubMed:11120822, PubMed:16738337). There is however no evidence that BTK itself binds directly to DNA (PubMed:11120822, PubMed:16738337). BTK has a dual role in the regulation of apoptosis (By similarity).', 'Btk', 'Mus musculus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Adaptive immunity, Apoptosis, ATP-binding, Cell membrane, Cytoplasm, Direct protein sequencing, Disease variant, Immunity, Innate immunity, Kinase, Lipid-binding, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, SH2 domain, SH3 domain, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (512, '5E8V', '', 'TGF-beta receptor type-2', 'Transmembrane serine/threonine kinase forming with the TGF-beta type I serine/threonine kinase receptor, TGFBR1, the non-promiscuous receptor for the TGF-beta cytokines TGFB1, TGFB2 and TGFB3. Transduces the TGFB1, TGFB2 and TGFB3 signal from the cell surface to the cytoplasm and thus regulates a plethora of physiological and pathological processes including cell cycle arrest in epithelial and hematopoietic cells, control of mesenchymal cell proliferation and differentiation, wound healing, extracellular matrix production, immunosuppression and carcinogenesis. The formation of the receptor complex composed of 2 TGFBR1 and 2 TGFBR2 molecules symmetrically bound to the cytokine dimer results in the phosphorylation and activation of TGFBR1 by the constitutively active TGFBR2. Activated TGFBR1 phosphorylates SMAD2 which dissociates from the receptor and interacts with SMAD4. The SMAD2-SMAD4 complex is subsequently translocated to the nucleus where it modulates the transcription of the TGF-beta-regulated genes. This constitutes the canonical SMAD-dependent TGF-beta signaling cascade. Also involved in non-canonical, SMAD-independent TGF-beta signaling pathways.', 'TGFBR2', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, Aortic aneurysm, Apoptosis, ATP-binding, Cell membrane, Craniosynostosis, Differentiation, Direct protein sequencing, Disease variant, Disulfide bond, Glycoprotein, Growth regulation, Hereditary nonpolyposis colorectal cancer, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Secreted, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (513, '3COK', '', 'Serine/threonine-protein kinase PLK4', 'Serine/threonine-protein kinase that plays a central role in centriole duplication. Able to trigger procentriole formation on the surface of the parental centriole cylinder, leading to the recruitment of centriole biogenesis proteins such as SASS6, CENPJ/CPAP, CCP110, CEP135 and gamma-tubulin. When overexpressed, it is able to induce centrosome amplification through the simultaneous generation of multiple procentrioles adjoining each parental centriole during S phase. Phosphorylates ''Ser-151'' of FBXW5 during the G1/S transition, leading to inhibit FBXW5 ability to ubiquitinate SASS6. Its central role in centriole replication suggests a possible role in tumorigenesis, centrosome aberrations being frequently observed in tumors. Also involved in deuterosome-mediated centriole amplification in multiciliated that can generate more than 100 centrioles. Also involved in trophoblast differentiation by phosphorylating HAND1, leading to disrupt the interaction between HAND1 and MDFIC and activate HAND1. Phosphorylates CDC25C and CHEK2. Required for the recruitment of STIL to the centriole and for STIL-mediated centriole amplification (PubMed:22020124). Phosphorylates CEP131 at ''Ser-78'' and PCM1 at ''Ser-372'' which is essential for proper organization and integrity of centriolar satellites (PubMed:30804208).', 'PLK4', 'Homo sapiens', '{[''2.7.11.21'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Dwarfism, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (514, '1AQ1', 'MENFQKVEKIGEGTYGVVYKARNKLTGEVVALKKIRLDTETEGVPSTAIREISLLKELNHPNIVKLLDVIHTENKLYLVFEFLHQDLKKFMDASALTGIPLPLIKSYLFQLLQGLAFCHSHRVLHRDLKPQNLLINTEGAIKLADFGLARAFGVPVRTYTHEVVTLWYRAPEILLGCKYYSTAVDIWSLGCIFAEMVTRRALFPGDSEIDQLFRIFRTLGTPDEVVWPGVTSMPDYKPSFPKWARQDFSKVVPPLDEDGRSLLSQMLHYDPNKRISAKAALAHPFFQDVTKPVPHLRL', 'Cyclin-dependent kinase 2', 'Serine/threonine-protein kinase involved in the control of the cell cycle; essential for meiosis, but dispensable for mitosis. Phosphorylates CTNNB1, USP37, p53/TP53, NPM1, CDK7, RB1, BRCA2, MYC, NPAT, EZH2. Triggers duplication of centrosomes and DNA. Acts at the G1-S transition to promote the E2F transcriptional program and the initiation of DNA synthesis, and modulates G2 progression; controls the timing of entry into mitosis/meiosis by controlling the subsequent activation of cyclin B/CDK1 by phosphorylation, and coordinates the activation of cyclin B/CDK1 at the centrosome and in the nucleus. Crucial role in orchestrating a fine balance between cellular proliferation, cell death, and DNA repair in human embryonic stem cells (hESCs). Activity of CDK2 is maximal during S phase and G2; activated by interaction with cyclin E during the early stages of DNA synthesis to permit G1-S transition, and subsequently activated by cyclin A2 (cyclin A1 in germ cells) during the late stages of DNA replication to drive the transition from S phase to mitosis, the G2 phase. EZH2 phosphorylation promotes H3K27me3 maintenance and epigenetic gene silencing. Phosphorylates CABLES1 (By similarity). Cyclin E/CDK2 prevents oxidative stress-mediated Ras-induced senescence by phosphorylating MYC. Involved in G1-S phase DNA damage checkpoint that prevents cells with damaged DNA from initiating mitosis; regulates homologous recombination-dependent repair by phosphorylating BRCA2, this phosphorylation is low in S phase when recombination is active, but increases as cells progress towards mitosis. In response to DNA damage, double-strand break repair by homologous recombination a reduction of CDK2-mediated BRCA2 phosphorylation. Phosphorylation of RB1 disturbs its interaction with E2F1. NPM1 phosphorylation by cyclin E/CDK2 promotes its dissociates from unduplicated centrosomes, thus initiating centrosome duplication. Cyclin E/CDK2-mediated phosphorylation of NPAT at G1-S transition and until prophase stimulates the NPAT-mediated activation of histone gene transcription during S phase. Required for vitamin D-mediated growth inhibition by being itself inactivated. Involved in the nitric oxide- (NO) mediated signaling in a nitrosylation/activation-dependent manner. USP37 is activated by phosphorylation and thus triggers G1-S transition. CTNNB1 phosphorylation regulates insulin internalization. Phosphorylates FOXP3 and negatively regulates its transcriptional activity and protein stability (By similarity). Phosphorylates CDK2AP2 (PubMed:12944431). Phosphorylates ERCC6 which is essential for its chromatin remodeling activity at DNA double-strand breaks (PubMed:29203878).', 'CDK2', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cell division, Cytoplasm, Cytoskeleton, DNA damage, DNA repair, Endosome, Kinase, Magnesium, Meiosis, Metal-binding, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, S-nitrosylation, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (515, '2X0G', '', 'Death-associated protein kinase 1', 'Calcium/calmodulin-dependent serine/threonine kinase involved in multiple cellular signaling pathways that trigger cell survival, apoptosis, and autophagy. Regulates both type I apoptotic and type II autophagic cell deaths signal, depending on the cellular setting. The former is caspase-dependent, while the latter is caspase-independent and is characterized by the accumulation of autophagic vesicles. Phosphorylates PIN1 resulting in inhibition of its catalytic activity, nuclear localization, and cellular function. Phosphorylates TPM1, enhancing stress fiber formation in endothelial cells. Phosphorylates STX1A and significantly decreases its binding to STXBP1. Phosphorylates PRKD1 and regulates JNK signaling by binding and activating PRKD1 under oxidative stress. Phosphorylates BECN1, reducing its interaction with BCL2 and BCL2L1 and promoting the induction of autophagy. Phosphorylates TSC2, disrupting the TSC1-TSC2 complex and stimulating mTORC1 activity in a growth factor-dependent pathway. Phosphorylates RPS6, MYL9 and DAPK3. Acts as a signaling amplifier of NMDA receptors at extrasynaptic sites for mediating brain damage in stroke. Cerebral ischemia recruits DAPK1 into the NMDA receptor complex and it phosphorylates GRINB at Ser-1303 inducing injurious Ca(2+) influx through NMDA receptor channels, resulting in an irreversible neuronal death. Required together with DAPK3 for phosphorylation of RPL13A upon interferon-gamma activation which is causing RPL13A involvement in transcript-selective translation inhibition.', 'DAPK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ANK repeat, Apoptosis, ATP-binding, Calmodulin-binding, Cytoplasm, Cytoskeleton, GTP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Translation regulation, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (516, '5ES1', '', 'MAP/microtubule affinity-regulating kinase 4', 'Serine/threonine-protein kinase (PubMed:15009667, PubMed:14594945, PubMed:23666762, PubMed:23184942). Phosphorylates the microtubule-associated protein MAPT/TAU (PubMed:14594945, PubMed:23666762). Also phosphorylates the microtubule-associated proteins MAP2 and MAP4 (PubMed:14594945). Involved in regulation of the microtubule network, causing reorganization of microtubules into bundles (PubMed:14594945, PubMed:25123532). Required for the initiation of axoneme extension during cilium assembly (PubMed:23400999). Regulates the centrosomal location of ODF2 and phosphorylates ODF2 in vitro (PubMed:23400999). Plays a role in cell cycle progression, specifically in the G1/S checkpoint (PubMed:25123532). Reduces neuronal cell survival (PubMed:15009667). Plays a role in energy homeostasis by regulating satiety and metabolic rate (By similarity). Promotes adipogenesis by activating JNK1 and inhibiting the p38MAPK pathway, and triggers apoptosis by activating the JNK1 pathway (By similarity). Phosphorylates mTORC1 complex member RPTOR and acts as a negative regulator of the mTORC1 complex, probably due to disruption of the interaction between phosphorylated RPTOR and the RRAGA/RRAGC heterodimer which is required for mTORC1 activation (PubMed:23184942). Involved in NLRP3 positioning along microtubules by mediating NLRP3 recruitment to microtubule organizing center (MTOC) upon inflammasome activation (PubMed:28656979).', 'MARK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cell division, Cell projection, Cilium biogenesis/degradation, Cytoplasm, Cytoskeleton, Kinase, Mitosis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (517, '1UA2', '', 'Cyclin-dependent kinase 7', 'Serine/threonine kinase involved in cell cycle control and in RNA polymerase II-mediated RNA transcription. Cyclin-dependent kinases (CDKs) are activated by the binding to a cyclin and mediate the progression through the cell cycle. Each different complex controls a specific transition between 2 subsequent phases in the cell cycle. Required for both activation and complex formation of CDK1/cyclin-B during G2-M transition, and for activation of CDK2/cyclins during G1-S transition (but not complex formation). CDK7 is the catalytic subunit of the CDK-activating kinase (CAK) complex. Phosphorylates SPT5/SUPT5H, SF1/NR5A1, POLR2A, p53/TP53, CDK1, CDK2, CDK4, CDK6 and CDK11B/CDK11. CAK activates the cyclin-associated kinases CDK1, CDK2, CDK4 and CDK6 by threonine phosphorylation, thus regulating cell cycle progression. CAK complexed to the core-TFIIH basal transcription factor activates RNA polymerase II by serine phosphorylation of the repetitive C-terminal domain (CTD) of its large subunit (POLR2A), allowing its escape from the promoter and elongation of the transcripts (PubMed:9852112). Phosphorylation of POLR2A in complex with DNA promotes transcription initiation by triggering dissociation from DNA. Its expression and activity are constant throughout the cell cycle. Upon DNA damage, triggers p53/TP53 activation by phosphorylation, but is inactivated in turn by p53/TP53; this feedback loop may lead to an arrest of the cell cycle and of the transcription, helping in cell recovery, or to apoptosis. Required for DNA-bound peptides-mediated transcription and cellular growth inhibition.', 'CDK7', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Acetylation, ATP-binding, Cell cycle, Cell division, Cytoplasm, DNA damage, DNA repair, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (518, '7QUE', '', 'Serine/threonine-protein kinase 17A', 'Acts as a positive regulator of apoptosis. Also acts as a regulator of cellular reactive oxygen species.', 'STK17A', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Apoptosis, ATP-binding, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (519, '3O96', '', 'RAC-alpha serine/threonine-protein kinase', 'AKT1 is one of 3 closely related serine/threonine-protein kinases (AKT1, AKT2 and AKT3) called the AKT kinase, and which regulate many processes including metabolism, proliferation, cell survival, growth and angiogenesis (PubMed:15861136, PubMed:15526160, PubMed:11882383, PubMed:21620960, PubMed:21432781, PubMed:31204173). This is mediated through serine and/or threonine phosphorylation of a range of downstream substrates (PubMed:15526160, PubMed:11882383, PubMed:21620960, PubMed:21432781, PubMed:31204173). Over 100 substrate candidates have been reported so far, but for most of them, no isoform specificity has been reported (PubMed:15526160, PubMed:11882383, PubMed:21620960, PubMed:21432781). AKT is responsible of the regulation of glucose uptake by mediating insulin-induced translocation of the SLC2A4/GLUT4 glucose transporter to the cell surface (By similarity). Phosphorylation of PTPN1 at ''Ser-50'' negatively modulates its phosphatase activity preventing dephosphorylation of the insulin receptor and the attenuation of insulin signaling (By similarity). Phosphorylation of TBC1D4 triggers the binding of this effector to inhibitory 14-3-3 proteins, which is required for insulin-stimulated glucose transport (PubMed:11994271). AKT regulates also the storage of glucose in the form of glycogen by phosphorylating GSK3A at ''Ser-21'' and GSK3B at ''Ser-9'', resulting in inhibition of its kinase activity (By similarity). Phosphorylation of GSK3 isoforms by AKT is also thought to be one mechanism by which cell proliferation is driven (By similarity). AKT regulates also cell survival via the phosphorylation of MAP3K5 (apoptosis signal-related kinase) (PubMed:11154276). Phosphorylation of ''Ser-83'' decreases MAP3K5 kinase activity stimulated by oxidative stress and thereby prevents apoptosis (PubMed:11154276). AKT mediates insulin-stimulated protein synthesis by phosphorylating TSC2 at ''Ser-939'' and ''Thr-1462'', thereby activating the mTORC1 signaling pathway, and leading to both phosphorylation of 4E-BP1 and in activation of RPS6KB1 (PubMed:12150915, PubMed:12172553). Also regulates the mTORC1 signaling pathway by catalyzing phosphorylation of CASTOR1 and DEPDC5 (PubMed:31548394, PubMed:33594058). AKT is involved in the phosphorylation of members of the FOXO factors (Forkhead family of transcription factors), leading to binding of 14-3-3 proteins and cytoplasmic localization (PubMed:10358075). In particular, FOXO1 is phosphorylated at ''Thr-24'', ''Ser-256'' and ''Ser-319'' (PubMed:10358075). FOXO3 and FOXO4 are phosphorylated on equivalent sites (PubMed:10358075). AKT has an important role in the regulation of NF-kappa-B-dependent gene transcription and positively regulates the activity of CREB1 (cyclic AMP (cAMP)-response element binding protein) (PubMed:9829964). The phosphorylation of CREB1 induces the binding of accessory proteins that are necessary for the transcription of pro-survival genes such as BCL2 and MCL1 (PubMed:9829964). AKT phosphorylates ''Ser-454'' on ATP citrate lyase (ACLY), thereby potentially regulating ACLY activity and fatty acid synthesis (By similarity). Activates the 3B isoform of cyclic nucleotide phosphodiesterase (PDE3B) via phosphorylation of ''Ser-273'', resulting in reduced cyclic AMP levels and inhibition of lipolysis (By similarity). Phosphorylates PIKFYVE on ''Ser-318'', which results in increased PI(3)P-5 activity (By similarity). The Rho GTPase-activating protein DLC1 is another substrate and its phosphorylation is implicated in the regulation cell proliferation and cell growth (By similarity). AKT plays a role as key modulator of the AKT-mTOR signaling pathway controlling the tempo of the process of newborn neurons integration during adult neurogenesis, including correct neuron positioning, dendritic development and synapse formation (By similarity). Signals downstream of phosphatidylinositol 3-kinase (PI(3)K) to mediate the effects of various growth factors such as platelet-derived growth factor (PDGF), epidermal growth factor (EGF), insulin and insulin-like growth factor I (IGF-I) (PubMed:12176338, PubMed:12964941). AKT mediates the antiapoptotic effects of IGF-I (By similarity). Essential for the SPATA13-mediated regulation of cell migration and adhesion assembly and disassembly (PubMed:19934221). May be involved in the regulation of the placental development (By similarity). Phosphorylates STK4/MST1 at ''Thr-120'' and ''Thr-387'' leading to inhibition of its: kinase activity, nuclear translocation, autophosphorylation and ability to phosphorylate FOXO3 (PubMed:17726016). Phosphorylates STK3/MST2 at ''Thr-117'' and ''Thr-384'' leading to inhibition of its: cleavage, kinase activity, autophosphorylation at Thr-180, binding to RASSF1 and nuclear translocation (PubMed:20086174, PubMed:20231902). Phosphorylates SRPK2 and enhances its kinase activity towards SRSF2 and ACIN1 and promotes its nuclear translocation (PubMed:19592491). Phosphorylates RAF1 at ''Ser-259'' and negatively regulates its activity (PubMed:10576742). Phosphorylation of BAD stimulates its pro-apoptotic activity (PubMed:10926925). Phosphorylates KAT6A at ''Thr-369'' and this phosphorylation inhibits the interaction of KAT6A with PML and negatively regulates its acetylation activity towards p53/TP53 (PubMed:23431171). Phosphorylates palladin (PALLD), modulating cytoskeletal organization and cell motility (PubMed:20471940). Phosphorylates prohibitin (PHB), playing an important role in cell metabolism and proliferation (PubMed:18507042). Phosphorylates CDKN1A, for which phosphorylation at ''Thr-145'' induces its release from CDK2 and cytoplasmic relocalization (PubMed:16982699). These recent findings indicate that the AKT1 isoform has a more specific role in cell motility and proliferation (PubMed:16139227). Phosphorylates CLK2 thereby controlling cell survival to ionizing radiation (PubMed:20682768). Phosphorylates PCK1 at ''Ser-90'', reducing the binding affinity of PCK1 to oxaloacetate and changing PCK1 into an atypical protein kinase activity using GTP as donor (PubMed:32322062). Also acts as an activator of TMEM175 potassium channel activity in response to growth factors: forms the lysoK(GF) complex together with TMEM175 and acts by promoting TMEM175 channel activation, independently of its protein kinase activity (PubMed:32228865). Acts as an inhibitor of tRNA methylation by mediating phosphorylation of the N-terminus of METTL1, thereby inhibiting METTL1 methyltransferase activity (PubMed:15861136). In response to LPAR1 receptor pathway activation, phosphorylates Rabin8/RAB3IP which alters its activity and phosphorylates WDR44 which induces WDR44 binding to Rab11, thereby switching Rab11 vesicular function from preciliary trafficking to endocytic recycling (PubMed:31204173).', 'AKT1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Carbohydrate metabolism, Cell membrane, Cytoplasm, Developmental protein, Disease variant, Disulfide bond, Glucose metabolism, Glycogen biosynthesis, Glycogen metabolism, Glycoprotein, Isopeptide bond, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Sugar transport, Transferase, Translation regulation, Transport, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (520, '3LXK', '', 'Tyrosine-protein kinase JAK3', 'Non-receptor tyrosine kinase involved in various processes such as cell growth, development, or differentiation. Mediates essential signaling events in both innate and adaptive immunity and plays a crucial role in hematopoiesis during T-cells development. In the cytoplasm, plays a pivotal role in signal transduction via its association with type I receptors sharing the common subunit gamma such as IL2R, IL4R, IL7R, IL9R, IL15R and IL21R. Following ligand binding to cell surface receptors, phosphorylates specific tyrosine residues on the cytoplasmic tails of the receptor, creating docking sites for STATs proteins. Subsequently, phosphorylates the STATs proteins once they are recruited to the receptor. Phosphorylated STATs then form homodimer or heterodimers and translocate to the nucleus to activate gene transcription. For example, upon IL2R activation by IL2, JAK1 and JAK3 molecules bind to IL2R beta (IL2RB) and gamma chain (IL2RG) subunits inducing the tyrosine phosphorylation of both receptor subunits on their cytoplasmic domain. Then, STAT5A and STAT5B are recruited, phosphorylated and activated by JAK1 and JAK3. Once activated, dimerized STAT5 translocates to the nucleus and promotes the transcription of specific target genes in a cytokine-specific fashion.', 'JAK3', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Adaptive immunity, Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Immunity, Innate immunity, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SCID, SH2 domain, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (521, '4B6L', '', 'Serine/threonine-protein kinase PLK3', 'Serine/threonine-protein kinase involved in cell cycle regulation, response to stress and Golgi disassembly. Polo-like kinases act by binding and phosphorylating proteins that are already phosphorylated on a specific motif recognized by the POLO box domains. Phosphorylates ATF2, BCL2L1, CDC25A, CDC25C, CHEK2, HIF1A, JUN, p53/TP53, p73/TP73, PTEN, TOP2A and VRK1. Involved in cell cycle regulation: required for entry into S phase and cytokinesis. Phosphorylates BCL2L1, leading to regulate the G2 checkpoint and progression to cytokinesis during mitosis. Plays a key role in response to stress: rapidly activated upon stress stimulation, such as ionizing radiation, reactive oxygen species (ROS), hyperosmotic stress, UV irradiation and hypoxia. Involved in DNA damage response and G1/S transition checkpoint by phosphorylating CDC25A, p53/TP53 and p73/TP73. Phosphorylates p53/TP53 in response to reactive oxygen species (ROS), thereby promoting p53/TP53-mediated apoptosis. Phosphorylates CHEK2 in response to DNA damage, promoting the G2/M transition checkpoint. Phosphorylates the transcription factor p73/TP73 in response to DNA damage, leading to inhibit p73/TP73-mediated transcriptional activation and pro-apoptotic functions. Phosphorylates HIF1A and JUN is response to hypoxia. Phosphorylates ATF2 following hyperosmotic stress in corneal epithelium. Also involved in Golgi disassembly during the cell cycle: part of a MEK1/MAP2K1-dependent pathway that induces Golgi fragmentation during mitosis by mediating phosphorylation of VRK1. May participate in endomitotic cell cycle, a form of mitosis in which both karyokinesis and cytokinesis are interrupted and is a hallmark of megakaryocyte differentiation, via its interaction with CIB1.', 'PLK3', 'Homo sapiens', '{[''2.7.11.21'']}', '3D-structure, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Cytoskeleton, DNA damage, Golgi apparatus, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (522, '4Y5O', '', 'Cerebral cavernous malformations 2 protein', 'Component of the CCM signaling pathway which is a crucial regulator of heart and vessel formation and integrity. May act through the stabilization of endothelial cell junctions (By similarity). May function as a scaffold protein for MAP2K3-MAP3K3 signaling. Seems to play a major role in the modulation of MAP3K3-dependent p38 activation induced by hyperosmotic shock (By similarity).', 'CCM2', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Cytoplasm, Developmental protein, Direct protein sequencing, Disease variant, Phosphoprotein, Reference proteome');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (524, '4JG6', '', 'Ribosomal protein S6 kinase alpha-3', 'Serine/threonine-protein kinase that acts downstream of ERK (MAPK1/ERK2 and MAPK3/ERK1) signaling and mediates mitogenic and stress-induced activation of the transcription factors CREB1, ETV1/ER81 and NR4A1/NUR77, regulates translation through RPS6 and EIF4B phosphorylation, and mediates cellular proliferation, survival, and differentiation by modulating mTOR signaling and repressing pro-apoptotic function of BAD and DAPK1 (PubMed:9770464, PubMed:16223362, PubMed:17360704, PubMed:16213824). In fibroblast, is required for EGF-stimulated phosphorylation of CREB1 and histone H3 at ''Ser-10'', which results in the subsequent transcriptional activation of several immediate-early genes (PubMed:9770464, PubMed:10436156). In response to mitogenic stimulation (EGF and PMA), phosphorylates and activates NR4A1/NUR77 and ETV1/ER81 transcription factors and the cofactor CREBBP (PubMed:16223362). Upon insulin-derived signal, acts indirectly on the transcription regulation of several genes by phosphorylating GSK3B at ''Ser-9'' and inhibiting its activity (PubMed:8250835). Phosphorylates RPS6 in response to serum or EGF via an mTOR-independent mechanism and promotes translation initiation by facilitating assembly of the preinitiation complex (PubMed:17360704). In response to insulin, phosphorylates EIF4B, enhancing EIF4B affinity for the EIF3 complex and stimulating cap-dependent translation (PubMed:18508509, PubMed:18813292). Is involved in the mTOR nutrient-sensing pathway by directly phosphorylating TSC2 at ''Ser-1798'', which potently inhibits TSC2 ability to suppress mTOR signaling, and mediates phosphorylation of RPTOR, which regulates mTORC1 activity and may promote rapamycin-sensitive signaling independently of the PI3K/AKT pathway (PubMed:18722121). Mediates cell survival by phosphorylating the pro-apoptotic proteins BAD and DAPK1 and suppressing their pro-apoptotic function (PubMed:16213824). Promotes the survival of hepatic stellate cells by phosphorylating CEBPB in response to the hepatotoxin carbon tetrachloride (CCl4) (PubMed:18508509, PubMed:18813292). Is involved in cell cycle regulation by phosphorylating the CDK inhibitor CDKN1B, which promotes CDKN1B association with 14-3-3 proteins and prevents its translocation to the nucleus and inhibition of G1 progression (By similarity). In LPS-stimulated dendritic cells, is involved in TLR4-induced macropinocytosis, and in myeloma cells, acts as effector of FGFR3-mediated transformation signaling, after direct phosphorylation at Tyr-529 by FGFR3 (By similarity). Negatively regulates EGF-induced MAPK1/3 phosphorylation via phosphorylation of SOS1 (By similarity). Phosphorylates SOS1 at ''Ser-1134'' and ''Ser-1161'' that create YWHAB and YWHAE binding sites and which contribute to the negative regulation of MAPK1/3 phosphorylation (By similarity). Phosphorylates EPHA2 at ''Ser-897'', the RPS6KA-EPHA2 signaling pathway controls cell migration (PubMed:26158630). Acts as a regulator of osteoblast differentiation by mediating phosphorylation of ATF4, thereby promoting ATF4 transactivation activity (By similarity).', 'RPS6KA3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell cycle, Cytoplasm, Disease variant, Intellectual disability, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Stress response, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (525, '4K2R', '', 'Tyrosine-protein kinase ZAP-70', 'Tyrosine kinase that plays an essential role in regulation of the adaptive immune response. Regulates motility, adhesion and cytokine expression of mature T-cells, as well as thymocyte development. Contributes also to the development and activation of primary B-lymphocytes. When antigen presenting cells (APC) activate T-cell receptor (TCR), a serie of phosphorylations lead to the recruitment of ZAP70 to the doubly phosphorylated TCR component CD247/CD3Z through ITAM motif at the plasma membrane. This recruitment serves to localization to the stimulated TCR and to relieve its autoinhibited conformation. Release of ZAP70 active conformation is further stabilized by phosphorylation mediated by LCK. Subsequently, ZAP70 phosphorylates at least 2 essential adapter proteins: LAT and LCP2. In turn, a large number of signaling molecules are recruited and ultimately lead to lymphokine production, T-cell proliferation and differentiation. Furthermore, ZAP70 controls cytoskeleton modifications, adhesion and mobility of T-lymphocytes, thus ensuring correct delivery of effectors to the APC. ZAP70 is also required for TCR-CD247/CD3Z internalization and degradation through interaction with the E3 ubiquitin-protein ligase CBL and adapter proteins SLA and SLA2. Thus, ZAP70 regulates both T-cell activation switch on and switch off by modulating TCR expression at the T-cell surface. During thymocyte development, ZAP70 promotes survival and cell-cycle progression of developing thymocytes before positive selection (when cells are still CD4/CD8 double negative). Additionally, ZAP70-dependent signaling pathway may also contribute to primary B-cells formation and activation through B-cell receptor (BCR).', 'ZAP70', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Adaptive immunity, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Disease variant, Immunity, Isopeptide bond, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SCID, SH2 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (526, '2COA', '', 'Serine/threonine-protein kinase D2', 'Serine/threonine-protein kinase that converts transient diacylglycerol (DAG) signals into prolonged physiological effects downstream of PKC, and is involved in the regulation of cell proliferation via MAPK1/3 (ERK1/2) signaling, oxidative stress-induced NF-kappa-B activation, inhibition of HDAC7 transcriptional repression, signaling downstream of T-cell antigen receptor (TCR) and cytokine production, and plays a role in Golgi membrane trafficking, angiogenesis, secretory granule release and cell adhesion (PubMed:15604256, PubMed:14743217, PubMed:17077180, PubMed:16928771, PubMed:17962809, PubMed:17951978, PubMed:18262756, PubMed:19192391, PubMed:19001381, PubMed:23503467, PubMed:28428613). May potentiate mitogenesis induced by the neuropeptide bombesin by mediating an increase in the duration of MAPK1/3 (ERK1/2) signaling, which leads to accumulation of immediate-early gene products including FOS that stimulate cell cycle progression (By similarity). In response to oxidative stress, is phosphorylated at Tyr-438 and Tyr-717 by ABL1, which leads to the activation of PRKD2 without increasing its catalytic activity, and mediates activation of NF-kappa-B (PubMed:15604256, PubMed:28428613). In response to the activation of the gastrin receptor CCKBR, is phosphorylated at Ser-244 by CSNK1D and CSNK1E, translocates to the nucleus, phosphorylates HDAC7, leading to nuclear export of HDAC7 and inhibition of HDAC7 transcriptional repression of NR4A1/NUR77 (PubMed:17962809). Upon TCR stimulation, is activated independently of ZAP70, translocates from the cytoplasm to the nucleus and is required for interleukin-2 (IL2) promoter up-regulation (PubMed:17077180). During adaptive immune responses, is required in peripheral T-lymphocytes for the production of the effector cytokines IL2 and IFNG after TCR engagement and for optimal induction of antibody responses to antigens (By similarity). In epithelial cells stimulated with lysophosphatidic acid (LPA), is activated through a PKC-dependent pathway and mediates LPA-stimulated interleukin-8 (IL8) secretion via a NF-kappa-B-dependent pathway (PubMed:16928771). During TCR-induced T-cell activation, interacts with and is activated by the tyrosine kinase LCK, which results in the activation of the NFAT transcription factors (PubMed:19192391). In the trans-Golgi network (TGN), regulates the fission of transport vesicles that are on their way to the plasma membrane and in polarized cells is involved in the transport of proteins from the TGN to the basolateral membrane (PubMed:14743217). Plays an important role in endothelial cell proliferation and migration prior to angiogenesis, partly through modulation of the expression of KDR/VEGFR2 and FGFR1, two key growth factor receptors involved in angiogenesis (PubMed:19001381). In secretory pathway, is required for the release of chromogranin-A (CHGA)-containing secretory granules from the TGN (PubMed:18262756). Downstream of PRKCA, plays important roles in angiotensin-2-induced monocyte adhesion to endothelial cells (PubMed:17951978). Plays a regulatory role in angiogenesis and tumor growth by phosphorylating a downstream mediator CIB1 isoform 2, resulting in vascular endothelial growth factor A (VEGFA) secretion (PubMed:23503467).', 'PRKD2', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Adaptive immunity, Alternative splicing, Angiogenesis, ATP-binding, Cell adhesion, Cell membrane, Cytoplasm, Golgi apparatus, Immunity, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (527, '2R5T', '', 'Serine/threonine-protein kinase Sgk1', 'Serine/threonine-protein kinase which is involved in the regulation of a wide variety of ion channels, membrane transporters, cellular enzymes, transcription factors, neuronal excitability, cell growth, proliferation, survival, migration and apoptosis. Plays an important role in cellular stress response. Contributes to regulation of renal Na(+) retention, renal K(+) elimination, salt appetite, gastric acid secretion, intestinal Na(+)/H(+) exchange and nutrient transport, insulin-dependent salt sensitivity of blood pressure, salt sensitivity of peripheral glucose uptake, cardiac repolarization and memory consolidation. Up-regulates Na(+) channels: SCNN1A/ENAC, SCN5A and ASIC1/ACCN2, K(+) channels: KCNJ1/ROMK1, KCNA1-5, KCNQ1-5 and KCNE1, epithelial Ca(2+) channels: TRPV5 and TRPV6, chloride channels: BSND, CLCN2 and CFTR, glutamate transporters: SLC1A3/EAAT1, SLC1A2 /EAAT2, SLC1A1/EAAT3, SLC1A6/EAAT4 and SLC1A7/EAAT5, amino acid transporters: SLC1A5/ASCT2, SLC38A1/SN1 and SLC6A19, creatine transporter: SLC6A8, Na(+)/dicarboxylate cotransporter: SLC13A2/NADC1, Na(+)-dependent phosphate cotransporter: SLC34A2/NAPI-2B, glutamate receptor: GRIK2/GLUR6. Up-regulates carriers: SLC9A3/NHE3, SLC12A1/NKCC2, SLC12A3/NCC, SLC5A3/SMIT, SLC2A1/GLUT1, SLC5A1/SGLT1 and SLC15A2/PEPT2. Regulates enzymes: GSK3A/B, PMM2 and Na(+)/K(+) ATPase, and transcription factors: CTNNB1 and nuclear factor NF-kappa-B. Stimulates sodium transport into epithelial cells by enhancing the stability and expression of SCNN1A/ENAC. This is achieved by phosphorylating the NEDD4L ubiquitin E3 ligase, promoting its interaction with 14-3-3 proteins, thereby preventing it from binding to SCNN1A/ENAC and targeting it for degradation. Regulates store-operated Ca(+2) entry (SOCE) by stimulating ORAI1 and STIM1. Regulates KCNJ1/ROMK1 directly via its phosphorylation or indirectly via increased interaction with SLC9A3R2/NHERF2. Phosphorylates MDM2 and activates MDM2-dependent ubiquitination of p53/TP53. Phosphorylates MAPT/TAU and mediates microtubule depolymerization and neurite formation in hippocampal neurons. Phosphorylates SLC2A4/GLUT4 and up-regulates its activity. Phosphorylates APBB1/FE65 and promotes its localization to the nucleus. Phosphorylates MAPK1/ERK2 and activates it by enhancing its interaction with MAP2K1/MEK1 and MAP2K2/MEK2. Phosphorylates FBXW7 and plays an inhibitory role in the NOTCH1 signaling. Phosphorylates FOXO1 resulting in its relocalization from the nucleus to the cytoplasm. Phosphorylates FOXO3, promoting its exit from the nucleus and interference with FOXO3-dependent transcription. Phosphorylates BRAF and MAP3K3/MEKK3 and inhibits their activity. Phosphorylates SLC9A3/NHE3 in response to dexamethasone, resulting in its activation and increased localization at the cell membrane. Phosphorylates CREB1. Necessary for vascular remodeling during angiogenesis. Sustained high levels and activity may contribute to conditions such as hypertension and diabetic nephropathy. Isoform 2 exhibited a greater effect on cell plasma membrane expression of SCNN1A/ENAC and Na(+) transport than isoform 1.', 'SGK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative promoter usage, Alternative splicing, Apoptosis, ATP-binding, Cell membrane, Cytoplasm, Disulfide bond, Endoplasmic reticulum, Kinase, Membrane, Mitochondrion, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (528, '8ELC', '', 'Mitogen-activated protein kinase 9', 'Serine/threonine-protein kinase involved in various processes such as cell proliferation, differentiation, migration, transformation and programmed cell death. Extracellular stimuli such as pro-inflammatory cytokines or physical stress stimulate the stress-activated protein kinase/c-Jun N-terminal kinase (SAP/JNK) signaling pathway. In this cascade, two dual specificity kinases MAP2K4/MKK4 and MAP2K7/MKK7 phosphorylate and activate MAPK9/JNK2. In turn, MAPK9/JNK2 phosphorylates a number of transcription factors, primarily components of AP-1 such as JUN and ATF2 and thus regulates AP-1 transcriptional activity. In response to oxidative or ribotoxic stresses, inhibits rRNA synthesis by phosphorylating and inactivating the RNA polymerase 1-specific transcription initiation factor RRN3. Promotes stressed cell apoptosis by phosphorylating key regulatory factors including TP53 and YAP1. In T-cells, MAPK8 and MAPK9 are required for polarized differentiation of T-helper cells into Th1 cells. Upon T-cell receptor (TCR) stimulation, is activated by CARMA1, BCL10, MAP2K7 and MAP3K7/TAK1 to regulate JUN protein levels. Plays an important role in the osmotic stress-induced epithelial tight-junctions disruption. When activated, promotes beta-catenin/CTNNB1 degradation and inhibits the canonical Wnt signaling pathway. Participates also in neurite growth in spiral ganglion neurons. Phosphorylates the CLOCK-BMAL1 heterodimer and plays a role in the regulation of the circadian clock (PubMed:22441692). Phosphorylates POU5F1, which results in the inhibition of POU5F1''s transcriptional activity and enhances its proteasomal degradation (By similarity).', 'MAPK9', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Biological rhythms, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (529, '5U6B', '', 'Tyrosine-protein kinase receptor UFO', 'Receptor tyrosine kinase that transduces signals from the extracellular matrix into the cytoplasm by binding growth factor GAS6 and which is thus regulating many physiological processes including cell survival, cell proliferation, migration and differentiation. Ligand binding at the cell surface induces dimerization and autophosphorylation of AXL. Following activation by ligand, AXL binds and induces tyrosine phosphorylation of PI3-kinase subunits PIK3R1, PIK3R2 and PIK3R3; but also GRB2, PLCG1, LCK and PTPN11. Other downstream substrate candidates for AXL are CBL, NCK2, SOCS1 and TNS2. Recruitment of GRB2 and phosphatidylinositol 3 kinase regulatory subunits by AXL leads to the downstream activation of the AKT kinase. GAS6/AXL signaling plays a role in various processes such as endothelial cell survival during acidification by preventing apoptosis, optimal cytokine signaling during human natural killer cell development, hepatic regeneration, gonadotropin-releasing hormone neuron survival and migration, platelet activation, or regulation of thrombotic responses. Also plays an important role in inhibition of Toll-like receptors (TLRs)-mediated innate immune response.', 'AXL', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Differentiation, Disulfide bond, Glycoprotein, Host cell receptor for virus entry, Host-virus interaction, Immunity, Immunoglobulin domain, Innate immunity, Kinase, Membrane, Nucleotide-binding, Oncogene, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (530, '7UY0', '', 'Tyrosine-protein kinase Fgr', 'Non-receptor tyrosine-protein kinase that transmits signals from cell surface receptors devoid of kinase activity and contributes to the regulation of immune responses, including neutrophil, monocyte, macrophage and mast cell functions, cytoskeleton remodeling in response to extracellular stimuli, phagocytosis, cell adhesion and migration. Promotes mast cell degranulation, release of inflammatory cytokines and IgE-mediated anaphylaxis. Acts downstream of receptors that bind the Fc region of immunoglobulins, such as MS4A2/FCER1B, FCGR2A and/or FCGR2B. Acts downstream of ITGB1 and ITGB2, and regulates actin cytoskeleton reorganization, cell spreading and adhesion. Depending on the context, activates or inhibits cellular responses. Functions as a negative regulator of ITGB2 signaling, phagocytosis and SYK activity in monocytes. Required for normal ITGB1 and ITGB2 signaling, normal cell spreading and adhesion in neutrophils and macrophages. Functions as a positive regulator of cell migration and regulates cytoskeleton reorganization via RAC1 activation. Phosphorylates SYK (in vitro) and promotes SYK-dependent activation of AKT1 and MAP kinase signaling. Phosphorylates PLD2 in antigen-stimulated mast cells, leading to PLD2 activation and the production of the signaling molecules lysophosphatidic acid and diacylglycerol. Promotes activation of PIK3R1. Phosphorylates FASLG, and thereby regulates its ubiquitination and subsequent internalization. Phosphorylates ABL1. Promotes phosphorylation of CBL, CTTN, PIK3R1, PTK2/FAK1, PTK2B/PYK2 and VAV2. Phosphorylates HCLS1 that has already been phosphorylated by SYK, but not unphosphorylated HCLS1. Together with CLNK, it acts as a negative regulator of natural killer cell-activating receptors and inhibits interferon-gamma production (By similarity).', 'FGR', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, ATP-binding, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Immunity, Innate immunity, Kinase, Lipoprotein, Membrane, Mitochondrion, Mitochondrion inner membrane, Myristate, Nucleotide-binding, Palmitate, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (531, '2X4F', '', 'Myosin light chain kinase family member 4', 'Unknown', 'MYLK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (532, '7LV3', '', 'cGMP-dependent protein kinase 1', 'Serine/threonine protein kinase that acts as a key mediator of the nitric oxide (NO)/cGMP signaling pathway. GMP binding activates PRKG1, which phosphorylates serines and threonines on many cellular proteins. Numerous protein targets for PRKG1 phosphorylation are implicated in modulating cellular calcium, but the contribution of each of these targets may vary substantially among cell types. Proteins that are phosphorylated by PRKG1 regulate platelet activation and adhesion, smooth muscle contraction, cardiac function, gene expression, feedback of the NO-signaling pathway, and other processes involved in several aspects of the CNS like axon guidance, hippocampal and cerebellar learning, circadian rhythm and nociception. Smooth muscle relaxation is mediated through lowering of intracellular free calcium, by desensitization of contractile proteins to calcium, and by decrease in the contractile state of smooth muscle or in platelet activation. Regulates intracellular calcium levels via several pathways: phosphorylates IRAG1 and inhibits IP3-induced Ca(2+) release from intracellular stores, phosphorylation of KCNMA1 (BKCa) channels decreases intracellular Ca(2+) levels, which leads to increased opening of this channel. PRKG1 phosphorylates the canonical transient receptor potential channel (TRPC) family which inactivates the associated inward calcium current. Another mode of action of NO/cGMP/PKGI signaling involves PKGI-mediated inactivation of the Ras homolog gene family member A (RhoA). Phosphorylation of RHOA by PRKG1 blocks the action of this protein in myriad processes: regulation of RHOA translocation; decreasing contraction; controlling vesicle trafficking, reduction of myosin light chain phosphorylation resulting in vasorelaxation. Activation of PRKG1 by NO signaling alters also gene expression in a number of tissues. In smooth muscle cells, increased cGMP and PRKG1 activity influence expression of smooth muscle-specific contractile proteins, levels of proteins in the NO/cGMP signaling pathway, down-regulation of the matrix proteins osteopontin and thrombospondin-1 to limit smooth muscle cell migration and phenotype. Regulates vasodilator-stimulated phosphoprotein (VASP) functions in platelets and smooth muscle.', 'PRKG1', 'Homo sapiens', '{[''2.7.11.12'']}', '3D-structure, Acetylation, Allosteric enzyme, Alternative splicing, Aortic aneurysm, ATP-binding, cGMP, cGMP-binding, Coiled coil, Cytoplasm, Disease variant, Disulfide bond, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (533, '8QGY', '', 'Mitogen-activated protein kinase kinase kinase 5', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. Plays an important role in the cascades of cellular responses evoked by changes in the environment. Mediates signaling for determination of cell fate such as differentiation and survival. Plays a crucial role in the apoptosis signal transduction pathway through mitochondria-dependent caspase activation. MAP3K5/ASK1 is required for the innate immune response, which is essential for host defense against a wide range of pathogens. Mediates signal transduction of various stressors like oxidative stress as well as by receptor-mediated inflammatory signals, such as the tumor necrosis factor (TNF) or lipopolysaccharide (LPS). Once activated, acts as an upstream activator of the MKK/JNK signal transduction cascade and the p38 MAPK signal transduction cascade through the phosphorylation and activation of several MAP kinase kinases like MAP2K4/SEK1, MAP2K3/MKK3, MAP2K6/MKK6 and MAP2K7/MKK7. These MAP2Ks in turn activate p38 MAPKs and c-jun N-terminal kinases (JNKs). Both p38 MAPK and JNKs control the transcription factors activator protein-1 (AP-1).', 'MAP3K5', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Endoplasmic reticulum, Host-virus interaction, Immunity, Innate immunity, Kinase, Magnesium, Metal-binding, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (534, '2M9X', '', 'Microtubule-associated serine/threonine-protein kinase 1', 'Microtubule-associated protein essential for correct brain development (PubMed:30449657). Appears to link the dystrophin/utrophin network with microtubule filaments via the syntrophins. Phosphorylation of DMD or UTRN may modulate their affinities for associated proteins (By similarity).', 'MAST1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Disease variant, Intellectual disability, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (535, '5D9H', '', 'STE20/SPS1-related proline-alanine-rich protein kinase', 'Effector serine/threonine-protein kinase component of the WNK-SPAK/OSR1 kinase cascade, which is involved in various processes, such as ion transport, response to hypertonic stress and blood pressure (PubMed:16382158, PubMed:17488636, PubMed:19633012, PubMed:21486947). Specifically recognizes and binds proteins with a RFXV motif (PubMed:14563843). Acts downstream of WNK kinases (WNK1, WNK2, WNK3 or WNK4): following activation by WNK kinases, catalyzes phosphorylation of ion cotransporters, such as SLC12A1/NKCC2, SLC12A2/NKCC1, SLC12A3/NCC, SLC12A5/KCC2 or SLC12A6/KCC3, regulating their activity (PubMed:14563843, PubMed:16382158, PubMed:17488636, PubMed:19633012, PubMed:21486947). Mediates regulatory volume increase in response to hyperosmotic stress by catalyzing phosphorylation of ion cotransporters SLC12A1/NKCC2, SLC12A2/NKCC1 and SLC12A6/KCC3 downstream of WNK1 and WNK3 kinases (By similarity). Phosphorylation of Na-K-Cl cotransporters SLC12A2/NKCC1 and SLC12A2/NKCC1 promote their activation and ion influx; simultaneously, phosphorylation of K-Cl cotransporters SLC12A5/KCC2 and SLC12A6/KCC3 inhibit their activity, blocking ion efflux (By similarity). Acts as a regulator of NaCl reabsorption in the distal nephron by mediating phosphorylation and activation of the thiazide-sensitive Na-Cl cotransporter SLC12A3/NCC in distal convoluted tubule cells of kidney downstream of WNK4 (PubMed:17488636, PubMed:19633012, PubMed:21486947). Mediates the inhibition of SLC4A4, SLC26A6 as well as CFTR activities (PubMed:21317537, PubMed:23542070). Phosphorylates RELT (PubMed:16530727).', 'Stk39', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (536, '7T8J', '', 'Transcription factor ETV6', 'Transcriptional repressor; binds to the DNA sequence 5''-CCGGAAGT-3''. Plays a role in hematopoiesis and malignant transformation.', 'ETV6', 'Homo sapiens', '{[]}', '3D-structure, Acetylation, Chromosomal rearrangement, Disease variant, DNA-binding, Isopeptide bond, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Repressor, Transcription, Transcription regulation, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (537, '7KJA', '', 'Ephrin type-A receptor 2', 'Receptor tyrosine kinase which binds promiscuously membrane-bound ephrin-A family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Activated by the ligand ephrin-A1/EFNA1 regulates migration, integrin-mediated adhesion, proliferation and differentiation of cells. Regulates cell adhesion and differentiation through DSG1/desmoglein-1 and inhibition of the ERK1/ERK2 (MAPK3/MAPK1, respectively) signaling pathway. May also participate in UV radiation-induced apoptosis and have a ligand-independent stimulatory effect on chemotactic cell migration. During development, may function in distinctive aspects of pattern formation and subsequently in development of several fetal tissues. Involved for instance in angiogenesis, in early hindbrain development and epithelial proliferation and branching morphogenesis during mammary gland development. Engaged by the ligand ephrin-A5/EFNA5 may regulate lens fiber cells shape and interactions and be important for lens transparency development and maintenance. With ephrin-A2/EFNA2 may play a role in bone remodeling through regulation of osteoclastogenesis and osteoblastogenesis.', 'EPHA2', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, Apoptosis, ATP-binding, Cataract, Cell adhesion, Cell junction, Cell membrane, Cell projection, Differentiation, Disease variant, Disulfide bond, Glycoprotein, Host cell receptor for virus entry, Host-virus interaction, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (538, '2J0J', '', 'Focal adhesion kinase 1', 'Non-receptor protein-tyrosine kinase that plays an essential role in regulating cell migration, adhesion, spreading, reorganization of the actin cytoskeleton, formation and disassembly of focal adhesions and cell protrusions, cell cycle progression, cell proliferation and apoptosis. Required for early embryonic development, embryonic angiogenesis, normal cardiomyocyte migration and proliferation, and normal heart development. Regulates axon growth and neuronal cell migration, axon branching and synapse formation; required for normal development of the nervous system. Plays a role in osteogenesis and differentiation of osteoblasts. Functions in integrin signal transduction, but also in signaling downstream of numerous growth factor receptors, G-protein coupled receptors (GPCR), ephrin receptors, netrin receptors and LDL receptors. Forms multisubunit signaling complexes with SRC and SRC family members upon activation; this leads to the phosphorylation of additional tyrosine residues, creating binding sites for scaffold proteins, effectors and substrates. Regulates numerous signaling pathways. Promotes activation of phosphatidylinositol 3-kinase and the AKT1 signaling cascade. Promotes activation of MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling cascade. Promotes localized and transient activation of guanine nucleotide exchange factors (GEFs) and GTPase-activating proteins (GAPs), and thereby modulates the activity of Rho family GTPases. Signaling via CAS family members mediates activation of RAC1. Regulates P53/TP53 activity and stability. Phosphorylates SRC; this increases SRC kinase activity. Isoform 2 (FRNK) does not contain a kinase domain and inhibits PTK2/FAK1 phosphorylation and signaling.', 'PTK2', 'Gallus gallus', '{[''2.7.10.2'']}', '3D-structure, Alternative promoter usage, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Developmental protein, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (539, '2HW6', '', 'MAP kinase-interacting serine/threonine-protein kinase 1', 'May play a role in the response to environmental stress and cytokines. Appears to regulate translation by phosphorylating EIF4E, thus increasing the affinity of this protein for the 7-methylguanosine-containing mRNA cap.', 'MKNK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Translation regulation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (540, '7NX0', '', 'Leukocyte tyrosine kinase receptor', 'Receptor with a tyrosine-protein kinase activity (PubMed:10445845, PubMed:20548102, PubMed:30061385). Following activation by ALKAL1 or ALKAL2 ligands at the cell surface, transduces an extracellular signal into an intracellular response (PubMed:30061385, PubMed:34646012). Ligand-binding to the extracellular domain induces tyrosine kinase activation, leading to activation of the mitogen-activated protein kinase (MAPK) pathway (PubMed:20548102). Phosphorylates almost exclusively at the first tyrosine of the Y-x-x-x-Y-Y motif (By similarity). The exact function of this protein is not known; studies with chimeric proteins demonstrate its ability to promote growth and specifically neurite outgrowth, and cell survival (PubMed:9223670, PubMed:18849880). Involved in regulation of the secretory pathway involving endoplasmic reticulum (ER) export sites (ERESs) and ER to Golgi transport (PubMed:20548102).', 'LTK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disulfide bond, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Signal, Systemic lupus erythematosus, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (541, '6GL7', '', 'Neurturin', 'Supports the survival of sympathetic neurons in culture. May regulate the development and maintenance of the CNS. Might control the size of non-neuronal cell population such as haemopoietic cells.', 'NRTN', 'Homo sapiens', '{[]}', '3D-structure, Disease variant, Disulfide bond, Growth factor, Hirschsprung disease, Reference proteome, Secreted, Signal');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (542, '5CEN', '', 'Mitogen-activated protein kinase kinase kinase 12', 'Part of a non-canonical MAPK signaling pathway (PubMed:28111074). Activated by APOE, enhances the AP-1-mediated transcription of APP, via a MAP kinase signal transduction pathway composed of MAP2K7 and MAPK1/ERK2 and MAPK3/ERK1 (PubMed:28111074). May be an activator of the JNK/SAPK pathway.', 'MAP3K12', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Kinase, Magnesium, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (543, '6KHD', '', 'Dual specificity protein kinase CLK1', 'Dual specificity kinase acting on both serine/threonine and tyrosine-containing substrates. Phosphorylates serine- and arginine-rich (SR) proteins of the spliceosomal complex and may be a constituent of a network of regulatory mechanisms that enable SR proteins to control RNA splicing. Phosphorylates: SRSF1, SRSF3 and PTPN1 (PubMed:10480872, PubMed:19168442). Regulates the alternative splicing of tissue factor (F3) pre-mRNA in endothelial cells (PubMed:19168442).', 'CLK1', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (544, '6ZIW', '', 'Interleukin-1 receptor-associated kinase 3', 'Putative inactive protein kinase which regulates signaling downstream of immune receptors including IL1R and Toll-like receptors (PubMed:10383454, PubMed:29686383). Inhibits dissociation of IRAK1 and IRAK4 from the Toll-like receptor signaling complex by either inhibiting the phosphorylation of IRAK1 and IRAK4 or stabilizing the receptor complex (By similarity). Upon IL33-induced lung inflammation, positively regulates expression of IL6, CSF3, CXCL2 and CCL5 mRNAs in dendritic cells (PubMed:29686383).', 'IRAK3', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Asthma, ATP-binding, Cytoplasm, Disulfide bond, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (545, '6NT9', '', 'Serine/threonine-protein kinase TBK1', 'Serine/threonine kinase that plays an essential role in regulating inflammatory responses to foreign agents (PubMed:12692549, PubMed:14703513, PubMed:18583960, PubMed:12702806, PubMed:15367631, PubMed:10581243, PubMed:11839743, PubMed:15485837, PubMed:21138416, PubMed:25636800, PubMed:23453971, PubMed:23453972, PubMed:23746807, PubMed:26611359, PubMed:32404352). Following activation of toll-like receptors by viral or bacterial components, associates with TRAF3 and TANK and phosphorylates interferon regulatory factors (IRFs) IRF3 and IRF7 as well as DDX3X (PubMed:12692549, PubMed:14703513, PubMed:18583960, PubMed:12702806, PubMed:15367631, PubMed:25636800). This activity allows subsequent homodimerization and nuclear translocation of the IRFs leading to transcriptional activation of pro-inflammatory and antiviral genes including IFNA and IFNB (PubMed:12702806, PubMed:15367631, PubMed:25636800, PubMed:32972995). In order to establish such an antiviral state, TBK1 form several different complexes whose composition depends on the type of cell and cellular stimuli (PubMed:23453971, PubMed:23453972, PubMed:23746807). Plays a key role in IRF3 activation: acts by first phosphorylating innate adapter proteins MAVS, STING1 and TICAM1 on their pLxIS motif, leading to recruitment of IRF3, thereby licensing IRF3 for phosphorylation by TBK1 (PubMed:25636800, PubMed:30842653). Phosphorylated IRF3 dissociates from the adapter proteins, dimerizes, and then enters the nucleus to induce expression of interferons (PubMed:25636800). Thus, several scaffolding molecules including FADD, TRADD, MAVS, AZI2, TANK or TBKBP1/SINTBAD can be recruited to the TBK1-containing-complexes (PubMed:21931631). Under particular conditions, functions as a NF-kappa-B effector by phosphorylating NF-kappa-B inhibitor alpha/NFKBIA, IKBKB or RELA to translocate NF-Kappa-B to the nucleus (PubMed:10783893, PubMed:15489227). Restricts bacterial proliferation by phosphorylating the autophagy receptor OPTN/Optineurin on ''Ser-177'', thus enhancing LC3 binding affinity and antibacterial autophagy (PubMed:21617041). Phosphorylates SMCR8 component of the C9orf72-SMCR8 complex, promoting autophagosome maturation (PubMed:27103069). Phosphorylates ATG8 proteins MAP1LC3C and GABARAPL2, thereby preventing their delipidation and premature removal from nascent autophagosomes (PubMed:31709703). Phosphorylates and activates AKT1 (PubMed:21464307). Seems to play a role in energy balance regulation by sustaining a state of chronic, low-grade inflammation in obesity, wich leads to a negative impact on insulin sensitivity (By similarity). Attenuates retroviral budding by phosphorylating the endosomal sorting complex required for transport-I (ESCRT-I) subunit VPS37C (PubMed:21270402). Phosphorylates Borna disease virus (BDV) P protein (PubMed:16155125). Plays an essential role in the TLR3- and IFN-dependent control of herpes virus HSV-1 and HSV-2 infections in the central nervous system (PubMed:22851595). Acts both as a positive and negative regulator of the mTORC1 complex, depending on the context: activates mTORC1 in response to growth factors by catalyzing phosphorylation of MTOR, while it limits the mTORC1 complex by promoting phosphorylation of RPTOR (PubMed:29150432, PubMed:31530866).', 'TBK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Amyotrophic lateral sclerosis, Antiviral defense, ATP-binding, Coiled coil, Cytoplasm, Disease variant, Glaucoma, Host-virus interaction, Immunity, Innate immunity, Isopeptide bond, Kinase, Neurodegeneration, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (546, '4OBO', '', 'Mitogen-activated protein kinase kinase kinase kinase 4', 'Serine/threonine kinase that may play a role in the response to environmental stress and cytokines such as TNF-alpha. Appears to act upstream of the JUN N-terminal pathway. Phosphorylates SMAD1 on Thr-322.', 'MAP4K4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (547, '7UKZ', '', 'Cyclin-dependent kinase 11B', 'Plays multiple roles in cell cycle progression, cytokinesis and apoptosis. Involved in pre-mRNA splicing in a kinase activity-dependent manner. Isoform 7 may act as a negative regulator of normal cell cycle progression.', 'CDK11B', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative initiation, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (555, '2W4O', '', 'Calcium/calmodulin-dependent protein kinase type IV', 'Calcium/calmodulin-dependent protein kinase that operates in the calcium-triggered CaMKK-CaMK4 signaling cascade and regulates, mainly by phosphorylation, the activity of several transcription activators, such as CREB1, MEF2D, JUN and RORA, which play pivotal roles in immune response, inflammation, and memory consolidation. In the thymus, regulates the CD4(+)/CD8(+) double positive thymocytes selection threshold during T-cell ontogeny. In CD4 memory T-cells, is required to link T-cell antigen receptor (TCR) signaling to the production of IL2, IFNG and IL4 (through the regulation of CREB and MEF2). Regulates the differentiation and survival phases of osteoclasts and dendritic cells (DCs). Mediates DCs survival by linking TLR4 and the regulation of temporal expression of BCL2. Phosphorylates the transcription activator CREB1 on ''Ser-133'' in hippocampal neuron nuclei and contribute to memory consolidation and long term potentiation (LTP) in the hippocampus. Can activate the MAP kinases MAPK1/ERK2, MAPK8/JNK1 and MAPK14/p38 and stimulate transcription through the phosphorylation of ELK1 and ATF2. Can also phosphorylate in vitro CREBBP, PRM2, MEF2A and STMN1/OP18.', 'CAMK4', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Adaptive immunity, ATP-binding, Calcium, Calmodulin-binding, Cytoplasm, Glycoprotein, Immunity, Inflammatory response, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (548, '1B6C', '', 'Peptidyl-prolyl cis-trans isomerase FKBP1A', 'Keeps in an inactive conformation TGFBR1, the TGF-beta type I serine/threonine kinase receptor, preventing TGF-beta receptor activation in absence of ligand. Recruits SMAD7 to ACVR1B which prevents the association of SMAD2 and SMAD3 with the activin receptor complex, thereby blocking the activin signal. May modulate the RYR1 calcium channel activity. PPIases accelerate the folding of proteins. It catalyzes the cis-trans isomerization of proline imidic peptide bonds in oligopeptides.', 'FKBP1A', 'Homo sapiens', '{[''5.2.1.8'']}', '3D-structure, Acetylation, Cytoplasm, Direct protein sequencing, Isomerase, Membrane, Reference proteome, Rotamase, Sarcoplasmic reticulum');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (549, '6BFN', '', 'Interleukin-1 receptor-associated kinase 1', 'Serine/threonine-protein kinase that plays a critical role in initiating innate immune response against foreign pathogens. Involved in Toll-like receptor (TLR) and IL-1R signaling pathways. Is rapidly recruited by MYD88 to the receptor-signaling complex upon TLR activation. Association with MYD88 leads to IRAK1 phosphorylation by IRAK4 and subsequent autophosphorylation and kinase activation. Phosphorylates E3 ubiquitin ligases Pellino proteins (PELI1, PELI2 and PELI3) to promote pellino-mediated polyubiquitination of IRAK1. Then, the ubiquitin-binding domain of IKBKG/NEMO binds to polyubiquitinated IRAK1 bringing together the IRAK1-MAP3K7/TAK1-TRAF6 complex and the NEMO-IKKA-IKKB complex. In turn, MAP3K7/TAK1 activates IKKs (CHUK/IKKA and IKBKB/IKKB) leading to NF-kappa-B nuclear translocation and activation. Alternatively, phosphorylates TIRAP to promote its ubiquitination and subsequent degradation. Phosphorylates the interferon regulatory factor 7 (IRF7) to induce its activation and translocation to the nucleus, resulting in transcriptional activation of type I IFN genes, which drive the cell in an antiviral state. When sumoylated, translocates to the nucleus and phosphorylates STAT3.', 'IRAK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Direct protein sequencing, Host-virus interaction, Immunity, Innate immunity, Isopeptide bond, Kinase, Lipid droplet, Magnesium, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (550, '1XJD', '', 'Protein kinase C theta type', 'Calcium-independent, phospholipid- and diacylglycerol (DAG)-dependent serine/threonine-protein kinase that mediates non-redundant functions in T-cell receptor (TCR) signaling, including T-cells activation, proliferation, differentiation and survival, by mediating activation of multiple transcription factors such as NF-kappa-B, JUN, NFATC1 and NFATC2. In TCR-CD3/CD28-co-stimulated T-cells, is required for the activation of NF-kappa-B and JUN, which in turn are essential for IL2 production, and participates in the calcium-dependent NFATC1 and NFATC2 transactivation. Mediates the activation of the canonical NF-kappa-B pathway (NFKB1) by direct phosphorylation of CARD11 on several serine residues, inducing CARD11 association with lipid rafts and recruitment of the BCL10-MALT1 complex, which then activates IKK complex, resulting in nuclear translocation and activation of NFKB1. May also play an indirect role in activation of the non-canonical NF-kappa-B (NFKB2) pathway. In the signaling pathway leading to JUN activation, acts by phosphorylating the mediator STK39/SPAK and may not act through MAP kinases signaling. Plays a critical role in TCR/CD28-induced NFATC1 and NFATC2 transactivation by participating in the regulation of reduced inositol 1,4,5-trisphosphate generation and intracellular calcium mobilization. After costimulation of T-cells through CD28 can phosphorylate CBLB and is required for the ubiquitination and subsequent degradation of CBLB, which is a prerequisite for the activation of TCR. During T-cells differentiation, plays an important role in the development of T-helper 2 (Th2) cells following immune and inflammatory responses, and, in the development of inflammatory autoimmune diseases, is necessary for the activation of IL17-producing Th17 cells. May play a minor role in Th1 response. Upon TCR stimulation, mediates T-cell protective survival signal by phosphorylating BAD, thus protecting T-cells from BAD-induced apoptosis, and by up-regulating BCL-X(L)/BCL2L1 levels through NF-kappa-B and JUN pathways. In platelets, regulates signal transduction downstream of the ITGA2B, CD36/GP4, F2R/PAR1 and F2RL3/PAR4 receptors, playing a positive role in ''outside-in'' signaling and granule secretion signal transduction. May relay signals from the activated ITGA2B receptor by regulating the uncoupling of WASP and WIPF1, thereby permitting the regulation of actin filament nucleation and branching activity of the Arp2/3 complex. May mediate inhibitory effects of free fatty acids on insulin signaling by phosphorylating IRS1, which in turn blocks IRS1 tyrosine phosphorylation and downstream activation of the PI3K/AKT pathway. Phosphorylates MSN (moesin) in the presence of phosphatidylglycerol or phosphatidylinositol. Phosphorylates PDPK1 at ''Ser-504'' and ''Ser-532'' and negatively regulates its ability to phosphorylate PKB/AKT1. Phosphorylates CCDC88A/GIV and inhibits its guanine nucleotide exchange factor activity (PubMed:23509302).', 'PRKCQ', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Immunity, Inflammatory response, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (551, '4QT8', '', 'Macrophage-stimulating protein receptor', 'Receptor tyrosine kinase that transduces signals from the extracellular matrix into the cytoplasm by binding to MST1 ligand. Regulates many physiological processes including cell survival, migration and differentiation. Ligand binding at the cell surface induces autophosphorylation of RON on its intracellular domain that provides docking sites for downstream signaling molecules. Following activation by ligand, interacts with the PI3-kinase subunit PIK3R1, PLCG1 or the adapter GAB1. Recruitment of these downstream effectors by RON leads to the activation of several signaling cascades including the RAS-ERK, PI3 kinase-AKT, or PLCgamma-PKC. RON signaling activates the wound healing response by promoting epithelial cell migration, proliferation as well as survival at the wound site. Also plays a role in the innate immune response by regulating the migration and phagocytic activity of macrophages. Alternatively, RON can also promote signals such as cell migration and proliferation in response to growth factors other than MST1 ligand.', 'MST1R', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cleavage on pair of basic residues, Disease variant, Disulfide bond, Glycoprotein, Immunity, Innate immunity, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (552, '3QUP', '', 'Tyrosine-protein kinase receptor TYRO3', 'Receptor tyrosine kinase that transduces signals from the extracellular matrix into the cytoplasm by binding to several ligands including TULP1 or GAS6. Regulates many physiological processes including cell survival, migration and differentiation. Ligand binding at the cell surface induces dimerization and autophosphorylation of TYRO3 on its intracellular domain that provides docking sites for downstream signaling molecules. Following activation by ligand, interacts with PIK3R1 and thereby enhances PI3-kinase activity. Activates the AKT survival pathway, including nuclear translocation of NF-kappa-B and up-regulation of transcription of NF-kappa-B-regulated genes. TYRO3 signaling plays a role in various processes such as neuron protection from excitotoxic injury, platelet aggregation and cytoskeleton reorganization. Also plays an important role in inhibition of Toll-like receptors (TLRs)-mediated innate immune response by activating STAT1, which selectively induces production of suppressors of cytokine signaling SOCS1 and SOCS3.', 'Tyro3', 'Mus musculus', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell membrane, Disulfide bond, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (553, '6WHB', '', 'Mitogen-activated protein kinase kinase kinase 1', 'Component of a protein kinase signal transduction cascade (PubMed:9808624). Activates the ERK and JNK kinase pathways by phosphorylation of MAP2K1 and MAP2K4 (PubMed:9808624). May phosphorylate the MAPK8/JNK1 kinase (PubMed:17761173). Activates CHUK and IKBKB, the central protein kinases of the NF-kappa-B pathway (PubMed:9808624).', 'MAP3K1', 'Homo sapiens', '{[''2.7.11.25'',''2.3.2.27'']}', '3D-structure, Acetylation, ATP-binding, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (554, '7MO7', '', 'Hepatocyte growth factor', 'Potent mitogen for mature parenchymal hepatocyte cells, seems to be a hepatotrophic factor, and acts as a growth factor for a broad spectrum of tissues and cell types (PubMed:20624990). Activating ligand for the receptor tyrosine kinase MET by binding to it and promoting its dimerization (PubMed:20977675, PubMed:15167892). Activates MAPK signaling following TMPRSS13 cleavage and activation (PubMed:20977675).', 'HGF', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Deafness, Direct protein sequencing, Disulfide bond, Glycoprotein, Growth factor, Kringle, Non-syndromic deafness, Pyrrolidone carboxylic acid, Reference proteome, Repeat, Serine protease homolog, Signal');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (556, '8X2A', '', 'Cytoplasmic tyrosine-protein kinase BMX', 'Non-receptor tyrosine kinase that plays central but diverse modulatory roles in various signaling processes involved in the regulation of actin reorganization, cell migration, cell proliferation and survival, cell adhesion, and apoptosis. Participates in signal transduction stimulated by growth factor receptors, cytokine receptors, G-protein coupled receptors, antigen receptors and integrins. Induces tyrosine phosphorylation of BCAR1 in response to integrin regulation. Activation of BMX by integrins is mediated by PTK2/FAK1, a key mediator of integrin signaling events leading to the regulation of actin cytoskeleton and cell motility. Plays a critical role in TNF-induced angiogenesis, and implicated in the signaling of TEK and FLT1 receptors, 2 important receptor families essential for angiogenesis. Required for the phosphorylation and activation of STAT3, a transcription factor involved in cell differentiation. Also involved in interleukin-6 (IL6) induced differentiation. Also plays a role in programming adaptive cytoprotection against extracellular stress in different cell systems, salivary epithelial cells, brain endothelial cells, and dermal fibroblasts. May be involved in regulation of endocytosis through its interaction with an endosomal protein RUFY1. May also play a role in the growth and differentiation of hematopoietic cells; as well as in signal transduction in endocardial and arterial endothelial cells.', 'BMX', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Apoptosis, ATP-binding, Cell adhesion, Cytoplasm, Direct protein sequencing, Kinase, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, SH2 domain, Stress response, Transferase, Tyrosine-protein kinase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (557, '5HGI', '', 'Serine/threonine-protein kinase/endoribonuclease IRE1', 'Serine/threonine-protein kinase and endoribonuclease that acts as a key sensor for the endoplasmic reticulum unfolded protein response (UPR) (PubMed:11175748, PubMed:11779464, PubMed:12637535, PubMed:21317875, PubMed:28128204, PubMed:9637683, PubMed:30118681). In unstressed cells, the endoplasmic reticulum luminal domain is maintained in its inactive monomeric state by binding to the endoplasmic reticulum chaperone HSPA5/BiP (PubMed:21317875). Accumulation of misfolded proteins in the endoplasmic reticulum causes release of HSPA5/BiP, allowing the luminal domain to homodimerize, promoting autophosphorylation of the kinase domain and subsequent activation of the endoribonuclease activity (PubMed:21317875). The endoribonuclease activity is specific for XBP1 mRNA and excises 26 nucleotides from XBP1 mRNA (PubMed:11779464, PubMed:24508390, PubMed:21317875). The resulting spliced transcript of XBP1 encodes a transcriptional activator protein that up-regulates expression of UPR target genes (PubMed:11779464, PubMed:24508390, PubMed:21317875). Acts as an upstream signal for ER stress-induced GORASP2-mediated unconventional (ER/Golgi-independent) trafficking of CFTR to cell membrane by modulating the expression and localization of SEC16A (PubMed:21884936, PubMed:28067262).', 'ERN1', 'Homo sapiens', '{[''2.7.11.1'',''3.1.26.-'']}', '3D-structure, ADP-ribosylation, Alternative splicing, Apoptosis, ATP-binding, Disulfide bond, Endoplasmic reticulum, Glycoprotein, Hydrolase, Kinase, Magnesium, Membrane, Metal-binding, Multifunctional enzyme, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Signal, Transcription, Transcription regulation, Transferase, Transmembrane, Transmembrane helix, Unfolded protein response');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (558, '2WWE', '', 'Phosphatidylinositol 3-kinase C2 domain-containing subunit gamma', 'Generates phosphatidylinositol 3-phosphate (PtdIns3P) and phosphatidylinositol 3,4-bisphosphate (PtdIns(3,4)P2) that act as second messengers (By similarity). May play a role in SDF1A-stimulated chemotaxis (By similarity).', 'PIK3C2G', 'Homo sapiens', '{[''2.7.1.137'',''2.7.1.154'']}', '3D-structure, Alternative splicing, ATP-binding, Chemotaxis, Kinase, Lipid metabolism, Membrane, Nucleotide-binding, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (559, '4WIH', '', 'cAMP-dependent protein kinase catalytic subunit alpha', 'Phosphorylates a large number of substrates in the cytoplasm and the nucleus (By similarity). Phosphorylates CDC25B, ABL1, NFKB1, CLDN3, PSMC5/RPT6, PJA2, RYR2, RORA, SOX9 and VASP (By similarity). Regulates the abundance of compartmentalized pools of its regulatory subunits through phosphorylation of PJA2 which binds and ubiquitinates these subunits, leading to their subsequent proteolysis. RORA is activated by phosphorylation. Required for glucose-mediated adipogenic differentiation increase and osteogenic differentiation inhibition from osteoblasts (By similarity). Involved in chondrogenesis by mediating phosphorylation of SOX9 (By similarity). Involved in the regulation of platelets in response to thrombin and collagen; maintains circulating platelets in a resting state by phosphorylating proteins in numerous platelet inhibitory pathways when in complex with NF-kappa-B (NFKB1 and NFKB2) and I-kappa-B-alpha (NFKBIA), but thrombin and collagen disrupt these complexes and free active PRKACA stimulates platelets and leads to platelet aggregation by phosphorylating VASP. RYR2 channel activity is potentiated by phosphorylation in presence of luminal Ca(2+), leading to reduced amplitude and increased frequency of store overload-induced Ca(2+) release (SOICR) characterized by an increased rate of Ca(2+) release and propagation velocity of spontaneous Ca(2+) waves, despite reduced wave amplitude and resting cytosolic Ca(2+). PSMC5/RPT6 activation by phosphorylation stimulates proteasome. Negatively regulates tight junctions (TJs) in ovarian cancer cells via CLDN3 phosphorylation. NFKB1 phosphorylation promotes NF-kappa-B p50-p50 DNA binding. Required for phosphorylation of GLI transcription factors which inhibits them and prevents transcriptional activation of Hedgehog signaling pathway target genes (By similarity). GLI transcription factor phosphorylation is inhibited by interaction of PRKACA with SMO which sequesters PRKACA at the cell membrane (By similarity). Involved in embryonic development by down-regulating the Hedgehog (Hh) signaling pathway that determines embryo pattern formation and morphogenesis most probably through the regulation of OFD1 in ciliogenesis (By similarity). Prevents meiosis resumption in prophase-arrested oocytes via CDC25B inactivation by phosphorylation (By similarity). May also regulate rapid eye movement (REM) sleep in the pedunculopontine tegmental (PPT) (By similarity). Phosphorylates APOBEC3G and AICDA. Phosphorylates HSF1; this phosphorylation promotes HSF1 nuclear localization and transcriptional activity upon heat shock (By similarity). Acts as a negative regulator of mTORC1 by mediating phosphorylation of RPTOR (By similarity).', 'PRKACA', 'Cricetulus griseus', '{[''2.7.11.11'']}', '3D-structure, ATP-binding, cAMP, Cell membrane, Cytoplasm, Kinase, Lipoprotein, Membrane, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (560, '1A06', '', 'Calcium/calmodulin-dependent protein kinase type 1', 'Calcium/calmodulin-dependent protein kinase that operates in the calcium-triggered CaMKK-CaMK1 signaling cascade and, upon calcium influx, regulates transcription activators activity, cell cycle, hormone production, cell differentiation, actin filament organization and neurite outgrowth. Recognizes the substrate consensus sequence [MVLIF]-x-R-x(2)-[ST]-x(3)-[MVLIF]. Regulates axonal extension and growth cone motility in hippocampal and cerebellar nerve cells. Upon NMDA receptor-mediated Ca(2+) elevation, promotes dendritic growth in hippocampal neurons and is essential in synapses for full long-term potentiation (LTP) and ERK2-dependent translational activation. Downstream of NMDA receptors, promotes the formation of spines and synapses in hippocampal neurons by phosphorylating ARHGEF7/BETAPIX on ''Ser-516'', which results in the enhancement of ARHGEF7 activity and activation of RAC1. Promotes neuronal differentiation and neurite outgrowth by activation and phosphorylation of MARK2 on ''Ser-91'', ''Ser-92'', ''Ser-93'' and ''Ser-294''. Promotes nuclear export of HDAC5 and binding to 14-3-3 by phosphorylation of ''Ser-259'' and ''Ser-498'' in the regulation of muscle cell differentiation (By similarity). Regulates NUMB-mediated endocytosis by phosphorylation of NUMB on ''Ser-275'' and ''Ser-294''. Involved in the regulation of basal and estrogen-stimulated migration of medulloblastoma cells through ARHGEF7/BETAPIX phosphorylation (By similarity). Is required for proper activation of cyclin-D1/CDK4 complex during G1 progression in diploid fibroblasts. Plays a role in K(+) and ANG2-mediated regulation of the aldosterone synthase (CYP11B2) to produce aldosterone in the adrenal cortex. Phosphorylates EIF4G3/eIF4GII. In vitro phosphorylates CREB1, ATF1, CFTR, MYL9 and SYN1/synapsin I.', 'Camk1', 'Rattus norvegicus', '{[''2.7.11.17'']}', '3D-structure, Allosteric enzyme, ATP-binding, Calmodulin-binding, Cell cycle, Cytoplasm, Developmental protein, Differentiation, Direct protein sequencing, Isopeptide bond, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (561, '3TTI', '', 'Mitogen-activated protein kinase 10', 'Serine/threonine-protein kinase involved in various processes such as neuronal proliferation, differentiation, migration and programmed cell death. Extracellular stimuli such as pro-inflammatory cytokines or physical stress stimulate the stress-activated protein kinase/c-Jun N-terminal kinase (SAP/JNK) signaling pathway. In this cascade, two dual specificity kinases MAP2K4/MKK4 and MAP2K7/MKK7 phosphorylate and activate MAPK10/JNK3. In turn, MAPK10/JNK3 phosphorylates a number of transcription factors, primarily components of AP-1 such as JUN and ATF2 and thus regulates AP-1 transcriptional activity. Plays regulatory roles in the signaling pathways during neuronal apoptosis. Phosphorylates the neuronal microtubule regulator STMN2. Acts in the regulation of the amyloid-beta precursor protein/APP signaling during neuronal differentiation by phosphorylating APP. Participates also in neurite growth in spiral ganglion neurons. Phosphorylates the CLOCK-BMAL1 heterodimer and plays a role in the photic regulation of the circadian clock (PubMed:22441692). Phosphorylates JUND and this phosphorylation is inhibited in the presence of MEN1 (PubMed:22327296).', 'MAPK10', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Alternative splicing, ATP-binding, Biological rhythms, Chromosomal rearrangement, Cytoplasm, Direct protein sequencing, Epilepsy, Intellectual disability, Kinase, Lipoprotein, Membrane, Mitochondrion, Nucleotide-binding, Nucleus, Palmitate, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (562, '1BO1', '', 'Phosphatidylinositol 5-phosphate 4-kinase type-2 beta', 'Participates in the biosynthesis of phosphatidylinositol 4,5-bisphosphate (PubMed:9038203, PubMed:26774281). Preferentially utilizes GTP, rather than ATP, for PI(5)P phosphorylation and its activity reflects changes in direct proportion to the physiological GTP concentration (PubMed:26774281). Its GTP-sensing activity is critical for metabolic adaptation (PubMed:26774281). PIP4Ks negatively regulate insulin signaling through a catalytic-independent mechanism. They interact with PIP5Ks and suppress PIP5K-mediated PtdIns(4,5)P2 synthesis and insulin-dependent conversion to PtdIns(3,4,5)P3 (PubMed:31091439).', 'PIP4K2B', 'Homo sapiens', '{[''2.7.1.149'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Endoplasmic reticulum, GTP-binding, Kinase, Lipid metabolism, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (563, '6KYQ', '', 'Serine/threonine-protein kinase DCLK1', 'Probable kinase that may be involved in a calcium-signaling pathway controlling neuronal migration in the developing brain. May also participate in functions of the mature nervous system.', 'DCLK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Developmental protein, Differentiation, Kinase, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (564, '3GGF', '', 'Serine/threonine-protein kinase 26', 'Serine/threonine-protein kinase that acts as a mediator of cell growth (PubMed:11641781, PubMed:17360971). Modulates apoptosis (PubMed:11641781, PubMed:17360971). In association with STK24 negatively regulates Golgi reorientation in polarized cell migration upon RHO activation (PubMed:27807006). Phosphorylates ATG4B at ''Ser-383'', thereby increasing autophagic flux (PubMed:29232556).', 'STK26', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Golgi apparatus, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (565, '8JFK', '', 'Phosphorylase b kinase regulatory subunit beta', 'Phosphorylase b kinase catalyzes the phosphorylation of serine in certain substrates, including troponin I. The beta chain acts as a regulatory unit and modulates the activity of the holoenzyme in response to phosphorylation.', 'PHKB', 'Homo sapiens', '{[]}', 'Acetylation, Alternative splicing, Calmodulin-binding, Carbohydrate metabolism, Cell membrane, Disease variant, Glycogen metabolism, Glycogen storage disease, Lipoprotein, Membrane, Phosphoprotein, Prenylation, Reference proteome');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (566, '6EIX', '', 'Activin receptor type-1', 'Bone morphogenetic protein (BMP) type I receptor that is involved in a wide variety of biological processes, including bone, heart, cartilage, nervous, and reproductive system development and regulation (PubMed:20628059, PubMed:22977237). As a type I receptor, forms heterotetrameric receptor complexes with the type II receptors AMHR2, ACVR2A or ACVR2B (PubMed:17911401). Upon binding of ligands such as BMP7 or GDF2/BMP9 to the heteromeric complexes, type II receptors transphosphorylate ACVR1 intracellular domain (PubMed:25354296). In turn, ACVR1 kinase domain is activated and subsequently phosphorylates SMAD1/5/8 proteins that transduce the signal (PubMed:9748228). In addition to its role in mediating BMP pathway-specific signaling, suppresses TGFbeta/activin pathway signaling by interfering with the binding of activin to its type II receptor (PubMed:17911401). Besides canonical SMAD signaling, can activate non-canonical pathways such as p38 mitogen-activated protein kinases/MAPKs (By similarity). May promote the expression of HAMP, potentially via its interaction with BMP6 (By similarity).', 'ACVR1', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, ATP-binding, Disease variant, Glycoprotein, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (567, '5DE2', '', 'Serine/threonine-protein kinase Nek7', 'Protein kinase which plays an important role in mitotic cell cycle progression (PubMed:17101132, PubMed:31409757, PubMed:19941817). Required for microtubule nucleation activity of the centrosome, robust mitotic spindle formation and cytokinesis (PubMed:17586473, PubMed:19414596, PubMed:31409757, PubMed:19941817, PubMed:26522158). Phosphorylates EML4 at ''Ser-146'', promoting its dissociation from microtubules during mitosis which is required for efficient chromosome congression (PubMed:31409757). Phosphorylates RPS6KB1 (By similarity). Acts as an essential activator of the NLRP3 inflammasome assembly independently of its kinase activity (PubMed:26642356, PubMed:36442502). Acts by unlocking NLRP3 following NLRP3 tranlocation into the microtubule organizing center (MTOC), relieving NLRP3 autoinhibition and promoting formation of the NLRP3:PYCARD complex, and activation of CASP1 (PubMed:26642356, PubMed:31189953, PubMed:36442502). Serves as a cellular switch that enforces mutual exclusivity of the inflammasome response and cell division: interaction with NEK9 prevents interaction with NLRP3 and activation of the inflammasome during mitosis (PubMed:26642356, PubMed:31189953).', 'NEK7', 'Homo sapiens', '{[''2.7.11.34'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Kinase, Magnesium, Metal-binding, Microtubule, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (568, '6G6W', '', 'Phosphatidylinositol 4,5-bisphosphate 3-kinase catalytic subunit delta isoform', 'Phosphoinositide-3-kinase (PI3K) phosphorylates phosphatidylinositol (PI) and its phosphorylated derivatives at position 3 of the inositol ring to produce 3-phosphoinositides (PubMed:9235916). Uses ATP and PtdIns(4,5)P2 (phosphatidylinositol 4,5-bisphosphate) to generate phosphatidylinositol 3,4,5-trisphosphate (PIP3) (PubMed:15135396). PIP3 plays a key role by recruiting PH domain-containing proteins to the membrane, including AKT1 and PDPK1, activating signaling cascades involved in cell growth, survival, proliferation, motility and morphology. Mediates immune responses. Plays a role in B-cell development, proliferation, migration, and function. Required for B-cell receptor (BCR) signaling. Mediates B-cell proliferation response to anti-IgM, anti-CD40 and IL4 stimulation. Promotes cytokine production in response to TLR4 and TLR9. Required for antibody class switch mediated by TLR9. Involved in the antigen presentation function of B-cells. Involved in B-cell chemotaxis in response to CXCL13 and sphingosine 1-phosphate (S1P). Required for proliferation, signaling and cytokine production of naive, effector and memory T-cells. Required for T-cell receptor (TCR) signaling. Mediates TCR signaling events at the immune synapse. Activation by TCR leads to antigen-dependent memory T-cell migration and retention to antigenic tissues. Together with PIK3CG participates in T-cell development. Contributes to T-helper cell expansion and differentiation. Required for T-cell migration mediated by homing receptors SELL/CD62L, CCR7 and S1PR1 and antigen dependent recruitment of T-cells. Together with PIK3CG is involved in natural killer (NK) cell development and migration towards the sites of inflammation. Participates in NK cell receptor activation. Plays a role in NK cell maturation and cytokine production. Together with PIK3CG is involved in neutrophil chemotaxis and extravasation. Together with PIK3CG participates in neutrophil respiratory burst. Plays important roles in mast-cell development and mast cell mediated allergic response. Involved in stem cell factor (SCF)-mediated proliferation, adhesion and migration. Required for allergen-IgE-induced degranulation and cytokine release. The lipid kinase activity is required for its biological function. Isoform 2 may be involved in stabilizing total RAS levels, resulting in increased ERK phosphorylation and increased PI3K activity.', 'PIK3CD', 'Homo sapiens', '{[''2.7.1.153'',''2.7.1.137'']}', '3D-structure, Adaptive immunity, Alternative splicing, ATP-binding, Chemotaxis, Cytoplasm, Differentiation, Direct protein sequencing, Disease variant, Immunity, Inflammatory response, Innate immunity, Kinase, Lipid metabolism, Nucleotide-binding, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (569, '3TKU', '', 'Serine/threonine-protein kinase MRCK beta', 'Serine/threonine-protein kinase which is an important downstream effector of CDC42 and plays a role in the regulation of cytoskeleton reorganization and cell migration. Regulates actin cytoskeletal reorganization via phosphorylation of PPP1R12C and MYL9/MLC2 (PubMed:21457715, PubMed:21949762). In concert with MYO18A and LURAP1, is involved in modulating lamellar actomyosin retrograde flow that is crucial to cell protrusion and migration (PubMed:18854160). Phosphorylates PPP1R12A (PubMed:21457715). In concert with FAM89B/LRAP25 mediates the targeting of LIMK1 to the lamellipodium resulting in its activation and subsequent phosphorylation of CFL1 which is important for lamellipodial F-actin regulation (By similarity).', 'CDC42BPB', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell junction, Cell membrane, Cell projection, Coiled coil, Cytoplasm, Disease variant, Intellectual disability, Kinase, Magnesium, Membrane, Metal-binding, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (570, '8C2Z', '', 'Dual specificity tyrosine-phosphorylation-regulated kinase 1B', 'Dual-specificity kinase which possesses both serine/threonine and tyrosine kinase activities. Plays an essential role in ribosomal DNA (rDNA) double-strand break repair and rDNA copy number maintenance (PubMed:33469661). During DNA damage, mediates transcription silencing in part via phosphorylating and enforcing DSB accumulation of the histone methyltransferase EHMT2 (PubMed:32611815). Enhances the transcriptional activity of TCF1/HNF1A and FOXO1. Inhibits epithelial cell migration. Mediates colon carcinoma cell survival in mitogen-poor environments. Inhibits the SHH and WNT1 pathways, thereby enhancing adipogenesis. In addition, promotes expression of the gluconeogenic enzyme glucose-6-phosphatase catalytic subunit 1 (G6PC1).', 'DYRK1B', 'Homo sapiens', '{[''2.7.12.1'']}', 'Alternative splicing, ATP-binding, Chromosome, Diabetes mellitus, DNA damage, DNA repair, Kinase, Nucleotide-binding, Nucleus, Obesity, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (571, '5VDK', '', 'Wee1-like protein kinase 2', 'Oocyte-specific protein tyrosine kinase that phosphorylates and inhibits CDK1/CDC2 and acts as a key regulator of meiosis during both prophase I and metaphase II (PubMed:29606300). Required to maintain meiotic arrest in oocytes during the germinal vesicle (GV) stage, a long period of quiescence at dictyate prophase I, by phosphorylating CDK1 at ''Tyr-15'', leading to inhibit CDK1 activity and prevent meiotic reentry. Also required for metaphase II exit during egg activation by phosphorylating CDK1 at ''Tyr-15'', to ensure exit from meiosis in oocytes and promote pronuclear formation (By similarity).', 'WEE2', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, ATP-binding, Coiled coil, Disease variant, Kinase, Magnesium, Meiosis, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (572, '4DC2', '', 'Protein kinase C iota type', 'Calcium- and diacylglycerol-independent serine/ threonine-protein kinase that plays a general protective role against apoptotic stimuli, is involved in NF-kappa-B activation, cell survival, differentiation and polarity, and contributes to the regulation of microtubule dynamics in the early secretory pathway. Is necessary for BCR-ABL oncogene-mediated resistance to apoptotic drug in leukemia cells, protecting leukemia cells against drug-induced apoptosis. In cultured neurons, prevents amyloid beta protein-induced apoptosis by interrupting cell death process at a very early step. In glioblastoma cells, may function downstream of phosphatidylinositol 3-kinase (PI3K) and PDPK1 in the promotion of cell survival by phosphorylating and inhibiting the pro-apoptotic factor BAD. Can form a protein complex in non-small cell lung cancer (NSCLC) cells with PARD6A and ECT2 and regulate ECT2 oncogenic activity by phosphorylation, which in turn promotes transformed growth and invasion. In response to nerve growth factor (NGF), acts downstream of SRC to phosphorylate and activate IRAK1, allowing the subsequent activation of NF-kappa-B and neuronal cell survival. Functions in the organization of the apical domain in epithelial cells by phosphorylating EZR. This step is crucial for activation and normal distribution of EZR at the early stages of intestinal epithelial cell differentiation. Forms a protein complex with LLGL1 and PARD6B independently of PARD3 to regulate epithelial cell polarity. Plays a role in microtubule dynamics in the early secretory pathway through interaction with RAB2A and GAPDH and recruitment to vesicular tubular clusters (VTCs). In human coronary artery endothelial cells (HCAEC), is activated by saturated fatty acids and mediates lipid-induced apoptosis (By similarity). Downstream of PI3K is required for insulin-stimulated glucose transport. Activates RAB4A and promotes its association with KIF3A which is required for the insulin-induced SLC2A4/GLUT4 translocation in adipocytes. Is essential in early embryogenesis and development of differentiating photoreceptors by playing a role in the establishment of epithelial and neuronal polarity. Involved in early synaptic long term potentiation phase in CA1 hippocampal cells and short term memory formation (By similarity).', 'Prkci', 'Mus musculus', '{[''2.7.11.13'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Developmental protein, Endosome, Kinase, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Tumor suppressor, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (573, '4FR4', '', 'Serine/threonine-protein kinase 32A', 'Unknown', 'STK32A', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Kinase, Lipoprotein, Magnesium, Membrane, Metal-binding, Myristate, Nucleotide-binding, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (575, '1QCF', '', 'Tyrosine-protein kinase HCK', 'Non-receptor tyrosine-protein kinase found in hematopoietic cells that transmits signals from cell surface receptors and plays an important role in the regulation of innate immune responses, including neutrophil, monocyte, macrophage and mast cell functions, phagocytosis, cell survival and proliferation, cell adhesion and migration. Acts downstream of receptors that bind the Fc region of immunoglobulins, such as FCGR1A and FCGR2A, but also CSF3R, PLAUR, the receptors for IFNG, IL2, IL6 and IL8, and integrins, such as ITGB1 and ITGB2. During the phagocytic process, mediates mobilization of secretory lysosomes, degranulation, and activation of NADPH oxidase to bring about the respiratory burst. Plays a role in the release of inflammatory molecules. Promotes reorganization of the actin cytoskeleton and actin polymerization, formation of podosomes and cell protrusions. Inhibits TP73-mediated transcription activation and TP73-mediated apoptosis. Phosphorylates CBL in response to activation of immunoglobulin gamma Fc region receptors. Phosphorylates ADAM15, BCR, ELMO1, FCGR2A, GAB1, GAB2, RAPGEF1, STAT5B, TP73, VAV1 and WAS.', 'HCK', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative initiation, Alternative splicing, ATP-binding, Cell junction, Cell membrane, Cell projection, Cytoplasm, Cytoplasmic vesicle, Cytoskeleton, Exocytosis, Golgi apparatus, Host-virus interaction, Immunity, Inflammatory response, Innate immunity, Kinase, Lipoprotein, Lysosome, Membrane, Myristate, Nucleotide-binding, Nucleus, Palmitate, Phagocytosis, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (576, '6TM5', '', 'Anaphase-promoting complex subunit 1', 'Component of the anaphase promoting complex/cyclosome (APC/C), a cell cycle-regulated E3 ubiquitin ligase that controls progression through mitosis and the G1 phase of the cell cycle. The APC/C complex acts by mediating ubiquitination and subsequent degradation of target proteins: it mainly mediates the formation of ''Lys-11''-linked polyubiquitin chains and, to a lower extent, the formation of ''Lys-48''- and ''Lys-63''-linked polyubiquitin chains.', 'ANAPC1', 'Homo sapiens', '{[]}', '3D-structure, Cell cycle, Cell division, Ectodermal dysplasia, Hypotrichosis, Mitosis, Phosphoprotein, Reference proteome, Repeat, Ubl conjugation pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (577, '2F57', '', 'Serine/threonine-protein kinase PAK 5', 'Serine/threonine protein kinase that plays a role in a variety of different signaling pathways including cytoskeleton regulation, cell migration, proliferation or cell survival. Activation by various effectors including growth factor receptors or active CDC42 and RAC1 results in a conformational change and a subsequent autophosphorylation on several serine and/or threonine residues. Phosphorylates the proto-oncogene RAF1 and stimulates its kinase activity. Promotes cell survival by phosphorylating the BCL2 antagonist of cell death BAD. Phosphorylates CTNND1, probably to regulate cytoskeletal organization and cell morphology. Keeps microtubules stable through MARK2 inhibition and destabilizes the F-actin network leading to the disappearance of stress fibers and focal adhesions.', 'PAK5', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Apoptosis, ATP-binding, Cytoplasm, Kinase, Mitochondrion, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (578, '6BDN', '', 'Serine/threonine-protein kinase TAO3', 'Serine/threonine-protein kinase that acts as a regulator of the p38/MAPK14 stress-activated MAPK cascade and of the MAPK8/JNK cascade. Acts as an activator of the p38/MAPK14 stress-activated MAPK cascade. In response to DNA damage, involved in the G2/M transition DNA damage checkpoint by activating the p38/MAPK14 stress-activated MAPK cascade, probably by mediating phosphorylation of upstream MAP2K3 and MAP2K6 kinases. Inhibits basal activity of MAPK8/JNK cascade and diminishes its activation in response epidermal growth factor (EGF).', 'TAOK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cell membrane, Coiled coil, Cytoplasm, DNA damage, DNA repair, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (579, '2R7B', '', '3-phosphoinositide-dependent protein kinase 1', 'Serine/threonine kinase which acts as a master kinase, phosphorylating and activating a subgroup of the AGC family of protein kinases. Its targets include: protein kinase B (PKB/AKT1, PKB/AKT2, PKB/AKT3), p70 ribosomal protein S6 kinase (RPS6KB1), p90 ribosomal protein S6 kinase (RPS6KA1, RPS6KA2 and RPS6KA3), cyclic AMP-dependent protein kinase (PRKACA), protein kinase C (PRKCD and PRKCZ), serum and glucocorticoid-inducible kinase (SGK1, SGK2 and SGK3), p21-activated kinase-1 (PAK1), protein kinase PKN (PKN1 and PKN2). Plays a central role in the transduction of signals from insulin by providing the activating phosphorylation to PKB/AKT1, thus propagating the signal to downstream targets controlling cell proliferation and survival, as well as glucose and amino acid uptake and storage. Negatively regulates the TGF-beta-induced signaling by: modulating the association of SMAD3 and SMAD7 with TGF-beta receptor, phosphorylating SMAD2, SMAD3, SMAD4 and SMAD7, preventing the nuclear translocation of SMAD3 and SMAD4 and the translocation of SMAD7 from the nucleus to the cytoplasm in response to TGF-beta. Activates PPARG transcriptional activity and promotes adipocyte differentiation. Activates the NF-kappa-B pathway via phosphorylation of IKKB. The tyrosine phosphorylated form is crucial for the regulation of focal adhesions by angiotensin II. Controls proliferation, survival, and growth of developing pancreatic cells. Participates in the regulation of Ca(2+) entry and Ca(2+)-activated K(+) channels of mast cells. Essential for the motility of vascular endothelial cells (ECs) and is involved in the regulation of their chemotaxis. Plays a critical role in cardiac homeostasis by serving as a dual effector for cell survival and beta-adrenergic response. Plays an important role during thymocyte development by regulating the expression of key nutrient receptors on the surface of pre-T cells and mediating Notch-induced cell growth and proliferative responses. Provides negative feedback inhibition to toll-like receptor-mediated NF-kappa-B activation in macrophages. Isoform 3 is catalytically inactive.', 'PDPK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Activator, Alternative splicing, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Direct protein sequencing, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (580, '2WQB', '', 'Angiopoietin-1 receptor', 'Tyrosine-protein kinase that acts as a cell-surface receptor for ANGPT1, ANGPT2 and ANGPT4 and regulates angiogenesis, endothelial cell survival, proliferation, migration, adhesion and cell spreading, reorganization of the actin cytoskeleton, but also maintenance of vascular quiescence. Has anti-inflammatory effects by preventing the leakage of pro-inflammatory plasma proteins and leukocytes from blood vessels. Required for normal angiogenesis and heart development during embryogenesis. Required for post-natal hematopoiesis. After birth, activates or inhibits angiogenesis, depending on the context. Inhibits angiogenesis and promotes vascular stability in quiescent vessels, where endothelial cells have tight contacts. In quiescent vessels, ANGPT1 oligomers recruit TEK to cell-cell contacts, forming complexes with TEK molecules from adjoining cells, and this leads to preferential activation of phosphatidylinositol 3-kinase and the AKT1 signaling cascades. In migrating endothelial cells that lack cell-cell adhesions, ANGT1 recruits TEK to contacts with the extracellular matrix, leading to the formation of focal adhesion complexes, activation of PTK2/FAK and of the downstream kinases MAPK1/ERK2 and MAPK3/ERK1, and ultimately to the stimulation of sprouting angiogenesis. ANGPT1 signaling triggers receptor dimerization and autophosphorylation at specific tyrosine residues that then serve as binding sites for scaffold proteins and effectors. Signaling is modulated by ANGPT2 that has lower affinity for TEK, can promote TEK autophosphorylation in the absence of ANGPT1, but inhibits ANGPT1-mediated signaling by competing for the same binding site. Signaling is also modulated by formation of heterodimers with TIE1, and by proteolytic processing that gives rise to a soluble TEK extracellular domain. The soluble extracellular domain modulates signaling by functioning as decoy receptor for angiopoietins. TEK phosphorylates DOK2, GRB7, GRB14, PIK3R1; SHC1 and TIE1.', 'TEK', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Cytoskeleton, Direct protein sequencing, Disease variant, Disulfide bond, EGF-like domain, Glaucoma, Glycoprotein, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (581, '4RER', '', '5''-AMP-activated protein kinase catalytic subunit alpha-1', 'Catalytic subunit of AMP-activated protein kinase (AMPK), an energy sensor protein kinase that plays a key role in regulating cellular energy metabolism (PubMed:17307971, PubMed:17712357, PubMed:24563466, PubMed:37821951). In response to reduction of intracellular ATP levels, AMPK activates energy-producing pathways and inhibits energy-consuming processes: inhibits protein, carbohydrate and lipid biosynthesis, as well as cell growth and proliferation (PubMed:17307971, PubMed:17712357). AMPK acts via direct phosphorylation of metabolic enzymes, and by longer-term effects via phosphorylation of transcription regulators (PubMed:17307971, PubMed:17712357). Regulates lipid synthesis by phosphorylating and inactivating lipid metabolic enzymes such as ACACA, ACACB, GYS1, HMGCR and LIPE; regulates fatty acid and cholesterol synthesis by phosphorylating acetyl-CoA carboxylase (ACACA and ACACB) and hormone-sensitive lipase (LIPE) enzymes, respectively (By similarity). Promotes lipolysis of lipid droplets by mediating phosphorylation of isoform 1 of CHKA (CHKalpha2) (PubMed:34077757). Regulates insulin-signaling and glycolysis by phosphorylating IRS1, PFKFB2 and PFKFB3 (By similarity). AMPK stimulates glucose uptake in muscle by increasing the translocation of the glucose transporter SLC2A4/GLUT4 to the plasma membrane, possibly by mediating phosphorylation of TBC1D4/AS160 (By similarity). Regulates transcription and chromatin structure by phosphorylating transcription regulators involved in energy metabolism such as CRTC2/TORC2, FOXO3, histone H2B, HDAC5, MEF2C, MLXIPL/ChREBP, EP300, HNF4A, p53/TP53, SREBF1, SREBF2 and PPARGC1A (PubMed:11554766, PubMed:11518699, PubMed:15866171, PubMed:17711846, PubMed:18184930). Acts as a key regulator of glucose homeostasis in liver by phosphorylating CRTC2/TORC2, leading to CRTC2/TORC2 sequestration in the cytoplasm (By similarity). In response to stress, phosphorylates ''Ser-36'' of histone H2B (H2BS36ph), leading to promote transcription (By similarity). Acts as a key regulator of cell growth and proliferation by phosphorylating FNIP1, TSC2, RPTOR, WDR24 and ATG1/ULK1: in response to nutrient limitation, negatively regulates the mTORC1 complex by phosphorylating RPTOR component of the mTORC1 complex and by phosphorylating and activating TSC2 (PubMed:14651849, PubMed:18439900, PubMed:20160076, PubMed:21205641). Also phosphorylates and inhibits GATOR2 subunit WDR24 in response to nutrient limitation, leading to suppress glucose-mediated mTORC1 activation (PubMed:36732624). In response to energetic stress, phosphorylates FNIP1, inactivating the non-canonical mTORC1 signaling, thereby promoting nuclear translocation of TFEB and TFE3, and inducing transcription of lysosomal or autophagy genes (PubMed:37079666). In response to nutrient limitation, promotes autophagy by phosphorylating and activating ATG1/ULK1 (PubMed:21205641). In that process also activates WDR45/WIPI4 (PubMed:28561066). Phosphorylates CASP6, thereby preventing its autoprocessing and subsequent activation (PubMed:32029622). In response to nutrient limitation, phosphorylates transcription factor FOXO3 promoting FOXO3 mitochondrial import (By similarity). Also acts as a regulator of cellular polarity by remodeling the actin cytoskeleton; probably by indirectly activating myosin (PubMed:17486097). AMPK also acts as a regulator of circadian rhythm by mediating phosphorylation of CRY1, leading to destabilize it (By similarity). May regulate the Wnt signaling pathway by phosphorylating CTNNB1, leading to stabilize it (By similarity). Also has tau-protein kinase activity: in response to amyloid beta A4 protein (APP) exposure, activated by CAMKK2, leading to phosphorylation of MAPT/TAU; however the relevance of such data remains unclear in vivo (By similarity). Also phosphorylates CFTR, EEF2K, KLC1, NOS3 and SLC12A1 (PubMed:20074060, PubMed:12519745). Regulates hepatic lipogenesis. Activated via SIRT3, represses sterol regulatory element-binding protein (SREBP) transcriptional activities and ATP-consuming lipogenesis to restore cellular energy balance.', 'PRKAA1', 'Homo sapiens', '{[''2.7.11.31'',''2.7.11.1'',''2.7.11.26'']}', '3D-structure, Alternative splicing, ATP-binding, Autophagy, Biological rhythms, Cholesterol biosynthesis, Cholesterol metabolism, Chromatin regulator, Cytoplasm, Fatty acid biosynthesis, Fatty acid metabolism, Glycoprotein, Host-virus interaction, Kinase, Lipid biosynthesis, Lipid metabolism, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Steroid biosynthesis, Steroid metabolism, Sterol biosynthesis, Sterol metabolism, Transcription, Transcription regulation, Transferase, Ubl conjugation, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (582, '4XI2', '', 'Tyrosine-protein kinase BTK', 'Non-receptor tyrosine kinase indispensable for B lymphocyte development, differentiation and signaling (PubMed:7538439, PubMed:8629002, PubMed:10852954). Binding of antigen to the B-cell antigen receptor (BCR) triggers signaling that ultimately leads to B-cell activation (By similarity). After BCR engagement and activation at the plasma membrane, phosphorylates PLCG2 at several sites, igniting the downstream signaling pathway through calcium mobilization, followed by activation of the protein kinase C (PKC) family members (By similarity). PLCG2 phosphorylation is performed in close cooperation with the adapter protein B-cell linker protein BLNK (By similarity). BTK acts as a platform to bring together a diverse array of signaling proteins and is implicated in cytokine receptor signaling pathways (By similarity). Plays an important role in the function of immune cells of innate as well as adaptive immunity, as a component of the Toll-like receptors (TLR) pathway (PubMed:17725607). The TLR pathway acts as a primary surveillance system for the detection of pathogens and are crucial to the activation of host defense (By similarity). Especially, is a critical molecule in regulating TLR9 activation in splenic B-cells (By similarity). Within the TLR pathway, induces tyrosine phosphorylation of TIRAP which leads to TIRAP degradation (By similarity). BTK also plays a critical role in transcription regulation (By similarity). Induces the activity of NF-kappa-B, which is involved in regulating the expression of hundreds of genes (By similarity). BTK is involved on the signaling pathway linking TLR8 and TLR9 to NF-kappa-B (By similarity). Acts as an activator of NLRP3 inflammasome assembly by mediating phosphorylation of NLRP3 (PubMed:34554188). Transiently phosphorylates transcription factor GTF2I on tyrosine residues in response to BCR (PubMed:11120822, PubMed:16738337). GTF2I then translocates to the nucleus to bind regulatory enhancer elements to modulate gene expression (PubMed:11120822, PubMed:16738337). ARID3A and NFAT are other transcriptional target of BTK (PubMed:11120822, PubMed:16738337). BTK is required for the formation of functional ARID3A DNA-binding complexes (PubMed:11120822, PubMed:16738337). There is however no evidence that BTK itself binds directly to DNA (PubMed:11120822, PubMed:16738337). BTK has a dual role in the regulation of apoptosis (By similarity).', 'Btk', 'Mus musculus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Adaptive immunity, Apoptosis, ATP-binding, Cell membrane, Cytoplasm, Direct protein sequencing, Disease variant, Immunity, Innate immunity, Kinase, Lipid-binding, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, SH2 domain, SH3 domain, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (583, '6T41', '', 'Cyclin-dependent kinase 8', 'Component of the Mediator complex, a coactivator involved in regulated gene transcription of nearly all RNA polymerase II-dependent genes. Mediator functions as a bridge to convey information from gene-specific regulatory proteins to the basal RNA polymerase II transcription machinery. Mediator is recruited to promoters by direct interactions with regulatory proteins and serves as a scaffold for the assembly of a functional pre-initiation complex with RNA polymerase II and the general transcription factors. Phosphorylates the CTD (C-terminal domain) of the large subunit of RNA polymerase II (RNAp II), which may inhibit the formation of a transcription initiation complex. Phosphorylates CCNH leading to down-regulation of the TFIIH complex and transcriptional repression. Recruited through interaction with MAML1 to hyperphosphorylate the intracellular domain of NOTCH, leading to its degradation.', 'CDK8', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Activator, Alternative splicing, ATP-binding, Autism spectrum disorder, Disease variant, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Reference proteome, Repressor, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (584, '6V6A', '', 'Mitogen-activated protein kinase', 'Unknown', 'MAPK2', 'Toxoplasma gondii', '{[''2.7.11.24'']}', '3D-structure, ATP-binding, Kinase, Magnesium, Nucleotide-binding, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (585, '2BUJ', '', 'Serine/threonine-protein kinase 16', 'Membrane-associated protein kinase that phosphorylates on serine and threonine residues. In vitro substrates include DRG1, ENO1 and EIF4EBP1. Also autophosphorylates. May be involved in secretory vesicle trafficking or intracellular signaling. May have a role in regulating stromal-epithelial interactions that occur during ductal morphogenesis in the mammary gland. May be involved in TGF-beta signaling. Able to autophosphorylate on Tyr residue; it is however unclear whether it has tyrosine-protein kinase toward other proteins.', 'STK16', 'Homo sapiens', '{[''2.7.10.2'',''2.7.11.1'']}', '3D-structure, ATP-binding, Cytoplasm, Kinase, Lipoprotein, Membrane, Myristate, Nucleotide-binding, Palmitate, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (586, '7MGJ', '', 'Serine/threonine-protein kinase TNNI3K', 'May play a role in cardiac physiology.', 'TNNI3K', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ANK repeat, ATP-binding, Cardiomyopathy, Coiled coil, Cytoplasm, Disease variant, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (587, '5FQD', '', 'DNA damage-binding protein 1', 'Protein, which is both involved in DNA repair and protein ubiquitination, as part of the UV-DDB complex and DCX (DDB1-CUL4-X-box) complexes, respectively (PubMed:15448697, PubMed:14739464, PubMed:16260596, PubMed:16482215, PubMed:17079684, PubMed:16407242, PubMed:16407252, PubMed:16940174). Core component of the UV-DDB complex (UV-damaged DNA-binding protein complex), a complex that recognizes UV-induced DNA damage and recruit proteins of the nucleotide excision repair pathway (the NER pathway) to initiate DNA repair (PubMed:15448697, PubMed:16260596, PubMed:16407242, PubMed:16940174). The UV-DDB complex preferentially binds to cyclobutane pyrimidine dimers (CPD), 6-4 photoproducts (6-4 PP), apurinic sites and short mismatches (PubMed:15448697, PubMed:16260596, PubMed:16407242, PubMed:16940174). Also functions as a component of numerous distinct DCX (DDB1-CUL4-X-box) E3 ubiquitin-protein ligase complexes which mediate the ubiquitination and subsequent proteasomal degradation of target proteins (PubMed:14739464, PubMed:16407252, PubMed:16482215, PubMed:17079684, PubMed:25043012, PubMed:25108355, PubMed:18332868, PubMed:18381890, PubMed:19966799, PubMed:22118460, PubMed:28886238). The functional specificity of the DCX E3 ubiquitin-protein ligase complex is determined by the variable substrate recognition component recruited by DDB1 (PubMed:14739464, PubMed:16407252, PubMed:16482215, PubMed:17079684, PubMed:25043012, PubMed:25108355, PubMed:18332868, PubMed:18381890, PubMed:19966799, PubMed:22118460). DCX(DDB2) (also known as DDB1-CUL4-ROC1, CUL4-DDB-ROC1 and CUL4-DDB-RBX1) may ubiquitinate histone H2A, histone H3 and histone H4 at sites of UV-induced DNA damage (PubMed:16678110, PubMed:17041588, PubMed:16473935, PubMed:18593899). The ubiquitination of histones may facilitate their removal from the nucleosome and promote subsequent DNA repair (PubMed:16678110, PubMed:17041588, PubMed:16473935, PubMed:18593899). DCX(DDB2) also ubiquitinates XPC, which may enhance DNA-binding by XPC and promote NER (PubMed:15882621). DCX(DTL) plays a role in PCNA-dependent polyubiquitination of CDT1 and MDM2-dependent ubiquitination of TP53 in response to radiation-induced DNA damage and during DNA replication (PubMed:17041588). DCX(ERCC8) (the CSA complex) plays a role in transcription-coupled repair (TCR) (PubMed:12732143). The DDB1-CUL4A-DTL E3 ligase complex regulates the circadian clock function by mediating the ubiquitination and degradation of CRY1 (PubMed:26431207). DDB1-mediated CRY1 degradation promotes FOXO1 protein stability and FOXO1-mediated gluconeogenesis in the liver (By similarity). By acting on TET dioxygenses, essential for oocyte maintenance at the primordial follicle stage, hence essential for female fertility (By similarity). Maternal factor required for proper zygotic genome activation and genome reprogramming (By similarity).', 'DDB1', 'Homo sapiens', '{[]}', '3D-structure, Acetylation, Alternative splicing, Biological rhythms, Cytoplasm, Disease variant, DNA damage, DNA repair, DNA-binding, Host-virus interaction, Intellectual disability, Isopeptide bond, Nucleus, Phosphoprotein, Reference proteome, Repeat, Ubl conjugation, Ubl conjugation pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (588, '1MRU', '', 'Serine/threonine-protein kinase PknB', 'Protein kinase that regulates many aspects of mycobacterial physiology, and is critical for growth in vitro and survival of the pathogen in the host (PubMed:24706757). Is a key component of a signal transduction pathway that regulates cell growth, cell shape and cell division via phosphorylation of target proteins such as GarA, GlmU, PapA5, FhaB (Rv0019c), FhaA (Rv0020c), MviN, PstP, EmbR, Rv1422, Rv1747, RseA and RmlA (PubMed:15978616, PubMed:15985609, PubMed:15987910, PubMed:16817899, PubMed:16980473, PubMed:19121323, PubMed:19826007, PubMed:20025669, PubMed:21423706, PubMed:22275220, PubMed:33868202). Also catalyzes the phosphorylation of the core proteasome alpha-subunit (PrcA), and thereby regulates the proteolytic activity of the proteasome (PubMed:25224505). Is a major regulator of the oxygen-dependent replication switch since PknB activity is necessary for reactivation of cells from the hypoxic state (PubMed:24409094). Shows a strong preference for Thr versus Ser as the phosphoacceptor. Overexpression of PknB alters cell morphology and leads to cell death (PubMed:24706757) (PubMed:24409094).', 'pknB', 'Mycobacterium tuberculosis (strain ATCC 25618 / H37Rv)', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Cell membrane, Direct protein sequencing, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix, Virulence');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (589, '4YOM', '', 'Serine/threonine-protein kinase BRSK2', 'Serine/threonine-protein kinase that plays a key role in polarization of neurons and axonogenesis, cell cycle progress and insulin secretion. Phosphorylates CDK16, CDC25C, MAPT/TAU, PAK1 and WEE1. Following phosphorylation and activation by STK11/LKB1, acts as a key regulator of polarization of cortical neurons, probably by mediating phosphorylation of microtubule-associated proteins such as MAPT/TAU at ''Thr-504'' and ''Ser-554''. Also regulates neuron polarization by mediating phosphorylation of WEE1 at ''Ser-642'' in post-mitotic neurons, leading to down-regulate WEE1 activity in polarized neurons. Plays a role in the regulation of the mitotic cell cycle progress and the onset of mitosis. Plays a role in the regulation of insulin secretion in response to elevated glucose levels, probably via phosphorylation of CDK16 and PAK1. While BRSK2 phosphorylated at Thr-175 can inhibit insulin secretion (PubMed:22798068), BRSK2 phosphorylated at Thr-261 can promote insulin secretion (PubMed:22669945). Regulates reorganization of the actin cytoskeleton. May play a role in the apoptotic response triggered by endoplasmic reticulum (ER) stress.', 'Brsk2', 'Mus musculus', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell division, Cytoplasm, Cytoskeleton, Endoplasmic reticulum, Exocytosis, Kinase, Magnesium, Metal-binding, Mitosis, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (590, '2IWI', '', 'Serine/threonine-protein kinase pim-2', 'Proto-oncogene with serine/threonine kinase activity involved in cell survival and cell proliferation. Exerts its oncogenic activity through: the regulation of MYC transcriptional activity, the regulation of cell cycle progression, the regulation of cap-dependent protein translation and through survival signaling by phosphorylation of a pro-apoptotic protein, BAD. Phosphorylation of MYC leads to an increase of MYC protein stability and thereby an increase transcriptional activity. The stabilization of MYC exerted by PIM2 might explain partly the strong synergism between these 2 oncogenes in tumorigenesis. Regulates cap-dependent protein translation in a mammalian target of rapamycin complex 1 (mTORC1)-independent manner and in parallel to the PI3K-Akt pathway. Mediates survival signaling through phosphorylation of BAD, which induces release of the anti-apoptotic protein Bcl-X(L)/BCL2L1. Promotes cell survival in response to a variety of proliferative signals via positive regulation of the I-kappa-B kinase/NF-kappa-B cascade; this process requires phosphorylation of MAP3K8/COT. Promotes growth factor-independent proliferation by phosphorylation of cell cycle factors such as CDKN1A and CDKN1B. Involved in the positive regulation of chondrocyte survival and autophagy in the epiphyseal growth plate.', 'PIM2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Apoptosis, ATP-binding, Cell cycle, Kinase, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (591, '3K2L', '', 'Dual specificity tyrosine-phosphorylation-regulated kinase 2', 'Serine/threonine-protein kinase involved in the regulation of the mitotic cell cycle, cell proliferation, apoptosis, organization of the cytoskeleton and neurite outgrowth. Functions in part via its role in ubiquitin-dependent proteasomal protein degradation. Functions downstream of ATM and phosphorylates p53/TP53 at ''Ser-46'', and thereby contributes to the induction of apoptosis in response to DNA damage. Phosphorylates NFATC1, and thereby inhibits its accumulation in the nucleus and its transcription factor activity. Phosphorylates EIF2B5 at ''Ser-544'', enabling its subsequent phosphorylation and inhibition by GSK3B. Likewise, phosphorylation of NFATC1, CRMP2/DPYSL2 and CRMP4/DPYSL3 promotes their subsequent phosphorylation by GSK3B. May play a general role in the priming of GSK3 substrates. Inactivates GYS1 by phosphorylation at ''Ser-641'', and potentially also a second phosphorylation site, thus regulating glycogen synthesis. Mediates EDVP E3 ligase complex formation and is required for the phosphorylation and subsequent degradation of KATNA1. Phosphorylates TERT at ''Ser-457'', promoting TERT ubiquitination by the EDVP complex. Phosphorylates SIAH2, and thereby increases its ubiquitin ligase activity. Promotes the proteasomal degradation of MYC and JUN, and thereby regulates progress through the mitotic cell cycle and cell proliferation. Promotes proteasomal degradation of GLI2 and GLI3, and thereby plays a role in smoothened and sonic hedgehog signaling. Plays a role in cytoskeleton organization and neurite outgrowth via its phosphorylation of DCX and DPYSL2. Phosphorylates CRMP2/DPYSL2, CRMP4/DPYSL3, DCX, EIF2B5, EIF4EBP1, GLI2, GLI3, GYS1, JUN, MDM2, MYC, NFATC1, p53/TP53, TAU/MAPT and KATNA1. Can phosphorylate histone H1, histone H3 and histone H2B (in vitro). Can phosphorylate CARHSP1 (in vitro).', 'DYRK2', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Kinase, Magnesium, Manganese, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase, Ubl conjugation, Ubl conjugation pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (592, '3VN9', '', 'Dual specificity mitogen-activated protein kinase kinase 6', 'Dual specificity protein kinase which acts as an essential component of the MAP kinase signal transduction pathway. With MAP3K3/MKK3, catalyzes the concomitant phosphorylation of a threonine and a tyrosine residue in the MAP kinases p38 MAPK11, MAPK12, MAPK13 and MAPK14 and plays an important role in the regulation of cellular responses to cytokines and all kinds of stresses. Especially, MAP2K3/MKK3 and MAP2K6/MKK6 are both essential for the activation of MAPK11 and MAPK13 induced by environmental stress, whereas MAP2K6/MKK6 is the major MAPK11 activator in response to TNF. MAP2K6/MKK6 also phosphorylates and activates PAK6. The p38 MAP kinase signal transduction pathway leads to direct activation of transcription factors. Nuclear targets of p38 MAP kinase include the transcription factors ATF2 and ELK1. Within the p38 MAPK signal transduction pathway, MAP3K6/MKK6 mediates phosphorylation of STAT4 through MAPK14 activation, and is therefore required for STAT4 activation and STAT4-regulated gene expression in response to IL-12 stimulation. The pathway is also crucial for IL-6-induced SOCS3 expression and down-regulation of IL-6-mediated gene induction; and for IFNG-dependent gene transcription. Has a role in osteoclast differentiation through NF-kappa-B transactivation by TNFSF11, and in endochondral ossification and since SOX9 is another likely downstream target of the p38 MAPK pathway. MAP2K6/MKK6 mediates apoptotic cell death in thymocytes. Acts also as a regulator for melanocytes dendricity, through the modulation of Rho family GTPases.', 'MAP2K6', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Cytoskeleton, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (593, '6KHE', '', 'Dual specificity protein kinase CLK2', 'Dual specificity kinase acting on both serine/threonine and tyrosine-containing substrates. Phosphorylates serine- and arginine-rich (SR) proteins of the spliceosomal complex. May be a constituent of a network of regulatory mechanisms that enable SR proteins to control RNA splicing and can cause redistribution of SR proteins from speckles to a diffuse nucleoplasmic distribution. Acts as a suppressor of hepatic gluconeogenesis and glucose output by repressing PPARGC1A transcriptional activity on gluconeogenic genes via its phosphorylation. Phosphorylates PPP2R5B thereby stimulating the assembly of PP2A phosphatase with the PPP2R5B-AKT1 complex leading to dephosphorylation of AKT1. Phosphorylates: PTPN1, SRSF1 and SRSF3. Regulates the alternative splicing of tissue factor (F3) pre-mRNA in endothelial cells. Phosphorylates PAGE4 at several serine and threonine residues and this phosphorylation attenuates the ability of PAGE4 to potentiate the transcriptional activator activity of JUN (PubMed:28289210).', 'CLK2', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (594, '5YKS', '', 'SNF-related serine/threonine-protein kinase', 'May play a role in hematopoietic cell proliferation or differentiation. Potential mediator of neuronal apoptosis.', 'SNRK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Magnesium, Metal-binding, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (595, '4YNZ', '', 'Serine/threonine-protein kinase BRSK2', 'Serine/threonine-protein kinase that plays a key role in polarization of neurons and axonogenesis, cell cycle progress and insulin secretion. Phosphorylates CDK16, CDC25C, MAPT/TAU, PAK1 and WEE1. Following phosphorylation and activation by STK11/LKB1, acts as a key regulator of polarization of cortical neurons, probably by mediating phosphorylation of microtubule-associated proteins such as MAPT/TAU at ''Thr-504'' and ''Ser-554''. Also regulates neuron polarization by mediating phosphorylation of WEE1 at ''Ser-642'' in post-mitotic neurons, leading to down-regulate WEE1 activity in polarized neurons. Plays a role in the regulation of the mitotic cell cycle progress and the onset of mitosis. Plays a role in the regulation of insulin secretion in response to elevated glucose levels, probably via phosphorylation of CDK16 and PAK1. While BRSK2 phosphorylated at Thr-175 can inhibit insulin secretion (PubMed:22798068), BRSK2 phosphorylated at Thr-261 can promote insulin secretion (PubMed:22669945). Regulates reorganization of the actin cytoskeleton. May play a role in the apoptotic response triggered by endoplasmic reticulum (ER) stress.', 'Brsk2', 'Mus musculus', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell division, Cytoplasm, Cytoskeleton, Endoplasmic reticulum, Exocytosis, Kinase, Magnesium, Metal-binding, Mitosis, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (596, '5HVJ', '', 'LIM domain kinase 1', 'Serine/threonine-protein kinase that plays an essential role in the regulation of actin filament dynamics. Acts downstream of several Rho family GTPase signal transduction pathways (PubMed:10436159, PubMed:11832213, PubMed:12807904, PubMed:15660133, PubMed:16230460, PubMed:18028908, PubMed:22328514, PubMed:23633677). Activated by upstream kinases including ROCK1, PAK1 and PAK4, which phosphorylate LIMK1 on a threonine residue located in its activation loop (PubMed:10436159). LIMK1 subsequently phosphorylates and inactivates the actin binding/depolymerizing factors cofilin-1/CFL1, cofilin-2/CFL2 and destrin/DSTN, thereby preventing the cleavage of filamentous actin (F-actin), and stabilizing the actin cytoskeleton (PubMed:11832213, PubMed:15660133, PubMed:16230460, PubMed:23633677). In this way LIMK1 regulates several actin-dependent biological processes including cell motility, cell cycle progression, and differentiation (PubMed:11832213, PubMed:15660133, PubMed:16230460, PubMed:23633677). Phosphorylates TPPP on serine residues, thereby promoting microtubule disassembly (PubMed:18028908). Stimulates axonal outgrowth and may be involved in brain development (PubMed:18028908).', 'LIMK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell projection, Cytoplasm, Cytoskeleton, Kinase, LIM domain, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Ubl conjugation, Williams-Beuren syndrome, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (597, '1KWP', '', 'MAP kinase-activated protein kinase 2', 'Stress-activated serine/threonine-protein kinase involved in cytokine production, endocytosis, reorganization of the cytoskeleton, cell migration, cell cycle control, chromatin remodeling, DNA damage response and transcriptional regulation. Following stress, it is phosphorylated and activated by MAP kinase p38-alpha/MAPK14, leading to phosphorylation of substrates. Phosphorylates serine in the peptide sequence, Hyd-X-R-X(2)-S, where Hyd is a large hydrophobic residue. Phosphorylates ALOX5, CDC25B, CDC25C, CEP131, ELAVL1, HNRNPA0, HSP27/HSPB1, KRT18, KRT20, LIMK1, LSP1, PABPC1, PARN, PDE4A, RCSD1, RPS6KA3, TAB3 and TTP/ZFP36. Phosphorylates HSF1; leading to the interaction with HSP90 proteins and inhibiting HSF1 homotrimerization, DNA-binding and transactivation activities (PubMed:16278218). Mediates phosphorylation of HSP27/HSPB1 in response to stress, leading to the dissociation of HSP27/HSPB1 from large small heat-shock protein (sHsps) oligomers and impairment of their chaperone activities and ability to protect against oxidative stress effectively. Involved in inflammatory response by regulating tumor necrosis factor (TNF) and IL6 production post-transcriptionally: acts by phosphorylating AU-rich elements (AREs)-binding proteins ELAVL1, HNRNPA0, PABPC1 and TTP/ZFP36, leading to the regulation of the stability and translation of TNF and IL6 mRNAs. Phosphorylation of TTP/ZFP36, a major post-transcriptional regulator of TNF, promotes its binding to 14-3-3 proteins and reduces its ARE mRNA affinity, leading to inhibition of dependent degradation of ARE-containing transcripts. Phosphorylates CEP131 in response to cellular stress induced by ultraviolet irradiation which promotes binding of CEP131 to 14-3-3 proteins and inhibits formation of novel centriolar satellites (PubMed:26616734). Also involved in late G2/M checkpoint following DNA damage through a process of post-transcriptional mRNA stabilization: following DNA damage, relocalizes from nucleus to cytoplasm and phosphorylates HNRNPA0 and PARN, leading to stabilization of GADD45A mRNA. Involved in toll-like receptor signaling pathway (TLR) in dendritic cells: required for acute TLR-induced macropinocytosis by phosphorylating and activating RPS6KA3.', 'MAPKAPK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, DNA damage, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (598, '4TPT', '', 'LIM domain kinase 2', 'Serine/threonine-protein kinase that plays an essential role in the regulation of actin filament dynamics (PubMed:10436159, PubMed:11018042). Acts downstream of several Rho family GTPase signal transduction pathways (PubMed:10436159, PubMed:11018042). Involved in astral microtubule organization and mitotic spindle orientation during early stages of mitosis by mediating phosphorylation of TPPP (PubMed:22328514). Displays serine/threonine-specific phosphorylation of myelin basic protein and histone (MBP) in vitro (PubMed:8537403). Suppresses ciliogenesis via multiple pathways; phosphorylation of CFL1, suppression of directional trafficking of ciliary vesicles to the ciliary base, and by facilitating YAP1 nuclear localization where it acts as a transcriptional corepressor of the TEAD4 target genes AURKA and PLK1 (PubMed:25849865).', 'LIMK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Kinase, LIM domain, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (599, '7B30', '', 'Serine/threonine-protein kinase 24', 'Serine/threonine-protein kinase that acts on both serine and threonine residues and promotes apoptosis in response to stress stimuli and caspase activation. Mediates oxidative-stress-induced cell death by modulating phosphorylation of JNK1-JNK2 (MAPK8 and MAPK9), p38 (MAPK11, MAPK12, MAPK13 and MAPK14) during oxidative stress. Plays a role in a staurosporine-induced caspase-independent apoptotic pathway by regulating the nuclear translocation of AIFM1 and ENDOG and the DNase activity associated with ENDOG. Phosphorylates STK38L on ''Thr-442'' and stimulates its kinase activity. In association with STK26 negatively regulates Golgi reorientation in polarized cell migration upon RHO activation (PubMed:27807006). Regulates also cellular migration with alteration of PTPN12 activity and PXN phosphorylation: phosphorylates PTPN12 and inhibits its activity and may regulate PXN phosphorylation through PTPN12. May act as a key regulator of axon regeneration in the optic nerve and radial nerve.', 'STK24', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (600, '4G16', '', 'Casein kinase I isoform gamma-3', 'Serine/threonine-protein kinase. Casein kinases are operationally defined by their preferential utilization of acidic proteins such as caseins as substrates. It can phosphorylate a large number of proteins. Participates in Wnt signaling. Regulates fast synaptic transmission mediated by glutamate (By similarity).', 'CSNK1G3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (602, '6GR8', '', 'Aurora kinase C', 'Serine/threonine-protein kinase component of the chromosomal passenger complex (CPC), a complex that acts as a key regulator of mitosis. The CPC complex has essential functions at the centromere in ensuring correct chromosome alignment and segregation and is required for chromatin-induced microtubule stabilization and spindle assembly. Also plays a role in meiosis and more particularly in spermatogenesis. Has redundant cellular functions with AURKB and can rescue an AURKB knockdown. Like AURKB, AURKC phosphorylates histone H3 at ''Ser-10'' and ''Ser-28''. AURKC phosphorylates the CPC complex subunits BIRC5/survivin and INCENP leading to increased AURKC activity. Phosphorylates TACC1, another protein involved in cell division, at ''Ser-228''.', 'AURKC', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cell division, Centromere, Chromosome, Cytoplasm, Cytoskeleton, Kinase, Meiosis, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (603, '5TWU', '', 'Maternal embryonic leucine zipper kinase', 'Serine/threonine-protein kinase involved in various processes such as cell cycle regulation, self-renewal of stem cells, apoptosis and splicing regulation. Has a broad substrate specificity; phosphorylates BCL2L14, CDC25B, MAP3K5/ASK1 and ZNF622. Acts as an activator of apoptosis by phosphorylating and activating MAP3K5/ASK1. Acts as a regulator of cell cycle, notably by mediating phosphorylation of CDC25B, promoting localization of CDC25B to the centrosome and the spindle poles during mitosis. Plays a key role in cell proliferation and carcinogenesis. Required for proliferation of embryonic and postnatal multipotent neural progenitors. Phosphorylates and inhibits BCL2L14, possibly leading to affect mammary carcinogenesis by mediating inhibition of the pro-apoptotic function of BCL2L14. Also involved in the inhibition of spliceosome assembly during mitosis by phosphorylating ZNF622, thereby contributing to its redirection to the nucleus. May also play a role in primitive hematopoiesis.', 'MELK', 'Homo sapiens', '{[''2.7.10.2'',''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Calcium, Cell cycle, Cell membrane, Kinase, Lipid-binding, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (604, '5UPL', '', 'Serine/threonine-protein kinase PAK 4', 'Serine/threonine protein kinase that plays a role in a variety of different signaling pathways including cytoskeleton regulation, cell migration, growth, proliferation or cell survival. Activation by various effectors including growth factor receptors or active CDC42 and RAC1 results in a conformational change and a subsequent autophosphorylation on several serine and/or threonine residues. Phosphorylates and inactivates the protein phosphatase SSH1, leading to increased inhibitory phosphorylation of the actin binding/depolymerizing factor cofilin. Decreased cofilin activity may lead to stabilization of actin filaments. Phosphorylates LIMK1, a kinase that also inhibits the activity of cofilin. Phosphorylates integrin beta5/ITGB5 and thus regulates cell motility. Phosphorylates ARHGEF2 and activates the downstream target RHOA that plays a role in the regulation of assembly of focal adhesions and actin stress fibers. Stimulates cell survival by phosphorylating the BCL2 antagonist of cell death BAD. Alternatively, inhibits apoptosis by preventing caspase-8 binding to death domain receptors in a kinase independent manner. Plays a role in cell-cycle progression by controlling levels of the cell-cycle regulatory protein CDKN1A and by phosphorylating RAN.', 'PAK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Kinase, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (605, '4RPV', '', 'Serine/threonine-protein kinase pim-1', 'Proto-oncogene with serine/threonine kinase activity involved in cell survival and cell proliferation and thus providing a selective advantage in tumorigenesis (PubMed:15528381, PubMed:1825810, PubMed:31548394). Exerts its oncogenic activity through: the regulation of MYC transcriptional activity, the regulation of cell cycle progression and by phosphorylation and inhibition of proapoptotic proteins (BAD, MAP3K5, FOXO3) (PubMed:18593906). Phosphorylation of MYC leads to an increase of MYC protein stability and thereby an increase of transcriptional activity (By similarity). The stabilization of MYC exerted by PIM1 might explain partly the strong synergism between these two oncogenes in tumorigenesis (By similarity). Mediates survival signaling through phosphorylation of BAD, which induces release of the anti-apoptotic protein Bcl-X(L)/BCL2L1 (By similarity). Phosphorylation of MAP3K5, another proapoptotic protein, by PIM1, significantly decreases MAP3K5 kinase activity and inhibits MAP3K5-mediated phosphorylation of JNK and JNK/p38MAPK subsequently reducing caspase-3 activation and cell apoptosis (PubMed:19749799). Stimulates cell cycle progression at the G1-S and G2-M transitions by phosphorylation of CDC25A and CDC25C (PubMed:16356754). Phosphorylation of CDKN1A, a regulator of cell cycle progression at G1, results in the relocation of CDKN1A to the cytoplasm and enhanced CDKN1A protein stability (PubMed:12431783). Promotes cell cycle progression and tumorigenesis by down-regulating expression of a regulator of cell cycle progression, CDKN1B, at both transcriptional and post-translational levels (PubMed:18593906). Phosphorylation of CDKN1B, induces 14-3-3 proteins binding, nuclear export and proteasome-dependent degradation (PubMed:18593906). May affect the structure or silencing of chromatin by phosphorylating HP1 gamma/CBX3 (PubMed:10664448). Acts also as a regulator of homing and migration of bone marrow cells involving functional interaction with the CXCL12-CXCR4 signaling axis (By similarity). Acts as a positive regulator of mTORC1 signaling by mediating phosphorylation and inhibition of DEPDC5 component of the GATOR1 complex (PubMed:31548394). Acts as a negative regulator of innate immunity by mediating phosphorylation and inactivation of GBP1 in absence of infection: phosphorylation of GBP1 induces interaction with 14-3-3 protein sigma (SFN) and retention in the cytosol (PubMed:37797010). Also phosphorylates and activates the ATP-binding cassette transporter ABCG2, allowing resistance to drugs through their excretion from cells (PubMed:18056989). Promotes brown adipocyte differentiation (By similarity).', 'PIM1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative initiation, Apoptosis, ATP-binding, Cell cycle, Cell membrane, Cytoplasm, Direct protein sequencing, Host-virus interaction, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (606, '5EBZ', '', 'Inhibitor of nuclear factor kappa-B kinase subunit alpha', 'Serine kinase that plays an essential role in the NF-kappa-B signaling pathway which is activated by multiple stimuli such as inflammatory cytokines, bacterial or viral products, DNA damages or other cellular stresses (PubMed:9244310, PubMed:9252186, PubMed:9346484, PubMed:18626576). Acts as a part of the canonical IKK complex in the conventional pathway of NF-kappa-B activation and phosphorylates inhibitors of NF-kappa-B on serine residues (PubMed:9244310, PubMed:9252186, PubMed:9346484, PubMed:18626576, PubMed:35952808). These modifications allow polyubiquitination of the inhibitors and subsequent degradation by the proteasome (PubMed:9244310, PubMed:9252186, PubMed:9346484, PubMed:18626576). In turn, free NF-kappa-B is translocated into the nucleus and activates the transcription of hundreds of genes involved in immune response, growth control, or protection against apoptosis (PubMed:9244310, PubMed:9252186, PubMed:9346484, PubMed:18626576). Negatively regulates the pathway by phosphorylating the scaffold protein TAXBP1 and thus promoting the assembly of the A20/TNFAIP3 ubiquitin-editing complex (composed of A20/TNFAIP3, TAX1BP1, and the E3 ligases ITCH and RNF11) (PubMed:21765415). Therefore, CHUK plays a key role in the negative feedback of NF-kappa-B canonical signaling to limit inflammatory gene activation. As part of the non-canonical pathway of NF-kappa-B activation, the MAP3K14-activated CHUK/IKKA homodimer phosphorylates NFKB2/p100 associated with RelB, inducing its proteolytic processing to NFKB2/p52 and the formation of NF-kappa-B RelB-p52 complexes (PubMed:20501937). In turn, these complexes regulate genes encoding molecules involved in B-cell survival and lymphoid organogenesis. Participates also in the negative feedback of the non-canonical NF-kappa-B signaling pathway by phosphorylating and destabilizing MAP3K14/NIK. Within the nucleus, phosphorylates CREBBP and consequently increases both its transcriptional and histone acetyltransferase activities (PubMed:17434128). Modulates chromatin accessibility at NF-kappa-B-responsive promoters by phosphorylating histones H3 at ''Ser-10'' that are subsequently acetylated at ''Lys-14'' by CREBBP (PubMed:12789342). Additionally, phosphorylates the CREBBP-interacting protein NCOA3. Also phosphorylates FOXO3 and may regulate this pro-apoptotic transcription factor (PubMed:15084260). Phosphorylates RIPK1 at ''Ser-25'' which represses its kinase activity and consequently prevents TNF-mediated RIPK1-dependent cell death (By similarity). Phosphorylates AMBRA1 following mitophagy induction, promoting AMBRA1 interaction with ATG8 family proteins and its mitophagic activity (PubMed:30217973).', 'CHUK', 'Homo sapiens', '{[''2.7.11.10'']}', '3D-structure, Acetylation, ATP-binding, Cytoplasm, Direct protein sequencing, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (607, '4TZ7', '', 'Phosphatidylinositol-4-phosphate 5-kinase type-1 gamma', 'Unknown', 'pip5k1aa', 'Danio rerio', '{[''2.7.1.68'']}', '3D-structure, ATP-binding, Calcium, Kinase, Metal-binding, Nucleotide-binding, Proteomics identification, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (608, '2AC3', '', 'MAP kinase-interacting serine/threonine-protein kinase 2', 'Serine/threonine-protein kinase that phosphorylates SFPQ/PSF, HNRNPA1 and EIF4E. May play a role in the response to environmental stress and cytokines. Appears to regulate translation by phosphorylating EIF4E, thus increasing the affinity of this protein for the 7-methylguanosine-containing mRNA cap. Required for mediating PP2A-inhibition-induced EIF4E phosphorylation. Triggers EIF4E shuttling from cytoplasm to nucleus. Isoform 1 displays a high basal kinase activity, but isoform 2 exhibits a very low kinase activity. Acts as a mediator of the suppressive effects of IFNgamma on hematopoiesis. Negative regulator for signals that control generation of arsenic trioxide As(2)O(3)-dependent apoptosis and anti-leukemic responses. Involved in anti-apoptotic signaling in response to serum withdrawal.', 'MKNK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Translation regulation, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (609, '3G33', '', 'Cyclin-dependent kinase 4', 'Ser/Thr-kinase component of cyclin D-CDK4 (DC) complexes that phosphorylate and inhibit members of the retinoblastoma (RB) protein family including RB1 and regulate the cell-cycle during G(1)/S transition. Phosphorylation of RB1 allows dissociation of the transcription factor E2F from the RB/E2F complexes and the subsequent transcription of E2F target genes which are responsible for the progression through the G(1) phase. Hypophosphorylates RB1 in early G(1) phase. Cyclin D-CDK4 complexes are major integrators of various mitogenenic and antimitogenic signals. Also phosphorylates SMAD3 in a cell-cycle-dependent manner and represses its transcriptional activity. Component of the ternary complex, cyclin D/CDK4/CDKN1B, required for nuclear translocation and activity of the cyclin D-CDK4 complex.', 'CDK4', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cell division, Cytoplasm, Disease variant, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (610, '7XZQ', '', 'TRAF2 and NCK-interacting protein kinase', 'Serine/threonine kinase that acts as an essential activator of the Wnt signaling pathway. Recruited to promoters of Wnt target genes and required to activate their expression. May act by phosphorylating TCF4/TCF7L2. Appears to act upstream of the JUN N-terminal pathway. May play a role in the response to environmental stress. Part of a signaling complex composed of NEDD4, RAP2A and TNIK which regulates neuronal dendrite extension and arborization during development. More generally, it may play a role in cytoskeletal rearrangements and regulate cell spreading. Phosphorylates SMAD1 on Thr-322.', 'TNIK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Endosome, Intellectual disability, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (611, '6KZC', '', 'NT-3 growth factor receptor', 'Receptor tyrosine kinase involved in nervous system and probably heart development. Upon binding of its ligand NTF3/neurotrophin-3, NTRK3 autophosphorylates and activates different signaling pathways, including the phosphatidylinositol 3-kinase/AKT and the MAPK pathways, that control cell survival and differentiation.', 'NTRK3', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Developmental protein, Differentiation, Direct protein sequencing, Disulfide bond, Glycoprotein, Immunoglobulin domain, Kinase, Leucine-rich repeat, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (612, '5OMY', '', 'Casein kinase II subunit alpha', 'Catalytic subunit of a constitutively active serine/threonine-protein kinase complex that phosphorylates a large number of substrates containing acidic residues C-terminal to the phosphorylated serine or threonine (PubMed:11239457, PubMed:11704824, PubMed:16193064, PubMed:19188443, PubMed:20545769, PubMed:20625391, PubMed:22017874, PubMed:22406621, PubMed:24962073, PubMed:30898438, PubMed:31439799). Regulates numerous cellular processes, such as cell cycle progression, apoptosis and transcription, as well as viral infection (PubMed:12631575, PubMed:19387552, PubMed:19387551). May act as a regulatory node which integrates and coordinates numerous signals leading to an appropriate cellular response (PubMed:12631575, PubMed:19387552, PubMed:19387551). During mitosis, functions as a component of the p53/TP53-dependent spindle assembly checkpoint (SAC) that maintains cyclin-B-CDK1 activity and G2 arrest in response to spindle damage (PubMed:11704824, PubMed:19188443). Also required for p53/TP53-mediated apoptosis, phosphorylating ''Ser-392'' of p53/TP53 following UV irradiation (PubMed:11239457). Phosphorylates a number of DNA repair proteins in response to DNA damage, such as MDC1, RAD9A, RAD51 and HTATSF1, promoting their recruitment to DNA damage sites (PubMed:20545769, PubMed:21482717, PubMed:22325354, PubMed:26811421, PubMed:30898438, PubMed:35597237). Can also negatively regulate apoptosis (PubMed:16193064, PubMed:22184066). Phosphorylates the caspases CASP9 and CASP2 and the apoptotic regulator NOL3 (PubMed:16193064). Phosphorylation protects CASP9 from cleavage and activation by CASP8, and inhibits the dimerization of CASP2 and activation of CASP8 (PubMed:16193064). Phosphorylates YY1, protecting YY1 from cleavage by CASP7 during apoptosis (PubMed:22184066). Regulates transcription by direct phosphorylation of RNA polymerases I, II, III and IV (PubMed:19387550, PubMed:12631575, PubMed:19387552, PubMed:19387551, PubMed:23123191). Also phosphorylates and regulates numerous transcription factors including NF-kappa-B, STAT1, CREB1, IRF1, IRF2, ATF1, ATF4, SRF, MAX, JUN, FOS, MYC and MYB (PubMed:19387550, PubMed:12631575, PubMed:19387552, PubMed:19387551, PubMed:23123191). Phosphorylates Hsp90 and its co-chaperones FKBP4 and CDC37, which is essential for chaperone function (PubMed:19387550). Mediates sequential phosphorylation of FNIP1, promoting its gradual interaction with Hsp90, leading to activate both kinase and non-kinase client proteins of Hsp90 (PubMed:30699359). Regulates Wnt signaling by phosphorylating CTNNB1 and the transcription factor LEF1 (PubMed:19387549). Acts as an ectokinase that phosphorylates several extracellular proteins (PubMed:19387550, PubMed:12631575, PubMed:19387552, PubMed:19387551). During viral infection, phosphorylates various proteins involved in the viral life cycles of EBV, HSV, HBV, HCV, HIV, CMV and HPV (PubMed:19387550, PubMed:12631575, PubMed:19387552, PubMed:19387551). Phosphorylates PML at ''Ser-565'' and primes it for ubiquitin-mediated degradation (PubMed:20625391, PubMed:22406621). Plays an important role in the circadian clock function by phosphorylating BMAL1 at ''Ser-90'' which is pivotal for its interaction with CLOCK and which controls CLOCK nuclear entry (By similarity). Phosphorylates CCAR2 at ''Thr-454'' in gastric carcinoma tissue (PubMed:24962073). Phosphorylates FMR1, promoting FMR1-dependent formation of a membraneless compartment (PubMed:30765518, PubMed:31439799).', 'CSNK2A1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Biological rhythms, Cell cycle, Disease variant, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (613, '1S9I', '', 'Dual specificity mitogen-activated protein kinase kinase 2', 'Catalyzes the concomitant phosphorylation of a threonine and a tyrosine residue in a Thr-Glu-Tyr sequence located in MAP kinases. Activates the ERK1 and ERK2 MAP kinases (By similarity). Activates BRAF in a KSR1 or KSR2-dependent manner; by binding to KSR1 or KSR2 releases the inhibitory intramolecular interaction between KSR1 or KSR2 protein kinase and N-terminal domains which promotes KSR1 or KSR2-BRAF dimerization and BRAF activation (PubMed:29433126).', 'MAP2K2', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, ATP-binding, Cardiomyopathy, Cytoplasm, Direct protein sequencing, Disease variant, Ectodermal dysplasia, Intellectual disability, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (614, '3V2A', '', 'Vascular endothelial growth factor receptor 2', 'Tyrosine-protein kinase that acts as a cell-surface receptor for VEGFA, VEGFC and VEGFD. Plays an essential role in the regulation of angiogenesis, vascular development, vascular permeability, and embryonic hematopoiesis. Promotes proliferation, survival, migration and differentiation of endothelial cells. Promotes reorganization of the actin cytoskeleton. Isoforms lacking a transmembrane domain, such as isoform 2 and isoform 3, may function as decoy receptors for VEGFA, VEGFC and/or VEGFD. Isoform 2 plays an important role as negative regulator of VEGFA- and VEGFC-mediated lymphangiogenesis by limiting the amount of free VEGFA and/or VEGFC and preventing their binding to FLT4. Modulates FLT1 and FLT4 signaling by forming heterodimers. Binding of vascular growth factors to isoform 1 leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate and the activation of protein kinase C. Mediates activation of MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. Mediates phosphorylation of PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase, reorganization of the actin cytoskeleton and activation of PTK2/FAK1. Required for VEGFA-mediated induction of NOS2 and NOS3, leading to the production of the signaling molecule nitric oxide (NO) by endothelial cells. Phosphorylates PLCG1. Promotes phosphorylation of FYN, NCK1, NOS3, PIK3R1, PTK2/FAK1 and SRC.', 'KDR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, Angiogenesis, ATP-binding, Cell junction, Cell membrane, Cytoplasm, Cytoplasmic vesicle, Developmental protein, Differentiation, Disulfide bond, Endoplasmic reticulum, Endosome, Glycoprotein, Host-virus interaction, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (615, '2GSF', '', 'Ephrin type-A receptor 3', 'Receptor tyrosine kinase which binds promiscuously membrane-bound ephrin family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Highly promiscuous for ephrin-A ligands it binds preferentially EFNA5. Upon activation by EFNA5 regulates cell-cell adhesion, cytoskeletal organization and cell migration. Plays a role in cardiac cells migration and differentiation and regulates the formation of the atrioventricular canal and septum during development probably through activation by EFNA1. Involved in the retinotectal mapping of neurons. May also control the segregation but not the guidance of motor and sensory axons during neuromuscular circuit development.', 'EPHA3', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell membrane, Direct protein sequencing, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Secreted, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (616, '2J90', '', 'Death-associated protein kinase 3', 'Serine/threonine kinase which is involved in the regulation of apoptosis, autophagy, transcription, translation and actin cytoskeleton reorganization. Involved in the regulation of smooth muscle contraction. Regulates both type I (caspase-dependent) apoptotic and type II (caspase-independent) autophagic cell deaths signal, depending on the cellular setting. Involved in regulation of starvation-induced autophagy. Regulates myosin phosphorylation in both smooth muscle and non-muscle cells. In smooth muscle, regulates myosin either directly by phosphorylating MYL12B and MYL9 or through inhibition of smooth muscle myosin phosphatase (SMPP1M) via phosphorylation of PPP1R12A; the inhibition of SMPP1M functions to enhance muscle responsiveness to Ca(2+) and promote a contractile state. Phosphorylates MYL12B in non-muscle cells leading to reorganization of actin cytoskeleton. Isoform 2 can phosphorylate myosin, PPP1R12A and MYL12B. Overexpression leads to condensation of actin stress fibers into thick bundles. Involved in actin filament focal adhesion dynamics. The function in both reorganization of actin cytoskeleton and focal adhesion dissolution is modulated by RhoD. Positively regulates canonical Wnt/beta-catenin signaling through interaction with NLK and TCF7L2. Phosphorylates RPL13A on ''Ser-77'' upon interferon-gamma activation which is causing RPL13A release from the ribosome, RPL13A association with the GAIT complex and its subsequent involvement in transcript-selective translation inhibition. Enhances transcription from AR-responsive promoters in a hormone- and kinase-dependent manner. Involved in regulation of cell cycle progression and cell proliferation. May be a tumor suppressor.', 'DAPK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Activator, Alternative splicing, Apoptosis, ATP-binding, Chromatin regulator, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Translation regulation, Tumor suppressor');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (617, '5EFQ', '', 'Cyclin-dependent kinase 13', 'Cyclin-dependent kinase which displays CTD kinase activity and is required for RNA splicing. Has CTD kinase activity by hyperphosphorylating the C-terminal heptapeptide repeat domain (CTD) of the largest RNA polymerase II subunit RPB1, thereby acting as a key regulator of transcription elongation. Required for RNA splicing, probably by phosphorylating SRSF1/SF2. Required during hematopoiesis. In case of infection by HIV-1 virus, interacts with HIV-1 Tat protein acetylated at ''Lys-50'' and ''Lys-51'', thereby increasing HIV-1 mRNA splicing and promoting the production of the doubly spliced HIV-1 protein Nef.', 'CDK13', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Disease variant, Host-virus interaction, Intellectual disability, Isopeptide bond, Kinase, mRNA processing, mRNA splicing, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, RNA editing, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (618, '4UYA', '', 'Mitogen-activated protein kinase kinase kinase 21', 'Negative regulator of TLR4 signaling. Does not activate JNK1/MAPK8 pathway, p38/MAPK14, nor ERK2/MAPK1 pathways.', 'MAP3K21', 'Homo sapiens', '{[''2.7.11.25'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, SH3 domain, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (619, '1ZMU', '', 'Serine/threonine-protein kinase MARK2', 'Serine/threonine-protein kinase. Involved in cell polarity and microtubule dynamics regulation. Phosphorylates CRTC2/TORC2, DCX, HDAC7, KIF13B, MAP2, MAP4 and RAB11FIP2. Phosphorylates the microtubule-associated protein MAPT/TAU. Plays a key role in cell polarity by phosphorylating the microtubule-associated proteins MAP2, MAP4 and MAPT/TAU at KXGS motifs, causing detachment from microtubules, and their disassembly. Regulates epithelial cell polarity by phosphorylating RAB11FIP2. Involved in the regulation of neuronal migration through its dual activities in regulating cellular polarity and microtubule dynamics, possibly by phosphorylating and regulating DCX. Regulates axogenesis by phosphorylating KIF13B, promoting interaction between KIF13B and 14-3-3 and inhibiting microtubule-dependent accumulation of KIF13B. Also required for neurite outgrowth and establishment of neuronal polarity. Regulates localization and activity of some histone deacetylases by mediating phosphorylation of HDAC7, promoting subsequent interaction between HDAC7 and 14-3-3 and export from the nucleus. Also acts as a positive regulator of the Wnt signaling pathway, probably by mediating phosphorylation of dishevelled proteins (DVL1, DVL2 and/or DVL3). Modulates the developmental decision to build a columnar versus a hepatic epithelial cell apparently by promoting a switch from a direct to a transcytotic mode of apical protein delivery. Essential for the asymmetric development of membrane domains of polarized epithelial cells.', 'Mark2', 'Rattus norvegicus', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, ATP-binding, Cell membrane, Cell projection, Cytoplasm, Cytoskeleton, Developmental protein, Differentiation, Kinase, Lipid-binding, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (620, '4OTD', '', 'Serine/threonine-protein kinase N1', 'PKC-related serine/threonine-protein kinase involved in various processes such as regulation of the intermediate filaments of the actin cytoskeleton, cell migration, tumor cell invasion and transcription regulation. Part of a signaling cascade that begins with the activation of the adrenergic receptor ADRA1B and leads to the activation of MAPK14. Regulates the cytoskeletal network by phosphorylating proteins such as VIM and neurofilament proteins NEFH, NEFL and NEFM, leading to inhibit their polymerization. Phosphorylates ''Ser-575'', ''Ser-637'' and ''Ser-669'' of MAPT/Tau, lowering its ability to bind to microtubules, resulting in disruption of tubulin assembly. Acts as a key coactivator of androgen receptor (AR)-dependent transcription, by being recruited to AR target genes and specifically mediating phosphorylation of ''Thr-11'' of histone H3 (H3T11ph), a specific tag for epigenetic transcriptional activation that promotes demethylation of histone H3 ''Lys-9'' (H3K9me) by KDM4C/JMJD2C. Phosphorylates HDAC5, HDAC7 and HDAC9, leading to impair their import in the nucleus. Phosphorylates ''Thr-38'' of PPP1R14A, ''Ser-159'', ''Ser-163'' and ''Ser-170'' of MARCKS, and GFAP. Able to phosphorylate RPS6 in vitro.', 'PKN1', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell membrane, Chromatin regulator, Coiled coil, Cytoplasm, Endosome, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (621, '5GRN', '', 'Platelet-derived growth factor receptor alpha', 'Tyrosine-protein kinase that acts as a cell-surface receptor for PDGFA, PDGFB and PDGFC and plays an essential role in the regulation of embryonic development, cell proliferation, survival and chemotaxis. Depending on the context, promotes or inhibits cell proliferation and cell migration. Plays an important role in the differentiation of bone marrow-derived mesenchymal stem cells. Required for normal skeleton development and cephalic closure during embryonic development. Required for normal development of the mucosa lining the gastrointestinal tract, and for recruitment of mesenchymal cells and normal development of intestinal villi. Plays a role in cell migration and chemotaxis in wound healing. Plays a role in platelet activation, secretion of agonists from platelet granules, and in thrombin-induced platelet aggregation. Binding of its cognate ligands - homodimeric PDGFA, homodimeric PDGFB, heterodimers formed by PDGFA and PDGFB or homodimeric PDGFC -leads to the activation of several signaling cascades; the response depends on the nature of the bound ligand and is modulated by the formation of heterodimers between PDGFRA and PDGFRB. Phosphorylates PIK3R1, PLCG1, and PTPN11. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate, mobilization of cytosolic Ca(2+) and the activation of protein kinase C. Phosphorylates PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase, and thereby mediates activation of the AKT1 signaling pathway. Mediates activation of HRAS and of the MAP kinases MAPK1/ERK2 and/or MAPK3/ERK1. Promotes activation of STAT family members STAT1, STAT3 and STAT5A and/or STAT5B. Receptor signaling is down-regulated by protein phosphatases that dephosphorylate the receptor and its down-stream effectors, and by rapid internalization of the activated receptor.', 'PDGFRA', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Cell projection, Chemotaxis, Developmental protein, Disease variant, Disulfide bond, Glycoprotein, Golgi apparatus, Host-virus interaction, Immunoglobulin domain, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (622, '3OFM', '', 'Casein kinase II subunit alpha''', 'Catalytic subunit of a constitutively active serine/threonine-protein kinase complex that phosphorylates a large number of substrates containing acidic residues C-terminal to the phosphorylated serine or threonine (PubMed:11239457, PubMed:11704824, PubMed:16193064, PubMed:30898438). Regulates numerous cellular processes, such as cell cycle progression, apoptosis and transcription, as well as viral infection (PubMed:11704824, PubMed:16193064, PubMed:30898438). May act as a regulatory node which integrates and coordinates numerous signals leading to an appropriate cellular response (PubMed:12631575, PubMed:19387552, PubMed:19387551). During mitosis, functions as a component of the p53/TP53-dependent spindle assembly checkpoint (SAC) that maintains cyclin-B-CDK1 activity and G2 arrest in response to spindle damage (PubMed:12631575, PubMed:19387552, PubMed:19387551). Also required for p53/TP53-mediated apoptosis, phosphorylating ''Ser-392'' of p53/TP53 following UV irradiation (PubMed:11239457). Phosphorylates a number of DNA repair proteins in response to DNA damage, such as MDC1, RAD9A, RAD51 and HTATSF1, promoting their recruitment to DNA damage sites (PubMed:20545769, PubMed:21482717, PubMed:22325354, PubMed:26811421, PubMed:30898438, PubMed:35597237). Can also negatively regulate apoptosis (PubMed:19387552, PubMed:19387551). Phosphorylates the caspases CASP9 and CASP2 and the apoptotic regulator NOL3 (PubMed:12631575, PubMed:19387552, PubMed:19387551). Phosphorylation protects CASP9 from cleavage and activation by CASP8, and inhibits the dimerization of CASP2 and activation of CASP8 (PubMed:12631575, PubMed:19387552, PubMed:19387551). Regulates transcription by direct phosphorylation of RNA polymerases I, II, III and IV (PubMed:12631575, PubMed:19387552, PubMed:19387551). Also phosphorylates and regulates numerous transcription factors including NF-kappa-B, STAT1, CREB1, IRF1, IRF2, ATF1, SRF, MAX, JUN, FOS, MYC and MYB (PubMed:12631575, PubMed:19387552, PubMed:19387551). Phosphorylates Hsp90 and its co-chaperones FKBP4 and CDC37, which is essential for chaperone function (PubMed:19387550). Regulates Wnt signaling by phosphorylating CTNNB1 and the transcription factor LEF1 (PubMed:19387549). Acts as an ectokinase that phosphorylates several extracellular proteins (PubMed:12631575, PubMed:19387552, PubMed:19387551). During viral infection, phosphorylates various proteins involved in the viral life cycles of EBV, HSV, HBV, HCV, HIV, CMV and HPV (PubMed:12631575, PubMed:19387552, PubMed:19387551).', 'CSNK2A2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Apoptosis, ATP-binding, Cell cycle, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (623, '7Z4V', '', 'Serine/threonine-protein kinase 25', 'Oxidant stress-activated serine/threonine kinase that may play a role in the response to environmental stress. Targets to the Golgi apparatus where it appears to regulate protein transport events, cell adhesion, and polarity complexes important for cell migration.', 'STK25', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Golgi apparatus, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (624, '2J4Z', '', 'Aurora kinase A', 'Mitotic serine/threonine kinase that contributes to the regulation of cell cycle progression (PubMed:26246606, PubMed:12390251, PubMed:18615013, PubMed:11039908, PubMed:17125279, PubMed:17360485). Associates with the centrosome and the spindle microtubules during mitosis and plays a critical role in various mitotic events including the establishment of mitotic spindle, centrosome duplication, centrosome separation as well as maturation, chromosomal alignment, spindle assembly checkpoint, and cytokinesis (PubMed:26246606, PubMed:14523000). Required for normal spindle positioning during mitosis and for the localization of NUMA1 and DCTN1 to the cell cortex during metaphase (PubMed:27335426). Required for initial activation of CDK1 at centrosomes (PubMed:13678582, PubMed:15128871). Phosphorylates numerous target proteins, including ARHGEF2, BORA, BRCA1, CDC25B, DLGP5, HDAC6, KIF2A, LATS2, NDEL1, PARD3, PPP1R2, PLK1, RASSF1, TACC3, p53/TP53 and TPX2 (PubMed:18056443, PubMed:15128871, PubMed:14702041, PubMed:11551964, PubMed:15147269, PubMed:15987997, PubMed:17604723, PubMed:18615013). Regulates KIF2A tubulin depolymerase activity (PubMed:19351716). Important for microtubule formation and/or stabilization (PubMed:18056443). Required for normal axon formation (PubMed:19812038). Plays a role in microtubule remodeling during neurite extension (PubMed:19668197). Also acts as a key regulatory component of the p53/TP53 pathway, and particularly the checkpoint-response pathways critical for oncogenic transformation of cells, by phosphorylating and destabilizing p53/TP53 (PubMed:14702041). Phosphorylates its own inhibitors, the protein phosphatase type 1 (PP1) isoforms, to inhibit their activity (PubMed:11551964). Inhibits cilia outgrowth (By similarity). Required for cilia disassembly via phosphorylation of HDAC6 and subsequent deacetylation of alpha-tubulin (PubMed:17604723, PubMed:20643351). Regulates protein levels of the anti-apoptosis protein BIRC5 by suppressing the expression of the SCF(FBXL7) E3 ubiquitin-protein ligase substrate adapter FBXL7 through the phosphorylation of the transcription factor FOXP1 (PubMed:28218735).', 'AURKA', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell cycle, Cell division, Cell membrane, Cell projection, Cilium, Cilium biogenesis/degradation, Cytoplasm, Cytoskeleton, Isopeptide bond, Kinase, Membrane, Microtubule, Mitosis, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (646, '6MNH', '', 'Serine/threonine-protein kinase ULK1', 'Serine/threonine-protein kinase involved in autophagy in response to starvation (PubMed:18936157, PubMed:21460634, PubMed:21795849, PubMed:23524951, PubMed:25040165, PubMed:31123703, PubMed:29487085). Acts upstream of phosphatidylinositol 3-kinase PIK3C3 to regulate the formation of autophagophores, the precursors of autophagosomes (PubMed:18936157, PubMed:21460634, PubMed:21795849, PubMed:25040165). Part of regulatory feedback loops in autophagy: acts both as a downstream effector and negative regulator of mammalian target of rapamycin complex 1 (mTORC1) via interaction with RPTOR (PubMed:21795849). Activated via phosphorylation by AMPK and also acts as a regulator of AMPK by mediating phosphorylation of AMPK subunits PRKAA1, PRKAB2 and PRKAG1, leading to negatively regulate AMPK activity (PubMed:21460634). May phosphorylate ATG13/KIAA0652 and RPTOR; however such data need additional evidences (PubMed:18936157). Plays a role early in neuronal differentiation and is required for granule cell axon formation (PubMed:11146101). Also phosphorylates SESN2 and SQSTM1 to regulate autophagy (PubMed:25040165, PubMed:37306101). Phosphorylates FLCN, promoting autophagy (PubMed:25126726). Phosphorylates AMBRA1 in response to autophagy induction, releasing AMBRA1 from the cytoskeletal docking site to induce autophagosome nucleation (PubMed:20921139). Phosphorylates ATG4B, leading to inhibit autophagy by decreasing both proteolytic activation and delipidation activities of ATG4B (PubMed:28821708).', 'ULK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Autophagy, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (625, '7BI2', '', 'Phosphatidylinositol 4-phosphate 3-kinase C2 domain-containing subunit alpha', 'Generates phosphatidylinositol 3-phosphate (PtdIns3P) and phosphatidylinositol 3,4-bisphosphate (PtdIns(3,4)P2) that act as second messengers. Has a role in several intracellular trafficking events. Functions in insulin signaling and secretion. Required for translocation of the glucose transporter SLC2A4/GLUT4 to the plasma membrane and glucose uptake in response to insulin-mediated RHOQ activation. Regulates insulin secretion through two different mechanisms: involved in glucose-induced insulin secretion downstream of insulin receptor in a pathway that involves AKT1 activation and TBC1D4/AS160 phosphorylation, and participates in the late step of insulin granule exocytosis probably in insulin granule fusion. Synthesizes PtdIns3P in response to insulin signaling. Functions in clathrin-coated endocytic vesicle formation and distribution. Regulates dynamin-independent endocytosis, probably by recruiting EEA1 to internalizing vesicles. In neurosecretory cells synthesizes PtdIns3P on large dense core vesicles. Participates in calcium induced contraction of vascular smooth muscle by regulating myosin light chain (MLC) phosphorylation through a mechanism involving Rho kinase-dependent phosphorylation of the MLCP-regulatory subunit MYPT1. May play a role in the EGF signaling cascade. May be involved in mitosis and UV-induced damage response. Required for maintenance of normal renal structure and function by supporting normal podocyte function. Involved in the regulation of ciliogenesis and trafficking of ciliary components (By similarity).', 'Pik3c2a', 'Mus musculus', '{[''2.7.1.153'',''2.7.1.137'',''2.7.1.154'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell membrane, Cytoplasm, Cytoplasmic vesicle, Endocytosis, Exocytosis, Golgi apparatus, Kinase, Lipid metabolism, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (626, '8OKU', '', 'Serine/threonine-protein kinase SIK3', 'Positive regulator of mTOR signaling that functions by triggering the degradation of DEPTOR, an mTOR inhibitor. Involved in the dynamic regulation of mTOR signaling in chondrocyte differentiation during skeletogenesis (PubMed:30232230). Negatively regulates cAMP signaling pathway possibly by acting on CRTC2/TORC2 and CRTC3/TORC3 (Probable). Prevents HDAC4 translocation to the nucleus (By similarity).', 'SIK3', 'Homo sapiens', '{[''2.7.11.1'']}', 'Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Dwarfism, Kinase, Magnesium, Metal-binding, Methylation, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (627, '3I6W', '', 'Serine/threonine-protein kinase Chk2', 'Serine/threonine-protein kinase which is required for checkpoint-mediated cell cycle arrest, activation of DNA repair and apoptosis in response to the presence of DNA double-strand breaks. May also negatively regulate cell cycle progression during unperturbed cell cycles. Following activation, phosphorylates numerous effectors preferentially at the consensus sequence [L-X-R-X-X-S/T]. Regulates cell cycle checkpoint arrest through phosphorylation of CDC25A, CDC25B and CDC25C, inhibiting their activity. Inhibition of CDC25 phosphatase activity leads to increased inhibitory tyrosine phosphorylation of CDK-cyclin complexes and blocks cell cycle progression. May also phosphorylate NEK6 which is involved in G2/M cell cycle arrest. Regulates DNA repair through phosphorylation of BRCA2, enhancing the association of RAD51 with chromatin which promotes DNA repair by homologous recombination. Also stimulates the transcription of genes involved in DNA repair (including BRCA2) through the phosphorylation and activation of the transcription factor FOXM1. Regulates apoptosis through the phosphorylation of p53/TP53, MDM4 and PML. Phosphorylation of p53/TP53 at ''Ser-20'' by CHEK2 may alleviate inhibition by MDM2, leading to accumulation of active p53/TP53. Phosphorylation of MDM4 may also reduce degradation of p53/TP53. Also controls the transcription of pro-apoptotic genes through phosphorylation of the transcription factor E2F1. Tumor suppressor, it may also have a DNA damage-independent function in mitotic spindle assembly by phosphorylating BRCA1. Its absence may be a cause of the chromosomal instability observed in some cancer cells. Promotes the CCAR2-SIRT1 association and is required for CCAR2-mediated SIRT1 inhibition (PubMed:25361978).', 'CHEK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell cycle, Cell division, Disease variant, DNA damage, DNA repair, Host-virus interaction, Kinase, Li-Fraumeni syndrome, Magnesium, Metal-binding, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Tumor suppressor, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (628, '3ALN', '', 'Dual specificity mitogen-activated protein kinase kinase 4', 'Dual specificity protein kinase which acts as an essential component of the MAP kinase signal transduction pathway. Essential component of the stress-activated protein kinase/c-Jun N-terminal kinase (SAP/JNK) signaling pathway. With MAP2K7/MKK7, is the one of the only known kinase to directly activate the stress-activated protein kinase/c-Jun N-terminal kinases MAPK8/JNK1, MAPK9/JNK2 and MAPK10/JNK3. MAP2K4/MKK4 and MAP2K7/MKK7 both activate the JNKs by phosphorylation, but they differ in their preference for the phosphorylation site in the Thr-Pro-Tyr motif. MAP2K4 shows preference for phosphorylation of the Tyr residue and MAP2K7/MKK7 for the Thr residue. The phosphorylation of the Thr residue by MAP2K7/MKK7 seems to be the prerequisite for JNK activation at least in response to pro-inflammatory cytokines, while other stimuli activate both MAP2K4/MKK4 and MAP2K7/MKK7 which synergistically phosphorylate JNKs. MAP2K4 is required for maintaining peripheral lymphoid homeostasis. The MKK/JNK signaling pathway is also involved in mitochondrial death signaling pathway, including the release cytochrome c, leading to apoptosis. Whereas MAP2K7/MKK7 exclusively activates JNKs, MAP2K4/MKK4 additionally activates the p38 MAPKs MAPK11, MAPK12, MAPK13 and MAPK14.', 'MAP2K4', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Kinase, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (629, '8GW3', '', 'TGF-beta-activated kinase 1 and MAP3K7-binding protein 1', 'Key adapter protein that plays an essential role in JNK and NF-kappa-B activation and proinflammatory cytokines production in response to stimulation with TLRs and cytokines (PubMed:22307082, PubMed:24403530). Mechanistically, associates with the catalytic domain of MAP3K7/TAK1 to trigger MAP3K7/TAK1 autophosphorylation leading to its full activation (PubMed:10838074, PubMed:25260751, PubMed:37832545). Similarly, associates with MAPK14 and triggers its autophosphorylation and subsequent activation (PubMed:11847341, PubMed:29229647). In turn, MAPK14 phosphorylates TAB1 and inhibits MAP3K7/TAK1 activation in a feedback control mechanism (PubMed:14592977). Plays also a role in recruiting MAPK14 to the TAK1 complex for the phosphorylation of the TAB2 and TAB3 regulatory subunits (PubMed:18021073).', 'TAB1', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, Cytoplasm, Endoplasmic reticulum, Glycoprotein, Membrane, Phosphoprotein, Reference proteome, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (630, '4IC7', '', 'Mitogen-activated protein kinase 7', 'Plays a role in various cellular processes such as proliferation, differentiation and cell survival. The upstream activator of MAPK7 is the MAPK kinase MAP2K5. Upon activation, it translocates to the nucleus and phosphorylates various downstream targets including MEF2C. EGF activates MAPK7 through a Ras-independent and MAP2K5-dependent pathway. As part of the MAPK/ERK signaling pathway, acts as a negative regulator of apoptosis in cardiomyocytes via interaction with STUB1/CHIP and promotion of STUB1-mediated ubiquitination and degradation of ICER-type isoforms of CREM (By similarity). May have a role in muscle cell differentiation. May be important for endothelial function and maintenance of blood vessel integrity. MAP2K5 and MAPK7 interact specifically with one another and not with MEK1/ERK1 or MEK2/ERK2 pathways. Phosphorylates SGK1 at Ser-78 and this is required for growth factor-induced cell cycle progression. Involved in the regulation of p53/TP53 by disrupting the PML-MDM2 interaction.', 'MAPK7', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Cytoplasm, Differentiation, Direct protein sequencing, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (631, '7LBF', '', 'Envelope glycoprotein H', 'The heterodimer glycoprotein H-glycoprotein L is required for the fusion of viral and plasma membranes leading to virus entry into the host cell. Following initial binding to host receptor, membrane fusion is mediated by the fusion machinery composed of gB and the heterodimer gH/gL. May also be involved in the fusion between the virion envelope and the outer nuclear membrane during virion morphogenesis (By similarity). In human cytomegalovirus, forms two distincts complexes to mediate viral entry, a trimer and a pentamer at the surface of the virion envelope. The gH-gL-gO trimer is required for infection in fibroblasts by interacting with host PDGFRA, and in glioblastoma cells by interacting with host EPHA2 (PubMed:28403202, PubMed:37146061). The gH-gL-UL128-UL130-UL131A pentamer is essential for viral entry in epithelial, endothelial and myeloid cells via interaction with host NRP2 (PubMed:17942555, PubMed:23853586, PubMed:30057110, PubMed:28783665).', 'gH', 'Human cytomegalovirus (strain Merlin)', '{[]}', '3D-structure, Fusion of virus membrane with host cell membrane, Fusion of virus membrane with host membrane, Glycoprotein, Host cell membrane, Host endosome, Host membrane, Host-virus interaction, Membrane, Reference proteome, Sialic acid, Signal, Transmembrane, Transmembrane helix, Viral attachment to host cell, Viral attachment to host entry receptor, Viral envelope protein, Viral penetration into host cytoplasm, Virion, Virus entry into host cell');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (632, '3MDY', '', 'Bone morphogenetic protein receptor type-1B', 'On ligand binding, forms a receptor complex consisting of two type II and two type I transmembrane serine/threonine kinases. Type II receptors phosphorylate and activate type I receptors which autophosphorylate, then bind and activate SMAD transcriptional regulators. Receptor for BMP7/OP-1 and GDF5. Positively regulates chondrocyte differentiation through GDF5 interaction.', 'BMPR1B', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Chondrogenesis, Disease variant, Disulfide bond, Dwarfism, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (633, '2JAM', '', 'Calcium/calmodulin-dependent protein kinase type 1G', 'Calcium/calmodulin-dependent protein kinase belonging to a proposed calcium-triggered signaling cascade. In vitro phosphorylates transcription factor CREB1 (By similarity).', 'CAMK1G', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Allosteric enzyme, Alternative splicing, ATP-binding, Calmodulin-binding, Cell membrane, Cytoplasm, Golgi apparatus, Kinase, Lipoprotein, Membrane, Nucleotide-binding, Prenylation, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (634, '6GVJ', '', 'Dual specificity protein kinase TTK', 'Phosphorylates proteins on serine, threonine, and tyrosine (PubMed:18243099, PubMed:29162720). Probably associated with cell proliferation (PubMed:18243099). Phosphorylates MAD1L1 to promote mitotic checkpoint signaling (PubMed:29162720). Essential for chromosome alignment by enhancing AURKB activity (via direct CDCA8 phosphorylation) at the centromere, and for the mitotic checkpoint (PubMed:18243099).', 'TTK', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (663, '1A9U', '', 'Mitogen-activated protein kinase 14', 'Serine/threonine kinase which acts as an essential component of the MAP kinase signal transduction pathway. MAPK14 is one of the four p38 MAPKs which play an important role in the cascades of cellular responses evoked by extracellular stimuli such as pro-inflammatory cytokines or physical stress leading to direct activation of transcription factors. Accordingly, p38 MAPKs phosphorylate a broad range of proteins and it has been estimated that they may have approximately 200 to 300 substrates each. Some of the targets are downstream kinases which are activated through phosphorylation and further phosphorylate additional targets. RPS6KA5/MSK1 and RPS6KA4/MSK2 can directly phosphorylate and activate transcription factors such as CREB1, ATF1, the NF-kappa-B isoform RELA/NFKB3, STAT1 and STAT3, but can also phosphorylate histone H3 and the nucleosomal protein HMGN1 (PubMed:9687510, PubMed:9792677). RPS6KA5/MSK1 and RPS6KA4/MSK2 play important roles in the rapid induction of immediate-early genes in response to stress or mitogenic stimuli, either by inducing chromatin remodeling or by recruiting the transcription machinery (PubMed:9687510, PubMed:9792677). On the other hand, two other kinase targets, MAPKAPK2/MK2 and MAPKAPK3/MK3, participate in the control of gene expression mostly at the post-transcriptional level, by phosphorylating ZFP36 (tristetraprolin) and ELAVL1, and by regulating EEF2K, which is important for the elongation of mRNA during translation. MKNK1/MNK1 and MKNK2/MNK2, two other kinases activated by p38 MAPKs, regulate protein synthesis by phosphorylating the initiation factor EIF4E2 (PubMed:11154262). MAPK14 interacts also with casein kinase II, leading to its activation through autophosphorylation and further phosphorylation of TP53/p53 (PubMed:10747897). In the cytoplasm, the p38 MAPK pathway is an important regulator of protein turnover. For example, CFLAR is an inhibitor of TNF-induced apoptosis whose proteasome-mediated degradation is regulated by p38 MAPK phosphorylation. In a similar way, MAPK14 phosphorylates the ubiquitin ligase SIAH2, regulating its activity towards EGLN3 (PubMed:17003045). MAPK14 may also inhibit the lysosomal degradation pathway of autophagy by interfering with the intracellular trafficking of the transmembrane protein ATG9 (PubMed:19893488). Another function of MAPK14 is to regulate the endocytosis of membrane receptors by different mechanisms that impinge on the small GTPase RAB5A. In addition, clathrin-mediated EGFR internalization induced by inflammatory cytokines and UV irradiation depends on MAPK14-mediated phosphorylation of EGFR itself as well as of RAB5A effectors (PubMed:16932740). Ectodomain shedding of transmembrane proteins is regulated by p38 MAPKs as well. In response to inflammatory stimuli, p38 MAPKs phosphorylate the membrane-associated metalloprotease ADAM17 (PubMed:20188673). Such phosphorylation is required for ADAM17-mediated ectodomain shedding of TGF-alpha family ligands, which results in the activation of EGFR signaling and cell proliferation. Another p38 MAPK substrate is FGFR1. FGFR1 can be translocated from the extracellular space into the cytosol and nucleus of target cells, and regulates processes such as rRNA synthesis and cell growth. FGFR1 translocation requires p38 MAPK activation. In the nucleus, many transcription factors are phosphorylated and activated by p38 MAPKs in response to different stimuli. Classical examples include ATF1, ATF2, ATF6, ELK1, PTPRH, DDIT3, TP53/p53 and MEF2C and MEF2A (PubMed:9430721, PubMed:9858528, PubMed:10330143). The p38 MAPKs are emerging as important modulators of gene expression by regulating chromatin modifiers and remodelers. The promoters of several genes involved in the inflammatory response, such as IL6, IL8 and IL12B, display a p38 MAPK-dependent enrichment of histone H3 phosphorylation on ''Ser-10'' (H3S10ph) in LPS-stimulated myeloid cells. This phosphorylation enhances the accessibility of the cryptic NF-kappa-B-binding sites marking promoters for increased NF-kappa-B recruitment. Phosphorylates CDC25B and CDC25C which is required for binding to 14-3-3 proteins and leads to initiation of a G2 delay after ultraviolet radiation (PubMed:11333986). Phosphorylates TIAR following DNA damage, releasing TIAR from GADD45A mRNA and preventing mRNA degradation (PubMed:20932473). The p38 MAPKs may also have kinase-independent roles, which are thought to be due to the binding to targets in the absence of phosphorylation. Protein O-Glc-N-acylation catalyzed by the OGT is regulated by MAPK14, and, although OGT does not seem to be phosphorylated by MAPK14, their interaction increases upon MAPK14 activation induced by glucose deprivation. This interaction may regulate OGT activity by recruiting it to specific targets such as neurofilament H, stimulating its O-Glc-N-acylation. Required in mid-fetal development for the growth of embryo-derived blood vessels in the labyrinth layer of the placenta. Also plays an essential role in developmental and stress-induced erythropoiesis, through regulation of EPO gene expression (PubMed:10943842). Isoform MXI2 activation is stimulated by mitogens and oxidative stress and only poorly phosphorylates ELK1 and ATF2. Isoform EXIP may play a role in the early onset of apoptosis. Phosphorylates S100A9 at ''Thr-113'' (PubMed:15905572). Phosphorylates NLRP1 downstream of MAP3K20/ZAK in response to UV-B irradiation and ribosome collisions, promoting activation of the NLRP1 inflammasome and pyroptosis (PubMed:35857590).', 'MAPK14', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Cytoplasm, Direct protein sequencing, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transcription, Transcription regulation, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (635, '8DKS', '', 'Interleukin-1 receptor-associated kinase 4', 'Serine/threonine-protein kinase that plays a critical role in initiating innate immune response against foreign pathogens. Involved in Toll-like receptor (TLR) and IL-1R signaling pathways (PubMed:17878374). Is rapidly recruited by MYD88 to the receptor-signaling complex upon TLR activation to form the Myddosome together with IRAK2. Phosphorylates initially IRAK1, thus stimulating the kinase activity and intensive autophosphorylation of IRAK1. Phosphorylates E3 ubiquitin ligases Pellino proteins (PELI1, PELI2 and PELI3) to promote pellino-mediated polyubiquitination of IRAK1. Then, the ubiquitin-binding domain of IKBKG/NEMO binds to polyubiquitinated IRAK1 bringing together the IRAK1-MAP3K7/TAK1-TRAF6 complex and the NEMO-IKKA-IKKB complex. In turn, MAP3K7/TAK1 activates IKKs (CHUK/IKKA and IKBKB/IKKB) leading to NF-kappa-B nuclear translocation and activation. Alternatively, phosphorylates TIRAP to promote its ubiquitination and subsequent degradation. Phosphorylates NCF1 and regulates NADPH oxidase activation after LPS stimulation suggesting a similar mechanism during microbial infections.', 'IRAK4', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Immunity, Innate immunity, Kinase, Magnesium, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (636, '4FL2', '', 'Tyrosine-protein kinase SYK', 'Non-receptor tyrosine kinase which mediates signal transduction downstream of a variety of transmembrane receptors including classical immunoreceptors like the B-cell receptor (BCR). Regulates several biological processes including innate and adaptive immunity, cell adhesion, osteoclast maturation, platelet activation and vascular development (PubMed:12387735, PubMed:33782605). Assembles into signaling complexes with activated receptors at the plasma membrane via interaction between its SH2 domains and the receptor tyrosine-phosphorylated ITAM domains. The association with the receptor can also be indirect and mediated by adapter proteins containing ITAM or partial hemITAM domains. The phosphorylation of the ITAM domains is generally mediated by SRC subfamily kinases upon engagement of the receptor. More rarely signal transduction via SYK could be ITAM-independent. Direct downstream effectors phosphorylated by SYK include DEPTOR, VAV1, PLCG1, PI-3-kinase, LCP2 and BLNK (PubMed:12456653, PubMed:15388330, PubMed:8657103, PubMed:34634301). Initially identified as essential in B-cell receptor (BCR) signaling, it is necessary for the maturation of B-cells most probably at the pro-B to pre-B transition (PubMed:12456653). Activated upon BCR engagement, it phosphorylates and activates BLNK an adapter linking the activated BCR to downstream signaling adapters and effectors. It also phosphorylates and activates PLCG1 and the PKC signaling pathway. It also phosphorylates BTK and regulates its activity in B-cell antigen receptor (BCR)-coupled signaling. In addition to its function downstream of BCR also plays a role in T-cell receptor signaling. Plays also a crucial role in the innate immune response to fungal, bacterial and viral pathogens. It is for instance activated by the membrane lectin CLEC7A. Upon stimulation by fungal proteins, CLEC7A together with SYK activates immune cells inducing the production of ROS. Also activates the inflammasome and NF-kappa-B-mediated transcription of chemokines and cytokines in presence of pathogens. Regulates neutrophil degranulation and phagocytosis through activation of the MAPK signaling cascade (By similarity). Required for the stimulation of neutrophil phagocytosis by IL15 (PubMed:15123770). Also mediates the activation of dendritic cells by cell necrosis stimuli. Also involved in mast cells activation. Involved in interleukin-3/IL3-mediated signaling pathway in basophils (By similarity). Also functions downstream of receptors mediating cell adhesion (PubMed:12387735). Relays for instance, integrin-mediated neutrophils and macrophages activation and P-selectin receptor/SELPG-mediated recruitment of leukocytes to inflammatory loci. Also plays a role in non-immune processes. It is for instance involved in vascular development where it may regulate blood and lymphatic vascular separation. It is also required for osteoclast development and function. Functions in the activation of platelets by collagen, mediating PLCG2 phosphorylation and activation. May be coupled to the collagen receptor by the ITAM domain-containing FCER1G. Also activated by the membrane lectin CLEC1B that is required for activation of platelets by PDPN/podoplanin. Involved in platelet adhesion being activated by ITGB3 engaged by fibrinogen. Together with CEACAM20, enhances production of the cytokine CXCL8/IL-8 via the NFKB pathway and may thus have a role in the intestinal immune response (By similarity).', 'SYK', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Adaptive immunity, Alternative splicing, Angiogenesis, ATP-binding, Cell membrane, Cytoplasm, Disease variant, Host-virus interaction, Immunity, Innate immunity, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, SH2 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (637, '4BK4', '', 'Ephrin type-A receptor 4', 'Receptor tyrosine kinase which binds membrane-bound ephrin family ligands residing on adjacent cells, leading to contact-dependent bidirectional signaling into neighboring cells. The signaling pathway downstream of the receptor is referred to as forward signaling while the signaling pathway downstream of the ephrin ligand is referred to as reverse signaling. Highly promiscuous, it has the unique property among Eph receptors to bind and to be physiologically activated by both GPI-anchored ephrin-A and transmembrane ephrin-B ligands including EFNA1 and EFNB3. Upon activation by ephrin ligands, modulates cell morphology and integrin-dependent cell adhesion through regulation of the Rac, Rap and Rho GTPases activity. Plays an important role in the development of the nervous system controlling different steps of axonal guidance including the establishment of the corticospinal projections. May also control the segregation of motor and sensory axons during neuromuscular circuit development. In addition to its role in axonal guidance plays a role in synaptic plasticity. Activated by EFNA1 phosphorylates CDK5 at ''Tyr-15'' which in turn phosphorylates NGEF regulating RHOA and dendritic spine morphogenesis. In the nervous system, also plays a role in repair after injury preventing axonal regeneration and in angiogenesis playing a role in central nervous system vascular formation. Additionally, its promiscuity makes it available to participate in a variety of cell-cell signaling regulating for instance the development of the thymic epithelium. During development of the cochlear organ of Corti, regulates pillar cell separation by forming a ternary complex with ADAM10 and CADH1 which facilitates the cleavage of CADH1 by ADAM10 and disruption of adherens junctions (By similarity). Phosphorylates CAPRIN1, promoting CAPRIN1-dependent formation of a membraneless compartment (By similarity).', 'EPHA4', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell adhesion, Cell junction, Cell membrane, Cell projection, Developmental protein, Endosome, Glycoprotein, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Phosphoprotein, Postsynaptic cell membrane, Receptor, Reference proteome, Repeat, Signal, Synapse, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (638, '6FAD', '', 'SRSF protein kinase 1', 'Serine/arginine-rich protein-specific kinase which specifically phosphorylates its substrates at serine residues located in regions rich in arginine/serine dipeptides, known as RS domains and is involved in the phosphorylation of SR splicing factors and the regulation of splicing. Plays a central role in the regulatory network for splicing, controlling the intranuclear distribution of splicing factors in interphase cells and the reorganization of nuclear speckles during mitosis. Can influence additional steps of mRNA maturation, as well as other cellular activities, such as chromatin reorganization in somatic and sperm cells and cell cycle progression. Isoform 2 phosphorylates SFRS2, ZRSR2, LBR and PRM1. Isoform 2 phosphorylates SRSF1 using a directional (C-terminal to N-terminal) and a dual-track mechanism incorporating both processive phosphorylation (in which the kinase stays attached to the substrate after each round of phosphorylation) and distributive phosphorylation steps (in which the kinase and substrate dissociate after each phosphorylation event). The RS domain of SRSF1 binds first to a docking groove in the large lobe of the kinase domain of SRPK1. This induces certain structural changes in SRPK1 and/or RRM2 domain of SRSF1, allowing RRM2 to bind the kinase and initiate phosphorylation. The cycles continue for several phosphorylation steps in a processive manner (steps 1-8) until the last few phosphorylation steps (approximately steps 9-12). During that time, a mechanical stress induces the unfolding of the beta-4 motif in RRM2, which then docks at the docking groove of SRPK1. This also signals RRM2 to begin to dissociate, which facilitates SRSF1 dissociation after phosphorylation is completed. Isoform 2 can mediate hepatitis B virus (HBV) core protein phosphorylation. It plays a negative role in the regulation of HBV replication through a mechanism not involving the phosphorylation of the core protein but by reducing the packaging efficiency of the pregenomic RNA (pgRNA) without affecting the formation of the viral core particles. Isoform 1 and isoform 2 can induce splicing of exon 10 in MAPT/TAU. The ratio of isoform 1/isoform 2 plays a decisive role in determining cell fate in K-562 leukaemic cell line: isoform 2 favors proliferation where as isoform 1 favors differentiation.', 'SRPK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Chromosome, Chromosome partition, Cytoplasm, Differentiation, Direct protein sequencing, Endoplasmic reticulum, Host-virus interaction, Kinase, Microsome, mRNA processing, mRNA splicing, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (639, '2IN6', '', 'Wee1-like protein kinase', 'Acts as a negative regulator of entry into mitosis (G2 to M transition) by protecting the nucleus from cytoplasmically activated cyclin B1-complexed CDK1 before the onset of mitosis by mediating phosphorylation of CDK1 on ''Tyr-15'' (PubMed:7743995, PubMed:8348613, PubMed:8428596, PubMed:15070733). Specifically phosphorylates and inactivates cyclin B1-complexed CDK1 reaching a maximum during G2 phase and a minimum as cells enter M phase (PubMed:7743995, PubMed:8348613, PubMed:8428596). Phosphorylation of cyclin B1-CDK1 occurs exclusively on ''Tyr-15'' and phosphorylation of monomeric CDK1 does not occur (PubMed:7743995, PubMed:8348613, PubMed:8428596). Its activity increases during S and G2 phases and decreases at M phase when it is hyperphosphorylated (PubMed:7743995). A correlated decrease in protein level occurs at M/G1 phase, probably due to its degradation (PubMed:7743995).', 'WEE1', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Cell division, Kinase, Magnesium, Metal-binding, Mitosis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (640, '4Z32', '', 'Tyrosine-protein kinase JAK2', 'Non-receptor tyrosine kinase involved in various processes such as cell growth, development, differentiation or histone modifications. Mediates essential signaling events in both innate and adaptive immunity. In the cytoplasm, plays a pivotal role in signal transduction via its association with type I receptors such as growth hormone (GHR), prolactin (PRLR), leptin (LEPR), erythropoietin (EPOR), thrombopoietin (THPO); or type II receptors including IFN-alpha, IFN-beta, IFN-gamma and multiple interleukins (PubMed:7615558). Following ligand-binding to cell surface receptors, phosphorylates specific tyrosine residues on the cytoplasmic tails of the receptor, creating docking sites for STATs proteins (PubMed:9618263). Subsequently, phosphorylates the STATs proteins once they are recruited to the receptor. Phosphorylated STATs then form homodimer or heterodimers and translocate to the nucleus to activate gene transcription. For example, cell stimulation with erythropoietin (EPO) during erythropoiesis leads to JAK2 autophosphorylation, activation, and its association with erythropoietin receptor (EPOR) that becomes phosphorylated in its cytoplasmic domain. Then, STAT5 (STAT5A or STAT5B) is recruited, phosphorylated and activated by JAK2. Once activated, dimerized STAT5 translocates into the nucleus and promotes the transcription of several essential genes involved in the modulation of erythropoiesis. Part of a signaling cascade that is activated by increased cellular retinol and that leads to the activation of STAT5 (STAT5A or STAT5B) (PubMed:21368206). In addition, JAK2 mediates angiotensin-2-induced ARHGEF1 phosphorylation (PubMed:20098430). Plays a role in cell cycle by phosphorylating CDKN1B (PubMed:21423214). Cooperates with TEC through reciprocal phosphorylation to mediate cytokine-driven activation of FOS transcription. In the nucleus, plays a key role in chromatin by specifically mediating phosphorylation of ''Tyr-41'' of histone H3 (H3Y41ph), a specific tag that promotes exclusion of CBX5 (HP1 alpha) from chromatin (PubMed:19783980).', 'JAK2', 'Homo sapiens', '{[''2.7.10.2'']}', '3D-structure, Adaptive immunity, ATP-binding, Chromatin regulator, Chromosomal rearrangement, Cytoplasm, Disease variant, Immunity, Innate immunity, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Repeat, SH2 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (641, '5A46', '', 'Fibroblast growth factor receptor 1', 'Tyrosine-protein kinase that acts as a cell-surface receptor for fibroblast growth factors and plays an essential role in the regulation of embryonic development, cell proliferation, differentiation and migration. Required for normal mesoderm patterning and correct axial organization during embryonic development, normal skeletogenesis and normal development of the gonadotropin-releasing hormone (GnRH) neuronal system. Phosphorylates PLCG1, FRS2, GAB1 and SHB. Ligand binding leads to the activation of several signaling cascades. Activation of PLCG1 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate. Phosphorylation of FRS2 triggers recruitment of GRB2, GAB1, PIK3R1 and SOS1, and mediates activation of RAS, MAPK1/ERK2, MAPK3/ERK1 and the MAP kinase signaling pathway, as well as of the AKT1 signaling pathway. Promotes phosphorylation of SHC1, STAT1 and PTPN11/SHP2. In the nucleus, enhances RPS6KA1 and CREB1 activity and contributes to the regulation of transcription. FGFR1 signaling is down-regulated by IL17RD/SEF, and by FGFR1 ubiquitination, internalization and degradation.', 'FGFR1', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Chromosomal rearrangement, Craniosynostosis, Cytoplasm, Cytoplasmic vesicle, Direct protein sequencing, Disease variant, Disulfide bond, Dwarfism, Glycoprotein, Heparin-binding, Holoprosencephaly, Hypogonadotropic hypogonadism, Immunoglobulin domain, Intellectual disability, Kallmann syndrome, Kinase, Membrane, Nucleotide-binding, Nucleus, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transcription, Transcription regulation, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (642, '6KHF', '', 'Dual specificity protein kinase CLK3', 'Dual specificity kinase acting on both serine/threonine and tyrosine-containing substrates. Phosphorylates serine- and arginine-rich (SR) proteins of the spliceosomal complex. May be a constituent of a network of regulatory mechanisms that enable SR proteins to control RNA splicing and can cause redistribution of SR proteins from speckles to a diffuse nucleoplasmic distribution. Phosphorylates SRSF1 and SRSF3. Regulates the alternative splicing of tissue factor (F3) pre-mRNA in endothelial cells.', 'CLK3', 'Homo sapiens', '{[''2.7.12.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoplasmic vesicle, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (643, '4W9X', '', 'BMP-2-inducible protein kinase', 'May be involved in osteoblast differentiation.', 'BMP2K', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (644, '7K7J', '', 'Ephrin type-B receptor 6', 'Kinase-defective receptor for members of the ephrin-B family. Binds to ephrin-B1 and ephrin-B2. Modulates cell adhesion and migration by exerting both positive and negative effects upon stimulation with ephrin-B2. Inhibits JNK activation, T-cell receptor-induced IL-2 secretion and CD25 expression upon stimulation with ephrin-B2.', 'EPHB6', 'Homo sapiens', '{[]}', '3D-structure, Alternative splicing, ATP-binding, Direct protein sequencing, Glycoprotein, Membrane, Nucleotide-binding, Receptor, Reference proteome, Repeat, Secreted, Signal, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (647, '4NEU', '', 'Receptor-interacting serine/threonine-protein kinase 1', 'Serine-threonine kinase which is a key regulator of TNF-mediated apoptosis, necroptosis and inflammatory pathways (PubMed:32657447, PubMed:31827280, PubMed:31827281, PubMed:17703191, PubMed:24144979). Exhibits kinase activity-dependent functions that regulate cell death and kinase-independent scaffold functions regulating inflammatory signaling and cell survival (PubMed:11101870, PubMed:19524512, PubMed:19524513, PubMed:29440439, PubMed:30988283). Has kinase-independent scaffold functions: upon binding of TNF to TNFR1, RIPK1 is recruited to the TNF-R1 signaling complex (TNF-RSC also known as complex I) where it acts as a scaffold protein promoting cell survival, in part, by activating the canonical NF-kappa-B pathway (By similarity). Kinase activity is essential to regulate necroptosis and apoptosis, two parallel forms of cell death: upon activation of its protein kinase activity, regulates assembly of two death-inducing complexes, namely complex IIa (RIPK1-FADD-CASP8), which drives apoptosis, and the complex IIb (RIPK1-RIPK3-MLKL), which drives necroptosis (By similarity). RIPK1 is required to limit CASP8-dependent TNFR1-induced apoptosis (By similarity). In normal conditions, RIPK1 acts as an inhibitor of RIPK3-dependent necroptosis, a process mediated by RIPK3 component of complex IIb, which catalyzes phosphorylation of MLKL upon induction by ZBP1 (PubMed:19524512, PubMed:19524513, PubMed:29440439, PubMed:30988283). Inhibits RIPK3-mediated necroptosis via FADD-mediated recruitment of CASP8, which cleaves RIPK1 and limits TNF-induced necroptosis (PubMed:19524512, PubMed:19524513, PubMed:29440439, PubMed:30988283). Required to inhibit apoptosis and necroptosis during embryonic development: acts by preventing the interaction of TRADD with FADD thereby limiting aberrant activation of CASP8 (By similarity). In addition to apoptosis and necroptosis, also involved in inflammatory response by promoting transcriptional production of pro-inflammatory cytokines, such as interleukin-6 (IL6) (PubMed:31827280, PubMed:31827281). Phosphorylates RIPK3: RIPK1 and RIPK3 undergo reciprocal auto- and trans-phosphorylation (PubMed:19524513). Phosphorylates DAB2IP at ''Ser-728'' in a TNF-alpha-dependent manner, and thereby activates the MAP3K5-JNK apoptotic cascade (PubMed:17389591, PubMed:15310755). Required for ZBP1-induced NF-kappa-B activation in response to DNA damage (By similarity).', 'RIPK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Cell membrane, Cytoplasm, Disease variant, Glycoprotein, Host-virus interaction, Inflammatory response, Isopeptide bond, Kinase, Membrane, Necrosis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (648, '4WAE', '', 'Phosphatidylinositol 4-kinase beta', 'Phosphorylates phosphatidylinositol (PI) in the first committed step in the production of the second messenger inositol-1,4,5,-trisphosphate (PIP). May regulate Golgi disintegration/reorganization during mitosis, possibly via its phosphorylation. Involved in Golgi-to-plasma membrane trafficking (By similarity) (PubMed:10559940, PubMed:11277933, PubMed:12749687, PubMed:9405935). May play an important role in the inner ear development.', 'PI4KB', 'Homo sapiens', '{[''2.7.1.67'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cytoplasm, Deafness, Direct protein sequencing, Disease variant, Endoplasmic reticulum, Golgi apparatus, Host-virus interaction, Kinase, Lipid metabolism, Membrane, Mitochondrion, Mitochondrion outer membrane, Non-syndromic deafness, Nucleotide-binding, Phosphoprotein, Reference proteome, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (649, '6FDY', '', 'Serine/threonine-protein kinase ULK3', 'Serine/threonine protein kinase that acts as a regulator of Sonic hedgehog (SHH) signaling and autophagy. Acts as a negative regulator of SHH signaling in the absence of SHH ligand: interacts with SUFU, thereby inactivating the protein kinase activity and preventing phosphorylation of GLI proteins (GLI1, GLI2 and/or GLI3). Positively regulates SHH signaling in the presence of SHH: dissociates from SUFU, autophosphorylates and mediates phosphorylation of GLI2, activating it and promoting its nuclear translocation. Phosphorylates in vitro GLI2, as well as GLI1 and GLI3, although less efficiently. Also acts as a regulator of autophagy: following cellular senescence, able to induce autophagy.', 'ULK3', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Autophagy, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (650, '1OPK', '', 'Tyrosine-protein kinase ABL1', 'Non-receptor tyrosine-protein kinase that plays a role in many key processes linked to cell growth and survival such as cytoskeleton remodeling in response to extracellular stimuli, cell motility and adhesion, receptor endocytosis, autophagy, DNA damage response and apoptosis. Coordinates actin remodeling through tyrosine phosphorylation of proteins controlling cytoskeleton dynamics like WASF3 (involved in branch formation); ANXA1 (involved in membrane anchoring); DBN1, DBNL, CTTN, RAPH1 and ENAH (involved in signaling); or MAPT and PXN (microtubule-binding proteins). Phosphorylation of WASF3 is critical for the stimulation of lamellipodia formation and cell migration. Involved in the regulation of cell adhesion and motility through phosphorylation of key regulators of these processes such as BCAR1, CRK, CRKL, DOK1, EFS or NEDD9. Phosphorylates multiple receptor tyrosine kinases and more particularly promotes endocytosis of EGFR, facilitates the formation of neuromuscular synapses through MUSK, inhibits PDGFRB-mediated chemotaxis and modulates the endocytosis of activated B-cell receptor complexes. Other substrates which are involved in endocytosis regulation are the caveolin (CAV1) and RIN1. Moreover, ABL1 regulates the CBL family of ubiquitin ligases that drive receptor down-regulation and actin remodeling. Phosphorylation of CBL leads to increased EGFR stability. Involved in late-stage autophagy by regulating positively the trafficking and function of lysosomal components. ABL1 targets to mitochondria in response to oxidative stress and thereby mediates mitochondrial dysfunction and cell death. In response to oxidative stress, phosphorylates serine/threonine kinase PRKD2 at ''Tyr-717'' (By similarity). ABL1 is also translocated in the nucleus where it has DNA-binding activity and is involved in DNA-damage response and apoptosis. Many substrates are known mediators of DNA repair: DDB1, DDB2, ERCC3, ERCC6, RAD9A, RAD51, RAD52 or WRN. Activates the proapoptotic pathway when the DNA damage is too severe to be repaired. Phosphorylates TP73, a primary regulator for this type of damage-induced apoptosis. Phosphorylates the caspase CASP9 on ''Tyr-191'' and regulates its processing in the apoptotic response to DNA damage. Phosphorylates PSMA7 that leads to an inhibition of proteasomal activity and cell cycle transition blocks. Regulates T-cell differentiation in a TBX21-dependent manner (PubMed:21690296). Positively regulates chemokine-mediated T-cell migration, polarization, and homing to lymph nodes and immune-challenged tissues, potentially via activation of NEDD9/HEF1 and RAP1 (PubMed:22810897). Phosphorylates TBX21 on tyrosine residues leading to an enhancement of its transcriptional activator activity (PubMed:21690296).', 'Abl1', 'Mus musculus', '{[''2.7.10.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Autophagy, Cell adhesion, Chromosomal rearrangement, Cytoplasm, Cytoskeleton, DNA damage, DNA repair, DNA-binding, Endocytosis, Kinase, Lipoprotein, Magnesium, Manganese, Metal-binding, Mitochondrion, Myristate, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, SH2 domain, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (651, '6YKY', '', 'Mitogen-activated protein kinase 6', 'Atypical MAPK protein. Phosphorylates microtubule-associated protein 2 (MAP2) and MAPKAPK5. The precise role of the complex formed with MAPKAPK5 is still unclear, but the complex follows a complex set of phosphorylation events: upon interaction with atypical MAPKAPK5, ERK3/MAPK6 is phosphorylated at Ser-189 and then mediates phosphorylation and activation of MAPKAPK5, which in turn phosphorylates ERK3/MAPK6. May promote entry in the cell cycle (By similarity).', 'MAPK6', 'Homo sapiens', '{[''2.7.11.24'']}', '3D-structure, ATP-binding, Cell cycle, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (652, '3RGF', '', 'Cyclin-dependent kinase 8', 'Component of the Mediator complex, a coactivator involved in regulated gene transcription of nearly all RNA polymerase II-dependent genes. Mediator functions as a bridge to convey information from gene-specific regulatory proteins to the basal RNA polymerase II transcription machinery. Mediator is recruited to promoters by direct interactions with regulatory proteins and serves as a scaffold for the assembly of a functional pre-initiation complex with RNA polymerase II and the general transcription factors. Phosphorylates the CTD (C-terminal domain) of the large subunit of RNA polymerase II (RNAp II), which may inhibit the formation of a transcription initiation complex. Phosphorylates CCNH leading to down-regulation of the TFIIH complex and transcriptional repression. Recruited through interaction with MAML1 to hyperphosphorylate the intracellular domain of NOTCH, leading to its degradation.', 'CDK8', 'Homo sapiens', '{[''2.7.11.23'',''2.7.11.22'']}', '3D-structure, Activator, Alternative splicing, ATP-binding, Autism spectrum disorder, Disease variant, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Reference proteome, Repressor, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (653, '6UNP', '', 'Bone morphogenetic protein receptor type-2', 'On ligand binding, forms a receptor complex consisting of two type II and two type I transmembrane serine/threonine kinases. Type II receptors phosphorylate and activate type I receptors which autophosphorylate, then bind and activate SMAD transcriptional regulators. Can also mediate signaling through the activation of the p38MAPK cascade (PubMed:12045205). Binds to BMP7, BMP2 and, less efficiently, BMP4. Binding is weak but enhanced by the presence of type I receptors for BMPs. Mediates induction of adipogenesis by GDF6.', 'BMPR2', 'Homo sapiens', '{[''2.7.11.30'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Kinase, Magnesium, Manganese, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Serine/threonine-protein kinase, Signal, Transferase, Transmembrane, Transmembrane helix');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (654, '5BRK', '', 'MOB kinase activator 1A', 'Activator of LATS1/2 in the Hippo signaling pathway which plays a pivotal role in organ size control and tumor suppression by restricting proliferation and promoting apoptosis. The core of this pathway is composed of a kinase cascade wherein STK3/MST2 and STK4/MST1, in complex with its regulatory protein SAV1, phosphorylates and activates LATS1/2 in complex with its regulatory protein MOB1, which in turn phosphorylates and inactivates YAP1 oncoprotein and WWTR1/TAZ. Phosphorylation of YAP1 by LATS1/2 inhibits its translocation into the nucleus to regulate cellular genes important for cell proliferation, cell death, and cell migration. Stimulates the kinase activity of STK38 and STK38L. Acts cooperatively with STK3/MST2 to activate STK38.', 'MOB1A', 'Homo sapiens', '{[]}', '3D-structure, Acetylation, Alternative splicing, Direct protein sequencing, Metal-binding, Phosphoprotein, Reference proteome, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (655, '8U4B', '', 'Insulin receptor', 'Receptor tyrosine kinase which mediates the pleiotropic actions of insulin. Binding of insulin leads to phosphorylation of several intracellular substrates, including, insulin receptor substrates (IRS1, 2, 3, 4), SHC, GAB1, CBL and other signaling intermediates. Each of these phosphorylated proteins serve as docking proteins for other signaling proteins that contain Src-homology-2 domains (SH2 domain) that specifically recognize different phosphotyrosine residues, including the p85 regulatory subunit of PI3K and SHP2. Phosphorylation of IRSs proteins lead to the activation of two main signaling pathways: the PI3K-AKT/PKB pathway, which is responsible for most of the metabolic actions of insulin, and the Ras-MAPK pathway, which regulates expression of some genes and cooperates with the PI3K pathway to control cell growth and differentiation. Binding of the SH2 domains of PI3K to phosphotyrosines on IRS1 leads to the activation of PI3K and the generation of phosphatidylinositol-(3, 4, 5)-triphosphate (PIP3), a lipid second messenger, which activates several PIP3-dependent serine/threonine kinases, such as PDPK1 and subsequently AKT/PKB. The net effect of this pathway is to produce a translocation of the glucose transporter SLC2A4/GLUT4 from cytoplasmic vesicles to the cell membrane to facilitate glucose transport. Moreover, upon insulin stimulation, activated AKT/PKB is responsible for: anti-apoptotic effect of insulin by inducing phosphorylation of BAD; regulates the expression of gluconeogenic and lipogenic enzymes by controlling the activity of the winged helix or forkhead (FOX) class of transcription factors. Another pathway regulated by PI3K-AKT/PKB activation is mTORC1 signaling pathway which regulates cell growth and metabolism and integrates signals from insulin. AKT mediates insulin-stimulated protein synthesis by phosphorylating TSC2 thereby activating mTORC1 pathway. The Ras/RAF/MAP2K/MAPK pathway is mainly involved in mediating cell growth, survival and cellular differentiation of insulin. Phosphorylated IRS1 recruits GRB2/SOS complex, which triggers the activation of the Ras/RAF/MAP2K/MAPK pathway. In addition to binding insulin, the insulin receptor can bind insulin-like growth factors (IGFI and IGFII). Isoform Short has a higher affinity for IGFII binding. When present in a hybrid receptor with IGF1R, binds IGF1. PubMed:12138094 shows that hybrid receptors composed of IGF1R and INSR isoform Long are activated with a high affinity by IGF1, with low affinity by IGF2 and not significantly activated by insulin, and that hybrid receptors composed of IGF1R and INSR isoform Short are activated by IGF1, IGF2 and insulin. In contrast, PubMed:16831875 shows that hybrid receptors composed of IGF1R and INSR isoform Long and hybrid receptors composed of IGF1R and INSR isoform Short have similar binding characteristics, both bind IGF1 and have a low affinity for insulin. In adipocytes, inhibits lipolysis (By similarity).', 'INSR', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Carbohydrate metabolism, Cell membrane, Cleavage on pair of basic residues, Diabetes mellitus, Direct protein sequencing, Disease variant, Disulfide bond, Endosome, Glycoprotein, Kinase, Lysosome, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (656, '8AZA', '', 'E3 ubiquitin-protein ligase XIAP', 'Multi-functional protein which regulates not only caspases and apoptosis, but also modulates inflammatory signaling and immunity, copper homeostasis, mitogenic kinase signaling, cell proliferation, as well as cell invasion and metastasis (PubMed:11447297, PubMed:12121969, PubMed:9230442, PubMed:11257230, PubMed:11257231, PubMed:12620238, PubMed:17967870, PubMed:19473982, PubMed:20154138, PubMed:22103349, PubMed:17560374). Acts as a direct caspase inhibitor (PubMed:11257230, PubMed:11257231, PubMed:12620238). Directly bind to the active site pocket of CASP3 and CASP7 and obstructs substrate entry (PubMed:11257230, PubMed:11257231, PubMed:16352606, PubMed:16916640). Inactivates CASP9 by keeping it in a monomeric, inactive state (PubMed:12620238). Acts as an E3 ubiquitin-protein ligase regulating NF-kappa-B signaling and the target proteins for its E3 ubiquitin-protein ligase activity include: RIPK1, RIPK2, MAP3K2/MEKK2, DIABLO/SMAC, AIFM1, CCS, PTEN and BIRC5/survivin (PubMed:17967870, PubMed:19473982, PubMed:20154138, PubMed:22103349, PubMed:22607974, PubMed:30026309, PubMed:29452636, PubMed:17560374). Acts as an important regulator of innate immunity by mediating ''Lys-63''-linked polyubiquitination of RIPK2 downstream of NOD1 and NOD2, thereby transforming RIPK2 into a scaffolding protein for downstream effectors, ultimately leading to activation of the NF-kappa-B and MAP kinases signaling (PubMed:19667203, PubMed:22607974, PubMed:30026309, PubMed:29452636). ''Lys-63''-linked polyubiquitination of RIPK2 also promotes recruitment of the LUBAC complex to RIPK2 (PubMed:22607974, PubMed:29452636). Regulates the BMP signaling pathway and the SMAD and MAP3K7/TAK1 dependent pathways leading to NF-kappa-B and JNK activation (PubMed:17560374). Ubiquitination of CCS leads to enhancement of its chaperone activity toward its physiologic target, SOD1, rather than proteasomal degradation (PubMed:20154138). Ubiquitination of MAP3K2/MEKK2 and AIFM1 does not lead to proteasomal degradation (PubMed:17967870, PubMed:22103349). Plays a role in copper homeostasis by ubiquitinating COMMD1 and promoting its proteasomal degradation (PubMed:14685266). Can also function as E3 ubiquitin-protein ligase of the NEDD8 conjugation pathway, targeting effector caspases for neddylation and inactivation (PubMed:21145488). Ubiquitinates and therefore mediates the proteasomal degradation of BCL2 in response to apoptosis (PubMed:29020630). Protects cells from spontaneous formation of the ripoptosome, a large multi-protein complex that has the capability to kill cancer cells in a caspase-dependent and caspase-independent manner (PubMed:22095281). Suppresses ripoptosome formation by ubiquitinating RIPK1 and CASP8 (PubMed:22095281). Acts as a positive regulator of Wnt signaling and ubiquitinates TLE1, TLE2, TLE3, TLE4 and AES (PubMed:22304967). Ubiquitination of TLE3 results in inhibition of its interaction with TCF7L2/TCF4 thereby allowing efficient recruitment and binding of the transcriptional coactivator beta-catenin to TCF7L2/TCF4 that is required to initiate a Wnt-specific transcriptional program (PubMed:22304967).', 'XIAP', 'Homo sapiens', '{[''2.3.2.27'']}', '3D-structure, Apoptosis, Cytoplasm, Isopeptide bond, Metal-binding, Nucleus, Phosphoprotein, Protease inhibitor, Reference proteome, Repeat, S-nitrosylation, Thiol protease inhibitor, Transferase, Ubl conjugation, Ubl conjugation pathway, Wnt signaling pathway, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (657, '6JK8', '', 'Insulin-like growth factor 1 receptor', 'Receptor tyrosine kinase which mediates actions of insulin-like growth factor 1 (IGF1). Binds IGF1 with high affinity and IGF2 and insulin (INS) with a lower affinity. The activated IGF1R is involved in cell growth and survival control. IGF1R is crucial for tumor transformation and survival of malignant cell. Ligand binding activates the receptor kinase, leading to receptor autophosphorylation, and tyrosines phosphorylation of multiple substrates, that function as signaling adapter proteins including, the insulin-receptor substrates (IRS1/2), Shc and 14-3-3 proteins. Phosphorylation of IRSs proteins lead to the activation of two main signaling pathways: the PI3K-AKT/PKB pathway and the Ras-MAPK pathway. The result of activating the MAPK pathway is increased cellular proliferation, whereas activating the PI3K pathway inhibits apoptosis and stimulates protein synthesis. Phosphorylated IRS1 can activate the 85 kDa regulatory subunit of PI3K (PIK3R1), leading to activation of several downstream substrates, including protein AKT/PKB. AKT phosphorylation, in turn, enhances protein synthesis through mTOR activation and triggers the antiapoptotic effects of IGFIR through phosphorylation and inactivation of BAD. In parallel to PI3K-driven signaling, recruitment of Grb2/SOS by phosphorylated IRS1 or Shc leads to recruitment of Ras and activation of the ras-MAPK pathway. In addition to these two main signaling pathways IGF1R signals also through the Janus kinase/signal transducer and activator of transcription pathway (JAK/STAT). Phosphorylation of JAK proteins can lead to phosphorylation/activation of signal transducers and activators of transcription (STAT) proteins. In particular activation of STAT3, may be essential for the transforming activity of IGF1R. The JAK/STAT pathway activates gene transcription and may be responsible for the transforming activity. JNK kinases can also be activated by the IGF1R. IGF1 exerts inhibiting activities on JNK activation via phosphorylation and inhibition of MAP3K5/ASK1, which is able to directly associate with the IGF1R.', 'IGF1R', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Cleavage on pair of basic residues, Direct protein sequencing, Disease variant, Disulfide bond, Glycoprotein, Host-virus interaction, Isopeptide bond, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (658, '2WTK', '', 'Calcium-binding protein 39', 'Component of a complex that binds and activates STK11/LKB1. In the complex, required to stabilize the interaction between CAB39/MO25 (CAB39/MO25alpha or CAB39L/MO25beta) and STK11/LKB1.', 'CAB39', 'Homo sapiens', '{[]}', '3D-structure, Cytoplasm, Reference proteome');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (659, '6T28', '', 'Calcium/calmodulin-dependent protein kinase type 1D', 'Calcium/calmodulin-dependent protein kinase that operates in the calcium-triggered CaMKK-CaMK1 signaling cascade and, upon calcium influx, activates CREB-dependent gene transcription, regulates calcium-mediated granulocyte function and respiratory burst and promotes basal dendritic growth of hippocampal neurons. In neutrophil cells, required for cytokine-induced proliferative responses and activation of the respiratory burst. Activates the transcription factor CREB1 in hippocampal neuron nuclei. May play a role in apoptosis of erythroleukemia cells. In vitro, phosphorylates transcription factor CREM isoform Beta.', 'CAMK1D', 'Homo sapiens', '{[''2.7.11.17'']}', '3D-structure, Allosteric enzyme, Alternative splicing, ATP-binding, Calcium, Calmodulin-binding, Cytoplasm, Inflammatory response, Isopeptide bond, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (660, '1XWS', '', 'Serine/threonine-protein kinase pim-1', 'Proto-oncogene with serine/threonine kinase activity involved in cell survival and cell proliferation and thus providing a selective advantage in tumorigenesis (PubMed:15528381, PubMed:1825810, PubMed:31548394). Exerts its oncogenic activity through: the regulation of MYC transcriptional activity, the regulation of cell cycle progression and by phosphorylation and inhibition of proapoptotic proteins (BAD, MAP3K5, FOXO3) (PubMed:18593906). Phosphorylation of MYC leads to an increase of MYC protein stability and thereby an increase of transcriptional activity (By similarity). The stabilization of MYC exerted by PIM1 might explain partly the strong synergism between these two oncogenes in tumorigenesis (By similarity). Mediates survival signaling through phosphorylation of BAD, which induces release of the anti-apoptotic protein Bcl-X(L)/BCL2L1 (By similarity). Phosphorylation of MAP3K5, another proapoptotic protein, by PIM1, significantly decreases MAP3K5 kinase activity and inhibits MAP3K5-mediated phosphorylation of JNK and JNK/p38MAPK subsequently reducing caspase-3 activation and cell apoptosis (PubMed:19749799). Stimulates cell cycle progression at the G1-S and G2-M transitions by phosphorylation of CDC25A and CDC25C (PubMed:16356754). Phosphorylation of CDKN1A, a regulator of cell cycle progression at G1, results in the relocation of CDKN1A to the cytoplasm and enhanced CDKN1A protein stability (PubMed:12431783). Promotes cell cycle progression and tumorigenesis by down-regulating expression of a regulator of cell cycle progression, CDKN1B, at both transcriptional and post-translational levels (PubMed:18593906). Phosphorylation of CDKN1B, induces 14-3-3 proteins binding, nuclear export and proteasome-dependent degradation (PubMed:18593906). May affect the structure or silencing of chromatin by phosphorylating HP1 gamma/CBX3 (PubMed:10664448). Acts also as a regulator of homing and migration of bone marrow cells involving functional interaction with the CXCL12-CXCR4 signaling axis (By similarity). Acts as a positive regulator of mTORC1 signaling by mediating phosphorylation and inhibition of DEPDC5 component of the GATOR1 complex (PubMed:31548394). Acts as a negative regulator of innate immunity by mediating phosphorylation and inactivation of GBP1 in absence of infection: phosphorylation of GBP1 induces interaction with 14-3-3 protein sigma (SFN) and retention in the cytosol (PubMed:37797010). Also phosphorylates and activates the ATP-binding cassette transporter ABCG2, allowing resistance to drugs through their excretion from cells (PubMed:18056989). Promotes brown adipocyte differentiation (By similarity).', 'PIM1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative initiation, Apoptosis, ATP-binding, Cell cycle, Cell membrane, Cytoplasm, Direct protein sequencing, Host-virus interaction, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (661, '6D3K', '', 'Interferon-induced, double-stranded RNA-activated protein kinase', 'IFN-induced dsRNA-dependent serine/threonine-protein kinase that phosphorylates the alpha subunit of eukaryotic translation initiation factor 2 (EIF2S1/eIF-2-alpha) and plays a key role in the innate immune response to viral infection (PubMed:18835251, PubMed:19507191, PubMed:19189853, PubMed:21123651, PubMed:21072047, PubMed:22948139, PubMed:23229543, PubMed:22381929). Inhibits viral replication via the integrated stress response (ISR): EIF2S1/eIF-2-alpha phosphorylation in response to viral infection converts EIF2S1/eIF-2-alpha in a global protein synthesis inhibitor, resulting to a shutdown of cellular and viral protein synthesis, while concomitantly initiating the preferential translation of ISR-specific mRNAs, such as the transcriptional activator ATF4 (PubMed:19189853, PubMed:21123651, PubMed:22948139, PubMed:23229543). Exerts its antiviral activity on a wide range of DNA and RNA viruses including hepatitis C virus (HCV), hepatitis B virus (HBV), measles virus (MV) and herpes simplex virus 1 (HHV-1) (PubMed:11836380, PubMed:19189853, PubMed:20171114, PubMed:19840259, PubMed:21710204, PubMed:23115276, PubMed:23399035). Also involved in the regulation of signal transduction, apoptosis, cell proliferation and differentiation: phosphorylates other substrates including p53/TP53, PPP2R5A, DHX9, ILF3, IRS1 and the HHV-1 viral protein US11 (PubMed:11836380, PubMed:22214662, PubMed:19229320). In addition to serine/threonine-protein kinase activity, also has tyrosine-protein kinase activity and phosphorylates CDK1 at ''Tyr-4'' upon DNA damage, facilitating its ubiquitination and proteasomal degradation (PubMed:20395957). Either as an adapter protein and/or via its kinase activity, can regulate various signaling pathways (p38 MAP kinase, NF-kappa-B and insulin signaling pathways) and transcription factors (JUN, STAT1, STAT3, IRF1, ATF3) involved in the expression of genes encoding pro-inflammatory cytokines and IFNs (PubMed:22948139, PubMed:23084476, PubMed:23372823). Activates the NF-kappa-B pathway via interaction with IKBKB and TRAF family of proteins and activates the p38 MAP kinase pathway via interaction with MAP2K6 (PubMed:10848580, PubMed:15121867, PubMed:15229216). Can act as both a positive and negative regulator of the insulin signaling pathway (ISP) (PubMed:20685959). Negatively regulates ISP by inducing the inhibitory phosphorylation of insulin receptor substrate 1 (IRS1) at ''Ser-312'' and positively regulates ISP via phosphorylation of PPP2R5A which activates FOXO1, which in turn up-regulates the expression of insulin receptor substrate 2 (IRS2) (PubMed:20685959). Can regulate NLRP3 inflammasome assembly and the activation of NLRP3, NLRP1, AIM2 and NLRC4 inflammasomes (PubMed:22801494). Plays a role in the regulation of the cytoskeleton by binding to gelsolin (GSN), sequestering the protein in an inactive conformation away from actin (By similarity).', 'EIF2AK2', 'Homo sapiens', '{[''2.7.10.2'',''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, Antiviral defense, ATP-binding, Cytoplasm, Direct protein sequencing, Disease variant, Dystonia, Host-virus interaction, Immunity, Innate immunity, Isopeptide bond, Kinase, Magnesium, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Repeat, RNA-binding, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (662, '2D9Z', '', 'Serine/threonine-protein kinase D3', 'Converts transient diacylglycerol (DAG) signals into prolonged physiological effects, downstream of PKC. Involved in resistance to oxidative stress (By similarity).', 'PRKD3', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (664, '5W5V', '', 'Serine/threonine-protein kinase TBK1', 'Serine/threonine kinase that plays an essential role in regulating inflammatory responses to foreign agents (PubMed:12692549, PubMed:14703513, PubMed:18583960, PubMed:12702806, PubMed:15367631, PubMed:10581243, PubMed:11839743, PubMed:15485837, PubMed:21138416, PubMed:25636800, PubMed:23453971, PubMed:23453972, PubMed:23746807, PubMed:26611359, PubMed:32404352). Following activation of toll-like receptors by viral or bacterial components, associates with TRAF3 and TANK and phosphorylates interferon regulatory factors (IRFs) IRF3 and IRF7 as well as DDX3X (PubMed:12692549, PubMed:14703513, PubMed:18583960, PubMed:12702806, PubMed:15367631, PubMed:25636800). This activity allows subsequent homodimerization and nuclear translocation of the IRFs leading to transcriptional activation of pro-inflammatory and antiviral genes including IFNA and IFNB (PubMed:12702806, PubMed:15367631, PubMed:25636800, PubMed:32972995). In order to establish such an antiviral state, TBK1 form several different complexes whose composition depends on the type of cell and cellular stimuli (PubMed:23453971, PubMed:23453972, PubMed:23746807). Plays a key role in IRF3 activation: acts by first phosphorylating innate adapter proteins MAVS, STING1 and TICAM1 on their pLxIS motif, leading to recruitment of IRF3, thereby licensing IRF3 for phosphorylation by TBK1 (PubMed:25636800, PubMed:30842653). Phosphorylated IRF3 dissociates from the adapter proteins, dimerizes, and then enters the nucleus to induce expression of interferons (PubMed:25636800). Thus, several scaffolding molecules including FADD, TRADD, MAVS, AZI2, TANK or TBKBP1/SINTBAD can be recruited to the TBK1-containing-complexes (PubMed:21931631). Under particular conditions, functions as a NF-kappa-B effector by phosphorylating NF-kappa-B inhibitor alpha/NFKBIA, IKBKB or RELA to translocate NF-Kappa-B to the nucleus (PubMed:10783893, PubMed:15489227). Restricts bacterial proliferation by phosphorylating the autophagy receptor OPTN/Optineurin on ''Ser-177'', thus enhancing LC3 binding affinity and antibacterial autophagy (PubMed:21617041). Phosphorylates SMCR8 component of the C9orf72-SMCR8 complex, promoting autophagosome maturation (PubMed:27103069). Phosphorylates ATG8 proteins MAP1LC3C and GABARAPL2, thereby preventing their delipidation and premature removal from nascent autophagosomes (PubMed:31709703). Phosphorylates and activates AKT1 (PubMed:21464307). Seems to play a role in energy balance regulation by sustaining a state of chronic, low-grade inflammation in obesity, wich leads to a negative impact on insulin sensitivity (By similarity). Attenuates retroviral budding by phosphorylating the endosomal sorting complex required for transport-I (ESCRT-I) subunit VPS37C (PubMed:21270402). Phosphorylates Borna disease virus (BDV) P protein (PubMed:16155125). Plays an essential role in the TLR3- and IFN-dependent control of herpes virus HSV-1 and HSV-2 infections in the central nervous system (PubMed:22851595). Acts both as a positive and negative regulator of the mTORC1 complex, depending on the context: activates mTORC1 in response to growth factors by catalyzing phosphorylation of MTOR, while it limits the mTORC1 complex by promoting phosphorylation of RPTOR (PubMed:29150432, PubMed:31530866).', 'TBK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Amyotrophic lateral sclerosis, Antiviral defense, ATP-binding, Coiled coil, Cytoplasm, Disease variant, Glaucoma, Host-virus interaction, Immunity, Innate immunity, Isopeptide bond, Kinase, Neurodegeneration, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (665, '8FP1', '', 'Protein kinase C eta type', 'Calcium-independent, phospholipid- and diacylglycerol (DAG)-dependent serine/threonine-protein kinase that is involved in the regulation of cell differentiation in keratinocytes and pre-B cell receptor, mediates regulation of epithelial tight junction integrity and foam cell formation, and is required for glioblastoma proliferation and apoptosis prevention in MCF-7 cells. In keratinocytes, binds and activates the tyrosine kinase FYN, which in turn blocks epidermal growth factor receptor (EGFR) signaling and leads to keratinocyte growth arrest and differentiation. Associates with the cyclin CCNE1-CDK2-CDKN1B complex and inhibits CDK2 kinase activity, leading to RB1 dephosphorylation and thereby G1 arrest in keratinocytes. In association with RALA activates actin depolymerization, which is necessary for keratinocyte differentiation. In the pre-B cell receptor signaling, functions downstream of BLNK by up-regulating IRF4, which in turn activates L chain gene rearrangement. Regulates epithelial tight junctions (TJs) by phosphorylating occludin (OCLN) on threonine residues, which is necessary for the assembly and maintenance of TJs. In association with PLD2 and via TLR4 signaling, is involved in lipopolysaccharide (LPS)-induced RGS2 down-regulation and foam cell formation. Upon PMA stimulation, mediates glioblastoma cell proliferation by activating the mTOR pathway, the PI3K/AKT pathway and the ERK1-dependent phosphorylation of ELK1. Involved in the protection of glioblastoma cells from irradiation-induced apoptosis by preventing caspase-9 activation. In camptothecin-treated MCF-7 cells, regulates NF-kappa-B upstream signaling by activating IKBKB, and confers protection against DNA damage-induced apoptosis. Promotes oncogenic functions of ATF2 in the nucleus while blocking its apoptotic function at mitochondria. Phosphorylates ATF2 which promotes its nuclear retention and transcriptional activity and negatively regulates its mitochondrial localization.', 'PRKCH', 'Homo sapiens', '{[''2.7.11.13'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Differentiation, Kinase, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (666, '7MFD', '', 'Serine/threonine-protein kinase B-raf', 'Protein kinase involved in the transduction of mitogenic signals from the cell membrane to the nucleus (Probable). Phosphorylates MAP2K1, and thereby activates the MAP kinase signal transduction pathway (PubMed:21441910, PubMed:29433126). Phosphorylates PFKFB2 (PubMed:36402789). May play a role in the postsynaptic responses of hippocampal neurons (PubMed:1508179).', 'BRAF', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Allosteric enzyme, ATP-binding, Cardiomyopathy, Cell membrane, Chromosomal rearrangement, Cytoplasm, Deafness, Direct protein sequencing, Disease variant, Ectodermal dysplasia, Intellectual disability, Isopeptide bond, Kinase, Membrane, Metal-binding, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Proto-oncogene, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation, Zinc, Zinc-finger');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (667, '7ZKX', '', 'SRSF protein kinase 2', 'Serine/arginine-rich protein-specific kinase which specifically phosphorylates its substrates at serine residues located in regions rich in arginine/serine dipeptides, known as RS domains and is involved in the phosphorylation of SR splicing factors and the regulation of splicing (PubMed:9472028, PubMed:18559500, PubMed:21056976). Promotes neuronal apoptosis by up-regulating cyclin-D1 (CCND1) expression (PubMed:19592491). This is done by the phosphorylation of SRSF2, leading to the suppression of p53/TP53 phosphorylation thereby relieving the repressive effect of p53/TP53 on cyclin-D1 (CCND1) expression (PubMed:21205200). Phosphorylates ACIN1, and redistributes it from the nuclear speckles to the nucleoplasm, resulting in cyclin A1 but not cyclin A2 up-regulation (PubMed:18559500). Plays an essential role in spliceosomal B complex formation via the phosphorylation of DDX23/PRP28 (PubMed:18425142). Probably by phosphorylating DDX23, leads to the suppression of incorrect R-loops formed during transcription; R-loops are composed of a DNA:RNA hybrid and the associated non-template single-stranded DNA (PubMed:28076779). Can mediate hepatitis B virus (HBV) core protein phosphorylation (PubMed:12134018). Plays a negative role in the regulation of HBV replication through a mechanism not involving the phosphorylation of the core protein but by reducing the packaging efficiency of the pregenomic RNA (pgRNA) without affecting the formation of the viral core particles (PubMed:16122776).', 'SRPK2', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Chromosome, Cytoplasm, Differentiation, Kinase, mRNA processing, mRNA splicing, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (668, '2YA9', '', 'Death-associated protein kinase 2', 'Calcium/calmodulin-dependent serine/threonine kinase involved in multiple cellular signaling pathways that trigger cell survival, apoptosis, and autophagy. Capable of regulating both type I apoptotic and type II autophagic cell death signals. The former involves caspase activation, chromatin and mitochondrial condensation while the latter involves caspase-independent cell death in conjunction with accumulation of mature autophagic vesicles, plasma membrane blebs, and nuclear condensation without DNA degradation. Mediator of anoikis and a suppressor of beta-catenin-dependent anchorage-independent growth of malignant epithelial cells. May play a role in granulocytic maturation (By similarity). Regulates granulocytes motility by controlling cell spreading and polarization (PubMed:24163421).', 'Dapk2', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Calmodulin-binding, Cytoplasm, Cytoplasmic vesicle, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (669, '3P1A', '', 'Membrane-associated tyrosine- and threonine-specific cdc2-inhibitory kinase', 'Acts as a negative regulator of entry into mitosis (G2 to M transition) by phosphorylation of the CDK1 kinase specifically when CDK1 is complexed to cyclins (PubMed:9268380, PubMed:9001210, PubMed:10504341, PubMed:10373560). Mediates phosphorylation of CDK1 predominantly on ''Thr-14''. Also involved in Golgi fragmentation (PubMed:9268380, PubMed:9001210). May be involved in phosphorylation of CDK1 on ''Tyr-15'' to a lesser degree, however tyrosine kinase activity is unclear and may be indirect (PubMed:9268380, PubMed:9001210).', 'PKMYT1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell cycle, Endoplasmic reticulum, Golgi apparatus, Kinase, Magnesium, Membrane, Metal-binding, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (670, '6YG1', '', 'Dual specificity mitogen-activated protein kinase kinase 7', 'Dual specificity protein kinase which acts as an essential component of the MAP kinase signal transduction pathway. Essential component of the stress-activated protein kinase/c-Jun N-terminal kinase (SAP/JNK) signaling pathway. With MAP2K4/MKK4, is the one of the only known kinase to directly activate the stress-activated protein kinase/c-Jun N-terminal kinases MAPK8/JNK1, MAPK9/JNK2 and MAPK10/JNK3. MAP2K4/MKK4 and MAP2K7/MKK7 both activate the JNKs by phosphorylation, but they differ in their preference for the phosphorylation site in the Thr-Pro-Tyr motif. MAP2K4/MKK4 shows preference for phosphorylation of the Tyr residue and MAP2K7/MKK7 for the Thr residue. The monophosphorylation of JNKs on the Thr residue is sufficient to increase JNK activity indicating that MAP2K7/MKK7 is important to trigger JNK activity, while the additional phosphorylation of the Tyr residue by MAP2K4/MKK4 ensures optimal JNK activation. Has a specific role in JNK signal transduction pathway activated by pro-inflammatory cytokines. The MKK/JNK signaling pathway is also involved in mitochondrial death signaling pathway, including the release cytochrome c, leading to apoptosis. Part of a non-canonical MAPK signaling pathway, composed of the upstream MAP3K12 kinase and downstream MAP kinases MAPK1/ERK2 and MAPK3/ERK1, that enhances the AP-1-mediated transcription of APP in response to APOE (PubMed:28111074).', 'MAP2K7', 'Homo sapiens', '{[''2.7.12.2'']}', '3D-structure, Acetylation, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Kinase, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Stress response, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (671, '3ZDU', '', 'Cyclin-dependent kinase-like 3', 'Unknown', 'CDKL3', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (672, '5L4Q', '', 'AP2-associated protein kinase 1', 'Regulates clathrin-mediated endocytosis by phosphorylating the AP2M1/mu2 subunit of the adaptor protein complex 2 (AP-2) which ensures high affinity binding of AP-2 to cargo membrane proteins during the initial stages of endocytosis (PubMed:17494869, PubMed:11877457, PubMed:11877461, PubMed:12952931, PubMed:14617351, PubMed:25653444). Isoform 1 and isoform 2 display similar levels of kinase activity towards AP2M1 (PubMed:17494869). Preferentially, may phosphorylate substrates on threonine residues (PubMed:11877457, PubMed:18657069). Regulates phosphorylation of other AP-2 subunits as well as AP-2 localization and AP-2-mediated internalization of ligand complexes (PubMed:12952931). Phosphorylates NUMB and regulates its cellular localization, promoting NUMB localization to endosomes (PubMed:18657069). Binds to and stabilizes the activated form of NOTCH1, increases its localization in endosomes and regulates its transcriptional activity (PubMed:21464124).', 'AAK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Acetylation, Alternative splicing, ATP-binding, Cell membrane, Cell projection, Coated pit, Endocytosis, Kinase, Membrane, Methylation, Nucleotide-binding, Pharmaceutical, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Synapse, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (673, '3ANQ', '', 'Dual specificity tyrosine-phosphorylation-regulated kinase 1A', 'Dual-specificity kinase which possesses both serine/threonine and tyrosine kinase activities (PubMed:21127067, PubMed:8769099, PubMed:30773093, PubMed:20981014, PubMed:23665168). Exhibits a substrate preference for proline at position P+1 and arginine at position P-3 (PubMed:23665168). Plays an important role in double-strand breaks (DSBs) repair following DNA damage (PubMed:31024071). Mechanistically, phosphorylates RNF169 and increases its ability to block accumulation of TP53BP1 at the DSB sites thereby promoting homologous recombination repair (HRR) (PubMed:30773093). Also acts as a positive regulator of transcription by acting as a CTD kinase that mediates phosphorylation of the CTD (C-terminal domain) of the large subunit of RNA polymerase II (RNAP II) POLR2A (PubMed:25620562, PubMed:29849146). May play a role in a signaling pathway regulating nuclear functions of cell proliferation (PubMed:14500717). Modulates alternative splicing by phosphorylating the splice factor SRSF6 (By similarity). Has pro-survival function and negatively regulates the apoptotic process (By similarity). Promotes cell survival upon genotoxic stress through phosphorylation of SIRT1 (By similarity). This in turn inhibits p53/TP53 activity and apoptosis (By similarity). Phosphorylates SEPTIN4, SEPTIN5 and SF3B1 at ''Thr-434'' (By similarity).', 'DYRK1A', 'Homo sapiens', '{[''2.7.11.23'',''2.7.12.1'']}', '3D-structure, Alternative splicing, ATP-binding, Host-virus interaction, Intellectual disability, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transcription, Transcription regulation, Transferase, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (674, '4CFE', '', '5''-AMP-activated protein kinase catalytic subunit alpha-2', 'Catalytic subunit of AMP-activated protein kinase (AMPK), an energy sensor protein kinase that plays a key role in regulating cellular energy metabolism (PubMed:17307971, PubMed:17712357). In response to reduction of intracellular ATP levels, AMPK activates energy-producing pathways and inhibits energy-consuming processes: inhibits protein, carbohydrate and lipid biosynthesis, as well as cell growth and proliferation (PubMed:17307971, PubMed:17712357). AMPK acts via direct phosphorylation of metabolic enzymes, and by longer-term effects via phosphorylation of transcription regulators (PubMed:17307971, PubMed:17712357). Regulates lipid synthesis by phosphorylating and inactivating lipid metabolic enzymes such as ACACA, ACACB, GYS1, HMGCR and LIPE; regulates fatty acid and cholesterol synthesis by phosphorylating acetyl-CoA carboxylase (ACACA and ACACB) and hormone-sensitive lipase (LIPE) enzymes, respectively (PubMed:7959015). Promotes lipolysis of lipid droplets by mediating phosphorylation of isoform 1 of CHKA (CHKalpha2) (PubMed:34077757). Regulates insulin-signaling and glycolysis by phosphorylating IRS1, PFKFB2 and PFKFB3 (By similarity). Involved in insulin receptor/INSR internalization (PubMed:25687571). AMPK stimulates glucose uptake in muscle by increasing the translocation of the glucose transporter SLC2A4/GLUT4 to the plasma membrane, possibly by mediating phosphorylation of TBC1D4/AS160 (By similarity). Regulates transcription and chromatin structure by phosphorylating transcription regulators involved in energy metabolism such as CRTC2/TORC2, FOXO3, histone H2B, HDAC5, MEF2C, MLXIPL/ChREBP, EP300, HNF4A, p53/TP53, SREBF1, SREBF2 and PPARGC1A (PubMed:11554766, PubMed:11518699, PubMed:15866171, PubMed:17711846, PubMed:18184930). Acts as a key regulator of glucose homeostasis in liver by phosphorylating CRTC2/TORC2, leading to CRTC2/TORC2 sequestration in the cytoplasm (By similarity). In response to stress, phosphorylates ''Ser-36'' of histone H2B (H2BS36ph), leading to promote transcription (By similarity). Acts as a key regulator of cell growth and proliferation by phosphorylating FNIP1, TSC2, RPTOR, WDR24 and ATG1/ULK1: in response to nutrient limitation, negatively regulates the mTORC1 complex by phosphorylating RPTOR component of the mTORC1 complex and by phosphorylating and activating TSC2 (PubMed:14651849, PubMed:20160076, PubMed:21205641). Also phosphorylates and inhibits GATOR2 subunit WDR24 in response to nutrient limitation, leading to suppress glucose-mediated mTORC1 activation (PubMed:36732624). In response to energetic stress, phosphorylates FNIP1, inactivating the non-canonical mTORC1 signaling, thereby promoting nuclear translocation of TFEB and TFE3, and inducing transcription of lysosomal or autophagy genes (PubMed:37079666). In response to nutrient limitation, promotes autophagy by phosphorylating and activating ATG1/ULK1 (PubMed:21205641). In that process also activates WDR45/WIPI4 (PubMed:28561066). Phosphorylates CASP6, thereby preventing its autoprocessing and subsequent activation (PubMed:32029622). AMPK also acts as a regulator of circadian rhythm by mediating phosphorylation of CRY1, leading to destabilize it (By similarity). May regulate the Wnt signaling pathway by phosphorylating CTNNB1, leading to stabilize it (By similarity). Also acts as a regulator of cellular polarity by remodeling the actin cytoskeleton; probably by indirectly activating myosin (PubMed:17486097). Also phosphorylates CFTR, EEF2K, KLC1, NOS3 and SLC12A1 (PubMed:12519745, PubMed:20074060). Plays an important role in the differential regulation of pro-autophagy (composed of PIK3C3, BECN1, PIK3R4 and UVRAG or ATG14) and non-autophagy (composed of PIK3C3, BECN1 and PIK3R4) complexes, in response to glucose starvation (By similarity). Can inhibit the non-autophagy complex by phosphorylating PIK3C3 and can activate the pro-autophagy complex by phosphorylating BECN1 (By similarity). Upon glucose starvation, promotes ARF6 activation in a kinase-independent manner leading to cell migration (PubMed:36017701). Upon glucose deprivation mediates the phosphorylation of ACSS2 at ''Ser-659'', which exposes the nuclear localization signal of ACSS2, required for its interaction with KPNA1 and nuclear translocation (PubMed:28552616).', 'PRKAA2', 'Homo sapiens', '{[''2.7.11.31'',''2.7.11.1'']}', '3D-structure, ATP-binding, Autophagy, Biological rhythms, Cholesterol biosynthesis, Cholesterol metabolism, Chromatin regulator, Cytoplasm, Fatty acid biosynthesis, Fatty acid metabolism, Kinase, Lipid biosynthesis, Lipid metabolism, Magnesium, Metal-binding, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Steroid biosynthesis, Steroid metabolism, Sterol biosynthesis, Sterol metabolism, Transcription, Transcription regulation, Transferase, Ubl conjugation, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (675, '4HZS', '', 'Activated CDC42 kinase 1', 'Non-receptor tyrosine-protein and serine/threonine-protein kinase that is implicated in cell spreading and migration, cell survival, cell growth and proliferation. Transduces extracellular signals to cytosolic and nuclear effectors. Phosphorylates AKT1, AR, MCF2, WASL and WWOX. Implicated in trafficking and clathrin-mediated endocytosis through binding to epidermal growth factor receptor (EGFR) and clathrin. Binds to both poly- and mono-ubiquitin and regulates ligand-induced degradation of EGFR, thereby contributing to the accumulation of EGFR at the limiting membrane of early endosomes. Downstream effector of CDC42 which mediates CDC42-dependent cell migration via phosphorylation of BCAR1. May be involved both in adult synaptic function and plasticity and in brain development. Activates AKT1 by phosphorylating it on ''Tyr-176''. Phosphorylates AR on ''Tyr-267'' and ''Tyr-363'' thereby promoting its recruitment to androgen-responsive enhancers (AREs). Phosphorylates WWOX on ''Tyr-287''. Phosphorylates MCF2, thereby enhancing its activity as a guanine nucleotide exchange factor (GEF) toward Rho family proteins. Contributes to the control of AXL receptor levels. Confers metastatic properties on cancer cells and promotes tumor growth by negatively regulating tumor suppressor such as WWOX and positively regulating pro-survival factors such as AKT1 and AR. Phosphorylates WASP (PubMed:20110370).', 'TNK2', 'Homo sapiens', '{[''2.7.10.2'',''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell junction, Cell membrane, Coated pit, Cytoplasm, Cytoplasmic vesicle, Endocytosis, Endosome, Kinase, Magnesium, Membrane, Metal-binding, Methylation, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, SH3 domain, Transferase, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (676, '6FER', '', 'Discoidin domain-containing receptor 2', 'Tyrosine kinase involved in the regulation of tissues remodeling (PubMed:30449416). It functions as a cell surface receptor for fibrillar collagen and regulates cell differentiation, remodeling of the extracellular matrix, cell migration and cell proliferation. Required for normal bone development. Regulates osteoblast differentiation and chondrocyte maturation via a signaling pathway that involves MAP kinases and leads to the activation of the transcription factor RUNX2. Regulates remodeling of the extracellular matrix by up-regulation of the collagenases MMP1, MMP2 and MMP13, and thereby facilitates cell migration and tumor cell invasion. Promotes fibroblast migration and proliferation, and thereby contributes to cutaneous wound healing.', 'DDR2', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Dwarfism, Glycoprotein, Kinase, Membrane, Nucleotide-binding, Osteogenesis, Phosphoprotein, Receptor, Reference proteome, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (677, '7SXF', '', 'Glycogen synthase kinase-3 alpha', 'Constitutively active protein kinase that acts as a negative regulator in the hormonal control of glucose homeostasis, Wnt signaling and regulation of transcription factors and microtubules, by phosphorylating and inactivating glycogen synthase (GYS1 or GYS2), CTNNB1/beta-catenin, APC and AXIN1 (PubMed:11749387, PubMed:17478001, PubMed:19366350). Requires primed phosphorylation of the majority of its substrates (PubMed:11749387, PubMed:17478001, PubMed:19366350). Contributes to insulin regulation of glycogen synthesis by phosphorylating and inhibiting GYS1 activity and hence glycogen synthesis (PubMed:11749387, PubMed:17478001, PubMed:19366350). Regulates glycogen metabolism in liver, but not in muscle (By similarity). May also mediate the development of insulin resistance by regulating activation of transcription factors (PubMed:10868943, PubMed:17478001). In Wnt signaling, regulates the level and transcriptional activity of nuclear CTNNB1/beta-catenin (PubMed:17229088). Facilitates amyloid precursor protein (APP) processing and the generation of APP-derived amyloid plaques found in Alzheimer disease (PubMed:12761548). May be involved in the regulation of replication in pancreatic beta-cells (By similarity). Is necessary for the establishment of neuronal polarity and axon outgrowth (By similarity). Through phosphorylation of the anti-apoptotic protein MCL1, may control cell apoptosis in response to growth factors deprivation (By similarity). Acts as a regulator of autophagy by mediating phosphorylation of KAT5/TIP60 under starvation conditions which activates KAT5/TIP60 acetyltransferase activity and promotes acetylation of key autophagy regulators, such as ULK1 and RUBCNL/Pacer (PubMed:30704899). Negatively regulates extrinsic apoptotic signaling pathway via death domain receptors. Promotes the formation of an anti-apoptotic complex, made of DDX3X, BRIC2 and GSK3B, at death receptors, including TNFRSF10B. The anti-apoptotic function is most effective with weak apoptotic signals and can be overcome by stronger stimulation (By similarity). Phosphorylates mTORC2 complex component RICTOR at ''Thr-1695'' which facilitates FBXW7-mediated ubiquitination and subsequent degradation of RICTOR (PubMed:25897075).', 'GSK3A', 'Homo sapiens', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, Acetylation, Alzheimer disease, ATP-binding, Carbohydrate metabolism, Diabetes mellitus, Glycogen metabolism, Kinase, Neurogenesis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Signal transduction inhibitor, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (678, '8SI2', '', 'Transient receptor potential cation channel subfamily M member 7', 'Essential ion channel and serine/threonine-protein kinase. Divalent cation channel permeable to calcium and magnesium. Has a central role in magnesium ion homeostasis and in the regulation of anoxic neuronal cell death. Involved in TNF-induced necroptosis downstream of MLKL by mediating calcium influx. The kinase activity is essential for the channel function. May be involved in a fundamental process that adjusts plasma membrane divalent cation fluxes according to the metabolic state of the cell. Phosphorylates annexin A1 (ANXA1).', 'Trpm7', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, Acetylation, ATP-binding, Calcium, Calcium channel, Calcium transport, Coiled coil, Ion channel, Ion transport, Kinase, Membrane, Metal-binding, Necrosis, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Transmembrane, Transmembrane helix, Transport, Zinc');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (679, '2QHM', '', 'Serine/threonine-protein kinase Chk1', 'Serine/threonine-protein kinase which is required for checkpoint-mediated cell cycle arrest and activation of DNA repair in response to the presence of DNA damage or unreplicated DNA (PubMed:11535615, PubMed:12446774, PubMed:12399544, PubMed:14559997, PubMed:14988723, PubMed:15311285, PubMed:15665856, PubMed:15650047, PubMed:32357935). May also negatively regulate cell cycle progression during unperturbed cell cycles (PubMed:11535615, PubMed:12446774, PubMed:12399544, PubMed:14559997, PubMed:14988723, PubMed:15311285, PubMed:15665856, PubMed:15650047). This regulation is achieved by a number of mechanisms that together help to preserve the integrity of the genome (PubMed:11535615, PubMed:12446774, PubMed:12399544, PubMed:14559997, PubMed:14988723, PubMed:15311285, PubMed:15665856, PubMed:15650047). Recognizes the substrate consensus sequence [R-X-X-S/T] (PubMed:11535615, PubMed:12446774, PubMed:12399544, PubMed:14559997, PubMed:14988723, PubMed:15311285, PubMed:15665856, PubMed:15650047). Binds to and phosphorylates CDC25A, CDC25B and CDC25C (PubMed:9278511, PubMed:12676583, PubMed:14681206, PubMed:12676925, PubMed:12759351, PubMed:19734889, PubMed:14559997). Phosphorylation of CDC25A at ''Ser-178'' and ''Thr-507'' and phosphorylation of CDC25C at ''Ser-216'' creates binding sites for 14-3-3 proteins which inhibit CDC25A and CDC25C (PubMed:9278511). Phosphorylation of CDC25A at ''Ser-76'', ''Ser-124'', ''Ser-178'', ''Ser-279'' and ''Ser-293'' promotes proteolysis of CDC25A (PubMed:9278511, PubMed:12676583, PubMed:14681206, PubMed:12676925, PubMed:12759351, PubMed:19734889). Phosphorylation of CDC25A at ''Ser-76'' primes the protein for subsequent phosphorylation at ''Ser-79'', ''Ser-82'' and ''Ser-88'' by NEK11, which is required for polyubiquitination and degradation of CDCD25A (PubMed:9278511, PubMed:19734889, PubMed:20090422). Inhibition of CDC25 leads to increased inhibitory tyrosine phosphorylation of CDK-cyclin complexes and blocks cell cycle progression (PubMed:9278511). Also phosphorylates NEK6 (PubMed:18728393). Binds to and phosphorylates RAD51 at ''Thr-309'', which promotes the release of RAD51 from BRCA2 and enhances the association of RAD51 with chromatin, thereby promoting DNA repair by homologous recombination (PubMed:15665856). Phosphorylates multiple sites within the C-terminus of TP53, which promotes activation of TP53 by acetylation and promotes cell cycle arrest and suppression of cellular proliferation (PubMed:10673501, PubMed:15659650, PubMed:16511572). Also promotes repair of DNA cross-links through phosphorylation of FANCE (PubMed:17296736). Binds to and phosphorylates TLK1 at ''Ser-743'', which prevents the TLK1-dependent phosphorylation of the chromatin assembly factor ASF1A (PubMed:12660173, PubMed:12955071). This may enhance chromatin assembly both in the presence or absence of DNA damage (PubMed:12660173, PubMed:12955071). May also play a role in replication fork maintenance through regulation of PCNA (PubMed:18451105). May regulate the transcription of genes that regulate cell-cycle progression through the phosphorylation of histones (By similarity). Phosphorylates histone H3.1 (to form H3T11ph), which leads to epigenetic inhibition of a subset of genes (By similarity). May also phosphorylate RB1 to promote its interaction with the E2F family of transcription factors and subsequent cell cycle arrest (PubMed:17380128). Phosphorylates SPRTN, promoting SPRTN recruitment to chromatin (PubMed:31316063). Reduces replication stress and activates the G2/M checkpoint, by phosphorylating and inactivating PABIR1/FAM122A and promoting the serine/threonine-protein phosphatase 2A-mediated dephosphorylation and stabilization of WEE1 levels and activity (PubMed:33108758).', 'CHEK1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell cycle, Chromosome, Cytoplasm, Cytoskeleton, DNA damage, DNA repair, Isopeptide bond, Kinase, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (680, '4LIQ', '', 'Macrophage colony-stimulating factor 1 receptor', 'Tyrosine-protein kinase that acts as a cell-surface receptor for CSF1 and IL34 and plays an essential role in the regulation of survival, proliferation and differentiation of hematopoietic precursor cells, especially mononuclear phagocytes, such as macrophages and monocytes. Promotes the release of pro-inflammatory chemokines in response to IL34 and CSF1, and thereby plays an important role in innate immunity and in inflammatory processes. Plays an important role in the regulation of osteoclast proliferation and differentiation, the regulation of bone resorption, and is required for normal bone and tooth development. Required for normal male and female fertility, and for normal development of milk ducts and acinar structures in the mammary gland during pregnancy. Promotes reorganization of the actin cytoskeleton, regulates formation of membrane ruffles, cell adhesion and cell migration, and promotes cancer cell invasion. Activates several signaling pathways in response to ligand binding, including the ERK1/2 and the JNK pathway (PubMed:20504948, PubMed:30982609). Phosphorylates PIK3R1, PLCG2, GRB2, SLA2 and CBL. Activation of PLCG2 leads to the production of the cellular signaling molecules diacylglycerol and inositol 1,4,5-trisphosphate, that then lead to the activation of protein kinase C family members, especially PRKCD. Phosphorylation of PIK3R1, the regulatory subunit of phosphatidylinositol 3-kinase, leads to activation of the AKT1 signaling pathway. Activated CSF1R also mediates activation of the MAP kinases MAPK1/ERK2 and/or MAPK3/ERK1, and of the SRC family kinases SRC, FYN and YES1. Activated CSF1R transmits signals both via proteins that directly interact with phosphorylated tyrosine residues in its intracellular domain, or via adapter proteins, such as GRB2. Promotes activation of STAT family members STAT3, STAT5A and/or STAT5B. Promotes tyrosine phosphorylation of SHC1 and INPP5D/SHIP-1. Receptor signaling is down-regulated by protein phosphatases, such as INPP5D/SHIP-1, that dephosphorylate the receptor and its downstream effectors, and by rapid internalization of the activated receptor. In the central nervous system, may play a role in the development of microglia macrophages (PubMed:30982608).', 'CSF1R', 'Homo sapiens', '{[''2.7.10.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cell membrane, Disease variant, Disulfide bond, Glycoprotein, Immunity, Immunoglobulin domain, Inflammatory response, Innate immunity, Kinase, Membrane, Neurodegeneration, Nucleotide-binding, Phosphoprotein, Proto-oncogene, Receptor, Reference proteome, Repeat, Signal, Transferase, Transmembrane, Transmembrane helix, Tyrosine-protein kinase, Ubl conjugation');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (681, '2J7T', '', 'Serine/threonine-protein kinase 10', 'Serine/threonine-protein kinase involved in regulation of lymphocyte migration. Phosphorylates MSN, and possibly PLK1. Involved in regulation of lymphocyte migration by mediating phosphorylation of ERM proteins such as MSN. Acts as a negative regulator of MAP3K1/MEKK1. May also act as a cell cycle regulator by acting as a polo kinase kinase: mediates phosphorylation of PLK1 in vitro; however such data require additional evidences in vivo.', 'STK10', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, ATP-binding, Cell cycle, Cell membrane, Coiled coil, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (682, '1I09', '', 'Glycogen synthase kinase-3 beta', 'Constitutively active protein kinase that acts as a negative regulator in the hormonal control of glucose homeostasis, Wnt signaling and regulation of transcription factors and microtubules, by phosphorylating and inactivating glycogen synthase (GYS1 or GYS2), EIF2B, CTNNB1/beta-catenin, APC, AXIN1, DPYSL2/CRMP2, JUN, NFATC1/NFATC, MAPT/TAU and MACF1 (PubMed:1846781, PubMed:9072970, PubMed:14690523, PubMed:20937854, PubMed:12554650, PubMed:11430833, PubMed:16484495). Requires primed phosphorylation of the majority of its substrates (PubMed:11430833, PubMed:16484495). In skeletal muscle, contributes to insulin regulation of glycogen synthesis by phosphorylating and inhibiting GYS1 activity and hence glycogen synthesis (PubMed:8397507). May also mediate the development of insulin resistance by regulating activation of transcription factors (PubMed:8397507). Regulates protein synthesis by controlling the activity of initiation factor 2B (EIF2BE/EIF2B5) in the same manner as glycogen synthase (PubMed:8397507). In Wnt signaling, GSK3B forms a multimeric complex with APC, AXIN1 and CTNNB1/beta-catenin and phosphorylates the N-terminus of CTNNB1 leading to its degradation mediated by ubiquitin/proteasomes (PubMed:12554650). Phosphorylates JUN at sites proximal to its DNA-binding domain, thereby reducing its affinity for DNA (PubMed:1846781). Phosphorylates NFATC1/NFATC on conserved serine residues promoting NFATC1/NFATC nuclear export, shutting off NFATC1/NFATC gene regulation, and thereby opposing the action of calcineurin (PubMed:9072970). Phosphorylates MAPT/TAU on ''Thr-548'', decreasing significantly MAPT/TAU ability to bind and stabilize microtubules (PubMed:14690523). MAPT/TAU is the principal component of neurofibrillary tangles in Alzheimer disease (PubMed:14690523). Plays an important role in ERBB2-dependent stabilization of microtubules at the cell cortex (PubMed:20937854). Phosphorylates MACF1, inhibiting its binding to microtubules which is critical for its role in bulge stem cell migration and skin wound repair (By similarity). Probably regulates NF-kappa-B (NFKB1) at the transcriptional level and is required for the NF-kappa-B-mediated anti-apoptotic response to TNF-alpha (TNF/TNFA) (By similarity). Negatively regulates replication in pancreatic beta-cells, resulting in apoptosis, loss of beta-cells and diabetes (By similarity). Through phosphorylation of the anti-apoptotic protein MCL1, may control cell apoptosis in response to growth factors deprivation (By similarity). Phosphorylates MUC1 in breast cancer cells, decreasing the interaction of MUC1 with CTNNB1/beta-catenin (PubMed:9819408). Is necessary for the establishment of neuronal polarity and axon outgrowth (PubMed:20067585). Phosphorylates MARK2, leading to inhibition of its activity (By similarity). Phosphorylates SIK1 at ''Thr-182'', leading to sustainment of its activity (PubMed:18348280). Phosphorylates ZC3HAV1 which enhances its antiviral activity (PubMed:22514281). Phosphorylates SNAI1, leading to its BTRC-triggered ubiquitination and proteasomal degradation (PubMed:15448698, PubMed:15647282). Phosphorylates SFPQ at ''Thr-687'' upon T-cell activation (PubMed:20932480). Phosphorylates NR1D1 st ''Ser-55'' and ''Ser-59'' and stabilizes it by protecting it from proteasomal degradation. Regulates the circadian clock via phosphorylation of the major clock components including BMAL1, CLOCK and PER2 (PubMed:19946213, PubMed:28903391). Phosphorylates FBXL2 at ''Thr-404'' and primes it for ubiquitination by the SCF(FBXO3) complex and proteasomal degradation (By similarity). Phosphorylates CLOCK AT ''Ser-427'' and targets it for proteasomal degradation (PubMed:19946213). Phosphorylates BMAL1 at ''Ser-17'' and ''Ser-21'' and primes it for ubiquitination and proteasomal degradation (PubMed:28903391). Phosphorylates OGT at ''Ser-3'' or ''Ser-4'' which positively regulates its activity. Phosphorylates MYCN in neuroblastoma cells which may promote its degradation (PubMed:24391509). Regulates the circadian rhythmicity of hippocampal long-term potentiation and BMAL1 and PER2 expression (By similarity). Acts as a regulator of autophagy by mediating phosphorylation of KAT5/TIP60 under starvation conditions, activating KAT5/TIP60 acetyltransferase activity and promoting acetylation of key autophagy regulators, such as ULK1 and RUBCNL/Pacer (PubMed:30704899). Negatively regulates extrinsic apoptotic signaling pathway via death domain receptors. Promotes the formation of an anti-apoptotic complex, made of DDX3X, BRIC2 and GSK3B, at death receptors, including TNFRSF10B. The anti-apoptotic function is most effective with weak apoptotic signals and can be overcome by stronger stimulation (PubMed:18846110). Phosphorylates E2F1, promoting the interaction between E2F1 and USP11, stabilizing E2F1 and promoting its activity (PubMed:17050006, PubMed:28992046). Phosphorylates mTORC2 complex component RICTOR at ''Thr-1695'' which facilitates FBXW7-mediated ubiquitination and subsequent degradation of RICTOR (PubMed:25897075). Phosphorylates FXR1, promoting FXR1 ubiquitination by the SCF(FBXO4) complex and FXR1 degradation by the proteasome (By similarity). Phosphorylates interleukin-22 receptor subunit IL22RA1, preventing its proteasomal degradation (By similarity).', 'GSK3B', 'Homo sapiens', '{[''2.7.11.26'',''2.7.11.1'']}', '3D-structure, ADP-ribosylation, Alternative splicing, Alzheimer disease, ATP-binding, Biological rhythms, Carbohydrate metabolism, Cell membrane, Cytoplasm, Developmental protein, Diabetes mellitus, Differentiation, Glycogen metabolism, Kinase, Membrane, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Signal transduction inhibitor, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (683, '4AGU', '', 'Cyclin-dependent kinase-like 1', 'Unknown', 'CDKL1', 'Homo sapiens', '{[''2.7.11.22'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Kinase, Nucleotide-binding, Nucleus, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (684, '8BEM', '', 'STE20-like serine/threonine-protein kinase', 'Mediates apoptosis and actin stress fiber dissolution.', 'SLK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, Apoptosis, ATP-binding, Coiled coil, Cytoplasm, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (685, '2CMW', '', 'Casein kinase I isoform gamma-1', 'Serine/threonine-protein kinase. Casein kinases are operationally defined by their preferential utilization of acidic proteins such as caseins as substrates. It can phosphorylate a large number of proteins. Participates in Wnt signaling. Regulates fast synaptic transmission mediated by glutamate (By similarity). Phosphorylates CLSPN.', 'CSNK1G1', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Disease variant, Kinase, Nucleotide-binding, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (686, '2X7F', '', 'TRAF2 and NCK-interacting protein kinase', 'Serine/threonine kinase that acts as an essential activator of the Wnt signaling pathway. Recruited to promoters of Wnt target genes and required to activate their expression. May act by phosphorylating TCF4/TCF7L2. Appears to act upstream of the JUN N-terminal pathway. May play a role in the response to environmental stress. Part of a signaling complex composed of NEDD4, RAP2A and TNIK which regulates neuronal dendrite extension and arborization during development. More generally, it may play a role in cytoskeletal rearrangements and regulate cell spreading. Phosphorylates SMAD1 on Thr-322.', 'TNIK', 'Homo sapiens', '{[''2.7.11.1'']}', '3D-structure, Alternative splicing, ATP-binding, Cytoplasm, Cytoskeleton, Endosome, Intellectual disability, Kinase, Neurogenesis, Nucleotide-binding, Nucleus, Phosphoprotein, Reference proteome, Serine/threonine-protein kinase, Transferase, Wnt signaling pathway');
INSERT INTO public.target_info (id, pdb_id, sequence, protein_name, protein_function, gene_name, source_organism, ec_numbers, keywords) VALUES (687, '5WNI', '', 'Receptor-interacting serine/threonine-protein kinase 4', 'Involved in stratified epithelial development (By similarity). It is a direct transcriptional target of TP63. Plays a role in NF-kappa-B activation.', 'Ripk4', 'Mus musculus', '{[''2.7.11.1'']}', '3D-structure, ANK repeat, ATP-binding, Cytoplasm, Isopeptide bond, Kinase, Membrane, Nucleotide-binding, Phosphoprotein, Receptor, Reference proteome, Repeat, Serine/threonine-protein kinase, Transferase, Ubl conjugation');
